import Transitioner from '@cb/shared/components/Transitioner';
import { useToggler } from '@cb/shared/utils';
import useScreenMatch from '@cb/shared/utils/useScreenMatch';
import { Icon } from '@cbhq/cds-web/icons/Icon';
import { Box } from '@cbhq/cds-web/layout';
import { Divider } from '@cbhq/cds-web/layout/Divider';
import { VStack } from '@cbhq/cds-web/layout/VStack';
import { Pressable } from '@cbhq/cds-web/system';
import { useConcurrentSuspense } from '@cbhq/common-web';
import { graphql, useFragment } from '@cbhq/data-layer';

import usePaymentMethods from 'hooks/api/queries/usePaymentMethods';

import Checklist from '../components/Checklist';
import InfoLinksSection from '../components/InfoLinksSection';
import Summary from '../components/Summary';
import { useAccountChecklistState } from '../hooks/useAccountChecklistState';
import { campaignInFirstBuyTreatment, useCampaign } from '../hooks/useCampaign';
import { useNavigateToChecklistAction } from '../hooks/useNavigateToChecklistAction';
import useWheelSpin from '../hooks/useWheelSpin';
import { AccountChecklistContentFragment$key } from './__generated__/AccountChecklistContentFragment.graphql';

type AccountChecklistSectionProps = {
  queryRef: AccountChecklistContentFragment$key;
  borderedBottom?: boolean;
};

function AccountChecklistContent({
  queryRef,
  borderedBottom = true,
}: AccountChecklistSectionProps) {
  const [paymentMethods, query] = useConcurrentSuspense(
    wrap => wrap(usePaymentMethods)(),
    wrap =>
      wrap(useFragment)<AccountChecklistContentFragment$key>(
        graphql`
          fragment AccountChecklistContentFragment on Query
          @argumentDefinitions(skipUserIncentives: { type: "Boolean!" }) {
            viewer {
              userProperties {
                firstBuyStatus
              }
            }
            ...SummaryFragment
            ...useNavigateToChecklistActionFragment
            ...useAccountChecklistStateFragment
            ...useCampaignFragment
            ...ChecklistFragment
            ...useWheelSpinFragment
              @arguments(skipUserIncentives: $skipUserIncentives)
          }
        `,
        queryRef,
      ),
  );

  const { viewer } = query;

  const navigateToAction = useNavigateToChecklistAction({
    paymentMethods,
    queryRef: query,
  });

  const firstBuyCompleted = Boolean(viewer.userProperties.firstBuyStatus);
  const campaignAmount = useCampaign(query);

  const { isToggled: isExpanded, toggle: onClick } = useToggler(true);

  const checklistState = useAccountChecklistState({
    paymentMethods,
    queryRef: query,
  });

  const isPhone = useScreenMatch('phone_small');
  const isDesktop = useScreenMatch('desktop');
  const { wheelSpinAvailable, completedWheelSpin, eligibleForGamification } =
    useWheelSpin(query);

  // If not eligible for gamification, close checklist when completing first buy
  if (
    !eligibleForGamification &&
    firstBuyCompleted &&
    campaignInFirstBuyTreatment(campaignAmount)
  ) {
    return null;
  }

  // If eligible for gamification, close checklist when wheel spin has been redeemed
  if (eligibleForGamification && completedWheelSpin) {
    return null;
  }

  return (
    <>
      <VStack
        bordered={false}
        borderedBottom={false}
        background
        borderRadius={isPhone ? undefined : 'rounded'}
        spacingTop={isPhone ? 2 : 3}
        spacingBottom={isPhone ? 0 : 3}
        position="relative"
        zIndex={0}
      >
        {!isDesktop && (
          <Box
            position="absolute"
            right={24}
            top={24}
            zIndex={1}
            spacingHorizontal={isPhone ? 2 : 3}
          >
            <Pressable background="background" onPress={onClick}>
              <Box
                height={32}
                width={32}
                borderRadius="roundedFull"
                alignItems="center"
                justifyContent="center"
                bordered
              >
                <Icon
                  size="s"
                  color="foreground"
                  name={isExpanded ? 'caretUp' : 'caretDown'}
                />
              </Box>
            </Pressable>
          </Box>
        )}
        <Transitioner step={isExpanded ? 'expanded' : 'collapsed'}>
          <VStack key="expanded">
            <Summary
              campaignAmount={campaignAmount}
              paymentMethods={paymentMethods}
              queryRef={query}
              isGamificationEligible={eligibleForGamification}
              madeFirstBuy={firstBuyCompleted}
              wheelSpinAvailable={wheelSpinAvailable}
            />
            <VStack
              spacingVertical={
                checklistState.checklistComplete || isPhone ? 3 : 5
              }
            >
              {!isPhone && !checklistState.checklistComplete ? (
                <Divider direction="horizontal" />
              ) : null}
            </VStack>
            <Checklist
              checklistState={checklistState}
              campaignAmount={campaignAmount}
              queryRef={query}
              isGamificationEligible={eligibleForGamification}
              wheelSpinAvailable={wheelSpinAvailable}
              madeFirstBuy={firstBuyCompleted}
              navigateToAction={navigateToAction}
            />
          </VStack>
          <Summary
            isCollapsed
            key="collapsed"
            campaignAmount={campaignAmount}
            paymentMethods={paymentMethods}
            queryRef={query}
            isGamificationEligible={eligibleForGamification}
            madeFirstBuy={firstBuyCompleted}
            wheelSpinAvailable={wheelSpinAvailable}
          />
        </Transitioner>
      </VStack>
      <Divider />
      <InfoLinksSection
        isGamificationEligible={eligibleForGamification}
        bordered={false}
      />
      {borderedBottom && <Divider />}
    </>
  );
}

export default AccountChecklistContent;

import React, { useMemo, useCallback, memo } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { useHistory } from 'react-router-dom';
import styled from 'styled-components';

import { ApiError } from '@cb/shared/components/RelayProvider';
import Transitioner from '@cb/shared/components/Transitioner';
import devices from '@cb/shared/styles/devices';
import { theme } from '@cb/shared/styles/theme';
import { useToggler } from '@cb/shared/utils';
import useScreenMatch from '@cb/shared/utils/useScreenMatch';
import { Button } from '@cbhq/cds-web/buttons/Button';
import { Icon } from '@cbhq/cds-web/icons/Icon';
import { NavigationIcon } from '@cbhq/cds-web/icons/NavigationIcon';
import { Box } from '@cbhq/cds-web/layout/Box';
import { HStack } from '@cbhq/cds-web/layout/HStack';
import { VStack } from '@cbhq/cds-web/layout/VStack';
import { Pressable } from '@cbhq/cds-web/system/Pressable';
import { PressableOpacity } from '@cbhq/cds-web/system/PressableOpacity';
import { spacing } from '@cbhq/cds-web/tokens';
import { TextBody } from '@cbhq/cds-web/typography';
import { TextHeadline } from '@cbhq/cds-web/typography/TextHeadline';
import { TextLabel1 } from '@cbhq/cds-web/typography/TextLabel1';
import { TextLabel2 } from '@cbhq/cds-web/typography/TextLabel2';
import { graphql, useFragment } from '@cbhq/data-layer';

import { CtaActionId } from 'components/AccountChecklist/hooks/useAccountChecklistState';
import { useHasGamificationUsdIncentive } from 'views/Gamification/useHasGamificationUsdIncentive';

import { ActionIds } from '../../constants';
import {
  logChecklistItemClickEvent,
  useChecklistItemView,
} from '../../hooks/AccountChecklistAnalytics';
import { CampaignAmount } from '../../hooks/useCampaign';
import { ChecklistItemFragment$key } from './__generated__/ChecklistItemFragment.graphql';
import {
  messages as checklistItemsMessages,
  Status,
  useIncompleteChecklistItem,
} from './useIncompleteChecklistItem';

const i18nKey = 'AccountChecklistItem';

const messages = defineMessages({
  linkText: {
    id: `${i18nKey}.linkText`,
    defaultMessage: 'Why is this important?',
    description: `#Component: TextBody
    #CharLimit: 60
    #Context: Text for learn more section`,
  },
  learnMore: {
    id: `${i18nKey}.learnMore`,
    defaultMessage: 'Learn more',
    description: `#Component: TextBody
    #CharLimit: 45
    #Context: Text for learn more section`,
  },
  gamificationChecklistCompleteCta: {
    id: `${i18nKey}.gamificationChecklistCompleteCta`,
    defaultMessage: 'Spin the wheel',
    description: `#Component: Button
    #CharLimit: 50
    #Context: CTA after gamification eligible users have completed checklist`,
  },
  rewardWillBeReadySoon: {
    id: `${i18nKey}.rewardWillBeReadySoon`,
    defaultMessage: 'Your reward will be ready soon',
    description: `#Component: TextHeadline
    #CharLimit: 70
    #Context: Text for checklist step after making first buy indicating reward will be ready soon`,
  },
  tradeVerifyingSubtitle: {
    id: `${i18nKey}.tradeVerifyingSubtitle`,
    defaultMessage: "We're working on it!",
    description: `#Component: TextHeadline
    #CharLimit: 55
    #Context: We're working on it!`,
  },
  // 2023-10-05: TODO please fix, see go/i18n-linter-messages
  // eslint-disable-next-line @cbhq/i18n-enhanced-description
  gamificationFirstBuySubtitleAsset: {
    id: `${i18nKey}.gamificationFirstBuySubtitleAsset`,
    defaultMessage: 'Earn up to $200 {asset} after your first buy',
    description:
      'Subtitle for first buy step for new user gamification incentive',
  },
  // 2023-10-05: TODO please fix, see go/i18n-linter-messages
  // eslint-disable-next-line @cbhq/i18n-enhanced-description
  depositSuccessful: {
    id: `${i18nKey}.depositSuccessful`,
    defaultMessage: 'Deposit successful',
    description: 'Title for successful deposit cell',
  },
});

export type ChecklistActionItem = {
  actionId: ActionIds;
  title: string;
  subtitle: string;
  ctaUrl?: string;
  ctaText?: string;
};

type ChecklistItemProps = {
  campaignAmount: CampaignAmount | null;
  action: ChecklistActionItem;
  actionId: CtaActionId;
  isLeadAction: boolean;
  overrideStatus: Status;
  isGamificationEligible: boolean;
  wheelSpinAvailable: boolean;
  cardIndex: number;
  madeFirstBuy: boolean;
  navigateToAction: (actionId: CtaActionId) => void;
  queryRef: ChecklistItemFragment$key;
};

function ChecklistItem({
  campaignAmount,
  action,
  actionId,
  isLeadAction,
  overrideStatus,
  isGamificationEligible,
  wheelSpinAvailable,
  cardIndex,
  madeFirstBuy,
  navigateToAction,
  queryRef,
}: ChecklistItemProps) {
  if (!action) {
    throw new ApiError('AccountChecklistAction was not returned');
  }

  const query = useFragment(
    graphql`
      fragment ChecklistItemFragment on Query {
        ...useHasGamificationUsdIncentiveFragment
      }
    `,
    queryRef,
  );

  const hasGamificationUsdIncentive = useHasGamificationUsdIncentive(query);

  useChecklistItemView({
    actionId: actionId || 'undefined',
    status: overrideStatus || 'undefined',
    type: 'primary',
    cardIndex,
  });

  switch (overrideStatus) {
    case 'COMPLETED':
      return (
        <CompletedItem
          actionId={actionId}
          action={action}
          isGamificationEligible={isGamificationEligible}
          wheelSpinAvailable={wheelSpinAvailable}
          cardIndex={cardIndex}
          madeFirstBuy={madeFirstBuy}
        />
      );
    case 'NOT_STARTED':
    case 'FAILED':
      return (
        <IncompleteItem
          actionId={actionId}
          campaignAmount={campaignAmount}
          action={action}
          isLeadAction={isLeadAction}
          overrideStatus={overrideStatus}
          isGamificationEligible={isGamificationEligible}
          cardIndex={cardIndex}
          navigateToAction={navigateToAction}
          hasGamificationUsdIncentive={hasGamificationUsdIncentive}
        />
      );
    case 'IN_PROGRESS':
      return (
        <ProcessingItem
          actionId={actionId}
          action={action}
          cardIndex={cardIndex}
          isGamificationEligible={isGamificationEligible}
          navigateToAction={navigateToAction}
          hasGamificationUsdIncentive={hasGamificationUsdIncentive}
        />
      );
    default:
      return null;
  }
}

type IconProps = {
  iconName:
    | 'error'
    | 'identityCard'
    | 'card'
    | 'firstBuy'
    | 'cash'
    | 'currencies'
    | undefined;
};

function IncompleteItemIcon({ iconName }: IconProps) {
  switch (iconName) {
    case 'error':
      return (
        <IconBorder>
          <Icon name="error" color="negative" size="xs" />
        </IconBorder>
      );
    case 'identityCard':
      return (
        <Icon
          name="identityCard"
          spacingTop={1}
          spacingEnd={2}
          size="m"
          color="foreground"
        />
      );
    case 'card':
      return (
        <Icon
          name="card"
          spacingTop={1}
          spacingEnd={2}
          size="m"
          color="foreground"
        />
      );
    case 'firstBuy':
      return <NavigationIcon name="gab" spacingTop={1} spacingEnd={2} />;
    case 'currencies':
      return (
        <Icon
          name="currencies"
          spacingTop={1}
          spacingEnd={2}
          size="m"
          color="foreground"
        />
      );
    case 'cash':
      return (
        <Icon
          name="cash"
          spacingTop={1}
          spacingEnd={2}
          size="m"
          color="foreground"
        />
      );
    default:
      return null;
  }
}

type Props = {
  action: ChecklistActionItem;
  actionId: CtaActionId;
  isLeadAction?: boolean;
  overrideStatus: Status;
  isGamificationEligible?: boolean;
  wheelSpinAvailable?: boolean;
  cardIndex: number;
  madeFirstBuy: boolean;
  navigateToAction: (actionId: CtaActionId) => void;
  hasGamificationUsdIncentive?: boolean;
};

type IncompleteItemProps = {
  campaignAmount: CampaignAmount | null;
  action: ChecklistActionItem;
  actionId: CtaActionId;
  isLeadAction?: boolean;
  overrideStatus: 'NOT_STARTED' | 'FAILED';
  isGamificationEligible: boolean;
  cardIndex: number;
  navigateToAction: (actionId: CtaActionId) => void;
  hasGamificationUsdIncentive: boolean;
};

function IncompleteItem({
  campaignAmount,
  action,
  actionId,
  isLeadAction,
  overrideStatus,
  isGamificationEligible,
  cardIndex,
  navigateToAction,
  hasGamificationUsdIncentive,
}: IncompleteItemProps) {
  const showsCta = isLeadAction;

  const actionDetails = useIncompleteChecklistItem(
    campaignAmount,
    action,
    actionId,
    overrideStatus,
    isGamificationEligible,
    hasGamificationUsdIncentive,
  );

  const onClick = useCallback(() => {
    logChecklistItemClickEvent({
      actionId: actionId || 'undefined',
      type: 'primary',
      cardIndex,
    });

    navigateToAction(actionId);
  }, [actionId, cardIndex, navigateToAction]);

  const iconName = useMemo(() => {
    if (overrideStatus === 'FAILED') {
      return 'error';
    }

    switch (actionId) {
      case ActionIds.kyc:
        return 'identityCard' as const;

      case ActionIds.paymentMethod:
        return 'card' as const;

      case ActionIds.firstBuy:
        return 'firstBuy' as const;

      case ActionIds.deposit:
        return 'cash' as const;

      default:
        return;
    }
  }, [actionId, overrideStatus]);

  return (
    <IncompleteItemRenderer
      iconName={iconName}
      title={actionDetails.title || action.title}
      subtitle={actionDetails.subtitle}
      description={actionDetails.description}
      linkText={actionDetails.linkText}
      isLeadAction={isLeadAction}
      onClick={onClick}
      showsCta={showsCta}
      ctaText={actionDetails.ctaText}
      isGamificationEligible={isGamificationEligible}
    />
  );
}

type IncompleteItemRendererProps = {
  iconName?:
    | 'error'
    | 'identityCard'
    | 'card'
    | 'firstBuy'
    | 'cash'
    | 'currencies';
  title: string;
  subtitle: string;
  description?: string;
  linkText?: string;
  isLeadAction?: boolean;
  onClick: () => void;
  showsCta?: boolean;
  ctaText?: string;
  isCtaDisabled?: boolean;
  isGamificationEligible?: boolean;
};

const IncompleteItemRenderer = memo(function IncompleteItemRenderer({
  iconName,
  title,
  subtitle,
  description,
  linkText,
  isLeadAction,
  onClick,
  ctaText,
  showsCta,
  isCtaDisabled = false,
  isGamificationEligible,
}: IncompleteItemRendererProps) {
  const { formatMessage } = useIntl();
  const isPhone = useScreenMatch('phone_small');
  const { isToggled: isExpanded, toggle: onToggleExpand } = useToggler(false);
  const canExpand = !!description;
  return (
    <Box spacingVertical={1}>
      <HStack flexGrow={1} width={100}>
        <IncompleteItemIcon iconName={iconName} />
        <VStack flexGrow={1}>
          <HStack justifyContent="space-between" alignItems="center">
            <VStack>
              <TextHeadline as="p">{title}</TextHeadline>
              <TextBody as="p" spacingBottom={1} color="foregroundMuted">
                {subtitle}
              </TextBody>
              {!!canExpand && (
                <PressableOpacity as="button" onPress={onToggleExpand}>
                  <HStack alignItems="center">
                    <TextBody
                      as="p"
                      color={isExpanded ? 'foregroundMuted' : 'primary'}
                    >
                      {iconName === 'currencies' ||
                      (isGamificationEligible && iconName === 'firstBuy')
                        ? formatMessage(messages.learnMore)
                        : linkText || formatMessage(messages.linkText)}
                    </TextBody>
                    <Icon
                      name={isExpanded ? 'caretUp' : 'caretDown'}
                      color={isExpanded ? 'foregroundMuted' : 'primary'}
                      size="xs"
                      spacingStart={0.5}
                    />
                  </HStack>
                </PressableOpacity>
              )}
            </VStack>
            {!isPhone && showsCta && ctaText && (
              <Button
                onPress={onClick}
                variant={isLeadAction ? 'primary' : 'secondary'}
                disabled={isCtaDisabled}
              >
                {ctaText}
              </Button>
            )}
          </HStack>
          <Transitioner step={isExpanded ? 'expanded' : 'collapsed'}>
            <Box spacingTop={1} key="expanded">
              <GrayWashBox isMobile={isPhone} column>
                <TextLabel2 as="p">{description}</TextLabel2>
                {isPhone && showsCta && ctaText && (
                  <PressableOpacity onPress={onClick}>
                    <HStack alignItems="center" spacingTop={2}>
                      <TextLabel1 as="p" color="primary" noWrap>
                        {ctaText}{' '}
                      </TextLabel1>
                      <Icon name="caretRight" size="xs" spacingStart={0.5} />
                    </HStack>
                  </PressableOpacity>
                )}
              </GrayWashBox>
            </Box>
          </Transitioner>
        </VStack>
      </HStack>
    </Box>
  );
});

function CompletedItem({
  action,
  actionId,
  isGamificationEligible,
  wheelSpinAvailable,
  madeFirstBuy,
}: Omit<Props, 'navigateToAction' | 'overrideStatus'>) {
  const { formatMessage } = useIntl();
  // The logic here is complicated due to there being no way to hook into a specific action without
  // modifying nux. If the gamification experiment is active, the checklist will stay open after the
  // first buy is made. We need to manipulate the last step of the checklist to display a
  // "pending" state before the transaction clears (hence PendingCompletedTradeRenderer) and
  // a completed state with a button to redeem their reward (a wheel spin).
  //
  // In addition, there is a delay from when the transaction is made to when it clears, usually
  // 1-24 hours long. Once it does clear, nux creates a user checklist item record which then
  // changes the "first trade" step's title. That's why we check against two different strings:
  // One for the before the transaction clears/completes ("Buy your first crypto") and one after
  // it clears ("You earned ").
  //
  // This requires knowing:
  // 1. What step they are in via the text present in the title
  // 2. If they are part of the gamification experiment
  // 3. If they have made a first buy
  // 4. If a wheel spin is available
  let title = action.title;
  const isFirstTradeStep =
    title.includes('You earned ') || title.includes('Buy your first crypto');

  if (actionId === ActionIds.deposit) {
    title = formatMessage(messages.depositSuccessful);
  } else if (isGamificationEligible && isFirstTradeStep && madeFirstBuy) {
    if (!wheelSpinAvailable) {
      return <PendingCompletedTradeRenderer />;
    }

    title = 'First trade completed';
  }

  return (
    <CompletedItemRenderer
      title={title}
      isGamificationEligible={isGamificationEligible}
      wheelSpinAvailable={wheelSpinAvailable}
    />
  );
}

type CompletedItemRendererProps = {
  title: string;
  isGamificationEligible?: boolean;
  wheelSpinAvailable?: boolean;
};

const CompletedItemRenderer = memo(function CompletedItemRenderer({
  title,
  isGamificationEligible,
  wheelSpinAvailable,
}: CompletedItemRendererProps) {
  const { formatMessage } = useIntl();

  const handleOnPress = useCallback(() => {
    window.open('/rewards/spin-the-wheel');
  }, []);

  return (
    <HStack spacingVertical={1}>
      <Icon name="circleCheckmark" size="m" color="positive" spacingEnd={2} />
      <TextHeadline as="p" color="foregroundMuted">
        {title}
      </TextHeadline>
      {isGamificationEligible &&
      wheelSpinAvailable &&
      title === 'First trade completed' ? (
        <ButtonWrapper>
          <Button variant="primary" onPress={handleOnPress}>
            {formatMessage(messages.gamificationChecklistCompleteCta)}
          </Button>
        </ButtonWrapper>
      ) : null}
    </HStack>
  );
});

const PendingCompletedTradeRenderer = memo(
  function PendingCompletedTradeRenderer() {
    const isPhone = useScreenMatch('phone_small');
    const { formatMessage } = useIntl();
    return (
      <GrayWashBox isMobile={isPhone}>
        <HStack alignItems="center">
          <Icon
            name="convert"
            size="m"
            color="foregroundMuted"
            spacingEnd={2}
          />
          <VStack>
            <TextHeadline as="p" color="foreground">
              {formatMessage(messages.rewardWillBeReadySoon)}
            </TextHeadline>
            <TextHeadline as="p" color="foregroundMuted">
              {formatMessage(messages.tradeVerifyingSubtitle)}
            </TextHeadline>
          </VStack>
        </HStack>
      </GrayWashBox>
    );
  },
);

function ProcessingItem({
  action,
  actionId,
  cardIndex,
  isGamificationEligible,
  navigateToAction,
  hasGamificationUsdIncentive,
}: Omit<Props, 'overrideStatus' | 'madeFirstBuy'>) {
  const { formatMessage } = useIntl();
  const history = useHistory();

  const actionDetails = ((): { title: string; subtitle: string } => {
    switch (actionId) {
      case ActionIds.paymentMethod:
      case ActionIds.deposit:
        return {
          title: formatMessage(checklistItemsMessages.pendingTitlePayment),
          subtitle: formatMessage(
            checklistItemsMessages.pendingSubtitlePayment,
          ),
        };

      case ActionIds.firstBuy:
        return {
          title: action.title,
          subtitle: isGamificationEligible
            ? formatMessage(messages.gamificationFirstBuySubtitleAsset, {
                asset: hasGamificationUsdIncentive ? 'USD' : 'BTC',
              })
            : action.subtitle,
        };

      default:
        return {
          title: action.title,
          subtitle: action.subtitle,
        };
    }
  })();

  const isPhone = useScreenMatch('phone_small');

  const onClick = useCallback(() => {
    logChecklistItemClickEvent({
      actionId: actionId || 'undefined',
      type: 'primary',
      cardIndex,
    });

    switch (actionId) {
      case ActionIds.paymentMethod:
      case ActionIds.deposit: {
        history.push('/settings/linked-accounts');
        return;
      }

      default: {
        if (action.ctaUrl) {
          history.push(action.ctaUrl);
        } else {
          navigateToAction(actionId);
        }
        return;
      }
    }
  }, [actionId, cardIndex, history, action.ctaUrl, navigateToAction]);

  return (
    <Pressable background="background" as="button" onPress={onClick}>
      <Box
        borderRadius={!isPhone ? 'rounded' : undefined}
        bordered={!isPhone}
        spacingVertical={2}
        spacingHorizontal={3}
      >
        <HStack justifyContent="space-between" alignItems="center" flexGrow={1}>
          <HStack>
            <IconBorder>
              <Icon name="convert" size="xs" color="foregroundMuted" />
            </IconBorder>
            <VStack>
              <TextHeadline as="p">{actionDetails.title}</TextHeadline>
              <TextBody as="p" color="foregroundMuted">
                {actionDetails.subtitle}
              </TextBody>
            </VStack>
          </HStack>
          <Icon
            name="caretRight"
            size={isPhone ? 's' : 'm'}
            color="foregroundMuted"
          />
        </HStack>
      </Box>
    </Pressable>
  );
}

type IconBorderProps = {
  children: React.ReactNode;
};

function IconBorder({ children }: IconBorderProps) {
  return (
    <Box spacingEnd={2} spacingTop={1}>
      <Box
        width={25}
        height={25}
        borderRadius="roundedFull"
        bordered
        alignItems="center"
        justifyContent="center"
      >
