type Props = {
  availablePaymentMethods: AvailablePaymentMethod[];
  renderLinkedAccountModal: (
    accountType: PaymentMethodType | LowerCasePaymentMethodTypeV2,
  ) => JSX.Element;
  customHeaderText?: string;
  handleChooseAccount: (
    type:
      | PaymentMethodType
      | LowerCasePaymentMethodTypeV2
      | CustomPaymentMethodType,
  ) => void;
  close?: () => void;
  entryPoint: PaymentsModalEntryPoints;
  dateOfBirth: string;
  countryCode?: string;
  transferTypes?: AvailablePaymentMethod['supports'];
};

const AUTO_TRIGGER_PAYMENT_METHODS: Partial<AvailablePaymentMethod['type']>[] =
  ['pix_withdrawal', 'zengin_withdrawal'];

function AddLinkedAccountPicker({
  availablePaymentMethods,
  renderLinkedAccountModal,
  customHeaderText,
  handleChooseAccount,
  close,
  entryPoint,
  dateOfBirth,
  countryCode,
  transferTypes,
}: Props) {
  const { formatNumber, formatMessage } = useIntl();

  availablePaymentMethods.sort(function (x) {
    if (countryCode === 'BR' && x.type === 'pix_deposit') {
      return -100;
    }

    return 0;
  });

  const feeLink = useFeeLink(countryCode);

  const handleKeyDown = useCallback(
    (event: React.KeyboardEvent<HTMLDivElement>) => {
      const pressedEnterKey = event.keyCode === 13;
      const pressedSpaceKey = event.keyCode === 32;

      if ((pressedEnterKey || pressedSpaceKey) && event.currentTarget) {
        event.currentTarget.click();
      }
    },
    [],
  );

  const renderFeeText = (paymentMethodType: string, additionalFees: string) => {
    return (
      Number(additionalFees) >= 2.5 && (
        <HStack>
          <TextLabel2 as="p" aria-hidden="true" spacingHorizontal={1}>
            |
          </TextLabel2>
          <TextLabel2 as="p" color="warning">
            {formatMessage(messages.fee, {
              amount: formatNumber(Number(additionalFees), {
                style: 'decimal',
                maximumFractionDigits: 1,
              }),
            })}
          </TextLabel2>
        </HStack>
      )
    );
  };

  const autoTriggerChooseAccount =
    availablePaymentMethods.length === 1 &&
    AUTO_TRIGGER_PAYMENT_METHODS.find(
      t => t === availablePaymentMethods[0].type,
    );

  const renderLinkedAccountOption = (paymentMethod: AvailablePaymentMethod) => {
    const {
      name,
      type,
      description,
      additionalFees,
      recommended,
      buyingPower,
    } = paymentMethod;

    if (type === 'open_banking') {
      logEvent('open_banking_viewed', {
        componentType: ComponentType.card,
        action: ActionType.render,
        entryPoint,
        countryCode: countryCode ?? '',
      });
    }

    logEvent('payment_method_viewed', {
      componentType: ComponentType.card,
      action: ActionType.render,
      payment_method: type,
      countryCode: countryCode ?? '',
    });

    const isNew = type === 'direct_deposit';

    const normalInvestText = (
      <TextLabel2 as="p" color="foreground">
        {buyingPower?.text}
      </TextLabel2>
    );
    const positiveInvestText = (
      <TextLabel2 as="p" color="positive">
        {buyingPower?.text}
      </TextLabel2>
    );
    const limitValues: Record<string, React.ReactNode> = {
      credit_card: normalInvestText,
      worldpay_card: normalInvestText,
      fiat_account: positiveInvestText,
      ach_bank_account: positiveInvestText,
      sepa_bank_account: positiveInvestText,
      sepa_v2: positiveInvestText,
      uk_bank_account: positiveInvestText,
      paypal_account: normalInvestText,
      fedwire: normalInvestText,
      gift_card: normalInvestText,
      direct_deposit: normalInvestText,
      zepto: positiveInvestText,
      open_banking: positiveInvestText,
      eft: normalInvestText,
      bancomat_pay: normalInvestText,
      interac: positiveInvestText,
    };

    return (
      <StyledModalTrigger
        modal={
          type !== 'direct_deposit' ? (
            <PaymentScamWarning
              paymentMethod={type}
              entryPoint={entryPoint}
              // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
              onContinue={() => renderLinkedAccountModal(type)}
              dateOfBirth={dateOfBirth}
            />
          ) : null
        }
        forceShowModal={Boolean(autoTriggerChooseAccount)}
        key={type}
      >
        <AccountOption
          position="relative"
          alignItems="stretch"
          width="100%"
          id={type}
          role="button"
          tabIndex={0}
          // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
          onClick={() => handleChooseAccount(type)}
          // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
          onKeyDown={(e: React.KeyboardEvent<HTMLDivElement>) =>
            handleKeyDown(e)
          }
          testID={`modal-trigger-payment-${type.replace(/_/g, '-')}`}
        >
          <Icon type={type} size={42} />
          <StyledVStack spacingHorizontal={3} role="none">
            <TextHeadline as="p">
              {name === 'Interac e-Transfer'
                ? formatMessage(messages.interac, {
                    i: (contents: React.ReactNode) => [<i>{contents}</i>],
                  })
                : name}
            </TextHeadline>
            <HStack role="none">
              {limitValues[type]}
              {renderFeeText(type, additionalFees)}
            </HStack>
            <TextLabel2 as="p" color="foregroundMuted" spacingTop={1}>
              {description}
            </TextLabel2>
            {recommended && (
              <Box spacingTop={1.5}>
                <Tag intent="informational">
                  {formatMessage(messages.recommendedTag)}
                </Tag>
              </Box>
            )}
            {isNew && (
              <Box spacingTop={1.5}>
                <Tag intent="informational">
                  {formatMessage(messages.newTag)}
                </Tag>
              </Box>
            )}
          </StyledVStack>
          <HStack alignItems="center" aria-hidden="true" role="none">
            <AddIcon role="none" focusable="false" aria-hidden="true" />
          </HStack>
        </AccountOption>
      </StyledModalTrigger>
    );
  };
  useEffect(() => {
    // Auto select  if its the only option being rendered
    if (autoTriggerChooseAccount) {
      handleChooseAccount(autoTriggerChooseAccount);
    }
  }, [autoTriggerChooseAccount, handleChooseAccount]);

  const paymentMethodV2UIEnabled = useIsPaymentMethodV2UIEnabled({
    countryCode,
  });

  return (
    <>
      <SystemAlert view="ADD_PAYMENT" />
      <ModalHeader
        title={customHeaderText ?? formatMessage(messages.addALinkedAccount)}
      />
      {availablePaymentMethods.length === 0 ? (
        <NoAvailablePaymentMethods
          aria-label={formatMessage(messages.noAvailablePaymentMethods)}
          close={close}
        />
      ) : (
        <>
          {!paymentMethodV2UIEnabled ? (
            <VStack
              aria-hidden="true"
              role="none"
              testID="availablePaymentMethodCellContentV1"
            >
              {availablePaymentMethods.map(renderLinkedAccountOption)}
            </VStack>
          ) : (
            <AvailablePaymentMethodSectionWiseList
              availablePaymentMethods={availablePaymentMethods}
              entryPoint={entryPoint}
              dateOfBirth={dateOfBirth}
              renderLinkedAccountModal={renderLinkedAccountModal}
              autoTriggerChooseAccount={Boolean(autoTriggerChooseAccount)}
              handleChooseAccount={handleChooseAccount}
              transferTypes={transferTypes}
            />
          )}
          <StyledModalFooter aria-hidden="true" role="none">
            <TextLegal as="p" color="foregroundMuted" testID="footnote">
              {formatMessage(messages.footNote, {
                feesLink: (
                  <Link
                    aria-label={formatMessage(messages.feeLinkAriaLabel)}
                    role="link"
                    href={feeLink}
                    target="_blank"
                  >
                    {formatMessage(messages.footNoteLink)}
                  </Link>
                ),
              })}
            </TextLegal>
          </StyledModalFooter>
        </>
      )}
    </>
  );
}

