import { useMemo, useCallback, useState, useEffect } from 'react';
import { useSubmitComplianceAnswers } from '@cb/onboarding/components/ComplianceQuestions/hooks/useSubmitComplianceAnswers';
import { useOnboardingContext } from '@cb/onboarding/Context';
import { IconButton } from '@cbhq/cds-web/buttons';
import { Box } from '@cbhq/cds-web/layout';
import {
  ActionType,
  ComponentType,
  logEvent,
  useLogEventOnMount,
} from '@cbhq/client-analytics';

import { useLayoutContext } from 'context/LayoutContext';
import { AssessmentProps, QuizQuestionProps } from 'types/AppropriatenessTest';
import {
  logAppropriatenessAssessmentSubmitFailure,
  logAppropriatenessAssessmentSubmitSuccess,
} from 'views/AppropriatenessTest/analytics';

import QuizQuestion from './common/QuizQuestion';

export default function Assessment({
  questions,
  goBackOnFirstQuestion,
  onAssessmentPass,
  onAssessmentFailure,
  onSubmitError,
}: AssessmentProps) {
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [isLoading, setIsLoading] = useState(false);
  const submitQA = useSubmitComplianceAnswers();
  const { addApiError } = useOnboardingContext();
  const { setDashedProgress, showProgress } = useLayoutContext();

  useLogEventOnMount('appropriateness_assessment_questions_page_view', {
    componentType: ComponentType.page,
    action: ActionType.render,
  });

  const submitAnswers = useCallback(() => {
    logEvent('appropriateness_assessment_questions_completed', {
      action: ActionType.click,
      componentType: ComponentType.button,
    });

    setIsLoading(true);
    const flattenedAnswers = Object.entries(answers).map(([key, value]) => ({
      answerOption: {
        subtitle: '',
        title: '',
        value: value || '',
      },
      questionUuid: key,
    }));

    submitQA({
      type: 'APPROPRIATENESS_ASSESSMENT',
      answers: flattenedAnswers,
    })
      .then(response => {
        if (
          response?.__typename === 'SubmitGenericComplianceAnswersByTypeSuccess'
        ) {
          //TODO: Handle generic error case here
          if (response?.metaData?.status === 'SUCCESS') {
            logAppropriatenessAssessmentSubmitSuccess();
            onAssessmentPass();
          } else {
            logAppropriatenessAssessmentSubmitFailure(
              response?.metaData?.status,
            );
            onAssessmentFailure(!!response?.metaData?.hasExceededMaxAttempts);
          }
        }
      })
      .catch(e => {
        logAppropriatenessAssessmentSubmitFailure(e);
        addApiError(e);
        onSubmitError();
      })
      .finally(() => setIsLoading(false));
  }, [
    answers,
    submitQA,
    addApiError,
    setIsLoading,
    onAssessmentPass,
    onAssessmentFailure,
    onSubmitError,
  ]);

  const handleGoBack = useCallback(() => {
    if (currentQuestionIndex > 0) {
      setCurrentQuestionIndex(currentQuestionIndex - 1);
    } else goBackOnFirstQuestion();
  }, [currentQuestionIndex, goBackOnFirstQuestion]);

  const handleContinue = useCallback(() => {
    if (currentQuestionIndex < questions.length - 1) {
      setCurrentQuestionIndex(currentQuestionIndex + 1);
    } else submitAnswers();
  }, [currentQuestionIndex, submitAnswers, questions]);

  useEffect(() => {
    showProgress('dashed');

    return () => {
      showProgress('none');
    };
  }, []);

  useEffect(() => {
    setDashedProgress({
      progress: 0.5,
      progressBarNumber: currentQuestionIndex + 1,
      totalProgressBars: questions.length,
    });
  }, [currentQuestionIndex]);

  const quizQuestionsProps: QuizQuestionProps = useMemo(
    () =>
      ({
        question: questions[currentQuestionIndex],
        onContinue: handleContinue,
        answers,
        setAnswers,
        isLoading,
        isLast: currentQuestionIndex === questions.length - 1,
      } as QuizQuestionProps),
    [
      questions,
      currentQuestionIndex,
      handleContinue,
      answers,
      setAnswers,
      isLoading,
    ],
  );

  return (
    <Box position="relative" offsetTop={2}>
      <Box position="absolute" left="-64px" top="8px">
        <IconButton
          variant="secondary"
          name="backArrow"
          testID="back-arrow"
          onPress={handleGoBack}
        />
      </Box>
      <QuizQuestion {...quizQuestionsProps} />
    </Box>
  );
}

