      fragment EntryInputFragment on ViewerAsset {
        asset {
          exponent
        }
      }
    `,
    viewerAssetRef as EntryInputFragment$key,
  );

  const { nativeCurrency, countryCode } = useUser();
  const { formatNumber, formatMessage, locale } = useIntl();
  const {
    symbol,
    displaySymbol,
    value,
    onChange,
    onEnter,
    onFocus,
    onBlur,
    readOnly = false,
    noCommas,
  } = input;
  const fiatPrecision = 2;
  const isNativeCurrency = nativeCurrency === symbol;
  const asset = viewerAsset?.asset;
  const isCrypto = isCryptoCurrency ?? (!isNativeCurrency && !!asset);
  const precision = isCrypto ? asset?.exponent || 8 : fiatPrecision;

  const canUseNewLocalizedCurrencyInput = useNewLocalizedCurrencyInput();
  const newLocalizedCurrencyInput =
    !isCrypto && canUseNewLocalizedCurrencyInput;

  const { decimalSeparator, groupSeparator } = useMemo(
    () => getLocaleConfig({ locale }),
    [locale],
  );

  const {
    displayLocalizedValue,
    handleLocalizedChange,
    handleLocalizedBlur,
    updateInputCursorPosition,
    clearFormattedValue,
  } = useLocalizedEntryInput({
    value,
    decimalSeparator,
    fiatPrecision,
    onBlur,
    onChange,
    newLocalizedCurrencyInput,
  });

  const defaultDisplayValue = !noCommas
    ? formatDisplayValue(value, decimalSeparator, groupSeparator)
    : value;

  const {
    displayValue,
    handleChange,
    handleBlur,
    handleUpdateInputCallback,
    handleClearFormattedValue,
  } = useMemo(
    () => ({
      displayValue: newLocalizedCurrencyInput
        ? displayLocalizedValue
        : defaultDisplayValue,
      handleChange: newLocalizedCurrencyInput
        ? handleLocalizedChange
        : onChange,
      handleBlur: newLocalizedCurrencyInput ? handleLocalizedBlur : onBlur,
      handleUpdateInputCallback: newLocalizedCurrencyInput
        ? updateInputCursorPosition
        : undefined,
      handleClearFormattedValue: newLocalizedCurrencyInput
        ? clearFormattedValue
        : undefined,
    }),
    [
      newLocalizedCurrencyInput,
      displayLocalizedValue,
      defaultDisplayValue,
      handleLocalizedChange,
      onChange,
      handleLocalizedBlur,
      onBlur,
      updateInputCursorPosition,
      clearFormattedValue,
    ],
  );

  const isCanadaExtendedCDDEligible =
    useIsCanadaExtendedCDDEligible(countryCode);
  const hasError = !!error && error !== '';
  // The backend doesn't translate the error message, nor send an error code.
  // And we want a more readable error message.
  const errorMessage =
    error === 'Invalid JWT token'
      ? formatMessage(messages.invalidJWTToken)
      : error;

  const trasferBuy = transferType === 'buy';
  // These numbers are for keeping the modal height unchanged
  const errorBoxHeight = trasferBuy ? '84px' : '36px';

  const textUnderInput = useMemo(() => {
    if (hasError) {
      return (
        <Box
          height={errorBoxHeight}
          justifyContent="center"
          alignItems="center"
        >
          <CaptionText
            testID={
              transferType
                ? `${transferType}-trade-inline-error-text`
                : 'trade-inline-error-text'
            }
          >
            {errorMessage}
            {additionalInfo && onAdditionalInfoClick && (
              // TODO this should use CDS Link when it's ready
              <CaptionText
                spacingStart={0.5}
                underline
                onClick={onAdditionalInfoClick}
              >
                {additionalInfo.prompt}
              </CaptionText>
            )}
          </CaptionText>
        </Box>
      );
    }

    if (helperText && !isCanadaExtendedCDDEligible) {
      return <CaptionText>{helperText}</CaptionText>;
    }

    return <HStack spacingTop={4} spacingBottom={0.5} />;
  }, [
    hasError,
    helperText,
    errorBoxHeight,
    transferType,
    errorMessage,
    additionalInfo,
    onAdditionalInfoClick,
    isCanadaExtendedCDDEligible,
  ]);

  return (
    <VStack width="100%" spacingBottom={1}>
      <HStack
        as="section"
        position="relative"
        alignItems="center"
        justifyContent="center"
        overflow="hidden"
        spacingBottom={1}
      >
        <FlexibleCurrencyInput
          {...getSymbolForCurrency({
            formatNumber,
            // Use displaySymbol for crypto values
            currency: isCrypto ? displaySymbol ?? '' : symbol,
            isCrypto,
          })}
          placeholder="0"
          value={displayValue}
          maxWidth={230}
          onChange={handleChange}
          onEnter={onEnter}
          autoFocus={autoFocus}
          precision={precision}
          onFocus={onFocus}
          onBlur={handleBlur}
          hasError={hasError}
          readOnly={readOnly}
          transferType={transferType}
          updateInputCallback={handleUpdateInputCallback}
          clearFormattedValue={handleClearFormattedValue}
          transparentBackground={transparentBackground}
          ariaLabel={ariaLabel}
          disabled={disableInput}
        />
        {switchActiveInput && !readOnly && !switchActiveInput.hidden && (
          <SwitchActiveInput
            transferType={transferType}
            {...switchActiveInput}
          />
        )}
      </HStack>
      {textUnderInput}
      {(!hasError || !trasferBuy) && secondaryButton && (
        <HStack alignItems="center" justifyContent="center" spacingBottom={1}>
          {secondaryButton}
        </HStack>
      )}
    </VStack>
  );
}

function EntryInputV2({
  viewerAssetRef,
  input,
  autoFocus = true,
  switchActiveInput,
  transferType,
  isCryptoCurrency,
  secondaryButton,
  ariaLabel,
  error,
}: EntryInputProps) {
  const viewerAsset = useFragment<EntryInputV2Fragment$key>(
    graphql`
      fragment EntryInputV2Fragment on ViewerAsset {
        asset {
          name
        }
        ...useConvertIncrementToPrecisionFragment
      }
    `,
    viewerAssetRef as EntryInputV2Fragment$key,
  );

  const palette = usePalette();
  const gray20 = paletteValueToCssVar('gray20');
  const isDarkMode = useIsDarkMode();
  const { nativeCurrency } = useUser();
  const { formatNumber, locale } = useIntl();
  const {
    symbol,
    displaySymbol,
    value,
    onChange,
    onEnter,
    onFocus,
    onBlur,
    readOnly = false,
    noCommas,
  } = input;
  const isNativeCurrency = nativeCurrency === symbol;
  const { fiatPrecision, cryptoPrecision } =
    useConvertIncrementToPrecision(viewerAsset);
  const asset = viewerAsset?.asset;
  const isCrypto = isCryptoCurrency ?? (!isNativeCurrency && !!asset);
  const precision = isCrypto ? cryptoPrecision : fiatPrecision;

  const canUseNewLocalizedCurrencyInput = useNewLocalizedCurrencyInput();
  const newLocalizedCurrencyInput =
    !isCrypto && canUseNewLocalizedCurrencyInput;

  const { decimalSeparator, groupSeparator } = useMemo(
    () => getLocaleConfig({ locale }),
    [locale],
  );

  const {
    displayLocalizedValue,
    handleLocalizedChange,
    handleLocalizedBlur,
    updateInputCursorPosition,
    clearFormattedValue,
  } = useLocalizedEntryInput({
    value,
    decimalSeparator,
    fiatPrecision,
    onBlur,
    onChange,
    newLocalizedCurrencyInput,
  });

  const defaultDisplayValue = !noCommas
    ? formatDisplayValue(value, decimalSeparator, groupSeparator)
    : value;

  const {
    displayValue,
    handleChange,
    handleBlur,
    handleUpdateInputCallback,
    handleClearFormattedValue,
  } = useMemo(
    () => ({
      displayValue: newLocalizedCurrencyInput
        ? displayLocalizedValue
        : defaultDisplayValue,
      handleChange: newLocalizedCurrencyInput
        ? handleLocalizedChange
        : onChange,
      handleBlur: newLocalizedCurrencyInput ? handleLocalizedBlur : onBlur,
      handleUpdateInputCallback: newLocalizedCurrencyInput
        ? updateInputCursorPosition
        : undefined,
      handleClearFormattedValue: newLocalizedCurrencyInput
        ? clearFormattedValue
        : undefined,
    }),
    [
      newLocalizedCurrencyInput,
      displayLocalizedValue,
      defaultDisplayValue,
      handleLocalizedChange,
      onChange,
      handleLocalizedBlur,
      onBlur,
      updateInputCursorPosition,
      clearFormattedValue,
    ],
  );

  const { formatMessage } = useIntl();
  // The backend doesn't translate the error message, nor send an error code.
  // And we want a more readable error message.
  const errorComponent = useMemo(() => {
    if (!error || error === '') {
      return null;
    }
    if (error === 'Invalid JWT token') {
      return formatMessage(messages.invalidJWTToken);
    }
    if (typeof error === 'string') {
      return <BaseErrorSection error={error} />;
    }
    if (isValidElement(error)) {
      return error;
    }
    return null;
  }, [error, formatMessage]);

  const switchInputButton = useMemo(() => {
    if (!switchActiveInput) {
      return null;
    }
    const swapAmountInNumber = switchActiveInput.inactiveAmount
      ? Number(switchActiveInput.inactiveAmount)
      : 0;
    const swapAmount = formatNumber(swapAmountInNumber, {
      maximumFractionDigits: isCrypto ? fiatPrecision : cryptoPrecision,
    });
    return (
      <Box minHeight={UNDER_INPUT_SECTION_HEIGHT}>
        <BaseSwapCurrenciesButton
          color="buttonFill"
          hideAmount={switchActiveInput.hideAmount}
          disabled={switchActiveInput.disabled}
          onPress={switchActiveInput.onPress}
          swapAmount={swapAmount}
          swapCode={switchActiveInput.inactiveSymbol}
          isSwapEnabled={switchActiveInput.isSwapEnabled}
        />
      </Box>
    );
  }, [
    cryptoPrecision,
    fiatPrecision,
    formatNumber,
    isCrypto,
    switchActiveInput,
  ]);

  const sectionUnderInput = useMemo(() => {
    if (errorComponent) {
      return errorComponent;
    }

    const fallback = <Box height={UNDER_INPUT_SECTION_HEIGHT} />;
    return switchInputButton ?? fallback;
  }, [errorComponent, switchInputButton]);

  return (
    <VStack width="100%">
      <HStack
        as="section"
        position="relative"
        alignItems="center"
        justifyContent="space-between"
        overflow="hidden"
      >
        <FlexibleCurrencyInput
          {...getSymbolForCurrency({
            formatNumber,
            // Use displaySymbol for crypto values
            currency: isCrypto ? displaySymbol ?? '' : symbol,
            isCrypto,
            isNewDesign: true,
          })}
          placeholder="0"
          value={displayValue}
          onChange={handleChange}
          onEnter={onEnter}
          autoFocus={autoFocus}
          precision={precision}
          onFocus={onFocus}
          onBlur={handleBlur}
          readOnly={readOnly}
          transferType={transferType}
          updateInputCallback={handleUpdateInputCallback}
          clearFormattedValue={handleClearFormattedValue}
          transparentBackground
          ariaLabel={ariaLabel}
          align="flex-start"
          alignSelfInput="center"
          color={palette.foreground}
          cursorColor={palette.primary}
          symbolColor={isDarkMode ? palette.foregroundMuted : gray20}
          fontSize={80}
          symbolFontSize={80}
          symbolFontWeight="thin"
          symbolPositionVertical="center"
          minWidth={50}
          inputHeight={isChrome() ? '68px' : 'inherit'}
          superscript={true}
        />
        {secondaryButton}
      </HStack>
      {sectionUnderInput}
    </VStack>
  );
}

