  if (hasDefaultCloseModal && isModal) {
    return (
      <Box position="absolute" right={16}>
        <IconButton
          onPress={closeModal}
          name="close"
          variant="secondary"
          transparent
        />
      </Box>
    );
  }

  return null;
}

