const key = 'TwoAmountsFormV2';

const message = defineMessages({
  information: {
    id: `${key}.information`,
    defaultMessage:
      'Check your card’s activity (ending with {cardLast}) for two pending transactions from Coinbase. To verify your card, enter these two amounts.',
