      #CharLimit: 20
      #Context: Label for the button that submits the card verification
    `,
  },
  cantFindDeposit: {
    id: `${key}.cantFindDeposit`,
    defaultMessage: "I can't find these deposits",
    description: `
      #Component: Button
      #CharLimit: 30
      #Context: Label for the button that opens a help page
    `,
  },
  success: {
    id: `${key}.success`,
    defaultMessage: 'Debit card successfully verified!',
    description: `
      #Component: Toast
      #CharLimit: 50
      #Context: Success message after a debit card has been verified
    `,
  },
});

function TwoAmountsFormV2({
  paymentMethod,
  onClose,
  onSuccess,
}: TwoAmountsFormProps) {
  const { formatMessage } = useIntl();
  const { showSuccessToast, showErrorToast } = useToast();
  const { logAddPaymentEvent } = useAddPaymentMethodUtils();

  const [isFocusFirstDeposit, setIsFocusFirstDeposit] =
    useState<boolean>(false);
  const [isFocusSecondDeposit, setIsFocusSecondDeposit] =
    useState<boolean>(false);

  const [, isReadyToSubmit] = useSubmitter(TwoAmountForm);

  const { firstDepositAmount, secondDepositAmount } = useFields(TwoAmountForm);

  const success = () => {
    showSuccessToast(formatMessage(message.success));

    onClose?.();
    onSuccess?.();
  };

  const { error, isFetching, verifyCard, onVerificationFormChange } =
    useTwoAmountsVerification({
      client,
      paymentMethod,
      onSuccess: success,
    });

  useEffect(() => {
    if (error) {
      showErrorToast(error);
    }
  }, [error]);

  const firstDepositValidationErrorMessage = useMemo(() => {
    if (isFocusFirstDeposit && firstDepositAmount.errors?.length) {
      return firstDepositAmount.errors[0].defaultMessage;
    }

    return '';
  }, [firstDepositAmount, isFocusFirstDeposit]);

  const secondDepositValidationErrorMessage = useMemo(() => {
    if (isFocusSecondDeposit && secondDepositAmount.errors?.length) {
      return secondDepositAmount.errors[0].defaultMessage;
    }

    return '';
  }, [secondDepositAmount, isFocusSecondDeposit]);

  const onHelp = useCallback(() => {
    window?.open(
      'https://support.coinbase.com/customer/en/portal/articles/2739613-where-are-my-payment-method-verification-amounts',
      '_blank',
    );

    logAddPaymentEvent('verify_card_help_button_pressed', {
      action: ActionType.click,
      componentType: ComponentType.link,
    });
  }, [logAddPaymentEvent]);

  const onValueChange = useCallback(
    ({ target }: React.ChangeEvent<HTMLInputElement>) => {
      const verification = {
        depositAmount1: firstDepositAmount.value,
        depositAmount2: secondDepositAmount.value,
      };

      if (target.name === 'firstDepositAmount') {
        verification.depositAmount1 = target.value;
        firstDepositAmount.onChange(target.value);
      } else if (target.name === 'secondDepositAmount') {
        verification.depositAmount2 = target.value;
        secondDepositAmount.onChange(target.value);
      }

      onVerificationFormChange(verification);
    },
    [firstDepositAmount, secondDepositAmount, onVerificationFormChange],
  );

  const handleOnFocus = useCallback(() => setIsFocusFirstDeposit(true), []);

  const handleOnFocus1 = useCallback(() => setIsFocusSecondDeposit(true), []);

  return (
    <VStack flexGrow={1} testID="card-two-amounts-form">
      <TextHeadline as="span" spacingBottom={2}>
        {formatMessage(message.information, {
          cardLast: paymentMethod.name.slice(-4),
        })}
      </TextHeadline>
      <Card borderRadius="rounded" background="primaryWash">
        <HStack
          spacerGap={1}
          spacingVertical={1}
          spacingHorizontal={2}
          alignItems="center"
        >
          <SeverityIcon size="s" type="INFO" fillColor="iconLight" />
          <TextLabel2 as="span" color="foregroundMuted">
            {formatMessage(message.hint)}
          </TextLabel2>
        </HStack>
      </Card>
      <VStack spacerGap={3} flexGrow={1} spacingTop={3}>
        <TextInput
          name="firstDepositAmount"
          label={formatMessage(message.firstDeposit)}
          value={firstDepositAmount.value}
          inputMode="numeric"
          maxLength={4}
          placeholder="0.00"
          helperText={firstDepositValidationErrorMessage}
          onFocus={handleOnFocus}
          onChange={onValueChange}
        />
        <TextInput
          name="secondDepositAmount"
          label={formatMessage(message.secondDeposit)}
          value={secondDepositAmount.value}
          inputMode="numeric"
          maxLength={4}
          placeholder="0.00"
          helperText={secondDepositValidationErrorMessage}
          onFocus={handleOnFocus1}
          onChange={onValueChange}
        />
        <VStack spacerGap={1} flexGrow={1} justifyContent="flex-end">
          <Button
            loading={isFetching}
            disabled={isFetching || !isReadyToSubmit}
            onPress={verifyCard}
            testID="verify-card-submit-button"
          >
            {formatMessage(message.verifyCard)}
          </Button>
          <Button variant="secondary" onPress={onHelp}>
            {formatMessage(message.cantFindDeposit)}
          </Button>
        </VStack>
      </VStack>
      <Disclosure />
    </VStack>
  );
}

