import { useCallback } from 'react';
import { Collapsible } from '@cbhq/cds-web/collapsible';
import { HStack, VStack } from '@cbhq/cds-web/layout';

import { CollectibleItemProps, CollectibleItem } from './CollectibleItem';

const MAX_COLS = 4;
const ROWS_TO_RENDER = 2;

type CollectibleGridProps = {
  showAll: boolean;
  collectibles: CollectibleItemProps[];
  maxColumnLength?: number;
  initialRowsToRender?: number;
};

export function getGridRows<T>(data: T[], maxColumnLength: number) {
  const rows: T[][] = [];
  for (let i = 0; i < data.length; i += maxColumnLength) {
    const row = data.slice(i, i + maxColumnLength);
    rows.push(row);
  }
  // To left-justify the last row, add some dummy list items
  const lastRow = rows[rows.length - 1];
  if (lastRow.length % maxColumnLength !== 0) {
    rows[rows.length - 1] = [
      ...lastRow,
      // Add as many dummy items are needed to sum to maxColumnLength items
      ...Array(maxColumnLength - lastRow.length).fill({ isPseudoItem: true }),
    ];
  }
  return rows;
}

function CollectibleGrid({
  showAll,
  collectibles,
  maxColumnLength = MAX_COLS,
  initialRowsToRender = ROWS_TO_RENDER,
}: CollectibleGridProps) {
  // Used to generate a unique key for each row of collectibles which is
  // their concatenated titles
  const getRowKey = useCallback(
    (row: CollectibleItemProps[]) =>
      row.map((collectible, index) => collectible.title || index).join('-'),
    [],
  );

  const renderRow = useCallback(
    (row: CollectibleItemProps[]) => (
      <HStack
        key={getRowKey(row)}
        spacerGap={3}
        spacingVertical={1}
        alignItems="flex-start"
        flexGrow={1}
      >
        {row.map((collectible, index) => (
          <CollectibleItem key={collectible.title || index} {...collectible} />
        ))}
      </HStack>
    ),
    [getRowKey],
  );

  const collectibleRows = getGridRows<CollectibleItemProps>(
    collectibles,
    maxColumnLength,
  );

  return (
    <VStack>
      {/* Render initial row(s) */}
      {collectibleRows.slice(0, initialRowsToRender).map(row => renderRow(row))}
      {/* Other rows are initially hidden by default */}
      {collectibleRows.length > initialRowsToRender && (
        <Collapsible collapsed={!showAll}>
          <VStack flexGrow={1} testID="collectibles-collapsed">
            {collectibleRows
              .slice(initialRowsToRender)
              .map(row => renderRow(row))}
          </VStack>
        </Collapsible>
      )}
    </VStack>
  );
}

export default CollectibleGrid;

