    cardType: props.type,
  });
  const trackClick = useLogDataCardEvent({
    action: ActionType.click,
    componentName: props.cardName,
    cardType: props.type,
  });

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const onPress = () => {
    trackClick();
    if (props.destinationModal) showModal(props.destinationModal);
    else if (props.openInNewWindow && props.destinationLink)
      window.open(props.destinationLink, '_blank', 'noopener,noreferrer');
    else if (props.destinationLink) history.push(props.destinationLink);
  };

  // Track when the component is rendered
  useLogEventOnMount('grow_balance_card', {
    action: ActionType.render,
    componentType: ComponentType.card,
    platform: 'web',
    componentName: props.cardName,
    cardType: props.type,
  });

  return (
    <VisibilityTrigger onVisibleOnce={trackViewed}>
      <WrapperDiv>
        <Box
          flexGrow={1}
          flexBasis={0}
          spacingEnd={spacingEnd}
          spacingBottom={isMobile ? 1 : 2}
        >
          <Pressable
            block
            onPress={onPress}
            as="button"
            background="background"
            borderRadius={isMobile ? undefined : 'rounded'}
            noScaleOnPress={isMobile}
          >
            <DataCardContent {...props} />
          </Pressable>
        </Box>
      </WrapperDiv>
    </VisibilityTrigger>
  );
}

