import { useEffect, useCallback, useState, memo } from 'react';
import {
  ChaosTest,
  FaultArg,
  Fault,
} from '@cb/shared/utils/clientChaosMonkey/chaosTest';
import { logChaosMonkeyMetric } from '@cb/shared/utils/clientChaosMonkey/logMetric';
import { Button } from '@cbhq/cds-web/buttons';
import { Checkbox } from '@cbhq/cds-web/controls';
import { Select, SelectOption } from '@cbhq/cds-web/controls';
import { TextInput } from '@cbhq/cds-web/controls';
import { Divider, VStack, HStack } from '@cbhq/cds-web/layout';
import {
  TextBody,
  TextTitle3,
  TextLabel1,
  TextLabel2,
} from '@cbhq/cds-web/typography';

import { FaultType } from './FaultType';

export const DebugChaosMonkeyChaosTestScreen = memo(() => {
  const [matchAllMethods, setMatchAllMethods] = useState(false);
  const [service, setService] = useState('');
  const [isClientInterceptor, setIsClientInterceptor] = useState(false);
  const [method, setMethod] = useState('');
  const [fault, setFault] = useState<Fault['type'] | undefined>(undefined);
  const [cookie, setCookie] = useState<string | null>(ChaosTest.getCookie());
  const [faultArg, setFaultArg] = useState<FaultArg | undefined>(undefined);

  const handleClear = useCallback(() => {
    setService('');
    setMethod('');
    setCookie(null);
    setFault(undefined);
    setMatchAllMethods(false);
    ChaosTest.resetParams();
  }, []);

  const handleFaultChange = useCallback((type: string) => {
    setFault(type as Fault['type']);
  }, []);

  const handleEnableChaosTest = useCallback(() => {
    if ((service && method && fault) || (service && matchAllMethods && fault)) {
      ChaosTest.setParam({
        service,
        method,
        fault,
        faultArg,
        clientInterceptor: isClientInterceptor,
        matchAllMethods,
      });
      ChaosTest.setCookie();
      setCookie(ChaosTest.getCookie());
    }
  }, [fault, faultArg, method, service, isClientInterceptor, matchAllMethods]);

  const onMatchAllMethodsChange = useCallback(
    (e?: React.ChangeEvent<HTMLInputElement>) => {
      setMatchAllMethods(e?.target.checked ? true : false);
      if (e?.target.checked) {
        setMethod('');
      }
    },
    [],
  );

  const onCheckboxChange = useCallback(
    (e?: React.ChangeEvent<HTMLInputElement>) => {
      setIsClientInterceptor(e?.target.checked ? true : false);
    },
    [],
  );

  const handleOnChangeService: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(e => {
      const newVal = e.target.value;
      setService(newVal);

      // if multiple services are passed, assume full service outage scenario.
      // disable method input to emphasize this in the UI
      const commaSplit = newVal.split(',');
      const enableMatchAllMethods = commaSplit.length > 1;
      setMatchAllMethods(enableMatchAllMethods);
    }, []);

  const handleOnChangeMethod: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(e => setMethod(e.target.value), []);

  const onFaultChange = useCallback((arg: FaultArg) => setFaultArg(arg), []);

  useEffect(() => logChaosMonkeyMetric('custom_chaos_test'), []);

  return (
    <>
      <VStack width="100%" spacing={2}>
        <TextTitle3 spacingBottom={1} as="p">
          🐒 Custom Chaos Testing
        </TextTitle3>
        <VStack spacing={1}>
          <TextBody as="p" spacingBottom={1}>
            Leverage the Chaos Testing Library using Chaos Monkey
          </TextBody>
        </VStack>

        <Divider spacingVertical={1} />

        <VStack spacing={1} spacingVertical={2}>
          <TextInput
            label="Service:"
            placeholder="service"
            onChange={handleOnChangeService}
            value={service}
          />
          <VStack spacing={1} spacingTop={2}>
            <Checkbox
              aria-labelledby="disable-entire-service"
              key="disable-entire-service"
              checked={matchAllMethods}
              onChange={onMatchAllMethodsChange}
            >
              Disable entire service
            </Checkbox>
          </VStack>
        </VStack>

        <VStack spacing={1}>
          <TextInput
            label="Method:"
            placeholder="method"
            onChange={handleOnChangeMethod}
            value={method}
            disabled={matchAllMethods}
          />
        </VStack>

        <VStack spacing={1}>
          <Select
            value={fault}
            label="Fault Type: "
            placeholder="Select fault type"
            onChange={handleFaultChange}
          >
            {ChaosTest.faultTypes.map(option => (
              <SelectOption value={option} key={option} title={option} />
            ))}
          </Select>
        </VStack>

        <FaultType faultType={fault} onFaultArgChange={onFaultChange} />

        <VStack spacing={1}>
          <Checkbox
            aria-labelledby="force-429-rate-limiting"
            key="force-429-rate-limiting"
            checked={isClientInterceptor}
            onChange={onCheckboxChange}
          >
            Use client interceptor
          </Checkbox>
        </VStack>

        <VStack spacingHorizontal={2} spacingVertical={1}>
          <Button compact block onPress={handleEnableChaosTest}>
            Enable Chaos Test
          </Button>
        </VStack>
        <VStack spacingHorizontal={2} spacingVertical={1}>
          <Button variant="secondary" compact block onPress={handleClear}>
            Clear
          </Button>
        </VStack>

        <Divider spacingVertical={1} />

        {cookie && (
          <>
            <VStack spacingVertical={3}>
              <HStack spacingBottom={2}>
                <TextLabel1 as="p">Chaos Testing Library config:</TextLabel1>
              </HStack>
              <HStack spacingBottom={2}>
                <TextLabel2 as="pre">{atob(cookie)}</TextLabel2>
              </HStack>
            </VStack>
          </>
        )}
      </VStack>
    </>
  );
});

