import React, { memo, useCallback, useMemo, useRef, useState } from 'react';
import CheckBox from '@cb/shared/components/CheckBox';
import {
  blockchainNetworksFullOutage,
  blockchainNetworksPartialOutage,
  defiAccountsFullOutage,
  defiBalancesFullOutage,
  defiBalancesPartialOutage,
  defiFullOutage,
  defiZeroBalancesPartialOutage,
  web3WalletAddressError,
  web3WalletTotalBalanceOutage,
} from '@cb/shared/fieldLevelMocks/defi/errorStates';
import {
  DebugFieldLevelMock,
  SharedFieldLevelMock,
} from '@cb/shared/fieldLevelMocks/types';
import { Banner } from '@cbhq/cds-web/banner/Banner';
import { Button } from '@cbhq/cds-web/buttons';
import { ButtonGroup } from '@cbhq/cds-web/buttons';
import { ListCell } from '@cbhq/cds-web/cells/ListCell';
import { Switch } from '@cbhq/cds-web/controls/Switch';
import { Box, HStack, VStack } from '@cbhq/cds-web/layout';
import { TextBody } from '@cbhq/cds-web/typography/TextBody';
import { TextHeadline } from '@cbhq/cds-web/typography/TextHeadline';
import {
  registerFieldLevelMockData,
  resetFieldLevelMockerCache,
} from '@cbhq/data-layer';

import { SearchBar } from 'components/DebugMenu/components/SubMenu';
import fieldLevelMockData from 'fieldLevelMockData';
import useToasts from 'hooks/useToasts';

const FIELD_LEVEL_MOCKER_KEY = 'field_level_mocker';
const FLM_PRESERVE_CACHE_KEY = `${FIELD_LEVEL_MOCKER_KEY}.preserve_cache`;

const defiMocks: DebugFieldLevelMock = {
  title: 'DeFi',
  sharedMocks: [
    defiFullOutage,
    web3WalletAddressError,
    defiAccountsFullOutage,
    blockchainNetworksFullOutage,
    defiBalancesFullOutage,
    defiBalancesPartialOutage,
    blockchainNetworksPartialOutage,
    defiZeroBalancesPartialOutage,
    web3WalletTotalBalanceOutage,
  ],
};

const fieldLevelMocks: DebugFieldLevelMock[] = [defiMocks];

type SelectedMocks = Map<string, boolean>;

const saveMocksToSessionStorage = (selectedMocks: SelectedMocks) => {
  sessionStorage.setItem(
    FIELD_LEVEL_MOCKER_KEY,
    JSON.stringify(Array.from(selectedMocks.entries())),
  );
};

function loadMocksFromSessionStorage(): SelectedMocks {
  try {
    const storedData = sessionStorage.getItem(FIELD_LEVEL_MOCKER_KEY);
    if (storedData) {
      return new Map(JSON.parse(storedData));
    }
  } catch (_) {}
  return new Map();
}

function loadPreserveCacheFromStore(): boolean {
  const serialized = sessionStorage.getItem(FLM_PRESERVE_CACHE_KEY);
  return serialized === 'true';
}

type FieldLevelMockCellProps = {
  sharedMock: SharedFieldLevelMock;
  onChange: (mock: SharedFieldLevelMock, value: boolean) => void;
  isChecked: boolean;
};

export const FieldLevelMockCell = memo(function FieldLevelMockCell({
  sharedMock,
  onChange,
  isChecked,
}: FieldLevelMockCellProps) {
  const handleChange = useCallback(
    (value: React.ChangeEvent<HTMLInputElement>) => {
      onChange(sharedMock, value.target.checked);
    },
    [onChange, sharedMock],
  );

  return (
    <ListCell
      key={sharedMock.key}
      title={sharedMock.title}
      description={sharedMock.description}
      action={
        <Switch
          checked={isChecked}
          onChange={handleChange}
          title={sharedMock.title}
        />
      }
      priority="end"
    />
  );
});

export const DebugFieldLevelMockerScreen = memo(
  function DebugFieldLevelMockerScreen() {
    const [selectedMocks, setSelectedMocks] = useState<SelectedMocks>(
      loadMocksFromSessionStorage(),
    );
    const [searchValue, setSearchValue] = useState('');
    const { showSuccessToast } = useToasts();

    const handleSetMock = useCallback((key: string, value: boolean) => {
      setSelectedMocks(prev => new Map(prev.set(key, value)));
    }, []);

    const [shouldPreserveCache, setShouldPreserveCache] = useState<boolean>(
      () => loadPreserveCacheFromStore(),
    );

    const selectedMocksCount = useMemo(
      () => Array.from(selectedMocks.values()).filter(value => value).length,
      [selectedMocks],
    );

    const handleApplyMocks = useCallback(() => {
      for (const [key, value] of selectedMocks.entries()) {
        setSelectedMocks(prev => new Map(prev.set(key, value)));
      }

      saveMocksToSessionStorage(selectedMocks);

      const mocksToApply = fieldLevelMocks.flatMap(fieldLevelMock =>
        fieldLevelMock.sharedMocks
          .filter(sharedMock => selectedMocks.get(sharedMock.key))
          .flatMap(sharedMock => sharedMock.mocks),
      );

      // do not clear the cache, instead, we dynamically swap out the mocks
      if (shouldPreserveCache) {
        registerFieldLevelMockData(mocksToApply);
      } else {
        // we will load the mock data from the session storage once the app reloads
        resetFieldLevelMockerCache();
        window.location.reload();
      }

      showSuccessToast(`${selectedMocksCount} mocks applied successfully`);
    }, [
      selectedMocks,
      selectedMocksCount,
      shouldPreserveCache,
      showSuccessToast,
    ]);

    const handleClearMocks = useCallback(() => {
      sessionStorage.removeItem(FIELD_LEVEL_MOCKER_KEY);
      setSelectedMocks(loadMocksFromSessionStorage());
      showSuccessToast('All mocks cleared successfully');
      resetFieldLevelMockerCache();
      window.location.reload();
    }, [showSuccessToast]);

    const filteredFieldLevelMocks = useMemo(() => {
      if (!searchValue) {
        return fieldLevelMocks;
      }

      const filteredMocks: DebugFieldLevelMock[] = [];
      return fieldLevelMocks.reduce((acc, fieldLevelMock) => {
        const filteredSharedMocks = fieldLevelMock.sharedMocks.filter(
          sharedMock =>
            sharedMock.title.toLowerCase().includes(searchValue.toLowerCase()),
        );

        if (filteredSharedMocks.length > 0) {
          acc.push({
            ...fieldLevelMock,
            sharedMocks: filteredSharedMocks,
          });
        }

        return acc;
      }, filteredMocks);
    }, [searchValue]);

    const handleSearch = useCallback(
      (e: React.ChangeEvent<HTMLInputElement>) => {
        setSearchValue(e.target.value);
      },
      [],
    );

    const handlePreserveCacheToggle = useCallback((value: boolean) => {
      setShouldPreserveCache(value);
      sessionStorage.setItem(FLM_PRESERVE_CACHE_KEY, value.toString());
    }, []);

    const handleCellChange = useCallback(
      (mock: SharedFieldLevelMock, value: boolean) => {
        handleSetMock(mock.key, value);
      },
      [handleSetMock],
    );

    if (fieldLevelMockData.length > 0) {
      return (
        <Box spacing={3}>
          <Banner
            title={`Local Mocks Detected`}
            variant="warning"
            startIcon="error"
          >
            {`Please remove the local "fieldLevelMocksData" file before using the Field Level Mocker Debug Menu`}
          </Banner>
        </Box>
      );
    }

    return (
      <>
        <SearchBar
          type="text"
          placeholder="Search mocks"
          value={searchValue}
          onChange={handleSearch}
        />

        <VStack>
          {filteredFieldLevelMocks.map(fieldLevelMock => (
            <VStack>
              <TextHeadline as="h2">{fieldLevelMock.title}</TextHeadline>
              {fieldLevelMock.sharedMocks.map(sharedMock => (
                <FieldLevelMockCell
                  key={sharedMock.key}
                  sharedMock={sharedMock}
                  onChange={handleCellChange}
                  isChecked={selectedMocks.get(sharedMock.key) ?? false}
                />
              ))}
            </VStack>
          ))}
        </VStack>

        <VStack spacingTop={2} gap={1}>
          <HStack justifyContent="space-between">
            <TextBody as="p" align="center">
              {`Selected mocks: ${selectedMocksCount}`}
            </TextBody>
            <HStack>
              <CheckBox
                onClick={handlePreserveCacheToggle}
                selected={shouldPreserveCache}
              />
              <TextBody as="p">Preserve Cache</TextBody>
            </HStack>
          </HStack>

          <ButtonGroup block>
            <Button
              onPress={handleClearMocks}
              variant="negative"
              disabled={selectedMocksCount === 0}
            >
              Clear All
            </Button>
            <Button onPress={handleApplyMocks} variant="primary">
              Apply
            </Button>
          </ButtonGroup>
        </VStack>
      </>
    );
  },
);

export const DebugFieldLevelMockerLoader = memo(
  function DebugFieldLevelMockerLoaderInner() {
    const firstMount = useRef(true);
    const selectedMocks = useMemo(() => loadMocksFromSessionStorage(), []);
    if (firstMount) {
      try {
        resetFieldLevelMockerCache();
        // local mocks take precedence over debug menu
        if (fieldLevelMockData.length === 0) {
          const mocksToApply = fieldLevelMocks.flatMap(fieldLevelMock =>
            fieldLevelMock.sharedMocks
              .filter(sharedMock => selectedMocks.get(sharedMock.key))
              .flatMap(sharedMock => sharedMock.mocks),
          );
          if (mocksToApply.length > 0) {
            registerFieldLevelMockData(mocksToApply);
          }
        }
      } catch (e) {
        console.error('Error parsing mock data from session storage', e);
      } finally {
        firstMount.current = false;
      }
    }

    return null;
  },
);

