function getSuspenseTimingKey(timing: BranchTiming) {
  return `${timing.instrumentationId}-${timing.firstRenderedAt}`;
}

type DebugSuspenseTimingsScreenProps = {
  hideTitle?: boolean;
};

export const DebugSuspenseTimingsScreen = memo<DebugSuspenseTimingsScreenProps>(
  function DebugSuspenseTimingsScreen({ hideTitle }) {
    const history = useHistory();
    const [suspenseTimings] = useState(() => {
      return (
        [...DefaultSuspenseInstrumentationStore]
          .reverse()
          // In SuspenseMode, two entries get added per each render,
          // filter out the one without dataTimings
          .filter(data => Object.keys(data.dataTimings).length > 0)
      );
    });

    return (
      <Table bordered variant="ruled" tableLayout="auto">
        {!hideTitle && <TableCaption>Suspense Timings</TableCaption>}
        <TableBody>
          {suspenseTimings.map(timing => (
            <TableRow key={getSuspenseTimingKey(timing)}>
              <TableCell
                title={`${timing.instrumentationId} @ ${new Date(
                  timing.firstRenderedAt,
                ).toLocaleTimeString()}`}
                width="100%"
                // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                onPress={() =>
                  history.push(
                    `/debug/suspense-timing/${getSuspenseTimingKey(timing)}`,
                  )
                }
              />
            </TableRow>
          ))}
        </TableBody>
      </Table>
    );
  },
);

