const StyledBox = styled(Box)`
  border-left-width: 1px;
  position: absolute;
  z-index: 1;
  padding: 4px;
  top: 0;
  bottom: 0;
`;

type Timing = BranchTiming['dataTimings'][0];

type BranchTimingWithSuspense = Timing & {
  dataTimings?: Timing[];
};

type DataTimingProps = {
  dataTiming: Timing;
  isWaterfall: boolean;
  scale: number;
};

function DataTiming({ dataTiming, isWaterfall, scale }: DataTimingProps) {
  const history = useHistory();
  const spectrum = useSpectrum();

  const backgroundColor = useMemo(() => {
    if (dataTiming.type === 'suspenseFallback') {
      return 'orange15';
    } else if (dataTiming.didSuspend) {
      return isWaterfall ? 'red15' : 'yellow20';
    } else if (dataTiming.type === 'fragment') {
      return 'gray10';
    }
    return 'blue5';
  }, [dataTiming.didSuspend, dataTiming.type, isWaterfall]);

  const textLabel = useMemo(() => {
    let textLabel =
      dataTiming.type === 'suspenseFallback'
        ? dataTiming.identifier
        : dataTiming.name || `${dataTiming.type}: ${dataTiming.identifier}`;

    textLabel += ` ∈ ${dataTiming.suspenseBoundaryName ?? 'unknown'}`;

    return textLabel;
  }, [
    dataTiming.identifier,
    dataTiming.name,
    dataTiming.suspenseBoundaryName,
    dataTiming.type,
  ]);

  const onPress = useCallback(() => {
    history.push(
      `${history.location.pathname}/${dataTiming.name}/${dataTiming.identifier}`,
    );
  }, [dataTiming.identifier, dataTiming.name, history]);

  return (
    <Box position="relative" spacingBottom={0.5}>
      <PressableOpacity
        role="button"
        width="100%"
        key={dataTiming.name + dataTiming.identifier}
        onPress={onPress}
      >
        <Box
          position="absolute"
          borderRadius="roundedSmall"
          height="100%"
          left={(dataTiming.firstRenderAt ?? 0) * scale}
          dangerouslySetBackground={paletteValueToHex(
            backgroundColor,
            spectrum,
          )}
          width={Math.max(
            ((dataTiming.resolvedAt ?? dataTiming.firstRenderAt ?? 0) -
              (dataTiming.firstRenderAt ?? 0)) *
              scale,
            10,
          )}
        />
        <Box
          spacing={0.5}
          left={(dataTiming.firstRenderAt ?? 0) * scale}
          position="relative"
        >
          <TextLabel2 as="span">{textLabel}</TextLabel2>
        </Box>
      </PressableOpacity>
    </Box>
  );
}

type TimelineViewProps = {
  suspenseTimingId: string;
};

const TimelineView = memo(function TimelineView({
  suspenseTimingId,
}: TimelineViewProps) {
  const timing = useMemo(
    () =>
      DefaultSuspenseInstrumentationStore.find(
        timing =>
          suspenseTimingId === getSuspenseTimingKey(timing) &&
          Object.keys(timing.dataTimings).length > 0,
      ),
    [suspenseTimingId],
  );

  const relativeTiming = useMemo(
    () => (timing ? calculateRelativeTimings(timing) : null),
    [timing],
  );

  const spectrum = useSpectrum();
  const [suspendedTimingsOnly, { toggle: toggleSuspendedOnly }] = useToggler();

  const sortedDataTimings = useMemo(() => {
    return Object.values(relativeTiming?.dataTimings ?? []).sort((a, b) => {
      if (a.firstRenderAt && b.firstRenderAt) {
        if (a.firstRenderAt === b.firstRenderAt) {
          return Number(b.didSuspend) - Number(a.didSuspend);
        }
        return a.firstRenderAt - b.firstRenderAt;
      }
      return 0;
    });
  }, [relativeTiming?.dataTimings]);

  const filteredDataTimings = useMemo(
    () =>
      sortedDataTimings.filter(dt =>
        suspendedTimingsOnly
          ? dt.didSuspend === true || dt.type === 'suspenseFallback'
          : true,
      ),
    [sortedDataTimings, suspendedTimingsOnly],
  );

  const hasBoundaryRelationships = useRef(false);
  // build suspense boundary relationship between data timings
  const [suspenseBoundaryList, boundarylessOperations] = useMemo(() => {
    const suspenseBoundaryMap: Record<string, BranchTimingWithSuspense> = {};
    // there's some data timings that are not instrumented, we'll put them in a separate list
    // e.g., fetch, streaming, etc.
    const nonInstrumentedList: Timing[] = [];
    // we will try out best to guess
    const unguessableList: Timing[] = [];

    // first pass, build suspense boundary map
    for (const timingKey in relativeTiming?.dataTimings) {
      const timing = relativeTiming.dataTimings[timingKey];
      if (timing.type === 'suspenseFallback') {
        suspenseBoundaryMap[timing.identifier] = { ...timing };
      }
    }

    // second pass, build suspense boundary relationships
    for (const timing of filteredDataTimings) {
      if (
        timing.suspenseBoundaryName &&
        suspenseBoundaryMap[timing.suspenseBoundaryName]
      ) {
        const suspenseBoundary =
          suspenseBoundaryMap[timing.suspenseBoundaryName];
        if (!suspenseBoundary?.dataTimings) {
          suspenseBoundary.dataTimings = [];
        }
        if (timing.type !== 'suspenseFallback') {
          if (!hasBoundaryRelationships.current) {
            hasBoundaryRelationships.current = true;
          }
          suspenseBoundary.dataTimings.push(timing);
        }
      } else if (!timing.suspenseBoundaryName) {
        nonInstrumentedList.push(timing);
      }
    }
    // incomplete data here, we need to "guess" where the uninstrumented operations happened
    for (const timing of nonInstrumentedList) {
      const firstRenderAt = timing.firstRenderAt ?? 0;
      const resolvedAt = timing.resolvedAt ?? 0;
      let guessed = false;
      for (const key of Object.keys(suspenseBoundaryMap)) {
        const suspenseBoundary = suspenseBoundaryMap[key];
        if (
          suspenseBoundary.firstRenderAt !== undefined &&
          suspenseBoundary.resolvedAt !== undefined &&
          suspenseBoundary.firstRenderAt <= firstRenderAt &&
          suspenseBoundary.resolvedAt >= resolvedAt
        ) {
          if (!suspenseBoundary.dataTimings) {
            suspenseBoundary.dataTimings = [];
          }
          suspenseBoundary.dataTimings.push(timing);
          guessed = true;
          break;
        }
      }
      if (!guessed) {
        // we can't guess where this operation happened, put it under unguessable list
        unguessableList.push(timing);
      }
    }
    // need to sort each dataTimings by firstRenderAt
    for (const key of Object.keys(suspenseBoundaryMap)) {
      const suspenseBoundary = suspenseBoundaryMap[key];
      suspenseBoundary.dataTimings?.sort(
        (a, b) => (a?.firstRenderAt ?? 0) - (b?.firstRenderAt ?? 0),
      );
    }

    return [
      Object.values(suspenseBoundaryMap).sort(
        (a, b) => (a?.firstRenderAt ?? 0) - (b?.firstRenderAt ?? 0),
      ),
      unguessableList,
    ];
  }, [filteredDataTimings, relativeTiming?.dataTimings]);

  const sortedByResolvedAt = useMemo(
    () =>
      [...sortedDataTimings].sort(
        (a, b) =>
          (a.resolvedAt ?? Number.MAX_SAFE_INTEGER) -
          (b.resolvedAt ?? Number.MAX_SAFE_INTEGER),
      ),
    [sortedDataTimings],
  );
  // find potential waterfall
  const waterfallList = useMemo(() => {
    const suspendedOnly = sortedByResolvedAt.filter(it => it.didSuspend);
    const waterfallList = new Set();
    // count the number of operations that has firstRenderAt value after an operation resolved
    for (let i = 0; i < suspendedOnly.length; i++) {
      const resolvedAt = suspendedOnly[i].resolvedAt;
      for (let j = i + 1; j < suspendedOnly.length; j++) {
        if (
          !waterfallList.has(
            suspendedOnly[j].name + suspendedOnly[j].identifier,
          ) &&
          resolvedAt &&
          (suspendedOnly[j]?.firstRenderAt ?? 0) > resolvedAt
        ) {
          waterfallList.add(
            suspendedOnly[j].name + suspendedOnly[j].identifier,
          );
        }
      }
    }
    return waterfallList;
  }, [sortedByResolvedAt]);

  const slowest = useMemo(() => {
    return sortedByResolvedAt[sortedByResolvedAt.length - 1];
  }, [sortedByResolvedAt]);

  const timelineEnd = useMemo(
    () => Math.max(0, ...filteredDataTimings.map(it => it.resolvedAt ?? 0)),
    [filteredDataTimings],
  );

  const renderedTimelineEnd = useMemo(
    () =>
      Math.max(
        0,
        ...filteredDataTimings.map(it => Math.max(0, ...it.mountedAt) ?? 0),
      ),
    [filteredDataTimings],
  );

  const screenWidth = window.innerWidth;

  const [scale, setScale] = useState(() =>
    Math.min((screenWidth - 300) / timelineEnd, 0.5),
  );
  const zoomOut = useCallback(() => setScale(s => s / 2), []);
  const zoomIn = useCallback(() => setScale(s => s * 2), []);

  const NUM_MARKERS_ON_SCREEN = 2;
  const timeMarkerPxWidth = screenWidth / (NUM_MARKERS_ON_SCREEN + 1);
  const timeMarkerTimespanWidth = timeMarkerPxWidth / scale;
  const numTimeMarkers = useMemo(
    () =>
      Math.max(
        Math.ceil(timelineEnd / timeMarkerTimespanWidth) + 1,
        NUM_MARKERS_ON_SCREEN,
      ),
    [timeMarkerTimespanWidth, timelineEnd],
  );

  if (!relativeTiming || !timing) {
    return <Redirect to="/debug/suspense-timing" />;
  }

  return (
    <>
      <Table>
        <TableCaption>{`${timing.instrumentationId} Rendering @${format(
          new Date(timing.firstRenderedAt),
          'hh:mm:ss.SSS a',
        )}`}</TableCaption>
        <TableHeader>
          <TableRow>
            <TableCell>
              <HStack spacerGap={1}>
                Resolved duration
                <Tooltip content="Duration between the time the screen was first rendered and the time the all suspenses were resolved">
                  <Icon name="info" size="m" />
                </Tooltip>
              </HStack>
            </TableCell>

            <TableCell>
              <HStack spacerGap={1}>
                Rendered duration
                <Tooltip content="Duration between the time the screen was first rendered and the time the all components were rendered">
                  <Icon name="info" size="m" />
                </Tooltip>
              </HStack>
            </TableCell>

            <TableCell>
              <HStack spacerGap={1}>
                Waterfall count
                <Tooltip content="Possible waterfall count detected during the rendering cycle. This method may not be 100% accurate, as it compares the resolvedAt time with the firstRenderedAt time for each operation. If one operation begins rendering after another operation has resolved, there's a high likelihood that a network waterfall occurred during that specific rendering cycle.">
                  <Icon name="info" size="m" />
                </Tooltip>
              </HStack>
            </TableCell>

            <TableCell>
              <HStack spacerGap={1}>
                Slowest
                <Tooltip
                  content="This operation took the longest to resolve. You should begin your investigation with this operation if you are aiming to improve the rendering performance"
                  placement="top"
                >
                  <Icon name="info" size="m" />
                </Tooltip>
              </HStack>
            </TableCell>
          </TableRow>
        </TableHeader>
        <TableBody>
          <TableRow disableHoverIndicator>
            <TableCell title={`${timelineEnd}ms`} />
            <TableCell title={`${renderedTimelineEnd}ms`} />
            <TableCell title={`${waterfallList.size}`} />
            <TableCell title={`${slowest.name}-${slowest.identifier}`} />
          </TableRow>
        </TableBody>
      </Table>
      <VStack spacingVertical={1}>
        <HStack alignContent="center" spacingVertical={2}>
          <HStack spacerGap={2}>
            <Tag
              intent="promotional"
              dangerouslySetBackground="red15"
              color="gray100"
            >
              Potential Network waterfall
            </Tag>
            <Tag
              intent="promotional"
              dangerouslySetBackground="orange15"
              color="gray100"
            >
              Suspense Fallback
            </Tag>
            <Tag
              intent="promotional"
              dangerouslySetBackground="yellow20"
              color="gray100"
            >
              Suspended operations
            </Tag>
            <Tag
              intent="promotional"
              dangerouslySetBackground="blue5"
              color="gray100"
            >
              Unsuspended operations
            </Tag>
            <Tag
              intent="promotional"
              dangerouslySetBackground="gray10"
              color="gray100"
            >
              Fragment
            </Tag>
          </HStack>
          <Spacer />
          <ButtonGroup accessibilityLabel="Group">
            <IconButton name="add" onPress={zoomIn} />
            <IconButton name="minus" onPress={zoomOut} />
          </ButtonGroup>
        </HStack>
        <Checkbox
          value="suspendedOnly"
          onChange={toggleSuspendedOnly}
          checked={suspendedTimingsOnly}
        >
          Only show operations that suspended
        </Checkbox>
      </VStack>
      <VStack
        overflow="scroll"
        spacing={0.5}
        spacingTop={6}
        position="relative"
      >
        <HStack>
          {numTimeMarkers > 0 &&
            new Array(numTimeMarkers).fill(0).map((_, i) => (
              <StyledBox
                style={{
                  left: i * timeMarkerTimespanWidth * scale,
                  borderLeftColor: paletteValueToHex('gray60', spectrum),
                }}
                key={i}
              >
                <TextLegal as="span">
                  {Math.round(i * timeMarkerTimespanWidth)} ms
                </TextLegal>
              </StyledBox>
            ))}
        </HStack>
        {hasBoundaryRelationships.current
          ? suspenseBoundaryList.map(suspenseBoundaryDataTiming => {
              return (
                <>
                  <DataTiming
                    dataTiming={suspenseBoundaryDataTiming}
                    isWaterfall={waterfallList.has(
                      suspenseBoundaryDataTiming.name +
                        suspenseBoundaryDataTiming.identifier,
                    )}
                    scale={scale}
                  />
                  {suspenseBoundaryDataTiming?.dataTimings?.map(dataTiming => {
                    return (
                      <DataTiming
                        dataTiming={dataTiming}
                        isWaterfall={waterfallList.has(
                          dataTiming.name + dataTiming.identifier,
                        )}
                        scale={scale}
                      />
                    );
                  })}
                </>
              );
            })
          : filteredDataTimings.map(dataTiming => {
              return (
                <DataTiming
                  dataTiming={dataTiming}
                  isWaterfall={waterfallList.has(
                    dataTiming.name + dataTiming.identifier,
                  )}
                  scale={scale}
                />
              );
            })}
        {boundarylessOperations.map(dataTiming => {
          return (
            <DataTiming
              dataTiming={dataTiming}
              isWaterfall={waterfallList.has(
                dataTiming.name + dataTiming.identifier,
              )}
              scale={scale}
            />
          );
        })}
      </VStack>
    </>
  );
});

