export const DebugSuspenseDataTimingScreen = memo(
  function DebugSuspenseDataTimingScreen() {
    const { suspenseTimingId, timingId, timingName } = useParams<{
      suspenseTimingId: string;
      timingId: string;
      timingName: string;
    }>();

    const timing = useMemo(
      () =>
        DefaultSuspenseInstrumentationStore.find(
          timing =>
            suspenseTimingId === getSuspenseTimingKey(timing) &&
            Object.keys(timing.dataTimings).length > 0,
        ),
      [suspenseTimingId],
    );

    const relativeTiming = useMemo(
      () => (timing ? calculateRelativeTimings(timing) : null),
      [timing],
    );

    if (!relativeTiming) {
      return <Redirect to="/debug/suspense-timing" />;
    }

    const dataTiming = relativeTiming.dataTimings[`${timingName}-${timingId}`];

    if (!dataTiming) {
      return null;
    }

    return (
      <VStack>
        <TextHeadline as="h2">Screen</TextHeadline>
        <TextBody as="p" spacingBottom={2}>
          {relativeTiming.instrumentationId}
        </TextBody>

        <TextHeadline as="h2">Type</TextHeadline>
        <TextBody as="p" spacingBottom={2}>
          {dataTiming.type}
        </TextBody>
        <TextHeadline as="h2">Name</TextHeadline>
        <TextBody as="p" spacingBottom={2}>
          {dataTiming.name}
        </TextBody>
        <TextHeadline as="h2">Identifier</TextHeadline>
        <TextBody as="p" spacingBottom={2}>
          {dataTiming.identifier}
        </TextBody>

        <TextHeadline as="h2">
          (All timings are relative to screen mount)
        </TextHeadline>
        <TextHeadline as="h2">First rendered</TextHeadline>
        <TextBody as="p" spacingBottom={2}>
          {dataTiming.firstRenderAt} ms
        </TextBody>

        <TextHeadline as="h2">Resolved (past suspense)</TextHeadline>
        <TextBody as="p" spacingBottom={2}>
          {dataTiming.resolvedAt} ms
        </TextBody>

        <TextHeadline as="h2">Triggered suspense?</TextHeadline>
        <TextBody as="p" spacingBottom={2}>
          {dataTiming.didSuspend ? 'Yes' : 'No'}
        </TextBody>

        {dataTiming.events.map(ev => (
          <>
            <TextHeadline as="h2">{ev.type}</TextHeadline>
            <TextBody as="p" spacingBottom={2}>
              {ev.time}
            </TextBody>
          </>
        ))}

        <TextHeadline as="h2">Mounted at</TextHeadline>
        <TextBody as="p" spacingBottom={2}>
          {dataTiming.mountedAt.join(',')}
        </TextBody>

        <TextHeadline as="h2">Unmounted at</TextHeadline>
        <TextBody as="p" spacingBottom={2}>
          {dataTiming.unmountedAt.join(',')}
        </TextBody>
      </VStack>
    );
  },
);

import { useState, memo, useCallback } from 'react';
import { Fault, FaultArg } from '@cb/shared/utils/clientChaosMonkey/chaosTest';
import { TextInput } from '@cbhq/cds-web/controls';
import { VStack } from '@cbhq/cds-web/layout';

type Props = {
  faultType?: Fault['type'];
  onFaultArgChange: (faultArg: FaultArg) => void;
};

export const FaultType = memo(({ faultType, onFaultArgChange }: Props) => {
  const [faultArg, setFaultArg] = useState<FaultArg | undefined>(undefined);

  const handleFaultArgChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      if (faultType === 'Abort') {
        setFaultArg({ code: e.currentTarget.value });
        onFaultArgChange({ code: e.currentTarget.value });
      }

      if (faultType === 'Latency') {
        setFaultArg({ delay: e.currentTarget.value });
        onFaultArgChange({ delay: e.currentTarget.value });
      }
    },
    [faultType, onFaultArgChange],
  );

  if (faultType === 'Abort') {
    return (
      <VStack spacing={1}>
        <TextInput
          label="Status Code:"
          placeholder="e.g. 503"
          type="number"
          onChange={handleFaultArgChange}
          value={(faultArg as { code?: number })?.code?.toString() ?? ''}
        />
      </VStack>
    );
  }

  if (faultType === 'Latency') {
    return (
      <VStack spacing={1}>
        <TextInput
          label="Delay:"
          placeholder="2s"
          type="text"
          onChange={handleFaultArgChange}
          value={(faultArg as { delay?: string })?.delay ?? ''}
        />
      </VStack>
    );
  }

  return null;
});

