type Props = {
  depositInformation: GqlDepositInformationTypes;
  onNextLegacy?: (a: Steps) => void;
  nextStep: Steps | undefined | null;
  stepName?: string;
};

const i18nKey = 'WireTransferInstructions.ReferenceStep';

const messages = defineMessages({
  continue: {
    id: `${i18nKey}.continue`,
    defaultMessage: 'Continue',
    description: `#Component: Button
    #CharLimit: 40
    #Context: Continue button label`,
  },
  referenceCheckboxLabel: {
    id: `${i18nKey}.referenceCheckboxLabel`,
    defaultMessage: "I've copied or written down my Reference Number",
    description: `#Component: Text:label
    #CharLimit: 90
    #Context: User acknowlegment for taking into account wire transfer reference number`,
  },
  referenceLabel: {
    id: `${i18nKey}.referenceLabel`,
    defaultMessage: 'Reference Number',
    description: `#Component: Text
    #CharLimit: 50
    #Context: Wire transfer reference number label`,
  },
  referenceWarningSubtitle: {
    id: `${i18nKey}.referenceWarningSubtitle`,
    defaultMessage:
      'Without this code, we cannot add these funds into your Coinbase account. ',
    description: `#Component: InlineAlert:subtitle
    #CharLimit: 125
    #Context: Wire transfer reference number label description`,
  },
  referenceWarning: {
    id: `${i18nKey}.referenceWarning`,
    defaultMessage: 'Please include this reference code in your transfer',
    description: `#Component: InlineAlert:title
    #CharLimit: 100
    #Context: Wire transfer reference number label description`,
  },
});

const Section = styled.div`
  margin-bottom: ${size.huge};
`;

function ReferenceStep({
  onNextLegacy,
  nextStep,
  depositInformation,
  stepName: _,
}: Props) {
  const { formatMessage } = useIntl();
  const [isCopied, setIsCopied] = useState(false);
  const onNext = useStepFunction(nextStep || '');
  const referenceNumber = (
    depositInformation?.find(i => i?.key === 'reference') || {}
  ).value;

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const advance = () => {
    if (onNextLegacy && nextStep) {
      onNextLegacy(nextStep);
    } else if (nextStep) {
      onNext();
    }
  };

  const handleOnCheckToggle = useCallback(() => setIsCopied(true), []);

  return (
    <VStack>
      <Section>
        <InlineAlert
          type="warning"
          title={formatMessage(messages.referenceWarning)}
          subtitle={formatMessage(messages.referenceWarningSubtitle)}
        />
      </Section>
      <Section>
        <FormLabel>
          <TextHeadline as="p">
            {formatMessage(messages.referenceLabel)}
          </TextHeadline>
        </FormLabel>
        <CopyOnlyInput
          // @ts-expect-error "referenceNumber" is expected to be a string but can be an undefined
          value={referenceNumber}
        />
      </Section>
      <Section>
        <Checkbox
          testID="reference-checkbox"
          checked={isCopied}
          label={
            <TextBody as="p">
              {formatMessage(messages.referenceCheckboxLabel)}
            </TextBody>
          }
          labelPosition="right"
          onCheckToggle={handleOnCheckToggle}
        />
      </Section>
      <Button block disabled={!isCopied} onPress={advance}>
        {formatMessage(messages.continue)}
      </Button>
    </VStack>
  );
}

