import { useMemo, useCallback, useEffect } from 'react';
import { useIntl } from 'react-intl';

import { FieldProps } from '@cb/forms';
import { FlexibleCurrencyInput } from '@cb/shared/components/FlexibleCurrencyInput/FlexibleCurrencyInput';
import { debounce } from '@cb/shared/utils';
import { getLocaleConfig } from '@cb/shared/utils/locale';
import { palette } from '@cbhq/cds-web/tokens';
import { TextBody } from '@cbhq/cds-web/typography';
import { graphql, useFragment } from '@cbhq/data-layer';

import useLocalizedEntryInput from 'components/BuySellComponents/EntryInput/hooks/useLocalizedEntryInput';
import useNewLocalizedCurrencyInput from 'components/BuySellComponents/EntryInput/hooks/useNewLocalizedCurrencyInput';
import formatDisplayValue from 'components/BuySellComponents/EntryInput/utils/formatDisplayValue';
import { TransferType } from 'components/DepositWithdraw/types';

import { trackTransferInputChange } from '../analytics/transferAnalytics';
import { useTransferFormFields } from '../sharedUtils/useTransferFormFields';
import { TransfersAmountInputFragment$key } from './__generated__/TransfersAmountInputFragment.graphql';
import { TransfersAmountInputPaymentMethodFragment$key } from './__generated__/TransfersAmountInputPaymentMethodFragment.graphql';

type TransfersAmountInputProps = {
  paymentMethodV2Ref: TransfersAmountInputPaymentMethodFragment$key | null;
  queryRef: TransfersAmountInputFragment$key;
  inputAmountField: FieldProps<string>;
  transferType: TransferType;
  hasBlockingError?: boolean;
  availableBalance?: string;
};

export function TransfersAmountInput({
  queryRef,
  paymentMethodV2Ref,
  inputAmountField,
  transferType,
  hasBlockingError,
  availableBalance,
}: TransfersAmountInputProps) {
  const { viewer } = useFragment(
    graphql`
      fragment TransfersAmountInputFragment on Query {
        viewer {
          accountByUuidV2(uuid: $accountId) {
            assetOrFiatCurrency {
              ... on TiersCurrency {
                code
              }
            }
          }
        }
      }
    `,
    queryRef,
  );

  const selectedPaymentMethod = useFragment(
    graphql`
      fragment TransfersAmountInputPaymentMethodFragment on PaymentMethodV2 {
        currency
      }
    `,
    paymentMethodV2Ref || null,
  );

  const { locale } = useIntl();
  const { amountCurrency, createTransferError } =
    useTransferFormFields(transferType);

  // Currency
  const currency = useMemo(() => {
    const fiatAccountCurrency =
      viewer?.accountByUuidV2?.assetOrFiatCurrency?.code;
    const selectedPaymentMethodCurrency = selectedPaymentMethod?.currency;

    return selectedPaymentMethodCurrency || fiatAccountCurrency;
  }, [
    selectedPaymentMethod?.currency,
    viewer?.accountByUuidV2?.assetOrFiatCurrency?.code,
  ]);

  const debouncedTrackTransferInputChange = debounce(
    (amount: string, transferType: TransferType) => {
      trackTransferInputChange({
        amount,
        transferType:
          transferType === TransferType.DEPOSIT ? 'deposit' : 'withdraw',
      });
    },
  );

  useEffect(() => {
    amountCurrency.onChange(currency);
  }, [currency]);

  // Locale-specific info
  const { decimalSeparator, groupSeparator } = useMemo(
    () => getLocaleConfig({ locale }),
    [locale],
  );

  // Input change handler
  const handleInputChange = useCallback(
    (newValue?: string) => {
      if (inputAmountField.value === '' && newValue === decimalSeparator) {
        // ex: typing '.' -> '0.'
        inputAmountField.onChange(`0${decimalSeparator}`);
      } else {
        inputAmountField.onChange(newValue || '');
      }

      // avoid triggering this event on every press
      debouncedTrackTransferInputChange(newValue ?? '', transferType);

      // Clear any errors on input amount change
      createTransferError.onChange(undefined);
    },
    [
      inputAmountField,
      decimalSeparator,
      createTransferError,
      debouncedTrackTransferInputChange,
      transferType,
    ],
  );

  // Ex: 1000 -> 1,000
  const defaultFormattedInputAmount = formatDisplayValue(
    inputAmountField.value,
    decimalSeparator,
    groupSeparator,
  );

  // "2023.feb.localized_currency_input" feature flag experiment
  const canUseNewLocalizedCurrencyInput = useNewLocalizedCurrencyInput();
  const {
    displayLocalizedValue,
    handleLocalizedChange,
    updateInputCursorPosition,
    clearFormattedValue,
  } = useLocalizedEntryInput({
    value: inputAmountField.value,
    decimalSeparator,
    fiatPrecision: 2,
    onChange: handleInputChange,
    newLocalizedCurrencyInput: canUseNewLocalizedCurrencyInput,
  });

  const {
    formattedInputAmount,
    handleChange,
    handleUpdateInputCallback,
    handleClearFormattedValue,
  } = useMemo(
    () =>
      canUseNewLocalizedCurrencyInput
        ? {
            formattedInputAmount: displayLocalizedValue,
            handleChange: handleLocalizedChange,
            handleUpdateInputCallback: updateInputCursorPosition,
            handleClearFormattedValue: clearFormattedValue,
          }
        : {
            formattedInputAmount: defaultFormattedInputAmount,
            handleChange: handleInputChange,
          },
    [
      canUseNewLocalizedCurrencyInput,
      handleInputChange,
      clearFormattedValue,
      defaultFormattedInputAmount,
      displayLocalizedValue,
      handleLocalizedChange,
      updateInputCursorPosition,
    ],
  );

  // If the currency is not available + there is a blocking backend outage
  // then we hide the input + available balance fields, and show an error banner in the parent component (design approved this UX)
  if (!currency && hasBlockingError) {
    return null;
  }

  return (
    <>
      <FlexibleCurrencyInput
        // If the currency is undefined but there isn't a blocking error, then we can still show the input field
        // ex: If only the accountByUuidV2 endpoint fails in the deposit input screen, this isn't a blocking error
        symbol={currency ?? ''}
        symbolPosition="after"
        superscript={false}
        placeholder="0"
        align="flex-start"
        color={hasBlockingError ? palette.foregroundMuted : palette.foreground}
        symbolColor={palette.foregroundMuted}
        autoFocus
        value={formattedInputAmount}
        onChange={handleChange}
        updateInputCallback={handleUpdateInputCallback}
        clearFormattedValue={handleClearFormattedValue}
        readOnly={hasBlockingError}
      />
      {availableBalance && (
        <TextBody id="avaialableBalance" as="p" color="foregroundMuted">
          {availableBalance}
        </TextBody>
      )}
    </>
  );
}

import { useContext, useCallback, useEffect } from 'react';
