import messages from '../messages';
import { StepProps } from '../types';
import { EntryStepWithdrawFragment$key } from './__generated__/EntryStepWithdrawFragment.graphql';

type EntryStepProps = {
  queryRef: EntryStepWithdrawFragment$key;
  onContinueClick?: () => void;
  showAccountSelector?: boolean;
} & StepProps;

function EntryStepContent(_props: EntryStepProps) {
  const { queryRef, onContinueClick, showAccountSelector = false } = _props;
  const { viewer } = useFragment<EntryStepWithdrawFragment$key>(
    graphql`
      fragment EntryStepWithdrawFragment on Query {
        viewer {
          fiatAccounts {
            allowWithdrawals
          }
          accountByUuidV2(uuid: $accountId) {
            assetOrFiatCurrency {
              ... on TiersCurrency {
                name
                code
              }
              ...WithdrawFooterFragment
              ...useAssetCefiAvailableToSendFragment
            }
          }
        }
      }
    `,
    queryRef,
  );

  const hasMultipleFiatAccounts =
    (viewer?.fiatAccounts?.filter(acc => acc?.allowWithdrawals) ?? []).length >
    1;

  const assetOrCurrency = viewer?.accountByUuidV2?.assetOrFiatCurrency ?? null;

  const { formatMessage } = useIntl();
  const { loading } = useContext(LoadingContext);
  const { amount, platformName, displaySymbol } = useFields(WithdrawForm);

  const { balance: availableBalance = 0 } = useAssetCefiAvailableToSend({
    assetOrCurrencyRef: assetOrCurrency,
  });

  const changeStep = useGoToWithdrawStep();

  // Validation
  const hasErrors = amount.errors.length > 0;
  useCheckZeroBalance({ availableBalance });

  // Tracking
  useWithdrawTrackOnMount('withdraw_amount_viewed');
  const trackWithdrawAction = useWithdrawTracker('withdraw_amount_selected');

  useEffect(() => {
    markStepOnce('loaded_asset_detail_fiat_withdraw_input');
  }, []);

  // Handlers
  const handleOnChange = useEntryInputHandler({ availableBalance });
  const handleWithdrawalAll = useCallback(() => {
    // some fiat balances can have precision greater than we want to display, as a result Intl formatNumber just round cents up and users might see the amount greater than their actual balance.
    // this formatted value just drops the numbers after specified precision.
    amount.onChange(enforceExponent(availableBalance.toString(), 2));
    trackWithdrawAction();
  }, [amount, availableBalance, trackWithdrawAction]);

  const handleSubmit = useCallback(() => {
    if (loading || amount.value === '') return;
    trackWithdrawAction();
    onContinueClick?.();
    changeStep('paymentSelectorStep');
  }, [amount.value, changeStep, loading, onContinueClick, trackWithdrawAction]);

  const handleAssetClick = useCallback(() => {
    changeStep('accountSelectorStep');
  }, [changeStep]);

  return (
    <VStack
      flexGrow={1}
      flexShrink={1}
      flexBasis="auto"
      minHeight={DEFAULT_WIDGET_HEIGHT_TALL}
    >
      <WithdrawHeader />
      <PaddedContent
        paddingTopDesktop={PADDING_TOP_INPUT}
        paddingTopMobile={PADDING_TOP_INPUT_SMALL}
      >
        <EntryInput
          error={hasErrors && <InlineError>{amount.errors[0]}</InlineError>}
          // Don't autofocus if user has zero balance
          autoFocus={availableBalance !== 0}
          input={{
            symbol: platformName.value,
            displaySymbol: displaySymbol.value,
            value: amount.value,
            // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
            onChange: handleOnChange,
            onEnter: handleSubmit,
          }}
          secondaryButton={
            availableBalance > 0 && (
              <EntryInputSecondaryButton onPress={handleWithdrawalAll}>
                {formatMessage(messages.withdrawAll)}
              </EntryInputSecondaryButton>
            )
          }
        />
        {showAccountSelector && hasMultipleFiatAccounts && (
          <VStack spacingBottom={2}>
            <VStack bordered borderRadius="roundedSmall">
              <SelectorRow
                icon={<FiatCurrencyIcon symbol={assetOrCurrency?.code ?? ''} />}
                primaryLabel={formatMessage(messages.withdraw)}
                onPress={handleAssetClick}
                secondaryLabel={assetOrCurrency?.name}
              />
            </VStack>
          </VStack>
        )}
        <VStack>
          <Button
            block
            loading={loading}
            onPress={handleSubmit}
            disabled={loading || hasErrors}
          >
            {formatMessage(messages.continue)}
          </Button>
        </VStack>
      </PaddedContent>
      <WithdrawFooter assetOrCurrencyRef={assetOrCurrency} />
      <MultiPortfolioDisclaimerV2
        transferType="withdraw"
        spacingHorizontal={3}
        spacingBottom={3}
      />
    </VStack>
  );
}

function EntryStepErrorFallback({ error }: ErrorFallbackProps) {
  const { formatMessage } = useIntl();
  const { amount, platformName, displaySymbol } = useFields(WithdrawForm);

  const handleOnPress = useCallback(() => {}, []);

  return (
    <VStack
      flexGrow={1}
      flexShrink={1}
      flexBasis="auto"
      minHeight={DEFAULT_WIDGET_HEIGHT_TALL}
    >
      <WithdrawHeader />
      <PaddedContent
        paddingTopDesktop={PADDING_TOP_INPUT}
        paddingTopMobile={PADDING_TOP_INPUT_SMALL}
      >
        <EntryInput
          viewerAssetRef={null}
          error={null}
          autoFocus={false}
          input={{
            symbol: platformName.value,
            displaySymbol: displaySymbol.value,
            value: amount.value,
            onChange: () => {},
            onEnter: () => {},
          }}
          secondaryButton={
            <EntryInputSecondaryButton onPress={handleOnPress} disabled>
              {formatMessage(messages.withdrawAll)}
            </EntryInputSecondaryButton>
          }
          disableInput
        />
        <Box offsetHorizontal={3} display="block">
          <PaymentsBannerEmptyState
            variant="cash-out"
