          />
        </Box>
        <Spacer vertical={2} />
        <VStack>
          <Button block loading={false} onPress={handleOnPress} disabled>
            {formatMessage(messages.continue)}
          </Button>
        </VStack>
      </PaddedContent>
      <WithdrawFooter assetOrCurrencyRef={null} />
      <MultiPortfolioDisclaimerV2
        transferType="withdraw"
        spacingHorizontal={3}
        spacingBottom={3}
      />
    </VStack>
  );
