  },
});

function InteracWithdrawConfirmationStep(_props: StepProps) {
  const { formatMessage } = useIntl();
  const formatCurrency = useCurrencyFormatter();
  const { email } = useUser();
  const toast = useToast();
  const { transferData } = useFields(WithdrawForm);
  const resetFlow = useResetFlow(WithdrawFlow);
  useLogEventOnMount('interac_withdraw_confirmation', {
    componentType: ComponentType.page,
    action: ActionType.view,
  });

  const [isLoading, setIsLoading] = useState(true);

  const onDonePress = useCallback(() => {
    logEvent('interac_withdraw_done_clicked', {
      action: ActionType.click,
      componentType: ComponentType.button,
    });
    resetFlow();
  }, [resetFlow]);

  const copyCode = useCallback(
    async (referenceNumber: string) => {
      logEvent('interac_withdraw_reference_code_copied', {
        componentType: ComponentType.button,
        action: ActionType.click,
      });
      await toast.hide();
      copyToClipboard(referenceNumber);
      toast.show(
        formatMessage(messages.copyToClipboard, { copyText: referenceNumber }),
      );
    },
    [formatMessage, toast],
  );

  useEffect(() => {
    markStep('loaded_fiat_withdraw_confirmation');
    setTimeout(() => setIsLoading(false), 1000);
  }, []);

  const handleOnPress = useCallback(() => {
    if (!transferData.value?.userReference) return null;
    return copyCode(transferData.value.userReference);
  }, [copyCode, transferData.value?.userReference]);

  if (!transferData.value || !transferData.value.userReference) {
    return null;
  }
  const { userReference, amount } = transferData.value;

  return (
    <PaddedContent
      paddingTopDesktop={24}
      paddingTopMobile={24}
      paddingBottom={24}
