          <>
            <Box>
              <SpotSquare
                name="confirmEmail"
                dimension="96x96"
                scaleMultiplier={1.25}
              />
            </Box>
            <TextTitle1 as="p" spacingBottom={1} align="center" color="primary">
              {formatCurrency({
                amount: {
                  amount: amount.value,
                  currency: amount.currency,
                },
                isFiat: true,
                maxDecimals: 2,
              })}
            </TextTitle1>
            <Box>
              <TextHeadline as="span" align="center">
                {formatMessage(messages.withdrawEmail, { email })}
              </TextHeadline>
            </Box>
            <TextBody
              as="p"
              color="foregroundMuted"
              align="center"
              spacingTop={2}
            >
              {formatMessage(messages.withdrawInfo)}
            </TextBody>
            <HStack alignItems="center" justifyContent="center" spacingTop={2}>
              <TextTitle3 as="p" color="foreground">
                {userReference}
              </TextTitle3>
              <IconButton transparent name="copy" onPress={handleOnPress} />
            </HStack>
            <VStack width="100%" spacingTop={3}>
              <Button block onPress={onDonePress}>
                {formatMessage(messages.done)}
              </Button>
            </VStack>
          </>
        )}
      </VStack>
    </PaddedContent>
  );
}

