  banner,
  isCenteredLayout,
}: LayoutProps) {
  const [
    showSpeedBumScreen,
    { toggleOn: showSpeedBum, toggleOff: hideSpeedBum },
  ] = useToggler();

  const handleExit = useCallback(() => {
    onSkip?.();
  }, [onSkip]);

  return showSpeedBumScreen ? (
    <SpeedBumScreen onContinue={hideSpeedBum} onExit={handleExit} />
  ) : (
    <ErrorBoundary
      owner="advanced-intl-perp"
      context="PerpetualFuturesOnboardingFlow"
    >
      <Navbar onSkip={showSpeedBum} logoRightContent={progressBar} />
      <VStack flexGrow={1}>
        {banner}
        <Container>
          <Primary
            className={cx(
              !secondaryContent && 'omitSecondaryContent',
              isCenteredLayout && 'centeredLayout',
            )}
            showBorder={!!secondaryContent}
          >
            <HStack spacerGap={3} alignItems="flex-start" width="85%">
              {!!onBackPress && (
                <Box flexGrow={1} spacingTop={2}>
                  <IconButton
                    onPress={onBackPress}
                    name={'backArrow'}
                    variant={'secondary'}
                    id="backIcon"
                    accessibilityLabelledBy="backIcon"
                  />
                </Box>
              )}
              <VStack>
                {title && (
                  <VStack spacingBottom={3} spacerGap={3}>
                    {titleMedia}
                    <TextDisplay2 as="h1">{title}</TextDisplay2>
                  </VStack>
                )}
                {description}
                {primaryContent}
              </VStack>
            </HStack>
          </Primary>
          {secondaryContent && <Secondary>{secondaryContent}</Secondary>}
        </Container>
      </VStack>
    </ErrorBoundary>
  );
}

