type FaqContent = string | ReactNode;

export type FaqItemProps = {
  question: FaqContent;
  answer: FaqContent;
  shouldShowDivider?: boolean;
  spacingVertical?: SpacingScale;
};

export function FaqItem({
  question,
  answer,
  spacingVertical = 3,
  shouldShowDivider = true,
}: FaqItemProps) {
