} from '../WidgetComponents/StepWithSuspense';
import StepWithSuspense from '../WidgetComponents/StepWithSuspense/StepWithSuspense';
import { IssuanceAgreementFragment$key } from './__generated__/IssuanceAgreementFragment.graphql';

const i18nKey = 'IssuanceAgreement';

const messages = defineMessages({
  esign: {
    id: `${i18nKey}.esign`,
    defaultMessage: 'Legal disclosures',
    description: `#Component: Header:title
    #CharLimit: 55
    #Context: Header for the disclosure step of the issuance flow`,
  },
  // 2023-10-05: TODO please fix, see go/i18n-linter-messages
  // eslint-disable-next-line @cbhq/i18n-enhanced-description
  continue: {
    id: `${i18nKey}.continue`,
    defaultMessage: `Scroll to the bottom to continue`,
    description: `Text for a button that scrolls to the bottom of legal disclosure`,
  },
  // 2023-10-05: TODO please fix, see go/i18n-linter-messages
  // eslint-disable-next-line @cbhq/i18n-enhanced-description
  accept: {
    id: `${i18nKey}.accept`,
    defaultMessage: `Accept`,
    description: `Text for a button that accepts legal disclosure`,
  },
});

// TODO: Remove this asap, need to get an appsec approved library
const TERMS_URL =
  'https://static-assets.coinbase.com/card/terms/v8/combined-terms.png';

type Props = {
  onAccept: () => void;
  onGoBack?: () => void;
  hasCloseButton?: boolean;
  // this prop is used for allowing to use deprecated non-CDS button. Once we fully migrate to CDS - this can be removed
  hasDeprecatedButton?: boolean;
  stepKey: string;
  cardRef: IssuanceAgreementFragment$key;
  acceptButtonLoading: boolean;
};

function IssuanceAgreement({
  onAccept,
  stepKey,
  onGoBack,
  hasCloseButton,
  hasDeprecatedButton,
  cardRef,
  acceptButtonLoading,
}: Props) {
  const closeModal = useCloseModal();
  const [checked, setChecked] = useState(false);
  const [hasScrolledToBottom, setHasScrolledToBottom] = useState(false);
  const stepContentRef = useRef<HTMLDivElement>(null);
  const { formatMessage } = useIntl();
  const buttonMessage = hasScrolledToBottom
    ? formatMessage(messages.accept)
    : formatMessage(messages.continue);
  const isDisabled = hasScrolledToBottom && !checked;

  const handleClick = useCallback(() => {
    if (hasScrolledToBottom) {
      onAccept();
    } else {
      stepContentRef.current?.scrollTo?.(0, 99999);
      setHasScrolledToBottom(true);
    }
  }, [onAccept, hasScrolledToBottom, setHasScrolledToBottom]);

  // 2023-10-19: TODO please fix
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleScroll = useCallback((event: any) => {
    const isScrolledToBottom =
      event.target.scrollHeight - event.target.scrollTop ===
      event.target.clientHeight;

    if (isScrolledToBottom) {
      setHasScrolledToBottom(true);
    }
  }, []);

  const query = useFragment(
    graphql`
      fragment IssuanceAgreementFragment on Card {
        applicationPrefillInfo @required(action: THROW) {
          agreementPdfUrl
          agreementText
          metabankCardholderAgreementUrl {
            url
            text
          }
          metabankPrivacyPolicyUrl {
            url
            text
          }
          shortFormAgreementUrl {
            url
            text
          }
          disclosures {
            url
            text
          }
          coinbaseUserAgreementUrl {
            url
            text
          }
          coinbaseCardTermsUrl {
            url
            text
          }
          coinbasePrivacyPolicyUrl {
            url
            text
          }
        }
      }
    `,
    cardRef,
  );

  const prefillInfo = query.applicationPrefillInfo;

  const handleOnCheckToggle = useCallback(
    () => setChecked(!checked),
    [checked],
  );

  return (
    <>
      <Header
        title={formatMessage(messages.esign)}
        goBack={onGoBack}
        hasDefaultCloseModal
        rightContent={
          <>
            <IconButton
              name="externalLink"
              to={prefillInfo.agreementPdfUrl}
              target="_blank"
              transparent
            />
            {hasCloseButton && (
              <IconButton
                onPress={closeModal}
                name="close"
                variant="secondary"
                transparent
              />
            )}
          </>
        }
        borderBottom
      />
      <StyledInnerStepContent
        key={stepKey}
        ref={stepContentRef}
        onScroll={handleScroll}
      >
        {/* // TODO: this is not a sustainable pattern
          We need to get an appsec approved PDF lib to host this
          so we can track scrolling. Embedded iframes dont allow
          you to access the DOM of the embedded window with JS so
          in order to track the scrolling we had to do this as it was
          blocking for CB Card launch
        */}
        <StyledTermsImage src={TERMS_URL} alt={formatMessage(messages.esign)} />
      </StyledInnerStepContent>
      <StickyButtonContainer>
        {hasScrolledToBottom && (
          <StyledCheckbox
            label={
              <TextLegal as="p" color="foregroundMuted">
                <TextWithLink
                  text={prefillInfo.agreementText}
                  objectWithLinks={prefillInfo}
                />
              </TextLegal>
            }
            labelPosition="right"
            checked={checked}
            onCheckToggle={handleOnCheckToggle}
          />
        )}
        {hasDeprecatedButton ? (
          <StepButton
            onClick={handleClick}
            disabled={isDisabled}
            loading={acceptButtonLoading}
          >
            {buttonMessage}
          </StepButton>
        ) : (
          <div style={{ display: 'flex', justifyContent: 'center' }}>
            <Button
              onPress={handleClick}
              disabled={isDisabled}
              loading={acceptButtonLoading}
            >
              {buttonMessage}
            </Button>
          </div>
        )}
      </StickyButtonContainer>
    </>
  );
}

const StyledTermsImage = styled(SuspenseImage)`
  max-width: 100%;
`;

const StyledInnerStepContent = styled(InnerStepContent)`
  padding: 0;
  scroll-behavior: smooth;
`;

const StyledCheckbox = styled(Checkbox)`
  align-items: flex-start;
  margin-bottom: ${({ theme }) => theme.size.large};

  ${Indicator} {
    margin-top: ${({ theme }) => theme.size.small};
