import {
  useContext,
  useEffect,
  useState,
  memo,
  useCallback,
  RefObject,
} from 'react';
import { useIntl } from 'react-intl';
import styled from 'styled-components';

import { toCssVar } from '@cb/shared/styles/colors';
import {
  cssValue,
  useDebounce,
  useScreenMatch,
  useViewportDimensions,
} from '@cb/shared/utils';
import { useSpectrumConditional } from '@cbhq/cds-common/hooks/useSpectrumConditional';
import { durations } from '@cbhq/cds-common/motion/tokens';
import { SearchInput } from '@cbhq/cds-web/controls';
import { VStack } from '@cbhq/cds-web/layout';
import { palette } from '@cbhq/cds-web/tokens';

import LockScroll from 'components/LockScroll';
import BodyScrollContext from 'context/BodyScrollContext';

import AssetSearchResults from './components/AssetSearchResults';
import { messages } from './messages';

export const SEARCH_DESKTOP_WIDTH = 300;

type SearchDesktopProps = {
  isSearching: boolean;
  setSearchOff: () => void;
  searchPositionRef: RefObject<HTMLElement>;
};

function SearchDesktop({
  isSearching,
  setSearchOff,
  searchPositionRef,
}: SearchDesktopProps) {
  const { formatMessage } = useIntl();
  const [inputValue, setInputValue] = useState('');
  const inputValueDebounced = useDebounce(inputValue, 250);

  const [visible, setVisible] = useState(false);
  const [searchPosition, setSearchPosition] = useState<DOMRect | null>(null);
  const [searchTopOffset, setSearchTopOffset] = useState(0);
  const [searchLeftOffset, setSearchLeftOffset] = useState(0);

  const { width: windowWidth, height: windowHeight } = useViewportDimensions();
  const { isLocked } = useContext(BodyScrollContext);
  const isDesktopLarge = useScreenMatch('desktop_large');

  const handleChangeText = useCallback((text: string) => {
    if (text === '/') {
      setInputValue(''); // avoid hotkey get typed in as search value
    } else {
      setInputValue(text);
    }
  }, []);

  const handleSearchBlur = useCallback(() => {
    setSearchOff();
    setInputValue('');
  }, [setSearchOff]);

  useEffect(() => {
    setSearchPosition(
      searchPositionRef.current?.getBoundingClientRect() ?? null,
    );
  }, [windowWidth, windowHeight, isDesktopLarge, isLocked]);

  useEffect(() => {
    setSearchTopOffset(searchPosition?.top ?? 0);
    setSearchLeftOffset(searchPosition?.left ?? 0);
  }, [searchPosition]);

  useEffect(() => {
    if (isSearching && searchTopOffset !== 0 && searchLeftOffset !== 0) {
      setVisible(true);
    }
  }, [isSearching, searchTopOffset, searchLeftOffset]);

  const overlayColor = useSpectrumConditional({
    light: palette.backgroundOverlay,
    dark: toCssVar(['gray0', 0.5]),
  });

  return (
    <>
      {visible ? <LockScroll /> : null}
      <Overlay
        visible={visible}
        onClick={handleSearchBlur}
        style={{ background: overlayColor }}
      />
      <Wrapper visible={visible} top={searchTopOffset} left={searchLeftOffset}>
        <VStack width={SEARCH_DESKTOP_WIDTH}>
          <SearchInput
            testID="header-search-bar"
            key="header-search-bar"
            compact
            value={inputValue}
            width="100%"
            height={40}
            autoCapitalize="none"
            onChangeText={handleChangeText}
            placeholder={formatMessage(messages.search)}
            autoFocus
          />
          <AssetSearchResults
            searchQuery={inputValueDebounced}
            handleSearchBlur={handleSearchBlur}
          />
        </VStack>
      </Wrapper>
    </>
  );
}

const Overlay = styled.div<{ visible: boolean }>`
  position: fixed;
  z-index: ${p => p.theme.zIndex.backdrop};
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  transition: opacity ${durations.moderate1}ms;
  opacity: ${p => (p.visible ? 1 : 0)};
  pointer-events: ${p => (p.visible ? 'auto' : 'none')};
`;

const Wrapper = styled.div<{ visible: boolean; top: number; left: number }>`
  position: fixed;
  opacity: ${p => (p.visible ? 1 : 0)};
  transition: opacity ${durations.moderate1}ms;
  z-index: ${p => p.theme.zIndex.overlay};
  top: ${p => cssValue(p.top - 1)}px;
  left: ${p => cssValue(p.left - 1)}px;
`;

export default memo(SearchDesktop);

