type TopNavigationBarMobileContentProps = HeaderBarProps & {
  queryRef: TopNavigationBarMobileFragment$key;
  content?: ReactNode;
  topOffset: number;
};

function TopNavigationBarMobileContent({
  queryRef,
  content: centerContent,
  topOffset,
}: TopNavigationBarMobileContentProps) {
  const { formatMessage } = useIntl();
  const query = useFragment(
    graphql`
      fragment TopNavigationBarMobileFragment on Query {
        ...HeaderBarNotificationButtonFragment
        ...MobileMenuFragment
      }
    `,
    queryRef,
  );

  const target = useIdentityTarget();
  const projectId =
    getEnvironmentVariable('COINBASE_ID_NAVIGATION_BAR_PROJECT_ID') ?? '';
  const { showKYCRefreshReviewPrompt } = useShowKYCRefreshReviewPrompt();

  const { hideSearch: shouldHideSearch } = useLayoutState();

  const [isSearching, { toggleOn: setSearchOn, toggleOff: setSearchOff }] =
    useToggler(false);
  const [isOpen, setIsOpen] = useState(false);

  const trackMoreMenuClicked = useLogSideBarButtonEvent(
    ActionType.click,
    'more',
  );
  const { colorMode, setThemeType } = useThemeType();

  const handleDarkModeToggleClick = useCallback(
    function handleDarkModeToggleClick() {
      setThemeType(colorMode === 'light' ? 'dark' : 'light');
    },
    [colorMode, setThemeType],
  );

  const bottomContent = useMemo(() => {
    return <HStack id={LAYOUT_TAB_NAVIGATION_ANCHOR} />;
  }, []);

  const startContent = useMemo(() => {
    return (
      <HStack spacerGap={1}>
        <HStack spacingVertical={0.5} spacingStart={0.5}>
          <IconButton
            name="hamburger"
            // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
            onPress={() => {
              setIsOpen(true);
              trackMoreMenuClicked();
            }}
            transparent
          />
        </HStack>
        <StyledConsumerLogo />
      </HStack>
    );
  }, [trackMoreMenuClicked]);

  const content = useMemo(() => {
    return (
      <>
        <HStack id={LAYOUT_CENTER_ANCHOR}>{centerContent}</HStack>
        <MobileMenu
          isOpen={isOpen}
          // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
          onClose={() => setIsOpen(false)}
          queryRef={query}
        />
        {!shouldHideSearch && isSearching && (
          <SearchMobile isSearching={isSearching} setSearchOff={setSearchOff} />
        )}
      </>
    );
  }, [
    centerContent,
    isOpen,
    isSearching,
    query,
    setSearchOff,
    shouldHideSearch,
  ]);

  const endContent = useMemo(() => {
    return (
      <HStack spacerGap={1}>
        {!shouldHideSearch && (
          <SearchButton isSearching={isSearching} setSearchOn={setSearchOn} />
        )}
        <LazyHeaderBarNotificationButton queryRef={query} />
      </HStack>
    );
  }, [isSearching, query, setSearchOn, shouldHideSearch]);

  const handleNavigate = useCallback(
    async (pathName: string) => {
      if (!pathName?.includes('/signout')) {
        window.location.assign(pathName);
        return;
      }
      setIsOpen(false);
      // we want to show the prompt only for sign out click
      showKYCRefreshReviewPrompt('signOut', () => {
        window.location.assign(pathName);
      });
    },
    [showKYCRefreshReviewPrompt],
  );

  return (
    <VStack>
      <TopPadding topOffset={topOffset} />
      <IDNavigationBar
        target={target}
        action="web-retail-NavigationBar"
        projectId={projectId}
        onThemeToggle={handleDarkModeToggleClick}
        activeThemeLabel={
          colorMode === 'dark'
            ? formatMessage(messages.darkMode)
            : formatMessage(messages.lightMode)
        }
        themeToggleValue={colorMode === 'dark' ? 'dark' : 'light'}
        start={startContent}
        end={endContent}
        bottom={bottomContent}
        navigate={handleNavigate}
      >
        {content}
      </IDNavigationBar>
    </VStack>
  );
}

function KYCRefreshReviewPromptSignOutButton() {
  const { formatMessage } = useIntl();
  return (
    <Button variant="secondary" to="/signout">
      {formatMessage(messages.signOut)}
    </Button>
  );
}

export default function TopNavigationBarMobile(
  props: TopNavigationBarMobileContentProps,
  fallback: ReactNode,
) {
  const renderFallback = useCallback(() => fallback, [fallback]);

  const handleSignoutOnInactivity = useCallback(() => {
    window.location.href = '/signout';
  }, []);

  return (
    <ErrorBoundary
      owner="infra"
      fallback={renderFallback}
      context="top_navigation_bar"
    >
      <InstrumentedSuspense
        instrumentationId="TopNavigationBar"
        fallback={fallback}
      >
        <KYCRefreshReviewPromptProvider
          onInactivity={handleSignoutOnInactivity}
          bottomButton={<KYCRefreshReviewPromptSignOutButton />}
        >
          <TopNavigationBarMobileContent {...props} />
        </KYCRefreshReviewPromptProvider>
      </InstrumentedSuspense>
    </ErrorBoundary>
  );
}

