type Props = {
  queryRef: AchBankAccountFormFragment$key;
  onSubmit: () => void;
};

function AchBankAccountForm({ queryRef, onSubmit }: Props) {
  const query = useFragment(
    graphql`
      fragment AchBankAccountFormFragment on Query {
        viewer {
          userProperties {
            userType
          }
        }
      }
    `,
    queryRef,
  );

  const { viewer } = query;
  const { userProperties } = viewer;
  const { userType } = userProperties;

  const [focusedField, setFocusedField] = useState('routing');
  const accountNumberField = useRef<HTMLInputElement | undefined>();
  const routingNumberField = useRef<HTMLInputElement | undefined>();
  const nameField = useRef<HTMLInputElement | undefined>();
  const intl = useIntl();
  const { formatMessage } = intl;

  const {
    detectOmega,
    markValid,
    markInvalid,
    handleFormChange,
    clearServerError,
    createBankAccount,
    formData,
    valid,
    loading,
    serverError,
  } = useAchBankAccountForm({
    client,
    account: accountTypes[0].value,
  });

  const activeAccount = formData.account;

  const filteredTypes = useMemo(() => {
    return accountTypes
      .filter((a: AccountType) =>
        userType === 'individual' ? a.value !== 'business_checking' : true,
      )
      .sort((a: AccountType) => (a.value === activeAccount ? -1 : 1));
  }, [userType, activeAccount]);

  const handleFieldFocused = useCallback(
    (fieldName: 'routing' | 'name' | 'account') => {
      setFocusedField(fieldName);
    },
    [],
  );

  const handleSetField = useCallback(
    (fieldName: 'routingNumber' | 'accountNumber' | 'name') => {
      return (ref: HTMLInputElement) => {
        if (!ref) {
          return;
        }

        const input = ref.getElementsByTagName('input')[0];

        if (!input) {
          return;
        }

        switch (fieldName) {
          case 'routingNumber':
            routingNumberField.current = input;
            return;

          case 'accountNumber':
            accountNumberField.current = input;
            return;

          case 'name':
          default:
            nameField.current = input;
        }
      };
    },
    [],
  );

  const handleUnsetFocusedField = useCallback((event: React.SyntheticEvent) => {
    if (!event) return setFocusedField('none');

    // Only in the case where we blur an input, but not to the other
    // routing/account number input, do we set the focusedField to none.
    // This is because setting focusedField to none unsets the CSS 'left'
    // property -- which disables animation upon re-focusing.
    // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
    if (event.relatedTarget === accountNumberField.current) {
      setFocusedField('account');
    } else if (
      // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
      event.relatedTarget === routingNumberField.current
    ) {
      setFocusedField('routing');
      // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
    } else if (event.relatedTarget === nameField.current) {
      setFocusedField('name');
    } else {
      setFocusedField('none');
    }
  }, []);

  const handleValidForm = useCallback(() => {
    markValid();
  }, [markValid]);

  const handleInvalidForm = useCallback(() => {
    markInvalid();
  }, [markInvalid]);

  const handleSubmit = useCallback(async () => {
    try {
      await createBankAccount();
      onSubmit();
    } catch {}
  }, [createBankAccount, onSubmit]);

  const handleOnFocus = useCallback(
    () => handleFieldFocused('routing'),
    [handleFieldFocused],
  );

  const handleOnFocus1 = useCallback(
    () => handleFieldFocused('account'),
    [handleFieldFocused],
  );

  const handleOnFocus2 = useCallback(
    () => handleFieldFocused('name'),
    [handleFieldFocused],
  );

  return (
    <SensitiveDataWrapper>
      <VStack testID="ach-bank-account-form">
        {!!serverError && (
          <Section>
            <Alert
              inline
              subtitle={serverError}
              type="error"
              onClickPrimary={clearServerError}
              primaryLabel={formatMessage(messages.dismiss)}
            />
          </Section>
        )}
        <Form
          // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
          onChange={handleFormChange}
          onSubmit={handleSubmit}
          onValid={handleValidForm}
          onInvalid={handleInvalidForm}
          initialValues={{
            account: activeAccount,
          }}
        >
          <FormGroup>
            <Labeled auto label={formatMessage(messages.bankAccountTypeLabel)}>
              <SelectList value={activeAccount} name="account">
                {filteredTypes.map((accountType: AccountType) => (
                  <SelectListItem
                    key={accountType.value}
                    value={accountType.value}
                    label={accountType.label}
                  />
                ))}
              </SelectList>
            </Labeled>
          </FormGroup>
          <CheckSection>
            <CheckContainer>
              <NumberBorder focusedField={focusedField} />
              <Check />
            </CheckContainer>
            <Row>
              <Col desktop={6} mobile={12} flexDirection="column">
                <PaddingContainer
                  ref={handleSetField('routingNumber')}
                  direction="right"
                >
                  <Labeled label={formatMessage(messages.routingNumber)} auto>
                    <ValidatedInput
                      autoFocus
                      maxLength={9}
                      name="routingNumber"
                      placeholder={formatMessage(messages.routingNumber)}
                      onFocus={handleOnFocus}
                      onBlur={handleUnsetFocusedField}
                      onPaste={detectOmega}
                      validators={[
                        ...makeRouterValidators(intl),
                        [required, undefined],
                      ]}
                    />
                  </Labeled>
                </PaddingContainer>
              </Col>
              <Col desktop={6} mobile={12} flexDirection="column">
                <PaddingContainer
                  ref={handleSetField('accountNumber')}
                  direction="left"
                >
                  <Labeled label={formatMessage(messages.accountNumber)} auto>
                    <ValidatedInput
                      maxLength={17}
                      name="accountNumber"
                      placeholder={formatMessage(messages.accountNumber)}
                      onFocus={handleOnFocus1}
                      onBlur={handleUnsetFocusedField}
                      onPaste={detectOmega}
                      validators={[[required, undefined]]}
                    />
                  </Labeled>
                </PaddingContainer>
              </Col>
            </Row>
            <NameField>
              <PlainContainer ref={handleSetField('name')}>
                <Labeled label={formatMessage(messages.fullName)} auto>
                  <ValidatedInput
                    name="fullName"
                    placeholder={formatMessage(messages.namePlaceholder)}
                    onFocus={handleOnFocus2}
                    onBlur={handleUnsetFocusedField}
                    validators={[
                      [required, formatMessage(messages.fullNameRequiredError)],
                    ]}
                  />
                </Labeled>
              </PlainContainer>
            </NameField>
          </CheckSection>
          <Button
            block
            disabled={loading || !valid}
            loading={loading}
            type="submit"
          >
            {formatMessage(messages.verifyBankButtonLabel)}
          </Button>
        </Form>
      </VStack>
    </SensitiveDataWrapper>
  );
}

