    componentType: ComponentType.page,
    action: ActionType.render,
  });

  const handleSuccess = useCallback(() => {
    toasts.showSuccessToast(formatMessage(messages.successMessage));
    if (close) close();
    if (onSuccess) onSuccess();
  }, [close, formatMessage, onSuccess, toasts]);

  const handleOnValid = useCallback(() => {
    setValidationError(undefined);
  }, []);

  const handleOnInvalid = useCallback((errors: ErrorsType) => {
    setValidationError(
      (errors.depositAmount1 && errors.depositAmount1[0]) ||
        (errors.depositAmount2 && errors.depositAmount2[0]),
