              flexGrow={1}
              flexShrink={1}
              flexBasis="auto"
            >
              <FormLabel>{formatMessage(messages.amount2FieldLabel)}</FormLabel>
              <ValidatedInput
                name="depositAmount2"
                size={2}
                annotation="$0."
                maxLength={2}
                placeholder="00"
                hideInlineErrorMessages
                validators={[
                  [required, formatMessage(messages.validationRequired)],
                  [length(2), formatMessage(messages.validationLength)],
                  [numeric, formatMessage(messages.validationNumeric)],
                ]}
              />
            </PaddingContainer>
          </HStack>
          {validationError && (
