function EmailVerificationModal({
  close,
  onSuccess,
  paymentMethodId,
  shouldSendEmailOnMount = false,
}: Props) {
  const { formatMessage } = useIntl();
  const { showSuccessToast, showErrorToast } = useToasts();
  const [isValid, setIsValid] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isResendLoading, setIsResendLoading] = useState(false);
  const [step, setStep] = useState<Step>('form');

  const setValid = useCallback(() => setIsValid(true), [setIsValid]);
  const setInvalid = useCallback(() => setIsValid(false), [setIsValid]);

  const [sendEmailVerification] =
    useMutation<EmailVerificationModalSendEmailVerificationMutation>(graphql`
      mutation EmailVerificationModalSendEmailVerificationMutation(
        $input: SendPaymentMethodEmailVerificationInput!
      ) {
        sendPaymentMethodEmailVerification(input: $input) {
          ... on SendPaymentMethodEmailVerificationSuccess {
            emailVerificationStatus
          }
        }
      }
    `);

  const [verifyEmailCode] =
    useMutation<EmailVerificationModalVerifyEmailCodeMutation>(graphql`
      mutation EmailVerificationModalVerifyEmailCodeMutation(
        $input: VerifyPaymentMethodEmailCodeInput!
      ) {
        verifyPaymentMethodEmailCode(input: $input) {
          ... on VerifyPaymentMethodEmailCodeSuccess {
            emailVerificationStatus
          }
        }
      }
    `);

  useEffect(() => {
    if (shouldSendEmailOnMount) {
      sendEmailVerification({
        variables: { input: { paymentMethodUuid: paymentMethodId } },
        onError: ({ alreadyReportedError }) => {
          showErrorToast(alreadyReportedError.message);
          notifyError(getErrorInstance(alreadyReportedError), {
            owner: 'payment',
            paymentMethodUuid: paymentMethodId,
            context: 'link_ach',
          });
        },
      });
    }
  }, []);

  const handleSubmit = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    ({ code }: any) => {
      setIsSubmitting(true);

      verifyEmailCode({
        variables: { input: { code, paymentMethodUuid: paymentMethodId } },
        onCompleted: ({ response }) => {
          if (!response.verifyPaymentMethodEmailCode) {
            // https://jira.coinbase-corp.com/browse/PYP-433
            // once ^ is complete, change this to only setStep('code_expired') if request returns 404 (otherwise, show error toast)
            setStep('code_expired');
          } else {
            setStep('success');
            onSuccess?.();
          }
          setIsSubmitting(false);
        },
        onError: ({ alreadyReportedError }) => {
          notifyError(getErrorInstance(alreadyReportedError), {
            owner: 'payment',
            code,
            paymentMethodUuid: paymentMethodId,
            context: 'link_ach',
          });
          setIsSubmitting(false);
          showErrorToast(alreadyReportedError.message);
        },
      });
    },
    [verifyEmailCode, paymentMethodId, onSuccess, showErrorToast],
  );

  const handleResend = useCallback(
    (event: React.MouseEvent<HTMLButtonElement, MouseEvent>) => {
      event.preventDefault();
      event.stopPropagation();

      setIsResendLoading(true);

      sendEmailVerification({
        variables: { input: { paymentMethodUuid: paymentMethodId } },
        onCompleted: ({ response }) => {
          if (!response.sendPaymentMethodEmailVerification) {
            notifyError(
              new Error('Send bank account email verification request failed'),
              { owner: 'payment', context: 'link_ach' },
            );
          }
          setStep('form');
          showSuccessToast(formatMessage(messages.codeResentToast));
          setIsResendLoading(false);
        },
        onError: ({ alreadyReportedError }) => {
          showErrorToast(alreadyReportedError.message);
          notifyError(getErrorInstance(alreadyReportedError), {
            owner: 'payment',
            paymentMethodUuid: paymentMethodId,
            context: 'link_ach',
          });
          setIsResendLoading(false);
        },
      });
    },
    [
      sendEmailVerification,
      paymentMethodId,
      showSuccessToast,
      formatMessage,
      showErrorToast,
    ],
  );

  const handleSuccessContinue = useCallback(() => {
    close?.();
  }, [close]);

  const handleClose = useCallback(() => {
    close?.();
  }, [close]);

  return (
    <Modal close={handleClose} width="small">
      <ModalHeader title={formatMessage(messages.title)} />
      <ModalBody>
        {step === 'form' && (
          <HStack height="100%">
            <Form
              // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
              onSubmit={handleSubmit}
              onValid={setValid}
              onInvalid={setInvalid}
            >
              <VStack height="100%" justifyContent="space-between">
                <div>
                  <TextBody as="p" color="foregroundMuted">
                    {formatMessage(messages.description)}
                  </TextBody>
                  <StyledFormGroup>
                    <Labeled
                      auto
                      bold
                      label={formatMessage(messages.codeLabel)}
                    >
                      <ValidatedInput
                        autoFocus
                        name="code"
                        placeholder={formatMessage(messages.codeLabel)}
                        validators={[[required, undefined]]}
                        maxLength={4}
                      />
                    </Labeled>
                  </StyledFormGroup>
                </div>
                <div>
                  <Button
                    data-testid="submit-button"
                    size="large"
                    fullWidth
                    disabled={!isValid || isSubmitting}
                    loading={isSubmitting}
                  >
                    {formatMessage(messages.submit)}
                  </Button>
                  <StyledResendButton
                    data-testid="resend-button"
                    size="large"
                    fullWidth
                    type="outlineWhite"
                    onClick={handleResend}
                    disabled={isResendLoading || isSubmitting}
                    loading={isResendLoading}
                  >
                    {formatMessage(messages.resendEmail)}
                  </StyledResendButton>
                </div>
              </VStack>
            </Form>
          </HStack>
        )}

        {step === 'code_expired' && (
          <VStack height="100%" justifyContent="space-between">
            <VStack justifyContent="center" alignItems="center">
              <StyledStatusTick type="failure" />
              <Header level={3} marginBottom="md">
                {formatMessage(messages.expiredTitle)}
              </Header>
              <TextBody
                as="p"
                spacingBottom={3}
                color="foregroundMuted"
                align="center"
              >
                {formatMessage(messages.expiredDescription)}
              </TextBody>
            </VStack>
            <Button
              size="large"
              fullWidth
              onClick={handleResend}
              disabled={isResendLoading}
              loading={isResendLoading}
            >
              {formatMessage(messages.resendEmail)}
            </Button>
          </VStack>
        )}

        {step === 'success' && (
          <VStack height="100%" justifyContent="space-between">
            <VStack justifyContent="center" alignItems="center">
              <StyledStatusTick type="success" />
              <Header level={3} marginBottom="md">
                {formatMessage(messages.successTitle)}
              </Header>
              <TextBody
                as="p"
                spacingBottom={3}
                color="foregroundMuted"
                align="center"
              >
                {formatMessage(messages.successDescription)}
              </TextBody>
            </VStack>
            <Button
              data-testid="button-success-continue"
              size="large"
              fullWidth
              onClick={handleSuccessContinue}
            >
              {formatMessage(messages.continue)}
            </Button>
          </VStack>
        )}
      </ModalBody>
    </Modal>
  );
}

