const i18nKey = 'BillingAddressInput';

const messages = defineMessages({
  label: {
    id: `${i18nKey}.label`,
    defaultMessage: 'Billing address',
    description: `#Component: Label
    #CharLimit: 50
    #Context: Label for the billing address input`,
  },
  placeholderText: {
    id: `${i18nKey}.placeholderText`,
    defaultMessage: 'Add billing address',
    description: `#Component: Button
    #CharLimit: 30
    #Context: Label for the billing address input when it is not pre-filled`,
  },
});

type BillingAddressInputProps = {
  billingAddress?: AddressData;
  onPress: () => void;
};

// Any formatted address display longer than this will be truncated
const MAX_DISPLAY_CHARS = 35;

function formatAddress(address?: AddressData) {
  if (!address) {
    return;
  }

  const { postalCode, city, state } = address;

  if (postalCode && city && state) {
    // If the postal code ends in -XXXX, we should trim off the hyphen and everything after it
    const trimmedPostalCode = postalCode.replace(/-.*$/, '');

    const display = `${trimmedPostalCode}, ${city}, ${state}`;

    // if the display is longer than MAX_DISPLAY_CHARS, we should truncate it and add "..."
    return display.length > MAX_DISPLAY_CHARS
      ? `${display.substring(0, MAX_DISPLAY_CHARS - 3)}...`
      : display;
  }
}

export default function BillingAddressInput({
  billingAddress,
  onPress,
}: BillingAddressInputProps) {
  const { formatMessage } = useIntl();

  return (
    <VStack>
      {/* nick-janda: Using TextLabel2 instead of setting the label prop on the TextInput so that it matches the rest of the non-CDS form */}
      <TextLabel2 as="p" spacingBottom={1}>
        {formatMessage(messages.label)}
      </TextLabel2>
      <Pressable as="button" background="transparent" onPress={onPress}>
        <TextInput
          placeholder={formatMessage(messages.placeholderText)}
          value={
            formatAddress(billingAddress) ??
            formatMessage(messages.placeholderText)
          }
          readOnly
          borderRadius="rounded"
          color="#E5E5E7"
          end={<InputIcon name="caretRight" />}
          // nick-janda: height is overridden to match the non-CDS fields on this form
          height="67px"
          testID="billing-address-input"
        />
      </Pressable>
    </VStack>
  );
}

