          [required, validationErrorMsg],
          [creditCardNumber, validationErrorMsg],
          [
            creditCardNetwork(['visa', 'mastercard', 'maestro']),
            formatMessage(messages.validationCardNetwork),
          ],
        ]}
        placeholder="XXXX XXXX XXXX XXXX"
        mask="9999 9999 9999 9999"
        maskChar=""
        autoComplete="cc-number"
        icon={
          shouldDisplayCardScanIcon ? (
            <CardScanButton onClick={handleCardScanButtonClick}>
              {improveCardScan ? (
                <TextLabel1 as="p" color="primary">
                  {formatMessage(messages.scanCard)}
                </TextLabel1>
              ) : (
                <Camera />
              )}
            </CardScanButton>
          ) : (
            <CardLogos />
          )
        }
        autoFocus={!isWebview}
        inputMode="numeric"
      />
      {isCardUXImprovementsEnabled ? (
        <TextLabel2 as="p" color="foregroundMuted">
          {formatMessage(messages.debitCardOnly)}
        </TextLabel2>
      ) : null}
    </StyledLabeled>
  );
}

