type Props = {
  onSuccess: (id: string, code: string, address?: AddressData) => void;
  isCondensedCardAddressEnabled?: boolean;
  billingAddress?: AddressData;
};

function CreditCardBillingAddress({
  onSuccess,
  isCondensedCardAddressEnabled,
  billingAddress,
}: Props) {
  const { formatMessage } = useIntl();
  const { useLogAddPaymentEventOnMount, logAddPaymentEvent: logEvent } =
    useAddPaymentMethodUtils();

  const processorType = useCreditCardProcessor();
  const { countryCode, addressLine1, addressLine2, city, state, postalCode } =
    useUser();

  const initialValues = useMemo(
    () => ({
      address1: billingAddress?.line1 ?? addressLine1,
      address2: billingAddress?.line2 ?? addressLine2,
      city: billingAddress?.city ?? city,
      state: billingAddress?.state ?? state,
      postalCode: billingAddress?.postalCode ?? postalCode,
    }),
    [addressLine1, addressLine2, billingAddress, city, postalCode, state],
  );

  const submitButtonText = useMemo(
    () =>
      isCondensedCardAddressEnabled && initialValues.postalCode?.length > 0
        ? formatMessage(messages.submitButtonUpdate)
        : formatMessage(messages.submitButton),
    [
      formatMessage,
      initialValues.postalCode?.length,
      isCondensedCardAddressEnabled,
    ],
  );

  const {
    activeCountry,
    setActiveCountry,
    requireState,
    addBillingAddress,
    error,
  } = useCreditCardBillingAddress({
    onSuccess,
    countryCode,
    logEvent,
  });

  const isCreditCardDisabled = useIsAddCreditCardDisabled();
  const isWebview = useIsWebView();

  useLogAddPaymentEventOnMount('credit_card_billing_address_start_flow', {
    action: ActionType.render,
    cardType: processorType,
    componentType: ComponentType.page,
  });

  useEffect(() => {
    markStepOnce('user_viewed_card_billing_address_screen');
    triggerResearchEventOnUserAction('CREDIT_CARD_BILLING_ADDRESS_START_FLOW');
  }, []);

  /**
   * Custom logic for city, state and postal code fields
   *
   * Due to length of the fields, error messages are grouped from <Form/>
   * callbacks and showed outside the components.
   */
  const [errors, setErrors] = useState<string[]>([]);
  const handleValidForm = useCallback(() => setErrors([]), []);
  const handleInvalidForm = useCallback(
    (formErrors: { [k: string]: Array<string> }) => {
      const newErrors: string[] = [];

      // Add new ones, but only one per field
      Object.keys(formErrors).forEach(field => {
        const error = formErrors[field][0];

        if (
          ['city', 'state', 'postalCode'].includes(field) &&
          !newErrors.includes(error)
        ) {
          // Only push the first error as there can be dups
          newErrors.push(error);
        }
        setErrors(newErrors);
      });
    },
    [],
  );

  const StateInput = useMemo(() => {
    return (
      <ValidatedInput
        name="state"
        maxLength={2}
        size={6}
        placeholder={formatMessage(messages.state)}
        validators={[
          [required, formatMessage(messages.validationState)],
          [minLength(1), formatMessage(messages.validationState)],
          [stateCode, formatMessage(messages.validationState)],
        ]}
        hideInlineErrorMessages
      />
    );
  }, [formatMessage]);

  const PostalCodeInput = useMemo(() => {
    return (
      <ValidatedInput
        name="postalCode"
        size={10}
        validators={[
          [minLength(3), formatMessage(messages.validationPostalCode)],
        ]}
        hideInlineErrorMessages
        placeholder={requireState ? 'ZIP' : undefined}
      />
    );
  }, [formatMessage, requireState]);

  return (
    <VStack height="100%">
      {error && (
        <FormGroup>
          <InlineAlert type="error" title={error} />
        </FormGroup>
      )}
      {isCondensedCardAddressEnabled ? (
        <TextHeadline spacingBottom={2} as="p">
          {formatMessage(messages.confirmationBillingAddress)}
        </TextHeadline>
      ) : isCreditCardDisabled ? (
        <TextBody spacingBottom={2} as="p">
          {formatMessage(messages.descriptionDebitOnly)}
        </TextBody>
      ) : (
        <TextBody spacingBottom={2} as="p">
          {formatMessage(messages.description)}
        </TextBody>
      )}
      {!isCondensedCardAddressEnabled && (
        <FormGroup flexGrow={0} flexShrink={0} flexBasis="auto">
          <Labeled label={formatMessage(messages.country)} auto>
            <CountrySelect
              activeCountry={activeCountry}
              onSelectCountry={setActiveCountry}
            />
          </Labeled>
        </FormGroup>
      )}
      <FlexForm>
        <Form
          // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
          onSubmit={addBillingAddress}
          onValid={handleValidForm}
          // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
          onInvalid={handleInvalidForm}
          initialValues={initialValues}
        >
          <FormGroup>
            <Labeled
              label={formatMessage(
                isCondensedCardAddressEnabled
                  ? messages.firstAddressLine
                  : messages.address1,
              )}
              auto
            >
              <ValidatedInput
                name="address1"
                placeholder={formatMessage(messages.address1)}
                validators={[
                  [required, formatMessage(messages.validationAddress)],
                  [minLength(1), formatMessage(messages.validationAddress)],
                ]}
                autoFocus={!isWebview}
              />
            </Labeled>
          </FormGroup>
          <FormGroup>
            <Labeled
              label={formatMessage(
                isCondensedCardAddressEnabled
                  ? messages.secondAddressLine
                  : messages.address2,
              )}
              auto
            >
              <ValidatedInput
                name="address2"
                placeholder={formatMessage(messages.address2Placeholder)}
                validators={[]}
              />
            </Labeled>
          </FormGroup>
          <FormGroup flexWrap="nowrap" flexDirection="column">
            <ContainerLocation flexGrow={1} flexShrink={1} flexBasis="auto">
              <SpacedLabeled label={formatMessage(messages.city)} auto>
                <ValidatedInput
                  name="city"
                  size={1}
                  placeholder={formatMessage(messages.city)}
                  validators={[
                    [required, formatMessage(messages.validationCity)],
                    [minLength(1), formatMessage(messages.validationCity)],
                  ]}
                  hideInlineErrorMessages
                />
              </SpacedLabeled>
              {isCondensedCardAddressEnabled ? (
                <HStack spacerGap={2} spacingVertical={2}>
                  {requireState && (
                    <>
                      <Labeled label={formatMessage(messages.state)} stretch>
                        {StateInput}
                      </Labeled>
                    </>
                  )}
                  <LabeledPostalCode
                    label={formatMessage(messages.postalCode)}
                    stretch
                  >
                    {PostalCodeInput}
                  </LabeledPostalCode>
                </HStack>
              ) : (
                <>
                  {requireState && (
                    <SpacedLabeled label={formatMessage(messages.state)}>
                      {StateInput}
                    </SpacedLabeled>
                  )}
                  <Labeled label={formatMessage(messages.postalCode)}>
                    {PostalCodeInput}
                  </Labeled>
                </>
              )}
            </ContainerLocation>
            {errors && (
              <VStack>
                {errors.map(error => (
                  <InlineError key={error}>{error}</InlineError>
                ))}
              </VStack>
            )}
          </FormGroup>
          <Spacer flexGrow={1} />
          <HStack flexShrink={1} flexBasis="auto" spacingBottom={6}>
            <Button block type="submit">
              {submitButtonText}
            </Button>
          </HStack>
        </Form>
      </FlexForm>
    </VStack>
  );
}

const SpacedLabeled = styled(Labeled)`
  @media not all and (${devices.phone}) {
    margin-right: ${size.large};
  }

