type ScrollButtonProps = {
  backgroundColor: string;
  direction: 'left' | 'right';
  containerRef: RefObject<HTMLElement>;
};

export function ScrollButton({
  backgroundColor,
  direction,
  containerRef,
}: ScrollButtonProps) {
  const scroll = useCallback(() => {
    if (!containerRef.current) {
      return;
    }
    const distance = containerRef.current?.clientWidth / 2;

    containerRef.current.scrollBy({
      left: direction === 'left' ? -distance : distance,
      behavior: 'smooth',
    });
  }, [containerRef, direction]);

  const style = useMemo(
    () => ({
      color: backgroundColor,
    }),
    [backgroundColor],
  );

  return (
    <Box position="relative" alignItems="center">
      <StyledBox
        right={direction === 'left' ? 'unset' : 0}
        left={direction === 'right' ? 'unset' : 0}
        position="absolute"
        zIndex={zIndex.interactable}
        direction={direction}
        style={style}
      >
        <IconButton
          name={direction === 'left' ? 'caretLeft' : 'caretRight'}
          onPress={scroll}
        />
      </StyledBox>
    </Box>
  );
}

const StyledBox = styled(Box)<{ direction: string }>`
  &:before {
    content: '';
    width: 80px;
    height: 100%;
    position: absolute;
    pointer-events: none;

    ${p => (p.direction === 'left' ? 'left' : 'right')}: 0;
    background: linear-gradient(
      to ${p => (p.direction === 'left' ? 'right' : 'left')},
      currentColor 50%,
      ${palette.transparent} 100%
    );
    transform-origin: ${p => (p.direction === 'left' ? 'left' : 'right')};
  }
`;

