type Props = {
  queryRef: PortfolioTransferEntryStepFragment$key;
  isDefaultStep?: boolean;
};

function AssetSelectorStep({ queryRef, isDefaultStep = false }: Props) {
  const { formatMessage } = useIntl();
  const formatCurrency = useCurrencyFormatter();
  const nativeCurrency = useNativeCurrency();

  const {
    assetField,
    sourcePortfolioField,
    targetPortfolioField,
    amountField,
    isNativeCurrencyInputField,
  } = useFields(portfolioTransferForm);

  const { symbol: assetSymbol, isFiatAsset, exponent } = assetField.value;
  const sourcePortfolioUuid = sourcePortfolioField.value.uuid;
  const targetPortfolioUuid = targetPortfolioField.value.uuid;

  const isAssetNativeCurrency = nativeCurrency === assetSymbol;

  const { replaceStep, goToStep } = useStepper(portfolioTransferStepper);

  const [nativeCurrencyInput, setNativeCurrencyInput] = useState<string>(
    amountField.value.rawAmountInNativeCurrency,
  );
  const [assetCurrencyInput, setAssetCurrencyInput] = useState<string>(
    amountField.value.rawAmount,
  );
  const [isNativeCurrencyInput, setIsNativeCurrencyInput] = useState<boolean>(
    isNativeCurrencyInputField.value,
  );

  const query = useFragment(
    graphql`
      fragment PortfolioTransferEntryStepFragment on Query {
        ...TransferPortfolioSelectorCellFragment

        viewer {
          sourcePortfolio: portfolioByUuid(
            uuid: $sourcePortfolioUuid
            currency: $nativeCurrency
          ) {
            spotPositions(assetSymbol: $assetSymbol) {
              edges {
                node {
                  availableToTradeFiat {
                    amount
                    currency
                  }
                  availableToTradeCrypto {
                    amount
                    currency
                  }
                }
              }
            }
          }
        }
        assetBySymbol(symbol: $assetSymbol) {
          ...useCurrencyConverterSourceAssetFragment
        }
      }
    `,
    queryRef,
  );

  const handleBackButtonPress = useCallback(() => {
    replaceStep(PortfolioTransferModalSteps.AssetSelector);
  }, [replaceStep]);

  const sourceSpotPosition =
    query.viewer.sourcePortfolio?.spotPositions?.edges?.[0]?.node;

  const availableBalanceInAssetCurrency =
    sourceSpotPosition?.availableToTradeCrypto?.amount ?? '0';

  const availableBalanceInNativeCurrency =
    sourceSpotPosition?.availableToTradeFiat?.amount ?? '0';

  const selectedPortfolioAvailableBalance = isNativeCurrencyInput
    ? Number(availableBalanceInNativeCurrency)
    : Number(availableBalanceInAssetCurrency);

  const entryAmount = isNativeCurrencyInput
    ? nativeCurrencyInput
    : assetCurrencyInput;

  const [showError, setShowError] = useState<boolean>(
    selectedPortfolioAvailableBalance <= 0 && !!query.viewer.sourcePortfolio,
  );

  useEffect(() => {
    setShowError(
      selectedPortfolioAvailableBalance <= 0 && !!query.viewer.sourcePortfolio,
    );
  }, [selectedPortfolioAvailableBalance, query.viewer.sourcePortfolio]);

  const previewButtonEnabled = useMemo(() => {
    return (
      Number(entryAmount ?? '0') > 0 &&
      Number(entryAmount ?? '0') <= selectedPortfolioAvailableBalance &&
      !!parseFloat(entryAmount) &&
      !!sourcePortfolioUuid &&
      !!targetPortfolioUuid
    );
  }, [
    entryAmount,
    selectedPortfolioAvailableBalance,
    sourcePortfolioUuid,
    targetPortfolioUuid,
  ]);

  const inputEnabled = useMemo(
    () =>
      !!sourcePortfolioUuid &&
      !!targetPortfolioUuid &&
      !!selectedPortfolioAvailableBalance,
    [
      sourcePortfolioUuid,
      targetPortfolioUuid,
      selectedPortfolioAvailableBalance,
    ],
  );

  const convertCurrency = useCurrencyConverter({
    sourceAssetRef: query.assetBySymbol,
    nativeCurrency,
  });

  const handleChange = useCallback(
    (value?: string | undefined) => {
      const nonNullValue = value ?? '';

      const convertedAmount = convertCurrency(
        {
          value: nonNullValue,
          currency: isNativeCurrencyInput ? nativeCurrency : assetSymbol,
        },
        isNativeCurrencyInput ? assetSymbol : nativeCurrency,
      );

      if (convertedAmount !== undefined && convertedAmount >= 0) {
        const strignifiedConvertedAmount = convertedAmount
          .toFixed(assetField.value.exponent)
          .toString();
        setNativeCurrencyInput(
          isNativeCurrencyInput ? nonNullValue : strignifiedConvertedAmount,
        );
        setAssetCurrencyInput(
          isNativeCurrencyInput ? strignifiedConvertedAmount : nonNullValue,
        );
      }

      if (
        !!sourcePortfolioUuid &&
        Number(value ?? '0') > selectedPortfolioAvailableBalance
      ) {
        setShowError(true);
      } else if (showError) {
        setShowError(false);
      }
    },
    [
      assetField.value.exponent,
      assetSymbol,
      convertCurrency,
      isNativeCurrencyInput,
      nativeCurrency,
      selectedPortfolioAvailableBalance,
      showError,
      sourcePortfolioUuid,
    ],
  );

  const handlePortfolioSelectorPressed = useCallback(
    (portfolioSelectorType: PortfolioSelectorType) => {
      amountField.onChange({
        ...amountField.value,
        rawAmount: assetCurrencyInput,
        rawAmountInNativeCurrency: nativeCurrencyInput,
      });
      isNativeCurrencyInputField.onChange(isNativeCurrencyInput);
      if (portfolioSelectorType === 'source') {
        goToStep(PortfolioTransferModalSteps.SelectSourcePortfolio);
      } else {
        goToStep(PortfolioTransferModalSteps.SelectTargetPortfolio);
      }
    },
    [
      amountField,
      assetCurrencyInput,
      goToStep,
      isNativeCurrencyInput,
      isNativeCurrencyInputField,
      nativeCurrencyInput,
    ],
  );

  const formattedSwapValue = useMemo(() => {
    return formatCurrency({
      isFiat: isNativeCurrencyInput ? isFiatAsset : true,
      amount: {
        value: isNativeCurrencyInput ? assetCurrencyInput : nativeCurrencyInput,
        currency: isNativeCurrencyInput ? assetSymbol : nativeCurrency,
      },
    });
  }, [
    assetSymbol,
    assetCurrencyInput,
    nativeCurrencyInput,
    formatCurrency,
    isFiatAsset,
    isNativeCurrencyInput,
    nativeCurrency,
  ]);

  const handleSwap = useCallback(() => {
    setIsNativeCurrencyInput(!isNativeCurrencyInput);
  }, [isNativeCurrencyInput]);

  const handleSubmit = useCallback(
    ({
      nativeCurrencyAmount,
      assetCurrencyAmount,
    }: {
      nativeCurrencyAmount: string;
      assetCurrencyAmount: string;
    }) => {
      const formattedAmount = formatCurrency({
        isFiat: isFiatAsset,
        amount: {
          value: assetCurrencyAmount,
          currency: assetSymbol,
        },
      });

      const formattedAmountInNativeCurrency = formatCurrency({
        isFiat: true,
        amount: {
          value: Big(nativeCurrencyAmount).round(2, Big.roundDown).toString(),
          currency: nativeCurrency,
        },
      });

      amountField.onChange({
        rawAmount: assetCurrencyAmount,
        rawAmountInNativeCurrency: nativeCurrencyAmount,
        formattedAmount,
        formattedAmountInNativeCurrency,
      });

      replaceStep(PortfolioTransferModalSteps.Preview);
    },
    [
      amountField,
      assetSymbol,
      formatCurrency,
      isFiatAsset,
      nativeCurrency,
      replaceStep,
    ],
  );

  const handleSubmitButtonPress = useCallback(() => {
    handleSubmit({
      assetCurrencyAmount: assetCurrencyInput,
      nativeCurrencyAmount: nativeCurrencyInput,
    });
  }, [assetCurrencyInput, handleSubmit, nativeCurrencyInput]);

  const handleMaxButtonPress = useCallback(() => {
    handleSubmit({
      assetCurrencyAmount: availableBalanceInAssetCurrency,
      nativeCurrencyAmount: (+availableBalanceInNativeCurrency).toFixed(2),
    });
  }, [
    availableBalanceInAssetCurrency,
    availableBalanceInNativeCurrency,
    handleSubmit,
  ]);

  const handleOnPress = useCallback(
    () => handlePortfolioSelectorPressed('source'),
    [handlePortfolioSelectorPressed],
  );

  const handleOnPress1 = useCallback(
    () => handlePortfolioSelectorPressed('target'),
    [handlePortfolioSelectorPressed],
  );

  return (
    <VStack height="100%" testID="portfolio-transfer-entry-step">
      <ModalHeader
        title={formatMessage(messages.transferAsset, { assetSymbol })}
        onBackButtonPress={isDefaultStep ? undefined : handleBackButtonPress}
      />
      <ModalBodyStyled>
        <HStack width="100%" justifyContent="space-between" alignItems="center">
          <FlexibleCurrencyInput
            symbol={isNativeCurrencyInput ? nativeCurrency : assetSymbol}
            precision={isNativeCurrencyInput ? 2 : exponent}
            symbolPosition="after"
            placeholder="0"
            autoFocus
            superscript={true}
            align="flex-start"
            alignSelfInput="center"
            minWidth={50}
            maxWidth={230}
            color={palette.foreground}
            fontSize={80}
            onChange={handleChange}
            symbolColor={palette.foregroundMuted}
            symbolFontSize={80}
            symbolFontWeight="thin"
            symbolPositionVertical="center"
            transparentBackground
            cursorColor={palette.primary}
            value={entryAmount}
            onEnter={handleSubmitButtonPress}
          />
          <Button
            testID="entry-step-max-button"
            variant="secondary"
            compact
            onPress={handleMaxButtonPress}
            disabled={!inputEnabled}
          >
            {formatMessage(messages.max)}
          </Button>
        </HStack>
        {!isAssetNativeCurrency && (
          <Box>
            <PressableOpacity
              onPress={handleSwap}
              testID="swap-crypto-fiat-input"
            >
              <HStack spacerGap={1} width="fit-content" alignItems="center">
                <Icon name="arrowsVertical" size="s" color="primary" />
                <ConversionTicker
                  fontWeight="bold"
                  value={formattedSwapValue}
                  color="buttonFill"
                />
              </HStack>
            </PressableOpacity>
          </Box>
        )}
        <Spacer vertical={5} />
        <TransferPortfolioSelectorCell
          portfolioSelectorType="source"
          portfolioUuid={sourcePortfolioUuid}
          onPress={handleOnPress}
          queryRef={query}
          isNativeCurrencyInput={isNativeCurrencyInput}
        />
        <Box offsetHorizontal={gutter} spacingStart={4}>
          <Icon name="verticalLine" size="s" color="foregroundMuted" />
        </Box>
        <TransferPortfolioSelectorCell
          portfolioSelectorType="target"
          portfolioUuid={targetPortfolioUuid}
          onPress={handleOnPress1}
          queryRef={query}
          isNativeCurrencyInput={isNativeCurrencyInput}
        />
        <Spacer vertical={3} />
        <Button
          testID="entry-step-preview-button"
          endIcon="forwardArrow"
          onPress={handleSubmitButtonPress}
          disabled={!previewButtonEnabled}
        >
          {formatMessage(messages.previewTransfer)}
        </Button>
        <Spacer vertical={2} />
        {showError && (
          <Banner title="" startIcon="info" variant="warning">
            {formatMessage(messages.insufficientBalanceError)}
          </Banner>
        )}
      </ModalBodyStyled>
    </VStack>
  );
}

export default memo(AssetSelectorStep);

