export type TabContentProps = {
  index: number;
  children: React.ReactElement | null;
};

function TabContent({ children, index }: TabContentProps) {
  const { activeIndex } = useContext(RetailRedesignTabContext);
  return activeIndex === index ? children : null;
}

export function RetailRedesignTabs({
  tabs,
  hideTabs,
  hideBackButton,
  tabHeight,
  onChange,
  turnOffAnimations,
}: TabsProps) {
  const { setActiveIndex, activeIndex } = useContext(RetailRedesignTabContext);
  const palette = usePalette();
  const { formatMessage } = useIntl();
  const uId = useRef(generateUUID());
  const isMobile = useIsMobile();
  const { closeMenu } = useContext(SendRedesignTriggerContext);

  const handleIndexChange = useCallback(
    (index: number) => {
      onChange?.(index);
      setActiveIndex(index);
    },
    [setActiveIndex, onChange],
  );

  if (hideTabs) {
    return null;
  }

  return (
    <LazyMotion features={domAnimation}>
      <LayoutGroup id={uId.current}>
        <VStack
          spacerGap={isMobile ? 3 : undefined}
          spacingTop={2}
          spacingStart={3}
        >
          {isMobile && !hideBackButton && (
            <IconButton
              name="backArrow"
              variant="secondary"
              transparent
              onPress={closeMenu}
            />
          )}
          <HStack
            width="max-content"
            borderRadius="roundedFull"
            background="backgroundAlternate"
            flexShrink={1}
            testID="redesign-tab-navigator"
          >
            {tabs.map(({ label, index, testID }) => {
              const active = activeIndex === index;

              return (
                <Box
                  position="relative"
                  height={tabHeight ?? SLIDER_HEIGHT}
                  testID={`tab-${index}`}
                >
                  <Pressable
                    testID={testID}
                    accessibilityLabel={
                      active
                        ? formatMessage(messages.selectedTab, { label })
                        : label
                    }
                    accessibilityHint={formatMessage(messages.hintTabToggle, {
                      label,
                    })}
                    borderRadius="roundedFull"
                    background="transparent"
                    key={index + label}
                    // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                    onPress={() => handleIndexChange(index)}
                    transparentWhileInactive
                    allowTransparency
                  >
                    {active && (
                      <m.span
                        layoutId={uId.current}
                        style={{
                          borderRadius: borderRadius.roundedFull,
                          position: 'absolute',
                          inset: 0,
                          backgroundColor: palette.foreground,
                          height: tabHeight ?? SLIDER_HEIGHT,
                        }}
                        transition={
                          turnOffAnimations
                            ? { duration: 0 }
                            : { type: 'spring', bounce: 0.2 }
                        }
                      />
                    )}
                    <Box position="relative">
                      <TextLabel1
                        spacingHorizontal={2}
                        color={active ? 'positiveForeground' : 'foreground'}
                        as="span"
                      >
                        {label}
                      </TextLabel1>
                    </Box>
                  </Pressable>
                </Box>
              );
            })}
          </HStack>
        </VStack>
      </LayoutGroup>
    </LazyMotion>
  );
}

