type AddressViewProps = {
  accountRef: AddressViewFragment$key | null;
  onAddressCopy: (address?: string) => void;
  isCopied: boolean;
  onRegenPress: () => void;
};

export default function AddressView({
  accountRef,
  onAddressCopy,
  onRegenPress,
  isCopied,
}: AddressViewProps) {
  const { formatMessage } = useIntl();
  const account = useFragment(
    graphql`
      fragment AddressViewFragment on Account {
        type
        name
        assetOrFiatCurrency {
          ... on ViewerAsset {
            asset @required(action: THROW) {
              name @required(action: THROW)
              displaySymbol @required(action: THROW)
              destinationTag {
                name
              }
            }
            supportedNetworks(
              action: RECEIVE
              applicationContext: CONSUMER
              address: $address
            ) {
              ...useSupportedNetworksFragment
            }
          }
        }
        address(forceRegeneration: $forceRegeneration, network: $network) {
          ...AddressViewInfoCopyViewFragment
          isRegenerable
          addressInfo {
            address
          }
        }
      }
    `,
    accountRef,
  );
  const { defaultNetwork } = useSupportedNetworks(
    account?.assetOrFiatCurrency?.supportedNetworks ?? null,
  );
  const { invoice } = useLightningInvoiceContext();
  const hasBtcLightningSupport = useHasBtcLightningSupport();

  const { receiveSelectedNetwork } = useFields(SendForm);
  const name = account?.assetOrFiatCurrency?.asset?.name;
  const displaySymbol = account?.assetOrFiatCurrency?.asset?.displaySymbol;
  const accountName = account?.name;

  const showBtcLightningInvoice = useMemo(() => {
    return (
      hasBtcLightningSupport &&
      receiveSelectedNetwork?.value?.networkName === 'Lightning' &&
      invoice !== null
    );
  }, [hasBtcLightningSupport, receiveSelectedNetwork?.value, invoice]);

  const address = useMemo(() => {
    if (showBtcLightningInvoice) {
      return invoice?.addressInfo?.address;
    }

    return account?.address?.addressInfo?.address;
  }, [
    showBtcLightningInvoice,
    account?.address?.addressInfo?.address,
    invoice?.addressInfo?.address,
  ]);
  const currentNetwork =
    receiveSelectedNetwork.value?.networkName ?? defaultNetwork?.networkName;

  const handleAddressCopy = useCallback(() => {
    onAddressCopy(address);
  }, [address, onAddressCopy]);

  const infoCopyTitle = useMemo(() => {
    if (showBtcLightningInvoice) {
      return formatMessage(messages.lightningInvoice);
    }

    if (account && isVault(account)) {
      return formatMessage(messages.addressTitle, {
        displaySymbol: accountName,
        name: currentNetwork ?? name,
      });
    }

    return formatMessage(messages.addressTitle, {
      displaySymbol,
      name: currentNetwork ?? name,
    });
  }, [
    account,
    formatMessage,
    currentNetwork,
    name,
    accountName,
    displaySymbol,
    showBtcLightningInvoice,
  ]);

  const infoCopyContent = useMemo(() => {
    if (showBtcLightningInvoice && invoice?.addressInfo?.address) {
      return getEllipsizedString(invoice?.addressInfo?.address, 8);
    }

    return <AddressInfoCopyView addressRef={account?.address ?? null} />;
  }, [
    showBtcLightningInvoice,
    invoice?.addressInfo?.address,
    account?.address,
  ]);

  return (
    <InfoCopyView
      title={infoCopyTitle}
      content={infoCopyContent}
      regenAddressButton={
        account?.address?.isRegenerable && (
          <IconButton name="refresh" onPress={onRegenPress} compact />
        )
      }
      copyButton={
        account?.address && (
          <SendReceiveCopyButton
            copied={isCopied}
            onPress={handleAddressCopy}
          />
        )
      }
    />
  );
}

