type Props = {
  children: (search: string) => React.ReactNode;
  onUpdate?(value: string): void;
  onClear?(): void;
  onEnterPress?(search?: string): void;
  value?: string;
  startIcon: UiIconName;
  iconColor?: 'positive';
};

export default function RecipientSearchInput({
  children,
  onUpdate,
  onEnterPress,
  value,
  onClear,
  startIcon,
  iconColor,
}: Props) {
  const [search, setSearch] = useState(value);
  const { formatMessage } = useIntl();
  const input = useRef<HTMLInputElement>(null);
  const { assetName, sendType } = useFields(SendForm);
  const hasBtcLightningSupport = useHasBtcLightningSupport();
  const debouncedValue = useDebounce(search, 500);

  useEffect(() => {
    if (debouncedValue !== value) {
      onUpdate?.(debouncedValue ?? '');
    }
  }, [debouncedValue]);

  useEffect(() => {
    setSearch(value);
    /**
     * Run this to update the search value when the value prop changes
     * based on the debounced value outside of the controlled component
     */
    if (input.current) {
      input.current.focus();
    }
  }, [value]);

  const handleChangeText = useCallback((e: ChangeEvent<HTMLInputElement>) => {
    setSearch(e.target.value);
  }, []);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Backspace' && e.metaKey) {
        onClear?.();
        return;
      }
      if (e.key === 'Enter') {
        onEnterPress?.(search);
        return;
      }
    },
    [onClear, onEnterPress, search],
  );

  const handleOnClear = useCallback(() => {
    setSearch('');
    onClear?.();
  }, [onClear]);

  const placeholder = useMemo(() => {
    if (hasBtcLightningSupport && assetName.value === 'Bitcoin') {
      return formatMessage(messages.invoicePlaceholder);
    }

    if (sendType.value) {
      return sendType.value === 'ON_CHAIN'
        ? formatMessage(messages.cryptoSendPlaceholder, {
            asset: assetName.value,
          })
        : formatMessage(messages.userSendPlaceholder);
    }

    return formatMessage(messages.placeholder);
  }, [assetName.value, formatMessage, sendType.value, hasBtcLightningSupport]);

  return (
    <>
      <TextInput
        testID="recipient-search-input"
        end={
          search?.length ? (
            <PressableOpacity onPress={handleOnClear}>
              <Icon spacing={2} name="close" size="s" />
            </PressableOpacity>
          ) : undefined
        }
        type="text"
        key="search-input"
        borderRadius="roundedFull"
        ref={input}
        value={search || ''}
        placeholder={placeholder}
        onChange={handleChangeText}
        onKeyDown={handleKeyDown}
        start={<Icon spacing={2} name={startIcon} size="s" color={iconColor} />}
      />
      {children(search || '')}
    </>
  );
}

