export default function SendRedesignHeader({
  children,
  showOldHeader = false,
}: SendRedesignHeaderProps) {
  const { goBack, currentStep } = useStepper(sendRedesignStepper);
  const {
    goBack: receiveGoBack,
    currentStep: receiveCurrentStep,
    goToStep,
  } = useStepper(receiveRedesignStepper);
  const { formatMessage } = useIntl();
  const { loading } = useContext(FormLoadingContext);
  const {
    recipient,
    recipientEns,
    isSendinToEnsAddress,
    assetName,
    recipientInfo,
    selectedNetwork,
    sendType,
    recipientContactName,
    amount,
  } = useFields(SendForm);

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleBackPress = () => {
    if (currentStep === 'recipientEntry') {
      if (recipient.errors.length > 0) {
        recipient.onChange('');
        recipientEns.onChange('');
        recipientContactName.onChange('');
        isSendinToEnsAddress.onChange(false);
      }

      // clean up recipient and amount if user added a invoice as recipient and then went back.
      // this prevent users from changing the amount to be sent. Ideally they should always rely on the amount provided by the invoice.
      if (
        recipient.value &&
        selectedNetwork.value?.networkName === 'Lightning'
      ) {
        recipient.onChange('');
        amount.onChange('0');
        recipientInfo.onChange(undefined);
        selectedNetwork.onChange(undefined);
      }
    }

    if (currentStep === 'selectRecipientType') {
      recipientInfo.onChange({});
    }

    if (currentStep === 'addNote') {
      markStep('send_redesign_note_added');
    }

    if (
      receiveCurrentStep === 'assetSelection' ||
      receiveCurrentStep === 'assetInfoStep' ||
      receiveCurrentStep === 'regenerateAddressStep' ||
      receiveCurrentStep === 'lightningAmountEntryStep' ||
      receiveCurrentStep === 'lightningAmountInfoStep' ||
      receiveCurrentStep === 'lightningInvoiceTimeRemainingStep' ||
      receiveCurrentStep === 'lightningRegenerateInvoiceStep' ||
      receiveCurrentStep === 'lightningReceiveNuxStep'
    ) {
      receiveGoBack();
      return;
    }

    goBack();
  };

  const textHeadline = useMemo(() => {
    if (receiveCurrentStep === 'assetSelection') {
      return formatMessage(messages.receiveAssetSelection);
    }

    if (receiveCurrentStep === 'networkSelection') {
      return formatMessage(messages.networkSelection);
    }

    if (receiveCurrentStep === 'lightningAmountEntryStep') {
      return formatMessage(messages.amountToReceive);
    }

    if (currentStep === 'recipientEntry' && sendType.value === 'ON_CHAIN') {
      return formatMessage(messages.recipientEntryWithNetwork, {
        asset: assetName.value,
        network: selectedNetwork.value?.networkName,
      });
    }

    return messages[currentStep]
      ? formatMessage(messages[currentStep], {
          asset: assetName.value,
        })
      : null;
  }, [
    assetName.value,
    currentStep,
    formatMessage,
    receiveCurrentStep,
    selectedNetwork.value?.networkName,
    sendType.value,
  ]);

  const handleLightningAmountEntryInfoPress = useCallback(() => {
    goToStep('lightningAmountInfoStep');
  }, [goToStep]);

  const headerAction = useMemo(() => {
    if (receiveCurrentStep === 'lightningAmountEntryStep') {
      return (
        <Box spacingEnd={2}>
          <IconButton
            name="info"
            onPress={handleLightningAmountEntryInfoPress}
            transparent
          />
        </Box>
      );
    }

    return null;
  }, [receiveCurrentStep, handleLightningAmountEntryInfoPress]);

  if (currentStep === 'amountEntry' && receiveCurrentStep === 'assetDisplay') {
    return <>{typeof children === 'function' ? children(false) : children}</>;
  }

  if (
    currentStep === 'networkSelection' ||
    currentStep === 'l2SelectionStep' ||
    currentStep === 'transactionDetailsStep' ||
    receiveCurrentStep === 'networkSelection'
  ) {
    return typeof children === 'function' ? children(true) : children;
  }

  const oldHeaderShowHeadline =
    currentStep !== 'statusStep' &&
    currentStep !== 'amountEntry' &&
    receiveCurrentStep !== 'assetDisplay' &&
    !!textHeadline;

  return showOldHeader ? (
    /**
     * this old header does't have the tabs integrated
     * into the steps so we need to render the tabs from the old header
     * and add the back button render logic if we are showing the old one fow now
     * this is for retail advanced trade support
     */
    <>
      <VStack
        minHeight={!oldHeaderShowHeadline ? 110 : undefined}
        spacingBottom={4}
      >
        <SendHeader hideTabs={false} onBack={goBack} />
      </VStack>
      {oldHeaderShowHeadline && (
        <Box height={72} alignItems="center">
          <Box spacing={1} flexGrow={1} flexShrink={1} flexBasis={0}>
            <IconButton
              name="backArrow"
              onPress={handleBackPress}
              transparent
              //lock going back if we are loading data on the form
              disabled={loading}
            />
          </Box>
          <Box flexGrow={1} flexShrink={1}>
            <TextHeadline as="h1">{textHeadline}</TextHeadline>
          </Box>
        </Box>
      )}
      {typeof children === 'function' ? children(true) : children}
    </>
  ) : (
    <>
      <Box height={72} alignItems="center">
        <Box spacing={1} flexGrow={1} flexShrink={1} flexBasis={0}>
          {currentStep !== 'statusStep' && (
            <IconButton
              name="backArrow"
              onPress={handleBackPress}
              transparent
              //lock going back if we are loading data on the form
              disabled={loading}
            />
          )}
        </Box>
        <Box flexGrow={1} flexShrink={1}>
          <TextHeadline as="h1">{textHeadline}</TextHeadline>
        </Box>
        {headerAction}
      </Box>
      {/**
       * if we are rendering the header
       * we tell children to hide tabs
       */}
      {typeof children === 'function' ? children(true) : children}
    </>
  );
}

