type DestinationTagStepProps = {
  viewerAssetRef: DestinationTagStepAssetFragment$key | null;
  refetch: (
    variables: SendReceivePreloadableQueryVariables,
    options?: RefetchOptions,
  ) => void;
};

export default function DestinationTagStep({
  viewerAssetRef,
  refetch,
}: DestinationTagStepProps) {
  const { formatMessage, locale } = useIntl();
  const MEMO_TAG_SUPPORT_URL = `https://help.coinbase.com/${locale}/coinbase/trading-and-funding/sending-or-receiving-cryptocurrency/destination-tag-memo-faq`;
  const { destinationTag, recipient, receiveId, accountId } =
    useFields(SendForm);
  const { goToStep } = useStepper(sendRedesignStepper);
  const { logSendReceiveRedesignFlowEvent } = useSendReceiveLoggers();
  const sendReceiveDefaultParams = useSendReceiveDefaultParams({
    accountIdProp: accountId?.value,
  });

  const viewerAsset = useFragment(
    graphql`
      fragment DestinationTagStepAssetFragment on ViewerAsset {
        asset {
          displaySymbol
          destinationTag {
            name
            regex
          }
          destinationTagForAddress(address: $address) {
            name
            regex
          }
        }
      }
    `,
    viewerAssetRef,
  );

  const displaySymbol = viewerAsset?.asset.displaySymbol;
  const tagRegex =
    viewerAsset?.asset?.destinationTag?.regex ||
    viewerAsset?.asset?.destinationTagForAddress?.regex;
  const regexExp = useMemo(() => tagRegex && new RegExp(tagRegex), [tagRegex]);
  const destinationTagInfo =
    viewerAsset?.asset.destinationTag ??
    viewerAsset?.asset.destinationTagForAddress;

  const handleDestinationTagChange = useCallback(
    (event: ChangeEvent<HTMLInputElement>) => {
      const value = event.target.value as string;
      destinationTag.onChange(value);
      if (regexExp && value !== '') {
        const hasTagError = !regex(regexExp)(value);
        if (hasTagError) {
          destinationTag.onErrors([
            formatMessage(messages.destinationTagError, {
              fieldName: destinationTag.name,
            }),
          ]);
        }
      }
    },
    [destinationTag, formatMessage, regexExp],
  );

  const handleSkipPress = useCallback(() => {
    destinationTag.onChange('');
    destinationTag.onErrors([]);
    goToStep('amountEntry');
    logSendReceiveRedesignFlowEvent('destination_tag_step_skip', {
      action: ActionType.render,
      componentType: ComponentType.button,
    });
    refetch({
      ...sendReceiveDefaultParams,
      address: recipient.value,
      uuid: accountId?.value,
      receiveUuid: receiveId.value,
      sendUseDefaultAccount: false,
      receiveUseDefaultAccount: receiveId.value ? false : true,
      skipAccountUuid: false,
      skipAssetUuid: true,
      skipAssetSlug: true,
      skipReceiveUseAccountByUuid: true,
    });
  }, [
    accountId?.value,
    destinationTag,
    goToStep,
    logSendReceiveRedesignFlowEvent,
    receiveId.value,
    recipient.value,
    refetch,
    sendReceiveDefaultParams,
  ]);

  const handleContinuePress = useCallback(() => {
    goToStep('amountEntry');
    markStep('redesign_recipient_selected');
    logSendReceiveRedesignFlowEvent('destination_tag_step_continue', {
      action: ActionType.render,
      componentType: ComponentType.button,
    });

    refetch({
      ...sendReceiveDefaultParams,
      address: recipient.value,
      uuid: accountId?.value,
      receiveUuid: receiveId.value,
      sendUseDefaultAccount: false,
      receiveUseDefaultAccount: receiveId.value ? false : true,
      skipAccountUuid: false,
      skipAssetUuid: true,
      skipAssetSlug: true,
      skipReceiveUseAccountByUuid: true,
    });
  }, [
    accountId?.value,
    goToStep,
    logSendReceiveRedesignFlowEvent,
    receiveId.value,
    recipient.value,
    refetch,
    sendReceiveDefaultParams,
  ]);

  useEffect(() => {
    logSendReceiveRedesignFlowEvent('destination_tag_step', {
      action: ActionType.render,
      componentType: ComponentType.modal,
    });
  }, []);

  const handleOnPress = useCallback(() => goToStep('memoInfoStep'), [goToStep]);

  return (
    <VStack
      spacingHorizontal={3}
      spacingBottom={3}
      spacerGap={4}
      justifyContent="space-between"
      minHeight={410}
    >
      <VStack spacerGap={1}>
        <TextTitle3 as="span">{formatMessage(messages.memoTitle)}</TextTitle3>
        <TextBody as="p">
          {formatMessage(messages.memoBody, {
            displaySymbol,
            memoType: destinationTagInfo?.name,
            learnMore: (
              <Link
                testID="MemoInfoLink"
                variant="body"
                to={MEMO_TAG_SUPPORT_URL}
                openInNewWindow
              >
                {formatMessage(messages.learnMore)}
              </Link>
            ),
          })}
        </TextBody>
        <TextInput
          onChange={handleDestinationTagChange}
          label={destinationTagInfo?.name}
          placeholder={destinationTagInfo?.name}
          helperText={
            destinationTag.errors.length > 0
              ? destinationTag.errors[0]
              : undefined
          }
          end={
            <Pressable background="transparent" onPress={handleOnPress}>
              <Box spacing={2}>
                <Icon name="info" size="s" color="foreground" />
              </Box>
            </Pressable>
          }
        />
      </VStack>
      <HStack spacerGap={1} justifyContent="center">
        <Button
          block
          variant="secondary"
          onPress={handleSkipPress}
          testID="skip-destination-tag"
        >
          {formatMessage(messages.skip)}
        </Button>
        <Button
          block
          variant="primary"
          disabled={
            destinationTag.errors.length > 0 || destinationTag.value === ''
          }
          onPress={handleContinuePress}
        >
          {formatMessage(messages.continue)}
        </Button>
      </HStack>
    </VStack>
  );
}

