  const amountFiat = formValue?.amountFiat;
  const recipient = formValue?.recipientDetails.displayValue ?? '';
  const network = formValue?.network;
  const timeEstimation = formValue?.timeEstimation;
  const networkFees = formValue?.feeDetailsList;
  const total = formValue?.amountTotal;
