    processingFeeModal.openModal(
      <ProcessingFeeModal
        visible={false}
        toggleOff={processingFeeModal.closeModal}
      />,
    );
  }, [processingFeeModal]);

  const formatCurrency = useCurrencyFormatter();

  const [reverseResolveEnsMutation] =
    useMutation<SendRedesignPreviewMutation>(graphql`
      mutation SendRedesignPreviewMutation($input: ReverseResolveEnsInput!) {
        reverseResolveEns(input: $input) {
          __typename
          ... on ReverseResolveEnsSuccess {
            ensName
          }
        }
      }
    `);

