    graphql`
      fragment SendRedesignPreviewFragment on Account {
        assetOrFiatCurrency {
          ... on ViewerAsset {
            asset {
              ...useReceiptAmountFormatterFragment
              exponent
              imageUrl
              platformName
            }
          }
