      if (
        Math.ceil(fee.amount.value) === 0 &&
        !isBtcLightningNetwork(recipient)
      ) {
        return (
          <Box>
            <TextBody as="div" color="positive">
              {formatMessage(messages.freeSend)}
            </TextBody>
          </Box>
        );
      }

      const converted = convert(from, to)?.toString();

      const formattedConvertedValue = converted
        ? formatCurrency({
            isFiat: true,
            amount: { value: converted, currency: nativeCurrency ?? '' },
            exponent: 2,
          })
        : '--';

      if (converted === '0') {
        return `~${formattedConvertedValue}`;
      }

      return formattedConvertedValue;
    },
    [
      convert,
      formatCurrency,
      formatFeeAmount,
      formatMessage,
      nativeCurrency,
      sendType,
      isBtcLightningNetwork,
      recipient,
    ],
  );

  const shouldShowVerifiedAddresses = useShouldShowVerifiedAddresses();
  const { fetchUserAttestations, isVerified } =
    useUserAttestationsByRecipient();
  useEffect(() => {
    if (shouldShowVerifiedAddresses) {
      fetchUserAttestations(recipient);
    }
  }, []);

  const ensVal = ensInfo?.ensName || recipientEns.value;
  const verifiedMsg = isVerified && formatMessage(messages.verifiedWallet);
  const detailVal = ensVal || verifiedMsg || undefined;
  const detailCell = (
    <HStack alignItems="center" spacerGap={0.5}>
      {detailVal}
      {isVerified && <Icon name="circleCheckmark" size="xs" color="primary" />}
    </HStack>
  );

  return (
    <VStack
      flexGrow={1}
      flexBasis={0}
      flexShrink={1}
      spacingHorizontal={3}
      spacingBottom={3}
    >
      <HStack justifyContent="center" spacingBottom={3}>
        <VStack alignItems="center">
          <RemoteImage source={assetImage} size="xxxl" />
          {/**
           * fiatRow
           */}
          <HStack spacingTop={2} spacingBottom={0.5}>
            <TextTitle2 as="h1" spacingEnd={0.5} testID="send-preview-title">
              {formatMessage(messages.send, {
                amountFiat: formattedSendAmount,
              })}
            </TextTitle2>
            <TextTitle2 as="h1" color="foregroundMuted">
              {amountFiat?.currency}
            </TextTitle2>
          </HStack>
          {/**
           * cryptoRow
           */}
          <HStack>
            <TextBody as="span" color="foregroundMuted" spacingEnd={0.5}>
              {formattedSendCrypto}
            </TextBody>
          </HStack>
        </VStack>
      </HStack>
      <Spacer vertical={2} />
      <Divider height={1} direction="horizontal" />
      <VStack spacerGap={2} spacingTop={2}>
        <LineItem
          vertical
          title={formatMessage(messages.sendTo)}
          value={recipient}
          detail={detailCell}
          truncate={recipient.length > MAX_LENGTH_TO_TRUNCATE}
        />
        {!!note.value && (
          <LineItem
            vertical
            title={formatMessage(messages.note)}
            value={note.value ?? ''}
          />
        )}
        {!!network?.name && (
          <LineItem
            title={formatMessage(messages.networkLabel)}
            value={network?.name ?? ''}
          />
        )}
        {networkFees?.map(fee => {
          if (!fee || (!Number(fee.amount.value) && !fee.amountBeforeSubsidy)) {
            return null;
          }

          if (isBtcLightningNetwork(recipient)) {
            return (
              <LineItem
                key={fee.name}
                title={formatMessage(messages.processingFee)}
                value={renderFeeAmountContent(fee)}
                icon={
                  <Pressable
                    onPress={openProcessingFeeModal}
                    background="transparent"
                  >
                    <Icon name="info" size="s" color="foregroundMuted" />
                  </Pressable>
                }
              />
            );
          }

          return (
            <LineItem
              key={fee.name}
              title={fee.name}
              value={renderFeeAmountContent(fee)}
            />
          );
        })}
        {!!timeEstimation && (
          <LineItem
            title={formatMessage(messages.estimatedSendTime)}
            value={timeEstimation}
          />
        )}
        {!!total && (
          <LineItem
            bold
            title={formatMessage(messages.total)}
            value={formattedTotal}
          />
        )}
        <Spacer vertical={1} />
        <Button
          testID="send-now-button"
          variant="primary"
          block
          loading={loading}
          disabled={loading || !submittable}
          onPress={handleSubmit}
        >
          {formatMessage(messages.sendNow)}
        </Button>
      </VStack>
    </VStack>
  );
}

type LineItemProps = {
  title: string;
  value: string | JSX.Element;
  icon?: JSX.Element;
  bold?: boolean;
  detail?: string | JSX.Element;
  vertical?: boolean;
  truncate?: boolean;
};

function LineItem({
  title,
  value,
  icon,
  bold,
  detail,
  vertical,
  truncate,
}: LineItemProps) {
  const Component = vertical ? VStack : HStack;
  const toast = useToast();
  const { formatMessage } = useIntl();
  const [isRecipientOpen, { toggle }] = useToggler(false);

  const handleCopyToClipboard = useCallback(() => {
    if (typeof value === 'string') {
      copyToClipboard(value);
      toast.show(formatMessage(messages.copiedToClipboard), {
        duration: TOAST_DURATION,
      });
    }
  }, [formatMessage, toast, value]);

  const truncatedRecipient = useMemo(() => {
    if (value && typeof value === 'string') {
      return getEllipsizedString(value, 6);
    }

    return '';
  }, [value]);

  const displayRecipient = useMemo(() => {
    if (truncate) {
      return isRecipientOpen ? value : truncatedRecipient;
    }

    return value;
  }, [isRecipientOpen, truncate, truncatedRecipient, value]);

  if (bold) {
    return (
      <HStack justifyContent="space-between">
        <TextHeadline as="label">{title}</TextHeadline>
        <TextHeadline as="span">{value}</TextHeadline>
      </HStack>
    );
  }

  return (
    <Component
      testID={`line-item-${title}`}
      justifyContent="space-between"
      style={{ wordBreak: 'break-all' }}
    >
      <HStack
        spacerGap={1}
        justifyContent={truncate ? 'space-between' : 'flex-start'}
        alignItems="center"
      >
        <TextBody as="label">{title}</TextBody>
        {truncate && (
          <Pressable onPress={toggle} background="transparent">
            <Icon name="caretDown" size="s" color="foreground" />
          </Pressable>
        )}
        {icon && icon}
      </HStack>
      {detail && <TextLabel2 as="label">{detail}</TextLabel2>}
      <Pressable onPress={handleCopyToClipboard} background="transparent">
        <TextBody as="p" color="foregroundMuted">
          {displayRecipient}
        </TextBody>
      </Pressable>
    </Component>
  );
}

import { useEffect, ChangeEvent, useState } from 'react';
