  useLazyLoadQuery,
  graphql,
  useMutation,
  InstrumentedSuspense,
} from '@cbhq/data-layer';

import SendForm from 'components/SendReceive/components/Send/form';
import { sendRedesignStepper } from 'components/SendReceive/SendRedesign/hooks/sendRedesignStepper';
import { useDebounce } from 'components/SendReceive/SendRedesign/hooks/useDebounce';
import useStepper from 'components/Stepper/hooks/useStepper';

import { useShouldShowVerifiedAddresses } from '../../../hooks/useShouldShowVerifiedAddresses';
import useUserAttestationsByRecipient from '../hooks/useUserAttestationsByRecipient';
import { recipientStepMessages } from '../recipientStepMessages';
import { AddContactStepMutation } from './__generated__/AddContactStepMutation.graphql';
import { AddContactStepQuery } from './__generated__/AddContactStepQuery.graphql';
import ContactFormFallback from './ContactFormFallback';
import { VerifiedWalletLabel } from './VerifiedWalletLabel';

type AddContactStepProps = {
  uuid: string | null;
};

function AddContactStep({ uuid }: AddContactStepProps) {
  const { formatMessage } = useIntl();
  const { recipient, destinationTag: destinationTagField } =
    useFields(SendForm);
  const [destinationTag, setDestinationTag] = useState(
    destinationTagField.value,
  );
  const { goBack } = useStepper(sendRedesignStepper);
  const [name, setName] = useState('');
  const [address, setAddress] = useState(recipient.value || '');
  const toast = useToast();

  const shouldShowVerifiedAddresses = useShouldShowVerifiedAddresses();
  const {
    fetchUserAttestations,
    isVerified,
    setIsVerified,
    isLoading: isAddressLoading,
  } = useUserAttestationsByRecipient();

  const debouncedAttestation = useDebounce(async () => {
    await fetchUserAttestations(address);
  });

  useEffect(() => {
    if (shouldShowVerifiedAddresses) {
      fetchUserAttestations(address);
    }
  }, []);

  if (!uuid) {
    const err = new Error('uuid is required and cannot be null');
    notifyError(err, {
      owner: 'p2p',
      context: 'AddContactStep',
      isHandled: false,
      severity: 'crash',
      isNetworkError: true,
    });
    throw err;
  }

  const query = useLazyLoadQuery<AddContactStepQuery>(
    graphql`
      query AddContactStepQuery($uuid: Uuid!, $address: String!) {
        viewer {
          accountByUuidV2(uuid: $uuid) {
            uuid
            assetOrFiatCurrency {
              ... on ViewerAsset {
                asset {
                  destinationTag {
                    name
                  }
                  destinationTagForAddress(address: $address) {
                    name
                  }
                }
              }
            }
            address {
              addressInfo {
                destinationTag
              }
            }
          }
        }
      }
    `,
    { uuid, address: recipient.value },
  );
  const account = query.viewer.accountByUuidV2;

  const [addContact, isLoading] = useMutation<AddContactStepMutation>(
    graphql`
      mutation AddContactStepMutation($input: CreateSendReceiveContactInput!) {
        createSendReceiveContact(input: $input) {
          __typename
          ... on CreateSendReceiveContactSuccess {
            viewer {
              ...FavoriteContactsViewerFragment
                @arguments(shouldShowVerifiedAddresses: false)
              ...useSendRecipientsFragment
                @arguments(first: 5, shouldShowVerifiedAddresses: false)
            }
          }
          ... on CreateSendReceiveContactError {
            error {
              message
              code
            }
          }
        }
      }
    `,
  );

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleSavePress = () => {
    addContact({
      variables: {
        input: {
          nickname: name,
          blockchainAddresses: [
            {
              destination_tag: '',
              address,
              label: name,
            },
          ],
        },
      },
      onError() {},
      onCompleted() {
        toast.show(formatMessage(recipientStepMessages.contactSaved));
        goBack();
      },
    });
  };

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleNameChange = (e: ChangeEvent<HTMLInputElement>) => {
    setName(e.target.value);
  };

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleAddressChange = (e: ChangeEvent<HTMLInputElement>) => {
    setAddress(e.target.value);
    setIsVerified(false);
    if (shouldShowVerifiedAddresses) {
      debouncedAttestation();
    }
  };

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleDestinationTagChange = (e: ChangeEvent<HTMLInputElement>) => {
    setDestinationTag(e.target.value);
  };

  return (
    <StyledVStack
      spacingHorizontal={3}
      spacingBottom={3}
      justifyContent="space-between"
      height={410}
    >
      <VStack gap={2}>
        <TextInput
          label={formatMessage(recipientStepMessages.name)}
          value={name}
          autoFocus
          onChange={handleNameChange}
          // prevents password manager icon from unnecessarily appearing
          type="search"
        />
        {isVerified && <VerifiedWalletLabel isLoading={isAddressLoading} />}
        <TextInput
          label={formatMessage(recipientStepMessages.address)}
          value={address}
          disabled={recipient.value.length > 0}
          onChange={handleAddressChange}
          // prevents password manager icon from unnecessarily appearing
          type="search"
        />
        {(account?.address?.addressInfo?.destinationTag ||
          account?.assetOrFiatCurrency?.asset?.destinationTagForAddress?.name ||
          account?.assetOrFiatCurrency?.asset?.destinationTag?.name) && (
          <TextInput
            onChange={handleDestinationTagChange}
            label={formatMessage(recipientStepMessages.destinationTag)}
            value={destinationTag}
          />
        )}
        <Button
          disabled={name.length === 0 && recipient.value.length === 0}
          variant="primary"
          block
          onPress={handleSavePress}
          loading={isLoading}
        >
          {formatMessage(recipientStepMessages.save)}
        </Button>
      </VStack>
    </StyledVStack>
  );
}

