function EditContactStep() {
  const { formatMessage } = useIntl();
  const { recipient, contact } = useFields(SendForm);
  const { goBack, goToStep } = useStepper(sendRedesignStepper);
  const [name, setName] = useState(contact.value.name);
  const [address, setAddress] = useState(contact.value.address);
  const [destinationTag, setDestinationTag] = useState(
    contact.value.destinationTag,
  );
  const toast = useToast();

  const [updateSendReceiveContact, isLoading] =
    useMutation<EditContactStepUpdateMutation>(graphql`
      mutation EditContactStepUpdateMutation(
        $input: UpdateSendReceiveContactInput!
      ) {
        updateSendReceiveContact(input: $input) {
          ... on UpdateSendReceiveContactSuccess {
            viewer {
              ...FavoriteContactsViewerFragment
                @arguments(shouldShowVerifiedAddresses: false)
              ...useSendRecipientsFragment
                @arguments(first: 5, shouldShowVerifiedAddresses: false)
              ...SendSelectRecipientStepViewerFragment
                @arguments(shouldShowVerifiedAddresses: false)
            }
          }
          ... on UpdateSendReceiveContactError {
            __typename
            error {
              message
              code
            }
          }
        }
      }
    `);

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleSavePress = () => {
    updateSendReceiveContact({
      variables: {
        input: {
          nickname: name,
          uuid: contact.value.uuid ?? '',
          contactFields: [
            {
              blockchainAddress: {
                address,
                label: name,
                destination_tag: contact.value.destinationTag,
                uuid: contact.value.uuids[0] ?? '',
              },
              updateMode: 'UPDATE_MODE_UPDATE',
            },
          ],
        },
      },
      onCompleted() {
        toast.show(formatMessage(recipientStepMessages.contactEdited));
        goBack();
      },
      onError() {},
    });
  };

  const shouldShowVerifiedAddresses = useShouldShowVerifiedAddresses();
  const {
    fetchUserAttestations,
    isVerified,
    setIsVerified,
    isLoading: isAddressLoading,
  } = useUserAttestationsByRecipient();

  const debouncedAttestation = useDebounce(async () => {
    await fetchUserAttestations(address);
  });

  useEffect(() => {
    if (shouldShowVerifiedAddresses) {
      fetchUserAttestations(contact.value.address);
    }
  }, []);

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleDeletePress = () => {
    goToStep('deleteContactConfirmation');
  };

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleNameChange = (e: ChangeEvent<HTMLInputElement>) => {
    setName(e.target.value);
  };

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleAddressChange = (e: ChangeEvent<HTMLInputElement>) => {
    setAddress(e.target.value);
    setIsVerified(false);
    if (shouldShowVerifiedAddresses) {
      debouncedAttestation();
    }
  };

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleDestinationTagChange = (e: ChangeEvent<HTMLInputElement>) => {
    setDestinationTag(e.target.value);
  };

  return (
    <VStack
      spacingHorizontal={3}
      spacingBottom={3}
      justifyContent="space-between"
      flexGrow={1}
      position="relative"
      height={410}
    >
      <Box position="absolute" right={0} top={-57} spacingEnd={0.5}>
        <Button
          variant="negative"
          transparent
          onPress={handleDeletePress}
          compact
        >
          {formatMessage(recipientStepMessages.delete)}
        </Button>
      </Box>
      <VStack spacerGap={2}>
        {isVerified ? (
          <VerifiedWalletLabel isLoading={isAddressLoading} />
        ) : (
          <HStack justifyContent="space-between" spacingTop={1}></HStack>
        )}
        <TextInput
          label={formatMessage(recipientStepMessages.name)}
          value={name}
          autoFocus
          onChange={handleNameChange}
        />
        <TextInput
          onChange={handleAddressChange}
          label={formatMessage(recipientStepMessages.address)}
          value={address}
          placeholder={formatMessage(recipientStepMessages.addressPlaceholder)}
          disabled={recipient.value.length > 0}
        />
        {contact.value.destinationTag.length > 0 && (
          <TextInput
            onChange={handleDestinationTagChange}
            label={formatMessage(recipientStepMessages.destinationTag)}
            value={destinationTag}
          />
        )}
      </VStack>
      <Button
        disabled={
          name === contact.value.name &&
          address === contact.value.address &&
          destinationTag === contact.value.destinationTag
        }
        variant="primary"
        block
        onPress={handleSavePress}
        loading={isLoading}
      >
        {formatMessage(recipientStepMessages.save)}
      </Button>
    </VStack>
  );
}

export default function EditContactStepBoundary() {
  return (
    <InstrumentedSuspense
      instrumentationId="sendReceiveContacts"
      fallback={<ContactFormFallback />}
    >
      <EditContactStep />
    </InstrumentedSuspense>
  );
}

