      mutation SendRecipientCellMutation($input: ReverseResolveEnsInput!) {
        reverseResolveEns(input: $input) {
          __typename
          ... on ReverseResolveEnsSuccess {
            address
            avatarUrl
            ensName
          }
        }
      }
    `);

  const onSuccess = useCallback(
    ({ name, address: ensAddress, hasConfusingCharacters }: ENSSuccess) => {
      /**
       * If we detect confusing (Homoglyph) charactes in the ENS name
       * then we don't want users to continue and we show the error.
       */
      if (hasConfusingCharacters) {
        return;
      }
      setEnsInfo({
        avatarUrl: null,
        ensName: name,
        address: ensAddress,
      });
    },
    [],
  );

  const lookupAddressFromEns = useLookupAddressFromEns(onSuccess);

  const onCompleted = useCallback(
    ({ response }: { response: SendRecipientCellMutation$data }) => {
      if (
        response.reverseResolveEns?.__typename === 'ReverseResolveEnsSuccess'
      ) {
        const ensResponse: EnsInfo = {
          ...response.reverseResolveEns,
        };

        setEnsInfo(ensResponse);
        onResolveEns?.(prevState => [...prevState, ensResponse]);
      }
    },
    [onResolveEns],
  );

  useEffect(() => {
    if (shouldCheckEns && address.match(nameRegex)?.length && !loading) {
      lookupAddressFromEns(address).then(res => {
        if (!res?.address || loading) {
          return;
        }
        reverseResolveEnsMutation({
          variables: {
            input: {
              address: res.address,
            },
          },
          onCompleted,
          onError: noop,
        });
      });
    }
  }, []);

  useEffect(() => {
    shouldCheckEns &&
      !loading &&
      !address.match(nameRegex)?.length &&
      reverseResolveEnsMutation({
        variables: {
          input: {
            address,
          },
        },
        onCompleted: ({ response }) => {
          if (
            response.reverseResolveEns?.__typename ===
            'ReverseResolveEnsSuccess'
          ) {
            const ensResponse: EnsInfo = {
              ...response.reverseResolveEns,
            };
            setEnsInfo(ensResponse);
          }
        },
        onError: noop,
      });
  }, []);

  const handleOnPress = useCallback(() => {
    handlePress({
      address: ensInfo?.address || address,
      nickname: ensInfo?.ensName ?? undefined,
      avatarUrl: ensInfo?.avatarUrl ?? undefined,
    });
  }, [
    address,
    ensInfo?.address,
    ensInfo?.avatarUrl,
    ensInfo?.ensName,
    handlePress,
  ]);

  const dropdownContent = useMemo(() => {
    return options.length > 0
      ? options.map(option => (
          <PressableOpacity onPress={option.onPress}>
            <Box spacingVertical={2} spacingStart={3} spacingEnd={10}>
              <TextLabel1 as="span" onClick={option.onPress}>
                {option.title}
              </TextLabel1>
            </Box>
          </PressableOpacity>
        ))
      : [];
  }, [options]);

  const description = useMemo(() => {
    if (
      typeof props.description === 'string' &&
      props.description.includes('@') &&
      props.description.length > MAX_DESCRIPTION_LENGTH
    ) {
      const [email, domain] = props.description.split('@');
      const maskedEmail = `${email.slice(0, 5)}...${email.slice(
        email.length - 6,
        email.length,
      )}`;
      return `${maskedEmail}@${domain}`;
    }

    return props.description;
  }, [props.description, MAX_DESCRIPTION_LENGTH]);

  const titleWrapper = useCallback(
    function (title: ReactNode) {
      if (!isVerified) {
        return title;
      }

      return (
        <HStack alignItems="center" spacerGap={0.5}>
          {title}
          <Icon name="circleCheckmark" size="xs" color="primary" />
        </HStack>
      );
    },
    [isVerified],
  );

  if (loading) {
    return <SendRecipientCellFallback />;
  }

  return (
    <Box position="relative">
      {!ensInfo ? (
        <ListCell
          {...props}
          testID="send-redesign-recipient-cell"
          outerSpacing={{
            spacingHorizontal: 1,
            spacingVertical: 0,
          }}
          innerSpacing={{ spacingHorizontal: 1 }}
          onPress={handleOnPress}
          description={description}
          title={titleWrapper(props.title)}
        />
      ) : (
        <ListCell
          {...props}
          testID="send-redesign-recipient-cell"
          outerSpacing={{
            spacingHorizontal: 1,
            spacingVertical: 0,
          }}
          innerSpacing={{ spacingHorizontal: 1 }}
          onPress={handleOnPress}
          media={
            ensInfo?.avatarUrl ? (
              <PreloadedEnsMedia src={ensInfo?.avatarUrl}>
                {isLoaded =>
                  isLoaded && ensInfo.avatarUrl ? (
                    <CellMedia type="avatar" source={ensInfo.avatarUrl} />
                  ) : (
                    props.media
                  )
                }
              </PreloadedEnsMedia>
            ) : (
              props.media
            )
          }
          description={
            props.description ??
            (ensInfo?.ensName
              ? formatAddress(ensInfo?.address || '')
              : undefined)
          }
          title={titleWrapper(
            ensInfo?.ensName ||
              formatAddress(ensInfo?.address || '') ||
              undefined,
          )}
        />
      )}
      {options.length > 0 && (
        <Box position="absolute" right={12} top={20}>
          <Dropdown
            contentPosition={{
              placement: 'left-start',
            }}
            content={dropdownContent}
            enableMobileModal
          >
            <IconButton name="more" compact transparent />
          </Dropdown>
        </Box>
      )}
    </Box>
  );
}

function SendRecipientCellWithBoundary(props: SendRecipientCellProps) {
  return (
    <Boundary
      owner="p2p"
      context="recipient_cell"
      name="recient_cell_suspense"
