type RedesignNetworkHeaderProps = {
  handleBackPress: () => void;
  hideText?: boolean;
  backIcon?: 'backArrow' | 'close';
  headerMessage?: string | null;
};

type ChangeNetworkStepProps = {
  accountRef: ChangeNetworkStepFragment$key | null;
  sendReceiveSupportedNetworksRef: ChangeNetworkStepSupportedNetworksFragment$key | null;
  flow: SendReceiveAction;
  onChange(networkSlug: string | null): void;
  selectedNetwork: SupportedNetwork | null;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  stepper: StepperType<any>;
  submit?: () => void;
  entryPoint?: SendReceiveEntryPoint;
  hasChangedNetwork?: boolean;
  setHasChangedNetwork?: (val: boolean) => void;
  networkOverrideSlug?: string;
  hasSupportedNetworks?: boolean;
  showHeader?: boolean;
  showReceiveMessage?: boolean;
  isSendReceiveRedesign?: boolean;
};

const PURPLE_COLOR = '#7B1AF7';

function ChangeNetworkStep({
  accountRef,
  sendReceiveSupportedNetworksRef,
  flow,
  onChange,
  selectedNetwork,
  stepper,
  submit = noop,
  entryPoint,
  hasChangedNetwork,
  setHasChangedNetwork,
  networkOverrideSlug,
  hasSupportedNetworks,
  showHeader = true,
  showReceiveMessage = true,
  isSendReceiveRedesign = false,
}: ChangeNetworkStepProps) {
  const { formatMessage } = useIntl();
  const [showWarning, setShowWarning] = useState(false);
  const hasBtcLightningSupport = useHasBtcLightningSupport();
  const nativeCurrency = useNativeCurrency();

  const account = useFragment(
    graphql`
      fragment ChangeNetworkStepFragment on Account {
        uuid
        assetOrFiatCurrency {
          ... on ViewerAsset {
            asset {
              slug
              displaySymbol
              platformName
            }
          }
        }
      }
    `,
    accountRef,
  );

  const sendReceiveSupportedNetworks = useFragment(
    graphql`
      fragment ChangeNetworkStepSupportedNetworksFragment on SendReceiveSupportedNetworks {
        supportedNetworks {
          networkSlug
          isDefault
          isEnabled
          networkName
          assetImageUrl
          isFreeGasEnabled
        }
      }
    `,
    sendReceiveSupportedNetworksRef,
  );

  const supportedNetworks = sendReceiveSupportedNetworks?.supportedNetworks;

  const { goBack, goToStep } = useStepper(stepper);
  const { logGenericSendReceiveFlowEvent, logSendReceiveRedesignFlowEvent } =
    useSendReceiveLoggers();
  const [nextNetwork, setNextNetwork] = useState<
    SupportedNetwork | null | undefined
  >(undefined);

  useEffect(
    () =>
      logGenericSendReceiveFlowEvent(`${flow}_modal`, {
        componentType: ComponentType.modal,
        flow: `${flow}_network_selection`,
        action: ActionType.render,
        step: 'change_network',
      }),
    [],
  );

  const trackButtonClick = useCallback(
    (componentName: ComponentNames, network?: SupportedNetwork | null) =>
      logGenericSendReceiveFlowEvent(`${flow}_modal_button`, {
        componentType: ComponentType.button,
        action: ActionType.click,
        flow: `${flow}_network_selection`,
        componentName,
        step: 'change_network',
        selectedNetwork: network?.networkName ?? '',
      }),
    [flow, logGenericSendReceiveFlowEvent],
  );

  const redesignTrackButtonClick = useCallback(
    (network: string | undefined, flow: SendReceiveAction) => {
      logSendReceiveRedesignFlowEvent('redesign_network_selector_row', {
        action: ActionType.click,
        componentType: ComponentType.button,
        step:
          flow === 'send'
            ? 'send_network_selection'
            : 'receive_network_selection',
        selectedNetwork: network,
      });
    },
    [logSendReceiveRedesignFlowEvent],
  );

  const onChangeGenerator = useCallback(
    (network?: SupportedNetwork | null | undefined) => {
      return async () => {
        onChange(network?.networkSlug || null);
        submit?.();
        // since this could be undefined, explicitly check for false
        if (hasChangedNetwork === false && !network?.isDefault) {
          setHasChangedNetwork?.(true);
        }

        trackButtonClick('select', network);

        const shouldShowWarning = await getShouldShowWarning({ flow });

        if (
          network?.networkSlug !== networkOverrideSlug ||
          network?.networkSlug !== selectedNetwork?.networkSlug
        ) {
          await setHasSeenPill(flow, true);
        }
        if (
          !!network &&
          !network.isDefault &&
          entryPoint !== 'l2-announcement-card'
        ) {
          setHasSeenMultichainNux(flow, true);
        }

        if (shouldShowWarning) {
          goToStep('l2WarningStep');
          return;
        }

        goToStep(flow === 'send' ? 'previewStep' : 'addressStep');
      };
    },
    [
      entryPoint,
      flow,
      goToStep,
      hasChangedNetwork,
      networkOverrideSlug,
      onChange,
      selectedNetwork?.networkSlug,
      setHasChangedNetwork,
      submit,
      trackButtonClick,
    ],
  );

  useEffect(() => {
    if (nextNetwork === undefined) {
      return;
    }

    getShouldShowWarning({ flow })
      .then((show: boolean) => {
        if (show) {
          setShowWarning(show);
          return;
        }

        if (
          !show &&
          nextNetwork?.networkSlug === 'polygon' &&
          account?.assetOrFiatCurrency?.asset?.displaySymbol === 'USDC'
        ) {
          setShowWarning(true);
          return;
        }

        if (!isSendReceiveRedesign) {
          submit?.();
        }
        onChange(nextNetwork?.networkSlug ?? null);
        goBack();
      })
      .catch(() => {
        setShowWarning(false);
        onChange(nextNetwork?.networkSlug ?? null);
      })
      .finally(() => {
        redesignTrackButtonClick(nextNetwork?.networkName ?? undefined, flow);
        markStep(
          flow === 'send'
            ? 'send_redesign_network_selected'
            : 'receive_redesign_network_selected',
        );
      });
  }, [nextNetwork]);

  // sets local state for the selector
  const onSelectNetwork = useCallback(
    (network: SupportedNetwork | null | undefined) => {
      if (!isSendReceiveRedesign) {
        return onChangeGenerator(network);
      }

      if (hasBtcLightningSupport && network?.networkSlug === 'lightning') {
        return () => {
          trackButtonClick('select', network);
          onChange(network?.networkSlug ?? null);
        };
      }

      return () => {
        setNextNetwork(network || null);
      };
    },
    [
      isSendReceiveRedesign,
      onChangeGenerator,
      hasBtcLightningSupport,
      onChange,
      trackButtonClick,
    ],
  );

  const handleLearnMoreTracking = useCallback(
    () => trackButtonClick('learn_more'),
    [trackButtonClick],
  );

  const handleGoBack = useCallback(() => {
    goBack();
    markStep(
      flow === 'send'
        ? 'select_send_redesign_network_selection'
        : 'receive_redesign_network_selected',
    );
  }, [flow, goBack]);

  const handleWarningBackPress = useCallback(() => {
    setShowWarning(false);
    setNextNetwork(undefined);
  }, []);

  const media = useCallback(
    (network?: SupportedNetwork | null) => {
      if (hasBtcLightningSupport && network?.networkSlug === 'lightning') {
        return (
          <Box
            justifyContent="center"
            alignItems="center"
            borderRadius="roundedFull"
            background="backgroundAlternate"
            dangerouslySetBackground={PURPLE_COLOR}
            width={32}
            height={32}
          >
            <Icon size="s" name="lightningBolt" dangerouslySetColor="white" />
          </Box>
        );
      }

      return <CellMedia type="asset" source={network?.assetImageUrl || ''} />;
    },
    [hasBtcLightningSupport],
  );

  const newPill = useCallback(
    (networkSlug?: string | null) => {
      if (
        hasBtcLightningSupport &&
        networkSlug === 'lightning' &&
        networkSlug !== selectedNetwork?.networkSlug
      ) {
        return <Pill label={formatMessage(messages.new)} />;
      }

      return null;
    },
    [hasBtcLightningSupport, formatMessage, selectedNetwork?.networkSlug],
  );

  if (showWarning) {
    return (
      <>
        <RedesignNetworkHeader
          handleBackPress={handleWarningBackPress}
          hideText={false}
        />
        <WarningStep
          flow={flow}
          hasSupportedNetworks={hasSupportedNetworks}
          showHeader={false}
          showPolygonWarningBody={
            nextNetwork?.networkSlug === 'polygon' &&
            account?.assetOrFiatCurrency?.asset?.displaySymbol === 'USDC'
          }
          // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
          onAcknowledgeWarning={() => {
            onChange(nextNetwork?.networkSlug ?? null);
            goBack();
          }}
        />
      </>
    );
  }

  return (
    <>
      {showHeader &&
        (isSendReceiveRedesign ? (
          <RedesignNetworkHeader handleBackPress={goBack} />
        ) : (
          <Header goBack={handleGoBack} />
        ))}
      <VStack
        flexGrow={1}
        flexShrink={1}
        flexBasis="auto"
        spacingBottom={2}
        minHeight={isSendReceiveRedesign ? REDESIGN_MIN_HEIGHT : undefined}
        maxHeight={560}
        overflow="auto"
      >
        <VStack spacingHorizontal={3}>
          {showReceiveMessage && (
            <TextBody as="p" color="foregroundMuted" spacingTop={1}>
              {isSendReceiveRedesign
                ? formatMessage(messages.sendRedesignMessage, {
                    learnMoreLink: (
                      <Link
                        testID="TrayLink"
                        variant="body"
                        to="https://help.coinbase.com/en/coinbase/trading-and-funding/sending-or-receiving-cryptocurrency/assets-on-multiple-networks"
                        openInNewWindow
                        onPress={handleLearnMoreTracking}
                      >
                        {formatMessage(messages.learnMore)}
                      </Link>
                    ),
                  })
                : formatMessage(messages.receiveMessage, {
                    currencyCode:
                      account?.assetOrFiatCurrency?.asset?.displaySymbol,
                    flow,
                    learnMoreLink: (
                      <Link
                        testID="TrayLink"
                        variant="body"
                        to="https://help.coinbase.com/en/coinbase/trading-and-funding/sending-or-receiving-cryptocurrency/assets-on-multiple-networks"
                        openInNewWindow
                        onPress={handleLearnMoreTracking}
                      >
                        {formatMessage(messages.learnMore)}
                      </Link>
                    ),
                  })}
            </TextBody>
          )}
        </VStack>
        <StyledListInner>
          {supportedNetworks?.map(network => (
            <ListCell
              innerSpacing={{ spacingHorizontal: 1 }}
              borderRadius="roundedLarge"
              disabled={!network?.isEnabled || false}
              key={network?.networkSlug || undefined}
              testID={`${network?.networkSlug}-network`}
              onPress={onSelectNetwork(network)}
              title={network?.networkName}
              detail={
                !network?.isDefault &&
                account?.assetOrFiatCurrency?.asset?.slug.toLowerCase() ===
                  'usdc' ? (
                  formatMessage(messages.freeSends)
                ) : (
                  <NetworkCellDetailFee
                    networkSlug={network?.networkSlug ?? ''}
                    platformName={
                      account?.assetOrFiatCurrency?.asset?.platformName ?? ''
                    }
                    currency={nativeCurrency}
                    ticker={
                      account?.assetOrFiatCurrency?.asset?.displaySymbol ?? ''
                    }
                  />
                )
              }
              description={
                network?.isDefault && (
                  <TextBody as="p" color="foregroundMuted">
                    {formatMessage(messages.default)}
                  </TextBody>
                )
              }
              selected={
                networkOverrideSlug
                  ? network?.networkSlug === networkOverrideSlug
                  : network?.networkSlug === selectedNetwork?.networkSlug
              }
              action={newPill(network?.networkSlug)}
              media={media(network)}
            />
          ))}
        </StyledListInner>
      </VStack>
    </>
  );
}

const StyledListInner = styled(ListInner)`
  overflow-y: auto;
  flex: 1 1 auto;
  @media (${devices.phone}) {
    flex: 1 1 0;
  }
`;

export function RedesignNetworkHeader({
  handleBackPress,
  hideText = true,
  backIcon = 'backArrow',
  headerMessage,
}: RedesignNetworkHeaderProps) {
  const { formatMessage } = useIntl();

  let formattedMessage;
  switch (headerMessage) {
    case null:
      formattedMessage = null;
      break;
    case undefined:
      formattedMessage = formatMessage(messages.changeNetwork);
      break;
    default:
      formattedMessage = headerMessage;
  }

  return (
    <Box height={72} alignItems="center">
      <Box spacing={1} flexGrow={1} flexShrink={1} flexBasis={0}>
        <IconButton name={backIcon} onPress={handleBackPress} transparent />
      </Box>
      {hideText && formattedMessage && (
        <Box flexGrow={1} flexShrink={1}>
          <TextHeadline as="h1">{formattedMessage}</TextHeadline>
        </Box>
      )}
    </Box>
  );
}

