function AddressField(props: AddressFieldProps) {
  const { onInputChange } = props;
  const googlePlacesClientRef = useRef(new GooglePlacesClient());
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);

  const getSuggestions = debounce(
    async (event: React.ChangeEvent<HTMLInputElement>) => {
      const client = googlePlacesClientRef.current;
      setSuggestions([]);
      try {
        const suggestions = await client.autofill({
          input: event.target.value,
        });
        setSuggestions(suggestions);
      } catch (error) {
        notifyError(error, { owner: 'p2p', context: 'send_receive' });
      }
    },
    500,
  );

  const handleChange = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (event: any) => {
      event.persist();
      onInputChange(event);
      getSuggestions(event);
    },
    [getSuggestions, onInputChange],
  );

  const handleSuggestionSelect = async (suggestion: SuggestionItem) => {
    const client = googlePlacesClientRef.current;
    const response = await client.getPlaceDetails({
      placeId: suggestion.placeId,
    });

    if (response && props.onSuggestionPick) {
      props.onSuggestionPick(response);
    }

    setSuggestions([]);
  };

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleOutsideClick = () => {
    setSuggestions([]);
  };

  const showSuggestions = suggestions.length > 0;

  return (
    <AddressFieldWrapper>
      <TextInput
        label={props.label}
        placeholder={props.placeholder}
        onChange={handleChange}
        onBlur={props.onBlur}
        variant={props.variant}
        value={props.value}
        compact={props.compact}
        helperText={props.helperText}
      />
      {showSuggestions && (
        <OutsideClickListener handleOutsideClick={handleOutsideClick}>
          <SuggesstionsWrapper>
            {suggestions.slice(0, 4).map((suggestion: SuggestionItem) => {
              return (
                <AddressFieldSuggestion
                  key={suggestion.placeId}
                  title={suggestion.title}
                  placeId={suggestion.placeId}
                  description={suggestion.description}
                  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                  onClick={() => handleSuggestionSelect(suggestion)}
                />
              );
            })}
          </SuggesstionsWrapper>
        </OutsideClickListener>
      )}
    </AddressFieldWrapper>
  );
}

