// Calls validator and returns error message
function validateFieldRequired(value: string) {
  if (!required(value)) return messages.requiredField;
}

// Calls validator and returns error message
function validateFieldMaxLength(value: string) {
  if (!validateMaxLength(value, 140)) return messages.maxLengthError;
}

// Calls validator and returns error message
function validateFieldName(value: string) {
  if (!validateName(value)) return messages.invalidName;
}

function RecipientInfoStep() {
  const { katakanaName } = useUser();

  const [isCalendarOpen, setIsCalendarOpen] = useState(false);
  const currentUser = useUser();

  const isCalendarOpenSetter = (value: boolean) => () =>
    setIsCalendarOpen(value);

  const formFields = useFields(SendForm);
  const [submit] = useSendSubmitter();
  const isSubmittingSendForm = useIsSubmitting();
  const { formatMessage, locale } = useIntl();
  const markDirty = useDirtySetter(SendForm);
  const { logSendReceiveRedesignFlowEvent } = useSendReceiveLoggers();
  const isPrefillTravelRuleEligible = useIsPrefillTravelRuleEligible();
  const [createSendReceiveContact, isCreatingSendReceiveContact] =
    useCreateSendReceiveContact();
  const [updateSendReceiveContact, isUpdatingSendReceiveContact] =
    useUpdateSendReceiveContact();
  const generateContactNickname = useGenerateContactNickname();

  const isSubmitting = useMemo(() => {
    return (
      isSubmittingSendForm ||
      isCreatingSendReceiveContact ||
      isUpdatingSendReceiveContact
    );
  }, [
    isSubmittingSendForm,
    isCreatingSendReceiveContact,
    isUpdatingSendReceiveContact,
  ]);

  const {
    recipient,
    recipientInfo,
    beneficiaryContactId,
    beneficiaryContactAddressId,
    beneficiaryWalletType,
    beneficiaryExchange,
    beneficiaryAddressLine1,
    beneficiaryAddressCity,
    beneficiaryAddressCountry,
    beneficiaryAddressPostcode,
    beneficiaryFullName,
    beneficiaryJapaneseEnglishName,
    beneficiaryJapaneseKanjiName,
    beneficiaryJapaneseKanaName,
    beneficiaryTransferPurpose,
    beneficiaryDateOfBirth,
    beneficiaryIsOwnAccount,
  } = formFields;
  const fieldsNeeded = new Set(recipientInfo.value?.fieldsRequired);
  const disclaimerMessage = recipientInfo.value?.disclaimerMessage;

  const walletType = useMemo<TravelRuleWalletType>(() => {
    switch (beneficiaryWalletType.value) {
      case 'UKNOWN_TYPE':
        return 'WALLET_TYPE_UNSPECIFIED';
      case 'SELF_HOSTED':
        return 'WALLET_TYPE_SELF_HOSTED';
      case 'EXCHANGE':
        return 'WALLET_TYPE_EXCHANGE';
      default:
        return 'WALLET_TYPE_UNSPECIFIED';
    }
  }, [beneficiaryWalletType.value]);

  const showFullName = fieldsNeeded.has(FIELD_NAME_MAP.FULL_NAME);
  const showNameJapanese = fieldsNeeded.has(FIELD_NAME_MAP.NAME_JAPANESE);
  const showNameKanji = fieldsNeeded.has(FIELD_NAME_MAP.NAME_JAPANESE);
  const showNameKana = fieldsNeeded.has(FIELD_NAME_MAP.NAME_JAPANESE);
  const showPurpose = fieldsNeeded.has(FIELD_NAME_MAP.PURPOSE);
  const showAddress = fieldsNeeded.has(FIELD_NAME_MAP.ADDRESS);
  const showCountry = !showAddress && fieldsNeeded.has(FIELD_NAME_MAP.COUNTRY);
  const showDOB = fieldsNeeded.has(FIELD_NAME_MAP.DOB);

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleSubmit = async () => {
    logSendReceiveRedesignFlowEvent('recipient_info_step_submit', {
      action: ActionType.click,
      componentType: ComponentType.button,
    });

    if (beneficiaryIsOwnAccount.value === undefined) {
      beneficiaryIsOwnAccount.onChange(false);
    }

    // Auto-save beneficiary info to a contact entry if:
    // - Beneficiary name is available
    // - User is elgibile for prefilling travel rule data
    if (beneficiaryFullName.value.length > 0 && isPrefillTravelRuleEligible) {
      const nickname = generateContactNickname(
        beneficiaryFullName.value,
        recipient.value,
      );
      const travelRuleParams = {
        nickname,
        address: recipient.value,
        travelRules: {
          walletType,
          name:
            beneficiaryFullName.value.length > 0
              ? beneficiaryFullName.value
              : undefined,
          country:
            beneficiaryAddressCountry.value.length > 0
              ? beneficiaryAddressCountry.value
              : undefined,
          transferPurpose:
            beneficiaryTransferPurpose.value.length > 0
              ? beneficiaryTransferPurpose.value
              : undefined,
          address1:
            beneficiaryAddressLine1.value.length > 0
              ? beneficiaryAddressLine1.value
              : undefined,
          address2: '',
          address3: '',
          city:
            beneficiaryAddressCity.value.length > 0
              ? beneficiaryAddressCity.value
              : undefined,
          state:
            beneficiaryAddressLine1.value.length > 0
              ? beneficiaryAddressLine1.value
              : undefined,
          postalCode:
            beneficiaryAddressPostcode.value.length > 0
              ? beneficiaryAddressPostcode.value
              : undefined,
          isSelf: beneficiaryIsOwnAccount.value,
          financialInstitution:
            beneficiaryExchange.value.length > 0
              ? beneficiaryExchange.value
              : undefined,
        },
      };

      if (beneficiaryContactId.value) {
        // If contact UUID is already available, we will just update the respective contact entry
        // instead of creating a new contact entry
        await updateSendReceiveContact(
          beneficiaryContactId.value,
          beneficiaryContactAddressId.value,
          travelRuleParams,
        );
      } else {
        // Create a new contact entry if there's no existing contact
        // containing the recipient address
        try {
          const uuid = await createSendReceiveContact(travelRuleParams);
          if (uuid !== null) {
            beneficiaryContactId.onChange(uuid);
          }
        } catch (err) {
          // Since this is auto-save flow, we will fail silently here
          // Error tracking has already been handled by 'createSendReceiveContact' itself.
        }
      }
    }

    await submit();
  };

  useEffect(() => {
    logSendReceiveRedesignFlowEvent('recipient_info_step', {
      action: ActionType.render,
      componentType: ComponentType.modal,
    });
  }, []);

  const handleAddressSuggestionPick = useCallback(
    (address: NormalizedAddress) => {
      const { line1, line2, city, country, zip } = address;
      const addressLine1 = [line1, line2].filter(Boolean).join(' ');

      if (addressLine1) {
        formFields.beneficiaryAddressLine1.onChange(addressLine1);
      }

      if (city) {
        formFields.beneficiaryAddressCity.onChange(city);
      }

      if (country) {
        formFields.beneficiaryAddressCountry.onChange(country);
      }

      if (zip) {
        formFields.beneficiaryAddressPostcode.onChange(zip);
      }
    },
    [formFields],
  );

  const createAddressFieldChangeHandler = useCallback(
    (fieldName: RecipientInfoAddressFields) =>
      (event: React.ChangeEvent<HTMLInputElement>) => {
        formFields[fieldName].onChange(event.target.value);
      },
    [formFields],
  );

  // Returns an array of errors for a given field, empty array means no error
  const isFieldValid = useCallback(
    (
      fieldName: keyof Omit<
        Pick<typeof defaultValues, RecipientInfoFields>,
        'beneficiaryIsOwnAccount'
      >,
    ): errorMessage[] => {
      const fields: Record<
        Exclude<RecipientInfoFields, 'beneficiaryIsOwnAccount'>,
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        FieldProps<string, any>
      > = {
        beneficiaryAddressLine1,
        beneficiaryAddressCity,
        beneficiaryAddressCountry,
        beneficiaryAddressPostcode,
        beneficiaryFullName,
        beneficiaryJapaneseEnglishName,
        beneficiaryJapaneseKanjiName,
        beneficiaryJapaneseKanaName,
        beneficiaryTransferPurpose,
        beneficiaryDateOfBirth,
      };
      const fieldValidators = FIELD_VALIDATORS[fieldName];
      const errors: errorMessage[] = [];
      for (const validator of fieldValidators) {
        const error = validator(fields[fieldName].value);
        if (error) {
          errors.push(error);
        }
      }
      return errors;
    },
    [
      beneficiaryAddressLine1,
      beneficiaryAddressCity,
      beneficiaryAddressCountry,
      beneficiaryAddressPostcode,
      beneficiaryFullName,
      beneficiaryJapaneseEnglishName,
      beneficiaryJapaneseKanjiName,
      beneficiaryJapaneseKanaName,
      beneficiaryTransferPurpose,
      beneficiaryDateOfBirth,
    ],
  );

  const isFieldDirty = useCallback(
    (
      fieldName: keyof Omit<
        Pick<typeof defaultValues, RecipientInfoFields>,
        'beneficiaryIsOwnAccount'
      >,
    ): boolean => {
      const fields: Record<
        Exclude<RecipientInfoFields, 'beneficiaryIsOwnAccount'>,
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        FieldProps<string, any>
      > = {
        beneficiaryAddressLine1,
        beneficiaryAddressCity,
        beneficiaryAddressCountry,
        beneficiaryAddressPostcode,
        beneficiaryFullName,
        beneficiaryJapaneseEnglishName,
        beneficiaryJapaneseKanjiName,
        beneficiaryJapaneseKanaName,
        beneficiaryTransferPurpose,
        beneficiaryDateOfBirth,
      };
      return fields[fieldName].isDirty;
    },
    [
      beneficiaryAddressLine1,
      beneficiaryAddressCity,
      beneficiaryAddressCountry,
      beneficiaryAddressPostcode,
      beneficiaryFullName,
      beneficiaryJapaneseEnglishName,
      beneficiaryJapaneseKanjiName,
      beneficiaryJapaneseKanaName,
      beneficiaryTransferPurpose,
      beneficiaryDateOfBirth,
    ],
  );

  const getInputVariant = useCallback(
    (
      fieldName: keyof Omit<
        Pick<typeof defaultValues, RecipientInfoFields>,
        'beneficiaryIsOwnAccount'
      >,
    ) => {
      if (!isFieldDirty(fieldName)) return 'foregroundMuted';
      const errors = isFieldValid(fieldName);
      return errors.length > 0 ? 'negative' : 'foregroundMuted';
    },
    [isFieldValid, isFieldDirty],
  );
  const errorMessages = useCallback(
    (
      fieldName: keyof Omit<
        Pick<typeof defaultValues, RecipientInfoFields>,
        'beneficiaryIsOwnAccount'
      >,
    ): string => {
      if (!isFieldDirty(fieldName)) {
        return '';
      }
      const errors = isFieldValid(fieldName);
      let errorsStr = '';

      for (const error of errors) {
        errorsStr = errorsStr + ' ' + formatMessage(error);
      }
      return errorsStr;
    },
    [formatMessage, isFieldValid, isFieldDirty],
  );

  const renderCountryField = useCallback(() => {
    return (
      <Select
        value={formFields.beneficiaryAddressCountry.value}
        data-testid="country-select"
        compact
        label={formatMessage(messages.countryLabel)}
        placeholder={formatMessage(messages.countryPlaceholder)}
      >
        {allowedCountries.map(option => (
          <SelectOption
            key={option.code}
            value={option.code}
            title={formatMessage(option.name)}
            compact
            // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
            onPress={() =>
              formFields.beneficiaryAddressCountry.onChange(option.code)
            }
          />
        ))}
      </Select>
    );
  }, [formFields.beneficiaryAddressCountry, formatMessage]);

  const popupHeight = 250;

  let spaceProvided = 0;
  if (showAddress) {
    spaceProvided = 250;
  } else if (showCountry) {
    spaceProvided = 60;
  }

  const spaceNeeded = popupHeight - spaceProvided;

  const isFormIncomplete = useCallback(() => {
    if (
      (showNameJapanese &&
        isFieldValid('beneficiaryJapaneseEnglishName').length > 0) ||
      (showNameKana &&
        isFieldValid('beneficiaryJapaneseKanaName').length > 0) ||
      (showNameKanji &&
        isFieldValid('beneficiaryJapaneseKanjiName').length > 0) ||
      (showPurpose && isFieldValid('beneficiaryTransferPurpose').length > 0) ||
      (showDOB && isFieldValid('beneficiaryDateOfBirth').length > 0) ||
      (showCountry && isFieldValid('beneficiaryAddressCountry').length > 0) ||
      (showFullName && isFieldValid('beneficiaryFullName').length > 0)
    )
      return true;

    if (showAddress) {
      const addressFieldKeys: Exclude<
        RecipientInfoFields,
        'beneficiaryIsOwnAccount'
      >[] = [
        'beneficiaryAddressLine1',
        'beneficiaryAddressCity',
        'beneficiaryAddressCountry',
        'beneficiaryAddressPostcode',
      ];

      const addressFieldsWithErrors = addressFieldKeys.filter(
        field => isFieldValid(field).length > 0,
      );

      if (addressFieldsWithErrors.length > 0) {
        return true;
      }
    }

    return false;
  }, [
    isFieldValid,
    showAddress,
    showCountry,
    showDOB,
    showFullName,
    showNameJapanese,
    showNameKana,
    showNameKanji,
    showPurpose,
  ]);

  const formIncomplete = isFormIncomplete();

  const createFieldChangeHandler = useCallback(
    (
        fieldName: keyof Omit<
          Pick<typeof defaultValues, RecipientInfoFields>,
          'beneficiaryIsOwnAccount'
        >,
      ) =>
      (event: React.ChangeEvent<HTMLInputElement>) => {
        const fields: Record<
          Exclude<RecipientInfoFields, 'beneficiaryIsOwnAccount'>,
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          FieldProps<string, any>
        > = {
          beneficiaryAddressLine1,
          beneficiaryAddressCity,
          beneficiaryAddressCountry,
          beneficiaryAddressPostcode,
          beneficiaryFullName,
          beneficiaryJapaneseEnglishName,
          beneficiaryJapaneseKanjiName,
          beneficiaryJapaneseKanaName,
          beneficiaryTransferPurpose,
          beneficiaryDateOfBirth,
        };
        fields[fieldName].onChange(event.target.value);
      },
    [
      beneficiaryAddressCity,
      beneficiaryAddressCountry,
      beneficiaryAddressLine1,
      beneficiaryAddressPostcode,
      beneficiaryDateOfBirth,
      beneficiaryFullName,
      beneficiaryJapaneseEnglishName,
      beneficiaryTransferPurpose,
      beneficiaryJapaneseKanjiName,
      beneficiaryJapaneseKanaName,
    ],
  );

  const handleIsOwnAccountChange = useCallback(
    (isOwnAccount: boolean) => {
      formFields.beneficiaryIsOwnAccount.onChange(isOwnAccount);

      if (isOwnAccount) {
        if (showFullName && currentUser.name) {
          formFields.beneficiaryFullName.onChange(currentUser.name);
        }
        if (showAddress) {
          if (currentUser.addressLine1) {
            formFields.beneficiaryAddressLine1.onChange(
              currentUser.addressLine1,
            );
          }

          if (currentUser.city) {
            formFields.beneficiaryAddressCity.onChange(currentUser.city);
          }

          if (currentUser.postalCode) {
            formFields.beneficiaryAddressPostcode.onChange(
              currentUser.postalCode,
            );
          }

          if (currentUser.countryCode) {
            formFields.beneficiaryAddressCountry.onChange(
              currentUser.countryCode,
            );
          }
        }

        if (showCountry && currentUser.countryCode) {
          formFields.beneficiaryAddressCountry.onChange(
            currentUser.countryCode,
          );
        }

        if (showNameJapanese && katakanaName) {
          formFields.beneficiaryJapaneseEnglishName.onChange(katakanaName);
        }
      } else {
        formFields.beneficiaryAddressLine1.onChange(
          initialAddressValues.beneficiaryAddressLine1,
        );
        formFields.beneficiaryAddressCity.onChange(
          initialAddressValues.beneficiaryAddressCity,
        );
        formFields.beneficiaryAddressPostcode.onChange(
          initialAddressValues.beneficiaryAddressPostcode,
        );
        formFields.beneficiaryAddressCountry.onChange(
          initialAddressValues.beneficiaryAddressCountry,
        );
      }
    },
    [
      currentUser.addressLine1,
      currentUser.city,
      currentUser.countryCode,
      currentUser.name,
      currentUser.postalCode,
      formFields.beneficiaryAddressCity,
      formFields.beneficiaryAddressCountry,
      formFields.beneficiaryAddressLine1,
      formFields.beneficiaryAddressPostcode,
      formFields.beneficiaryFullName,
      formFields.beneficiaryIsOwnAccount,
      formFields.beneficiaryJapaneseEnglishName,
      katakanaName,
      showAddress,
      showCountry,
      showFullName,
      showNameJapanese,
    ],
  );

  const handleDOBChange = useCallback(
    (date: Date) => {
      formFields.beneficiaryDateOfBirth.onChange(date.valueOf().toString());
    },
    [formFields],
  );

  useOnce(() => {
    // BeneficiaryIsOwnAccount might be populated by SignMessageStep.
    // Call handleIsOwnAccountChange if its pre populated.
    if (formFields.beneficiaryIsOwnAccount.value) {
      handleIsOwnAccountChange(true);
    }
  });

  const handleOnChange: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(
      e => handleIsOwnAccountChange(e.target.checked),
      [handleIsOwnAccountChange],
    );

  const handleOnBlur = useCallback(() => {
    markDirty(['beneficiaryFullName']);
  }, [markDirty]);

  const handleOnBlur1 = useCallback(() => {
    markDirty(['beneficiaryJapaneseEnglishName']);
  }, [markDirty]);

  const handleOnBlur2 = useCallback(() => {
    markDirty(['beneficiaryJapaneseKanjiName']);
  }, [markDirty]);

  const handleOnBlur3 = useCallback(() => {
    markDirty(['beneficiaryJapaneseKanaName']);
  }, [markDirty]);

  const handleOnBlur4 = useCallback(() => {
    markDirty(['beneficiaryTransferPurpose']);
  }, [markDirty]);

  const handleOnBlur5 = useCallback(() => {
    markDirty(['beneficiaryDateOfBirth']);
  }, [markDirty]);

  const handleOnBlur6 = useCallback(() => {
    markDirty(['beneficiaryAddressLine1']);
  }, [markDirty]);

  const handleOnBlur7 = useCallback(() => {
    markDirty(['beneficiaryAddressCity']);
  }, [markDirty]);

  const handleOnBlur8 = useCallback(() => {
    markDirty(['beneficiaryAddressPostcode']);
  }, [markDirty]);

  return (
    <VStack>
      <VStack
        spacing={3}
        spacerGap={1}
        overflow="auto"
        justifyContent="space-between"
      >
        <TextTitle3 as="p">{formatMessage(messages.title)}</TextTitle3>
        {disclaimerMessage ? (
          <TextBody as="p" color="foregroundMuted">
            <div dangerouslySetInnerHTML={{ __html: disclaimerMessage }}></div>
          </TextBody>
        ) : (
          <TextBody as="p" color="foregroundMuted">
            {formatMessage(messages.description)}{' '}
            <Link
              openInNewWindow
              rel="noopener noreferrer"
              to={`https://help.coinbase.com/${locale}/coinbase/trading-and-funding/sending-or-receiving-cryptocurrency/how-to-send-crypto`}
            >
              {formatMessage(messages.learnMoreLink)}
            </Link>
          </TextBody>
        )}
        <Checkbox
          name="isOwnAccount"
          testID="own-account-checkbox"
          onChange={handleOnChange}
          checked={formFields.beneficiaryIsOwnAccount.value}
        >
          <TextBody as="p" color="foregroundMuted">
            {formatMessage(messages.isOwnAccountLabel)}
          </TextBody>
        </Checkbox>
        {showFullName && (
          <TextInput
            label={formatMessage(messages.fullNameLabel)}
            compact
            placeholder={formatMessage(messages.fullNamePlaceholder)}
            name="fullName"
            onChange={createFieldChangeHandler('beneficiaryFullName')}
            value={formFields.beneficiaryFullName.value}
            onBlur={handleOnBlur}
            variant={getInputVariant('beneficiaryFullName')}
            helperText={errorMessages('beneficiaryFullName')}
          />
        )}
        {showNameJapanese && (
          <TextInput
            compact
            label={formatMessage(messages.nameJapaneseLabel)}
            placeholder={formatMessage(messages.fullNamePlaceholder)}
            name="nameJapanese"
            onChange={createFieldChangeHandler(
              'beneficiaryJapaneseEnglishName',
            )}
            value={formFields.beneficiaryJapaneseEnglishName.value}
            onBlur={handleOnBlur1}
            variant={getInputVariant('beneficiaryJapaneseEnglishName')}
            helperText={errorMessages('beneficiaryJapaneseEnglishName')}
          />
        )}
        {showNameKanji && (
          <TextInput
            compact
            label={formatMessage(messages.nameKanjiLabel)}
            placeholder={formatMessage(messages.fullNamePlaceholder)}
            name="nameKanji"
            onChange={createFieldChangeHandler('beneficiaryJapaneseKanjiName')}
            value={formFields.beneficiaryJapaneseKanjiName.value}
            onBlur={handleOnBlur2}
            variant={getInputVariant('beneficiaryJapaneseKanjiName')}
            helperText={errorMessages('beneficiaryJapaneseKanjiName')}
          />
        )}
        {showNameKana && (
          <TextInput
            compact
            label={formatMessage(messages.nameKanaLabel)}
            placeholder={formatMessage(messages.fullNamePlaceholder)}
            name="nameKana"
            onChange={createFieldChangeHandler('beneficiaryJapaneseKanaName')}
            value={formFields.beneficiaryJapaneseKanaName.value}
            onBlur={handleOnBlur3}
            variant={getInputVariant('beneficiaryJapaneseKanaName')}
            helperText={errorMessages('beneficiaryJapaneseKanaName')}
          />
        )}
        {showPurpose && (
          <TextInput
            compact
            label={formatMessage(messages.purposeLabel)}
            placeholder={formatMessage(messages.purposePlaceholder)}
            name="purpose"
            onChange={createFieldChangeHandler('beneficiaryTransferPurpose')}
            value={formFields.beneficiaryTransferPurpose.value}
            onBlur={handleOnBlur4}
            variant={getInputVariant('beneficiaryTransferPurpose')}
            helperText={errorMessages('beneficiaryTransferPurpose')}
          />
        )}
        {showDOB && (
          <VStack spacerGap={0.5}>
            <TextLabel1 as="p">{formatMessage(messages.dobLabel)}</TextLabel1>
            <DatePickerWrapper
              hasError={
                getInputVariant('beneficiaryDateOfBirth') === 'negative'
              }
            >
              <DatePicker
                // @ts-expect-error The date field needs needs to be shown as empty at first
                selected={
                  formFields.beneficiaryDateOfBirth.value
                    ? new Date(
                        parseInt(formFields.beneficiaryDateOfBirth.value),
                      )
                    : undefined
                }
                onChange={handleDOBChange}
                onBlur={handleOnBlur5}
                popperPlacement="bottom-start"
                onCalendarClose={isCalendarOpenSetter(false)}
                onCalendarOpen={isCalendarOpenSetter(true)}
                wrapperClassName="datepicker-recipient-info"
                maxDate={new Date()}
              />
            </DatePickerWrapper>
          </VStack>
        )}
        {showAddress && (
          <VStack spacerGap={1}>
            <AddressField
              label={formatMessage(messages.addressLabel)}
              onInputChange={createAddressFieldChangeHandler(
                'beneficiaryAddressLine1',
              )}
              value={formFields.beneficiaryAddressLine1.value}
              onSuggestionPick={handleAddressSuggestionPick}
              onBlur={handleOnBlur6}
              variant={getInputVariant('beneficiaryAddressLine1')}
              compact
              helperText={errorMessages('beneficiaryAddressLine1')}
            />
            <TextInput
              compact
              label={formatMessage(messages.cityLabel)}
              name="address.city"
              onChange={createAddressFieldChangeHandler(
                'beneficiaryAddressCity',
              )}
              value={formFields.beneficiaryAddressCity.value}
              onBlur={handleOnBlur7}
              variant={getInputVariant('beneficiaryAddressCity')}
              helperText={errorMessages('beneficiaryAddressCity')}
            />
            <TextInput
              compact
              label={formatMessage(messages.zipLabel)}
              name="address.postcode"
              onChange={createAddressFieldChangeHandler(
                'beneficiaryAddressPostcode',
              )}
              value={formFields.beneficiaryAddressPostcode.value}
              onBlur={handleOnBlur8}
              variant={getInputVariant('beneficiaryAddressPostcode')}
              helperText={errorMessages('beneficiaryAddressPostcode')}
            />
            {renderCountryField()}
          </VStack>
        )}
        {showCountry && (
          <VStack spacerGap={0.5}>
            <TextLabel1 as="p">
              {formatMessage(messages.countryOfResidenceLabel)}
            </TextLabel1>
            {renderCountryField()}
          </VStack>
        )}
        {isCalendarOpen && <Box minHeight={spaceNeeded} />}
        <Button
          onPress={handleSubmit}
          disabled={formIncomplete || isSubmitting}
          testID="submit-button"
        >
          {formatMessage(messages.submitButtonText)}
        </Button>
      </VStack>
    </VStack>
  );
}

