export type Props = {
  viewerAssetRef: EntryStepBuySellAssetFragment$key;
  queryRef: EntryStepBuySellFragment$key;
  accountRef: EntryStepBuySellAccountFragment$key;
  closeModal?: () => void;
  disableAssetSelectors?: boolean;
  disableSourceAssetSelection?: boolean;
  totalNativeBalance: number;
  assetSelectorLabelOverride?: string;
  entryStepModalHeaderTitle?: string;
  onEntrySelectorSwitch?: (type: TradeAction) => void;
  eventContext?: TradeEventContext;
  hasPreviewRefreshExperiment?: boolean; // added this as a prop as this step is used on old and new input steps. We want to trigger new preview endpoints for new entry step only
};

const i18nKey = 'BuySellStepper.EntryStep';

const accessibilityMessages = defineMessages({
  // 2023-10-05: TODO please fix, see go/i18n-linter-messages
  // eslint-disable-next-line @cbhq/i18n-enhanced-description
  previewButtonLabel: {
    id: `${i18nKey}.previewButtonLabel`,
    defaultMessage: 'Preview {type}',
    description: `#Component: Button:aria-label
    #CharLimit: 50
    #Context: A label for buy/sell preview button`,
  },
  // 2023-10-05: TODO please fix, see go/i18n-linter-messages
  // eslint-disable-next-line @cbhq/i18n-enhanced-description
  depositButtonLabel: {
    id: `${i18nKey}.depositButtonLabel`,
    defaultMessage: 'Top up {currency} wallet',
    description: `#Component: Button:aria-label
    #CharLimit: 60
    #Context: A label for buy deposit button when fiat balance is insufficient`,
  },
  // 2023-10-05: TODO please fix, see go/i18n-linter-messages
  // eslint-disable-next-line @cbhq/i18n-enhanced-description
  accessibilityLabel: {
    id: `${i18nKey}.accessibilityLabel`,
    defaultMessage: '{asset} amount',
    description:
      'An accessibility label that adds the asset selected to the input text field',
  },
});

function noop() {}

function EntryStep({
  queryRef,
  accountRef,
  viewerAssetRef,
  closeModal,
  disableAssetSelectors,
  disableSourceAssetSelection,
  totalNativeBalance,
  assetSelectorLabelOverride,
  entryStepModalHeaderTitle,
  onEntrySelectorSwitch,
  eventContext,
  hasPreviewRefreshExperiment = false,
}: Props) {
  const query = useFragment(
    graphql`
      fragment EntryStepBuySellFragment on Query {
        ...useLimitGetterForTransferTypeFragment
        ...useTransferQuoterQueryFragment
        ...SimpleTradeFixedAmountsFragment
        ...AddCashSelectModalFragment
        viewer {
          isOnboardedPortfolio
          balanceData {
            balanceInWbl {
              value
            }
          }
          fiatAccounts {
            uuid
            availableBalance {
              value
            }
            assetOrFiatCurrency {
              __typename
              ... on ViewerAsset {
                asset {
                  platformName
                }
              }
              ... on TiersCurrency {
                code
              }
            }
          }
        }
        ...useBuyPresetAmountsFragment
        ...useTieredRewardsDataFragment
      }
    `,
    queryRef,
  );

  const account = useFragment(
    graphql`
      fragment EntryStepBuySellAccountFragment on Account {
        uuid
        availableBalance {
          value
        }
        ...useAssetBalanceInfoAccountFragment
        ...useTransferQuoterFragment
        ...BuySellFooterAccountFragment
        ...useTransferQuoteSubmitterFragment
        ...SimpleTradeFixedAmountsAccountFragment
      }
    `,
    accountRef,
  );

  const selectedViewerAsset = useFragment(
    graphql`
      fragment EntryStepBuySellAssetFragment on ViewerAsset {
        asset {
          uuid
          platformName
          displaySymbol
          name
          isStablecoin
          ...useCurrencyConverterSourceAssetFragment
          ...BuySellEntrySelectorFragmentAssetFragment
          ...SimpleTradeFixedAmountsAccountTargetAssetFragment
        }
        ...EntryInputFragment
        ...EntryInputV2Fragment
        ...RewardApyLabelFragment
        ...BuySellFooterAssetOrCurrencyFragment
        ...RewardApyLabelFragment
        ...useAssetSelectorViewerAssetFragment
        ...useTransferQuoteSubmitterViewerAssetFragment
        ...useTransferQuoterViewerAssetFragment
        ...useIsInputDisabledFragment
        ...useFetchBuySellQuotesFragment
      }
    `,
    viewerAssetRef,
  );

  const { viewer } = query;
  const { fiatAccounts } = viewer;

  const { hasWebRefreshTreatment } = useSimpleTradeRedesignContext();

  const totalHoldBalance = parseFloat(
    viewer.balanceData?.balanceInWbl?.value || '0',
  );

  const { renderTabs } = useContext(FolderTabsContext);
  const {
    fiatInput,
    cryptoInput,
    isFiatInputValue,
    recurringOption,
    setFiatInput: setInputAmount,
    setIsFiatInput,
    disableAutoFocus,
  } = useBuySellProxyContext();
  const isMobile = useIsMobile();
  const {
    amount,
    isFiatInput,
    showPresetAmountsIfAvailable,
    transferType,
    recurringPeriod,
    shouldBuyAndStake,
  } = useSimpleTradeForm();
  let entryInputError = amount.errors[0]?.message;

  const messages = useEntryMessages(transferType.value);

  const { assetBalance, assetBalanceInFiat } = useAssetBalanceInfo({
    accountRef: account,
  });

  const { trackEvent } = useBuySellEventTracker();

  const { formatMessage, formatNumber } = useIntl();
  const { showModal } = useModal();

  const paymentSelector = usePaymentSelector();
  const nativeCurrency = useNativeCurrency();
  const { variant } = useBuySellContext();
  const isModal = useHasModalParent();
  const isDisabled = useIsInputDisabled(
    selectedViewerAsset,
    transferType.value,
  );

  const { isTransferExperiment } = useHasTransferTrayExperiment();
  const hasSimpleTradeSellMigrationExperiment =
    useSimpleTradeSellMigrationExperiment();
  const hasBuyMigrationExperiment = useSimpleTradeBuyMutationMigration();

  const showCashDepositInput =
    isModal &&
    variant === 'cashIn' &&
    eventContext !== 'advancedPortfolioUSDCConvert' &&
    isTransferExperiment;

  const isBuyTrade = transferType.value === 'buy';
  const amountKey: 'total' | 'amount' = useMemo(
    () => (isBuyTrade && isFiatInput.value ? 'total' : 'amount'),
    [isFiatInput.value, isBuyTrade],
  );

  const activePaymentMethod = useActivePaymentMethod('EntryStep');
  const convert = useCurrencyConverter({
    sourceAssetRef: selectedViewerAsset.asset,
    nativeCurrency,
    targetFiatCurrencies: [activePaymentMethod.currency],
  });
  const getLimitForTransferType = useLimitGetterForTransferType({
    queryRef: query,
    totalHoldBalance,
    totalNativeBalance,
    paymentMethodCurrencyList: [activePaymentMethod.currency],
  });
  const { conciseDescription } = useFormattedActivePaymentMethod('EntryStep');

  const activeFiatAccount = useMemo(() => {
    if (activePaymentMethod.type !== 'fiat_account') {
      return undefined;
    }

    return (fiatAccounts || []).find(account => {
      const currencyCode =
        account?.assetOrFiatCurrency?.__typename === 'ViewerAsset'
          ? account.assetOrFiatCurrency.asset.platformName
          : account?.assetOrFiatCurrency?.__typename === 'TiersCurrency'
          ? account.assetOrFiatCurrency.code
          : undefined;
      return currencyCode === activePaymentMethod.currency;
    });
  }, [fiatAccounts, activePaymentMethod]);

  // Check if the current user is eligible to see the Deposit button
  // when user's fiat balance is insufficient to match input amount
  const isDepositButtonEligible = useDepositButtonEligible(
    activePaymentMethod,
    isBuyTrade,
  );

  // Flag indiciating if Deposit button should be displayed.
  // 1. User first needs to be eligible to view the Deposit button
  // 2. Either user's fiat account balance is 0 or not sufficient enough to match the input amount
  const shouldShowDepositButton = useMemo(() => {
    if (!isDepositButtonEligible) {
      return false;
    }

    const isEmptyFiatBalance =
      activeFiatAccount &&
      Number(activeFiatAccount.availableBalance.value) === 0;

    return (
      isEmptyFiatBalance ||
      amount.errors[0]?.data?.apiError?.id ===
        'ERROR_CODES_INSUFFICIENT_BALANCE'
    );
  }, [activeFiatAccount, isDepositButtonEligible, amount.errors]);

  const fiatLimit = getLimitForTransferType({
    paymentMethod: activePaymentMethod,
    transferType: transferType.value,
  });
  const buyPresetAmounts = useBuyPresetAmounts({
    queryRef: query,
    fiatLimit: fiatLimit ?? 0,
  });

  const currenciesMatch = nativeCurrency === activePaymentMethod.currency;
  const showPresetAmounts =
    showPresetAmountsIfAvailable.value &&
    !!buyPresetAmounts &&
    currenciesMatch &&
    variant !== 'cashTransfer';

  const isMobileModal = isMobile && !!closeModal;

  const backButton = useMemo(() => {
    return isMobileModal ? closeModal : undefined;
  }, [isMobileModal, closeModal]);

  const buttonText =
    amount.value === '' ? messages.defaultButton : messages.previewButton;

  const blockSell = Boolean(
    transferType.value === 'sell' && parseFloat(assetBalance.amount) === 0,
  );

  const fiatCode = activePaymentMethod.currency;

  const usdAccount = (fiatAccounts || []).find(account => {
    return (
      account?.assetOrFiatCurrency?.__typename === 'TiersCurrency' &&
      account?.assetOrFiatCurrency?.code === fiatCode
    );
  })?.uuid as string;

  const assetSelector = useAssetSelector({
    viewerAssetRef: selectedViewerAsset,
    overrideOnPress: showCashDepositInput
      ? () => {
          closeModal?.();
          showModal(
            <AddCashSelectModal
              queryRef={query}
              showBalances
              source="entry_step"
              accountId={usdAccount}
            />,
          );
        }
      : undefined,
  });

  const platformName = selectedViewerAsset.asset.platformName ?? '';
  const displaySymbol = selectedViewerAsset.asset.displaySymbol ?? '';

  const {
    cancelQuote,
    clearQuote,
    fetchQuote,
    debouncedFetchQuote,
    isLoaded,
    isFetching,
    fiatAmount,
    cryptoAmount,
  } = useTransferQuoter({
    accountRef: account,
    viewerAssetRef: selectedViewerAsset,
    queryRef: query,
    hasPreviewRefreshExperiment,
    hasSimpleTradeSellMigrationExperiment,
    accountUuid: account.uuid,
    assetPlatformName: platformName,
  });

  const { submitQuote: submitQuoteV1, isSubmitting: isSubmittingV1 } =
    useTransferQuoteSubmitter({
      accountRef: account,
      viewerAssetRef: selectedViewerAsset,
    });

  const { submitQuote: submitQuoteV2, isSubmitting: isSubmittingV2 } =
    useFetchBuySellQuotes({
      accountUuid: account.uuid,
      viewerAssetRef: selectedViewerAsset,
    });

  const submitQuote = useMemo(() => {
    if (
      (hasPreviewRefreshExperiment || hasBuyMigrationExperiment) &&
      transferType.value === 'buy'
    ) {
      return submitQuoteV2;
    } else if (
      (hasPreviewRefreshExperiment || hasSimpleTradeSellMigrationExperiment) &&
      transferType.value === 'sell'
    ) {
      return submitQuoteV2;
    } else {
      return submitQuoteV1;
    }
  }, [
    hasPreviewRefreshExperiment,
    hasSimpleTradeSellMigrationExperiment,
    hasBuyMigrationExperiment,
    submitQuoteV1,
    submitQuoteV2,
    transferType.value,
  ]);

  const isSubmitting = useMemo(
    () =>
      hasPreviewRefreshExperiment ||
      (hasSimpleTradeSellMigrationExperiment && transferType.value === 'sell')
        ? isSubmittingV2
        : isSubmittingV1,
    [
      hasPreviewRefreshExperiment,
      hasSimpleTradeSellMigrationExperiment,
      isSubmittingV1,
      isSubmittingV2,
      transferType.value,
    ],
  );

  const switchActiveInput = useEntryInputSwitcher({
    form,
    quoteFiatAmount: fiatAmount as string,
    quoteCryptoAmount: cryptoAmount,
  });

  //TEMP: This is a temporary fix to support the deprecated form during web refresh experiment
  const switchActiveInputDeprecated = useEntryInputSwitcher({
    form: deprecatedBuySellForm,
    quoteFiatAmount: fiatAmount as string,
    quoteCryptoAmount: cryptoAmount,
  });

  useEffect(() => {
    // If we were coming from the USDC entry step proxy and isFiatInput was false there we also want
    // to align the experience here when we update the payment method or source target to fiat like cash.
    if (isFiatInputValue !== undefined) {
      isFiatInput.onChange(isFiatInputValue);
    }

    if (isBuyTrade && recurringOption) {
      recurringPeriod.onChange(recurringOption);

      // if recurring option is set, turn off buy and stake
      if (recurringOption !== 'never') {
        shouldBuyAndStake.onChange(false);
      }
    }
  }, []);

  // Update amount value if USDC Entry Step input was dirtied so that fetchQuote gets the latest amount
  useEffect(() => {
    let updateAmountInput = amount.value;

    if (!isFiatInput.value && cryptoInput) {
      updateAmountInput = cryptoInput;
    } else if (isFiatInput.value && fiatInput) {
      updateAmountInput = fiatInput;
    }
    amount.onChange(updateAmountInput);
  }, [isFiatInput.value]);

  useEffect(() => {
    if (blockSell) {
      amount.onErrors([{ message: messages.sellEmptyError }]);
      trackEvent('viewed_validation_error', {
        error: `You don't have any ${selectedViewerAsset.asset.name} to sell. Try buying some to get started.`,
      });
      return;
    }

    if (!parseFloat(amount.value)) {
      return;
    }

    fetchQuote();
  }, [amount.value, blockSell]);

  useEffectOnUpdate(() => {
    if (amount.errors[0] && !blockSell) {
      trackEvent('viewed_error', {
        error: amount.errors[0].message,
      });
    }
  }, [amount.errors]);

  const toggleInput = useCallback(() => {
    trackEvent('tapped_switch');
    if (hasWebRefreshTreatment) {
      switchActiveInput();
    } else {
      switchActiveInputDeprecated();
    }
  }, [
    switchActiveInput,
    trackEvent,
    hasWebRefreshTreatment,
    switchActiveInputDeprecated,
  ]);

  const handleChange = useCallback(
    (value: string) => {
      // limit input to a max amount of integers depending on input type
      if (
        (Number(value) ?? 0) >
        getMaxInputNumber(isFiatInput.value ? 'fiat' : 'crypto', fiatCode)
      ) {
        return;
      }
      amount.onChange(value);

      if (isFiatInput.value) {
        setInputAmount?.(value);
      }

      if (!parseFloat(value)) {
        cancelQuote();
        clearQuote();
        return;
      }

      debouncedFetchQuote(value);
      // TODO we should consider removing this it doesn't really make sense
      // to track this event every time we update the input value
      trackEvent('viewed_updated_amount');
    },
    [
      fiatCode,
      amount,
      isFiatInput.value,
      debouncedFetchQuote,
      trackEvent,
      setInputAmount,
      cancelQuote,
      clearQuote,
    ],
  );

  const handlePresetAmount = useCallback(
    (total: string) => {
      cancelQuote();
      amount.onChange(total);
      setInputAmount?.(total);
      submitQuote({ total });
    },
    [cancelQuote, amount, submitQuote, setInputAmount],
  );

  const sendTriggerEvent = useTradeDropOffNotificationTrigger();

  const handleGoToPreview = useCallback(() => {
    if (isBuyTrade) {
      markStepOnce('trigger_buy_order_preview_button');
    } else {
      markStepOnce('trigger_sell_order_preview_button');
    }

    cancelQuote();
    trackEvent('tapped_preview');
    sendTriggerEvent(
      'CLICK_BUY_BUTTON_PREVIEW_BUY_BUTTON_WEB',
      transferType.value,
      {
        uuid: selectedViewerAsset.asset.uuid,
        symbol: selectedViewerAsset.asset.platformName,
      },
    );

    if (!parseFloat(amount.value)) {
      return amount.onErrors([
        { message: formatMessage(invalidInputMessage.invalidInputWarning) },
      ]);
    }
    submitQuote({ [amountKey]: amount.value });
  }, [
    isBuyTrade,
    cancelQuote,
    trackEvent,
    sendTriggerEvent,
    transferType.value,
    selectedViewerAsset.asset.uuid,
    selectedViewerAsset.asset.platformName,
    amount,
    submitQuote,
    amountKey,
    formatMessage,
  ]);

  const handleGoToDeposit = useCallback(() => {
    trackEvent('tapped_deposit_insufficient_balance_buy');
    trackTransferEntryPoint({
      transferType: 'deposit',
      entryPoint: transferType.value,
    });
    showModal(
      <LazyDepositModal
        accountId={activePaymentMethod.fiatAccount?.id || ''}
        allowRedirect={false}
        // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
        onSuccess={() => fetchQuote()}
        // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
        close={() => fetchQuote()}
        entryPoint={transferType.value}
      />,
    );
  }, [
    activePaymentMethod,
    showModal,
    trackEvent,
    fetchQuote,
    transferType.value,
  ]);

  const handleBuySellMax = useCallback(() => {
    // in a buy flow, max will set to the limit of the active item
    if (transferType.value === 'buy') {
      trackEvent('tapped_buy_max');
      return handlePresetAmount(String(fiatLimit));
    }

    trackEvent('tapped_sell_all');
    const max = getLimitForTransferType({
      paymentMethod: activePaymentMethod,
      transferType: 'sell',
    });

    function updateValueToMax(value?: string) {
      if (value) {
        if (isFiatInput.value) {
          toggleInput();
        }
        amount.onChange(value);
        setInputAmount?.(value);
      }
    }

    if (!max) {
      updateValueToMax(assetBalance.amount);
      submitQuote({
        amount: assetBalance.amount,
        currency: assetBalance.currency,
      });
    } else {
      // compare crypto balance in fiat with payment method limit and sell min of those
      const sourceCurrency = {
        currency: selectedViewerAsset.asset.platformName || '',
        amount: account?.availableBalance.value ?? '0',
      };
      const fiatBalanceInPaymentMethod = convert(sourceCurrency, fiatCode);

      const maxAllowed = min(
        compact([max, fiatBalanceInPaymentMethod]),
      )?.toString();
      updateValueToMax(maxAllowed);
      submitQuote({ amount: maxAllowed, currency: fiatCode });
    }
  }, [
    account?.availableBalance.value,
    activePaymentMethod,
    amount,
    assetBalance.amount,
    assetBalance.currency,
    convert,
    fiatCode,
    fiatLimit,
    getLimitForTransferType,
    handlePresetAmount,
    isFiatInput.value,
    selectedViewerAsset.asset.platformName,
    setInputAmount,
    submitQuote,
    toggleInput,
    trackEvent,
    transferType.value,
  ]);

  const getInactiveSymbol = useMemo(() => {
    if (isFiatInput.value) {
      return displaySymbol;
    } else {
      return fiatCode;
    }
  }, [fiatCode, displaySymbol, isFiatInput.value]);

  const getInactiveAmount = useMemo(() => {
    if (!parseFloat(amount.value)) {
      return '';
    }
    if (isFiatInput.value) {
      return cryptoAmount;
    } else {
      return fiatAmount as string;
    }
  }, [amount.value, cryptoAmount, fiatAmount, isFiatInput.value]);

  const buttonFaded =
    activePaymentMethod.rejected ||
    activePaymentMethod.disableBuyReason === 'wbl';

  const alertViewType = isBuyTrade ? 'BUY' : 'SELL';

  const isStableAssetTransaction =
    variant === 'cashIn' || variant === 'cashOut' || variant === 'cashTransfer';

  const headerProps = useMemo(() => {
    if (isMobileModal) {
      return { goBack: backButton };
    }
    // inside the modal, handle the stable assets header as info modal not back
    else if (isModal && isStableAssetTransaction) {
      return {
        title: entryStepModalHeaderTitle,
        hasDefaultCloseModal: true,
        borderBottom: true,
      };
    }
    return null;
  }, [
    isStableAssetTransaction,
    backButton,
    entryStepModalHeaderTitle,
    isMobileModal,
    isModal,
  ]);

  const tabs = useMemo(() => renderTabs?.() ?? null, [renderTabs]);

  const isTransferCash = variant === 'cashTransfer';

  // transfer cash "buy" show the payment on top
  const isTransferCashTypeBuy = isTransferCash && transferType.value === 'buy';
  const row1AssetOrPayment = isTransferCashTypeBuy
    ? paymentSelector
    : assetSelector;
  const row2AssetOrPayment = isTransferCashTypeBuy
    ? assetSelector
    : paymentSelector;
  // disable flag if the limit is 0 or not set for cash transfer buy type ( can't buy )
  const blockTransferCashBuy = isTransferCashTypeBuy && !fiatLimit;
  if (blockTransferCashBuy && activePaymentMethod?.currency) {
    entryInputError = formatMessage(entryMessages.transferCashEmptyError, {
      name: activePaymentMethod.currency,
    });
  }

  // this is turned off for transfer cash flows (toggles between asset and usd)
  const switchActiveInputConfig = useMemo(() => {
    if (!isTransferCash) {
      return {
        onPress: toggleInput,
        inactiveSymbol: getInactiveSymbol || '',
        inactiveAmount: getInactiveAmount || '',
        disabled: isSubmitting || !!amount.errors[0],
      };
    }
  }, [
    amount.errors,
    getInactiveAmount,
    getInactiveSymbol,
    isSubmitting,
    isTransferCash,
    toggleInput,
  ]);

  // transfer cash supports inline switcher
  const handleClickSwitcher = useMemo(() => {
    if (isTransferCash && onEntrySelectorSwitch) {
      return () => {
        const nextTypeValue = transferType.value === 'buy' ? 'sell' : 'buy';
        return onEntrySelectorSwitch(nextTypeValue);
      };
    }
  }, [isTransferCash, onEntrySelectorSwitch, transferType.value]);

  const sourceRowProps = useMemo(() => {
    return {
      ...row1AssetOrPayment,
      ...(assetSelectorLabelOverride && {
        primaryLabel: assetSelectorLabelOverride,
      }),
      disabled: isSubmitting || disableAssetSelectors,
      disableSelection:
        (!isSubmitting && isStableAssetTransaction && !showCashDepositInput) ||
        disableSourceAssetSelection,
      hideCaret:
        disableAssetSelectors ||
        (isStableAssetTransaction && !showCashDepositInput) ||
        disableSourceAssetSelection,
    };
  }, [
    assetSelectorLabelOverride,
    disableAssetSelectors,
    disableSourceAssetSelection,
    showCashDepositInput,
    isStableAssetTransaction,
    isSubmitting,
    row1AssetOrPayment,
  ]);

  const targetRowProps = useMemo(() => {
    return {
      ...row2AssetOrPayment,
      disabled: isSubmitting || disableAssetSelectors,
      disableSelection: !isSubmitting && isTransferCash,
      hideCaret: disableAssetSelectors || isTransferCash,
    };
  }, [disableAssetSelectors, isSubmitting, isTransferCash, row2AssetOrPayment]);

  const ariaAssetInputLabel = useMemo(() => {
    return formatMessage(accessibilityMessages.accessibilityLabel, {
      asset: selectedViewerAsset.asset.name,
    });
  }, [formatMessage, selectedViewerAsset.asset.name]);

  const transferBuy = transferType.value === 'buy';
  const hasLimitOrderExperiment = useIsSimpleTradeLimitOrderExp(false);
  const isStablecoin = selectedViewerAsset.asset.isStablecoin;
  const { isInUS } = useUser();
  const shouldMoveOrderTypeSelectorToCorner =
    (hasLimitOrderExperiment || (!isInUS && transferBuy)) && !isStablecoin;
  const showTooltip = hasLimitOrderExperiment && !isStablecoin;

  const handleSkipToPreview = useCallback(
    (value: string) => {
      submitQuote({
        amount: value,
        currency: assetBalance.currency,
      });
    },
    [assetBalance.currency, submitQuote],
  );

  const handleSetInputValueOnMaxPress = useCallback(
    (value?: string) => {
      if (value) {
        amount.onChange(value);
        setInputAmount?.(value);
        if (transferType.value === 'sell') {
          handleSkipToPreview(value);
        }
      }
    },
    [amount, setInputAmount, transferType.value, handleSkipToPreview],
  );

  const handleSwapCurrency = useCallback(
    (isFiat: boolean) => {
      isFiatInput.onChange(isFiat);
      setIsFiatInput?.(isFiat);
    },
    [isFiatInput, setIsFiatInput],
  );

  const fixedAmounts = useMemo(
    () => (
      <SimpleTradeFixedAmounts
        queryRef={query}
        accountRef={account}
        setInputValue={handleSetInputValueOnMaxPress}
        setInputCurrency={handleSwapCurrency}
        tradeTypeUI={transferType.value}
        // disable preset / max btns when fetching quote to avoid incidental clicks as quote is resolving
        disabled={
          isFetching || isSubmitting || (!isFiatInput.value && transferBuy)
        }
        target={{ paymentMethod: activePaymentMethod }}
        targetAssetRef={selectedViewerAsset.asset}
        triggerSubmit={noop}
      />
    ),
    [
      query,
      account,
      handleSetInputValueOnMaxPress,
      handleSwapCurrency,
      transferType.value,
      isFetching,
      isSubmitting,
      isFiatInput.value,
      transferBuy,
      activePaymentMethod,
      selectedViewerAsset.asset,
    ],
  );

  const secondaryButton = useMemo(() => {
    if (hasWebRefreshTreatment) {
      return fixedAmounts;
    }
    return shouldMoveOrderTypeSelectorToCorner &&
      transferBuy &&
      variant !== 'cashTransfer' ? null : (
      <BuySellInputSecondaryButton
        onPressMax={handleBuySellMax}
        disabled={
          isSubmitting ||
          !!amount.errors[0] ||
          isDisabled ||
          blockTransferCashBuy
        }
      />
    );
  }, [
    amount.errors,
    blockTransferCashBuy,
    fixedAmounts,
    handleBuySellMax,
    hasWebRefreshTreatment,
    isDisabled,
    isSubmitting,
    shouldMoveOrderTypeSelectorToCorner,
    transferBuy,
    variant,
  ]);

  const input = useMemo(() => {
    return (
      <InstrumentedSuspense instrumentationId="EntryInput" fallback={null}>
        <EntryInput
          isNewDesign={hasWebRefreshTreatment}
          autoFocus={!disableAutoFocus}
          error={entryInputError}
          input={{
            symbol: isFiatInput.value ? fiatCode : platformName,
            displaySymbol: isFiatInput.value ? undefined : displaySymbol,
            value: amount.value,
            // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
            onChange: handleChange,
            onEnter: handleGoToPreview,
            readOnly:
              blockSell || isSubmitting || isDisabled || blockTransferCashBuy,
          }}
          helperText={
            <TradeInputHelper
              transferType={transferType.value}
              amount={amount.value}
              fiatCode={fiatCode}
              fiatLimit={fiatLimit}
              variant={variant}
            />
          }
          secondaryButton={secondaryButton}
          switchActiveInput={switchActiveInputConfig}
          transferType={transferType.value}
          isCryptoCurrency={!isFiatInput.value}
          viewerAssetRef={selectedViewerAsset}
          ariaLabel={ariaAssetInputLabel}
        />
      </InstrumentedSuspense>
    );
  }, [
    amount.value,
    disableAutoFocus,
    ariaAssetInputLabel,
    blockSell,
    blockTransferCashBuy,
    displaySymbol,
    entryInputError,
    fiatCode,
    fiatLimit,
    handleChange,
    handleGoToPreview,
    hasWebRefreshTreatment,
    isDisabled,
    isFiatInput.value,
    isSubmitting,
    platformName,
    secondaryButton,
    selectedViewerAsset,
    switchActiveInputConfig,
    transferType.value,
    variant,
  ]);

  const previewButton = useMemo(() => {
    const disabled =
      !!amount.errors[0] ||
      isSubmitting ||
      isDisabled ||
      amount.value === '' ||
      amount.value === '0';
    if (hasWebRefreshTreatment) {
      return (
        <InputSubmitButton
          block
          loading={isSubmitting}
          disabled={disabled}
          handleSubmit={handleGoToPreview}
          testID={`${transferType.value}-preview-button`}
          data-testid={`${transferType.value}-preview-button`}
          aria-label={formatMessage(accessibilityMessages.previewButtonLabel, {
            type: transferType.value,
          })}
          label={buttonText}
          endIcon="forwardArrow"
        />
      );
    }
    return (
      <Button
        block
        disabled={disabled}
        loading={isSubmitting}
        onPress={handleGoToPreview}
        testID={`${transferType.value}-preview-button`}
        data-testid={`${transferType.value}-preview-button`}
        aria-label={formatMessage(accessibilityMessages.previewButtonLabel, {
          type: transferType.value,
        })}
      >
        {buttonText}
      </Button>
    );
  }, [
    amount.errors,
    amount.value,
    buttonText,
    formatMessage,
    handleGoToPreview,
    hasWebRefreshTreatment,
    isDisabled,
    isSubmitting,
    transferType.value,
  ]);

  const orderTypeSelectorButton = useMemo(() => {
    return (
      <BuySellInputSecondaryButton
        showOrderTypeSelector={hasLimitOrderExperiment}
        disabled={
          isSubmitting ||
          !!amount.errors[0] ||
          isDisabled ||
          blockTransferCashBuy
        }
      />
    );
  }, [
    amount.errors,
    blockTransferCashBuy,
    hasLimitOrderExperiment,
    isDisabled,
    isSubmitting,
  ]);

  const entryStepHeader = useMemo(() => {
    // if we are in the web refresh experiment, we don't want to show the header
    if (hasWebRefreshTreatment) {
      return null;
    }
    return (
      <>
        {tabs}
        {headerProps && <Header {...headerProps} />}
        {showTooltip && <LimitOrderCalloutTooltip />}
      </>
    );
  }, [hasWebRefreshTreatment, headerProps, showTooltip, tabs]);

  const entryStep = useMemo(() => {
    return (
      <>
        <SystemAlert
          view={alertViewType}
          currencies={[selectedViewerAsset.asset.platformName ?? '']}
        />
        {entryStepHeader}
        <PaddedContent
          paddingTopDesktop={!hasWebRefreshTreatment ? PADDING_TOP_INPUT : 0}
          paddingTopMobile={!hasWebRefreshTreatment ? PADDING_TOP_INPUT : 0}
        >
          {shouldMoveOrderTypeSelectorToCorner && !hasWebRefreshTreatment ? (
            <Box alignSelf="flex-end" spacingBottom={1}>
              {orderTypeSelectorButton}
            </Box>
          ) : (
            !hasWebRefreshTreatment && <Spacer vertical={6} />
          )}

          {isBuyTrade ? (
            <InstrumentedSuspense
              instrumentationId="RewardApyLabel"
              fallback={null}
            >
              <RewardApyLabel
                viewerAssetRef={selectedViewerAsset}
                queryRef={query}
                hasWebRefreshTreatment={hasWebRefreshTreatment}
                fiatAmount={{
                  amount: fiatInput ?? '0',
                  currency: fiatCode,
                }}
              />
            </InstrumentedSuspense>
          ) : (
            !hasWebRefreshTreatment && <Spacer vertical={4} />
          )}
          {input}
          {showPresetAmounts &&
          !!buyPresetAmounts &&
          !hasWebRefreshTreatment ? (
            <PresetAmountsPanel
              amounts={buyPresetAmounts}
              onPressAmount={handlePresetAmount}
              disabled={isSubmitting || !isFiatInput.value || isDisabled}
              testID="preset-amounts-panel"
            />
          ) : null}

          <VStack>
            <BuySellEntrySelector
              row1={sourceRowProps}
              row2={targetRowProps}
              onClickSwitcher={handleClickSwitcher}
              transferType={transferType.value}
              selectedViewerAssetDisplaySymbol={
                selectedViewerAsset.asset.displaySymbol ?? ''
              }
              activePaymentMethodFiatCode={fiatCode}
              assetBalanceInFiat={assetBalanceInFiat}
              activePaymentConciseDescription={conciseDescription}
              activePaymentMethodType={activePaymentMethod.type}
              fiatLimit={fiatLimit}
              variant={variant}
              isNewDesign={hasWebRefreshTreatment}
              assetRef={selectedViewerAsset.asset}
            />
            <Box
              opacity={buttonFaded ? 0.5 : 1}
              testID={
                isFetching || isSubmitting
                  ? `${transferType.value}-quote-loading`
                  : isLoaded
                  ? `${transferType.value}-quote-loaded`
                  : ''
              }
            >
              {shouldShowDepositButton ? (
                <Button
                  block
                  onPress={handleGoToDeposit}
                  testID={`${transferType.value}-deposit-button`}
                  data-testid={`${transferType.value}-deposit-button`}
                  aria-label={formatMessage(
                    accessibilityMessages.depositButtonLabel,
                    { currency: activePaymentMethod.currency },
                  )}
                >
                  {formatMessage(accessibilityMessages.depositButtonLabel, {
                    currency: activePaymentMethod.currency,
                  })}
                </Button>
              ) : (
                previewButton
              )}
            </Box>
            {query?.viewer?.isOnboardedPortfolio && (
              <MultiPortfolioDisclaimerV2
                transferType={
                  transferType.value === 'buy' ? 'deposit' : 'withdraw'
                }
                spacingTop={3}
              />
            )}
          </VStack>
        </PaddedContent>

        {isTransferCashTypeBuy ? (
          <BuySellFooterPaymentDetails
            amount={formatNumber(fiatLimit || 0, {
              style: 'currency',
              currency: fiatCode,
            })}
            currency={activePaymentMethod.currency}
          />
        ) : (
          <Spacer vertical={2} />
        )}
        {hasWebRefreshTreatment && <Spacer vertical={2} />}
      </>
    );
  }, [
    alertViewType,
    selectedViewerAsset,
    entryStepHeader,
    hasWebRefreshTreatment,
    shouldMoveOrderTypeSelectorToCorner,
    orderTypeSelectorButton,
    isBuyTrade,
    query,
    fiatInput,
    fiatCode,
    input,
    showPresetAmounts,
    buyPresetAmounts,
    handlePresetAmount,
    isSubmitting,
    isFiatInput.value,
    isDisabled,
    sourceRowProps,
    targetRowProps,
    handleClickSwitcher,
    transferType.value,
    assetBalanceInFiat,
    conciseDescription,
    activePaymentMethod.type,
    activePaymentMethod.currency,
    fiatLimit,
    variant,
    buttonFaded,
    isFetching,
    isLoaded,
    shouldShowDepositButton,
    handleGoToDeposit,
    formatMessage,
    previewButton,
    isTransferCashTypeBuy,
    formatNumber,
  ]);

  return entryStep;
}

export default memo(EntryStep);

import { memo, useCallback, useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';

import { FlexibleCurrencyInput } from '@cb/shared/components/FlexibleCurrencyInput/FlexibleCurrencyInput';
import getSymbolForCurrency from '@cb/shared/utils/getSymbolForCurrency';
import getLocaleConfig from '@cb/shared/utils/locale/getLocaleConfig';
import { TradeFiatAction } from '@cb/types';
import { VStack } from '@cbhq/cds-web/layout/VStack';
import { palette } from '@cbhq/cds-web/tokens';
import { graphql, useFragment } from '@cbhq/data-layer';

import { InputProps } from 'components/BuySellComponents/EntryInput/EntryInput';
import useLocalizedEntryInput from 'components/BuySellComponents/EntryInput/hooks/useLocalizedEntryInput';
import useNewLocalizedCurrencyInput from 'components/BuySellComponents/EntryInput/hooks/useNewLocalizedCurrencyInput';
import formatDisplayValue from 'components/BuySellComponents/EntryInput/utils/formatDisplayValue';

import { useConvertIncrementToPrecision } from '../hooks/useConvertIncrementToPrecision';
import { countDecimals } from '../utils';
import { LimitOrderAmountInputFragment$key } from './__generated__/LimitOrderAmountInputFragment.graphql';
import { LimitOrderAmountInputViewerAssetFragment$key } from './__generated__/LimitOrderAmountInputViewerAssetFragment.graphql';
import LimitOrderInputFieldSubline from './LimitOrderInputFieldSubline';
import LimitOrderInputFieldSwapButton from './LimitOrderInputFieldSwapButton';
import LimitOrderSuggestionSection, {
  getSuggestionVariant,
} from './LimitOrderSuggestionSection';

const i18nKey = 'LimitOrderAmountInput';

const messages = defineMessages({
  amount: {
    id: `${i18nKey}.amount`,
    defaultMessage: 'Amount',
    description: `#Component: FlexibleCurrencyInput:ariaLabel
    #CharLimit: 40
    #Context: Label for the value in the amount input`,
  },
  targetPrice: {
    id: `${i18nKey}.targetPrice`,
    defaultMessage: 'Target price',
    description: `#Component: FlexibleCurrencyInput:ariaLabel
    #CharLimit: 45
    #Context: Label for the value in the target price input`,
