export type LimitOrderInputFieldType = 'amount' | 'target_price';

export type LimitOrderAmountInputProps = Omit<
  InputProps,
  'onChange' | 'onFocus' | 'value'
> & {
  fiatAmount: string;
  cryptoAmount: string;
  targetPriceValue: string;
  type: LimitOrderInputFieldType;
  isFocused?: boolean;
  onFocus?: (type: LimitOrderInputFieldType) => void;
  onChange: (value: string, type: LimitOrderInputFieldType) => void;
  autoFocus?: boolean;
  isFiatInput: boolean;
  onSwapButtonPress?: () => void;
  transferType: TradeFiatAction;
  queryRef: LimitOrderAmountInputFragment$key;
  viewerAssetRef: LimitOrderAmountInputViewerAssetFragment$key;
};

function LimitOrderAmountInput({
  symbol,
  displaySymbol,
  fiatAmount,
  cryptoAmount,
  onBlur,
  onChange,
  noCommas,
  type = 'amount',
  isFocused,
  onFocus,
  autoFocus = false,
  targetPriceValue = '',
  isFiatInput,
  transferType,
  onSwapButtonPress,
  queryRef,
  viewerAssetRef,
}: LimitOrderAmountInputProps) {
  const query = useFragment(
    graphql`
      fragment LimitOrderAmountInputFragment on Query {
        ...LimitOrderSuggestionSectionFragment
      }
    `,
    queryRef,
  );

  const selectedViewerAsset = useFragment(
    graphql`
      fragment LimitOrderAmountInputViewerAssetFragment on ViewerAsset {
        ...useConvertIncrementToPrecisionFragment
        ...LimitOrderSuggestionSectionViewerAssetFragment
        ...LimitOrderInputFieldSublineViewerAssetFragment
      }
    `,
    viewerAssetRef,
  );

  const { formatNumber, locale, formatMessage } = useIntl();
  const { decimalSeparator, groupSeparator } = useMemo(
    () => getLocaleConfig({ locale }),
    [locale],
  );
  const { fiatPrecision, cryptoPrecision } =
    useConvertIncrementToPrecision(selectedViewerAsset);

  const canUseNewLocalizedCurrencyInput = useNewLocalizedCurrencyInput();
  const newLocalizedCurrencyInput =
    isFiatInput && canUseNewLocalizedCurrencyInput;
  const inputAmount = isFiatInput ? fiatAmount : cryptoAmount;
  const precision = isFiatInput ? fiatPrecision : cryptoPrecision;

  const handleOnChange = useCallback(
    (value: string | undefined) => {
      onChange(value ?? '', type);
    },
    [onChange, type],
  );

  const activeValue = useMemo(
    () => (type === 'amount' ? inputAmount : targetPriceValue),
    [targetPriceValue, type, inputAmount],
  );

  const inputPrecision = type === 'target_price' ? fiatPrecision : precision;

  const formattedActiveValue = useMemo(() => {
    const value = type === 'amount' ? inputAmount : targetPriceValue;
    return countDecimals(Number(value)) > inputPrecision
      ? formatNumber(Number(value), {
          maximumFractionDigits: inputPrecision,
        })
      : value;
  }, [type, inputAmount, targetPriceValue, inputPrecision, formatNumber]);

  const activeCurrency = useMemo(() => {
    if (type === 'amount') {
      return isFiatInput ? symbol : displaySymbol ?? '';
    }
    return symbol;
  }, [displaySymbol, isFiatInput, symbol, type]);

  const {
    displayLocalizedValue,
    handleLocalizedChange,
    handleLocalizedBlur,
    updateInputCursorPosition,
    clearFormattedValue,
  } = useLocalizedEntryInput({
    value: activeValue,
    decimalSeparator,
    fiatPrecision,
    onBlur,
    onChange: handleOnChange,
    newLocalizedCurrencyInput,
  });

  const defaultDisplayValue = !noCommas
    ? formatDisplayValue(formattedActiveValue, decimalSeparator, groupSeparator)
    : formattedActiveValue;

  const {
    displayValue,
    handleChange,
    handleBlur,
    handleUpdateInputCallback,
    handleClearFormattedValue,
  } = useMemo(
    () =>
      newLocalizedCurrencyInput
        ? {
            displayValue: displayLocalizedValue,
            handleChange: handleLocalizedChange,
            handleBlur: handleLocalizedBlur,
            handleUpdateInputCallback: updateInputCursorPosition,
            handleClearFormattedValue: clearFormattedValue,
          }
        : {
            displayValue: defaultDisplayValue,
            handleChange: handleOnChange,
            handleBlur: onBlur,
          },
    [
      newLocalizedCurrencyInput,
      displayLocalizedValue,
      defaultDisplayValue,
      handleLocalizedChange,
      handleOnChange,
      handleLocalizedBlur,
      onBlur,
      updateInputCursorPosition,
      clearFormattedValue,
    ],
  );

  const handleOnFocus = useCallback(() => {
    onFocus?.(type);
  }, [onFocus, type]);

  const suggestionVariant = useMemo(
    () => getSuggestionVariant(transferType, false),
    [transferType],
  );

  const subline = useMemo(() => {
    if (type === 'target_price') {
      return (
        <VStack visibility={isFocused ? 'visible' : 'hidden'} spacerGap={2}>
          <LimitOrderInputFieldSubline
            viewerAssetRef={selectedViewerAsset}
            targetPrice={targetPriceValue}
          />
          <LimitOrderSuggestionSection
            variant={suggestionVariant}
            queryRef={query}
            viewerAssetRef={selectedViewerAsset}
            compact
          />
        </VStack>
      );
    } else {
      const amount =
        Number(targetPriceValue) !== 0
          ? isFiatInput
            ? cryptoAmount
            : fiatAmount
          : undefined;
      return (
        <LimitOrderInputFieldSwapButton
          code={isFiatInput ? displaySymbol ?? '' : symbol}
          amount={amount}
          onPress={onSwapButtonPress}
          isVisibile={isFocused}
          precision={isFiatInput ? cryptoPrecision : fiatPrecision}
        />
      );
    }
  }, [
    cryptoAmount,
    cryptoPrecision,
    displaySymbol,
    fiatAmount,
    fiatPrecision,
    isFiatInput,
    isFocused,
    onSwapButtonPress,
    query,
    selectedViewerAsset,
    suggestionVariant,
    symbol,
    targetPriceValue,
    type,
  ]);

  const input = useMemo(() => {
    return (
      <FlexibleCurrencyInput
        {...getSymbolForCurrency({
          formatNumber,
          currency: activeCurrency,
          isNewDesign: true,
          isCrypto: !isFiatInput,
        })}
        placeholder="0"
        value={displayValue}
        onChange={handleChange}
        onBlur={handleBlur}
        updateInputCallback={handleUpdateInputCallback}
        clearFormattedValue={handleClearFormattedValue}
        onFocus={handleOnFocus}
        align="flex-start"
        color={palette.foreground}
        transparentBackground
        symbolColor={palette.foregroundMuted}
        autoFocus={autoFocus}
        maxWidth={330}
        precision={inputPrecision}
        ariaLabel={
          type === 'amount'
            ? formatMessage(messages.amount)
            : formatMessage(messages.targetPrice)
        }
      />
    );
  }, [
    activeCurrency,
    autoFocus,
    displayValue,
    formatMessage,
    formatNumber,
    handleBlur,
    handleChange,
    handleClearFormattedValue,
    handleOnFocus,
    handleUpdateInputCallback,
    inputPrecision,
    isFiatInput,
    type,
  ]);

  return (
    <VStack spacerGap={0.5}>
      {input}
      {subline}
    </VStack>
  );
}

export default memo(LimitOrderAmountInput);

