const LimitOrderInputErrorSectionContent =
  memo<LimitOrderInputErrorSectionProps>(function LimitOrderInputErrorSection({
    action,
    viewerAssetRef,
  }: LimitOrderInputErrorSectionProps) {
    const selectedViewerAsset = useFragment(
      graphql`
        fragment LimitOrderInputErrorSectionViewerAssetFragment on ViewerAsset {
          asset {
            platformName
          }
          ...useLatestPrice
          ...useHandleInputFieldChangeViewerAssetFragment
          ...useBaseSizesViewerAssetFragment
          ...useAvailableBalanceForAssetViewerAssetFragment
        }
      `,
      viewerAssetRef,
    );

    const platformName = selectedViewerAsset.asset.platformName ?? '';
    const { isFiatInput, targetPrice } = useSimpleTradeForm();
    const { availableBalanceInFiat, availableBalanceInCrypto } =
      useAvailableBalanceForAsset(selectedViewerAsset);
    const { handleInputAmountChange, handleTargetAmountChange } =
      useHandleInputFieldChange(selectedViewerAsset);
    const { maxSize, minSize } = useBaseSizes(selectedViewerAsset);
    const currentCryptoPrice = useLatestPrice(selectedViewerAsset);
    const { trackEvent } = useBuySellEventTracker();

    useEffect(() => {
      if (action === ErrorSuggestionAction.minimumBuyPercentage) {
        trackEvent('limit_price_error', {
          action: ActionType.view,
          componentType: ComponentType.banner,
          amount: targetPrice.value,
        });
      }
    }, []);
    const handleApplySuggestion = useCallback(() => {
      switch (action) {
        case ErrorSuggestionAction.minAmountValue: {
          /*
           * In limit orders we always use the target price as reference to
           * converting from and to Fiat since that's our target, unless when it
           * has not yet been set.
           * */
          handleInputAmountChange('5.01', true);
          isFiatInput.onChange(true);
          break;
        }
        case ErrorSuggestionAction.maxSellValue:
          handleInputAmountChange(
            isFiatInput.value
              ? availableBalanceInFiat
              : availableBalanceInCrypto,
          );
          isFiatInput.onChange(false);
          break;
        case ErrorSuggestionAction.minimumBuyPercentage: {
          trackEvent('tapped_limit_price_error', {
            action: ActionType.click,
            componentType: ComponentType.button,
          });
          handleTargetAmountChange(
            String(Number(currentCryptoPrice) * MinimumPercentThreshold.minus),
          );
          break;
        }
        case ErrorSuggestionAction.minimumSellPercentage: {
          trackEvent('tapped_limit_price_error', {
            action: ActionType.click,
            componentType: ComponentType.button,
          });
          handleTargetAmountChange(
            String(Number(currentCryptoPrice) * MinimumPercentThreshold.plus),
          );
          break;
        }
        // These 3 cases do not have associated actions, so we do nothing
        case ErrorSuggestionAction.maxTradeValueApiLimit:
        case ErrorSuggestionAction.minTradeValueApiLimit:
        case ErrorSuggestionAction.needCryptoToSell:
          break;
        default:
          break;
      }
    }, [
      action,
      handleInputAmountChange,
      isFiatInput,
      availableBalanceInFiat,
      availableBalanceInCrypto,
      trackEvent,
      handleTargetAmountChange,
      currentCryptoPrice,
    ]);

    const { formatMessage, formatNumber } = useIntl();

    const formatCurrency = useCurrencyFormatter();
    const cryptoBalance = useMemo(() => {
      if (action === ErrorSuggestionAction.maxSellValue) {
        return `${formatCurrency({
          amount: {
            value: availableBalanceInCrypto,
            currency: platformName,
          },
          isFiat: false,
        })}`;
      }

      return '--';
    }, [action, availableBalanceInCrypto, formatCurrency, platformName]);

    const title = useMemo(
      () =>
        formatMessage(messages[`${action}Title`], {
          percentageThreshold: MinimumPercentThreshold.percent,
          cryptoBalance,
          platformName,
          baseMaxSize: formatNumber(Number(maxSize)),
          baseMinSize: formatNumber(Number(minSize), {
            maximumFractionDigits: minSize.length ?? 0,
          }),
        }),
      [
        formatMessage,
        action,
        cryptoBalance,
        platformName,
        formatNumber,
        maxSize,
        minSize,
      ],
    );

    // These cases do not have actions associated with them
    const hasAction =
      action !== ErrorSuggestionAction.maxTradeValueApiLimit &&
      action !== ErrorSuggestionAction.minTradeValueApiLimit &&
      action !== ErrorSuggestionAction.needCryptoToSell;

    const actionTitle = useMemo(() => {
      return hasAction
        ? formatMessage(messages[`${action}Action`], {
            percentageThreshold: MinimumPercentThreshold.percent,
            platformName,
          })
        : '';
    }, [action, formatMessage, hasAction, platformName]);

    return (
      <HStack
        spacingHorizontal={3}
        alignItems="center"
        minHeight="56px"
        width="100%"
      >
        <Box spacingVertical={1} flexGrow={1} flexBasis={0} spacingEnd={2}>
          <TextLabel2 as="p" spacing={0}>
            {title}
          </TextLabel2>
        </Box>
        <Pressable
          onPress={handleApplySuggestion}
          background="transparent"
          style={{ backgroundColor: 'transparent' }}
          accessibilityHint={actionTitle}
        >
          <TextHeadline as="p" color="primary" numberOfLines={1}>
            {actionTitle}
          </TextHeadline>
        </Pressable>
      </HStack>
    );
  });

function LimitOrderInputErrorSectionContentFallback() {
