type LimitOrderInputFieldsContentProps = Pick<
  InputProps,
  'symbol' | 'displaySymbol'
> & {
  queryRef: LimitOrderInputFieldsContentFragment$key;
  viewerAssetRef: LimitOrderInputFieldsContentViewerAssetFragment$key;
};

function LimitOrderInputFieldsContent(
  props: LimitOrderInputFieldsContentProps,
) {
  const query = useFragment<LimitOrderInputFieldsContentFragment$key>(
    graphql`
      fragment LimitOrderInputFieldsContentFragment on Query {
        ...LimitOrderAmountInputFragment
      }
    `,
    props.queryRef,
  );

  const selectedViewerAsset =
    useFragment<LimitOrderInputFieldsContentViewerAssetFragment$key>(
      graphql`
        fragment LimitOrderInputFieldsContentViewerAssetFragment on ViewerAsset {
          ...LimitOrderAmountInputViewerAssetFragment
          ...useHandleInputFieldChangeViewerAssetFragment
        }
      `,
      props.viewerAssetRef,
    );

  const {
    inputFiatAmount,
    inputCryptoAmount,
    targetPrice,
    isFiatInput,
    currentFocus,
    transferType,
  } = useSimpleTradeForm();
  const { formatMessage } = useIntl();
  const { trackEvent } = useBuySellEventTracker();

  const handleOnFocus = useCallback(
    (type: LimitOrderInputFieldType) => {
      if (type === 'target_price')
        trackEvent('tapped_limit_price', {
          action: ActionType.focus,
          componentType: ComponentType.text_input,
        });
      currentFocus.onChange(type);
    },
    [currentFocus, trackEvent],
  );

  const { handleInputAmountChange, handleTargetAmountChange } =
    useHandleInputFieldChange(selectedViewerAsset);

  const handleOnChange = useCallback(
    (value: string | undefined, type: LimitOrderInputFieldType) => {
      trackEvent('tapped_numpad', {
        action: ActionType.keyPress,
        componentType: ComponentType.text_input,
      });
      if (type === 'amount') {
        handleInputAmountChange(value ?? '');
      } else if (type === 'target_price') {
        handleTargetAmountChange(value ?? '');
      }
    },
    [handleInputAmountChange, handleTargetAmountChange, trackEvent],
  );

  const handleSwapCurrency = useCallback(() => {
    isFiatInput.onChange(!isFiatInput.value);
  }, [isFiatInput]);

  const commonProps = {
    ...props,
    onChange: handleOnChange,
    onFocus: handleOnFocus,
    targetPriceValue: targetPrice.value,
    isFiatInput: isFiatInput.value,
    fiatAmount: inputFiatAmount.value,
    cryptoAmount: inputCryptoAmount.value,
    transferType: transferType.value,
    queryRef: query,
    viewerAssetRef: selectedViewerAsset,
  };

  return (
    <VStack>
      <Box spacingBottom={0.5}>
        <TextBody as="p">{formatMessage(messages.amountInputTitle)}</TextBody>
      </Box>
      <LimitOrderAmountInput
        type="amount"
        isFocused={currentFocus.value === 'amount'}
        autoFocus
        onSwapButtonPress={handleSwapCurrency}
        {...commonProps}
      />
      <Spacer vertical={4} />
      <Box>
        <TextBody as="p">{formatMessage(messages.targetPriceTitle)}</TextBody>
      </Box>
      <LimitOrderAmountInput
        type="target_price"
        isFocused={currentFocus.value === 'target_price'}
        {...commonProps}
      />
    </VStack>
  );
}

