type EntryStepProps = Pick<SimpleTradeStepperProps, 'tradeActions'> & {
  queryRef: EntryStepQueryFragment$key;
  viewerAssetRefs: EntryStepViewerAssetFragment$key;
  setTradeTypeUI: (tradeType: TradeAction) => void;
  closeModal?: () => void;
  buySellProxy?: TradeFiatAction;
  shouldNotClearFormBuySellProxy?: boolean;
  entryPoint?: BuySellEntryPoint;
};

function EntryStep({
  queryRef,
  viewerAssetRefs,
  tradeActions,
  setTradeTypeUI,
  closeModal,
  buySellProxy,
  shouldNotClearFormBuySellProxy,
  entryPoint,
}: EntryStepProps) {
  const query = useFragment(
    graphql`
      fragment EntryStepQueryFragment on Query {
        ...BuySellEntryStepQueryFragment
        ...ConvertEntryStepQueryFragment
        ...BuySellProxyEntryStepQueryFragment
      }
    `,
    queryRef,
  );

  const entryStepViewAssetFragment = useFragment(
    graphql`
      fragment EntryStepViewerAssetFragment on ViewerAsset
      @relay(plural: true) {
        asset {
          uuid
          platformName
        }
        accounts {
          type
          primary
          ...EntryStepBuySellAccountFragment
        }
        ...BuySellEntryStepTradableAssetFragment
        ...ConvertEntryStepConvertibleAssetFragment
        ...BuySellProxyEntryStepConvertibleAssetFragment
      }
    `,
    viewerAssetRefs,
  );

  const { formatMessage } = useIntl();
  const isPhoneSmall = useScreenMatch('phone_small');
  const { transferType, eventContext, assetId, sourceAssetId, targetAssetId } =
    useFields(form);
  const { isCryptoOnlyTrader } = useUser();
  const isUsdcAdpWidget =
    entryPoint === 'stable-asset-buy' && eventContext.value === 'assetPage';

  const { initialAssetId } = useBuySellContext();
  const resetField = useFieldResetter(form);
  const hasLimitOrderExperiment = useIsSimpleTradeLimitOrderExp(false);
  const hasPreviewRefreshExperiment =
    useSimpleTradeWebPreviewRefreshExperiment();

  //TODO move all of this tab logic into its own dedicated component
  const newTabs = useMemo(() => {
    const buyTab = { transferType: 'buy' };
    const sellTab = { transferType: 'sell' };
    const swapTab = { transferType: 'convert' };

    return [buyTab, sellTab, swapTab];
  }, []);

  const clearForm = useCallback(() => {
    if (shouldNotClearFormBuySellProxy) {
      return;
    }
    resetField([
      'amount',
      'buyCommitResponse',
      'sellCommitResponse',
      'quoteResponse',
      'buyCommitResponse',
      'buyInputParams',
      'buyQuoteResponse',
      'sellCommitResponse',
      'sellInputParams',
      'sellQuoteResponse',
    ]);
  }, [resetField, shouldNotClearFormBuySellProxy]);

  const handleTabChange = useCallback(
    (newTabIndex: number) => {
      let currentTradeTab = '';
      if (newTabs[newTabIndex].transferType === transferType.value) {
        return;
      }

      if (transferType.value === 'buy') {
        currentTradeTab = 'buy';
      } else if (transferType.value === 'sell') {
        currentTradeTab = 'sell';
      } else {
        currentTradeTab = 'convert';
      }

      clearForm();

      // reset source and target asset ids when switching tabs from one tradeTypeUI to the other
      if (
        hasPreviewRefreshExperiment &&
        currentTradeTab !== newTabs[newTabIndex].transferType
      ) {
        sourceAssetId.onChange('');
        targetAssetId.onChange('');
      }

      logEvent(`${currentTradeTab}_switched_trade_type`, {
        componentType: ComponentType.button,
        action: ActionType.click,
        switchToType: newTabs[newTabIndex].transferType,
      });

      //Only update transferType if the tab is buy or sell
      if (newTabIndex === 0 || newTabIndex === 1) {
        transferType.onChange(
          newTabs[newTabIndex].transferType as TradeFiatAction,
        );
        if (initialAssetId) {
          assetId.onChange(initialAssetId);
        }
      } else if (newTabIndex === 2) {
        transferType.onChange(undefined);
      }
      setTradeTypeUI(newTabs[newTabIndex].transferType as TradeAction);

      if (isUsdcAdpWidget && !isAssetOfType(assetId.value, 'USDC')) {
        assetId.onChange(STABLECOIN_IDS.USDC);
      }
    },
    [
      newTabs,
      transferType,
      clearForm,
      setTradeTypeUI,
      hasPreviewRefreshExperiment,
      isUsdcAdpWidget,
      assetId,
      initialAssetId,
      sourceAssetId,
      targetAssetId,
    ],
  );

  const entryStepSecondaryButton = useMemo(() => {
    const entryStepSecondaryFallback = (
      <Box
        spacingTop={2}
        spacingHorizontal={3}
        width={ORDER_TYPE_SELECTOR_FALLBACK_WIDTH}
        height={ORDER_TYPE_SELECTOR_FALLBACK_HEIGHT}
      />
    );

    if (!transferType.value) {
      return entryStepSecondaryFallback;
    }

    if (transferType.value === 'sell' && isUsdcAdpWidget) {
      return entryStepSecondaryFallback;
    }

    return (
      <Box spacingTop={2} spacingHorizontal={3}>
        <BuySellInputSecondaryButton
          showOrderTypeSelector={hasLimitOrderExperiment && !isUsdcAdpWidget}
          disabled={false}
        />
      </Box>
    );
  }, [transferType.value, hasLimitOrderExperiment, isUsdcAdpWidget]);

  const entryStep = useMemo(() => {
    if (buySellProxy) {
      return (
        <BuySellProxyEntryStep
          queryRef={query}
          viewerAssetRefs={entryStepViewAssetFragment}
          transferType={buySellProxy}
          closeModal={closeModal}
          clearForm={clearForm}
        />
      );
    }
    if (transferType.value === 'buy' || transferType.value === 'sell') {
      return (
        <BuySellEntryStep
          queryRef={query}
          viewerAssetRefs={entryStepViewAssetFragment}
        />
      );
    }
    return (
      <ConvertEntryStep
        queryRef={query}
        viewerAssetRefs={entryStepViewAssetFragment}
      />
    );
  }, [
    buySellProxy,
    transferType.value,
    query,
    entryStepViewAssetFragment,
    closeModal,
    clearForm,
  ]);

  const backButton = useMemo(
    () => (
      <Box spacingTop={2} spacingStart={2}>
        <IconButton
          onPress={closeModal}
          name={'backArrow'}
          variant="secondary"
          transparent
        />
      </Box>
    ),
    [closeModal],
  );

  const tabs = useMemo(() => {
    if (isCryptoOnlyTrader) {
      return [{ index: 2, label: formatMessage(tabTitleMessages.convert) }];
    }

    const buyTabMessage = isUsdcAdpWidget
      ? stableAssetTabTitleMessages.deposit
      : tabTitleMessages.buy;

    // If tradeActions is undefined, we show all the transfer types
    if (!tradeActions) {
      return [
        { index: 0, label: formatMessage(buyTabMessage) },
        { index: 1, label: formatMessage(tabTitleMessages.sell) },
        { index: 2, label: formatMessage(tabTitleMessages.convert) },
      ];
    }

    return tradeActions?.map((action, index) => {
      return {
        index,
        label: formatMessage(tabTitleMessages[action]),
      } as Tab;
    });
  }, [formatMessage, tradeActions, isCryptoOnlyTrader, isUsdcAdpWidget]);

  return (
    <RetailRedesignTabProvider
      defaultIndex={
        transferType.value === 'buy' ? 0 : transferType.value === 'sell' ? 1 : 2
      }
    >
      <>
        <Box flexWrap="wrap" justifyContent="space-between" spacingTop={2}>
          {isPhoneSmall ? (
            <HStack
              justifyContent="space-between"
              spacingBottom={2}
              width="100%"
            >
              {backButton}
              {entryStepSecondaryButton}
            </HStack>
          ) : null}

          <RetailRedesignTabs
            hideBackButton={true}
            hideTabs={false}
            tabHeight={40}
            tabs={tabs}
            onChange={handleTabChange}
            turnOffAnimations
          />
          {!isPhoneSmall ? entryStepSecondaryButton : null}
        </Box>
        {entryStep}
      </>
    </RetailRedesignTabProvider>
  );
}

export default memo(EntryStep);

import { useEffect, useMemo, ReactElement, memo } from 'react';
import { TransferCancelReasonCode } from '@cb/shared/types/__relay_enums__/enums';
import { LottieStatusAnimationType } from '@cbhq/cds-common';
import { HeroSquare } from '@cbhq/cds-web/illustrations/HeroSquare';
import { Box } from '@cbhq/cds-web/layout/Box';
import { Spacer } from '@cbhq/cds-web/layout/Spacer';
import { VStack } from '@cbhq/cds-web/layout/VStack';

const LOTTIE_FAILURE_STATUS_CIRCLE_RADIUS = 320; // Matching `HeroSquare` circle radius (128px)
const LOTTIE_FAILURE_STATUS_SVG_LINK =
  'https://static-assets.coinbase.com/simple/lottie-failure-status.svg';

export type ConfirmationStatus = LottieStatusAnimationType;

export type ConfirmationCancelReasonCode = TransferCancelReasonCode | undefined;

type BaseConfirmationProps = {
  status: LottieStatusAnimationType;
  illustration?: ReactElement;
  copy: ReactElement;
  upsell?: ReactElement | null;
  ctaButtons: ReactElement;
  trackEvent: (event: string) => void;
  perfMarker: () => void;
};

export const BaseConfirmation = memo(function BaseConfirmation({
  status,
  illustration: customIllustration,
  copy,
  upsell,
  ctaButtons,
  trackEvent,
  perfMarker,
}: BaseConfirmationProps) {
  const illustration = useMemo(() => {
    if (customIllustration) return customIllustration;
    if (status === 'pending') {
      return (
        <Box alignSelf="center" offsetBottom={2}>
          <HeroSquare name="processing" />
        </Box>
      );
    }
    if (status === 'success') {
      return (
        <Box alignSelf="center" offsetBottom={2}>
          <HeroSquare name="success" />
        </Box>
      );
    }

    // TODO: Replace with `HeroSquare` once CDS added the failure illustration
    return (
      <Box offsetBottom={7} offsetTop={5} alignSelf="center">
        <img
          src={LOTTIE_FAILURE_STATUS_SVG_LINK}
          height={LOTTIE_FAILURE_STATUS_CIRCLE_RADIUS}
          width={LOTTIE_FAILURE_STATUS_CIRCLE_RADIUS}
        />
      </Box>
    );
  }, [customIllustration, status]);

  // Tracking
  useEffect(() => {
    perfMarker();

    trackEvent('viewed_status');
    if (status === 'success') {
      trackEvent('success_view');
    }
    if (status === 'failure') {
      trackEvent('failure_view');
    }
  }, []);

  return (
    <Box>
      <VStack alignContent="center" flexWrap="wrap" flexGrow={1}>
        {illustration}
        {copy}
        <Spacer vertical={2} />
        {upsell}
        {ctaButtons}
      </VStack>
    </Box>
  );
});

