  ActionableRow,
  ActionableRowProps,
} from 'components/SimpleTrade/SimpleTradeV2/BasePreview/components/PreviewBody/ActionableSection/ActionableRow/ActionableRow';

export type ToggleRowProps = Pick<SwitchProps, 'onChange'> & {
  checked: boolean; // not pulling this one off the child props because we want to ensure the parent sets a value
  title: string;
  description?: string;
  accessibility: string;
  onInfoPress?: () => void;
  testID?: SwitchProps['testID'];
  disabled?: boolean;
  media?: ActionableRowProps['media'];
  showInfoIcon?: boolean;
};

// this is a controlled component so the parent will control the state of the switch
// to provide consumers more flexibility in how they use this component
// in particular this allows for programmatic change of state easier than keeping it here
export const ToggleRow = memo(function ToggleRow({
  title,
  description,
  accessibility,
  onInfoPress,
  testID,
  disabled,
  media,
  showInfoIcon,
  ...switchProps
}: ToggleRowProps) {
  const cellDescription = useMemo(
    () =>
      description ? (
        <HStack spacerGap={0.5} alignItems="center" spacingVertical={0.5}>
          <TextLabel2 color="foregroundMuted" as="label">
            {description}
          </TextLabel2>
          {showInfoIcon && <InfoIcon onPress={onInfoPress} />}
        </HStack>
      ) : undefined,
    [description, onInfoPress, showInfoIcon],
  );

  return (
    <ActionableRow
      title={title}
      description={cellDescription}
      action={
        <Switch
          {...switchProps}
          accessibilityLabel={accessibility}
          testID={testID ?? 'toggle-row-switch'}
          disabled={disabled}
        />
      }
      media={media}
      multiline
      priority="end"
    />
  );
});

type ToggleRowFallbackProps = Pick<ToggleRowProps, 'title' | 'description'>;

export const ToggleRowFallback = memo(function ToggleRowFallback({
