    [description],
  );

  return (
    <ActionableRow
      title={title}
      description={cellDescription}
      action={<Switch disabled />}
    />
  );
});

import React, { memo, useEffect, useCallback, useState } from 'react';
import invariant from 'invariant';

import { useSubmitter } from '@cb/forms';
import { useIsMobile } from '@cb/shared/utils';
import { IconButton } from '@cbhq/cds-web/buttons';
import { ListCell } from '@cbhq/cds-web/cells';
import { Box, VStack } from '@cbhq/cds-web/layout';
import { TextTitle3 } from '@cbhq/cds-web/typography';
import { ActionType, ComponentType, logEvent } from '@cbhq/client-analytics';

import { WidgetLoadingFallback } from 'components/WidgetComponents';
import useToasts from 'hooks/useToasts';
import { client } from 'utils/client';

import AcknowledgementForm from './AcknowledgementForm';
import AcknowledgmentFormFields from './AcknowledgmentFormFields';
import { StepProgress } from './StepProgress';
import {
  SocialEngineeringQuestionnaire,
  SocialEngineeringQuestion,
  SocialEngineeringQuestionnaireStackItem,
} from './types';

export type QuestionnaireProps = {
  answers: Record<never, never>;
  setAnswers: React.Dispatch<React.SetStateAction<Record<string, string>>>;
  isSaving: boolean;
};

function Questionnaire({ answers, setAnswers, isSaving }: QuestionnaireProps) {
  const toasts = useToasts();
  const [submit] = useSubmitter(AcknowledgementForm);

  const [isLoading, setIsLoading] = useState(true);
  const [navigationStack, setNavigationStack] = useState<
    SocialEngineeringQuestionnaireStackItem[]
  >([]);
  const [questions, setQuestions] = useState<SocialEngineeringQuestionnaire[]>(
    [],
  );
  const [shouldSubmitForm, setShouldSubmitForm] = useState(false);
  const currentQuestion =
    navigationStack && navigationStack[navigationStack.length - 1];
  const isMobile = useIsMobile();

  const onItemSelect = useCallback(
    (
      question: SocialEngineeringQuestionnaire,
      option: SocialEngineeringQuestion,
    ) => {
      if (navigationStack.length === 1) {
        setAnswers({ [question.answerKey]: option.value });
      } else {
        setAnswers({ ...answers, [question.answerKey]: option.value });
      }

      logEvent('social_engineering_question_selected', {
        action: ActionType.select,
        componentType: ComponentType.button,
        option: option.value,
      });

      function goToAcknowledgementForm() {
        const stackItem: SocialEngineeringQuestionnaireStackItem = {
          steps: 3,
          progress: 3,
          question: undefined,
          hasForm: true,
          formWithReasonField: false,
        };
        setNavigationStack([...navigationStack, stackItem]);
      }

      switch (option.value) {
        case 'to_elsewhere':
        case 'to_stranger':
        case 'to_coinbase':
        case 'to_friend': {
          goToAcknowledgementForm();
          break;
        }
        case 'other': {
          const stackItem: SocialEngineeringQuestionnaireStackItem = {
            steps: 2,
            progress: 2,
            question: undefined,
            hasForm: true,
            formWithReasonField: true,
          };
          setNavigationStack([...navigationStack, stackItem]);
          break;
        }
        default: {
          const nextQuestion = questions.find(
            q => q.answerKey === option.value,
          );
          const stackItem: SocialEngineeringQuestionnaireStackItem = {
            steps: 3,
            progress: 2,
            question: nextQuestion,
            hasForm: false,
            formWithReasonField: false,
          };
          setNavigationStack([...navigationStack, stackItem]);
        }
      }
    },
    [navigationStack, setAnswers, answers, questions],
  );

  const goBack = useCallback(() => {
    navigationStack.pop();
    setNavigationStack([...navigationStack]);
  }, [setNavigationStack, navigationStack]);

  function renderStep(stackItem: SocialEngineeringQuestionnaireStackItem) {
    const { question, hasForm, formWithReasonField } = stackItem;
    if (question) {
      return isSaving ? (
        <WidgetLoadingFallback />
      ) : (
        <VStack>
          <TextTitle3 as="p" spacingBottom={1}>
            {question.question}
          </TextTitle3>
          {question.options?.map(o => (
            <ListCell
              outerSpacing={{ spacing: 0 }}
              key={o.value}
              title={o.title}
              description={o.subTitle}
              accessory="arrow"
              // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
              onPress={() => onItemSelect(question, o)}
            />
          ))}
        </VStack>
      );
    }
    if (hasForm) {
      return (
        <AcknowledgmentFormFields
          showReasonField={formWithReasonField}
          isSaving={isSaving}
        />
      );
    }
  }

  async function fetchSocialEngineeringQuestions() {
    try {
      setIsLoading(true);
      const res = await client.get(
        '/v3/coinbase.public_api.authed.proofing.CustomerDueDiligenceService/GetSocialEngineeringQuestion',
      );
      invariant(
        res && res.data,
        'Fetching social engineering questionnaire failed',
      );
      setQuestions(res.data);
      setNavigationStack([
        {
          steps: 3,
          progress: 1,
          question: res.data[0],
          hasForm: false,
          formWithReasonField: false,
        },
      ]);
      setIsLoading(false);
    } catch (e) {
      toasts.showApiErrorToast(e);
      setIsLoading(false);
    }
  }
  useEffect(() => {
    fetchSocialEngineeringQuestions();
  }, []);

  useEffect(() => {
    if (shouldSubmitForm) {
      submit();
      setShouldSubmitForm(false);
    }
  }, [shouldSubmitForm]);

  return isLoading || isSaving ? (
    <WidgetLoadingFallback />
  ) : (
    <VStack>
      <Box
        spacingHorizontal={3}
        spacingVertical={5}
        justifyContent="center"
        position="relative"
      >
        <Box pin="left" justifyContent="center" alignItems="center">
          <IconButton
            testID="backButton"
            name="backArrow"
            onPress={goBack}
            variant="secondary"
            disabled={navigationStack.length <= 1}
          />
        </Box>
        <StepProgress
          steps={currentQuestion.steps}
          progress={currentQuestion.progress}
        />
      </Box>
      <VStack width={isMobile ? '100%' : '450px'}>
        {renderStep(currentQuestion)}
      </VStack>
    </VStack>
  );
}

export default memo(Questionnaire);

