  onPress: (asset: AssetMetadata) => void;
};

export type CashTableRowProps = {
  assetOrCurrencyRef: CashTableRowAssetOrCurrencyFragment$key | null;
  queryRef: CashTableRowFragment$key;
  rawDappWalletBalance?: number;
  hidePrimaryAssets?: boolean;
  actionButtonColumns?: ActionButton[];
  showBalanceFallback?: boolean;
};

function CashTableRowContent({
  queryRef,
  assetOrCurrencyRef,
  rawDappWalletBalance,
  hidePrimaryAssets,
  showBalanceFallback,
}: CashTableRowProps) {
  const query = useFragment(
    graphql`
      fragment CashTableRowFragment on Query {
        viewer {
          earn {
            assets {
              current {
                assetV2: asset {
                  asset {
                    platformName
                  }
                  rewardApy {
                    formattedValue
                  }
                }
              }
            }
          }
        }
        ...useCountryRestrictionsFragment
      }
    `,
    queryRef,
  );

  const assetOrCurrency = useFragment(
    graphql`
      fragment CashTableRowAssetOrCurrencyFragment on AssetOrCurrency {
        __typename
        ... on TiersCurrency {
          code
          name
          accounts {
            uuid
          }
          assetCurrentBalance {
            totalBalanceFiat {
              value
            }
          }
        }
        ... on ViewerAsset {
          asset {
            uuid
            imageUrl
            name
            platformName
            slug
            displaySymbol
            contractAddress
          }
          accounts {
            uuid
            name
            type
            allowWithdrawals
            allowDeposits
          }
          supportedContextsV2 {
            isTradable
            isConvertible
          }
          assetCurrentBalance {
            totalBalanceFiat {
              value
            }
          }
        }
      }
    `,
    assetOrCurrencyRef,
  );

  const nativeCurrency = useNativeCurrency() || 'USD';

  const restrictedActions = useCountryRestrictions(query);

  const {
    assetKey,
    assetName,
    assetBalanceInNativeCurrency,
    assetImageUrl,
    platformName,
    displaySymbol,
    assetType,
    assetSlug,
    canSend,
    canReceive,
    canBuy,
    canSell,
    canConvert,
    canAddCash,
    accountId,
    assetUuid,
    contractAddress,
  } = useMemo(() => {
    if (assetOrCurrency?.__typename === 'ViewerAsset') {
      const viewerAssetNode = assetOrCurrency;
      let totalBalance = hidePrimaryAssets
        ? 0
        : Number(
            viewerAssetNode?.assetCurrentBalance?.totalBalanceFiat?.value || '',
          );

      if (rawDappWalletBalance) {
        totalBalance += rawDappWalletBalance;
      }

      // In the scenario where there is more than one account (web3, vault, etc.), find the wallet account
      const account = viewerAssetNode?.accounts?.find(
        account => account?.type === 'WALLET',
      );

      return {
        assetKey: account?.uuid ?? '',
        assetName: viewerAssetNode?.asset?.name ?? '',
        assetBalanceInNativeCurrency: String(totalBalance) ?? '',
        platformName: viewerAssetNode?.asset?.platformName ?? '',
        displaySymbol: viewerAssetNode?.asset?.displaySymbol ?? '',
        assetImageUrl: viewerAssetNode?.asset?.imageUrl ?? '',
        assetUuid: viewerAssetNode?.asset?.uuid ?? '',
        assetType: account?.type?.toUpperCase() ?? '',
        assetSlug: viewerAssetNode?.asset?.slug ?? '',
        canSend: account?.allowWithdrawals,
        canReceive: account?.allowDeposits,
        canBuy:
          (viewerAssetNode?.supportedContextsV2?.isTradable ?? false) &&
          !restrictedActions.includes('buys'),
        canSell:
          (viewerAssetNode?.supportedContextsV2?.isTradable ?? false) &&
          !restrictedActions.includes('sells'),
        canConvert:
          (viewerAssetNode?.supportedContextsV2?.isConvertible ?? false) &&
          !restrictedActions.includes('trades'),
        canAddCash: false,
        accountId: account?.uuid ?? '',
        contractAddress: viewerAssetNode?.asset?.contractAddress ?? '',
      };
    } else if (assetOrCurrency?.__typename === 'TiersCurrency') {
      const account = assetOrCurrency.accounts?.[0];
      return {
        assetKey: account?.uuid ?? assetOrCurrency?.code ?? '',
        assetName: assetOrCurrency?.name ?? '',
        assetBalanceInNativeCurrency:
          assetOrCurrency.assetCurrentBalance?.totalBalanceFiat?.value ?? '',
        assetImageUrl: '',
        platformName: assetOrCurrency?.code ?? '',
        displaySymbol: assetOrCurrency?.code ?? '',
        currencyName: assetOrCurrency?.name ?? '',
        assetType: 'FIAT' ?? '',
        assetSlug: '',
        canAddCash: true,
        accountId: assetOrCurrency?.accounts?.[0]?.uuid ?? '',
        assetUuid: '',
        contractAddress: '',
      };
    }
    // assetOrCurrency can be null
    return {};
  }, [
    assetOrCurrency,
    hidePrimaryAssets,
    restrictedActions,
    rawDappWalletBalance,
  ]);

  const history = useHistory();
  const isMobile = useIsMobile();
  const isTablet = useScreenMatch('tablet');
  const formatCurrency = useCurrencyFormatter();

  const assetReward = useMemo(() => {
    return query.viewer.earn?.assets?.current?.find(
      reward => reward?.assetV2?.asset.platformName === platformName,
    );
  }, [query.viewer.earn?.assets, platformName]);

  const onRowClick = useCallback(() => {
    let assetLink;

    logStableAssetsRowClicked({
      flow: 'cash_table',
      step: 'navigate_to_asset_page',
      otherParams: { asset_name: assetName },
    });

    if (assetSlug) {
      assetLink = assetPageUrl(assetSlug);
    } else if (assetKey) {
      assetLink = accountUrl(assetKey);
    } else {
      return;
    }

    history.push(assetLink);
  }, [assetName, assetSlug, assetKey, history]);

  const isInRelabelExperiment = useDigitalUsdRelabelExperiment();

  const nameColumn = useMemo(() => {
    if (!platformName) {
      return null;
    }

    let width = undefined;

    if (isMobile) {
      width = '50%';
    } else if (isTablet) {
      width = '38%';
    } else {
      width = '33%';
    }

    if (platformName === USDC_ASSET_SYMBOL && isInRelabelExperiment) {
      return (
        <UsdcTableCell
          width={width}
          assetImageUrl={assetImageUrl}
          displaySymbol={displaySymbol}
        />
      );
    }

    const title = displaySymbol === 'USD' ? 'US Dollar' : assetName ?? '';

    return (
      <TableCell
        start={
          assetType === 'FIAT' || !assetImageUrl ? (
            <FiatCurrencyIcon symbol={platformName} size={32} />
          ) : (
            <CellMedia
              type="asset"
              source={assetImageUrl}
              accessibilityLabel={displaySymbol}
            />
          )
        }
        title={title}
        subtitleColor={assetReward ? 'positive' : 'currentColor'}
        innerSpacing={{ spacingStart: 3 }}
        width={width}
      />
    );
  }, [
    isMobile,
    isTablet,
    displaySymbol,
    assetName,
    platformName,
    assetType,
    assetImageUrl,
    assetReward,
    isInRelabelExperiment,
  ]);

  const formattedTotalBalanceInNativeCurrency = useMemo(
    () =>
      assetBalanceInNativeCurrency
        ? formatCurrency({
            isFiat: true,
            amount: {
              amount: assetBalanceInNativeCurrency,
              currency: nativeCurrency,
            },
          })
        : '',
    [assetBalanceInNativeCurrency, formatCurrency, nativeCurrency],
  );

  const totalBalanceColumn = useMemo(() => {
    if (showBalanceFallback) {
      return <TableCell title={DEFAULT_FORMATTED_FALLBACK} />;
    }

    return (
      <TableCell
        title={formattedTotalBalanceInNativeCurrency}
        testID="cash-total-balance-cell"
      />
    );
  }, [showBalanceFallback, formattedTotalBalanceInNativeCurrency]);

  const breakpoints = useBreakpoints();
  const apyColumn = useMemo(() => {
    const formattedValue = assetReward?.assetV2?.rewardApy?.formattedValue;

    if (breakpoints.isPhone) {
      return null;
    }

    return (
      <TableCell
        title={formattedValue || '--'}
        titleColor={formattedValue ? 'positive' : 'currentColor'}
        innerSpacing={{ spacingStart: 3 }}
        testID="cash-apy-cell"
      />
    );
  }, [assetReward, breakpoints.isPhone]);

  // check if add cash usdc is enabled
  const hasAddCashUsdc = useHasAddCashUsdc();

  // cashTransfer if correct cash asset and experiment
  const hasCashTransferUsdc = useHasCashTransferUsdc();

  const inlineQuickActionColumn = useMemo(() => {
    // value of allowed quick action items
    const permissions = [
      canConvert,
      canReceive,
      canSend,
      canBuy,
      canSell,
      canAddCash,
      hasCashTransferUsdc,
    ];

    // to prevent row divider inconsistencies if none are enabled
    if (permissions.every(permission => !permission)) {
      return (
        <TableCell width="5%">
          <></>
        </TableCell>
      );
    }

    // cashOut and addCash are the same in quick actions so optionally split them
    const canCashOut = canAddCash;
    // hide if the quick action item is visible inline
    const canAddCashInQuickActions = hasAddCashUsdc || canAddCash;
    const canBuyInQuickActions = hasAddCashUsdc && canBuy;

    if (!accountId || !displaySymbol) {
      return null;
    }

    return (
      <td
        // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
        onClick={e => {
          e.stopPropagation();
        }}
      >
        <HStack spacerGap={5} alignItems="center" justifyContent="flex-end">
          <Box spacingEnd={2}>
            <InlineQuickActions
              contractAddress={contractAddress}
              assetUuid={assetUuid}
              accountId={accountId}
              canSend={canSend}
              canReceive={canReceive}
              canBuy={canBuyInQuickActions}
              canSell={canSell}
              canConvert={canConvert}
              canAddCash={canAddCashInQuickActions}
              canCashOut={canCashOut}
              canCashTransfer={hasCashTransferUsdc}
              assetCode={displaySymbol}
              nativeCurrency={nativeCurrency}
              surface="assets"
            />
          </Box>
        </HStack>
      </td>
    );
  }, [
    canConvert,
    canReceive,
    canSend,
    canBuy,
    canSell,
    canAddCash,
    hasCashTransferUsdc,
    hasAddCashUsdc,
    accountId,
    displaySymbol,
    contractAddress,
    assetUuid,
    nativeCurrency,
  ]);

  if (!assetName) return null;

  return (
    <TableRow onPress={onRowClick}>
      {nameColumn}
      {totalBalanceColumn}
      {apyColumn}
      {inlineQuickActionColumn}
    </TableRow>
  );
}

export function logAddCash(assetName = '') {
  logStableAssetsButtonClicked({
    flow: 'cash_table',
    step: 'add_cash',
    otherParams: { asset_name: assetName },
  });
}

const networkErrorBoundaryProps = {
  name: 'CashTableRow',
  context: 'cash_table',
  owner: 'usdc' as ErrorOwner,
};

function CashTableRow(props: CashTableRowProps) {
  const onCatchNetworkErrorBoundary = useCallback<ErrorBoundaryCatchHandler>(
    (error, info) =>
      notifyError(error, {
        severity: 'error',
        isHandled: false,
        componentStack: info?.componentStack,
        ...networkErrorBoundaryProps,
      }),
    [],
  );

  return (
    <Boundary
      skipErrorLogging
      onCatch={onCatchNetworkErrorBoundary}
      {...networkErrorBoundaryProps}
    >
      <CashTableRowContent {...props} />
    </Boundary>
  );
}

export default memo(CashTableRow);

