import { memo, useMemo, useCallback, useEffect } from 'react';
import noop from 'lodash/noop';
import { useIntl } from 'react-intl';
import styled from 'styled-components';

import { useFields } from '@cb/forms';
import CloseIcon from '@cb/shared/components/CloseIcon';
import { Button } from '@cbhq/cds-web/buttons/Button';
import { VStack } from '@cbhq/cds-web/layout/VStack';
import {
  ActionType,
  ComponentType,
  logEvent,
  useLogEventOnMount,
  markStep,
} from '@cbhq/client-analytics';
import { graphql, useFragment } from '@cbhq/data-layer';

import EntryInput, {
  useEntryInputSwitcher,
} from 'components/BuySellComponents/EntryInput';
import EntryInputSecondaryButton from 'components/BuySellComponents/EntryInputSecondaryButton';
import Header from 'components/BuySellComponents/Header';
import { useLoader } from 'components/LoadingProvider';
import { useCloseModal } from 'components/Modal/hooks';
import useStepper from 'components/Stepper/hooks/useStepper';
import {
  StepWrapper,
  StickyButtonContainer,
  InnerStepContent,
} from 'components/WidgetComponents/StepWithSuspense';
import useDebouncedCallback from 'hooks/useDebouncedCallback';

import { useInputSymbols } from '../hooks/useInputSymbols';
import { usePreviewStake } from '../hooks/usePreviewStake';
import { useStakeDropOffNotificationTriggerOnMount } from '../hooks/useStakeDropOffNotificationTrigger';
import { useStakeMaxDefaultExperiment } from '../hooks/useStakeMaxDefaultExperiment';
import messages from '../messages';
import { StakingInputFragment$key } from './__generated__/StakingInputFragment.graphql';
import { stepper, form } from './Common';
import StakingFooter from './StakingFooter';

export const FooterContainer = styled.div`
  footer {
    padding: 0;
  }
`;

type StakingInputProps = {
  queryRef: StakingInputFragment$key;
  isNuxSkipped?: boolean;
};

function StakingInput({ queryRef, isNuxSkipped }: StakingInputProps) {
  const { goBack, goToStep } = useStepper(stepper);
  const closeModal = useCloseModal();
  const {
    amount,
    isFiatInput,
    previewStakeResponse,
    cryptoAmountAvailable,
    eventContext,
    isDefaultedMax,
  } = useFields(form);
  const { formatMessage } = useIntl();
  const { previewStake } = usePreviewStake();
  const debouncedPreviewStake = useDebouncedCallback(previewStake);
  const switchInput = useEntryInputSwitcher({
    form,
    quoteFiatAmount: previewStakeResponse.value?.total?.fiatAmount?.value ?? '',
    quoteCryptoAmount:
      previewStakeResponse.value?.total?.cryptoAmount?.value ?? '',
  });
  const { loading, setLoading } = useLoader();

  const query = useFragment(
    graphql`
      fragment StakingInputFragment on Query
      @argumentDefinitions(slug: { type: "String!" }) {
        viewer {
          assetAccounts: assetBySlug(slug: $slug) {
            ...EntryInputFragment
            asset {
              name
              uuid
              platformName
            }
            accounts {
              primary
              availableBalance {
                currency
                value
              }
              availableBalanceInNativeCurrency {
                value
              }
            }
            staking {
              pendingRequests {
                stakingAvailableBalance {
                  value
                  currency
                }
              }
            }
          }
        }
        ...StakingFooterFragment @arguments(slug: $slug)
      }
    `,
    queryRef,
  );

  const { viewer } = query;

  const assetAccount = viewer?.assetAccounts?.accounts?.find(
    account => account?.primary,
  );
  const assetName = viewer?.assetAccounts?.asset?.name ?? '';
  const assetUuid = viewer?.assetAccounts?.asset?.uuid ?? '';
  const assetSymbol = viewer?.assetAccounts?.asset?.platformName ?? '';
  const { activeSymbol, inactiveSymbol } = useInputSymbols({
    isFiatInput,
    targetAssetSymbol: assetSymbol,
  });

  useStakeDropOffNotificationTriggerOnMount(
    'ENTERS_STAKEFLOW_TAP_STAKE_BUTTON_MOBILE',
    'single_asset_stake',
    { uuid: assetUuid, symbol: assetSymbol },
  );

  const balance = useMemo(
    () => ({
      currency: assetAccount?.availableBalance?.currency ?? '',
      amount: assetAccount?.availableBalance?.value ?? '',
    }),
    [assetAccount?.availableBalance],
  );

  const inStakeDefaultMaxExperiment = useStakeMaxDefaultExperiment();
  useEffect(() => {
    if (inStakeDefaultMaxExperiment && isDefaultedMax.value === undefined) {
      const amounAvailableToStakeFiat =
        assetAccount?.availableBalanceInNativeCurrency?.value;
      if (!amounAvailableToStakeFiat) return;
      const roundedAmount =
        Math.floor(Number(amounAvailableToStakeFiat) * 100) / 100;
      isDefaultedMax.onChange(true);
      amount.onChange(String(roundedAmount));
    }
  }, []);

  const handlePreviewSuccess = useCallback(() => {
    setLoading(false);
    goToStep('stakingPreview');
  }, [goToStep, setLoading]);

  const handlePreviewError = useCallback(() => {
    setLoading(false);
  }, [setLoading]);

  const handleChange = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (value: any) => {
      amount.onChange(value);
      if (isDefaultedMax.value) {
        isDefaultedMax.onChange(false);
      }

      if (!value) return;

      debouncedPreviewStake({
        amount: {
          value,
          currency: activeSymbol,
        },
        assetUuid,
      });
    },
    [amount, isDefaultedMax, debouncedPreviewStake, activeSymbol, assetUuid],
  );

  const handlePreviewButtonPress = useCallback(() => {
    if (!amount.value) return;
    logEvent('staking_flow_input', {
      action: ActionType.click,
      componentType: ComponentType.button,
      asset: assetSymbol,
      context: eventContext.value,
    });

    setLoading(true);
    markStep('navigate_to_staking_preview_screen');
    cryptoAmountAvailable.onChange(
      viewer?.assetAccounts?.staking?.pendingRequests?.stakingAvailableBalance
        ?.value,
    );

    const amountToStake = isDefaultedMax.value ? balance.amount : amount.value;
    const symbol = isDefaultedMax.value ? balance.currency : activeSymbol;

    previewStake(
      {
        amount: {
          value: amountToStake,
          currency: symbol,
        },
        assetUuid,
      },
      { onSuccess: handlePreviewSuccess, onError: handlePreviewError },
    );
  }, [
    amount.value,
    assetSymbol,
    eventContext.value,
    setLoading,
    cryptoAmountAvailable,
    viewer?.assetAccounts?.staking?.pendingRequests?.stakingAvailableBalance
      ?.value,
    isDefaultedMax.value,
    balance.amount,
    balance.currency,
    activeSymbol,
    previewStake,
    assetUuid,
    handlePreviewSuccess,
    handlePreviewError,
  ]);

  const handleMaxButtonPress = useCallback(() => {
    logEvent('staking_flow_input_max', {
      action: ActionType.click,
      componentType: ComponentType.button,
      asset: assetSymbol,
      context: eventContext.value,
    });

    const balance =
      viewer?.assetAccounts?.staking?.pendingRequests?.stakingAvailableBalance;
    if (!balance) {
      return;
    }
    setLoading(true);

    cryptoAmountAvailable.onChange(balance.value);

    previewStake(
      {
        amount: {
          value: balance.value,
          currency: balance.currency,
        },
        assetUuid,
      },
      { onSuccess: handlePreviewSuccess, onError: handlePreviewError },
    );
  }, [
    assetUuid,
    viewer?.assetAccounts?.staking?.pendingRequests?.stakingAvailableBalance,
    cryptoAmountAvailable,
    handlePreviewError,
    handlePreviewSuccess,
    previewStake,
    setLoading,
    assetSymbol,
    eventContext,
  ]);

  useLogEventOnMount('staking_flow_input', {
    action: ActionType.render,
    componentType: ComponentType.button,
    asset: assetSymbol,
    context: eventContext.value,
    isNuxSkipped,
    defaultMaxStake: inStakeDefaultMaxExperiment,
  });

  useEffect(() => {
    markStep('loaded_staking_input_screen');
  }, []);

  return (
    <StepWrapper>
      <Header
        title={formatMessage(messages.stakingInputTitle, {
          asset: assetName,
        })}
        goBack={goBack}
        rightContent={<CloseIcon onClick={closeModal} />}
        borderBottom
      />
      <VStack spacingTop={1} flexGrow={1}>
        <InnerStepContent noTopPadding noBottomPadding>
          <EntryInput
            viewerAssetRef={viewer?.assetAccounts}
            error={amount.errors[0]}
            autoFocus
            input={{
              symbol: activeSymbol,
              displaySymbol: balance.currency,
              value: amount.value,
              onChange: handleChange,
              onEnter: noop,
              readOnly: loading,
              noCommas: true,
            }}
            secondaryButton={
              <EntryInputSecondaryButton
                disabled={loading}
                onPress={handleMaxButtonPress}
              >
                {formatMessage(messages.stakeAll)}
              </EntryInputSecondaryButton>
            }
            switchActiveInput={{ onPress: switchInput, inactiveSymbol }}
          />
        </InnerStepContent>
      </VStack>
      <StickyButtonContainer>
        <Button
          onPress={handlePreviewButtonPress}
          disabled={Number(amount.value) === 0 || amount.errors.length > 0}
          loading={loading}
        >
          {formatMessage(messages.previewStake)}
        </Button>
        <FooterContainer>
          <StakingFooter queryRef={query} type="stake" />
        </FooterContainer>
      </StickyButtonContainer>
    </StepWrapper>
  );
}

