import {
  ActionType,
  ComponentType,
  logEvent,
  useLogEventOnMount,
  markStep,
} from '@cbhq/client-analytics';
import { graphql, useFragment } from '@cbhq/data-layer';

import EntryInput, {
  useEntryInputSwitcher,
} from 'components/BuySellComponents/EntryInput';
import EntryInputSecondaryButton from 'components/BuySellComponents/EntryInputSecondaryButton';
import Header from 'components/BuySellComponents/Header';
import { useLoader } from 'components/LoadingProvider';
import { useCloseModal } from 'components/Modal/hooks';
import { FooterContainer } from 'components/StakingV2/Stake/StakingInput';
import useStepper from 'components/Stepper/hooks/useStepper';
import {
  StepWrapper,
  StickyButtonContainer,
  InnerStepContent,
} from 'components/WidgetComponents/StepWithSuspense';
import useDebouncedCallback from 'hooks/useDebouncedCallback';

import { useInputSymbols } from '../hooks/useInputSymbols';
import { usePreviewUnstake } from '../hooks/usePreviewUnstake';
import messages from '../messages';
import { UnstakingInputFragment$key } from './__generated__/UnstakingInputFragment.graphql';
import { stepper, form } from './Common';
import UnstakingFooter from './UnstakingFooter';

type UnstakingInputProps = {
  queryRef: UnstakingInputFragment$key;
};

function UnstakingInput({ queryRef }: UnstakingInputProps) {
  const { goToStep } = useStepper(stepper);
  const closeModal = useCloseModal();
  const {
    amount,
    isFiatInput,
    previewUnstakeResponse,
    cryptoAmountAvailable,
    eventContext,
  } = useFields(form);
  const { formatMessage } = useIntl();
  const { previewUnstake } = usePreviewUnstake();
  const debouncedPreviewUnstake = useDebouncedCallback(previewUnstake);
  const switchInput = useEntryInputSwitcher({
    form,
    quoteFiatAmount:
      previewUnstakeResponse.value?.total?.fiatAmount?.value ?? '',
    quoteCryptoAmount:
      previewUnstakeResponse.value?.total?.cryptoAmount?.value ?? '',
  });
  const { loading, setLoading } = useLoader();

  const query = useFragment(
    graphql`
      fragment UnstakingInputFragment on Query
      @argumentDefinitions(slug: { type: "String!" }) {
        viewer {
          viewerAsset: assetBySlug(slug: $slug) {
            ...EntryInputFragment
            asset {
              uuid
              slug
              platformName
              name
            }
            accounts {
              primary
              type
              availableBalance {
                currency
                value
              }
            }
            staking {
              pendingRequests {
                unstakingAvailableBalance {
                  value
                  currency
                }
              }
            }
          }
        }
        ...UnstakingFooterFragment @arguments(slug: $slug)
      }
    `,
    queryRef,
  );

  const { viewer } = query;

  const viewerAsset = viewer.viewerAsset;
  const asset = viewerAsset?.asset;
  // For ETH2, we will be unstaking from their primary account
  const primaryAccount = viewerAsset?.accounts?.find(
    account => account?.primary,
  );
  // For all other assets, we will be unstaking from their `STAKED_FUNDS` account
  const stakedFundsAccount = viewerAsset?.accounts?.find(
    account => account?.type === 'STAKED_FUNDS',
  );
  const stakingAccount =
    asset?.slug === 'ethereum-2' ? primaryAccount : stakedFundsAccount;
  const assetName = asset?.name ?? '';
  const assetUuid = asset?.uuid ?? '';
  const assetSymbol = asset?.platformName ?? '';
  const pendingRequests = viewerAsset?.staking?.pendingRequests;
  const { activeSymbol, inactiveSymbol } = useInputSymbols({
    isFiatInput,
    targetAssetSymbol: assetSymbol,
  });

  const stakedBalance = useMemo(
    () => ({
      currency: stakingAccount?.availableBalance?.currency ?? '',
      amount: stakingAccount?.availableBalance?.value ?? '',
    }),
    [stakingAccount?.availableBalance],
  );

  const handlePreviewSuccess = useCallback(() => {
    setLoading(false);
    goToStep('unstakingPreview');
  }, [goToStep, setLoading]);

  const handlePreviewError = useCallback(() => {
    setLoading(false);
  }, [setLoading]);

  const handleChange = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    async (value: any) => {
      amount.onChange(value);

      if (!value) return;

      debouncedPreviewUnstake({
        amount: {
          value,
          currency: activeSymbol,
        },
        assetUuid,
      });
    },
    [activeSymbol, amount, assetUuid, debouncedPreviewUnstake],
  );

  const handlePreviewButtonPress = useCallback(() => {
    if (!amount.value) return;
    logEvent('unstaking_flow_input', {
      action: ActionType.click,
      componentType: ComponentType.button,
      asset: asset?.platformName ?? '',
      context: eventContext.value,
    });

    setLoading(true);
    markStep('navigate_to_unstaking_preview_screen');
    cryptoAmountAvailable.onChange(
      pendingRequests?.unstakingAvailableBalance?.value,
    );

    previewUnstake(
      {
        amount: {
          value: amount.value,
          currency: activeSymbol,
        },
        assetUuid,
      },
      { onSuccess: handlePreviewSuccess, onError: handlePreviewError },
    );
  }, [
    activeSymbol,
    amount.value,
    assetUuid,
    eventContext,
    handlePreviewError,
    handlePreviewSuccess,
    previewUnstake,
    setLoading,
    asset?.platformName,
    cryptoAmountAvailable,
    pendingRequests?.unstakingAvailableBalance,
  ]);

  const handleUnstakeAll = useCallback(() => {
    logEvent('unstaking_flow_input_max', {
      action: ActionType.click,
      componentType: ComponentType.button,
      asset: asset?.platformName ?? '',
      context: eventContext.value,
    });
    setLoading(true);

    const balance = pendingRequests?.unstakingAvailableBalance;
    if (!balance) {
      return;
    }

    cryptoAmountAvailable.onChange(balance.value);

    previewUnstake(
      {
        amount: {
          value: balance.value,
          currency: balance.currency,
        },
        assetUuid,
      },
      { onSuccess: handlePreviewSuccess, onError: handlePreviewError },
    );
  }, [
    assetUuid,
    pendingRequests?.unstakingAvailableBalance,
    handlePreviewError,
    handlePreviewSuccess,
    previewUnstake,
    setLoading,
    eventContext,
    asset?.platformName,
    cryptoAmountAvailable,
  ]);

  useLogEventOnMount('unstaking_flow_input', {
    action: ActionType.render,
    componentType: ComponentType.button,
    asset: asset?.platformName ?? '',
    context: eventContext.value,
  });

  useEffect(() => {
    markStep('loaded_unstaking_input_screen');
  }, []);

  return (
    <StepWrapper>
      <Header
        title={formatMessage(messages.unstakingInputTitle, {
          asset: assetName,
        })}
        goBack={closeModal}
        rightContent={<CloseIcon onClick={closeModal} />}
        borderBottom
      />
      <VStack spacingTop={1} flexGrow={1}>
        <InnerStepContent noTopPadding noBottomPadding>
          <EntryInput
            viewerAssetRef={viewerAsset}
            error={amount.errors[0]}
            autoFocus
            input={{
              symbol: activeSymbol,
              displaySymbol: stakedBalance.currency,
              value: amount.value,
              onChange: handleChange,
              onEnter: noop,
              readOnly: loading,
              noCommas: true,
            }}
            secondaryButton={
              <EntryInputSecondaryButton
                disabled={loading}
                onPress={handleUnstakeAll}
              >
                {formatMessage(messages.unstakeAll)}
              </EntryInputSecondaryButton>
            }
            switchActiveInput={{ onPress: switchInput, inactiveSymbol }}
          />
        </InnerStepContent>
      </VStack>
      <StickyButtonContainer>
        <Button
          onPress={handlePreviewButtonPress}
          disabled={Number(amount.value) === 0 || amount.errors.length > 0}
          loading={loading}
        >
          {formatMessage(messages.previewUnstake)}
        </Button>
        <FooterContainer>
          <UnstakingFooter queryRef={query} />
        </FooterContainer>
      </StickyButtonContainer>
    </StepWrapper>
  );
}

export default memo(UnstakingInput);

