import { useEffect, useCallback, memo } from 'react';
import VisibilityTrigger from '@cb/shared/components/VisibilityTrigger';
import { useToggler } from '@cbhq/cds-common';
import { Button, IconButton } from '@cbhq/cds-web/buttons';
import { Box, VStack } from '@cbhq/cds-web/layout';
import { Modal, ModalBody } from '@cbhq/cds-web/overlays';
import { TextBody, TextTitle3 } from '@cbhq/cds-web/typography';

import SeverityIcon from 'components/SeverityIcon';

import { SystemAlertWithHandlers } from '../hooks/useSystemAlertWithHandlers';

type SystemAlertModalBodyProps = SystemAlertWithHandlers & {
  handleDismiss: () => void;
};

export const SystemAlertModalBody = memo<SystemAlertModalBodyProps>(
  function SystemAlertModalBody({
    handleDismiss,
    title,
    description,
    primaryCta,
    secondaryCta,
    isDismissible,
    alertLevel,
    handleViewEvent,
    handlePrimaryPress,
    handleSecondaryPress,
  }: SystemAlertModalBodyProps) {
    const type = alertLevel === 'SYSTEM_ALERT_LEVEL_INFO' ? 'INFO' : 'WARNING';

    return (
      <VisibilityTrigger onVisibleOnce={handleViewEvent}>
        <VStack justifyContent="center" alignItems="center" spacerGap={2}>
          {isDismissible && (
            <Box width="100%" justifyContent="flex-end" testID="dismiss-button">
              <IconButton name="close" onPress={handleDismiss} transparent />
            </Box>
          )}
          <SeverityIcon type={type} size="xl" />
          <TextTitle3 as="h3">{title}</TextTitle3>
          <TextBody as="p">{description}</TextBody>
          <VStack
            width="100%"
            justifyContent="center"
            spacingVertical={2}
            spacerGap={2}
          >
            {primaryCta?.text && (
              <Button
                variant="primary"
                onPress={handlePrimaryPress}
                testID="primary-button"
                block
              >
                {primaryCta.text}
              </Button>
            )}
            {secondaryCta?.text && (
              <Button
                variant="secondary"
                onPress={handleSecondaryPress}
                testID="secondary-button"
                block
              >
                {secondaryCta.text}
              </Button>
            )}
          </VStack>
        </VStack>
      </VisibilityTrigger>
    );
  },
);

const SystemAlertModal = memo<SystemAlertWithHandlers>(
  function SystemAlertModalContent(alert: SystemAlertWithHandlers) {
    const [visible, { toggleOn, toggleOff }] = useToggler(false);

    useEffect(() => {
      if (!visible) {
        toggleOn();
      }
    }, []);

    const handleDismiss = useCallback(() => {
      if (visible) {
        toggleOff();
      }
      if (alert.isDismissible) {
        alert.handleDismissPress();
      }
    }, [alert, toggleOff, visible]);

    return (
      <Modal
        key={alert.id}
        visible={visible}
        width={400}
        onRequestClose={handleDismiss}
        testID="system-alert-modal"
      >
        <ModalBody>
          <SystemAlertModalBody handleDismiss={handleDismiss} {...alert} />
        </ModalBody>
      </Modal>
    );
  },
);

export default memo(SystemAlertModal);

import { useContext, useEffect, useCallback, useMemo } from 'react';
import { useIntl } from 'react-intl';
