import { useCurrencyFormatter } from '@cbhq/common-web/hooks';
import { Amount } from '@cbhq/common-web/types';

import {
  useHasBtcLightningSupport,
  MAX_LENGTH_TO_TRUNCATE,
} from 'components/SendReceive/components/Send/hooks/useHasBtcLightningSupport';
import { sendRedesignStepper } from 'components/SendReceive/SendRedesign/hooks/sendRedesignStepper';
import { getEllipsizedString } from 'components/SendReceive/SendRedesign/steps/utils';
import { SendRedesignTriggerContext } from 'components/SendReceiveTrigger/SendRedesignTriggerContext';
