  AccountHistoryEntryStatus,
  AccountHistoryEntryCategory,
} from 'queries/accountHistoryEntry';

import { useShouldShowVerifiedAddresses } from '../../../SendReceive/SendRedesign/hooks/useShouldShowVerifiedAddresses';
import useUserAttestationsByRecipient from '../../../SendReceive/SendRedesign/steps/SendSelectRecipientStep/hooks/useUserAttestationsByRecipient';
import messages from './messages';
import { TransactionDetailRedesignRow } from './TransactionDetailRedesignRow';
import TransactionStatusTrackerV2, {
  TransactionDetailsType,
} from './TransactionStatusTrackerV2';
import useGetTransactionDetails from './useGetTransactionDetails';
import usePollTransactionDetails, {
  PricePerCoin,
  NetworkInfo,
  TransactionDetailsAssetNetwork,
} from './usePollTransactionDetails';

export type CryptoSendTransactionDetailsTransactionObject = {
  transactionTypename: string;
  transactionAccountId: string;
  defaultRelayId: string;
  transactionUuid: string;
  transactionCryptoAmount: Amount | undefined;
  transactionNativeAmount: Amount | undefined;
  transactionFee: Amount | undefined;
  recipientAddress: string;
  recipientMemoTag?: string;
  transactionCategory: AccountHistoryEntryCategory | null;
  defaultStatus: AccountHistoryEntryStatus;
  defaultTitle: string;
  defaultTransactionHash?: string;
  defaultPricePerCoin?: PricePerCoin;
  assetPlatformName?: string;
  defaultNetworkInfo?: NetworkInfo;
  defaultTransactionUrl?: string;
  transactionCreatedAt: string;
  defaultUndelayRequirement?: (string | null)[];
  defaultDelayedSendDate?: string;
};

type CryptoSendTransactionDetailsContentProps = {
  transaction: CryptoSendTransactionDetailsTransactionObject;
  hasHeader?: boolean;
  givenAssetNetworks?: TransactionDetailsAssetNetwork[];
};

function CryptoSendTransactionDetailsContent({
  transaction,
  hasHeader = false,
  givenAssetNetworks,
}: CryptoSendTransactionDetailsContentProps) {
  const {
    transactionTypename,
    transactionAccountId,
    defaultRelayId,
    transactionUuid,
    transactionCryptoAmount,
    transactionNativeAmount,
    transactionFee,
    recipientAddress,
    recipientMemoTag,
    transactionCategory,
    defaultStatus,
    defaultTitle,
    defaultTransactionHash,
    defaultPricePerCoin,
    assetPlatformName,
    defaultNetworkInfo,
    defaultTransactionUrl,
    transactionCreatedAt,
    defaultUndelayRequirement,
    defaultDelayedSendDate,
  } = transaction;

  const { formatMessage, formatDate, formatTime } = useIntl();
  const toast = useToast();
  const shouldShowVerifiedAddresses = useShouldShowVerifiedAddresses();
  const hasBtcLightingEnabled = useHasBtcLightningSupport();
  const formatAddress = useFormatAddress();
  const { goToStep, currentStep } = useStepper(sendRedesignStepper);
  const { closeMenu } = useContext(SendRedesignTriggerContext);
  const {
    fetchUserAttestations,
    isVerified,
    isLoading: isLoadingVerified,
  } = useUserAttestationsByRecipient();

  const handleAddressCopy = useCallback(() => {
    toast.show(formatMessage(messages.addressCopied), {
      duration: 2000,
    });

    copyToClipboard(recipientAddress);
  }, [formatMessage, toast, recipientAddress]);

  useEffect(() => {
    if (shouldShowVerifiedAddresses) {
      fetchUserAttestations(recipientAddress);
    }
  }, []);

  const toAddress = useMemo(() => {
    const address = recipientAddress;

    if (address.length > MAX_LENGTH_TO_TRUNCATE) {
      return getEllipsizedString(address, 6);
    }

    return address;
  }, [recipientAddress]);

  const formatCurrency = useCurrencyFormatter();

  const getTransactionDetails = useGetTransactionDetails({
    accountId: transactionCryptoAmount?.currency ?? '',
    transactionId: transactionUuid,
  });

  const shouldSkipPolling =
    !!defaultRelayId &&
    !!defaultTitle &&
    !!defaultStatus &&
    defaultStatus !== 'PENDING' &&
    !!defaultTransactionHash &&
    !!defaultPricePerCoin?.value &&
    !!defaultPricePerCoin?.currency &&
    !!defaultNetworkInfo?.networkName &&
    !!defaultNetworkInfo?.networkIconUrl &&
    !!defaultTransactionUrl;

  const pollForAssetNetworks =
    !givenAssetNetworks || givenAssetNetworks.length === 0;

  const {
    transactionRelayId,
    status: transactionStatus,
    transactionTitle,
    transactionHash,
    pricePerCoin,
    networkInfo,
    transactionUrl,
    undelayRequirement,
    delayedSendDate,
    assetNetworks: polledAssetNetworks,
  } = usePollTransactionDetails({
    numIntervals: 600,
    intervalMs: 10000,
    getTransactionDetails,
    defaultRelayId,
    defaultStatus,
    defaultTitle,
    defaultTransactionHash,
    defaultPricePerCoin,
    defaultNetworkInfo,
    defaultTransactionUrl,
    defaultUndelayRequirement,
    defaultDelayedSendDate,
    skipPolling: shouldSkipPolling,
    pollForAssetNetworks,
  });

  const formattedPricePerCoin = useMemo(() => {
    if (pricePerCoin?.currency && pricePerCoin?.value) {
      return formatCurrency({
        amount: pricePerCoin,
        isFiat: true,
      });
    }

    return null;
  }, [formatCurrency, pricePerCoin]);

  const feeLabel = useMemo(() => {
    if (hasBtcLightingEnabled && networkInfo?.networkName === 'Lightning') {
      return formatMessage(messages.processingFee);
    }

    return formatMessage(messages.networkFee);
  }, [formatMessage, hasBtcLightingEnabled, networkInfo?.networkName]);

  const isLightningNetwork = useMemo(() => {
    return networkInfo?.networkName === 'Lightning';
  }, [networkInfo?.networkName]);

  const assetNetworks = pollForAssetNetworks
    ? polledAssetNetworks
    : givenAssetNetworks;

  const formattedCryptoAmount = formatCurrency({
    amount: transactionCryptoAmount,
    isFiat: false,
  });

  const formattedFiatAmount = formatCurrency({
    amount: transactionNativeAmount,
    isFiat: true,
  });

  const formattedFee = formatCurrency({
    amount: transactionFee,
    isFiat: false,
  });

  const formattedHash = formatAddress(transactionHash ?? '');

  const date = useMemo(
    () => new Date(transactionCreatedAt),
    [transactionCreatedAt],
  );

  const formattedDate = formatDate(date, {
    month: 'short',
    day: '2-digit',
    year: 'numeric',
  });

  const formattedTime = formatTime(date, {
    hour: '2-digit',
    minute: '2-digit',
    hour12: true,
  });

  const handleClose = useCallback(() => {
    closeMenu?.();
    if (currentStep === 'transactionDetailsStep') {
      goToStep('amountEntry');
    }
  }, [closeMenu, currentStep, goToStep]);

  const transactionObject: TransactionDetailsType = useMemo(
    () => ({
      typename: transactionTypename,
      transactionStatus,
      category: transactionCategory,
      createdAt: transactionCreatedAt,
      transactionUrl: transactionUrl ?? '',
      undelayRequirement: undelayRequirement ?? [],
      delayedSendDate,
      assetPlatformName,
      networkName: networkInfo?.networkName ?? '',
      networkIconUrl: networkInfo?.networkIconUrl ?? '',
      transactionIds: {
        accountId: transactionAccountId,
        transactionId: transactionUuid,
        transactionRelayId: transactionRelayId ?? '',
      },
    }),
    [
      assetPlatformName,
      delayedSendDate,
      networkInfo?.networkIconUrl,
      networkInfo?.networkName,
      transactionAccountId,
      transactionCategory,
      transactionCreatedAt,
      transactionRelayId,
      transactionStatus,
      transactionTypename,
      transactionUrl,
      transactionUuid,
      undelayRequirement,
    ],
  );

  return (
    <>
      {hasHeader && (
        <HStack
          justifyContent="space-between"
          alignItems="center"
          height={72}
          spacingHorizontal={2}
        >
          <IconButton
            name="close"
            variant="secondary"
            onPress={handleClose}
            transparent
          />
          <TextHeadline as="h1">{transactionTitle}</TextHeadline>
          <Box width={40} height={40} />
        </HStack>
      )}
      <VStack
        spacingBottom={3}
        justifyContent="center"
        alignItems="center"
        testID="CryptoSendTransactionDetails"
      >
        {transactionStatus === 'CANCELED' ? (
          <>
            <StrikeThroughBody as="p" color="foregroundMuted">
              {formattedCryptoAmount}
            </StrikeThroughBody>
            <StrikeThroughTitle as="h2" color="foreground">
              {formattedFiatAmount}
            </StrikeThroughTitle>
          </>
        ) : (
          <>
            <TextBody as="p" color="foregroundMuted">
              {formattedCryptoAmount}
            </TextBody>
            <TextTitle2 as="h2" color="foreground">
              {formattedFiatAmount}
            </TextTitle2>
          </>
        )}
      </VStack>
      <Divider />
      <VStack spacingBottom={2} spacingHorizontal={3}>
        <TransactionDetailRedesignRow
          title={formatMessage(messages.to)}
          detail={
            <Pressable background="transparent" onPress={handleAddressCopy}>
              {isLoadingVerified ? (
                <VStack alignItems="flex-end">
                  <Fallback height={20} width={150} />
                </VStack>
              ) : (
                isVerified && (
                  <VStack alignItems="flex-end">
                    <HStack spacerGap={0.5} alignItems="center">
                      <TextBody as="p" align="end" color="foreground">
                        {formatMessage(messages.verifiedWallet)}
                      </TextBody>
                      <Icon name="circleCheckmark" size="xs" color="primary" />
                    </HStack>
                  </VStack>
                )
              )}
              {
                <TextBody as="p" align="end" color="foregroundMuted">
                  {toAddress}
                </TextBody>
              }
            </Pressable>
          }
          wrapDetail
          spacingBottom={0}
        />
        {recipientMemoTag && (
          <TransactionDetailRedesignRow
            title={formatMessage(messages.memoTag)}
            detail={recipientMemoTag ?? ''}
          />
        )}
        {formattedPricePerCoin && (
          <TransactionDetailRedesignRow
            title={formatMessage(messages.price)}
            detail={formattedPricePerCoin}
          />
        )}
        {networkInfo?.networkName && (
          <TransactionDetailRedesignRow
            title={formatMessage(messages.network)}
            detail={networkInfo.networkName}
            detailMediaSource={networkInfo?.networkIconUrl ?? ''}
          />
        )}
        <TransactionDetailRedesignRow
          title={feeLabel}
          detail={`~${formattedFee}`}
        />
        {transactionHash && (
          <TransactionDetailRedesignRow
            title={formatMessage(messages.transactionHash)}
            detail={formattedHash}
          />
        )}
        <TransactionDetailRedesignRow
          title={formatMessage(messages.date)}
          detail={`${formattedTime} – ${formattedDate}`}
          spacingBottom={0}
        />
      </VStack>
      <Divider />
      <TransactionStatusTrackerV2
        transaction={transactionObject}
        assetNetworks={assetNetworks}
        isLightningNetwork={isLightningNetwork}
        handleClose={handleClose}
      />
    </>
  );
}

