type Props = {
  transaction: AccountHistoryEntry;
  legalFullName?: string;
  accountId?: string;
  handleTaxInfo: (value: string) => void;
};

type TaxDetail = {
  name: string;
  amount: {
    value: string;
    currency: string;
  };
};

function TransactionDetails({
  legalFullName,
  transaction,
  accountId = '',
  handleTaxInfo,
}: Props) {
  const intl = useIntl();
  const { formatMessage } = intl;
  const hasTransactionDetailsSplitFeeFlag = useFeature(
    '2023.oct.transaction_details_split_fee',
  );
  const shouldUseSplitFeeEntries = useMemo(() => {
    return (
      (transaction.details?.__typename === 'BuyDetails' ||
        transaction.details?.__typename === 'SellDetails') &&
      hasTransactionDetailsSplitFeeFlag
    );
  }, [hasTransactionDetailsSplitFeeFlag, transaction.details?.__typename]);

  const transactionUrl = (() => {
    if (
      transaction.details?.__typename ===
      'RetailUnsupportedAssetRecoveryDetails'
    ) {
      return transaction.details.recoveryTransactionUrl;
    }

    return transaction.details?.__typename === 'CryptoReceiveDetails' ||
      transaction.details?.__typename === 'CryptoSendDetails'
      ? transaction.details.transactionUrl
      : null;
  })();

  const isSubscriptionRebate =
    transaction.details?.__typename === 'SubscriptionRebateDetails';
  const isMgxBuyCategory = transaction?.category === 'RETAIL_MGX_DEX_BUY';

  const tagName = transaction.viewerAsset?.asset?.destinationTag?.name;

  const [cancelWithdrawal, isCanceling] = useCancelTransaction({
    accountId,
    transactionId: transaction.uuid,
    transactionRelayId: transaction.id,
  });

  const renderAmountDetails = () => {
    const { formatMessage, formatNumber } = intl;

    if (
      (transaction.details?.__typename === 'BuyDetails' ||
        transaction.details?.__typename === 'SellDetails') &&
      transaction.details.nonNullablePricePerCoin
    ) {
      const price = formatNumber(
        Number(transaction.details.nonNullablePricePerCoin.value),
        {
          style: 'currency',
          currency: transaction.details.nonNullablePricePerCoin.currency,
          minimumFractionDigits: getPriceScale(
            parseFloat(transaction.details.nonNullablePricePerCoin.value),
          ),
        },
      );
      return formatMessage(messages.pricePerCoin, {
        price,
        currency: transaction.amount?.currency,
      });
    }

    if (
      transaction.details?.__typename === 'ConvertDetails' &&
      transaction.details.pricePerCoin
    ) {
      const price = formatNumber(
        Number(transaction.details.pricePerCoin.value),
        {
          style: 'currency',
          currency: transaction.details.pricePerCoin.currency,
          minimumFractionDigits: getPriceScale(
            parseFloat(transaction.details.pricePerCoin.value),
          ),
        },
      );
      return formatMessage(messages.pricePerCoin, {
        price,
        currency: transaction.amount?.currency,
      });
    }

    if (
      transaction.amount?.currency !== transaction.nativeAmount?.currency &&
      !(
        transaction.details?.__typename === 'ConvertDetails' &&
        transaction.details.hideNativeAmount
      )
    ) {
      const amount = formatNumber(
        Math.abs(Number(transaction.nativeAmount.value)),
        {
          style: 'currency',
          currency: transaction.nativeAmount.currency,
        },
      );

      return `≈ ${amount}`;
    }

    if (
      isMgxBuyCategory &&
      transaction.details?.__typename === 'RetailMGXBuyDetails'
    ) {
      const price = transaction.details.pricePerCoin ?? {
        value: (
          Number(transaction.nativeAmount.value) /
          Number(transaction.amount.value)
        ).toString(),
        currency: transaction.nativeAmount.value,
      };
      const formattedPrice = formatNumber(Number(price.value), {
        style: 'currency',
        currency: price.currency,
        minimumFractionDigits: getPriceScale(parseFloat(price.value)),
      });

      return formatMessage(messages.pricePerCoin, {
        price: formattedPrice,
        currency: price.currency,
      });
    }

    return null;
  };

  const sendToFromLabel = useMemo(() => {
    if (transaction.details?.__typename === 'CryptoSendDetails') {
      return transaction.details.cryptoSendRecipient.address;
    }
    if (transaction.details?.__typename === 'UserSendDetails') {
      return transaction.details.recipient;
    }
    if (transaction.details?.__typename === 'UserReceiveDetails') {
      return transaction.details.from;
    }
  }, [transaction]);

  const taxLabelText: Record<string, string> = useMemo(
    () => ({
      INDIA_WITHHOLDING: formatMessage(messages.labelsTds),
      AUSTRALIA_GST: formatMessage(messages.labelsGst),
      SINGAPORE_GST: formatMessage(messages.labelsGst),
    }),
    [formatMessage],
  );

  const renderSendDetails = () => {
    if (
      transaction.category === 'USER_RECEIVE' ||
      transaction.category === 'CRYPTO_RECEIVE'
    ) {
      return (
        <InfoSection flexDirection="column" justifyContent="space-between">
          {sendToFromLabel && (
            <Item
              flexGrow={1}
              flexShrink={1}
              flexBasis="auto"
              justifyContent="space-between"
            >
              <ItemTitle>{formatMessage(messages.from)}</ItemTitle>
              <ItemInfo>{sendToFromLabel}</ItemInfo>
            </Item>
          )}
          {renderNote()}
          {renderPricePerCoin()}
          {transaction.details?.__typename === 'CryptoReceiveDetails' &&
            transaction.details?.networkInfo && (
              <Item
                flexGrow={1}
                flexShrink={1}
                flexBasis="auto"
                justifyContent="space-between"
              >
                <ItemTitle>{formatMessage(messages.labelsnetwork)}</ItemTitle>
                <ItemInfo>
                  <HStack alignItems="center" spacerGap={1}>
                    <RemoteImage
                      width={16}
                      height={16}
                      source={
                        transaction.details?.networkInfo?.networkIconUrl ?? ''
                      }
                    ></RemoteImage>
                    {transaction.details?.networkInfo?.networkName}
                  </HStack>
                </ItemInfo>
              </Item>
            )}
          {transactionUrl && (
            <Item
              flexGrow={1}
              flexShrink={1}
              flexBasis="auto"
              justifyContent="space-between"
            >
              <ItemTitle>{transaction.subtitle}</ItemTitle>
              <ItemInfo>
                <a
                  href={transactionUrl}
                  target="_blank"
                  rel="noopener noreferrer external"
                >
                  {formatMessage(messages.viewTransaction)}
                </a>
              </ItemInfo>
            </Item>
          )}
        </InfoSection>
      );
    } else if (
      (transaction.category === 'CRYPTO_SEND' ||
        transaction.category === 'PHONE_SEND' ||
        transaction.category === 'EMAIL_SEND') &&
      sendToFromLabel
    ) {
      return (
        <InfoSection flexDirection="column" justifyContent="space-between">
          <Item
            flexGrow={1}
            flexShrink={1}
            flexBasis="auto"
            justifyContent="space-between"
          >
            <ItemTitle>{formatMessage(messages.to)}</ItemTitle>
            <ItemInfo>{sendToFromLabel}</ItemInfo>
          </Item>
          {transaction.details?.__typename === 'CryptoSendDetails' &&
            tagName &&
            transaction.details.cryptoSendRecipient.destinationTag && (
              <Item
                flexGrow={1}
                flexShrink={1}
                flexBasis="auto"
                justifyContent="space-between"
              >
                <ItemTitle>{tagName}</ItemTitle>
                <ItemInfo>
                  {transaction.details.cryptoSendRecipient.destinationTag}
                </ItemInfo>
              </Item>
            )}
          {renderNote()}
          {renderPricePerCoin()}
          {transaction.details?.__typename === 'CryptoSendDetails' && (
            <>
              {transaction.details?.networkInfo && (
                <Item
                  flexGrow={1}
                  flexShrink={1}
                  flexBasis="auto"
                  justifyContent="space-between"
                >
                  <ItemTitle>{formatMessage(messages.labelsnetwork)}</ItemTitle>
                  <ItemInfo>
                    <HStack alignItems="center" spacerGap={1}>
                      <RemoteImage
                        width={16}
                        height={16}
                        source={
                          transaction.details?.networkInfo?.networkIconUrl ?? ''
                        }
                      ></RemoteImage>
                      {transaction.details?.networkInfo?.networkName}
                    </HStack>
                  </ItemInfo>
                </Item>
              )}
              <Item
                flexGrow={1}
                flexShrink={1}
                flexBasis="auto"
                justifyContent="space-between"
              >
                <ItemTitle>
                  {formatMessage(messages.labelstransactionFee)}
                </ItemTitle>
                <ItemInfo>
                  {`${transaction.details.fee.value} ${transaction.details.fee.currency}`}
                </ItemInfo>
              </Item>
            </>
          )}
          {transaction.details?.__typename === 'CryptoSendDetails' && !tagName && (
            <Item
              flexGrow={1}
              flexShrink={1}
              flexBasis="auto"
              justifyContent="space-between"
            >
              <ItemTitle>
                {formatMessage(messages.labelsconfirmations)}
              </ItemTitle>
              <ItemInfo>{transaction.details.confirmations}</ItemInfo>
            </Item>
          )}
          {transactionUrl && (
            <Item
              flexGrow={1}
              flexShrink={1}
              flexBasis="auto"
              justifyContent="space-between"
            >
              <ItemTitle>{formatMessage(messages.labelstransaction)}</ItemTitle>
              <ItemInfo>
                <a
                  href={transactionUrl}
                  target="_blank"
                  rel="noopener noreferrer external"
                >
                  {formatMessage(messages.viewTransaction)}
                </a>
              </ItemInfo>
            </Item>
          )}
        </InfoSection>
      );
    }

    return null;
  };

  const renderPricePerCoin = () => {
    if (
      !transaction.details ||
      transaction.details.__typename === 'FiatDepositDetails' ||
      transaction.details.__typename === 'FiatWithdrawalDetails' ||
      transaction.details.__typename === 'OrderDetails' ||
      transaction.details.__typename === 'AdvancedTradeDetails' ||
      transaction.details.__typename === 'SubscriptionRebateDetails' ||
      transaction.details.__typename === '%other'
    ) {
      return null;
    }
    const pricePerCoin =
      transaction.details?.__typename === 'BuyDetails' ||
      transaction.details?.__typename === 'SellDetails'
        ? transaction.details.nonNullablePricePerCoin
        : transaction.details.pricePerCoin;

    const isSend =
      transaction.details?.__typename === 'CryptoSendDetails' ||
      transaction.details?.__typename === 'UserSendDetails';

    const isReceive =
      transaction.details?.__typename === 'CryptoReceiveDetails' ||
      transaction.details?.__typename === 'UserReceiveDetails';

    if (!pricePerCoin) {
      return null;
    }

    return (
      <Item
        flexGrow={1}
        flexShrink={1}
        flexBasis="auto"
        justifyContent="space-between"
      >
        <ItemTitle>
          {transaction.amount.currency !== 'USDC' && !isSend && !isReceive ? (
            <Tooltip
              placement="right"
              content={
                <TextBody as="p">
                  {formatMessage(messages.priceExecuted, {
                    link: (str: ReactNode) => [
                      <LinkCds
                        color="primary"
                        to="https://help.coinbase.com/coinbase/trading-and-funding/pricing-and-fees/fees"
                      >
                        {str || ''}
                      </LinkCds>,
                    ],
                  })}
                </TextBody>
              }
            >
              <TrailingIcon
                content={formatMessage(messages.priceUpdated)}
                icon={
                  <Icon
                    name="info"
                    size="xs"
                    color="foregroundMuted"
                    spacingStart={0.5}
                  />
                }
              />
            </Tooltip>
          ) : (
            formatMessage(messages.priceUpdated)
          )}
        </ItemTitle>
        <ItemInfo>
          <FormattedAmount
            amount={pricePerCoin.value}
            currency={pricePerCoin.currency}
            options={{
              minimumFractionDigits: getPriceScale(
                parseFloat(pricePerCoin.value),
              ),
            }}
          />
        </ItemInfo>
      </Item>
    );
  };

  const renderNote = () => {
    let note = '';
    if (
      transaction.details?.__typename === 'CryptoSendDetails' ||
      transaction.details?.__typename === 'UserSendDetails' ||
      transaction.details?.__typename === 'UserReceiveDetails' ||
      transaction.details?.__typename === 'CryptoReceiveDetails'
    ) {
      // @ts-expect-error BE is not currently returning note for Receives but they should
      // once it is, we can get this for free
      note = transaction.details.note;
    } else if (transaction.details?.__typename === 'OrderDetails') {
      note = transaction.details.description;
    }

    if (note) {
      return (
        <Item
          flexGrow={1}
          flexShrink={1}
          flexBasis="auto"
          justifyContent="space-between"
        >
          <ItemTitle>{formatMessage(messages.note)}</ItemTitle>
          <ItemInfo>{note}</ItemInfo>
        </Item>
      );
    }
  };

  const renderRetailUnsupportedAssetRecoveryDetails = () => {
    if (
      transaction.details?.__typename !==
      'RetailUnsupportedAssetRecoveryDetails'
    ) {
      return null;
    }
    return (
      <VStack flexGrow={1} flexShrink={1} flexBasis="auto">
        <InfoSection flexDirection="column" justifyContent="space-between">
          <Item
            flexGrow={1}
            flexShrink={1}
            flexBasis="auto"
            justifyContent="space-between"
          >
            <ItemTitle>{formatMessage(messages.to)}</ItemTitle>
            <ItemInfo>{transaction.details.recoveryTo}</ItemInfo>
          </Item>
          <Item
            flexGrow={1}
            flexShrink={1}
            flexBasis="auto"
            justifyContent="space-between"
          >
            <ItemTitle>{formatMessage(messages.labelscoinbaseFee)}</ItemTitle>
            <ItemInfo>
              {Number(transaction.details?.coinbaseFee?.value) > 0
                ? `${transaction.details?.coinbaseFee?.value} ${transaction.details.coinbaseFee?.currency}`
                : formatMessage(messages.labelfree)}
            </ItemInfo>
          </Item>
          <Item
            flexGrow={1}
            flexShrink={1}
            flexBasis="auto"
            justifyContent="space-between"
          >
            <ItemTitle>
              {formatMessage(messages.labelstransactionFee)}
            </ItemTitle>
            <ItemInfo>
              {Number(transaction.details?.networkFee?.value) > 0
                ? ` ${Number(transaction.details?.networkFee?.value).toFixed(
                    4,
                  )} ${transaction.details.networkFee?.currency}`
                : formatMessage(messages.labelfree)}
            </ItemInfo>
          </Item>
          {transactionUrl && (
            <Item
              flexGrow={1}
              flexShrink={1}
              flexBasis="auto"
              justifyContent="center"
            >
              <ItemInfo>
                <a
                  href={transactionUrl}
                  target="_blank"
                  rel="noopener noreferrer external"
                >
                  {formatMessage(messages.viewTransaction)}
                </a>
              </ItemInfo>
            </Item>
          )}
        </InfoSection>
      </VStack>
    );
  };

  const renderDelayedDetails = () => {
    if (
      !(
        transaction.details?.__typename === 'CryptoSendDetails' ||
        transaction.details?.__typename === 'UserSendDetails'
      ) ||
      transaction.details.delayedSendDate === null
    ) {
      return null;
    }

    const { details } = transaction;
    const displayName =
      details.__typename === 'CryptoSendDetails'
        ? details.cryptoSendRecipient.address
        : details.recipient;

    return (
      <VStack flexGrow={1} flexShrink={1} flexBasis="auto">
        <InfoSection flexDirection="column" justifyContent="space-between">
          <Item
            flexGrow={1}
            flexShrink={1}
            flexBasis="auto"
            justifyContent="space-between"
          >
            <ItemTitle>{formatMessage(messages.to)}</ItemTitle>
            <ItemInfo>{displayName}</ItemInfo>
          </Item>
          <Item
            flexGrow={1}
            flexShrink={1}
            flexBasis="auto"
            justifyContent="space-between"
          >
            <ItemTitle>{formatMessage(messages.clears)}</ItemTitle>
            <ItemInfo>
              <FormattedDate
                value={details.delayedSendDate || ''}
                year="numeric"
                month="long"
                day="2-digit"
                hour="numeric"
                minute="numeric"
              />
            </ItemInfo>
          </Item>
        </InfoSection>
        <ButtonSection>
          <ButtonLink href="/verify-document?facematch=true">
            <StyledButton>
              {formatMessage(messages.labelsaccelerateSend)}
            </StyledButton>
          </ButtonLink>
          <StyledButton
            onClick={cancelWithdrawal}
            type="secondary"
            loading={isCanceling}
          >
            {formatMessage(messages.labelscancelSend)}
          </StyledButton>
        </ButtonSection>
      </VStack>
    );
  };

  const renderFee = (
    value: string,
    currency: string,
    label: React.ReactNode,
  ) => {
    return (
      <Item
        flexGrow={1}
        flexShrink={1}
        flexBasis="auto"
        justifyContent="space-between"
      >
        <ItemTitle>{label}</ItemTitle>
        <ItemInfo>
          <FormattedNumber
            value={Number(value)}
            style="currency"
            currency={currency}
          />
        </ItemInfo>
      </Item>
    );
  };

  const renderFees = () => {
    if (
      transaction.details?.__typename !== 'BuyDetails' &&
      transaction.details?.__typename !== 'SellDetails'
    ) {
      return null;
    }

    const fees = transaction.details?.fees ?? [];

    if (fees.length === 0) {
      return null;
    }

    return (
      <>
        {fees.map(fee => {
          if (fee === null) {
            return null;
          }

          return (
            <Item
              flexGrow={1}
              flexShrink={1}
              flexBasis="auto"
              justifyContent="space-between"
              key={fee.name}
            >
              <ItemTitle>{fee.label}</ItemTitle>
              <ItemInfo>
                <FormattedNumber
                  value={Number(fee.amount.value || '0')}
                  style="currency"
                  currency={fee.amount.currency}
                />
              </ItemInfo>
            </Item>
          );
        })}
      </>
    );
  };

  const renderTaxes = ({ name, amount }: TaxDetail) => {
    if (!Number(amount.value)) return null;

    return (
      <Item
        flexGrow={1}
        flexShrink={1}
        flexBasis="auto"
        justifyContent="space-between"
        key={name}
      >
        <ItemTitle>
          <Box>
            {taxLabelText[name]}
            <HStack
              alignItems="center"
              justifyContent="space-between"
              width="100%"
              testID="tax-info-icon"
              // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
              onClick={() => handleTaxInfo(name)}
            >
              <Spacer horizontal={1} />
              <Icon name="questionMark" size="xs" color="foregroundMuted" />
            </HStack>
          </Box>
        </ItemTitle>
        <ItemInfo>
          <FormattedNumber
            value={Number(amount.value)}
            style="currency"
            currency={amount.currency}
          />
        </ItemInfo>
      </Item>
    );
  };

  const renderTradeDetails = () => {
    if (
      !(
        transaction.details?.__typename === 'BuyDetails' ||
        transaction.details?.__typename === 'SellDetails'
      )
    ) {
      return null;
    }

    const { details } = transaction;
    const recurringPeriod =
      details.__typename === 'BuyDetails' && details.recurringPeriod
        ? // @ts-expect-error recurringPeriod is guaranteed but not typed correctly in GQL
          transactionMessages[details.recurringPeriod.toLowerCase()]
        : null;

    return (
      <InfoSection flexDirection="column" justifyContent="space-between">
        <Item
          flexGrow={1}
          flexShrink={1}
          flexBasis="auto"
          justifyContent="space-between"
        >
          <ItemTitle>{formatMessage(messages.labelsreferenceCode)}</ItemTitle>
          <ItemInfo>
            <TextBody as="p" color="primary" mono>
              {details.referenceCode}
            </TextBody>
          </ItemInfo>
        </Item>
        {renderPricePerCoin()}
        <Item
          flexGrow={1}
          flexShrink={1}
          flexBasis="auto"
          justifyContent="space-between"
        >
          <ItemTitle>{formatMessage(messages.labelspaymentMethod)}</ItemTitle>
          <ItemInfo>{details.paymentMethod}</ItemInfo>
        </Item>
        {!shouldUseSplitFeeEntries &&
          renderFee(
            details.fee.value,
            details.fee.currency,
            formatMessage(messages.labelscoinbaseFee),
          )}
        {!shouldUseSplitFeeEntries &&
          transaction.details?.taxDetails?.map(renderTaxes)}
        {shouldUseSplitFeeEntries && renderFees()}
        <Item
          flexGrow={1}
          flexShrink={1}
          flexBasis="auto"
          justifyContent="space-between"
        >
          <ItemTitle>{formatMessage(messages.labelssubtotal)}</ItemTitle>
          <ItemInfo>
            <FormattedNumber
              value={Number(details.subtotal.value)}
              style="currency"
              currency={details.subtotal.currency}
            />
          </ItemInfo>
        </Item>
        <Item
          flexGrow={1}
          flexShrink={1}
          flexBasis="auto"
          justifyContent="space-between"
        >
          <ItemTitle>{formatMessage(messages.labelstotal)}</ItemTitle>
          <ItemInfo>
            <FormattedNumber
              value={Number(details.total.value)}
              style="currency"
              currency={details.total.currency}
            />
          </ItemInfo>
        </Item>
        {recurringPeriod && (
          <Item
            flexGrow={1}
            flexShrink={1}
            flexBasis="auto"
            justifyContent="space-between"
          >
            <ItemTitle>
              <FormattedMessage
                data-testid="recurring-label"
                id={`${i18nKey}.labels.recurring`}
                defaultMessage="Recurring"
                description="Label for a recurring transaction (e.g. 'Recurring - Weekly')"
              />
            </ItemTitle>
            <ItemInfo>{formatMessage(recurringPeriod)}</ItemInfo>
          </Item>
        )}
      </InfoSection>
    );
  };

  const renderTradeHelp = () => {
    return (
      <HelpSection width="100%" flexDirection="column">
        <VStack justifyContent="center">
          <HelpContent flexDirection="column">
            <VStack>
              <TextBody as="p">
                <FormattedMessage
                  id={`${i18nKey}.labels.faq`}
                  defaultMessage="Frequently asked questions"
                  description="Label for Frequently asked questions section"
                />
              </TextBody>
              <HelpQuestion justifyContent="center">
                <a
                  href="https://support.coinbase.com/customer/en/portal/articles/2489501-how-long-does-a-purchase-or-deposit-take-to-complete-"
                  target="_blank"
                  rel="noopener noreferrer"
                >
                  <FormattedMessage
                    id={`${i18nKey}.labels.questionPayout`}
                    defaultMessage="How long does a purchase or deposit take to complete?"
                    description="FAQ link title"
                  />
                </a>
              </HelpQuestion>
              <HelpQuestion justifyContent="center">
                <a
                  href="https://support.coinbase.com/customer/en/portal/articles/1826294-how-are-fees-applied-when-i-buy-or-sell-digital-currency-?b_id=13521"
                  target="_blank"
                  rel="noopener noreferrer"
                >
                  <FormattedMessage
                    id={`${i18nKey}.labels.questionFees`}
                    defaultMessage="How are fees applied when I buy or sell cryptocurrency?"
                    description="FAQ link title"
                  />
                </a>
              </HelpQuestion>
              {transaction.category === 'BUY' && (
                <HelpQuestion justifyContent="center">
                  <a
                    href="https://support.coinbase.com/customer/en/portal/articles/1403864-cancelling-a-purchase?b_id=13521"
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    <FormattedMessage
                      id={`${i18nKey}.labels.questionCancel`}
                      defaultMessage="Can I cancel my purchase?"
                      description="FAQ link title"
                    />
                  </a>
                </HelpQuestion>
              )}
            </VStack>
          </HelpContent>
        </VStack>
      </HelpSection>
    );
  };

  const renderTransferDetails = () => {
    if (transaction.details?.__typename === 'TransferFromDetails') {
      return (
        <InfoSection flexDirection="column" justifyContent="space-between">
          {renderPricePerCoin()}
          <Item
            flexGrow={1}
            flexShrink={1}
            flexBasis="auto"
            justifyContent="space-between"
          >
            <ItemTitle>{formatMessage(messages.from)}</ItemTitle>
            <ItemInfo>
              <Link to={accountUrl(transaction.details.fromUrl)}>
                {transaction.details.from}
              </Link>
            </ItemInfo>
          </Item>
        </InfoSection>
      );
    } else if (transaction.details?.__typename === 'TransferToDetails') {
      return (
        <InfoSection flexDirection="column" justifyContent="space-between">
          {renderPricePerCoin()}
          <Item
            flexGrow={1}
            flexShrink={1}
            flexBasis="auto"
            justifyContent="space-between"
          >
            <ItemTitle>{formatMessage(messages.to)}</ItemTitle>
            <ItemInfo>
              <Link to={accountUrl(transaction.details.toUrl)}>
                {transaction.details.to}
              </Link>
            </ItemInfo>
          </Item>
        </InfoSection>
      );
    }

    return null;
  };

  const renderDepositWithdrawalDetails = () => {
    if (
      transaction.details?.__typename === 'FiatDepositDetails' ||
      transaction.details?.__typename === 'FiatWithdrawalDetails'
    ) {
      const isPixTransaction =
        transaction?.amount?.currency === 'BRL' &&
        !!transaction.details?.pixDetails?.pixTransactionId;

      if (isPixTransaction) {
        return (
          <PixTransactionDetails
            transaction={transaction}
            legalFullName={legalFullName}
            extraMessages={{
              labelsLegalFullName: messages.labelsLegalFullName,
              labelsreferenceCode: messages.labelsreferenceCode,
              from: messages.from,
              to: messages.to,
            }}
          />
        );
      }

      return (
        <>
          {!!transaction.details?.transactionReferenceCode && (
            <InfoSection flexDirection="column" justifyContent="space-between">
              <Item
                flexGrow={1}
                flexShrink={1}
                flexBasis="auto"
                justifyContent="space-between"
              >
                <ItemTitle>
                  {formatMessage(messages.labelsreferenceCode)}
                </ItemTitle>
                <ItemInfo>
                  {transaction.details.transactionReferenceCode}
                </ItemInfo>
              </Item>
            </InfoSection>
          )}
          <InfoSection flexDirection="column" justifyContent="space-between">
            <Item
              flexGrow={1}
              flexShrink={1}
              flexBasis="auto"
              justifyContent="space-between"
            >
              <ItemTitle>
                {transaction.details?.__typename === 'FiatDepositDetails'
                  ? formatMessage(messages.from)
                  : formatMessage(messages.to)}
              </ItemTitle>
              <ItemInfo>
                {transaction.details?.__typename === 'FiatDepositDetails'
                  ? transaction.details.from
                  : transaction.details.to}
              </ItemInfo>
            </Item>
          </InfoSection>
        </>
      );
    }
    return null;
  };

  const renderRequestDetails = () => {
    if (transaction.details?.__typename === 'RequestDetails') {
      return (
        <VStack flexGrow={1} flexShrink={1} flexBasis="auto">
          <InfoSection flexDirection="column" justifyContent="space-between">
            <Item
              flexGrow={1}
              flexShrink={1}
              flexBasis="auto"
              justifyContent="space-between"
            >
              <ItemTitle>
                <ItemTitle>
                  {transaction.details.isFrom
                    ? formatMessage(messages.from)
                    : formatMessage(messages.to)}
                </ItemTitle>
              </ItemTitle>
              <ItemInfo>{transaction.details.otherUser}</ItemInfo>
            </Item>
          </InfoSection>
        </VStack>
      );
    }

    return null;
  };

  const renderMerchantOrderDetails = () => {
    if (transaction.details?.__typename === 'OrderDetails') {
      return (
        <VStack flexGrow={1} flexShrink={1} flexBasis="auto">
          <InfoSection flexDirection="column" justifyContent="space-between">
            {transaction.details.to && (
              <Item
                flexGrow={1}
                flexShrink={1}
                flexBasis="auto"
                justifyContent="space-between"
              >
                <ItemTitle>
                  <ItemTitle>
                    <FormattedMessage
                      id={`${i18nKey}.labels.merchant`}
                      defaultMessage="Merchant"
                      description="Merchant name label"
                    />
                  </ItemTitle>
                </ItemTitle>
                <ItemInfo>{transaction.details.name}</ItemInfo>
              </Item>
            )}
            <Item
              flexGrow={1}
              flexShrink={1}
              flexBasis="auto"
              justifyContent="space-between"
            >
              <ItemTitle>
                <ItemTitle>
                  <FormattedMessage
                    id={`${i18nKey}.labels.orderDetails`}
                    defaultMessage="Details"
                    description="Order details label"
                  />
                </ItemTitle>
              </ItemTitle>
              <ItemInfo>
                <div>{transaction.details.description}</div>
              </ItemInfo>
            </Item>
            <Item
              flexGrow={1}
              flexShrink={1}
              flexBasis="auto"
              justifyContent="space-between"
            >
              <ItemTitle>
                <ItemTitle>
                  <FormattedMessage
                    id={`${i18nKey}.labels.orderLabel`}
                    defaultMessage="Order"
                    description="Order number title"
                  />
                </ItemTitle>
              </ItemTitle>
              <ItemInfo>
                <div>{transaction.details.code} (</div>
              </ItemInfo>
            </Item>
          </InfoSection>
        </VStack>
      );
    }

    return null;
  };

  const renderVaultWithdrawalDetails = () => {
    if (
      transaction.details?.__typename === 'VaultWithdrawalToDetails' ||
      transaction.details?.__typename === 'VaultWithdrawalFromDetails'
    ) {
      return (
        <ButtonSection>
          <ButtonLink href={transaction.details.detailsUrl}>
            <StyledButton size="large">
              {formatMessage(messages.viewDetails)}
            </StyledButton>
          </ButtonLink>
        </ButtonSection>
      );
    }

    return null;
  };

  const renderMgxBuyDetails = () => {
    const { details } = transaction;
    if (details?.__typename === 'RetailMGXBuyDetails') {
      return (
        <InfoSection flexDirection="column" justifyContent="space-between">
          {renderPricePerCoin()}
          <Item
            flexGrow={1}
            flexShrink={1}
            flexBasis="auto"
            justifyContent="space-between"
          >
            <ItemTitle>{formatMessage(messages.labelsnetwork)}</ItemTitle>
            <ItemInfo>{details.networkInfo?.networkName}</ItemInfo>
          </Item>
          {details.networkFee
            ? renderFee(
                details.networkFee.value,
                details.networkFee.currency,
                formatMessage(messages.labelsnetworkFee),
              )
            : null}
          {details.coinbaseFee
            ? renderFee(
                details.coinbaseFee.value,
                details.coinbaseFee.currency,
                formatMessage(messages.labelscoinbaseFee),
              )
            : null}

          <Item
            flexGrow={1}
            flexShrink={1}
            flexBasis="auto"
            justifyContent="space-between"
          >
            <ItemTitle>{formatMessage(messages.labelssubtotal)}</ItemTitle>
            <ItemInfo>
              <FormattedNumber
                value={Number(details.subTotal?.value)}
                style="currency"
                currency={details.subTotal?.currency}
              />
            </ItemInfo>
          </Item>
          <Item
            flexGrow={1}
            flexShrink={1}
            flexBasis="auto"
            justifyContent="space-between"
          >
            <ItemTitle>{formatMessage(messages.labelstotal)}</ItemTitle>
            <ItemInfo>
              <FormattedNumber
                value={Number(details.nullableTotal?.value)}
                style="currency"
                currency={details.nullableTotal?.currency}
              />
            </ItemInfo>
          </Item>
        </InfoSection>
      );
    }

    return null;
  };

  const renderMgxTradeDetails = () => {
    const { details } = transaction;
    if (details?.__typename === 'RetailMGXTradeDetails') {
      return (
        <InfoSection flexDirection="column" justifyContent="space-between">
          {renderPricePerCoin()}
          <Item
            flexGrow={1}
            flexShrink={1}
            flexBasis="auto"
            justifyContent="space-between"
          >
            <ItemTitle>{formatMessage(messages.labelsnetwork)}</ItemTitle>
            <ItemInfo>{details.networkInfo?.networkName}</ItemInfo>
          </Item>
          {details.networkFee
            ? renderFee(
                details.networkFee.value,
                details.networkFee.currency,
                formatMessage(messages.labelsnetworkFee),
              )
            : null}
          {details.coinbaseFee
            ? renderFee(
                details.coinbaseFee.value,
                details.coinbaseFee.currency,
                formatMessage(messages.labelscoinbaseFee),
              )
            : null}
        </InfoSection>
      );
    }

    return null;
  };

  const isTrade =
    transaction.details?.__typename === 'BuyDetails' ||
    transaction.details?.__typename === 'SellDetails';
  const isSend =
    transaction.details?.__typename === 'CryptoSendDetails' ||
    transaction.details?.__typename === 'UserSendDetails';

  // Cancel Button is already shown for delayed transactions.
  const isCancelled = transaction.status === 'CANCELED';
  const showCancelButton =
    accountId &&
    !isCancelled &&
    transaction.details?.__typename === 'UserSendDetails' &&
    transaction.details?.cancelable &&
    !transaction.details?.delayedSendDate;

  const isPending = transaction.status === 'PENDING';
  const isOnHold = transaction.status === 'WAITING_FOR_INFORMATION';
  const showConvertTax = transaction.details?.__typename === 'ConvertDetails';

  return (
    <VStack flexGrow={1} flexShrink={1} flexBasis="auto">
      {transaction.amount && (
        <TopContent
          amount={transaction.amount}
          details={renderAmountDetails()}
          icon={<GQLTransactionIcon transaction={transaction} size="large" />}
        />
      )}
      {showConvertTax && (
        <InfoSection flexDirection="column" justifyContent="space-between">
          {transaction.details?.taxDetails?.map(renderTaxes)}
        </InfoSection>
      )}
      {renderDelayedDetails()}
      {renderTradeDetails()}
      {renderMgxBuyDetails()}
      {renderMgxTradeDetails()}
      {isTrade && isPending && renderTradeHelp()}
      {renderSendDetails()}
      {renderTransferDetails()}
      {renderVaultWithdrawalDetails()}
      {renderRequestDetails()}
      {renderMerchantOrderDetails()}
      {renderDepositWithdrawalDetails()}
      {renderRetailUnsupportedAssetRecoveryDetails()}
      {RebateTransactionDetails({ intl, transaction })}
      {!isSubscriptionRebate && (
        <TransactionFooter
          createdAt={transaction.createdAt}
          rightContent={
            <GQLTransactionStatus
              transaction={transaction}
              style={isSend ? 'inline' : 'large'}
            />
          }
        />
      )}
      {isOnHold ? (
        <TransactionProvideInfoButton transactionId={transaction.uuid} />
      ) : null}
      {showCancelButton ? (
        <GQLTransactionCancelButton
          accountId={accountId}
          transactionId={transaction.uuid}
          transactionRelayId={transaction.id}
        />
      ) : null}
    </VStack>
  );
}

