export { TransactionDetails };
export default memo(TransactionDetails);

import { useEffect, useMemo, useState } from 'react';
import { formatDistanceToNowStrict, differenceInHours } from 'date-fns';
import { useIntl } from 'react-intl';

import { Icon } from '@cbhq/cds-web/icons/Icon';
import { HStack, VStack } from '@cbhq/cds-web/layout';
import { Pressable } from '@cbhq/cds-web/system/Pressable';
import { TextBody, TextHeadline } from '@cbhq/cds-web/typography';
import { graphql, useFragment } from '@cbhq/data-layer';

import { useTransactionTransparencyLoggers } from 'components/TransactionList/useTransactionTransparencyLoggers';
import { AccountHistoryEntryStatus } from 'queries/accountHistoryEntry';

import { TransactionStatusTrackerFragment$key } from './__generated__/TransactionStatusTrackerFragment.graphql';
import TransactionStatusIndicator from './TransactionStatusIndicator';
import TransactionStatusTrackerButtonGroup from './TransactionStatusTrackerButtonGroup';
import messages from './transactionStatusTrackerMessages';

const STATUSES: Record<string, object> = {
  COMPLETED: messages.completed,
  FAILED: messages.failed,
  EXPIRED: messages.expired,
  CANCELED: messages.canceled,
  RETURNED: messages.returned,
  PENDING: messages.pending,
  WAITING_FOR_CLEARING: messages.waitingForClearingWithoutContext,
  WAITING_FOR_INFORMATION: messages.delayed,
};

type TransactionStatusTrackerProps = {
  accountHistoryEntryRef: TransactionStatusTrackerFragment$key;
  transactionStatus: AccountHistoryEntryStatus | null;
  transactionUrl?: string;
  hideTransactionUrlButton?: boolean;
  manualOnChainSet?: boolean;
  handleClose?: () => void;
};

function getHelpUrls(locale: string) {
  const pendingTxSupportUrl = `https://help.coinbase.com/${locale}/coinbase/trading-and-funding/sending-or-receiving-cryptocurrency/why-is-my-transaction-pending`;
  const delayedTxSupportUrl = `https://help.coinbase.com/${locale}/contact-us/support-faq/coinbase/what-to-do-if-your-transaction-has-been-delayed`;

  return {
    pendingTxSupportUrl,
    delayedTxSupportUrl,
  };
}

export const LIGHTNING_INVOICE_EXPIRATION_HOURS = 72;

function TransactionStatusTracker({
  accountHistoryEntryRef,
  transactionStatus,
  transactionUrl,
  hideTransactionUrlButton = false,
  manualOnChainSet = false,
  handleClose,
}: TransactionStatusTrackerProps) {
  const transaction = useFragment(
    graphql`
      fragment TransactionStatusTrackerFragment on AccountHistoryEntry {
        id
        uuid
        accountId
        category
        createdAt
        details {
          __typename
          ... on CryptoSendDetails {
            transactionUrl
            delayedSendDate
            networkInfo {
              networkName
              networkIconUrl
            }
            undelayRequirement
          }
          ... on UserSendDetails {
            delayedSendDate
            undelayRequirement
          }
          ... on CryptoReceiveDetails {
            transactionUrl
            networkInfo {
              networkName
              networkIconUrl
            }
          }
        }
      }
    `,
    accountHistoryEntryRef,
  );

  const { locale, formatDate } = useIntl();
  const { pendingTxSupportUrl, delayedTxSupportUrl } = useMemo(
    () => getHelpUrls(locale),
    [locale],
  );

  const isPending = transactionStatus === 'PENDING';
  const isDelayed = transactionStatus === 'WAITING_FOR_CLEARING';
  const isCanceled = transactionStatus === 'CANCELED';
  const isWaitingForInfo = transactionStatus === 'WAITING_FOR_INFORMATION';

  // Shown when user can Accelerate their send by completing undelay requirements (IDV, Scam Quiz)
  const shouldShowAccelerateButton = useMemo(() => {
    if (
      transaction?.details?.__typename === 'CryptoSendDetails' ||
      transaction?.details?.__typename === 'UserSendDetails'
    ) {
      const requirements = transaction?.details?.undelayRequirement;
      const hasRequirements = requirements && requirements.length > 0;
      return {
        showIdvButton:
          hasRequirements && requirements.includes('UNDELAY_REQUIREMENT_IDV'),
        showScamQuizButton:
          hasRequirements &&
          requirements.includes('UNDELAY_REQUIREMENT_SCAM_QUIZ'),
      };
    }
    return {
      showIdvButton: false,
      showScamQuizButton: false,
    };
  }, [transaction?.details]);

  const delayedSendDate = useMemo(() => {
    const delayedString =
      (transaction?.details?.__typename === 'CryptoSendDetails' ||
        transaction?.details?.__typename === 'UserSendDetails') &&
      transaction?.details?.delayedSendDate
        ? new Date(transaction?.details?.delayedSendDate)
        : undefined;

    if (!delayedString) {
      return null;
    }

    const formattedDate = formatDate(delayedString, {
      month: 'short',
      day: 'numeric',
    });

    const formattedTime = formatDate(delayedString, {
      hour: 'numeric',
      minute: 'numeric',
      hour12: true,
    });

    return `${formattedDate} at ${formattedTime}`;
  }, [formatDate, transaction?.details]);

  const isOnChainSendReceive =
    transaction?.details?.__typename === 'CryptoSendDetails' ||
    transaction?.details?.__typename === 'CryptoReceiveDetails' ||
    manualOnChainSet;

  const isLightningNetwork =
    (transaction?.details?.__typename === 'CryptoSendDetails' ||
      transaction?.details?.__typename === 'CryptoReceiveDetails') &&
    transaction?.details?.networkInfo?.networkName === 'Lightning';

  const shouldShowTxUrlButton =
    isOnChainSendReceive &&
    !hideTransactionUrlButton &&
    !isDelayed &&
    !isCanceled &&
    !isLightningNetwork;

  const hasIcon =
    isOnChainSendReceive &&
    transaction?.details?.__typename === 'CryptoSendDetails' &&
    !!transaction?.details?.networkInfo?.networkIconUrl;

  const transactionDate = useMemo(
    () => new Date(transaction.createdAt),
    [transaction.createdAt],
  );

  const { formatMessage } = useIntl();
  const [formattedElapsedTime, setFormattedElapsedTime] = useState(
    formatDistanceToNowStrict(transactionDate),
  );

  const remainingHoursForLightningExpiration =
    LIGHTNING_INVOICE_EXPIRATION_HOURS +
    differenceInHours(transactionDate, new Date());

  const [logWhenStatusIsComplete, setLogWhenStatusIsComplete] = useState(false);

  const { logTxStatusUpdatedToComplete } = useTransactionTransparencyLoggers();

  const transactionStatusMessage = useMemo(() => {
    if (transactionStatus) {
      if (isDelayed) {
        if (
          (transaction?.details?.__typename === 'CryptoSendDetails' ||
            transaction?.details?.__typename === 'UserSendDetails') &&
          delayedSendDate
        ) {
          return formatMessage(messages.waitingForClearingWithContext);
        }

        return formatMessage(messages.waitingForClearingWithoutContext);
      }

      return (
        <TextBody as="p" align="end">
          {STATUSES[transactionStatus] !== undefined
            ? formatMessage(STATUSES[transactionStatus])
            : formatMessage(messages.pending)}
        </TextBody>
      );
    }

    return null;
  }, [
    transactionStatus,
    isDelayed,
    formatMessage,
    transaction?.details?.__typename,
    delayedSendDate,
  ]);

  const transactionIds = useMemo(
    () => ({
      accountId: transaction?.accountId ?? '',
      transactionId: transaction.uuid,
      transactionRelayId: transaction.id,
    }),
    [transaction.accountId, transaction.id, transaction.uuid],
  );

  useEffect(() => {
    if (logWhenStatusIsComplete && transactionStatus === 'COMPLETED') {
      logTxStatusUpdatedToComplete({
        txCategory: transaction?.category ?? null,
      });
    }

    if (transactionStatus !== 'COMPLETED') {
      setLogWhenStatusIsComplete(true);
    }
  }, [transactionStatusMessage]);

  useEffect(() => {
    const interval = setInterval(() => {
      setFormattedElapsedTime(formatDistanceToNowStrict(transactionDate));
    }, 1000);

    return () => {
      clearInterval(interval);
    };
  }, [formattedElapsedTime]);

  return (
    <>
      <VStack
        spacerGap={3}
        spacingVertical={isOnChainSendReceive ? 2 : 3}
        spacingHorizontal={3}
        testID="TransactionStatusTracker"
      >
        <HStack justifyContent="space-between">
          <HStack alignItems="center">
            <TransactionStatusIndicator
              transactionStatus={transactionStatus}
              category={transaction?.category ?? null}
              assetImageUrl={
                hasIcon
                  ? transaction.details?.networkInfo?.networkIconUrl
                  : undefined
              }
            />
            <VStack>
              <TextHeadline as="p" color="foreground">
                {formatMessage(messages.transactionStatusTitle)}
              </TextHeadline>
              {isPending && (
                <TextBody as="p" color="foregroundMuted">
                  {formatMessage(
                    isLightningNetwork
                      ? messages.expiresIn
                      : messages.elapsedTimeTitle,
                  )}
                </TextBody>
              )}
            </VStack>
          </HStack>
          <HStack spacerGap={2} alignItems="center">
            <VStack justifyContent="center" alignItems="flex-end">
              <TextBody as="p" color="foreground">
                {transactionStatusMessage}
              </TextBody>
              {isPending && !isLightningNetwork && (
                <TextBody as="p" color="foregroundMuted">
                  {formattedElapsedTime}
                </TextBody>
              )}
              {isPending && isLightningNetwork && (
                <TextBody as="p" color="foregroundMuted">
                  {formatMessage(messages.timeToExpire, {
                    hour: remainingHoursForLightningExpiration,
                  })}
                </TextBody>
              )}
              {isDelayed && delayedSendDate && (
                <TextBody as="p" color="foregroundMuted">
                  {delayedSendDate}
                </TextBody>
              )}
              {isWaitingForInfo && (
                <TextBody as="p" color="foregroundMuted">
                  {formatMessage(messages.waitingForInformation)}
                </TextBody>
              )}
            </VStack>
            {isPending && (
              <Pressable
                background="transparent"
                to={isPending ? pendingTxSupportUrl : delayedTxSupportUrl}
              >
                <Icon
                  testID="infoIcon"
                  name="info"
                  size="s"
                  color="foregroundMuted"
                />
              </Pressable>
            )}
          </HStack>
        </HStack>
      </VStack>
      <TransactionStatusTrackerButtonGroup
        isLightningNetwork={isLightningNetwork}
        isTransactionDelayed={isDelayed}
        isWaitingForInfo={isWaitingForInfo}
        shouldShowTxUrlButton={shouldShowTxUrlButton}
        shouldShowAccelerateButton={shouldShowAccelerateButton}
        transactionStatus={transactionStatus}
        transactionCategory={transaction?.category ?? null}
        transactionUrl={transactionUrl}
        transactionIds={transactionIds}
        handleClose={handleClose}
      />
    </>
  );
}

export default TransactionStatusTracker;

import { useCallback, useContext, useMemo } from 'react';
