import TransfersWidget from 'components/DepositWithdraw/TransfersWidget/TransfersWidget';
import { TransferType } from 'components/DepositWithdraw/types';
import { QuickAction } from 'components/DynamicQuickActions/hooks/useDynamicQuickActions';
