import { useSendReceiveDefaultParams } from 'components/SendReceive/SendRedesign/hooks/useSendReceiveDefaultParams';
import SendReceiveModal from 'components/SendReceiveModal';
import useModal from 'hooks/useModal';
import {
  addUIComponentEvent,
  UIComponentAnalyticsProps,
} from 'views/Home/utils/Analytics';

import SendTransferListCell from './SendReceiveTransferCell';
import TransferTriggerItemFallback from './TransferTriggerItemFallback';

type Props = {
  accountId: string;
  children: React.ReactNode;
  items: QuickAction[];
  onClick?: (e: React.MouseEvent) => void;
  uicomponent: UIComponentAnalyticsProps;
};

function TransferTriggerContent({
  accountId,
  children,
  items,
  uicomponent,
}: Props) {
  const [selectedValue, setSelectedValue] = useState<string>('');
  const preloadSendReceiveParams = useSendReceiveDefaultParams();

  const { showModal } = useModal();

  const dropdownRef = useRef<DropdownRefProps>(null);

  const trackActionClick = (item: QuickAction) => {
    addUIComponentEvent({
      action: ActionType.click,
      actionSource: 'tray_item',
      componentType: ComponentType.tray,
      triggerPointEventName: 'tray_item_click',
      metadata: {
        description: item.description,
        name: item.name,
        title: item.title,
      },
      ...uicomponent,
    });
  };

  const closeDropdown = () => {
    if (dropdownRef.current !== null) {
      dropdownRef.current?.closeMenu();
    }
  };

  const handleActionPress = (item: QuickAction) => {
    closeDropdown();
    trackActionClick(item);

    switch (item.name) {
      case 'send':
      case 'receive': {
        markStep('receive_loaded');

        showModal(
          <SendReceiveModal
            defaultTab={item.name}
            entryPoint="global"
            queryVariables={preloadSendReceiveParams}
          />,
        );
        break;
      }

      case 'cash_in':
      case 'cash_out': {
        markStep(
          item.name === 'cash_in'
            ? 'navigate_to_fiat_deposit_modal'
            : 'navigate_to_fiat_withdrawal_modal',
        );
        showModal(
          <TransfersWidget
            accountId={accountId}
            defaultTab={
              item.name === 'cash_in'
                ? TransferType.DEPOSIT
                : TransferType.WITHDRAW
            }
            entryPoint="transferTray"
            topAligned
            modalStyle={{
              position: 'fixed',
              top: `${HEADER_BAR_DEFAULT_HEIGHT_DESKTOP_V2}px`,
              right: '180px',
              margin: 0,
            }}
          />,
        );
        break;
      }

      default: {
        break;
      }
    }
  };

  return (
    <Dropdown
      content={
        <VStack>
          {items.map(item => {
            return (
              <ErrorBoundary
                key={item.name + 'boundary'}
                // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                fallback={props => (
                  <TransferTriggerItemFallback
                    {...props}
                    type={item.name as 'send' | 'receive'}
                    media={
                      <IconButton
                        disabled
                        name={item.iconName}
                        variant="secondary"
                      />
                    }
                  />
                )}
                owner="feed-and-home"
                context="transfer-trigger"
              >
                {item.name === 'send' || item.name === 'receive' ? (
                  <SendTransferListCell
                    as="li"
                    description={item.description}
                    key={item.name}
                    media={
                      <IconButton name={item.iconName} variant="secondary" />
                    }
                    // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                    onPress={() => handleActionPress(item)}
                    title={item.title}
                    queryVariables={preloadSendReceiveParams}
                  />
                ) : (
                  <ListCell
                    as="li"
                    description={item.description}
                    key={item.name}
                    media={
                      <IconButton name={item.iconName} variant="secondary" />
                    }
                    // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                    onPress={() => handleActionPress(item)}
                    title={item.title}
                  />
                )}
              </ErrorBoundary>
            );
          })}
        </VStack>
      }
      enableMobileModal
      onChange={setSelectedValue}
      ref={dropdownRef}
      showOverlay
      maxHeight={480}
      value={selectedValue}
      testID="transfer-trigger-dropdown"
    >
      {children}
    </Dropdown>
  );
}

function TransferTrigger(props: Props) {
  return <TransferTriggerContent {...props} />;
}

