type Props = {
  onClose: () => void;
  transactionId?: string;
  transferIdem: string;
};

export const InputStep = memo(function InputStep({
  onClose,
  transactionId,
  transferIdem,
}: Props) {
  const generateContactNickname = useGenerateContactNickname();
  const { formatMessage } = useIntl();
  const { showModal } = useModal();
  const { goBack, goToStep } = useStepper(travelRuleReceiveOnHoldStepper);
  const { showErrorToast } = useToasts();
  const [fulfillReceiveRequirements, isSubmitting] =
    useFulfillReceiveRequirements();

  // Form data state
  const [showOriginatorName, setShowOriginatorName] = useState(false);
  const [originatorName, setOriginatorName] = useState('');
  const [showOriginatorCountry, setShowOriginatorCountry] = useState(false);
  const [originatorCountry, setOriginatorCountry] = useState('');
  const [currentContactId, setCurrentContactId] = useState<string | undefined>(
    undefined,
  );

  // Fetch initial field requirements & transaction data
  const query = useLazyLoadQuery<InputStepQuery>(
    graphql`
      query InputStepQuery($transferIdem: Uuid!) {
        viewer {
          receiveRequirements(transferIdem: $transferIdem) {
            missingFields {
              options
            }
            displayText
            learnMoreUrl
            transactionInformation {
              amount {
                currency
                value
              }
              network
              iconUrl
              senderAddress
              transactionHash
              transactionUrl
            }
          }
          skipSaveTravelRuleInfoInContactsNetworks
        }
        ...useSendReceiveContactByAddressFragment
      }
    `,
    {
      transferIdem,
    },
  );
  const receiveRequirements = query.viewer?.receiveRequirements;

  // Network and address of the sender for the RECEIVE transaction
  const transactionNetwork =
    receiveRequirements?.transactionInformation?.network;
  const transactionSenderAddress =
    receiveRequirements?.transactionInformation?.senderAddress;

  // List of networks where we shouldn't autosave travel rule infos
  const skipSaveTravelRuleInfoInContactsNetworks = useMemo(() => {
    return query.viewer?.skipSaveTravelRuleInfoInContactsNetworks ?? [];
  }, [query.viewer?.skipSaveTravelRuleInfoInContactsNetworks]);

  const isPrefillTravelRuleEligible = useIsPrefillTravelRuleEligible();

  // Contact matched with the sender address
  const contact = useSendReceiveContactByAddress(
    query,
    transactionSenderAddress ?? '',
  );

  // IDs of the matched contact and matched contact address
  const contactId = contact?.uuid;
  const addressEntry = (contact?.blockchainAddresses ?? []).find(
    blockchainAddressEntry =>
      blockchainAddressEntry?.address === transactionSenderAddress,
  );
  const contactAddressId = addressEntry?.uuid;

  const [createSendReceiveContact, isCreatingSendReceiveContact] =
    useCreateSendReceiveContact();
  const [updateSendReceiveContact, isUpdatingSendReceiveContact] =
    useUpdateSendReceiveContact();

  const autoSaveContact = useCallback(async () => {
    // Skip auto-saving if user is not eligible for prefilling travel rule infos
    if (!isPrefillTravelRuleEligible) {
      return;
    }
    // Skip auto-saving if transaction information is not available
    if (!transactionNetwork || !transactionSenderAddress) {
      return;
    }
    // Skip auto-saving if we shouldn't auto-save for the respective transaction network
    if (skipSaveTravelRuleInfoInContactsNetworks.includes(transactionNetwork)) {
      return;
    }
    // Skip auto-saving if beneficiary name is not available
    if (originatorName.length === 0) {
      return;
    }

    const nickname = generateContactNickname(
      originatorName,
      transactionSenderAddress,
    );
    const travelRuleParams = {
      nickname,
      address: transactionSenderAddress,
      travelRules: {
        walletType: 'WALLET_TYPE_UNSPECIFIED' as TravelRuleWalletType,
        name: originatorName.length > 0 ? originatorName : undefined,
        country: originatorCountry.length > 0 ? originatorCountry : undefined,
      },
    };

    if (currentContactId) {
      // If contact UUID is already available, we will just update the respective contact entry
      // instead of creating a new contact entry
      try {
        await updateSendReceiveContact(
          currentContactId,
          contactAddressId ?? undefined,
          travelRuleParams,
        );
      } catch (err) {
        // Since this is auto-save flow, we will fail silently here
        // Error tracking has already been handled by 'updateSendReceiveContact' itself.
      }
    } else {
      // Create a new contact entry if there's no existing contact
      // containing the sender address
      try {
        const uuid = await createSendReceiveContact(travelRuleParams);
        if (uuid !== null) {
          setCurrentContactId(uuid);
        }
      } catch (err) {
        // Since this is auto-save flow, we will fail silently here
        // Error tracking has already been handled by 'createSendReceiveContact' itself.
      }
    }
  }, [
    currentContactId,
    isPrefillTravelRuleEligible,
    transactionNetwork,
    transactionSenderAddress,
    skipSaveTravelRuleInfoInContactsNetworks,
    originatorName,
    originatorCountry,
    contactAddressId,
    createSendReceiveContact,
    updateSendReceiveContact,
    generateContactNickname,
  ]);

  useEffect(() => {
    setCurrentContactId(contactId ?? undefined);
  }, [contactId]);

  // Decide which fields to be prompted to the user
  useEffect(() => {
    if (receiveRequirements?.missingFields) {
      // If there is no missing requirement fields,
      // we will just pop the modal
      if (receiveRequirements.missingFields.length === 0) {
        onClose();
        return;
      }

      for (const missingField of receiveRequirements.missingFields) {
        if (missingField?.options) {
          for (const option of missingField.options) {
            switch (option) {
              case 'FIELD_ORIGINATOR_NAME':
                setShowOriginatorName(true);
                break;
              case 'FIELD_ORIGINATOR_COUNTRY':
                setShowOriginatorCountry(true);
                break;
              default:
                break;
            }
          }
        }
      }
    }
  }, [
    receiveRequirements?.missingFields,
    setShowOriginatorName,
    setShowOriginatorCountry,
  ]);

  // Check if field values are valid
  const isOriginatorNameFieldValid = useMemo(
    () => !showOriginatorName || originatorName.length > 0,
    [showOriginatorName, originatorName],
  );
  const isOriginatorCountryFieldValid = useMemo(
    () => !showOriginatorCountry || originatorCountry.length > 0,
    [showOriginatorCountry, originatorCountry],
  );
  const isValid = useMemo(
    () => isOriginatorNameFieldValid && isOriginatorCountryFieldValid,
    [isOriginatorNameFieldValid, isOriginatorCountryFieldValid],
  );

  const handleOriginatorNameInputChange = useCallback(
    (event: React.ChangeEvent<HTMLInputElement>) => {
      setOriginatorName(event.target.value);
    },
    [setOriginatorName],
  );

  // Handle form submit
  const handleSubmitButtonPress = useCallback(async () => {
    // Auto-save contact entry with inputted travel rule information
    await autoSaveContact();

    fulfillReceiveRequirements({
      variables: {
        input: {
          transferIdem,
          collectionData: {
            ...(showOriginatorName ? { originatorName } : {}),
            ...(showOriginatorCountry ? { originatorCountry } : {}),
          },
        },
      },
      onCompleted: ({ response }) => {
        matchUnion(response.fulfillReceiveRequirements)
          .when('FulfillReceiveRequirementsSuccess', () => {
            goToStep(TravelRuleReceiveOnHoldStep.Success);
          })
          .when('FulfillReceiveRequirementsError', partialSuccess => {
            // Refresh the updated list of fields to be prompted to the user
            setShowOriginatorName(false);
            setShowOriginatorCountry(false);
            if (partialSuccess.missingFields) {
              for (const missingField of partialSuccess.missingFields) {
                if (missingField?.options) {
                  for (const option of missingField.options) {
                    switch (option) {
                      case 'FIELD_ORIGINATOR_NAME':
                        setShowOriginatorName(true);
                        break;
                      case 'FIELD_ORIGINATOR_COUNTRY':
                        setShowOriginatorCountry(true);
                        break;
                      default:
                        break;
                    }
                  }
                }
              }
            }
          })
          .when('GenericError', ({ message }) => {
            showErrorToast(message);
          })
          .otherwise(() => {
            notifyError(
              new Error(
                `fulfillReceiveRequirements returned unknown response or null.`,
              ),
              {
                owner: 'legal',
                context: 'travel_rule_receive_on_hold',
              },
            );
          });
      },
      onError: ({ alreadyReportedError }) => {
        notifyError(getErrorInstance(alreadyReportedError), {
          owner: 'legal',
          context: 'travel_rule_receive_on_hold',
        });
      },
    });
  }, [
    goToStep,
    fulfillReceiveRequirements,
    transferIdem,
    showOriginatorName,
    originatorName,
    showOriginatorCountry,
    originatorCountry,
    setShowOriginatorName,
    setShowOriginatorCountry,
    showErrorToast,
    autoSaveContact,
  ]);

  const handleViewTransactionDetailsButtonPress = useCallback(() => {
    showModal(
      <TravelRuleReceiveOnHoldTransactionDetailsModal
        amount={receiveRequirements?.transactionInformation?.amount}
        network={receiveRequirements?.transactionInformation?.network}
        networkIconUrl={receiveRequirements?.transactionInformation?.iconUrl}
        senderAddress={
          receiveRequirements?.transactionInformation?.senderAddress
        }
        transactionHash={
          receiveRequirements?.transactionInformation?.transactionHash
        }
        transactionUrl={
          receiveRequirements?.transactionInformation?.transactionUrl
        }
      />,
    );
  }, [
    showModal,
    receiveRequirements?.transactionInformation?.amount,
    receiveRequirements?.transactionInformation?.network,
    receiveRequirements?.transactionInformation?.iconUrl,
    receiveRequirements?.transactionInformation?.senderAddress,
    receiveRequirements?.transactionInformation?.transactionHash,
    receiveRequirements?.transactionInformation?.transactionUrl,
  ]);

  const handleBack = useCallback(() => {
    goBack();
  }, [goBack]);

  return (
    <>
      <ModalHeader
        center
        title={formatMessage(messages.navTitle)}
        onBack={transactionId !== undefined ? handleBack : undefined}
        onClose={onClose}
      />
      <VStack width="100%" spacingVertical={4} spacingHorizontal={4}>
        <TextTitle3 as="h1" spacingBottom={2}>
          {formatMessage(messages.title)}
        </TextTitle3>
        <TextBody as="p" color="foregroundMuted" spacingBottom={2}>
          {receiveRequirements?.displayText ?? formatMessage(messages.subtitle)}{' '}
          <Link
            to={receiveRequirements?.learnMoreUrl ?? ''}
            openInNewWindow
            rel="noopener noreferrer"
          >
            {formatMessage(messages.learnMoreLink)}
          </Link>
        </TextBody>
        {showOriginatorName && (
          <>
            <Spacer vertical={2} />
            <TextInput
              label={formatMessage(messages.nameFieldLabel)}
              placeholder={formatMessage(messages.nameFieldPlaceholder)}
              name="originatorName"
              onChange={handleOriginatorNameInputChange}
              value={originatorName}
            />
          </>
        )}
        {showOriginatorCountry && (
          <>
            <Spacer vertical={2} />
            <VStack spacerGap={1}>
              <TextLabel1 as="p">
                {formatMessage(messages.countryOfResidenceFieldLabel)}
              </TextLabel1>
              <SelectList
                value={originatorCountry}
                placeholder={formatMessage(
                  messages.countryOfResidenceFieldPlaceholder,
                )}
              >
                {/* eslint-disable-next-line @typescript-eslint/no-explicit-any */}
                {countries.map((option: any) => (
                  <SelectListItem
                    key={option.code}
                    value={option.code}
                    label={formatMessage(option.name)}
                    // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                    onClick={() => setOriginatorCountry(option.code)}
                  />
                ))}
              </SelectList>
            </VStack>
          </>
        )}
      </VStack>
      <VStack spacingHorizontal={4} spacingBottom={5} spacerGap={2}>
        <Button
          variant="primary"
          block
          onPress={handleSubmitButtonPress}
          disabled={
            isSubmitting ||
            !isValid ||
            isCreatingSendReceiveContact ||
            isUpdatingSendReceiveContact
          }
          loading={
            isSubmitting ||
            isCreatingSendReceiveContact ||
            isUpdatingSendReceiveContact
          }
        >
          {formatMessage(messages.submitButton)}
        </Button>
        <Button
          variant="secondary"
          block
          onPress={handleViewTransactionDetailsButtonPress}
        >
          {formatMessage(messages.viewTransactionDetailsButton)}
        </Button>
      </VStack>
    </>
  );
});

import { useState } from 'react';
import { IconButton } from '@cbhq/cds-web/buttons';
import { HStack } from '@cbhq/cds-web/layout';
