import { ProgressBar } from '@cbhq/cds-web/visualizations';
import useInterval from '@cbhq/common-web/hooks/useInterval';

type Props = {
  value: number;
  total: number;
  delay: number;
  onClose: () => void;
};

export function ProgressBarHeader({ value, total, delay, onClose }: Props) {
  return (
    <ThemeProvider spectrum="light">
      <HStack
        spacerGap={2}
        spacing={3}
        alignItems="center"
        background="background"
      >
        {[...Array(total).keys()].map(index =>
          value === index ? (
            <AnimatedProgressBar key={index} delay={delay} />
          ) : (
            <ProgressBar
              key={index}
              progress={value > index ? 1 : 0}
              color={value > index ? 'primary' : 'foreground'}
              disableAnimateOnMount
            />
          ),
        )}

        <IconButton name="close" onClick={onClose} />
      </HStack>
    </ThemeProvider>
  );
}

type AnimatedProgressBarProps = { delay: number };

function AnimatedProgressBar({ delay = 0 }: AnimatedProgressBarProps) {
  const [value, setValue] = useState(0);

  const interval = delay / 100;

  useInterval(() => {
    if (value >= 1) {
      return;
    }

    setValue(prev => prev + 0.01);
  }, interval);

  return <ProgressBar progress={value} color="primary" />;
}

