type WrapUnavailableProps = {
  closeModal: () => void;
};

function WrapUnavailable({ closeModal }: WrapUnavailableProps) {
  const { goToStep } = useStepper(stepper);
  const { viewer } = useLazyLoadQuery<UnwrapUnavailableQuery>(
    graphql`
      query UnwrapUnavailableQuery($assetSymbol: String!) {
        viewer {
          assetBySymbol(symbol: $assetSymbol) {
            wrappedAsset {
              disabledWarning(isUnwrap: true) {
                isDisabled
                title
                text
                iconName
              }
            }
          }
          targetAccount: accountByUuidV2(uuid: "ETH2", createIfNotExist: true) {
            uuid
          }
        }
      }
    `,
    {
      assetSymbol: 'CBETH',
    },
  );

  const result = viewer.assetBySymbol?.wrappedAsset?.disabledWarning;

  useEffect(() => {
    !result?.isDisabled && goToStep('input');
  }, [result]);

  const { targetAccount } = viewer;
  if (!targetAccount?.uuid) {
    throw new Error('WrappedNux: targetAccount is required but not found');
  }

  if (!viewer || !result?.title) return null;

  const { title, text, iconName } = result;

  return (
    <ModalBody>
      <VStack alignItems="center" spacingBottom={2}>
        <Box justifyContent="flex-end" width="100%">
          <IconButton
            name="close"
            onPress={closeModal}
            variant="foregroundMuted"
            transparent
          />
        </Box>
        <Box flexDirection="column" alignItems="center">
          <SpotSquare
            name={iconName as IllustrationSpotSquareNames}
            dimension="96x96"
            scaleMultiplier={1.25}
          />
          <TextTitle3
            as="span"
            color="foreground"
            align="center"
            spacingBottom={2}
          >
            {title}
          </TextTitle3>
          <TextBody as="p" color="foregroundMuted" align="center">
            {text}
          </TextBody>
        </Box>
      </VStack>
    </ModalBody>
  );
}

function WrapUnavailableStep(props: WrapUnavailableProps) {
  return (
    <Boundary
      owner="wrapped-assets"
      name="WrapNuxModal"
      fallback={<WidgetLoadingFallback />}
      errorFallback={WrappedErrorFallback}
      context="unwrapped_asset"
    >
      <WrapUnavailable {...props} />
    </Boundary>
  );
}

