  const cryptoAmount = isBuy
    ? convertQuote.outputAmount
    : convertQuote.inputAmount;

  const displayInputAmount = convertQuote.displayInputAmount.value;
  const amountWithoutFee = convertQuote.total.value;

  const actionValue = useMemo(() => {
    return isBuy ? amountWithoutFee : displayInputAmount;
  }, [amountWithoutFee, displayInputAmount, isBuy]);

  const subscriptionFeeBenefit = useMemo(
    () => parseSimpleTradeBenefitFromQuote(convertQuote, 'convert'),
    [convertQuote],
  );

  const totalAmount = useMemo(
    () =>
      formatAmount({
        amount: isBuy ? convertQuote.subtotal : convertQuote.total,
        isFiat: true,
      }),
    [convertQuote.subtotal, convertQuote.total, formatAmount, isBuy],
  );

  const recurringPayment = convertQuote.recurringPeriod;
  const hasRecurringOptions = hasRecurringBuysUsdc && isBuy;

  const { hasConvertTradeToRecurringSwitch, isToggled, setIsToggled } =
    useConvertTradeToRecurringBanner({
      recurringBuyPolicyRestrictionCount:
        viewer?.policyRestrictions?.length ?? 0,
      recurringPayment,
      hasRecurringOptions,
    });

  const accessibilityLabel = useMemo(
    () =>
      formatMessage(buySellMessages.buySellPreviewHeaderLabel, {
        buyOrSell: tradeType,
        orderAmount: formatAmount({
          amount: cryptoAmount,
          isFiat: false,
        }),
      }),
    [formatMessage, tradeType, formatAmount, cryptoAmount],
  );

  const eventLogger = useEventLogger('trade_disclosure_cta', {
    action: ActionType.click,
    componentType: ComponentType.button,
    display_type: 'label',
    cta_type: 'primary',
  });

  const handleUserWarningContextClick = useCallback(() => {
    goToStep('buyDisclosures');
    eventLogger();
  }, [eventLogger, goToStep]);

  const buyRiskNotice = useMemo(() => {
    const buyTradeDisclosure = userWarnings.find(warning =>
      warning.id?.startsWith(BUY_TRADE_DISCLOSURE),
    );
    return buyTradeDisclosure?.context ? (
      <PreviewLinkCopy
        copy={buyTradeDisclosure.message}
        link={{
          label: buyTradeDisclosure.context.linkText,
          handleLinkPress: handleUserWarningContextClick,
        }}
      />
    ) : null;
  }, [handleUserWarningContextClick, userWarnings]);

  const apyUserWarning = useMemo(() => {
    if (showRewardApy) {
      const apyWarning = {
        id: 'usdc_rewards_notice',
        message: formatMessage(messages.earnUsdcApy, {
          apy: (
            <TextCaption as="span" color="positive">
              {assetReward?.formattedValue ?? ''} {assetReward?.label ?? ''}
            </TextCaption>
          ),
        }),
      };
      return apyWarning;
    }
    return null;
  }, [
    assetReward?.formattedValue,
    assetReward?.label,
    formatMessage,
    showRewardApy,
  ]);

  const filteredUserWarnings = useMemo(() => {
    const newUserWarnings = userWarnings
      .slice()
      .filter(
        warning =>
          (showRewardApy &&
            !warning.id?.startsWith('shared.trades.rewards_notice')) ||
          !warning.id?.startsWith(BUY_TRADE_DISCLOSURE),
      );

    return newUserWarnings;
  }, [userWarnings, showRewardApy]);

  const recurringValue = recurringPayment
    ? formatRecurringText({
        formatMessage,
        period: recurringPayment.toUpperCase(),
        amount: formatAmount({
          amount: convertQuote.total,
          isFiat: true,
        }),
      })
    : undefined;

  const recurringValueDetails = recurringPayment
    ? formatRecurringSubtext({
        formatMessage,
        period: recurringPayment.toUpperCase(),
      })
    : undefined;

  const handleRecurringUpsellPress = useCallback(() => {
    stopPolling();

    setIsToggled(!isToggled);

    submitQuote({
      variables: {
        amount: convertQuote.displayInputAmount,
        recurringPeriod: isToggled ? undefined : 'weekly',
      },
    });

    recurringPeriod.onChange(isToggled ? 'never' : 'weekly');
    toggleRecurringReceiptRow();
  }, [
    stopPolling,
    setIsToggled,
    isToggled,
    submitQuote,
    convertQuote.displayInputAmount,
    recurringPeriod,
    toggleRecurringReceiptRow,
  ]);

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const goToPriceInfo = () => {
    goToStep('priceInfo');
  };

  if (!convertQuote) return null;

  const unitPrice = isBuy
    ? convertQuote.targetToSource
    : convertQuote.sourceToTarget;

  return (
    <PreviewWrapper>
      <Header
        goBack={!isCommitting ? goBack : undefined}
        title={<FormattedMessage {...buySellMessages.previewHeader} />}
        testID="preview-header"
      />

      <VStack alignItems="center" spacingHorizontal={3}>
        <TradeAmountWithScaling
          accessibilityLabel={accessibilityLabel}
          text={formatAmount({
            amount: {
              value: cryptoAmount.value,
              currency: cryptoAmount.currency,
            },
            isFiat: false,
          })}
          useTicker={true}
        />

        <Spacer vertical={2} />

        {/* add to / pay with */}
        <PreviewRow
          label={
            <FormattedMessage
              {...entryMessages[`${tradeType}SelectPaymentLabel`]}
            />
          }
          rightContent={
            isBuy
              ? convertQuote.inputAmount.currency
              : convertQuote.outputAmount.currency
          }
          rightIcon={
            <RemoteImage
              source={isBuy ? sourceAsset.imageUrl : targetAsset.imageUrl}
              alt={formatMessage(messages.altIconDescription)}
              width={24}
            />
          }
        />

        {/* recurring */}
        {isBuy && (
          <PreviewRowContainer>
            <Collapsible
              collapsed={!recurringValue && collapsed}
              spacing={0}
              maxWidth={100}
            >
              <PreviewRow
                label={<FormattedMessage {...buyMessages.recurringLabel} />}
                testID="recurring-preview-row"
                rightContent={
                  <>
                    {recurringValue}
                    <br />
                    {recurringValueDetails}
                  </>
                }
              />
            </Collapsible>
          </PreviewRowContainer>
        )}

        {/* price */}
        <PreviewFeeRow
          label={formatMessage(buySellMessages.priceLabel)}
          rightContent={`${formatAmount({
            amount: unitPrice?.amount,
            isFiat: true,
            exponent: getPriceScale(parseFloat(unitPrice?.amount?.value || '')),
          })} / ${
            isBuy ? targetAsset.displaySymbol : sourceAsset.displaySymbol
          }`}
          onClick={goToPriceInfo}
        />

        {/* purchase - sale */}
        <PreviewRow
          label={
            <FormattedMessage
              {...(isBuy
                ? buyMessages.buyActionLabel
                : sellMessages.sellActionLabel)}
            />
          }
          rightContent={formatAmount({
            amount: {
              value: actionValue,
              currency: convertQuote.displayInputAmount.currency,
            },
            isFiat: true,
          })}
          testID="purchase"
        />
        <ConvertPreviewFeeRows
          fees={convertQuote.fees}
          subscriptionFeeBenefit={subscriptionFeeBenefit}
          isCoinbaseOneSubscriber={isCoinbaseOneSubscriber}
        />
        {/* total */}
        <PreviewRow
          label={
            <FormattedMessage
              {...(isBuy
                ? buyMessages.buyTotalLabel
                : sellMessages.sellTotalLabel)}
            />
          }
          rightContent={totalAmount}
          isLastRow={!hasConvertTradeToRecurringSwitch}
          testID="total"
        />

        {/* invest weekly */}
        {hasConvertTradeToRecurringSwitch && (
          <PreviewRecurringUpsellRow
            onChange={handleRecurringUpsellPress}
            isToggled={isToggled}
            isDisabled={isRefreshing || isCommitting}
          />
        )}
      </VStack>

      <Spacer vertical={3} />

      {filteredUserWarnings.length > 0 && (
        <PreviewBanners>
          {apyUserWarning && (
            <PreviewBanner
              key={apyUserWarning.id}
              text={apyUserWarning.message}
            />
          )}
          {filteredUserWarnings.map(warning => (
            <PreviewBanner
              key={warning.id}
              text={warning.message}
              link={warning.link ?? undefined}
            />
          ))}
        </PreviewBanners>
      )}
      {buyRiskNotice && (
        <VStack borderedVertical spacingHorizontal={3} spacingVertical={1}>
          {buyRiskNotice}
        </VStack>
      )}
      <Box spacingHorizontal={3} spacingTop={buyRiskNotice ? 2 : 0}>
        <Button
          block
          loading={isCommitting || isRefreshing}
          disabled={isCommitting}
          onPress={onCommitClick}
          testID={`${tradeType}-commit-button`}
        >
          <FormattedMessage {...buttonText} />
        </Button>
      </Box>

      {footer}
    </PreviewWrapper>
  );
}

type Props = {
  queryRef: ProxyPreviewStepFragment$key;
  footer?: ReactNode;
  tradeType: TradeFiatAction;
  convertQuote: QuoteResponse['convert'];
  userWarnings: QuoteResponse['userWarnings'];
  onCommitClick: () => void;
  goBack: () => void;
  stopPolling: () => void;
};

import { useEffect, useCallback, useContext, useMemo } from 'react';
import { FormattedMessage, useIntl } from 'react-intl';

import { useIsTreatment } from '@cb/shared/hooks/useIsTreatment';
import { useEffectOnUpdate, useIsMobile } from '@cb/shared/utils';
import { TradeFiatAction } from '@cb/types';
import { Button } from '@cbhq/cds-web/buttons';
import { Box, Spacer, VStack } from '@cbhq/cds-web/layout';
import { TextBody } from '@cbhq/cds-web/typography';
import { markStepOnce } from '@cbhq/client-analytics';
import { graphql, useFragment } from '@cbhq/data-layer';

import { PADDING_TOP_INPUT } from 'components/BuySellComponents/constants';
import EntryInput, {
  useEntryInputSwitcher,
} from 'components/BuySellComponents/EntryInput';
import Header from 'components/BuySellComponents/Header';
import PaddedContent from 'components/BuySellComponents/PaddedContent';
import { FolderTabsContext } from 'components/FolderTabs';
import { useBuySellProxyContext } from 'components/SimpleTrade/BuySell/BuySellProxyProvider';
import { useActiveAccount } from 'components/SimpleTrade/BuySell/hooks/useActiveAccount';
import useBuyPresetAmounts from 'components/SimpleTrade/BuySell/hooks/useBuyPresetAmounts';
import useHasRecurringBuysUsdc from 'components/SimpleTrade/BuySell/hooks/useHasRecurringBuysUsdc';
import InvalidInputError from 'components/SimpleTrade/BuySell/messages';
import PresetAmountsPanel from 'components/SimpleTrade/BuySell/steps/EntryStep/components/PresetAmountsPanel';
import { TradeInputHelper } from 'components/SimpleTrade/BuySell/steps/EntryStep/components/TradeInputHelper';
import { messages } from 'components/SimpleTrade/BuySell/steps/EntryStep/hooks/useEntryMessages';
import { USDCEntrySelector } from 'components/SimpleTrade/components/TradeLimitsAndBalances/USDCEntrySelector';
import { useConvertContext } from 'components/SimpleTrade/Convert/ConvertProvider';
import { form as deprecatedConvertForm } from 'components/SimpleTrade/Convert/flow';
import useConvertEventTracker from 'components/SimpleTrade/Convert/hooks/useConvertEventTracker';
import useConvertQuoter from 'components/SimpleTrade/Convert/steps/EntryStep/useConvertQuoter';
import useConvertQuoteSubmitter from 'components/SimpleTrade/Convert/steps/EntryStep/useConvertQuoteSubmitter';
import { useHasCryptoConvertTargetExperiment } from 'components/SimpleTrade/hooks/useHasCryptoConvertTargetExperiment/useHasCryptoConvertTargetExperiment';
import { useSimpleTradeConvertMutationMigration } from 'components/SimpleTrade/hooks/useSimpleTradeConvertMutationMigration/useSimpleTradeConvertMutationMigration';
import useSimpleTradeForm from 'components/SimpleTrade/hooks/useSimpleTradeForm/useSimpleTradeForm';
import useSimpleTradeStepper from 'components/SimpleTrade/hooks/useSimpleTradeStepper/useSimpleTradeStepper';
import { form } from 'components/SimpleTrade/SimpleTradeRedesign/flow';
import useFetchSwapQuotes from 'components/SimpleTrade/SimpleTradeRedesign/hooks/useFetchSwapQuotes/useFetchSwapQuotes';
import useSwapQuoter from 'components/SimpleTrade/SimpleTradeRedesign/hooks/useSwapQuoter/useSwapQuoter';
import { useSimpleTradeRedesignContext } from 'components/SimpleTrade/SimpleTradeRedesign/SimpleTradeRedesignProvider';
import { InputSubmitButton } from 'components/SimpleTrade/SimpleTradeV2/BaseInput/InputSubmitButton/InputSubmitButton';
import { SimpleTradeFixedAmounts } from 'components/SimpleTrade/SimpleTradeV2/BaseInput/MaxAmount/SimpleTradeFixedAmounts';
import SystemAlert from 'components/SystemAlert';
import { useTradeDropOffNotificationTrigger } from 'hooks/notifications/useTradeDropOffNotificationTrigger';
import useNativeCurrency from 'hooks/useNativeCurrency';
import { messages as quoterMessages } from 'hooks/useQuoter/useQuoter';
import { STABLECOIN_IDS } from 'utils/stableAsset';

import { UsdcEntryStepQueryFragment$key } from './__generated__/UsdcEntryStepQueryFragment.graphql';
import { UsdcEntryStepSourceAssetFragment$key } from './__generated__/UsdcEntryStepSourceAssetFragment.graphql';
import { UsdcEntryStepTargetAssetFragment$key } from './__generated__/UsdcEntryStepTargetAssetFragment.graphql';
import BuySellProxySecondaryButton from './BuySellProxySecondaryButton';

function noop() {}

/**
 * Mimic's the Buy/Sell flow's entry step but using Convert flow.
 * TODO: Refactor to use the same components as Buy/Sell flow
 */

type Props = {
  targetViewerAssetRef: UsdcEntryStepTargetAssetFragment$key;
  sourceViewerAssetRef: UsdcEntryStepSourceAssetFragment$key;
  transferType: TradeFiatAction;
  closeModal?: () => void;
  clearForm?: () => void;
  queryRef: UsdcEntryStepQueryFragment$key;
  hasPreviewRefreshExperiment?: boolean; // added this as a prop as this step is used on old and new input steps. We want to trigger new preview endpoints for new entry step only
};

export default function UsdcEntryStep({
  sourceViewerAssetRef,
  targetViewerAssetRef,
  transferType,
  closeModal,
  clearForm,
  queryRef,
  hasPreviewRefreshExperiment = false,
}: Props) {
  const sourceAsset = useFragment(
    graphql`
      fragment UsdcEntryStepSourceAssetFragment on ViewerAsset
      @argumentDefinitions(
        includeApy: { type: "Boolean!", defaultValue: false }
        includeBalance: { type: "Boolean!", defaultValue: false }
      ) {
        asset {
          name
          imageUrl
          platformName
          displaySymbol
          uuid
        }
        assetBalanceBreakdown @include(if: $includeBalance) {
          availableToTradeBalanceFiat {
            value
          }
        }
        accounts {
          ...SimpleTradeFixedAmountsAccountFragment
          type
          primary
        }
        rewardApy @include(if: $includeApy) {
          formattedValue
          label
        }
        ...EntryInputFragment
        ...EntryInputV2Fragment
      }
    `,
    // We need to fix the ESLint rule to accept prefixes before "viewerAssetRef"

    sourceViewerAssetRef,
  );

  const targetAsset = useFragment(
    graphql`
      fragment UsdcEntryStepTargetAssetFragment on ViewerAsset
      @argumentDefinitions(
        includeApy: { type: "Boolean!", defaultValue: false }
        includeBalance: { type: "Boolean!", defaultValue: false }
      ) {
        asset {
          name
          imageUrl
          platformName
          displaySymbol
          uuid
          ...USDCEntrySelectorAssetFragment
          ...SimpleTradeFixedAmountsAccountTargetAssetFragment
        }
        assetBalanceBreakdown @include(if: $includeBalance) {
          availableToTradeBalanceFiat {
            value
          }
        }
        rewardApy @include(if: $includeApy) {
          formattedValue
          label
        }
        ...EntryInputFragment
        ...EntryInputV2Fragment
      }
    `,
    // We need to fix the ESLint rule to accept prefixes before "viewerAssetRef"

    targetViewerAssetRef,
  );

  const query = useFragment(
    graphql`
      fragment UsdcEntryStepQueryFragment on Query {
        ...useBuyPresetAmountsFragment
        ...SimpleTradeFixedAmountsFragment
      }
    `,
    queryRef,
  );

  const { formatMessage } = useIntl();
  const { renderTabs } = useContext(FolderTabsContext);
  const {
    cryptoInput,
    fiatInput,
    recurringOption,
    setFiatInput,
    setIsFiatInput,
    disableAutoFocus,
  } = useBuySellProxyContext();
  const isMobile = useIsMobile();
  const nativeCurrency = useNativeCurrency();
  const { amount, isFiatInput, sourceAssetId, targetAssetId, recurringPeriod } =
    useSimpleTradeForm('convert');
  const trackEvent = useConvertEventTracker({ transferType });
  const convertQuoterResponse = useConvertQuoter({
    buySellProxy: transferType,
  });
  const swapQuoterResponse = useSwapQuoter({ buySellProxy: transferType });
  const hasSimpleTradeConvertMutationMigrationExperiment =
    useSimpleTradeConvertMutationMigration();
  const response = useMemo(
    () =>
      hasSimpleTradeConvertMutationMigrationExperiment ||
      hasPreviewRefreshExperiment
        ? swapQuoterResponse
        : convertQuoterResponse,
    [
      hasSimpleTradeConvertMutationMigrationExperiment,
      hasPreviewRefreshExperiment,
      swapQuoterResponse,
      convertQuoterResponse,
    ],
  );

  const {
    fetchQuote,
    debouncedFetchQuote,
    cancelQuote,
    fiatAmount,
    cryptoAmount,
    isFetching,
  } = response;

  const { submitQuote: submitQuoteV1, isSubmitting: isSubmittingV1 } =
    useConvertQuoteSubmitter(transferType);
  const {
    generateSwapQuoteMutation: submitQuoteV2,
    isFetchingNewQuote: isSubmittingV2,
  } = useFetchSwapQuotes({ tradeTypeUI: transferType });

  const submitQuote = useMemo(
    () =>
      hasSimpleTradeConvertMutationMigrationExperiment ||
      hasPreviewRefreshExperiment
        ? submitQuoteV2
        : submitQuoteV1,
    [
      hasPreviewRefreshExperiment,
      hasSimpleTradeConvertMutationMigrationExperiment,
      submitQuoteV1,
      submitQuoteV2,
    ],
  );

  const isSubmitting = useMemo(
    () =>
      hasSimpleTradeConvertMutationMigrationExperiment ||
      hasPreviewRefreshExperiment
        ? isSubmittingV2
        : isSubmittingV1,
    [
      hasPreviewRefreshExperiment,
      hasSimpleTradeConvertMutationMigrationExperiment,
      isSubmittingV1,
      isSubmittingV2,
    ],
  );

  const { sourceAccount } = useConvertContext();
  const { goToStep } = useSimpleTradeStepper('convert');
  const { hasWebRefreshTreatment } = useSimpleTradeRedesignContext();

  const hasCryptoConvertTargetExperiment =
    useHasCryptoConvertTargetExperiment();

  const enableRecurringBuys = useHasRecurringBuysUsdc();

  const isBuy = transferType === 'buy';
  const asset = isBuy ? sourceAsset : targetAsset;
  const assetDisplaySymbol = asset?.asset.displaySymbol;
  const assetReward = asset?.rewardApy;
  const assetLimit = parseFloat(
    asset?.assetBalanceBreakdown?.availableToTradeBalanceFiat?.value || '',
  );

  const hasSellingToUsdcExperiment = useIsTreatment(
    'sep_2023_web_sell_to_usdc_growth',
    {
      skipTracking: isBuy || !assetReward?.formattedValue,
    },
  );

  const buyPresetAmounts = useBuyPresetAmounts({
    queryRef: query,
    fiatLimit: assetLimit ?? 0,
  });
  const showPresetAmounts = isBuy && !!buyPresetAmounts;

  const selectedAsset = isBuy ? targetAsset?.asset : sourceAsset?.asset;
  const displaySymbol = selectedAsset?.displaySymbol ?? '';
  const platformName = selectedAsset?.platformName ?? '';

  const sendTriggerEvent = useTradeDropOffNotificationTrigger();

  const goToPreview = useCallback(async () => {
    cancelQuote();
    trackEvent('tapped_preview');

    markStepOnce(`trigger_${transferType}_order_preview_button_usdc`);

    sendTriggerEvent(
      'CLICK_BUY_BUTTON_PREVIEW_BUY_BUTTON_WEB',
      transferType,
      {
        uuid: targetAsset.asset.uuid,
        symbol: targetAsset.asset.platformName,
      },
      {
        uuid: sourceAsset.asset.uuid,
        symbol: sourceAsset.asset.platformName,
      },
    );

    if (!parseFloat(amount.value)) {
      amount.onErrors([formatMessage(InvalidInputError.invalidInputWarning)]);
    } else {
      submitQuote({
        variables: {
          amount: {
            value: amount.value,
            currency: isFiatInput.value ? nativeCurrency : platformName,
          },
          recurringPeriod: enableRecurringBuys
            ? recurringPeriod.value
            : undefined,
        },
      });
    }
  }, [
    cancelQuote,
    trackEvent,
    transferType,
    sendTriggerEvent,
    targetAsset.asset.uuid,
    targetAsset.asset.platformName,
    sourceAsset.asset.uuid,
    sourceAsset.asset.platformName,
    amount,
    formatMessage,
    submitQuote,
    isFiatInput.value,
    nativeCurrency,
    platformName,
    enableRecurringBuys,
    recurringPeriod.value,
  ]);

  const switchActiveInputDeprecated = useEntryInputSwitcher({
    form: deprecatedConvertForm,
    quoteFiatAmount: fiatAmount as string,
    quoteCryptoAmount: cryptoAmount,
  });

  const switchActiveInput = useEntryInputSwitcher({
    form,
    quoteFiatAmount: fiatAmount as string,
    quoteCryptoAmount: cryptoAmount,
  });

  const selectedAccount = useActiveAccount(sourceAsset);

  useEffectOnUpdate(() => {
    if (amount.errors[0]) {
      trackEvent('viewed_error', {
        error: amount.errors[0],
      });
    }
  }, [amount.errors]);

  useEffect(() => {
    if (hasWebRefreshTreatment) {
      // If the user has the web refresh treatment, we want to default to fiat input
      if (
        !isFiatInput.value &&
        transferType === 'buy' &&
        !hasCryptoConvertTargetExperiment
      ) {
        isFiatInput.onChange(true);
      }
      // Reset the form if when entering the step if the user has the web refresh treatment
      clearForm?.();
    }
  }, []);

  // Update amount value if Buy/Sell Entry Step input was dirtied so that fetchQuote gets the latest amount
  useEffect(() => {
    // If the user has the web refresh treatment, we don't want to update the amount value
    if (hasWebRefreshTreatment) {
      return;
    }
    let updateAmountInput = amount.value;

    if (!isFiatInput.value && cryptoInput) {
      updateAmountInput = cryptoInput;
    } else if (isFiatInput.value && fiatInput) {
      updateAmountInput = fiatInput;
    }

    amount.onChange(updateAmountInput);
  }, []);

  // Updates recurring period if user has recurring buys enabled
  useEffect(() => {
    if (isBuy && recurringOption) {
      recurringPeriod.onChange(recurringOption);
    }
  }, []);

  useEffect(() => {
    if (!parseFloat(sourceAccount.availableBalance.value)) {
      amount.onErrors([
        <FormattedMessage
          {...messages.sellEmptyError}
          values={{ assetName: sourceAsset?.asset.name }}
        />,
      ]);
      trackEvent('viewed_validation_error', {
        error: `You don't have any ${sourceAsset?.asset.name} to ${transferType}. Try buying some to get started.`,
      });
      return;
    }

    if (!parseFloat(amount.value)) {
      return;
    }

    if (sourceAssetId.value === '' || targetAssetId.value === '') {
      return;
    }

    if (sourceAssetId.value === targetAssetId.value) {
      amount.onErrors([formatMessage(quoterMessages.sameSourceAndTargetError)]);
      return;
    }

    fetchQuote({
      input: {
        amount: {
          value: amount.value,
          currency: isFiatInput.value ? nativeCurrency : platformName,
        },
        sourceAssetUuid: sourceAssetId.value,
        targetAssetUuid: targetAssetId.value,
        recurringPeriod: enableRecurringBuys
          ? recurringPeriod.value
          : undefined,
        ...(hasCryptoConvertTargetExperiment
          ? {
              quotingType: transferType === 'buy' ? 'OUTPUT' : 'INPUT',
            }
          : {}),
      },
    });
  }, [sourceAssetId.value, targetAssetId.value, amount.value]);

  const sellAll = useCallback(() => {
    cancelQuote();
    trackEvent('tapped_convert_all');

    submitQuote({
      variables: {
        amount: sourceAccount.availableBalance,
      },
    });
  }, [cancelQuote, sourceAccount.availableBalance, submitQuote, trackEvent]);

  const handlePresetAmount = useCallback(
    (total: string) => {
      cancelQuote();
      amount.onChange(total);
      setFiatInput?.(total);

      submitQuote({
        variables: {
          amount: {
            value: total,
            currency: isFiatInput.value ? nativeCurrency : platformName,
          },
          recurringPeriod: enableRecurringBuys
            ? recurringPeriod.value
            : undefined,
        },
      });
    },
    [
      cancelQuote,
      amount,
      setFiatInput,
      submitQuote,
      isFiatInput,
      nativeCurrency,
      platformName,
      enableRecurringBuys,
      recurringPeriod.value,
    ],
  );

  const toggleInput = useCallback(() => {
    if (hasWebRefreshTreatment) {
      switchActiveInput();
    } else {
      switchActiveInputDeprecated();
    }
    if (!isFiatInput.value && amount.errors[0]) {
      // clear errors if toggling from crypto input from buy/sell. i.e. Buying BTC with cash, toggling to USDC, and not having enough USDC causes an error
      if (fiatInput) {
        amount.onChange(fiatInput);
      }
    }
  }, [
    switchActiveInput,
    isFiatInput.value,
    amount,
    fiatInput,
    hasWebRefreshTreatment,
    switchActiveInputDeprecated,
  ]);

  const handleChange = useCallback(
    (value: string) => {
      // for lagecy experience, we want to disable entering crypto
      //input as backend hasn't supported it yet
      if (
        !hasWebRefreshTreatment &&
        !hasCryptoConvertTargetExperiment &&
        !isFiatInput.value
      ) {
        return;
      }

      amount.onChange(value);
      setFiatInput?.(value);

      if (!parseFloat(value)) {
        return cancelQuote();
      }

      debouncedFetchQuote({
        input: {
          amount: {
            value,
            currency: isFiatInput.value ? nativeCurrency : platformName,
          },
          sourceAssetUuid: sourceAssetId.value,
          targetAssetUuid: targetAssetId.value,
          ...(hasCryptoConvertTargetExperiment
            ? {
                quotingType: transferType === 'buy' ? 'OUTPUT' : 'INPUT',
              }
            : {}),
        },
      });
    },
    [
      hasWebRefreshTreatment,
      isFiatInput.value,
      amount,
      setFiatInput,
      debouncedFetchQuote,
      nativeCurrency,
      platformName,
      sourceAssetId.value,
      targetAssetId.value,
      cancelQuote,
      hasCryptoConvertTargetExperiment,
      transferType,
    ],
  );

  const getInactiveSymbol = useMemo(() => {
    if (isFiatInput.value) {
      return displaySymbol;
    } else {
      return assetDisplaySymbol;
    }
  }, [isFiatInput.value, displaySymbol, assetDisplaySymbol]);

  const getInactiveAmount = useMemo(() => {
    if (!parseFloat(amount.value)) {
      return '';
    }
    if (isFiatInput.value) {
      return cryptoAmount;
    } else {
      return fiatAmount as string;
    }
  }, [amount.value, cryptoAmount, fiatAmount, isFiatInput.value]);

  const currencies = [
    sourceAsset?.asset.platformName ?? '',
    targetAsset?.asset.platformName ?? '',
  ];

  const entryStepButtonText = useMemo(() => {
    if (hasWebRefreshTreatment) {
      return messages.reviewOrderButton;
    }
    if (amount.value === '') {
      return messages[`${transferType}DefaultButton`];
    }
    return messages[`${transferType}PreviewButton`];
  }, [amount.value, hasWebRefreshTreatment, transferType]);

  const showRewardApy = useMemo(
    () => !isBuy && !!assetReward?.formattedValue && hasSellingToUsdcExperiment,
    [hasSellingToUsdcExperiment, isBuy, assetReward?.formattedValue],
  );

  const rewardSecondaryLabel = useMemo(() => {
    return (
      <>
        {targetAsset?.asset.name ? (
          <TextBody as="span" color="foregroundMuted">
            {targetAsset?.asset.name}
            {' • '}
          </TextBody>
        ) : null}
        <TextBody as="span" color="positive">
          {assetReward?.formattedValue ?? ''} {assetReward?.label ?? ''}
        </TextBody>
      </>
    );
  }, [
    targetAsset?.asset.name,
    assetReward?.formattedValue,
    assetReward?.label,
  ]);

  const sourceAssetRow = useMemo(() => {
    return {
      secondaryLabel: sourceAsset?.asset.name,
      image: sourceAsset?.asset.imageUrl,
      onPress: () => goToStep('selectSource'),
    };
  }, [goToStep, sourceAsset?.asset.imageUrl, sourceAsset?.asset.name]);

  const targetAssetRow = useMemo(() => {
    return {
      secondaryLabel: showRewardApy
        ? rewardSecondaryLabel
        : targetAsset?.asset.name,
      image: targetAsset?.asset.imageUrl,
      onPress: () => goToStep('selectTarget'),
    };
  }, [
    goToStep,
    rewardSecondaryLabel,
    showRewardApy,
    targetAsset?.asset.imageUrl,
    targetAsset?.asset.name,
  ]);

  const sourceRowProps = useMemo(() => {
    return {
      primaryLabel: (
        <FormattedMessage {...messages[`${transferType}SelectAssetLabel`]} />
      ),
      ...(isBuy ? targetAssetRow : sourceAssetRow),
      disabled: isSubmitting,
      testID: `${transferType}-source-selector`,
    };
  }, [isBuy, isSubmitting, sourceAssetRow, targetAssetRow, transferType]);

  const targetRowProps = useMemo(() => {
    return {
      primaryLabel:
        hasWebRefreshTreatment && transferType === 'sell' ? (
          <FormattedMessage {...messages[`sellSelectPaymentLabelRedesign`]} />
        ) : (
          <FormattedMessage
            {...messages[`${transferType}SelectPaymentLabel`]}
          />
        ),
      ...(isBuy ? sourceAssetRow : targetAssetRow),
      disabled: isSubmitting,
      testID: `${transferType}-target-selector`,
    };
  }, [
    isBuy,
    isSubmitting,
    sourceAssetRow,
    targetAssetRow,
    transferType,
    hasWebRefreshTreatment,
  ]);

  const previewButton = useMemo(() => {
    const buttonText = isBuy ? (
      <FormattedMessage
        {...entryStepButtonText}
        values={{ assetName: targetAsset?.asset.name }}
      />
    ) : (
      <FormattedMessage
        {...entryStepButtonText}
        values={{ assetName: sourceAsset?.asset.name }}
      />
    );
    // disabling when isFiatInput.value is true. BE does not support input changes for crypto to crypto trades
    const disabled =
      !!amount.errors[0] ||
      isSubmitting ||
      (!isFiatInput.value &&
        !hasWebRefreshTreatment &&
        !hasCryptoConvertTargetExperiment) ||
      amount.value === '' ||
      amount.value === '0';
    if (hasWebRefreshTreatment) {
      return (
        <InputSubmitButton
          block
          loading={isSubmitting}
          disabled={disabled}
          handleSubmit={goToPreview}
          testID={`${transferType}-preview-button`}
          label={buttonText}
          endIcon="forwardArrow"
        />
      );
    }
    return (
      <Button
        block
        disabled={disabled}
        loading={isSubmitting}
        onPress={goToPreview}
        testID={`${transferType}-preview-button`}
      >
        {buttonText}
      </Button>
    );
  }, [
    amount.errors,
    amount.value,
    entryStepButtonText,
    goToPreview,
    hasWebRefreshTreatment,
    isBuy,
    isFiatInput.value,
    isSubmitting,
    sourceAsset?.asset.name,
    targetAsset?.asset.name,
    transferType,
    hasCryptoConvertTargetExperiment,
  ]);

  const switchActiveInputConfig = useMemo(() => {
    return {
      onPress: toggleInput,
      inactiveSymbol: getInactiveSymbol || '',
      inactiveAmount: getInactiveAmount || '',
      // Do not disable if somehow there is an error when it is a crypto input.
      // If there is an error when isFiatInput is false, the user will be stuck in this experience.
      // Enabling the switch allows users to correct the input.
      disabled:
        isSubmitting ||
        (amount.errors[0] && isFiatInput.value) ||
        (!hasCryptoConvertTargetExperiment &&
          hasWebRefreshTreatment &&
          transferType === 'buy'),
    };
  }, [
    amount.errors,
    getInactiveAmount,
    getInactiveSymbol,
    hasWebRefreshTreatment,
    isFiatInput.value,
    isSubmitting,
    toggleInput,
    transferType,
    hasCryptoConvertTargetExperiment,
  ]);

  const handleSkipToPreview = useCallback(
    (value: string) => {
      submitQuote({
        variables: {
          amount: {
            value,
            currency: sourceAccount.availableBalance.currency,
          },
        },
      });
    },
    [submitQuote, sourceAccount.availableBalance.currency],
  );

  const handleSetInputValueOnMaxPress = useCallback(
    (value?: string) => {
      if (value) {
        amount.onChange(value);
        setFiatInput?.(value);
        if (transferType !== 'buy') {
          handleSkipToPreview(value);
        }
      }
    },
    [amount, setFiatInput, transferType, handleSkipToPreview],
  );

  const handleSwapCurrency = useCallback(
    (isFiat: boolean) => {
      isFiatInput.onChange(isFiat);
      setIsFiatInput?.(isFiat);
    },
    [isFiatInput, setIsFiatInput],
  );

  const fixedAmounts = useMemo(
    () => (
      <SimpleTradeFixedAmounts
        queryRef={query}
        accountRef={selectedAccount}
        setInputValue={handleSetInputValueOnMaxPress}
        setInputCurrency={handleSwapCurrency}
        tradeTypeUI={transferType}
        // disable preset / max btns when fetching quote to avoid incidental clicks as quote is resolving
        disabled={
          isFetching ||
          isSubmitting ||
          (!isFiatInput.value && transferType === 'buy')
        }
        target={{ assetId: STABLECOIN_IDS.USDC }}
        targetAssetRef={targetAsset.asset}
        triggerSubmit={noop}
      />
    ),
    [
      query,
      selectedAccount,
      handleSetInputValueOnMaxPress,
      handleSwapCurrency,
      transferType,
      isFetching,
      isSubmitting,
      targetAsset.asset,
      isFiatInput.value,
    ],
  );

  const entryStepHeader = useMemo(() => {
    // if we are in the web refresh experiment, we don't want to show the header
    if (hasWebRefreshTreatment) {
      return null;
    }
    return (
      <>
        {renderTabs && renderTabs()}

        {isMobile && !!closeModal && <Header goBack={closeModal} />}
      </>
    );
  }, [closeModal, hasWebRefreshTreatment, isMobile, renderTabs]);

  return (
    <>
      <SystemAlert view="CONVERT" currencies={currencies} />
      {entryStepHeader}
      <PaddedContent
        paddingTopDesktop={!hasWebRefreshTreatment ? PADDING_TOP_INPUT : 0}
        paddingTopMobile={!hasWebRefreshTreatment ? PADDING_TOP_INPUT : 0}
      >
        {!hasWebRefreshTreatment && (
          <Box alignSelf="flex-end" spacingBottom={6}>
            <BuySellProxySecondaryButton
              transferType={transferType}
              onPressSell={sellAll}
              disabled={isSubmitting || !!amount.errors[0]}
            />
          </Box>
        )}
        <EntryInput
          viewerAssetRef={transferType === 'buy' ? targetAsset : sourceAsset}
          isNewDesign={hasWebRefreshTreatment}
          autoFocus={!disableAutoFocus}
          transferType={transferType}
          input={{
            symbol: isFiatInput.value ? nativeCurrency : platformName,
            displaySymbol: isFiatInput.value ? undefined : displaySymbol,
            value: amount.value,
            // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
            onChange: handleChange,
            onEnter: goToPreview,
            readOnly: isSubmitting,
          }}
          // Errors from BE through convert flow do not support our instance. Since we block purchasing/selling when isFiatInput is false, don't show the confusing error message
          error={
            (isFiatInput.value ||
              hasWebRefreshTreatment ||
              hasCryptoConvertTargetExperiment) &&
            amount.errors[0]
          }
          helperText={
            isBuy && (
              <TradeInputHelper
                transferType={transferType}
                amount={amount.value}
                fiatCode={nativeCurrency}
                fiatLimit={assetLimit}
              />
            )
          }
          switchActiveInput={switchActiveInputConfig}
          secondaryButton={hasWebRefreshTreatment ? fixedAmounts : null}
        />
        {showPresetAmounts && !hasWebRefreshTreatment ? (
          <PresetAmountsPanel
            amounts={buyPresetAmounts}
            onPressAmount={handlePresetAmount}
            disabled={isSubmitting || !isFiatInput.value}
            testID="preset-amounts-panel"
          />
        ) : null}
        {/*
          NOTE: To make it easier to follow:
            * Proxy Buy:
                top row: crypto to buy = targetAsset
                bottom row: crypto sourceAsset
            * Proxy Sell:
                top row: crypto to sell = sourceAsset
                bottom row: crypto targetAsset
        */}

        <VStack>
          <USDCEntrySelector
            row1={sourceRowProps}
            row2={targetRowProps}
            transferType={transferType}
            targetAssetDisplaySymbol={targetAsset?.asset.displaySymbol ?? ''}
            isNewDesign={hasWebRefreshTreatment}
            assetRef={targetAsset.asset}
          />
          {previewButton}
        </VStack>
      </PaddedContent>

      <Spacer vertical={hasWebRefreshTreatment ? 4 : 2} />
    </>
  );
}

import { useMemo, useCallback, memo, ChangeEvent } from 'react';
import { InputIcon } from '@cbhq/cds-web/controls/InputIcon';
import { TextInput } from '@cbhq/cds-web/controls/TextInput';

import { isValidEmail } from '../utils';

type BaseFormInputProps = {
  label: string;
  placeholder?: string;
  key: number;
  value: string;
  onChange: (value: string) => void;
};

const BaseFormInput = memo(function BaseFormInput({
  label,
  placeholder,
  value,
  key,
  onChange,
}: BaseFormInputProps) {
  const isInputValid = useMemo(() => {
    if (!value || value === '') {
      return undefined;
    }
    return isValidEmail(value);
  }, [value]);

  const endIcon = useMemo(() => {
    if (isInputValid === true) {
      return <InputIcon name="checkmark" color="positive" />;
    } else if (isInputValid === false) {
      return <InputIcon name="circleCross" color="negative" />;
    }
    return null;
  }, [isInputValid]);

  const handleOnChange = useCallback(
    (e: ChangeEvent<HTMLInputElement>) => {
      e.preventDefault();
      onChange(e.target.value as string);
    },
    [onChange],
  );

  return (
    <TextInput
      key={key}
      type="email"
      label={label}
      placeholder={placeholder}
      onChange={handleOnChange}
      value={value}
      end={endIcon}
      variant={isInputValid === false ? 'negative' : undefined}
    />
  );
});

export default BaseFormInput;

import { useCallback, memo } from 'react';
import { IllustrationSpotRectangleNames, SpacingScale } from '@cbhq/cds-common';
