import ErrorBoundary from 'components/ErrorBoundary';
import { WRAP_FLOW, SEE_OPTIONS_CLICK } from 'components/WrappedAsset/events';
import useWrappedCta from 'components/WrappedAsset/hooks/useWrappedCta';
import { YieldEventContext } from 'views/YieldCenter/components/eventing';

import { WrappedActions } from '../WrappedActions/WrappedActions';
import { WrapEntryPointFragment$key } from './__generated__/WrapEntryPointFragment.graphql';

type WrapEntryPointContentProps = {
  viewerAssetRef: WrapEntryPointFragment$key | null;
  spacingTop?: SpacingScale;
  spacingBottom?: SpacingScale;
  variant?: 'banner' | 'card';
  context: YieldEventContext;
};

function WrapEntryPointContent({
  viewerAssetRef,
  spacingBottom,
  spacingTop,
  variant = 'banner',
  context,
}: WrapEntryPointContentProps) {
  const viewerAsset = useFragment(
    graphql`
      fragment WrapEntryPointFragment on ViewerAsset {
        ...WrappedActionsFragment
        wrappedAsset {
          wrapUnwrapEntryPoint {
            text
            title
            cta @required(action: NONE) {
              text @required(action: NONE)
            }
            model {
              title
              text
              helpCta @required(action: NONE) {
                text @required(action: NONE)
                url @required(action: NONE)
              }
            }
          }
        }
      }
    `,
    viewerAssetRef,
  );

  const { openModal, closeModal } = useModal();

  const ctaHelpHandler = useWrappedCta({
    ctaUrl:
      viewerAsset?.wrappedAsset?.wrapUnwrapEntryPoint?.model?.helpCta?.url,
    context,
  });

  const handleWrapModal = useCallback(() => {
    const model = viewerAsset?.wrappedAsset?.wrapUnwrapEntryPoint?.model;
    if (!model || !model?.title) return;

    openModal(
      <Modal hideCloseButton visible onRequestClose={closeModal}>
        <ModalHeader title={model?.title} onBackButtonPress={closeModal} />
        <ModalBody>
          <HStack alignItems="center" display="block" alignSelf="center">
            <SpotRectangle
              dimension="240x120"
              name={'wrapEth' as IllustrationSpotRectangleNames}
            />
          </HStack>
          <TextBody
            color="foregroundMuted"
            spacingBottom={2}
            spacingTop={4}
            as="p"
          >
            {model?.text}{' '}
            <Link color="primary" onClick={ctaHelpHandler} variant="body">
              {model?.helpCta?.text}
            </Link>
          </TextBody>
          <WrappedActions
            viewerAssetRef={viewerAsset}
            onCtaPress={closeModal}
            source={context}
          />
        </ModalBody>
      </Modal>,
    );
  }, [context, openModal, closeModal, viewerAsset, ctaHelpHandler]);

  const handleShowWrapTray = useCallback(() => {
    logEvent(WRAP_FLOW, {
      ...SEE_OPTIONS_CLICK,
    });
    handleWrapModal();
  }, [handleWrapModal]);

  const { title, text, cta } =
    viewerAsset?.wrappedAsset?.wrapUnwrapEntryPoint || {};

  if (variant === 'card') {
    return (
      <Box spacingTop={spacingTop} spacingBottom={spacingBottom}>
        <Pressable
          noScaleOnPress
          as="button"
          width="100%"
          background="transparent"
          onPress={handleShowWrapTray}
        >
          <NudgeCard
            title={<TextHeadline as="p">{title}</TextHeadline>}
            description={text}
            pictogram="earnNavigation"
            width="100%"
          />
        </Pressable>
      </Box>
    );
  }

  return (
    <>
      {viewerAsset?.wrappedAsset?.wrapUnwrapEntryPoint && cta?.text && (
        <>
          <Spacer vertical={spacingTop || 0} />
          <Card bordered borderRadius="rounded" spacing={4}>
            <HStack justifyContent="space-between" alignItems="center">
              <VStack justifyContent="flex-start" alignItems="flex-start">
                <TextTitle3 as="h2" spacingBottom={1}>
                  {title}
                </TextTitle3>
                <TextBody as="p" color="foregroundMuted">
                  {text}
                </TextBody>
                <Spacer vertical={2} />
                <Button
                  variant="secondary"
                  compact
                  onPress={handleShowWrapTray}
                >
                  {cta.text}
                </Button>
              </VStack>
              <Spacer horizontal={2} />
              <SpotRectangle
                dimension="240x120"
                name={'wrapEth' as IllustrationSpotRectangleNames}
              />
            </HStack>
          </Card>
          <Spacer vertical={spacingBottom || 3} />
        </>
      )}
    </>
  );
}

function WrapEntryPoint(props: WrapEntryPointContentProps) {
  const renderFallback = useCallback(() => null, []);

  return (
    <ErrorBoundary
      owner="wrapped-assets"
      fallback={renderFallback}
      context="wrapped_asset"
    >
      <WrapEntryPointContent {...props} />
    </ErrorBoundary>
  );
}

export default memo(WrapEntryPoint);

import { useEffect } from 'react';
import { IllustrationSpotSquareNames } from '@cbhq/cds-common';
import { IconButton } from '@cbhq/cds-web/buttons/IconButton';
import { SpotSquare } from '@cbhq/cds-web/illustrations/SpotSquare';
import { Box } from '@cbhq/cds-web/layout/Box';
import { VStack } from '@cbhq/cds-web/layout/VStack';
import { ModalBody } from '@cbhq/cds-web/overlays';
import { TextBody } from '@cbhq/cds-web/typography';
import { TextTitle3 } from '@cbhq/cds-web/typography/TextTitle3';
import { graphql, useLazyLoadQuery } from '@cbhq/data-layer';

import Boundary from 'components/Boundary';
import useStepper from 'components/Stepper/hooks/useStepper';
import { WidgetLoadingFallback } from 'components/WidgetComponents';
import { WrappedErrorFallback } from 'components/WrappedAsset/components/ErrorFallback';

import { stepper, WRAP_NUX_MODALS_INTRODUCTION_COMPLETE } from '../../flow';
import { WrapUnavailableQuery } from './__generated__/WrapUnavailableQuery.graphql';

type WrapUnavailableProps = {
  closeModal: () => void;
};

function WrapUnavailable({ closeModal }: WrapUnavailableProps) {
  const { goToStep } = useStepper(stepper);

  const { viewer } = useLazyLoadQuery<WrapUnavailableQuery>(
    graphql`
      query WrapUnavailableQuery($assetSymbol: String!) {
        viewer {
          assetBySymbol(symbol: $assetSymbol) {
            wrappedAsset {
              disabledWarning {
                isDisabled
                title
                text
                iconName
              }
            }
          }
        }
      }
    `,
    { assetSymbol: 'cbETH' },
  );

  const result = viewer.assetBySymbol?.wrappedAsset?.disabledWarning;

  useEffect(() => {
    const defaultStep =
      localStorage.getItem(WRAP_NUX_MODALS_INTRODUCTION_COMPLETE) === 'true'
        ? 'input'
        : 'nux';
    !result?.isDisabled && goToStep(defaultStep);
  }, [result]);

  if (!viewer || !result?.title) return null;
  const { title, text, iconName } = result;

  return (
    <ModalBody>
      <VStack alignItems="center" spacingBottom={2}>
        <Box justifyContent="flex-end" width="100%">
          <IconButton
            name="close"
            onPress={closeModal}
            variant="foregroundMuted"
            transparent
          />
        </Box>
        <Box flexDirection="column" alignItems="center">
          <SpotSquare
            name={iconName as IllustrationSpotSquareNames}
            dimension="96x96"
            scaleMultiplier={1.25}
          />
          <TextTitle3
            as="span"
            color="foreground"
            align="center"
            spacingBottom={2}
          >
            {title}
          </TextTitle3>
          <TextBody as="p" color="foregroundMuted" align="center">
            {text}
          </TextBody>
        </Box>
      </VStack>
    </ModalBody>
  );
}

function WrapUnavailableStep(props: WrapUnavailableProps) {
  return (
    <Boundary
      owner="wrapped-assets"
      name="WrapNuxModal"
      fallback={<WidgetLoadingFallback />}
      errorFallback={WrappedErrorFallback}
      context="wrapped_asset"
    >
      <WrapUnavailable {...props} />
    </Boundary>
  );
}

export default WrapUnavailableStep;

