const i18nKey = `PromotionsModal`;

const messages = defineMessages({
  promoTitle: {
    id: `${i18nKey}.promoTitle`,
    defaultMessage: 'Add promo code',
    description: `#Component: ModalHeader:title
    #CharLimit: 50
    #Context: Title for promotion code tray`,
  },
  enterYourCode: {
    id: `${i18nKey}.enterYourCode`,
    defaultMessage: 'Enter your code (optional)',
    description: `#Component: TextInput:accessibilityLabel
    #CharLimit: 65
    #Context: Description for promo code field`,
  },
  apply: {
    id: `${i18nKey}.apply`,
    defaultMessage: 'Apply',
    description: `#Component: Link:end
    #CharLimit: 35
    #Context: Text for button to submit promo code`,
  },
});

type Props = {
  isVisible: boolean;
  onRequestClose: () => void;
  onPressApply: (code: string) => void;
  isRequestInFlight?: boolean;
  errorMessage?: string | null;
};

function PromotionsModalContent({
  onRequestClose,
  onPressApply,
  isRequestInFlight,
  errorMessage,
}: Props) {
  const { formatMessage } = useIntl();

  const [code, setCode] = useState('');

  const handleApply = useCallback(() => {
    onPressApply(code);
  }, [onPressApply, code]);

  const handleOnBack = useCallback(() => {
    onRequestClose();
  }, [onRequestClose]);

  const handleCodeChange = useCallback(
    (ev: React.ChangeEvent<HTMLInputElement>) => {
      const value = ev.target.value;
      setCode(value);
    },
    [setCode],
  );

  return (
    <>
      <ModalHeader
        title={formatMessage(messages.promoTitle)}
        onBackButtonPress={handleOnBack}
      />
      <ModalBody>
        <VStack spacingHorizontal={3} spacerGap={2} spacingBottom={3}>
          <TextInput
            accessibilityLabel={formatMessage(messages.enterYourCode)}
            accessibilityHint=""
            autoFocus
            helperText={errorMessage ?? ''}
            variant={errorMessage !== null ? 'negative' : 'primary'}
            onChange={handleCodeChange}
            label={formatMessage(messages.enterYourCode)}
            end={
              <Box spacingEnd={2}>
                {isRequestInFlight ? (
                  <Spinner color="primary" size={2} />
                ) : (
                  <Link variant="label1" onPress={handleApply}>
                    {formatMessage(messages.apply)}
                  </Link>
                )}
              </Box>
            }
          />
        </VStack>
      </ModalBody>
    </>
  );
}

export default function EnterPromotionCodeModal(props: Props) {
  const renderFallback = useCallback(
    () => <ErrorContent onPressTryAgain={props.onRequestClose} />,
    [props.onRequestClose],
  );

  return (
    <Modal
      onRequestClose={props.onRequestClose}
      visible={props.isVisible}
      hideDividers
    >
      <Cb1ErrorBoundary
        boundaryName="PromotionsModal"
        fallback={renderFallback}
      >
        <PromotionsModalContent {...props} />
      </Cb1ErrorBoundary>
    </Modal>
  );
}

