type Props = {
  queryRef: BoostedStakingOptInCardFragment$key;
};

function BoostedStakingOptInCard({ queryRef }: Props) {
  const query = useFragment(
    graphql`
      fragment BoostedStakingOptInCardFragment on Query
      @argumentDefinitions(productKey: { type: "String!" }) {
        viewer {
          coinbaseSubscription(productKey: $productKey) {
            subscriptionPlan {
              type
            }
          }
        }
        ...useSubscriberStatusFragment @arguments(productKey: $productKey)
        ...SubscriptionBoostedRatesModalFragment
        ...getStakingOptInStatus_inline
      }
    `,
    queryRef,
  );

  const { viewer } = query;
  const { formatMessage } = useIntl();
  const { isSubscribed } = useSubscriberStatus(query);
  const isOptedInBoostedStaking = getStakingOptInStatus(query);
  const hasPausedSubscription =
    viewer?.coinbaseSubscription?.subscriptionPlan?.type === 'PAUSE_PLAN';
  const showBoostedStakingBenefit =
    isSubscribed && !hasPausedSubscription && isOptedInBoostedStaking;

  const { openModal: openRatesModal, closeModal: closeRatesModal } = useModal();
  const params = useQueryParams();
  const showBoostedStakingOptIn = params.get('showBoostedStakingOptIn');

  const showRatesModal = useCallback(
    (source: 'earn' | 'upsell' = 'earn') => {
      stakingEvents.logStakingOptInViewed(
        stakingEventFlows.yieldCenterCardFlow,
        stakingOptInModalStates.default,
      );

      openRatesModal(
        <SubscriptionBoostedRatesModal
          queryRef={query}
          closeModal={closeRatesModal}
          source={source}
        />,
      );
    },
    [openRatesModal, closeRatesModal, query],
  );

  useEffect(() => {
    const showBoostedStakingUpsell = params.get('showBoostedStakingUpsell');
    if (showBoostedStakingOptIn !== null) {
      showRatesModal('earn');
    }
    if (showBoostedStakingUpsell !== null) {
      showRatesModal('upsell');
    }
  }, [showBoostedStakingOptIn, params]);

  const handleOnPress = useCallback(() => {
    showRatesModal();
  }, [showRatesModal]);

  if (!showBoostedStakingBenefit) return null;

  return (
    <VStack
      bordered
      borderRadius="rounded"
      background="background"
      overflow="hidden"
    >
      <Box spacingHorizontal={3} spacingVertical={2}>
        <TextTitle3 as="span">
          {formatMessage(messages.title, { productName: PRODUCT_NAME })}
        </TextTitle3>
      </Box>
      <Divider />
      <VStack width="100%">
        <Pressable
          as="button"
          background="background"
          onPress={handleOnPress}
          testID="boostedStakingOptInCard-button"
          width="100%"
          noScaleOnPress
        >
          <HStack spacingHorizontal={3} spacingVertical={2} alignItems="center">
            <Pictogram name="coinbaseOneLogo" dimension="48x48" />
            <VStack spacingStart={2} width="100%">
              <TextBody color="foregroundMuted" as="div">
                {formatMessage(messages.description)}
              </TextBody>
            </VStack>
            <VStack alignItems="flex-end" spacingStart={2}>
              <Icon size="s" color="foregroundMuted" name="caretRight" />
            </VStack>
          </HStack>
        </Pressable>
      </VStack>
    </VStack>
  );
}

