import React, { useContext } from 'react';
import { Link as RouterLink } from 'react-router-dom';

import { PaletteForeground, Typography } from '@cbhq/cds-common/types';
import { Link } from '@cbhq/cds-web/typography/Link';
import LinkLocalizationContext from '@cbhq/common-web/contexts/LinkLocalizationContext';

export type Props = {
  to?: string;
  href?: string;
  children: NonNullable<React.ReactNode>;
  variant?: Exclude<
    Typography,
    'display1' | 'display2' | 'display2Frontier' | 'display3' | 'inherit'
  >;
  openInNewTab?: boolean;
  color?: PaletteForeground;
  onPress?: () => void;
  onMouseEnter?: () => void;
};

export default function LinkCDS({
  to,
  href,
  children,
  openInNewTab,
  variant = 'body',
  color,
  onPress,
  onMouseEnter,
}: Props) {
  // This is a bit of a hack -- hideLocaleSelector is true for logged-in and false for logged-out
  const { localize, hideLocaleSelector: loggedIn } = useContext(
    LinkLocalizationContext,
  );
  const destination = to || href;
  const forceSSR = !loggedIn && destination?.match('^/price');
  const localizedDestination = localize(to || href);
  const shouldUseReactRouterLink = to && !forceSSR;
  const rel = openInNewTab ? 'noopener' : undefined;
  const target = openInNewTab ? '_blank' : undefined;
  const renderContainer = !localizedDestination
    ? undefined
    : (props: React.HTMLAttributes<HTMLAnchorElement>) => {
        if (shouldUseReactRouterLink) {
          return <RouterLink {...props} to={localizedDestination} />;
        }

        return (
          <a {...props} rel={rel} target={target} href={localizedDestination} />
        );
      };

  return (
    <Link
      variant={variant}
      color={color}
      onPress={onPress}
      onMouseEnter={onMouseEnter}
      openInNewWindow={openInNewTab}
      renderContainer={renderContainer}
    >
      {children}
    </Link>
  );
}

