function AdvancedGlobalTransferButtonContent({
  queryRef,
}: AdvancedGlobalTransferButtonProps) {
  const { formatMessage } = useIntl();
  const { openModal, closeModal } = useModal();
  const { showModal } = useModalNonCds();

  const [selectedValue, setSelectedValue] = useState<string>('');

  const query = useFragment(
    graphql`
      fragment AdvancedGlobalTransferButtonFragment on Query {
        ...useAdvancedGlobalButtonActionsFragment
        ...useDepositWithdrawAccountFragment
        ...DepositTriggerFragment
      }
    `,
    queryRef,
  );

  const { depositAccount, withdrawAccountUuid } = useDepositWithdrawAccount({
    queryRef: query,
  });

  const handleFuturesManualSweepPress = useHandleManualSweepPress({
    entryPoint: 'advanced-global-transfer',
  });

  const dropdownRef = useRef<DropdownRefProps>(null);

  const closeDropdown = () => {
    if (dropdownRef.current !== null) {
      dropdownRef.current?.closeMenu();
    }
  };

  const handleTransferByType = useCallback(
    (transferType: GlobalTransferType) => {
      logAdvancedGlobalTransferDropdownOptionClickEvent({
        transferType,
      });

      closeDropdown();
      if (transferType === 'futures') {
        handleFuturesManualSweepPress();
      } else if (transferType === 'perpetuals') {
        openModal(
          <TransferModal
            visible
            onClose={closeModal}
            hideDividers
            entryPage="portfolio"
          />,
        );
      } else if (transferType === 'multiportfolio') {
        logPortfolioTransferClickEvent({
          portfolioType: 'USER',
          transferType: undefined,
          entryPoint: 'global',
        });
        openModal(<LazyPortfolioTransferModal onClose={closeModal} visible />);
      }
    },
    [closeModal, handleFuturesManualSweepPress, openModal],
  );

  const { advancedPortfolioActions, simpleActions } =
    useAdvancedGlobalButtonActions({ queryRef: query });

  const handleSimpleActionPress = useCallback(
    (item: QuickActionWithType) => {
      switch (item.transferType) {
        case 'send':
        case 'receive':
          return () => {
            closeDropdown();
            logAdvancedGlobalTransferDropdownOptionClickEvent({
              transferType: item.transferType as AdvancedGlobalTransferType,
            });
            markStep('receive_loaded');
            openModal(
              <SendReceiveModal
                defaultTab={item.transferType as SendReceiveAction}
                entryPoint="advanced_global_transfer"
                close={closeModal}
              />,
            );
          };
        case 'withdraw':
          return () => {
            closeDropdown();
            logAdvancedGlobalTransferDropdownOptionClickEvent({
              transferType: item.transferType as AdvancedGlobalTransferType,
            });
            showModal(
              <LazyDepositWithdrawModal
                accountId={withdrawAccountUuid ?? ''}
                entryPoint="advanced-global-transfer"
              />,
            );
          };
        default:
          return;
      }
    },
    [openModal, closeModal, withdrawAccountUuid, showModal],
  );

  const handleOpenDropdown = useCallback(() => {
    logAdvancedGlobalTransferButtonClickEvent();
  }, []);

  return useMemo(() => {
    const content = (
      <VStack>
        {simpleActions.map((item, idx) => {
          if (item.transferType === 'deposit') {
            if (!depositAccount?.rawDepositAccount) {
              return null;
            }
            return (
              <LazyDepositTrigger
                queryRef={query}
                entryPoint="advanced-global-transfer"
                accountRef={depositAccount?.rawDepositAccount}
                allowRedirect={false}
              >
                {depositProps => {
                  function handlePress() {
                    closeDropdown();
                    logAdvancedGlobalTransferDropdownOptionClickEvent({
                      transferType:
                        item.transferType as AdvancedGlobalTransferType,
                    });
                    depositProps.onClick();
                  }
                  return (
                    <ListCell
                      as="li"
                      description={item.description}
                      key={idx}
                      media={
                        <IconButton name={item.iconName} variant="secondary" />
                      }
                      onPress={handlePress}
                      title={item.title}
                    />
                  );
                }}
              </LazyDepositTrigger>
            );
          }
          return (
            <ListCell
              as="li"
              description={item.description}
              key={idx}
              media={<IconButton name={item.iconName} variant="secondary" />}
              onPress={handleSimpleActionPress(item)}
              title={item.title}
            />
          );
        })}
        {advancedPortfolioActions.map((item, idx) => (
          <ListCell
            as="li"
            key={`adv-portfolio-action-${idx}`}
            title={item.title}
            description={item.description}
            media={
              // NOTE(serra.park): This is a temporary solution to use the navIcon
              // until CDS provides a consolidated Icon component
              // https://coinbase.slack.com/archives/C05H922EYP7/p1705438738143569
              item.iconType === 'navIcon' ? (
                <NavigationIconButton
                  name={item.iconName}
                  variant="secondary"
                />
              ) : (
                <IconButton name={item.iconName} variant="secondary" />
              )
            }
            // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
            onPress={() => handleTransferByType(item.name)}
            testID={`transfer-dropdown-${item.name}`}
          />
        ))}
      </VStack>
    );

    return (
      <Spotlight
        name="FUTURES_AFTER_FIRST_TRADE"
        stepNumber={2}
        align="start"
        position="bottom"
      >
        <Dropdown
          content={content}
          testID="transfer-dropdown"
          onChange={setSelectedValue}
          ref={dropdownRef}
          showOverlay
          maxHeight={480}
          value={selectedValue}
          onOpenMenu={handleOpenDropdown}
        >
          <Button variant="secondary" testID="transfer-dropdown-button" compact>
            {formatMessage(messages.transfer)}
          </Button>
        </Dropdown>
      </Spotlight>
    );
  }, [
    advancedPortfolioActions,
    depositAccount?.rawDepositAccount,
    formatMessage,
    handleOpenDropdown,
    handleSimpleActionPress,
    handleTransferByType,
    query,
    selectedValue,
    simpleActions,
  ]);
}

