export function AdvancedSwitch({ compact, hideTooltip }: AdvancedSwitchProps) {
  const { formatMessage } = useIntl();
  const isAdvancedMode = useIsAdvancedModeEnabled();
  const navigateToTradePath = useNavigateToTradePath();
  const { advancedModeUrl } = useLayoutContext();
  const { push } = useHistory();
  const splashScreenContext = useSplashScreenContext();

  const handleSwitchClick = useCallback(() => {
    logEvent('advanced-mode-switch', {
      componentType: ComponentType.button,
      action: ActionType.click,
      mode: isAdvancedMode ? 'advanced' : 'simple',
    });

    const shouldSkipNavigation =
      Object.values(AdvancedAndSimpleSkipNavigationRoutes).some(route =>
        location.pathname.includes(route),
      ) || Boolean(advancedModeUrl);

    if (isAdvancedMode) {
      splashScreenContext?.displaySplashScreen('simple', () => {
        navigateToTradePath('simple', {
          skipNavigation: shouldSkipNavigation,
        });
      });
    } else {
      splashScreenContext?.displaySplashScreen('advanced', () => {
        markStepOnce('navigate_advanced_trade_from_advanced_switch');
        navigateToTradePath('advanced', {
          skipNavigation: shouldSkipNavigation,
        });
      });
    }

    if (advancedModeUrl) {
      push(advancedModeUrl);
    }
  }, [
    isAdvancedMode,
    advancedModeUrl,
    splashScreenContext,
    navigateToTradePath,
    push,
  ]);

  return (
    <Pressable
      testID="advanced-switch"
      onPress={handleSwitchClick}
      background="background"
      borderRadius={compact ? 'roundedLarge' : 'roundedFull'}
      as="button"
      width="100%"
    >
      {hideTooltip ? (
        <AdvancedSwitchContent
          compact={compact}
          isAdvancedMode={isAdvancedMode}
          label={formatMessage(messages.switchLabel)}
        />
      ) : (
        <Tooltip
          placement={compact ? 'right' : 'top'}
          content={
            isAdvancedMode
              ? formatMessage(messages.switchTooltipOn)
              : formatMessage(messages.switchTooltipOff)
          }
        >
          <AdvancedSwitchContent
            compact={compact}
            isAdvancedMode={isAdvancedMode}
            label={formatMessage(messages.switchLabel)}
          />
        </Tooltip>
      )}
    </Pressable>
  );
}

