export type EditOrderFormProps = {
  close?: () => void;
  /** Order id of the order to edit */
  orderId: string;
  /** Where did the user view the order form */
  entryPoint:
    | 'orders-blotter'
    | 'order-detail-modal'
    | 'order-management'
    | 'order-row-context-menu';
};

type EditOrderFormContentProps = {
  order: CoinbasePublicApiAuthedRetailBrokerageApiOrder;
} & Pick<EditOrderFormProps, 'entryPoint' | 'close'>;

function EditOrderFormContent({
  order,
  close,
  entryPoint,
}: EditOrderFormContentProps) {
  const { showSuccessToast } = useToasts();
  const { formatMessage } = useIntl();

  const [baseSymbol, quoteSymbol] = useSpotProductSymbols(order?.productId);
  const isQuoteFiat = useIsSymbolFiat(quoteSymbol);
  const product = useSilentGetProduct({
    productId: order.productId,
  });
  const nativeCurrency = useNativeCurrency();
  const isBuy =
    order.side === CoinbasePublicApiAuthedRetailBrokerageApiOrderSide.BUY;
  const basePrecision = convertIncrementToPrecision(product.baseIncrement);
  const quotePrecision = convertIncrementToPrecision(product.quoteIncrement);
  const pricePrecision = convertIncrementToPrecision(
    product.priceIncrement ?? product.quoteIncrement,
  );
  const executionOption = getExecutionOption(order);

  // Depth stream requires the alias i.e. BTC-USDC will respond with BTC-USD as the alias
  // Be careful where using this because we will need USD in some places (i.e. depth stream)
  // and USDC in others (i.e. graphql queries)
  const productIdAlias = product.alias || product.productId;

  const productType = product.productType;

  const selectedPortfolioUuid = order.retailPortfolioId;

  // This is intentionally loaded in the modal boundary to avoid unneccessary requests
  const query = useLazyLoadQuery<EditOrderFormQuery>(
    graphql`
      query EditOrderFormQuery(
        $baseCurrencyId: String!
        $quoteCurrencyId: String!
        $baseCurrencyUuid: Uuid!
        $quoteCurrencyUuid: Uuid!
        $isQuoteFiat: Boolean!
        $productKey: String!
        $nativeCurrency: TickerSymbol!
        $skipUsdc: Boolean!
        $productType: RetailBrokerageProductType!
        $skipMultiPortfolio: Boolean!
        $portfolioUuid: Uuid
      ) {
        ...AvailableToTrade__EditOrderFormFragment
        ...EstimatedRebateFragment @arguments(productKey: $productKey)
        ...EditOrderAmountShortcutsFragment
          @arguments(productType: $productType)
      }
    `,
    {
      baseCurrencyId: baseSymbol ?? '',
      quoteCurrencyId: quoteSymbol ?? '',
      baseCurrencyUuid: baseSymbol ?? '',
      quoteCurrencyUuid: quoteSymbol ?? '',
      isQuoteFiat,
      productKey: order.productId,
      nativeCurrency,
      skipUsdc: true, // not needed for us since we pass in USDC as the quote value
      productType:
        productType ===
        CoinbasePublicApiAuthedRetailBrokerageApiProductType.FUTURE
          ? 'FUTURE'
          : 'SPOT',
      skipMultiPortfolio: false,
      portfolioUuid: selectedPortfolioUuid,
    },
  );

  const [limitPriceValue, setLimitPriceValue] = useState(
    getLimitPrice(order) || '',
  );

  const handleLimitPriceChange = useCallback(
    (ev: React.ChangeEvent<HTMLInputElement>) => {
      const value = ev.target.value;
      setLimitPriceValue(value);
    },
    [],
  );

  const handleLimitPriceShortcutPress = useCallback((value: string) => {
    setLimitPriceValue(value);
  }, []);

  const [amountValue, setAmountValue] = useState(getOrderSize(order) || '');

  const handleAmountChange = useCallback(
    (ev: React.ChangeEvent<HTMLInputElement>) => {
      const value = ev.target.value;
      setAmountValue(value);
    },
    [],
  );

  const handleAmountShortcutPress = useCallback((value: string) => {
    setAmountValue(value);
  }, []);

  const orderAmountAsBase = getOrderSize(order) || '0';
  // Handle the hold from the order being edited
  // Quote: The total order value including size in quote + fees
  const additionalQuoteAvailableToTrade = isBuy ? getOrderTotal(order) : '0';
  // Base: Only need the available base because fees are on top of the size
  const additionalBaseAvailableToTrade = isBuy ? '0' : orderAmountAsBase;

  const {
    isLoading: isPreviewLoading,
    isValid: isPreviewResponseValid,
    errors: previewErrors,
    previewOrderDetails,
  } = useValidateEditOrderForm({
    price: limitPriceValue,
    size: amountValue,
    order,
  });

  const {
    submitEditOrder,
    isLoading: isSubmitLoading,
    errors: submitErrors,
  } = useSubmitEditOrder();

  const isLoading = isPreviewLoading || isSubmitLoading;

  const { formError, fieldErrors } = useFormErrorMessages(
    { order, product },
    submitErrors,
    previewErrors,
  );

  const handleSubmit = useCallback(
    async (e: MouseEvent | FormEvent) => {
      e.preventDefault();
      if (!isPreviewResponseValid || isLoading) {
        return;
      }

      logEditOrderFormSubmitAttempt();

      try {
        await submitEditOrder({
          price: limitPriceValue,
          size: amountValue,
          orderUuid: order.orderId,
        });

        logEditOrderFormSubmitSuccess();
        showSuccessToast(formatMessage(messages.successToastMessage));
        close?.();
      } catch (e) {
        let errorDebugMessage;
        if (Array.isArray(e)) {
          // This is just informational based on our form error handling.
          // More granular, groupable data will be reported via the error message formatting hook.
          errorDebugMessage = JSON.stringify(e);
        } else if (e instanceof Error) {
          errorDebugMessage = e.message;
        } else if (typeof e === 'string') {
          errorDebugMessage = e;
        } else {
          errorDebugMessage = JSON.stringify(e);
        }

        logEditOrderFormSubmitError({ errorDebugMessage });
      }
    },
    [
      amountValue,
      close,
      formatMessage,
      isLoading,
      isPreviewResponseValid,
      limitPriceValue,
      order.orderId,
      showSuccessToast,
      submitEditOrder,
    ],
  );

  useLogEditOrderFormViewedEvent(entryPoint);

  // Report outside of the error parsing hook so we can eventually share it across mobile/web.
  useEffect(() => {
    if (formError) {
      logEditOrderFormValidationException(formError);
    }
  }, [formError]);

  useEffect(() => {
    // Because multiple field errors can be displayed out once we need to log
    // each validation error individually so we can aggregate properly in Amplitude.
    if (fieldErrors) {
      Object.values(fieldErrors).forEach(error => {
        if (error) {
          logEditOrderFormValidationException(error);
        }
      });
    }
  }, [fieldErrors?.LIMIT_PRICE?.code, fieldErrors?.SIZE?.code]);

  return (
    <form onSubmit={handleSubmit}>
      {/*error banner*/}
      {Boolean(formError?.userFriendlyMessage) && (
        <VStack spacingBottom={2}>
          <EditOrderFormErrorBanner
            errorMessage={formError?.userFriendlyMessage}
          />
        </VStack>
      )}
      <VStack spacingHorizontal={3}>
        <LatestTradePrice
          productId={order?.productId}
          quoteSymbol={quoteSymbol}
        />

        {/* Fields */}
        <VStack spacerGap={1} spacingTop={2}>
          <StyledDiv>
            <TextInput
              label={formatMessage(advancedCommonMessages.limitPrice)}
              type="number"
              compact
              align="end"
              value={limitPriceValue}
              onChange={handleLimitPriceChange}
              suffix={quoteSymbol}
              testID="limit-price-input"
              variant={fieldErrors?.LIMIT_PRICE && 'negative'}
              helperText={fieldErrors?.LIMIT_PRICE?.userFriendlyMessage}
            />
          </StyledDiv>
          <LimitPriceShortcuts
            entryPoint="EditOrderForm"
            productId={productIdAlias}
            orderSide={isBuy ? 'buy' : 'sell'}
            pricePrecision={pricePrecision}
            onSelect={handleLimitPriceShortcutPress}
          />

          <TextLegal as="p" align="end" color="foregroundMuted">
            {formatMessage(messages.filledAmount)} - {order?.filledSize} (
            {order?.completionPercentage}%)
          </TextLegal>
          <StyledDiv>
            <TextInput
              label={formatMessage(advancedCommonMessages.amount)}
              type="number"
              compact
              align="end"
              placeholder={getOrderSize(order)}
              suffix={baseSymbol}
              testID="amount-input"
              value={amountValue}
              onChange={handleAmountChange}
              variant={fieldErrors?.SIZE && 'negative'}
              helperText={fieldErrors?.SIZE?.userFriendlyMessage}
            />
          </StyledDiv>
          <EditOrderAmountShortcuts
            queryRef={query}
            onChange={handleAmountShortcutPress}
            orderAmountAsBase={orderAmountAsBase}
            orderSide={isBuy ? 'buy' : 'sell'}
            orderType={order.orderType || 'LIMIT'}
            paymentMethod={quoteSymbol === 'USDC' ? 'USDC' : 'USD'}
            limitPrice={limitPriceValue}
            productId={product.productId}
            quoteCurrencyId={quoteSymbol}
            basePrecision={basePrecision}
            quotePrecision={quotePrecision}
            aliasTo={product.aliasTo}
            executionOption={executionOption}
            additionalQuoteAvailableToTrade={additionalQuoteAvailableToTrade}
            additionalBaseAvailableToTrade={additionalBaseAvailableToTrade}
            selectedPortfolioUuid={selectedPortfolioUuid}
          />
        </VStack>

        {/* Calculated totals */}
        <VStack spacingHorizontal={1} spacingVertical={2} spacerGap={1}>
          <HStack justifyContent="space-between">
            <TextLabel1 as="p" color="foregroundMuted" transform="uppercase">
              {formatMessage(advancedCommonMessages.subtotal)}
            </TextLabel1>
            <TextLabel1 as="p" color="foregroundMuted" mono>
              {previewOrderDetails?.subtotal || DEFAULT_FORMATTED_FALLBACK}
            </TextLabel1>
          </HStack>

          <HStack justifyContent="space-between">
            <TextLabel1 as="p" color="foregroundMuted" transform="uppercase">
              {formatMessage(advancedCommonMessages.feeEst)}
            </TextLabel1>
            <TextLabel1 as="p" color="foregroundMuted" mono>
              {previewOrderDetails?.fee || DEFAULT_FORMATTED_FALLBACK}
            </TextLabel1>
          </HStack>
          <EstimatedRebate
            queryRef={query}
            quoteSymbol={quoteSymbol}
            fee={previewOrderDetails?.fee}
            label={formatMessage(messages.estRebateLabel)}
            amountColor="foregroundMuted"
          />
          <HStack justifyContent="space-between">
            <TextLabel1 as="p" color="foregroundMuted" transform="uppercase">
              {formatMessage(advancedCommonMessages.totalEst)}
            </TextLabel1>
            <TextLabel1 as="p" color="foregroundMuted" mono>
              {previewOrderDetails?.total || DEFAULT_FORMATTED_FALLBACK}
            </TextLabel1>
          </HStack>
        </VStack>

        {/* Buttons */}
        <VStack spacerGap={2}>
          <Button
            block
            compact
            variant="primary"
            onPress={handleSubmit}
            disabled={!isPreviewResponseValid}
            loading={isLoading}
            type="submit"
          >
            {formatMessage(messages.confirm)}
          </Button>
          <Button
            block
            compact
            variant="secondary"
            onPress={close}
            disabled={isLoading}
          >
            {formatMessage(messages.discardChanges)}
          </Button>
        </VStack>

        {/* Available to trade */}
        <AvailableToTrade
          queryRef={query}
          quoteSymbol={quoteSymbol}
          basePrecision={basePrecision}
          quotePrecision={quotePrecision}
          additionalQuoteAvailableToTrade={additionalQuoteAvailableToTrade}
          additionalBaseAvailableToTrade={additionalBaseAvailableToTrade}
          selectedPortfolioUuid={selectedPortfolioUuid}
        />
      </VStack>
    </form>
  );
}

function EditOrderForm(props: EditOrderFormProps) {
  const { orderId, close } = props;
  const { formatMessage } = useIntl();

  const { combinedOrders } = useOrdersStreams({});
  const order = useMemo(
    () => combinedOrders.find(o => o.orderId === orderId),
    [combinedOrders, orderId],
  );

  const formContent = useMemo(() => {
    if (!order) {
      return (
        <EditOrderFormErrorFallback code="ORDER_NOT_FOUND" close={close} />
      );
    }

    if (
      order.status !==
      CoinbasePublicApiAuthedRetailBrokerageApiOrderExecutionStatus.OPEN
    ) {
      return (
        <EditOrderFormErrorFallback
          code="STATUS_NOT_OPEN"
          close={close}
          order={order}
        />
      );
    }

    if (
      order.timeInForce ===
      CoinbasePublicApiAuthedRetailBrokerageApiTimeInForceType.GOOD_UNTIL_DATE_TIME
    ) {
      return (
        <EditOrderFormErrorFallback
          code="TIL_DATE_TIME"
          close={close}
          order={order}
        />
      );
    }

    return <EditOrderFormContent order={order} {...props} />;
  }, [close, order, props]);

  return (
    <VStack spacingBottom={3} minHeight={300}>
      <VStack spacingHorizontal={3} spacingVertical={3}>
        <HStack>
          <HStack width="66%" justifyContent="flex-end">
            <TextTitle3 as="h2">{formatMessage(messages.title)}</TextTitle3>
          </HStack>
          <HStack width="33%" justifyContent="flex-end">
            <PressableOpacity onPress={close}>
              <Icon name="close" size="s" color="foreground" />
            </PressableOpacity>
          </HStack>
        </HStack>
      </VStack>
      {formContent}
    </VStack>
  );
}

