import {
  useLogFeedbackButtonClick,
  useLogFeedbackButtonView,
} from './eventing';
import FeedbackAndResourcesModal from './FeedbackAndResourcesModal';

const SEEN_FEEDBACK_BUTTON_ATTRIBUTE = 'seen_advanced_feedback_button_web';

function FeedbackButton() {
  const [visible, { toggleOff, toggleOn }] = useToggler(false);
  const logFeedbackButtonClick = useLogFeedbackButtonClick();

  useLogFeedbackButtonView();

  const setUserAttribute = useSetUserAttribute();
  const hasSeenFeedbackButton = useUserAttribute<boolean>(
    SEEN_FEEDBACK_BUTTON_ATTRIBUTE,
  );

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleClick = () => {
    toggleOn();
    logFeedbackButtonClick();
    if (!hasSeenFeedbackButton) {
      setUserAttribute(SEEN_FEEDBACK_BUTTON_ATTRIBUTE, 'true');
    }
  };

  return (
    <>
      <Box spacingStart={0.5}>
        {hasSeenFeedbackButton ? (
          <IconButton name="info" onClick={toggleOn} />
        ) : (
          <DotStatusColor
            variant="primary"
            size="xs"
            overlap="circular"
            pin="top-end"
          >
            <IconButton name="info" onClick={handleClick} />
          </DotStatusColor>
        )}
      </Box>
      <FeedbackAndResourcesModal visible={visible} onClose={toggleOff} />
    </>
  );
}

