const MAX_INPUT_VALUE = 9999999;

type ProcessingSweep =
  | {
      isMax: boolean | null;
      value: string | undefined;
    }
  | undefined;

type PreviewSweepContentProps = {
  onTransferAmountPressed?: () => void;
  onTransferAllPressed?: () => void;
  excessLiquidity?: string;
  processingSweep?: ProcessingSweep;
};

export const PreviewSweepContent = memo(
  ({
    onTransferAmountPressed,
    onTransferAllPressed,
    excessLiquidity,
    processingSweep,
  }: PreviewSweepContentProps) => {
    const { formatMessage } = useIntl();
    const [amount, setAmount] = useState<string | undefined>();
    const [error, setError] = useState<boolean | undefined>();
    const formatAmount = useCurrencyFormatter();
    const { endAdvancedTradePerfMark } = useAdvancedTradePerfMarkers();
    const onAmountChanged = useCallback((amount?: string) => {
      setError(Number(amount) > MAX_INPUT_VALUE);
      setAmount(amount);
    }, []);

    endAdvancedTradePerfMark('view_schedule_manual_sweep_modal');

    const { setSweepAmount } = useManualSweepContext();

    const transferAmountButtonDisabled = useMemo(
      () =>
        amount === undefined || amount === '' || Number(amount) === 0 || error,
      [amount, error],
    );

    const onTransferAmount = useCallback(() => {
      logManualSweepCtaEvent({ componentName: 'schedule_transfer' });
      setSweepAmount(amount);
      onTransferAmountPressed?.();
    }, [amount, onTransferAmountPressed, setSweepAmount]);

    const onTransferMax = useCallback(() => {
      logManualSweepCtaEvent({ componentName: 'schedule_transfer_max' });
      setSweepAmount(undefined);
      onTransferAllPressed?.();
    }, [onTransferAllPressed, setSweepAmount]);

    return (
      <>
        <ModalBody alignItems="center">
          <VStack spacerGap={2}>
            <EntryInput
              viewerAssetRef={null}
              autoFocus
              input={{
                value: amount ?? '',
                symbol: 'USD',
                onChange: onAmountChanged,
                onEnter: onTransferAmount,
              }}
              error={
                error ? formatMessage(messages.validInputError) : undefined
              }
              helperText={formatMessage(messages.cashAvailableDisclaimer, {
                amount: formatAmount({
                  amount: {
                    currency: 'USD',
                    value:
                      !!excessLiquidity && Number(excessLiquidity) > 0
                        ? excessLiquidity
                        : '0',
                  },
                  isFiat: true,
                }),
              })}
              transparentBackground
            />
          </VStack>
          {Boolean(processingSweep) && (
            <ProcessingSweepInfo
              isMax={Boolean(processingSweep?.isMax)}
              value={processingSweep?.value}
            />
          )}
          <VStack spacingVertical={2} spacerGap={2}>
            <VStack spacerGap={1}>
              <Button
                testID="preview-sweep-transfer-amount-cta"
                disabled={transferAmountButtonDisabled}
                block
                variant="primary"
                onPress={onTransferAmount}
              >
                {formatMessage(messages.transferAmount)}
              </Button>
              <Button
                testID="preview-sweep-transfer-all-cta"
                block
                variant="secondary"
                onPress={onTransferMax}
              >
                {formatMessage(messages.transferAll)}
              </Button>
            </VStack>
            <VStack spacerGap={2}>
              <TextLegal
                testID="preview-sweep-disclaimer-one"
                as="p"
                color="foreground"
              >
                {formatMessage(messages.disclaimerOne)}
              </TextLegal>
              <TextLegal
                testID="preview-sweep-disclaimer-two"
                as="p"
                color="foreground"
              >
                {formatMessage(messages.disclaimerTwo, {
                  seeFullTerms: (
                    <Link
                      to={getDerivativesHelpLink('transfer_cash')}
                      target="_blank"
                      aria-label={messages.seeFullTerms.description}
                      underline={false}
                    >
                      {formatMessage(messages.seeFullTerms)}
                    </Link>
                  ),
                })}
              </TextLegal>
              <TextLegal
                testID="preview-sweep-disclaimer-three"
                as="p"
                color="foreground"
              >
                {formatMessage(messages.disclaimerThree)}
              </TextLegal>
            </VStack>
          </VStack>
        </ModalBody>
      </>
    );
  },
);

PreviewSweepContent.displayName = 'PreviewSweepContent';

