import useSubscribePriceOverrideHandler from 'views/Advanced/contexts/PriceOverrideNotificationContext/useSubscribePriceOverrideHandler';
import { useOrderFormContext } from 'views/Advanced/surfaces/perpetual-futures/context/OrderFormContext/useOrderFormContext';
import { useSurfaceContext } from 'views/Advanced/surfaces/perpetual-futures/context/SurfaceContext';
import useIsAuctionMode from 'views/Advanced/surfaces/perpetual-futures/utils/useIsAuctionMode';
import { advancedTradeSharedEvent } from 'views/Advanced/utils/eventing/useAdvancedTradeEvent';

const i18nKey = 'LimitPriceField';

const messages = defineMessages({
  invalidLimitPrice: {
    id: `${i18nKey}.invalidLimitPrice`,
    defaultMessage: 'Invalid limit price',
    description: `
      #Component:Label
      #CharLimit:50
      #Context:label for the error denoting an invalid limit price on the order form
    `,
  },
});

type Props = {
  label: string;
  currency?: string;
  errors: string[];
  placeholder?: string;
  onChange?: (n: number) => void;
  disabled: boolean;
  value: number | null;
};

function LimitPriceField({
  onChange,
  value,
  errors,
  label,
  currency,
  disabled,
  placeholder,
}: Props) {
  const limitPriceRef = useRef<HTMLInputElement>(null);
  const { priceIncrement, product } = useSurfaceContext();
  const { formatMessage } = useIntl();
  const { midMarketPrice } = useOrderFormContext();
  const isAuctionMode = useIsAuctionMode(product.auctionMode);
  const [touched, setTouched] = useState<boolean>(false);
  const [limitPrice, setLimitPrice] = useState<string | undefined>(undefined);
  const subscribePriceOverrideHandler = useSubscribePriceOverrideHandler();

  const updateLimitPrice = useCallback(
    (value: string) => {
      setLimitPrice(value);
      const valueAsNumber = Number(value);
      // for an empty field "" convert empty string to number (0)
      onChange?.(valueAsNumber);
    },
    [onChange],
  );

  const handleChange = useCallback<ChangeEventHandler<HTMLInputElement>>(
    event => {
      const value = event.target.value;
      updateLimitPrice(value);
    },
    [updateLimitPrice],
  );

  // if there is an error this field cares about
  const hasError = useMemo(() => {
    return errors.find(error =>
      [
        CoinbasePublicApiAuthedRetailBrokerageApiPreviewFailureReason.PREVIEW_INVALID_LIMIT_PRICE,
        CoinbasePublicApiAuthedRetailBrokerageApiPreviewFailureReason.PREVIEW_INVALID_LIMIT_PRICE_POST_ONLY,
      ].includes(
        error as CoinbasePublicApiAuthedRetailBrokerageApiPreviewFailureReason,
      ),
    );
  }, [errors]);

  const onFocus = useCallback(() => {
    setTouched(true);
    advancedTradeSharedEvent({
      eventName: 'order_form_limit_price_focus',
    });
  }, []);

  useEffect(() => {
    if (!touched) {
      setLimitPrice(
        isAuctionMode ? '0' : midMarketPrice?.toString() ?? undefined,
      );
    }
    if (value === null && onChange && isAuctionMode) {
      onChange(0);
    } else if (value === null && onChange && midMarketPrice) {
      onChange(midMarketPrice);
    }
  }, [midMarketPrice, onChange, value, setLimitPrice, touched, isAuctionMode]);

  useEffect(() => {
    return subscribePriceOverrideHandler((price: string) => {
      if (!onChange) {
        return;
      }
      limitPriceRef.current?.focus();
      // Round price to nearest increment to ensure valid input
      const roundedToIncrementPrice = Big(price)
        .div(priceIncrement)
        .round()
        .times(priceIncrement)
        .toString();

      updateLimitPrice(roundedToIncrementPrice);
    });
  }, [subscribePriceOverrideHandler]);

  return (
    <StyledVStack spacerGap={0.5}>
      <TextInput
        align="end"
        placeholder={placeholder}
        color="foreground"
        type="number"
        min={0}
        ref={limitPriceRef}
        key="perps-limit-price-field"
        onFocus={onFocus}
        variant={hasError ? 'negative' : undefined}
        onChange={handleChange}
        value={limitPrice}
        disabled={disabled}
        start={
          <TextLabel1
            as="label"
            noWrap={true}
            transform="uppercase"
            spacingHorizontal={2}
            color="foreground"
          >
            {label}
          </TextLabel1>
        }
        end={
          currency ? (
            <TextHeadline
              as="label"
              noWrap={true}
              transform="uppercase"
              spacingEnd={2}
              color="foregroundMuted"
            >
              {currency}
            </TextHeadline>
          ) : null
        }
      />
      {hasError && (
        <TextLabel1 as="p" color="negative" transform="uppercase">
          {formatMessage(messages.invalidLimitPrice)}
        </TextLabel1>
      )}
    </StyledVStack>
  );
}

const StyledVStack = styled(VStack)`
  /* stylelint-disable declaration-no-important -- 2023.08.29 */
  span {
    border-color: var(--line) !important;
  }
`;

export default memo(LimitPriceField);

