import { TextHeadline, TextLabel1, TextLabel2 } from '@cbhq/cds-web/typography';
import { logEvent, ComponentType, ActionType } from '@cbhq/client-analytics';
import { CoinbasePublicApiAuthedRetailBrokerageApiPreviewFailureReason } from '@cbhq/instant-api-hooks-retail-brokerage/types';

import { useSurfaceContext } from 'views/Advanced/surfaces/perpetual-futures/context/SurfaceContext';
import { convertQuoteAmountToBase } from 'views/Advanced/surfaces/perpetual-futures/utils/convertQuoteAmountToBase';
import { advancedTradeSharedEvent } from 'views/Advanced/utils/eventing/useAdvancedTradeEvent';

import TransferModal from '../../../../flows/TransferFlow/TransferModal';
