const i18nKey = 'SizeField';

const messages = defineMessages({
  size: {
    id: `${i18nKey}.size`,
    defaultMessage: 'Size',
    description: `
      #Component:Label
      #CharLimit:50
      #Context:label for the size field
    `,
  },
  amount: {
    id: `${i18nKey}.amount`,
    defaultMessage: 'Amount',
    description: `
      #Component:Label
      #CharLimit:50
      #Context:label for the size field
    `,
  },
  insufficientBalance: {
    id: `${i18nKey}.insufficientBalance`,
    defaultMessage: 'Insufficient Balance.',
    description: `
      #Component:Body
      #CharLimit:100
      #Context:label for the insufficient balance error message
    `,
  },
  transferFunds: {
    id: `${i18nKey}.transferFunds`,
    defaultMessage: 'Transfer Funds',
    description: `
      #Component:Button
      #CharLimit:50
      #Context:label for the propt to add funds if there is an insufficient balance
    `,
  },
});

type Props = {
  errors: string[];
  placeholder?: string;
  onChange?: (n: number) => void;
  disabled: boolean;
  value: number;
  orderType: OrderType;
  limitPrice: number;
  disableQuoteChange?: boolean;
};

function SizeField({
  errors,
  placeholder,
  onChange,
  disabled,
  value,
  orderType,
  limitPrice,
  disableQuoteChange,
}: Props) {
  const { formatMessage } = useIntl();
  const { openModal, closeModal } = useModal();
  const {
    productId,
    quoteCurrencyId,
    baseCurrencyId,
    quotePrecision,
    basePrecision,
    baseIncrement,
    amountCurrencyId,
    setAmountCurrencyId,
  } = useSurfaceContext();
  const [size, setSize] = useState<number | undefined>(value);
  const marketPrice = useMidMarketPrice(productId);

  useEffect(() => {
    setAmountCurrencyId(baseCurrencyId);
    setSize(0);
    onChange?.(0);
  }, [baseCurrencyId]);

  // if there is an error this field cares about
  const hasError = useMemo(() => {
    return errors.includes(
      CoinbasePublicApiAuthedRetailBrokerageApiPreviewFailureReason.PREVIEW_INSUFFICIENT_FUNDS_FOR_FUTURES,
    );
  }, [errors]);

  const handleChange = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (event: any) => {
      const newValue = event.target.value;
      if (newValue === '') {
        setSize(undefined);
        onChange?.(0);
        return;
      }
      if (amountCurrencyId === quoteCurrencyId) {
        // quote currency
        const regex = new RegExp(`^\\d*(\\.\\d{0,${quotePrecision}})*$`);
        if (regex.test(newValue)) {
          setSize(newValue);
        } else {
          return;
        }
        const valueInBaseCurrency = convertQuoteAmountToBase({
          amount: newValue.toString(),
          price:
            orderType === OrderTypeRecord.LIMIT
              ? limitPrice?.toString()
              : marketPrice,
          basePrecision,
        });
        onChange?.(Number(Number(valueInBaseCurrency).toFixed(basePrecision)));
        return;
      } else {
        // base currency
        const regex = new RegExp(`^\\d*(\\.\\d{0,${basePrecision}})*$`);
        if (regex.test(newValue)) {
          setSize(newValue);
          onChange?.(Number(newValue));
        }
      }
    },
    [
      amountCurrencyId,
      quoteCurrencyId,
      onChange,
      quotePrecision,
      orderType,
      limitPrice,
      marketPrice,
      basePrecision,
    ],
  );

  // 2023-10-19: TODO please fix
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleFocus = useCallback((event: any) => {
    if (event.target.value === '0') setSize(undefined);
    advancedTradeSharedEvent({
      eventName: 'order_form_amount_focus',
    });
  }, []);

  // 2023-10-19: TODO please fix
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleBlur = useCallback((event: any) => {
    if (event.target.value === '') setSize(0);
  }, []);

  const handleAddFunds = useCallback(() => {
    logEvent('transfer_funds_click', {
      componentType: ComponentType.link,
      action: ActionType.click,
      entryPage: 'order_form_error_insufficient_funds_intx',
      productType: 'perpetual_future',
    });
    openModal(
      <TransferModal
        visible
        hideCloseButton
        hideDividers
        onClose={closeModal}
        disableWithdraw
        entryPage="order_form"
      />,
    );
  }, [openModal, closeModal]);

  const handleCurrencyChange = useCallback(
    (newCurrency: string) => {
      setAmountCurrencyId(newCurrency);
      setSize(0);
    },
    [setAmountCurrencyId],
  );

  const content = useMemo(() => {
    return [baseCurrencyId, quoteCurrencyId].map(currency => (
      <SelectOption key={currency} value={currency} title={currency} />
    ));
  }, [baseCurrencyId, quoteCurrencyId]);

  return (
    <StyledVStack spacerGap={0.5}>
      <TextInput
        align="end"
        placeholder={placeholder}
        color="foreground"
        type="number"
        min={0}
        step={baseIncrement}
        variant={hasError ? 'negative' : undefined}
        value={size === undefined ? '' : size}
        onChange={handleChange}
        onFocus={handleFocus}
        onBlur={handleBlur}
        disabled={disabled}
        testID="size-field"
        start={
          <TextLabel1
            as="label"
            noWrap={true}
            transform="uppercase"
            spacingHorizontal={2}
            color="foreground"
          >
            {formatMessage(messages.amount)}
          </TextLabel1>
        }
        end={
          <HStack alignItems="center">
            <TextHeadline
              as="label"
              noWrap={true}
              transform="uppercase"
              color="foreground"
              spacingEnd={0}
            >
              {amountCurrencyId}
            </TextHeadline>
            {!disableQuoteChange ? (
              <Dropdown
                value={amountCurrencyId}
                onChange={handleCurrencyChange}
                content={content}
              >
                <IconButton
                  transparent
                  name="caretDown"
                  variant="foregroundMuted"
                />
              </Dropdown>
            ) : (
              <Box spacingEnd={2} />
            )}
          </HStack>
        }
      />
      {errors.includes(
        CoinbasePublicApiAuthedRetailBrokerageApiPreviewFailureReason.PREVIEW_INSUFFICIENT_FUNDS_FOR_FUTURES,
      ) && (
        <TextLabel2 as="p" color="negative" transform="uppercase">
          {formatMessage(messages.insufficientBalance)}{' '}
          <Pressable background="transparent" onPress={handleAddFunds}>
            <TextLabel2 as="span" color="primary" transform="uppercase">
              {formatMessage(messages.transferFunds)}
            </TextLabel2>
          </Pressable>
        </TextLabel2>
      )}
    </StyledVStack>
  );
}

const StyledVStack = styled(VStack)`
  /* stylelint-disable declaration-no-important -- 2023.08.29 */
  span {
    border-color: var(--line) !important;
  }
`;

export default memo(SizeField);

