      #CharLimit:50
      #Context:label for denoting market order type cannot be used when auction mode is on
      #VariableExample:link to learn more about auction mode
    `,
  },
  stopLimitOrdersUnavailableAuctionModeTooltipContent: {
    id: `${i18nKey}.stopLimitOrdersUnavailableAuctionMode`,
    defaultMessage:
      'Stop limit orders are unavailable in auction mode. {learnMoreLink}',
    description: `
      #Component:Label
      #CharLimit:50
      #Context:label for denoting stop limit order type cannot be used when auction mode is on
      #VariableExample:link to learn more about auction mode
    `,
  },
  invalidLimitOrStopLimitPrice: {
    id: `${i18nKey}.invalidLimitOrStopLimitPrice`,
    defaultMessage:
      'Invalid order configuration. Enter a valid limit / stop price and try again',
    description: `
      #Component:Body
      #CharLimit:160
      #Context:Error message informing user that their stop limit price or limit price is invalid`,
  },
  marginTypeChangeDisabledOpenOrdersOrPositionsTooltipContent: {
    id: `${i18nKey}.marginTypeChangeDisabledOpenOrdersOrPositionsTooltipContent`,
    defaultMessage:
      "Margin type can't be changed while you currently have open orders or positions of the other type. {learnMoreLink}",
    description: `
      #Component:Tooltip
      #CharLimit:150
      #Context:text for the tooltip notifying user they can't change their margin type due to having an open order or position of other type
      #VariableExample:link to learn more about margin types
    `,
  },
  marginTypeChangeDisabledForPreLaunchContractToolTipContent: {
    id: `${i18nKey}.marginTypeChangeDisabledForPreLaunchContractToolTipContent`,
    defaultMessage:
      'Pre-Launch Markets can only be traded using isolated margin. {learnMoreLink}',
    description: `
      #Component:Tooltip
      #CharLimit:150
      #Context:text for the modal notifying user they can't change their margin type due to market being prelaunch contract
      #VariableExample:link to learn more about pre-launch contracts
    `,
  },
});

type Props = {
  onSubmit: (orderPreview: OrderPreviewData) => void;
  side: OrderFormContext['side'];
  execution: ExecutionType;
  setExecution: (execution: ExecutionType) => void;
  expiration: TimeInForceOptions;
  setExpiration: (expiration: TimeInForceOptions) => void;
  queryRef: PerpsOrderFormFragment$key;
  setSide: (side: CoinbasePublicApiAuthedRetailBrokerageApiOrderSide) => void;
};

function PerpsOrderForm({
  onSubmit,
  side,
  execution,
  expiration,
  setExecution,
  setExpiration,
  queryRef,
  setSide,
}: Props) {
  const { openModal, closeModal } = useModal();
  // NOTE: decided to use formatNumber rather than `useCurrencyFormatter` due to some formatting issues
  // specifically getting USDC to format as USD.
  const { formatMessage, formatNumber } = useIntl();

  const { productId, quoteCurrencyId, product } = useSurfaceContext();
  const marketPrice = useMidMarketPrice(productId);

  const isAuctionMode = useIsAuctionMode(product.auctionMode);
  const isPreLaunchContract = useIsIntxPreLaunchContract(product.status);

  const query = useFragment(
    graphql`
      fragment PerpsOrderFormFragment on Query {
        ...useIntxAccessLevelATSFragment
        ...useHasOpenOrdersOrExistingPositionsFragment
        ...PromotionalTagContentFragment
        viewer @skip(if: $skipPerpsTrading) {
          perpetualFuturePositionsV2 {
            portfolioSummary {
              buyingPower {
                amount
              }
            }
          }
        }
      }
    `,
    queryRef,
  );
  const {
    hasOpenOrdersOrExistingPositions,
    existingMarginType,
    existingLeverage,
  } = useHasOpenOrdersOrExistingPositions(query, productId);

  const { intxAccessLevel } = useIntxAccessLevel({ queryRef: query });
  const isStopLimitEnabled = useIsPerpsStopLimitEnabled();
  const mapOrderPreviewErrorToContent = useMapOrderPreviewErrorEnumsToContent();

  const isTPSLEnabled = useIsIntxTPSLEnabled();

  const [orderType, setOrderType] = useState<OrderType>(OrderTypeRecord.LIMIT);
  const [marginType, setMarginType] =
    useState<CoinbasePublicApiAuthedRetailBrokerageApiMarginType>(
      isPreLaunchContract
        ? CoinbasePublicApiAuthedRetailBrokerageApiMarginType.ISOLATED
        : existingMarginType ||
            CoinbasePublicApiAuthedRetailBrokerageApiMarginType.CROSS,
    );

  const { defaultLeverage, leverageOptions } = useProductLeverageMapping(
    productId,
    existingLeverage,
    isPreLaunchContract,
  );
  const [leverage, setLeverage] = useState<number>(defaultLeverage);
  const [limitPrice, setLimitPrice] = useState<number | null>(null);
  const [stopLimitPrice, setStopLimitPrice] = useState<number | null>(null);
  const [size, setSize] = useState<number>(0);
  const [hasNetworkError, setHasNetworkError] = useState<boolean>(false);

  const [orderPreview, setOrderPreview] = useState<OrderPreviewData>({
    request: null,
    response: null,
    orderType,
  });

  const isAccessLevelRestricted =
    intxAccessLevel === 'ACCESS_LEVEL_RESTRICTED_IP';

  const isolatedMarginExperimentEnabled = useIsIsolatedMarginEnabled({
    skipTracking: isAccessLevelRestricted,
  });

  const defaultMarginType = isPreLaunchContract
    ? CoinbasePublicApiAuthedRetailBrokerageApiMarginType.ISOLATED
    : hasOpenOrdersOrExistingPositions && existingMarginType !== null
    ? existingMarginType
    : marginType;

  const previewOrder = usePreviewOrder();

  useEffect(() => {
    advancedTradeSharedEvent({
      eventName: 'order_form_page',
    });
  }, []);

  useEffect(() => {
    const validate = async () => {
      if (
        hasRequiredValues({
          orderType,
          size,
          limitPrice,
          stopLimitPrice,
          execution,
          expiration,
          stopLimitError,
          limitPriceError,
        })
      ) {
        setHasNetworkError(false);
        const orderConfiguration = getOrderConfiguration({
          orderType,
          size,
          limitPrice,
          stopLimitPrice,
          execution,
          expiration,
        });
        const request: CoinbasePublicApiAuthedRetailBrokerageApiOrderPreviewRequest =
          {
            productId,
            side,
            commissionRate: {}, // NOTE: real rate is calculated by the BE
            orderConfiguration,
            leverage: leverage.toString(),
            marginType,
          };
        const response = (await previewOrder(request)) as
          | CoinbasePublicApiAuthedRetailBrokerageApiOrderPreviewResponse
          | ErrorTypes;
        if ('error' in response) {
          setHasNetworkError(true);
          advancedTradeSharedEvent({
            eventName: 'order_form_preview_error',
            optionalEventParameters: {
              orderSide: request?.side,
              orderType: orderPreview?.orderType as OrderFormType,
              error: response?.error?.message,
            },
          });
        } else if ('orderTotal' in response) {
          // TODO: errors from here should be reflected in UI
          setOrderPreview({ request, response, orderType });
          if (orderPreview?.response?.errs[0]) {
            advancedTradeSharedEvent({
              eventName: 'order_form_preview_error',
              optionalEventParameters: {
                orderSide: orderPreview?.request?.side,
                orderType: orderPreview?.orderType as OrderFormType,
                error: orderPreview?.response?.errs[0],
              },
            });
          }
        }
      }
    };
    validate();
  }, [
    productId,
    orderType,
    limitPrice,
    stopLimitPrice,
    size,
    expiration,
    execution,
    side,
    leverage,
    marginType,
  ]);

  const handleSubmit = useCallback(async () => {
    if (orderPreview) {
      onSubmit(orderPreview);
      advancedTradeSharedEvent({
        eventName: 'order_preview_button',
        optionalEventParameters: {
          orderSide: orderPreview?.request?.side,
          orderType: orderPreview?.orderType,
          feeUsd: orderPreview?.response?.commissionTotal,
          totalUsd: orderPreview?.response?.orderTotal,
        },
      });
    }
  }, [onSubmit, orderPreview]);

  const reset = useCallback(() => {
    setLimitPrice(null);
    setStopLimitPrice(null);
    setSize(0);
    setExecution(DEFAULT_EXECUTION_TYPE);
    setExpiration({
      timeInForce: 'GTC',
      expiration: '1m',
    });
    setOrderPreview({
      request: null,
      response: null,
      orderType: null,
    });
    setLeverage(defaultLeverage);
  }, [defaultLeverage, setExecution, setExpiration]);

  // when a productId changes - reset the form
  useEffect(() => {
    reset();
  }, [productId, reset]);

  const handleOrderTypeChange = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (type: any) => {
      reset();
      setOrderType(type);
      advancedTradeSharedEvent({
        eventName: 'order_type_button',
        optionalEventParameters: {
          orderType: type,
        },
      });
    },
    [setOrderType, reset],
  );

  const handleStopPriceChange = useCallback(
    (value: number) => {
      setStopLimitPrice(value);
    },
    [setStopLimitPrice],
  );

  const handleLimitPriceChange = useCallback(
    (value: number) => {
      setLimitPrice(value);
    },
    [setLimitPrice],
  );

  const handleSizeChange = useCallback(
    (value: number) => {
      setSize(value);
    },
    [setSize],
  );

  const handleExecutionChange = useCallback(
    (value: ExecutionType) => {
      setExecution(value);
      advancedTradeSharedEvent({
        eventName: 'order_type_details_execution_select',
        optionalEventParameters: {
          orderType,
          executionType: value,
        },
      });
    },
    [orderType, setExecution],
  );

  const handleExpirationChange = useCallback(
    (value: TimeInForceOptions) => {
      setExpiration(value);
      advancedTradeSharedEvent({
        eventName: 'order_type_details_expiration',
        optionalEventParameters: {
          expirationType: value,
        },
      });
    },
    [setExpiration],
  );

  const handleTransferPress = useCallback(() => {
    logEvent('transfer_funds_click', {
      componentType: ComponentType.button,
      action: ActionType.click,
      entryPage: 'order_form_insufficient_funds_preview_error_cta_intx',
      productType: 'perpetual_future',
    });
    openModal(
      <TransferModal
        visible
        onClose={closeModal}
        hideCloseButton
        hideDividers
        disableWithdraw
        entryPage="order_form"
      />,
    );
  }, [closeModal, openModal]);

  const notionalValue = useMemo(() => {
    let notional = 0;
    if (orderType === OrderTypeRecord.MARKET) {
      notional = (marketPrice ? parseFloat(marketPrice) : 0) * size;
    } else if (
      orderType === OrderTypeRecord.LIMIT ||
      orderType === OrderTypeRecord.STOP_LIMIT
    ) {
      notional = (limitPrice ?? 0) * size;
    }
    return `${formatNumber(notional, {
      style: 'decimal',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    })} ${quoteCurrencyId}`;
  }, [limitPrice, size, formatNumber, quoteCurrencyId, orderType, marketPrice]);

  /*NOTE: There is currently a race condition with the query persisting size data after
  the reset which causes margin to be displayed from the previous form entry when a perp is changed
  via navigation. While the reset works correctly the quickest work around is to evaluate size before
  calculating margin for total */
  const marginRequired = useMemo(
    () =>
      size && orderPreview.response?.orderMarginTotal
        ? Number(orderPreview.response?.orderMarginTotal)
        : 0,
    [orderPreview.response?.orderMarginTotal, size],
  );

  const marginRequiredFormatted = useMemo(
    () =>
      `${formatNumber(marginRequired, {
        style: 'decimal',
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
      })} ${quoteCurrencyId}`,
    [formatNumber, marginRequired, quoteCurrencyId],
  );

  const estFee = useMemo(() => {
    const fee = Number(orderPreview?.response?.commissionTotal) || 0;
    return `${formatNumber(fee, {
      style: 'decimal',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    })} ${quoteCurrencyId}`;
  }, [orderPreview, formatNumber, quoteCurrencyId]);

  const estTotal = useMemo(() => {
    const fee = Number(orderPreview?.response?.commissionTotal) || 0;
    const total = marginRequired + fee;
    return `${formatNumber(total, {
      style: 'decimal',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    })} ${quoteCurrencyId}`;
  }, [
    orderPreview?.response?.commissionTotal,
    marginRequired,
    formatNumber,
    quoteCurrencyId,
  ]);

  const maxLeverage = useMemo(
    () => orderPreview.response?.maxLeverage,
    [orderPreview.response?.maxLeverage],
  );

  const error = useMemo(() => {
    const errs = orderPreview.response?.errs;
    if (hasNetworkError) return formatMessage(messages.genericError);
    if (!errs || errs.length === 0) return null;
    const error = head(errs);
    if (!error) return null;
    // temporary until intx supports specific error messaging on which part of the order configuration is invalid
    if (
      error ===
        CoinbasePublicApiAuthedRetailBrokerageApiPreviewFailureReason.PREVIEW_INVALID_LIMIT_PRICE &&
      orderType === 'stop_limit'
    ) {
      return formatMessage(messages.invalidLimitOrStopLimitPrice);
    }
    return mapOrderPreviewErrorToContent(
      error,
      side.toLowerCase() as OrderFormSide,
      maxLeverage,
    ).message;
  }, [
    orderPreview.response?.errs,
    hasNetworkError,
    formatMessage,
    orderType,
    mapOrderPreviewErrorToContent,
    side,
    maxLeverage,
  ]);

  const disabled = useMemo(() => {
    return (
      !orderPreview?.response ||
      (orderPreview.response?.errs && orderPreview.response?.errs.length > 0)
    );
  }, [orderPreview]);

  const button = useMemo(() => {
    const buyingPower =
      query.viewer?.perpetualFuturePositionsV2?.portfolioSummary?.buyingPower
        ?.amount;
    if (
      !hasOpenOrdersOrExistingPositions &&
      buyingPower &&
      Number(buyingPower) === 0
    ) {
      return (
        <Button onPress={handleTransferPress}>
          {formatMessage(messages.transferCta)}
        </Button>
      );
    }
    return (
      <>
        <Button
          variant={
            side === CoinbasePublicApiAuthedRetailBrokerageApiOrderSide.BUY
              ? 'positive'
              : 'negative'
          }
          onPress={handleSubmit}
          disabled={disabled || isAccessLevelRestricted}
        >
          {side === CoinbasePublicApiAuthedRetailBrokerageApiOrderSide.BUY
            ? formatMessage(messages.previewBuyOrder)
            : formatMessage(messages.previewSellOrder)}
        </Button>
        <TextLegal as="p">
          {formatMessage(sharedMessages.disclaimer, {
            LearnMoreLink: (
              <Link
                to="https://help.coinbase.com/en/coinbase/trading-and-funding/derivatives/pf-funds"
                openInNewWindow
              >
                {formatMessage(sharedMessages.learnMoreLink)}
              </Link>
            ),
          })}
        </TextLegal>
      </>
    );
  }, [
    hasOpenOrdersOrExistingPositions,
    disabled,
    formatMessage,
    handleSubmit,
    handleTransferPress,
    isAccessLevelRestricted,
    query.viewer?.perpetualFuturePositionsV2?.portfolioSummary?.buyingPower
      ?.amount,
    side,
  ]);

  // TODO: 2024-04-26: We should pull these tooltips out of the component for readability.
  const marketOrdersUnavailableAuctionModeTooltipContent = useMemo(() => {
    return (
      <TextBody as="p">
        {formatMessage(
          messages.marketOrdersUnavailableAuctionModeTooltipContent,
          {
            learnMoreLink: (
              <Link
                to="https://help.coinbase.com/en/coinbase/trading-and-funding/derivatives/auction-mode-international-exchange"
                openInNewWindow
              >
                {formatMessage(sharedMessages.learnMoreLink)}
              </Link>
            ),
          },
        )}
      </TextBody>
    );
  }, [formatMessage]);

  const marginTypeChangeDisabledForPreLaunchContractToolTipContent =
    useMemo(() => {
      return (
        <TextBody as="p" color="primaryForeground">
          {formatMessage(
            messages.marginTypeChangeDisabledForPreLaunchContractToolTipContent,
            {
              learnMoreLink: (
                <Link
                  to="https://help.coinbase.com/en/international-exchange/pre-launch-markets/what-is-a-pre-launch-market"
                  openInNewWindow
                >
                  {formatMessage(sharedMessages.learnMoreLink)}
                </Link>
              ),
            },
          )}
        </TextBody>
      );
    }, [formatMessage]);

  const marginTypeChangeDisabledOpenOrdersOrPositionsTooltipContent =
    useMemo(() => {
      return (
        <TextBody as="p" color="primaryForeground">
          {formatMessage(
            messages.marginTypeChangeDisabledOpenOrdersOrPositionsTooltipContent,
            {
              learnMoreLink: (
                <Link
                  to="https://help.coinbase.com/en/coinbase/trading-and-funding/derivatives/pf-margin-types"
                  openInNewWindow
                >
                  {formatMessage(sharedMessages.learnMoreLink)}
                </Link>
              ),
            },
          )}
        </TextBody>
      );
    }, [formatMessage]);

  const stopLimitOrdersUnavailableAuctionModeTooltipContent = useMemo(() => {
    return (
      <TextBody as="p">
        {formatMessage(
          messages.stopLimitOrdersUnavailableAuctionModeTooltipContent,
          {
            learnMoreLink: (
              <Link
                to="https://help.coinbase.com/en/coinbase/trading-and-funding/derivatives/auction-mode-international-exchange"
                openInNewWindow
              >
                {formatMessage(sharedMessages.learnMoreLink)}
              </Link>
            ),
          },
        )}
      </TextBody>
    );
  }, [formatMessage]);

  const limitOnlyTooltipContent = useMemo(() => {
    return (
      <TextBody as="p">
        {formatMessage(messages.limitOnlyTooltipContent, {
          learnMoreLink: (
            <Link
              to="https://help.coinbase.com/en/coinbase/trading-and-funding/advanced-trade/market-availability"
              openInNewWindow
            >
              {formatMessage(sharedMessages.learnMoreLink)}
            </Link>
          ),
        })}
      </TextBody>
    );
  }, [formatMessage]);

  const pillButtons = useMemo(() => {
    const buttons: PillButton[] = [
      {
        key: OrderTypeRecord.LIMIT,
        content: formatMessage(sharedMessages.limitOrder),
      },
      {
        key: OrderTypeRecord.MARKET,
        content: formatMessage(sharedMessages.marketOrder),
        pillDisabled: isAuctionMode || product.postOnly,
        tooltipContent: isAuctionMode
          ? marketOrdersUnavailableAuctionModeTooltipContent
          : product.postOnly
          ? limitOnlyTooltipContent
          : null,
      },
    ];

    if (isTPSLEnabled) {
      // TODO(RTINTX-1735): Add TP/SL button to list of pill buttons
    }

    if (isStopLimitEnabled) {
      buttons.push({
        key: OrderTypeRecord.STOP_LIMIT,
        content: formatMessage(sharedMessages.stopLimitOrder),
        pillDisabled: isAuctionMode,
        tooltipContent: isAuctionMode
          ? stopLimitOrdersUnavailableAuctionModeTooltipContent
          : null,
      });
    }
    return buttons;
  }, [
    formatMessage,
    isAuctionMode,
    isStopLimitEnabled,
    isTPSLEnabled,
    limitOnlyTooltipContent,
    marketOrdersUnavailableAuctionModeTooltipContent,
    product.postOnly,
    stopLimitOrdersUnavailableAuctionModeTooltipContent,
  ]);

  const placeholderFormatConfig = useMemo(
    () => ({
      style: 'decimal' as const,
      minimumFractionDigits: 2,
    }),
    [],
  );

  const quoteNumericPlaceholder = useMemo(
    () => formatNumber(0, placeholderFormatConfig),
    [formatNumber, placeholderFormatConfig],
  );

  const stopLimitError = useMemo(() => {
    if (
      side === CoinbasePublicApiAuthedRetailBrokerageApiOrderSide.BUY &&
      stopLimitPrice &&
      marketPrice &&
      stopLimitPrice < Number(marketPrice)
    ) {
      return formatMessage(messages.invalidStopLimitPriceBuy);
    } else if (
      side === CoinbasePublicApiAuthedRetailBrokerageApiOrderSide.SELL &&
      stopLimitPrice &&
      marketPrice &&
      stopLimitPrice > Number(marketPrice)
    ) {
      return formatMessage(messages.invalidStopPriceSell);
    }
    return '';
  }, [formatMessage, marketPrice, side, stopLimitPrice]);

  const limitPriceError = useMemo(() => {
    if (
      side === CoinbasePublicApiAuthedRetailBrokerageApiOrderSide.BUY &&
      stopLimitPrice &&
      limitPrice &&
      limitPrice <= stopLimitPrice
    ) {
      return formatMessage(messages.invalidLimitPriceBuy);
    } else if (
      side === CoinbasePublicApiAuthedRetailBrokerageApiOrderSide.SELL &&
      stopLimitPrice &&
      limitPrice &&
      limitPrice >= stopLimitPrice
    ) {
      return formatMessage(messages.invalidLimitPriceSell);
    }
    return '';
  }, [formatMessage, limitPrice, side, stopLimitPrice]);

  const marginTooltip = isPreLaunchContract
    ? marginTypeChangeDisabledForPreLaunchContractToolTipContent
    : hasOpenOrdersOrExistingPositions
    ? marginTypeChangeDisabledOpenOrdersOrPositionsTooltipContent
    : undefined;

  return (
    <MaskContainer data-dulled={isAccessLevelRestricted}>
      <VStack flexGrow={1} spacerGap={2} borderedTop offsetHorizontal={2}>
        <VStack spacerGap={2}>
          <OrderFormTabs side={side} handleSideUpdate={setSide} />
          <VStack spacerGap={2} spacingHorizontal={2}>
            <HStack
              alignItems="center"
              spacerGap={1}
              justifyContent="space-between"
              spacingEnd={1}
            >
              <PillButtonGroup
                onChange={handleOrderTypeChange}
                defaultKey={orderType}
                disabled={isAccessLevelRestricted}
                buttons={pillButtons}
              />
              <a
                href="https://www.coinbase.com/learn/advanced-trading/order-types"
                target="_blank"
                rel="noreferrer"
              >
                <Icon name="info" size="s" color="foregroundMuted" />
              </a>
            </HStack>
            {orderType === OrderTypeRecord.STOP_LIMIT && (
              <>
                <MarginField
                  leverageOptions={leverageOptions}
                  type={defaultMarginType}
                  value={leverage}
                  onTypeChange={setMarginType}
                  marginTooltip={marginTooltip}
                  onValueChange={setLeverage}
                  disabledFields={{
                    marginType:
                      !isolatedMarginExperimentEnabled || isPreLaunchContract,
                    leverage: isAccessLevelRestricted,
                  }}
                  hasOpenOrdersOrExistingPositions={
                    hasOpenOrdersOrExistingPositions
                  }
                />
                <StopLimitPriceField
                  label={formatMessage(advancedCommonMessages.limitPrice)}
                  currency={quoteCurrencyId}
                  onChange={handleLimitPriceChange}
                  disabled={isAccessLevelRestricted}
                  placeholder={quoteNumericPlaceholder}
                  error={limitPriceError}
                  type="limit"
                />
                <StopLimitPriceField
                  label={formatMessage(advancedCommonMessages.stopPrice)}
                  currency={quoteCurrencyId}
                  onChange={handleStopPriceChange}
                  disabled={isAccessLevelRestricted}
                  placeholder={quoteNumericPlaceholder}
                  error={stopLimitError}
                  type="stop_limit"
                />
                <SizeField
                  value={size}
                  disabled={isAccessLevelRestricted}
                  orderType={orderType}
                  limitPrice={limitPrice ? limitPrice : 0}
                  onChange={handleSizeChange}
                  errors={orderPreview?.response?.errs || []}
                />
              </>
            )}
            {/* TODO: abstract based on order type */}
            {orderType === OrderTypeRecord.LIMIT && (
              <>
                <MarginField
                  leverageOptions={leverageOptions}
                  type={defaultMarginType}
                  value={leverage}
                  onTypeChange={setMarginType}
                  onValueChange={setLeverage}
                  disabledFields={{
                    marginType:
                      !isolatedMarginExperimentEnabled || isPreLaunchContract,
                    leverage: isAccessLevelRestricted,
                  }}
                  marginTooltip={marginTooltip}
                  hasOpenOrdersOrExistingPositions={
                    hasOpenOrdersOrExistingPositions
                  }
                />
                <LimitPriceField
                  label={formatMessage(advancedCommonMessages.limitPrice)}
                  currency={quoteCurrencyId}
                  value={limitPrice}
                  onChange={handleLimitPriceChange}
                  disabled={isAccessLevelRestricted}
                  errors={orderPreview?.response?.errs || []}
                />
                <SizeField
                  value={size}
                  disabled={isAccessLevelRestricted}
                  onChange={handleSizeChange}
                  orderType={orderType}
                  limitPrice={limitPrice ? limitPrice : 0}
                  errors={orderPreview?.response?.errs || []}
                />
              </>
            )}
            {orderType === OrderTypeRecord.MARKET && (
              <>
                <MarginField
                  leverageOptions={leverageOptions}
                  type={defaultMarginType}
                  value={leverage}
                  disabledFields={{
                    marginType:
                      !isolatedMarginExperimentEnabled || isPreLaunchContract,
                    leverage: isAccessLevelRestricted,
                  }}
                  onTypeChange={setMarginType}
                  onValueChange={setLeverage}
                  marginTooltip={marginTooltip}
                  hasOpenOrdersOrExistingPositions={
                    hasOpenOrdersOrExistingPositions
                  }
                />
                <SizeField
                  value={size}
                  disabled={isAccessLevelRestricted}
                  onChange={handleSizeChange}
                  orderType={orderType}
                  limitPrice={limitPrice ? limitPrice : 0}
                  errors={orderPreview?.response?.errs || []}
                />
              </>
            )}
            <Divider />
            <VStack spacerGap={1} width="100%">
              {orderType !== OrderTypeRecord.MARKET && (
                <>
                  {orderType !== 'stop_limit' && (
                    <Execution
                      orderType={orderType}
                      disabled={isAccessLevelRestricted}
                      onChange={handleExecutionChange}
                      limitOnly={product.postOnly}
                      auctionMode={isAuctionMode}
                    />
                  )}
                  <Expiration
                    disabled={isAccessLevelRestricted}
                    onChange={handleExpirationChange}
                  />
                </>
              )}
              <OrderFormDetailRow
                label={formatMessage(sharedMessages.notionalValue)}
                value={notionalValue}
                tooltip={
                  <TextBody as="p">
                    {formatMessage(sharedMessages.notionalValueTooltip)}
                  </TextBody>
                }
                tooltipIconName="info"
              />
              <OrderFormDetailRow
                label={formatMessage(sharedMessages.marginRequired)}
                value={marginRequiredFormatted}
                tooltip={
                  <TextBody as="p">
                    {formatMessage(sharedMessages.marginRequiredTooltip)}
                  </TextBody>
                }
                tooltipIconName="info"
              />
              <OrderFormDetailRow
                label={formatMessage(advancedCommonMessages.feeEst)}
                value={estFee}
                promotionalLabel={<PromotionalTag queryRef={query} />}
              />
              <OrderFormDetailRow
                label={formatMessage(sharedMessages.estTotal)}
                value={estTotal}
                color="foreground"
              />
            </VStack>
            <VStack spacerGap={2}>
              {((orderPreview.response?.errs &&
                orderPreview.response?.errs.length > 0) ||
                hasNetworkError) && (
                <TextLegal as="p" color="negative" align="center">
                  {error}
                </TextLegal>
              )}
              {button}
            </VStack>
          </VStack>
        </VStack>
      </VStack>
    </MaskContainer>
  );
}

