import { advancedCommonMessages } from 'views/Advanced/constants/commonMessages';
import { OrderPreviewData } from 'views/Advanced/surfaces/perpetual-futures/context/OrderFormContext';
import { useSurfaceContext } from 'views/Advanced/surfaces/perpetual-futures/context/SurfaceContext';
import { advancedTradeSharedEvent } from 'views/Advanced/utils/eventing/useAdvancedTradeEvent';

import { ExecutionType } from '../../components/Execution';
import { TimeInForceOptions } from '../../components/Expiration';
import sharedMessages from '../../messages';

const i18nKey = 'OrderPreview';

const messages = defineMessages({
  title: {
    id: `${i18nKey}.title`,
    defaultMessage: 'order preview',
    description: `
      #Component:Header
      #CharLimit:50
      #Context:title for order preview view on the order form
    `,
  },
  buyBtn: {
    id: `${i18nKey}.buyBtn`,
    defaultMessage: 'Buy',
    description: `
      #Component:Button
      #CharLimit:50
      #Context:label for the button to execute the trade
    `,
  },
  sellBtn: {
    id: `${i18nKey}.sellBtn`,
    defaultMessage: 'Sell',
    description: `
      #Component:Button
      #CharLimit:50
      #Context:label for the button to execute the trade
    `,
  },
});

type Props = {
  onBack: () => void;
  onSubmit: () => void;
  orderPreview: OrderPreviewData;
  execution: ExecutionType;
  expiration: TimeInForceOptions;
};

function Preview({
  onBack,
  onSubmit,
  orderPreview,
  execution,
  expiration,
}: Props) {
  const { formatMessage, formatNumber } = useIntl();
  const isMobile = useScreenMatch('phone');
  const { quoteCurrencyId, productId, baseCurrencyId } = useSurfaceContext();
  const orderType = orderPreview?.orderType;
  const marketPrice = useMidMarketPrice(productId);
  const orderConfiguration = useMemo(() => {
    if (orderPreview.orderType === 'stop_limit') {
      return expiration.timeInForce === 'GTC'
        ? orderPreview.request?.orderConfiguration.stopLimitStopLimitGtc
        : orderPreview.request?.orderConfiguration.stopLimitStopLimitGtd;
    }

    return expiration.timeInForce === 'GTC'
      ? orderPreview.request?.orderConfiguration.limitLimitGtc
      : orderPreview.request?.orderConfiguration.limitLimitGtd;
  }, [
    expiration.timeInForce,
    orderPreview.orderType,
    orderPreview.request?.orderConfiguration.limitLimitGtc,
    orderPreview.request?.orderConfiguration.limitLimitGtd,
    orderPreview.request?.orderConfiguration.stopLimitStopLimitGtc,
    orderPreview.request?.orderConfiguration.stopLimitStopLimitGtd,
  ]);

  const limitPrice = Number(orderConfiguration?.limitPrice) || 0;
  const stopPrice = useMemo(() => {
    if (orderConfiguration && 'stopPrice' in orderConfiguration) {
      return Number(orderConfiguration?.stopPrice) || 0;
    }
    return 0;
  }, [orderConfiguration]);

  const baseSizeLimit = Number(orderConfiguration?.baseSize) || 0;

  const baseSizeMarket =
    Number(
      orderPreview.request?.orderConfiguration.marketMarketIoc?.baseSize,
    ) || 0;

  const amountFormatted = useMemo(() => {
    return orderType === 'limit' || orderType === 'stop_limit'
      ? `${baseSizeLimit} ${baseCurrencyId}`
      : `${baseSizeMarket} ${baseCurrencyId}`;
  }, [baseCurrencyId, baseSizeLimit, baseSizeMarket, orderType]);

  useEffect(() => {
    if (isMobile) {
      advancedTradeSharedEvent({
        eventName: 'order_confirmation_page',
        optionalEventParameters: {
          orderSide: orderPreview?.request
            ?.side as CoinbasePublicApiAuthedRetailBrokerageApiOrderSide,
        },
      });
    }
  }, [orderPreview]);

  const handleBack = useCallback(() => {
    onBack();
  }, [onBack]);

  const handleSubmit = useCallback(() => {
    markStep('submit_perpetuals_order');
    advancedTradeSharedEvent({
      eventName: 'order_confirm_button',
      optionalEventParameters: {
        orderSide: orderPreview?.request?.side,
        orderType: orderPreview?.orderType,
        feeUsd: orderPreview?.response?.commissionTotal,
        totalUsd: orderPreview?.response?.orderTotal,
      },
    });
    onSubmit();
  }, [
    onSubmit,
    orderPreview?.orderType,
    orderPreview?.request?.side,
    orderPreview?.response?.commissionTotal,
    orderPreview?.response?.orderTotal,
  ]);

  const notionalValueLimit = useMemo(() => {
    const notional = baseSizeLimit * limitPrice;
    return `${formatNumber(notional, {
      style: 'decimal',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    })} ${quoteCurrencyId}`;
  }, [baseSizeLimit, limitPrice, formatNumber, quoteCurrencyId]);

  const notionalValueMarket = useMemo(() => {
    const notional =
      baseSizeMarket * (marketPrice ? parseFloat(marketPrice) : 0);
    return `${formatNumber(notional, {
      style: 'decimal',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    })} ${quoteCurrencyId}`;
  }, [baseSizeMarket, formatNumber, marketPrice, quoteCurrencyId]);

  const notionalValue = useMemo(
    () =>
      orderType === 'limit' || orderType === 'stop_limit'
        ? notionalValueLimit
        : notionalValueMarket,
    [notionalValueLimit, notionalValueMarket, orderType],
  );

  const marginRequired = useMemo(
    () => Number(orderPreview.response?.orderMarginTotal) || 0,
    [orderPreview.response?.orderMarginTotal],
  );

  const marginRequiredFormatted = useMemo(
    () =>
      `${formatNumber(marginRequired, {
        style: 'decimal',
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
      })} ${quoteCurrencyId}`,
    [formatNumber, marginRequired, quoteCurrencyId],
  );

  const feeEst = useMemo(() => {
    const total = Number(orderPreview?.response?.commissionTotal) || 0;
    return `${formatNumber(total, {
      style: 'decimal',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    })} ${quoteCurrencyId}`;
  }, [orderPreview, formatNumber, quoteCurrencyId]);

  const totalEst = useMemo(() => {
    const fee = Number(orderPreview.response?.commissionTotal) || 0;
    const total = marginRequired + fee;
    return formatNumber(total, {
      style: 'decimal',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });
  }, [formatNumber, marginRequired, orderPreview.response?.commissionTotal]);

  const limitPriceFormatted = useMemo(() => {
    return `${limitPrice} ${quoteCurrencyId}`;
  }, [limitPrice, quoteCurrencyId]);

  const stopPriceFormatted = useMemo(() => {
    return `${stopPrice} ${quoteCurrencyId}`;
  }, [quoteCurrencyId, stopPrice]);

  const marketPriceFormatted = useMemo(() => {
    return `${marketPrice} ${quoteCurrencyId}`;
  }, [marketPrice, quoteCurrencyId]);

  const leverageFormatted = useMemo(() => {
    return `${orderPreview?.response?.leverage}X`;
  }, [orderPreview?.response?.leverage]);

  const expirationMessage = useMemo(() => {
    return expiration.timeInForce === 'GTC'
      ? formatMessage(sharedMessages.GTC)
      : formatMessage(sharedMessages.GTT);
  }, [expiration.timeInForce, formatMessage]);

  const executionMessage = useMemo(() => {
    return execution === 'allow_taker'
      ? formatMessage(sharedMessages.allowTaker)
      : formatMessage(sharedMessages.postOnly);
  }, [execution, formatMessage]);

  const btnCopy = useMemo(() => {
    return orderPreview?.request?.side ===
      CoinbasePublicApiAuthedRetailBrokerageApiOrderSide.BUY
      ? formatMessage(messages.buyBtn)
      : formatMessage(messages.sellBtn);
  }, [orderPreview, formatMessage]);

  const btnVariant = useMemo(() => {
    return orderPreview?.request?.side ===
      CoinbasePublicApiAuthedRetailBrokerageApiOrderSide.BUY
      ? 'positive'
      : 'negative';
  }, [orderPreview]);

  return (
    <VStack spacerGap={3} flexGrow={1}>
      <HStack
        justifyContent="center"
        alignItems="center"
        spacing={3}
        position="relative"
      >
        <Box position="absolute" left={0} zIndex={100}>
          <IconButton transparent name="backArrow" onPress={handleBack} />
        </Box>
        <TextHeadline as="p" color="foreground" transform="capitalize">
          {formatMessage(messages.title)}
        </TextHeadline>
      </HStack>
      <HStack justifyContent="space-between" alignItems="center">
        <TextBody as="p" color="foregroundMuted" transform="capitalize">
          {formatMessage(sharedMessages.side)}
        </TextBody>
        <TextBody as="p" color="foreground">
          {capitalize(orderPreview?.request?.side || '')}
        </TextBody>
      </HStack>
      <HStack justifyContent="space-between" alignItems="center">
        <TextBody as="p" color="foregroundMuted" transform="capitalize">
          {formatMessage(sharedMessages.type)}
        </TextBody>
        <TextBody as="p" color="foreground">
          {orderPreview?.orderType
            ? capitalize(orderPreview?.orderType.replace(/_/g, ' '))
            : ''}
        </TextBody>
      </HStack>
      <HStack justifyContent="space-between" alignItems="center">
        <TextBody as="p" color="foregroundMuted" transform="capitalize">
          {formatMessage(sharedMessages.marginType)}
        </TextBody>
        <TextBody as="p" color="foreground">
          {capitalize(orderPreview?.request?.marginType || '')}
        </TextBody>
      </HStack>
      {(orderType === 'limit' || orderType === 'stop_limit') && (
        <HStack justifyContent="space-between" alignItems="center">
          <TextBody as="p" color="foregroundMuted" transform="capitalize">
            {formatMessage(advancedCommonMessages.limitPrice)}
          </TextBody>
          <TextBody as="p" color="foreground">
            {limitPriceFormatted}
          </TextBody>
        </HStack>
      )}
      {orderType === 'stop_limit' && (
        <HStack justifyContent="space-between" alignItems="center">
          <TextBody as="p" color="foregroundMuted" transform="capitalize">
            {formatMessage(advancedCommonMessages.stopPrice)}
          </TextBody>
          <TextBody as="p" color="foreground">
            {stopPriceFormatted}
          </TextBody>
        </HStack>
      )}
      {orderType === 'market' && (
        <HStack justifyContent="space-between" alignItems="center">
          <TextBody as="p" color="foregroundMuted" transform="capitalize">
            {formatMessage(sharedMessages.marketPrice)}
          </TextBody>
          <TextBody as="p" color="foreground">
            {marketPriceFormatted}
          </TextBody>
        </HStack>
      )}
      <HStack justifyContent="space-between" alignItems="center">
        <TextBody as="p" color="foregroundMuted" transform="capitalize">
          {formatMessage(sharedMessages.amountLbl)}
        </TextBody>
        <TextBody as="p" color="foreground">
          {amountFormatted}
        </TextBody>
      </HStack>
      <HStack justifyContent="space-between" alignItems="center">
        <TextBody as="p" color="foregroundMuted" transform="capitalize">
          {formatMessage(sharedMessages.leverage)}
        </TextBody>
        <TextBody as="p" color="foreground">
          {leverageFormatted}
        </TextBody>
      </HStack>
      {(orderType === 'limit' || orderType === 'stop_limit') && (
        <HStack justifyContent="space-between" alignItems="center">
          <TextBody as="p" color="foregroundMuted" transform="capitalize">
            {formatMessage(sharedMessages.execution)}
          </TextBody>
          <TextBody as="p" color="foreground">
            {executionMessage}
          </TextBody>
        </HStack>
      )}
      {(orderType === 'limit' || orderType === 'stop_limit') && (
        <HStack justifyContent="space-between" alignItems="center">
          <TextBody as="p" color="foregroundMuted" transform="capitalize">
            {formatMessage(sharedMessages.expiration)}
          </TextBody>
          <TextBody as="p" color="foreground">
            {expirationMessage}
          </TextBody>
        </HStack>
      )}
      <HStack justifyContent="space-between" alignItems="center">
        <TextBody as="p" color="foregroundMuted" transform="capitalize">
          {formatMessage(sharedMessages.notionalValue)}
        </TextBody>
        <TextBody as="p" color="foreground">
          {notionalValue}
        </TextBody>
      </HStack>
      <HStack justifyContent="space-between" alignItems="center">
        <TextBody as="p" color="foregroundMuted" transform="capitalize">
          {formatMessage(sharedMessages.marginRequired)}{' '}
        </TextBody>
        <TextBody as="p" color="foreground">
          {marginRequiredFormatted}
        </TextBody>
      </HStack>

      <HStack justifyContent="space-between" alignItems="center">
        <TextBody as="p" color="foregroundMuted" transform="capitalize">
          {formatMessage(advancedCommonMessages.feeEst)}
        </TextBody>
        <TextBody as="p" color="foreground">
          {feeEst}
        </TextBody>
      </HStack>
      <HStack justifyContent="space-between" alignItems="center">
        <TextHeadline as="p" color="foreground" transform="capitalize">
          {formatMessage(sharedMessages.estTotal)}
        </TextHeadline>
        <HStack spacerGap={0.5}>
          <TextHeadline as="p" color="foreground" transform="capitalize">
            {totalEst}
          </TextHeadline>
          <TextBody as="span" color="foreground" transform="capitalize">
            {quoteCurrencyId}
          </TextBody>
        </HStack>
      </HStack>
      <Button onPress={handleSubmit} variant={btnVariant}>
        {btnCopy}
      </Button>
    </VStack>
  );
}

