type MobileTrayProps = {
  isPreviewModeOnly?: boolean;
  baseCurrencyId: string;
  quoteCurrencyId: string;
};

export function MobileTray({
  isPreviewModeOnly = true,
  baseCurrencyId,
  quoteCurrencyId,
}: MobileTrayProps) {
  const [collapsed, setCollapsed] = useState<boolean>(true);
  const [activeTab, setActiveTab] = useState<string>('order_book');

  const { formatMessage } = useIntl();

  const handleTrayPress = useCallback(() => {
    setCollapsed(!collapsed);
  }, [setCollapsed, collapsed]);

  const activeTabContent = useMemo(() => {
    switch (activeTab) {
      case 'order_book':
        return (
          <AdvancedBoundaryWithSuspense
            name="advanced-component-orders-tray"
            suspenseFallback={
              <LoadingOrderBook
                baseCurrencyId={baseCurrencyId}
                quoteCurrencyId={quoteCurrencyId}
                productType={
                  CoinbasePublicApiAuthedRetailBrokerageApiProductType.FUTURE
                }
              />
            }
            owner={ADVANCED_PERP_FUTURES_OWNERSHIP_TAG}
          >
            <OrderBook />
          </AdvancedBoundaryWithSuspense>
        );
      case 'trade_history':
        return (
          <AdvancedBoundaryWithSuspense
            name="advanced-component-orders-tray"
            suspenseFallback={<LoadingTradeHistory />}
            owner={ADVANCED_PERP_FUTURES_OWNERSHIP_TAG}
          >
            <TradeHistory />
          </AdvancedBoundaryWithSuspense>
        );
      case 'orders':
        return <MobileOrderHistory />;
      default:
        return null;
    }
  }, [activeTab, baseCurrencyId, quoteCurrencyId]);

  const buttons = useMemo(() => {
    if (isPreviewModeOnly) {
      return [
        {
          key: 'order_book',
          content: formatMessage(messages.orderBook),
        },
        {
          key: 'trade_history',
          content: formatMessage(messages.tradeHistory),
        },
      ];
    } else {
      return [
        {
          key: 'order_book',
          content: formatMessage(messages.orderBook),
        },
        {
          key: 'trade_history',
          content: formatMessage(messages.tradeHistory),
        },
        { key: 'orders', content: formatMessage(messages.orders) },
      ];
    }
  }, [formatMessage, isPreviewModeOnly]);

  return (
    <Card
      borderRadius="roundedNone"
      gap={2}
      background="background"
      testID="mobile-tray"
    >
      <VStack>
        <HStack
          spacingHorizontal={2}
          spacingVertical={1}
          justifyContent="space-between"
          alignItems="center"
        >
          <PillButtonGroup
            onChange={setActiveTab}
            defaultKey={activeTab}
            disabled={false}
            buttons={buttons}
          />
          <Box bordered={true} borderRadius="roundedFull">
            <IconButton
              onPress={handleTrayPress}
              name={collapsed ? 'caretDown' : 'caretUp'}
              transparent={true}
              variant="foregroundMuted"
            />
          </Box>
        </HStack>
        {collapsed && <Box height={OPEN_HEIGHT}>{activeTabContent}</Box>}
      </VStack>
    </Card>
  );
}

