          <TextHeadline as="p" color="foreground">
            {title}
          </TextHeadline>
          <TextBody as="p" color="foregroundMuted">
            {description}
          </TextBody>
          <Box offsetStart={2}>
            <Button transparent compact noScaleOnPress>
              {actionLabel}
            </Button>
          </Box>
        </VStack>
        <SpotSquare name={spotSquare} />
      </Box>
    </Pressable>
  );
}

type Props = {
  queryRef: PromotionalCardFragment$key;
  isUpsellCardViewable: boolean;
};

function PromotionalCardContent({ queryRef, isUpsellCardViewable }: Props) {
  const history = useHistory();
  const [currCardIndex, setCurrCardIndex] = useState(0);
  const [isOpen, { toggleOff }] = useToggler(true);
  const { formatMessage, formatNumber } = useIntl();
  const { openModal, closeModal } = useModal();
  const isCrossCollateralEnabled = useIsCrossCollateralEnabled();

  const query = useFragment(
    graphql`
      fragment PromotionalCardFragment on Query {
        viewer {
          retailBrokerage {
            transactionSummary(
              productVenue: INTX
              productType: FUTURE
              contractExpiryType: PERPETUAL
            ) {
              feeTier {
                makerFeeRate
                takerFeeRate
              }
            }
          }
          ownedAssets(platform: ASSET_PLATFORM_INTX, cashEquivalent: true) {
            edges {
              node {
                ... on ViewerAsset {
                  earnPrograms {
                    platform
                    currentRate {
                      formatted
                    }
                  }
                }
              }
            }
          }
        }
      }
    `,
    queryRef,
  );

  const { makerFeeRate, takerFeeRate } =
    query?.viewer?.retailBrokerage?.transactionSummary?.feeTier || {};
  const makerFeeValue = makerFeeRate
    ? formatNumber(parseFloat(makerFeeRate), FORMATTED_PERCENT_CONFIG)
    : DEFAULT_FORMATTED_FALLBACK;
  const takerFeeValue = takerFeeRate
    ? formatNumber(parseFloat(takerFeeRate), FORMATTED_PERCENT_CONFIG)
    : DEFAULT_FORMATTED_FALLBACK;
  const makerFeeTruncated = makerFeeRate
    ? formatNumber(Number(makerFeeRate), {
        ...FORMATTED_PERCENT_CONFIG,
        minimumFractionDigits: 0,
      })
    : DEFAULT_FORMATTED_FALLBACK;

  const navigateToPerps = useCallback(() => {
    history.push(AdvancedRoutes.FuturesTradeDefault);
  }, [history]);

  const openTransferModal = useCallback(() => {
    openModal(
      <TransferModal
        visible
        onClose={closeModal}
        hideCloseButton
        hideDividers
        entryPage="portfolio"
        transferType="DEPOSIT"
      />,
    );
  }, [openModal, closeModal]);

  const openCrossCollateralLink = useCallback(() => {
    window.open(
      PERP_FUTURES_MULTI_ASSET_COLLATERAL_HELP_LINK,
      '_blank',
      'noopener',
    );
  }, []);

  const earnAPY = useMemo(() => {
    const edges = removeFalsyValues(query?.viewer?.ownedAssets?.edges ?? []);
    const formatted = edges[0]?.node?.earnPrograms?.find(
      program => program?.platform === 'INTERNATIONAL_EXCHANGE',
    )?.currentRate?.formatted;
    return formatted;
  }, [query]);
  let promotionalCards = [
    <PromoCard
      actionLabel={formatMessage(messages.perpsAction)}
      description={formatMessage(messages.description, {
        maker: makerFeeValue,
        taker: takerFeeValue,
      })}
      onClick={navigateToPerps}
      spotSquare="defiRisk"
      title={formatMessage(messages.title, {
        percent: makerFeeTruncated,
      })}
    />,
  ];

  if (isUpsellCardViewable && earnAPY) {
    promotionalCards = [
      <PromoCard
        actionLabel={formatMessage(messages.upsellAction)}
        description={formatMessage(messages.upsellDescription, {
          apy: earnAPY,
        })}
        onClick={openTransferModal}
        spotSquare="retailUSDCRewards"
        title={formatMessage(messages.upsellTitle, {
          apy: earnAPY,
        })}
      />,
      ...promotionalCards,
    ];
  }

  if (isCrossCollateralEnabled) {
    promotionalCards.push(
      <PromoCard
        actionLabel={formatMessage(messages.learnMoreAction)}
        description={formatMessage(messages.crossCollateralDescription)}
        onClick={openCrossCollateralLink}
        spotSquare="cryptoAndMore"
        title={formatMessage(messages.crossCollateralTitle)}
      />,
    );
  }

  const handleOnPress = useCallback(
    () =>
      setCurrCardIndex(
        (index: number) =>
          (index - 1 + promotionalCards.length) % promotionalCards.length,
      ),
    [promotionalCards.length],
  );

  const handleOnPress1 = useCallback(
    () =>
      setCurrCardIndex(
        (index: number) => (index + 1) % promotionalCards.length,
      ),
    [promotionalCards.length],
  );

  if (!isOpen) return null;

  return (
    // Div to prevent border between dimiss header and the rest of the card
    <div>
      <HStack
        bordered={false}
        justifyContent="space-between"
        spacingHorizontal={1}
        spacingTop={1}
        testID="perps-promotional-card"
      >
        <HStack>
          <IconButton
            name="backArrow"
            transparent
            variant="secondary"
            onPress={handleOnPress}
            testID="back-arrow"
          />
          <IconButton
            name="forwardArrow"
            transparent
            variant="secondary"
            onPress={handleOnPress1}
            testID="forward-arrow"
          />
        </HStack>
        <IconButton
          name="close"
          transparent
          variant="secondary"
          onPress={toggleOff}
          testID="dismiss-btn"
        />
      </HStack>
      {promotionalCards[currCardIndex]}
    </div>
  );
}

function PromotionalCard({ queryRef, isUpsellCardViewable }: Props) {
  return (
    <AdvancedBoundaryWithSuspense
      name="advanced-component-perpetuals-promotional-card"
      owner="advanced-intl-perp"
      suspenseFallback={null}
    >
      <PromotionalCardContent
        isUpsellCardViewable={isUpsellCardViewable}
        queryRef={queryRef}
      />
    </AdvancedBoundaryWithSuspense>
  );
}

export default memo(PromotionalCard);

import {
  memo,
  useCallback,
  useMemo,
  useState,
  Dispatch,
  SetStateAction,
} from 'react';
import { useIntl } from 'react-intl';

import { useFields } from '@cb/forms';
import { ADVANCED_PERP_FUTURES_OWNERSHIP_TAG } from '@cbhq/advanced-trade-web/constants/errorLogging';
import { Button } from '@cbhq/cds-web/buttons/Button';
import { Spinner } from '@cbhq/cds-web/loaders';
import { TextBody } from '@cbhq/cds-web/typography';
import { useCurrencyConverter } from '@cbhq/common-web/hooks/useCurrencyConverter';
import { graphql, useFragment, InstrumentedSuspense } from '@cbhq/data-layer';

import EntryInput from 'components/BuySellComponents/EntryInput';
import { LazyBuySellModal } from 'components/BuySellModal';
import NetworkErrorBoundary from 'components/NetworkErrorBoundary';
import useModal from 'hooks/useModal/useModal';
import useNativeCurrency from 'hooks/useNativeCurrency';
import { enforceExponent } from 'utils/enforceExponent/enforceExponent';

import { form } from '../../../form';
import { TransferFundsEntryPage, USDC, USDC_PRECISION } from '../TransferFunds';
import { TransferFundsInputFragment$key } from './__generated__/TransferFundsInputFragment.graphql';
import { messages } from './messages';

type TransferFundsInputProps = {
  assetOrCurrencyRef: TransferFundsInputFragment$key | null;
  entryPage: TransferFundsEntryPage;
  availableBalance: number;
  transferType: 'DEPOSIT' | 'WITHDRAWAL';
  onTransferClose: () => void;
  onFiatAmountChange: (cryptoAmount: string) => void;
  onFiatModeChange: Dispatch<SetStateAction<boolean>>;
  isFiat: boolean;
};

function TransferFundsInput({
  assetOrCurrencyRef,
  availableBalance,
  transferType,
  onTransferClose,
  entryPage,
  onFiatAmountChange,
  onFiatModeChange,
  isFiat,
}: TransferFundsInputProps) {
  const { formatMessage } = useIntl();
  const [inputAmount, setInputAmount] = useState<string | undefined>();
  const [error, setError] = useState<boolean | undefined>();
  const { amount } = useFields(form);
  const { showModal: showBuyModal } = useModal();
  const nativeCurrency = useNativeCurrency();

  const viewerAsset = useFragment(
    graphql`
      fragment TransferFundsInputFragment on AssetOrCurrency {
        ... on ViewerAsset {
          ...EntryInputFragment
          asset {
            platformName
            ...useCurrencyConverterSourceAssetFragment
          }
        }
      }
    `,
    assetOrCurrencyRef,
  );

  const convert = useCurrencyConverter({
    nativeCurrency,
    sourceAssetRef: viewerAsset?.asset,
  });

  const onAmountChanged = useCallback(
    (inputAmount?: string) => {
      // This is needed to make sure user can't enter an amount more than 4 digits of precision
      // This is a temp fix and we should look for a more permanent solution
      const preciseInputAmount = enforceExponent(
        inputAmount ?? '',
        USDC_PRECISION,
      );
      // Set invalid amount error
      if (preciseInputAmount && Number(preciseInputAmount) > availableBalance) {
        setError(true);
      }
      setInputAmount(preciseInputAmount);
      amount.onChange(preciseInputAmount);
      if (isFiat) {
        const from = {
          amount: preciseInputAmount,
          currency: nativeCurrency,
        };
        const to = viewerAsset?.asset?.platformName ?? '';
        const cryptoAmount = convert(from, to);
        if (cryptoAmount !== undefined) {
          onFiatAmountChange(cryptoAmount.toString());
        }
      }
    },
    [
      amount,
      availableBalance,
      convert,
      isFiat,
      nativeCurrency,
      onFiatAmountChange,
      viewerAsset?.asset?.platformName,
    ],
  );

  const handleTransferAll = useCallback(() => {
    if (isFiat) {
      const from = {
        amount: String(availableBalance),
        currency: viewerAsset?.asset?.platformName ?? '',
      };
      const to = nativeCurrency;
      const fiatAmount = convert(from, to);
      if (typeof fiatAmount === 'number')
        onAmountChanged(fiatAmount.toString());
    } else {
      onAmountChanged(availableBalance.toString());
    }
  }, [
    availableBalance,
    convert,
    isFiat,
    nativeCurrency,
    onAmountChanged,
    viewerAsset?.asset?.platformName,
  ]);

  const depositHelperText = useMemo(
    () => (
      <TextBody as="p" align="center" color="foregroundMuted">
        {formatMessage(messages.depositHelperText)}
      </TextBody>
    ),
    [formatMessage],
  );

  const withdrawHelperText = useMemo(
    () => (
      <TextBody as="p" align="center" color="foregroundMuted">
        {formatMessage(
          entryPage === 'isolated_position'
            ? messages.withdrawIsolatedHelperText
            : messages.withdrawHelperText,
        )}
      </TextBody>
    ),
    [entryPage, formatMessage],
  );

  const helperText =
    transferType === 'DEPOSIT' ? depositHelperText : withdrawHelperText;

  const validInputError = useMemo(
    () => (
      <TextBody
        as="p"
        align="center"
        color="foregroundMuted"
        overflow="wrap"
        spacingBottom={2}
        spacingTop={1}
      >
        {formatMessage(messages.validInputError)}
      </TextBody>
    ),
    [formatMessage],
  );

  // TODO: Confirm that this is working - currently Buy flow is broken on staging and this shows the same error modal as clicking on Buy button
  const openBuyModal = useCallback(() => {
    onTransferClose();
    showBuyModal(<LazyBuySellModal assetCode="USDC" initialActiveTab="buy" />);
  }, [onTransferClose, showBuyModal]);

  const zeroRetailBalance = useMemo(
    () => (
      <TextBody as="p" align="center" color="foregroundMuted">
        {formatMessage(messages.zeroRetailBalanceError)}
      </TextBody>
    ),
    [formatMessage],
  );

  const addUSDCBtn = useMemo(() => {
    return (
      <Button variant="secondary" compact onPress={openBuyModal}>
        {formatMessage(messages.addUSDC)}
      </Button>
    );
  }, [formatMessage, openBuyModal]);

  const zeroIntxBalance = useMemo(
    () => (
      <TextBody as="p" align="center" color="foregroundMuted">
        {formatMessage(messages.zeroIntxBalanceError)}
      </TextBody>
    ),
    [formatMessage],
  );

  const errorMessage = useMemo(() => {
    // If retail balance is 0, user needs to buy more USDC through simple trade flow
    // If retail account is not created, user needs to create a retail account
    if (
      (availableBalance === 0 && transferType === 'DEPOSIT') ||
      (!availableBalance && transferType === 'DEPOSIT')
    ) {
      return zeroRetailBalance;
    }
    if (availableBalance === 0 && transferType === 'WITHDRAWAL') {
      return zeroIntxBalance;
    }
    if (inputAmount && Number(inputAmount) > availableBalance) {
      return validInputError;
    }
    return null;
  }, [
    availableBalance,
    inputAmount,
    transferType,
    validInputError,
    zeroIntxBalance,
    zeroRetailBalance,
  ]);

  const transferAllDisabled = useMemo(() => {
    if (availableBalance === 0 || !availableBalance) return true;
    return false;
  }, [availableBalance]);

  const transferAllBtn = useMemo(() => {
    return (
      <Button
        variant="secondary"
        compact
        onPress={handleTransferAll}
        disabled={transferAllDisabled}
      >
        {formatMessage(messages.transferAllButton)}
      </Button>
    );
  }, [formatMessage, handleTransferAll, transferAllDisabled]);

  const secondaryButton = useMemo(() => {
    // If retail balance is 0, user needs to buy more USDC through simple trade flow
    // If retail account is not created, user needs to create a retail account
    if (
      (availableBalance === 0 && transferType === 'DEPOSIT') ||
      (!availableBalance && transferType === 'DEPOSIT')
    ) {
      return addUSDCBtn;
    }

    return transferAllBtn;
  }, [addUSDCBtn, availableBalance, transferAllBtn, transferType]);

  const getInactiveSymbol = useCallback(() => {
    if (viewerAsset?.asset?.platformName === USDC) return '';

    return !isFiat ? nativeCurrency : viewerAsset?.asset?.platformName ?? '';
  }, [isFiat, nativeCurrency, viewerAsset?.asset?.platformName]);

  const handleSwitchActiveInput = useCallback(() => {
    onFiatModeChange(isFiat => !isFiat);
    amount.onChange('');
    setInputAmount('');
    setError(false);
  }, [amount, onFiatModeChange]);

  const switchActiveInputConfig = useMemo(() => {
    return {
      onPress: handleSwitchActiveInput,
      inactiveSymbol: getInactiveSymbol(),
      hidden: viewerAsset?.asset?.platformName === USDC,
    };
  }, [
    getInactiveSymbol,
    handleSwitchActiveInput,
    viewerAsset?.asset?.platformName,
  ]);
  const entryInput = useMemo(
    () => ({
      value: inputAmount ?? '',
      symbol: isFiat ? nativeCurrency : '',
      onChange: onAmountChanged,

      displaySymbol: viewerAsset?.asset?.platformName ?? '',
    }),
    [
      inputAmount,
      isFiat,
      nativeCurrency,
      onAmountChanged,
      viewerAsset?.asset?.platformName,
    ],
  );

  return (
    <InstrumentedSuspense
      instrumentationId="TransferFundsInput"
      fallback={<Spinner size={3} />}
    >
      <NetworkErrorBoundary
        context="transfer-funds-modal"
        owner={ADVANCED_PERP_FUTURES_OWNERSHIP_TAG}
        boundaryName="TransferFundsInputModal"
      >
        <EntryInput
          autoFocus
          input={entryInput}
          helperText={helperText}
          error={error || errorMessage ? errorMessage : undefined}
          viewerAssetRef={viewerAsset}
          secondaryButton={secondaryButton}
          switchActiveInput={switchActiveInputConfig}
          isCryptoCurrency={!isFiat}
          transparentBackground
        />
      </NetworkErrorBoundary>
    </InstrumentedSuspense>
  );
}

export default memo(TransferFundsInput);

import React, { useRef, useCallback, useState, memo } from 'react';
import { Controller, ControllerRenderProps } from 'react-hook-form';
import { useIntl } from 'react-intl';

import { useModal } from '@cbhq/cds-common/overlays/useModal';
import { Button, IconButton } from '@cbhq/cds-web/buttons';
import { Select, SelectOption, TextInput } from '@cbhq/cds-web/controls';
import { VStack } from '@cbhq/cds-web/layout';
import { Pressable } from '@cbhq/cds-web/system';
import {
  TextBody,
  TextDisplay3,
  TextHeadline,
  TextTitle4,
} from '@cbhq/cds-web/typography';
import { getErrorInstance } from '@cbhq/common-web/utils/notifyError';
import { useMutation, useFragment, graphql } from '@cbhq/data-layer';

import useNotifyAdvancedError from 'views/Advanced/utils/useNotifyAdvancedError';

import { LazyAdvancedFeeUpgradeProofExampleModal } from '../AdvancedFeeUpgradeProofExampleModal';
import {
  logAdvancedFeeUpgradeCreateStatusMatchInquirySuccessEvent,
  logAdvancedFeeUpgradeFileUploadSuccessEvent,
  logAdvancedFeeUpgradeSubmitEvent,
} from '../eventing';
import messages from '../messages';
import { AdvancedFeeUpgradeFormFragment$key } from './__generated__/AdvancedFeeUpgradeFormFragment.graphql';
import { AdvancedFeeUpgradeFormMutation } from './__generated__/AdvancedFeeUpgradeFormMutation.graphql';
import { exchangeOptions } from './constants';
import FilePill from './FilePill';
import { AdvancedFeeUpgradeFormSchemaType } from './schema';
import { useAdvancedFeeUpgradeForm } from './useAdvancedFeeUpgradeForm';
import { hasMissingData, FileData } from './utils';

type AdvancedFeeUpgradeFormProps = {
  queryRef: AdvancedFeeUpgradeFormFragment$key;
  onSuccess: () => void;
  onFailure: () => void;
};

function AdvancedFeeUpgradeForm({
  queryRef,
  onSuccess,
  onFailure,
}: AdvancedFeeUpgradeFormProps) {
  const { viewer } = useFragment(
    graphql`
      fragment AdvancedFeeUpgradeFormFragment on Query {
        viewer {
          retailBrokerage {
            statusMatchEligibility {
              s3ObjectKey
              s3ObjectKeys
              s3Urls
            }
          }
        }
      }
    `,
    queryRef,
  );

  const [commitCreateStatusMatchInquiry] =
    useMutation<AdvancedFeeUpgradeFormMutation>(
      graphql`
        mutation AdvancedFeeUpgradeFormMutation(
          $input: RetailBrokerageCreateStatusMatchInquiryInput!
        ) {
          retailBrokerageCreateStatusMatchInquiry(input: $input) {
            __typename
            ... on RetailBrokerageCreateStatusMatchInquirySuccess {
              dummy
            }
            ... on GenericError {
              message
              code
            }
          }
        }
      `,
    );

  const { formatMessage } = useIntl();
  const inputFileRef = useRef<HTMLInputElement>(null);
  const notifyAdvancedError = useNotifyAdvancedError();
  const { openModal, closeModal } = useModal();
  const [isLoading, setIsLoading] = useState(false);

  const handleSeeExampleClick = useCallback(() => {
    openModal(
      <LazyAdvancedFeeUpgradeProofExampleModal visible onClose={closeModal} />,
    );
  }, [openModal, closeModal]);

  const {
    handleSubmit: handleSubmitWrapper,
    watch,
    control,
    resetField,
    reset,
    getFieldState,
    clearErrors,
    formState,
  } = useAdvancedFeeUpgradeForm();

  const handleSuccess = useCallback(() => {
    setIsLoading(false);
    onSuccess();
  }, [onSuccess]);

  const handleFailure = useCallback(() => {
    setIsLoading(false);
    onFailure();
  }, [onFailure]);

  const handleSubmit = useCallback(
    async (data: AdvancedFeeUpgradeFormSchemaType) => {
      setIsLoading(true);
      logAdvancedFeeUpgradeSubmitEvent();
      const { s3ObjectKey, s3Urls, s3ObjectKeys } =
        viewer.retailBrokerage?.statusMatchEligibility || {};

      const { isDataMissing, missingData } = hasMissingData({
        s3Urls,
        s3ObjectKeys,
      });

      if (isDataMissing) {
        notifyAdvancedError(
          new Error(
            `Can't submit the form. Missing properties: ${missingData.join(
              ', ',
            )}`,
          ),
          {
            context: 'advanced-fee-upgrade-form',
          },
        );
        handleFailure();
        return;
      }

      if (data.files === undefined) {
        notifyAdvancedError(new Error('Please select a file to upload'), {
          context: 'advanced-fee-upgrade-form',
        });
        handleFailure();
        return;
      }

      const uploadFilePromises =
        s3Urls?.map(async (url, index) => {
          if (!url || !data.files || !data.files[index]) {
            // Skip over the empty urls
            return undefined;
          }

          const uploadToS3Response = await fetch(url, {
            method: 'PUT',
            body: data.files[index],
          });

          if (!uploadToS3Response.ok) {
            throw new Error(`Failed to upload file number ${index + 1} to S3`);
          }
          logAdvancedFeeUpgradeFileUploadSuccessEvent();
        }) || [];

      try {
        await Promise.all(uploadFilePromises);
      } catch (error) {
        notifyAdvancedError(error, {
          context: 'advanced-fee-upgrade-form',
        });
        handleFailure();
        return;
      }

      const nonNullS3ObjectKeys =
        s3ObjectKeys?.filter((key): key is string => key !== null) || null;

      commitCreateStatusMatchInquiry({
        variables: {
          input: {
            s3ObjectKey,
            s3ObjectKeys: nonNullS3ObjectKeys,
            exchangeName:
              data.exchangeName === 'Other'
                ? data.customExchangeName
                : data.exchangeName,
          },
        },
        onCompleted: ({ response }) => {
          if (
            response.retailBrokerageCreateStatusMatchInquiry?.__typename ===
            'RetailBrokerageCreateStatusMatchInquirySuccess'
          ) {
            logAdvancedFeeUpgradeCreateStatusMatchInquirySuccessEvent();
            handleSuccess();
          } else if (
            response.retailBrokerageCreateStatusMatchInquiry?.__typename ===
            'GenericError'
          ) {
            notifyAdvancedError(
              new Error(
                response.retailBrokerageCreateStatusMatchInquiry.message,
              ),
              {
                context: 'advanced-fee-upgrade-form',
              },
            );
            handleFailure();
          }
        },
        onError: e => {
          notifyAdvancedError(getErrorInstance(e), {
            context: 'advanced-fee-upgrade-form',
          });
          handleFailure();
        },
      });

      reset();

      // Reset the file input after submission
      if (inputFileRef.current) {
        inputFileRef.current.value = '';
      }
    },
    [
      commitCreateStatusMatchInquiry,
      handleFailure,
      handleSuccess,
      notifyAdvancedError,
      reset,
      viewer.retailBrokerage?.statusMatchEligibility,
    ],
  );

  const handleFileInputClick = useCallback((event: React.MouseEvent) => {
    event.stopPropagation();

    inputFileRef?.current?.click();
  }, []);

  type handleAddFileProps = {
    event: React.ChangeEvent<HTMLInputElement>;
    field: ControllerRenderProps<FileData, 'files'>;
  };

  const handleAddFile = useCallback(
    ({ event, field }: handleAddFileProps) => {
      clearErrors('files');
      if (event.target.files) {
        const newFiles = Array.from(event.target.files);
        const updatedFiles = field.value ? [...field.value] : [];

        newFiles.forEach(newFile => {
          if (!updatedFiles.some(file => file.name === newFile.name)) {
            updatedFiles.push(newFile);
          }
        });

        field.onChange(updatedFiles);
      }
    },
    [clearErrors],
  );

  const exchangeName = watch('exchangeName');
  const shouldShowCustomExchangeName = exchangeName === 'Other';

  const isSubmitDisabled = getFieldState('files', formState).error
    ? true
    : false;

  return (
    <VStack width={446} spacerGap={4} testID="advanced-fee-upgrade-form">
      <TextDisplay3 as="h1" color="foreground">
        {formatMessage(messages.feeUpgradeFormTitle)}
      </TextDisplay3>
      <TextTitle4 as="h4" color="foregroundMuted">
        {formatMessage(messages.feeUpgradeFormDescription, {
          seeExample: (
            <Pressable
              background="transparent"
              onPress={handleSeeExampleClick}
              key="see-trading-volume-proof-example"
            >
              <TextTitle4 as="h4" color="primary">
                {formatMessage(messages.seeExample)}
              </TextTitle4>
            </Pressable>
          ),
        })}
      </TextTitle4>

      <form onSubmit={handleSubmitWrapper(handleSubmit)}>
        <VStack spacingTop={2} spacingBottom={7}>
          <TextHeadline as="p" spacingBottom={0.5}>
            {formatMessage(messages.exchangeSelectionSelectLabel, {
              asterisk: () => (
                <TextHeadline
                  as="span"
                  color="negative"
                  key="negative-asterisk"
                >
                  *
                </TextHeadline>
              ),
            })}
          </TextHeadline>

          <Controller
            control={control}
            name="exchangeName"
            // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
            render={({ field, fieldState }) => (
              <Select
                testID="advanced-fee-upgrade-exchange-selector"
                value={field.value}
                accessibilityLabel={formatMessage(
                  messages.exchangeSelectionPlaceholder,
                )}
                placeholder={formatMessage(
                  messages.exchangeSelectionPlaceholder,
                )}
                // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
