            </TextBody>
            <TextBody as="li" spacingStart={1}>
              {formatMessage(messages.tradingVolumeProofRequirementTwo, {
                asterisk: () => (
                  <TextHeadline
                    as="span"
                    color="negative"
                    key="negative-asterisk"
                  >
                    *
                  </TextHeadline>
                ),
              })}
            </TextBody>
            <TextBody as="li" spacingStart={1} spacingBottom={0.5}>
              {formatMessage(messages.tradingVolumeProofRequirementThree, {
                asterisk: () => (
                  <TextHeadline
                    as="span"
                    color="negative"
                    key="negative-asterisk"
                  >
                    *
                  </TextHeadline>
                ),
              })}
            </TextBody>
          </VStack>

          <Controller
            control={control}
            name="files"
            // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
            render={({ field, fieldState }) => {
              return (
                <>
                  <TextInput
