                    }
                    disabled={isLoading}
                    start={
                      <>
                        <IconButton
                          onPress={
                            fieldState.error?.type === 'CLIENT_MAX_NUM_FILES'
                              ? // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                                () => null
                              : handleFileInputClick
                          }
                          name="upload"
                          transparent
                          color="foregroundMuted"
                        />

                        <VStack
                          alignItems="flex-start"
                          spacingVertical={0.5}
                          spacerGap={0.5}
                        >
                          {field.value?.map((file, index) => (
                            <FilePill
                              key={index}
                              file={file}
                              index={index}
                              field={field}
                              resetField={resetField}
                            />
