        </VStack>
        <Button
          loading={isLoading}
          disabled={isSubmitDisabled}
          testID="advanced-fee-upgrade-submit"
          type="submit"
        >
          {formatMessage(messages.submit)}
        </Button>
      </form>
    </VStack>
  );
}

