import { memo, useMemo } from 'react';
import Big from 'big.js';

import { useFormatCellAmount } from '@cbhq/advanced-trade-web/hooks/useFormatCellAmount';
import { convertIncrementToPrecision } from '@cbhq/advanced-trade-web/utils/convertIncrementToPrecision';
import { getProductCurrencyIds } from '@cbhq/advanced-trade-web/utils/getProductCurrencyIds';
import { ListCell } from '@cbhq/cds-web/cells/ListCell';
import { CoinbasePublicApiAuthedRetailBrokerageApiProduct } from '@cbhq/instant-api-hooks-retail-brokerage/types';

import MarketIconPair from 'components/MarketIconPair';
import { AdvancedRoutes } from 'views/Advanced/constants/routes';

type Props = {
  product: CoinbasePublicApiAuthedRetailBrokerageApiProduct;
};

function TopMoverRow({
  product: { productId, price, pricePercentageChange24h, quoteIncrement },
}: Props) {
  const formatCellAmount = useFormatCellAmount();
  const [baseCurrencyId, quoteCurrencyId] = useMemo(
    () => getProductCurrencyIds(productId),
    [productId],
  );
  const quotePrecision = convertIncrementToPrecision(quoteIncrement);
  const formattedQuotePrice = useMemo(
    () =>
      formatCellAmount({
        currency: quoteCurrencyId,
        value: price,
        exponent: quotePrecision,
      }),
    [formatCellAmount, quoteCurrencyId, price, quotePrecision],
  );

  return (
    <a
      href={`${AdvancedRoutes.SpotTrade}/${productId}`}
      rel="noopener noreferrer"
    >
      <ListCell
        media={
          <MarketIconPair
            baseCurrencyId={baseCurrencyId}
            quoteCurrencyId={quoteCurrencyId}
          />
        }
        title={productId}
        description={quoteCurrencyId}
        detail={formattedQuotePrice}
        subdetail={`${Big(pricePercentageChange24h)
          .round(2)
          .toNumber()
          .toFixed(2)}%`}
        variant={
          parseFloat(pricePercentageChange24h) >= 0 ? 'positive' : 'negative'
        }
      />
    </a>
  );
}

export default memo(
  TopMoverRow,
  (
    { product: { price: pPrice, pricePercentageChange24h: pChange } },
    { product: { price: nPrice, pricePercentageChange24h: nChange } },
  ) => {
    /**
     *  We only need to rerender if there's been a change in rendered price or change values
     *  We'll realistically get rerenders on productId for free, so spare the comparison
     */
    return pPrice === nPrice && pChange === nChange;
  },
);

