import {
  useMemo,
  useContext,
  memo,
  useState,
  useCallback,
  lazy,
  useEffect,
  ReactNode,
} from 'react';
import { useIntl } from 'react-intl';

import type { BorderRadius } from '@cbhq/cds-common';
import { IconButton } from '@cbhq/cds-web/buttons/IconButton';
import { BoxProps } from '@cbhq/cds-web/layout';
import { HStack } from '@cbhq/cds-web/layout/HStack';
import { VStack } from '@cbhq/cds-web/layout/VStack';
import { graphql, useFragment, InstrumentedSuspense } from '@cbhq/data-layer';
import {
  CoinbasePublicApiAuthedRetailBrokerageApiOrder,
  CoinbasePublicApiAuthedRetailBrokerageApiProductType,
} from '@cbhq/instant-api-hooks-retail-brokerage/types';

import AdvancedBoundary from 'views/Advanced/components/AdvancedBoundary';
import { MarketTypeContext } from 'views/AdvancedMarkets/contexts/MarketTypeContext';
import { FiltersProvider } from 'views/AdvancedOrders/contexts/FiltersContext/FiltersContext';
import LoadingColumnHeaderDropdown from 'views/AdvancedOrders/shared/LoadingColumnHeaderDropdown';
import type { ColKey } from 'views/AdvancedOrders/shared/Table/TableHeader';

import useFiltersContext from '../contexts/FiltersContext/useFiltersContext';
import {
  useAssetFilterOptions,
  useMarketFilterOptions,
} from '../contexts/FiltersContext/useMarketFilterOptions';
import messages from '../messages';
import ExpiryFilterDropdown from '../shared/FilterDropdowns/ExpiryFilterDropdown';
import OpenAssetsFilterDropdown from '../shared/FilterDropdowns/OpenAssetsFilterDropdown';
import SideFilterDropdown from '../shared/FilterDropdowns/SideFilterDropdown';
import TypeFilterDropdown from '../shared/FilterDropdowns/TypeFilterDropdown';
import OrdersContainer from '../shared/OrdersContainer/OrdersContainer';
import { OpenOrdersFragment$key } from './__generated__/OpenOrdersFragment.graphql';
import OpenOrdersCancelAllButton from './components/OpenOrdersCancelAllButton';
import OpenOrdersTable from './components/OpenOrdersTable';

const OpenPairFilterDropdown = lazy(() =>
  import(
    /* webpackChunkName: "OpenPairFilterDropdown" */
    'views/AdvancedOrders/shared/FilterDropdowns/OpenPairFilterDropdown'
  ).then(props => ({ default: props.default })),
);

type Props = {
  handleShowModal: (
    order: CoinbasePublicApiAuthedRetailBrokerageApiOrder,
  ) => void;
  borderRadius?: BorderRadius;
  // when this is true, toggle button is hidden
  disableToggle?: boolean;
  // when assetSymbol is defined, we only show asset related pairs in order table
  // e.g. assetSymbol is ETH, we show ETH-USD, ETH-DAI, SOL-ETH, etc
  // this will be passed into FiltersProvider context and be static
  assetSymbol?: string;
  hiddenCols?: Array<ColKey>;
  // this will be added to the right of cancel all button
  trailing?: ReactNode;
  queryRef: OpenOrdersFragment$key;
} & Pick<BoxProps, 'background' | 'bordered' | 'elevation'>;

function OpenOrders({
  handleShowModal,
  borderRadius,
  disableToggle = false,
  hiddenCols,
  trailing,
  background,
  bordered,
  elevation,
  queryRef,
}: Props) {
  const { formatMessage } = useIntl();

  const query = useFragment(
    graphql`
      fragment OpenOrdersFragment on Query {
        ...OpenOrdersTableFragment
      }
    `,
    queryRef,
  );

  const { marketTypeFilter } = useContext(MarketTypeContext);
  const { marketFilterOptions, setMarketFilterOptions } =
    useMarketFilterOptions(marketTypeFilter);
  const { assetFilterOptions, setAssetFilterOptions } =
    useAssetFilterOptions(marketTypeFilter);
  const [isOpen, setIsOpen] = useState(true);
  const handleToggleIsOpen = useCallback(() => setIsOpen(prev => !prev), []);
  const isFuturesMarket =
    marketTypeFilter ===
    CoinbasePublicApiAuthedRetailBrokerageApiProductType.FUTURE;

  const {
    assetFilter,
    setAssetFilter,

    marketFilter,
    setMarketFilter,

    typeFilter,
    setTypeFilter,

    sideFilter,
    setSideFilter,

    expiryFilter,
    setExpiryFilter,

    resetAllFilters,
    assetSymbol,
  } = useFiltersContext();

  useEffect(() => {
    resetAllFilters();
  }, [marketTypeFilter]);

  const headerRight = useMemo(() => {
    return (
      !disableToggle && (
        <HStack spacerGap={1}>
          <IconButton
            testID="toggle-icon"
            compact
            name={isOpen ? 'caretUp' : 'caretDown'}
            onPress={handleToggleIsOpen}
          />
        </HStack>
      )
    );
  }, [disableToggle, handleToggleIsOpen, isOpen]);

  return (
    <OrdersContainer
      name={formatMessage(messages.openOrdersTableTitle)}
      titleDataTestId="open-orders-title"
      headerRight={headerRight}
      borderRadius={borderRadius}
      background={background}
      bordered={bordered}
      elevation={elevation}
      marketTypeFilter={marketTypeFilter}
      showTitle
    >
      {isOpen && (
        <>
          <HStack
            spacingHorizontal={3}
            spacingBottom={2}
            justifyContent="space-between"
            id="open-orders-filters-container"
          >
            <HStack spacerGap={1}>
              {isFuturesMarket && (
                <InstrumentedSuspense
                  instrumentationId="OpenAssetsFilterDropdown"
                  fallback={<LoadingColumnHeaderDropdown type="assets" />}
                >
                  <OpenAssetsFilterDropdown
                    marketTypeFilter={marketTypeFilter}
                    assetFilterOptions={assetFilterOptions}
                    setAssetFilterOptions={setAssetFilterOptions}
                    assetFilter={assetFilter}
                    setAssetFilter={setAssetFilter}
                    assetSymbol={assetSymbol}
                  />
                </InstrumentedSuspense>
              )}
              {!assetSymbol && !isFuturesMarket && (
                <InstrumentedSuspense
                  instrumentationId="OpenPairFilterDropdown"
                  fallback={<LoadingColumnHeaderDropdown type="market" />}
                >
                  <OpenPairFilterDropdown
                    marketTypeFilter={marketTypeFilter}
                    marketFilterOptions={marketFilterOptions}
                    setMarketFilterOptions={setMarketFilterOptions}
                    marketFilter={marketFilter}
                    setMarketFilter={setMarketFilter}
                    assetSymbol={assetSymbol}
                  />
                </InstrumentedSuspense>
              )}
              <TypeFilterDropdown
                marketTypeFilter={marketTypeFilter}
                typeFilter={typeFilter}
                setTypeFilter={setTypeFilter}
                multiSelect
              />
              <SideFilterDropdown
                marketTypeFilter={marketTypeFilter}
                sideFilter={sideFilter}
                setSideFilter={setSideFilter}
              />
              {isFuturesMarket && (
                <ExpiryFilterDropdown
                  marketTypeFilter={marketTypeFilter}
                  expiryFilter={expiryFilter}
                  setExpiryFilter={setExpiryFilter}
                />
              )}
            </HStack>
            <HStack spacerGap={1}>
              <OpenOrdersCancelAllButton
                symbol={assetSymbol}
                marketTypeFilter={marketTypeFilter}
              />
              {trailing}
            </HStack>
          </HStack>
          <VStack minHeight={300} id="open-orders-table-container">
            <OpenOrdersTable
              handleShowModal={handleShowModal}
              hiddenCols={hiddenCols}
              queryRef={query}
            />
          </VStack>
        </>
      )}
    </OrdersContainer>
  );
}

function OpenOrdersContainer(props: Props) {
  return (
    <AdvancedBoundary owner="advanced" name="advanced-component-open-orders">
      <FiltersProvider assetSymbol={props.assetSymbol}>
        <OpenOrders {...props} />
      </FiltersProvider>
    </AdvancedBoundary>
  );
}

export default memo(OpenOrdersContainer);

