import SelectorPill from '@cbhq/advanced-trade-web/components/shared/SelectorPill';

import FadedScrollable from 'components/FadedScrollable';
import feesMessages from 'views/AdvancedFees/messages';
import { useLogOrdersNavClickedEvent } from 'views/AdvancedOrders/eventing';
import ordersMessages from 'views/AdvancedOrders/messages';

type TradeManagementTabId = 'orders' | 'positions' | 'advanced-fees' | 'fills';

interface Props {
  route: TradeManagementTabId;
}

function OrdersFeesToggle({ route }: Props) {
  const { formatMessage } = useIntl();

  const location = useLocation();
  const ordersRoute =
    new URLSearchParams(location.search).get('type') || 'openOrders';

  const orderHistoryTitle = formatMessage(
    ordersMessages.orderHistoryTableTitle,
  );
  const openOrdersTitle = formatMessage(ordersMessages.openOrdersTableTitle);
  const feesMobileTitle = formatMessage(feesMessages.feesSummary);
  const history = useHistory();
  const logOrdersNavClickedEvent = useLogOrdersNavClickedEvent();

  const onFeesClick = useCallback(() => {
    history.replace('/advanced-fees');
    logOrdersNavClickedEvent({
      ordersNav: 'fees_page',
    });
  }, [history, logOrdersNavClickedEvent]);

  const onOpenOrdersClick = useCallback(() => {
    history.replace('/orders?type=openOrders');
    logOrdersNavClickedEvent({ ordersNav: 'orders_page' });
  }, [history, logOrdersNavClickedEvent]);

  const onOrderHistoryClick = useCallback(() => {
    history.replace('/orders?type=orderHistory');
    logOrdersNavClickedEvent({ ordersNav: 'orders_page' });
  }, [history, logOrdersNavClickedEvent]);

  return (
    <div tabIndex={0} id="orders-fees-toggle">
      <FadedScrollable>
        <SelectorPill
          id="open-orders"
          active={route === 'orders' && ordersRoute === 'openOrders'}
          label={openOrdersTitle}
          onClick={onOpenOrdersClick}
        />
        <SelectorPill
          id="order-history"
          active={route === 'orders' && ordersRoute === 'orderHistory'}
          label={orderHistoryTitle}
          onClick={onOrderHistoryClick}
        />
        <SelectorPill
          id="fees"
          active={route === 'advanced-fees'}
          label={feesMobileTitle}
          onClick={onFeesClick}
        />
      </FadedScrollable>
    </div>
  );
}

export default memo(OrdersFeesToggle);

