import { useEffect, useCallback, useMemo, useRef, useState } from 'react';
import debounce from 'lodash/debounce';
import styled from 'styled-components';

import { usePalette } from '@cbhq/cds-web/hooks/usePalette';
import { HStack } from '@cbhq/cds-web/layout';
import { Tooltip } from '@cbhq/cds-web/overlays';
import { useTypographyStyles } from '@cbhq/cds-web/typography/useTypographyStyles';

import { typedMemo } from 'views/AdvancedPortfolio/utils/typedMemo';

import type { Column, CommonData } from './types';

type Props<T extends CommonData<T>> = {
  content: unknown;
  accessoryEnd?: React.ReactNode;
  accessoryStart?: React.ReactNode;
  column: Pick<
    Column<T>,
    | 'align'
    | 'cellColor'
    | 'cellType'
    | 'onCellClick'
    | 'enableCellHighlight'
    | 'defaultValue'
    | 'key'
  >;
  data: T;
  isSubRowCell?: boolean;
};

const textAlignMap: Record<
  'center' | 'flex-start' | 'flex-end',
  'center' | 'left' | 'right'
> = {
  center: 'center',
  'flex-start': 'left',
  'flex-end': 'right',
};

// this component is used in DataTable. You also can use it in renderCell function
// to render a cell with the same style as DataTable but with custom accessory
function DataTableBodyCell<T extends CommonData<T>>(props: Props<T>) {
  const {
    content,
    column,
    data,
    accessoryEnd,
    accessoryStart,
    isSubRowCell = false,
  } = props;
  const textRef = useRef<HTMLDivElement>(null);
  const [isOverflow, setIsOverflow] = useState<boolean | undefined>(undefined);

  const {
    align = 'flex-end',
    cellType = 'body',
    cellColor = 'foreground',
    onCellClick,
    enableCellHighlight = true,
    defaultValue = '-',
    key,
  } = column;

  const palette = usePalette();
  const colorVar = useMemo(() => {
    if (isSubRowCell) {
      return palette.foregroundMuted;
    }
    return palette[
      typeof cellColor === 'function' ? cellColor(data) : cellColor
    ];
  }, [cellColor, data, isSubRowCell, palette]);
  const headlineClassName = useTypographyStyles('headline');
  const BodyClassName = useTypographyStyles('body');
  const textClassName =
    cellType === 'headline' ? headlineClassName : BodyClassName;

  useEffect(() => {
    const handleResize = debounce(() => {
      setIsOverflow(undefined);
    }, 2000);

    window.addEventListener('resize', handleResize);
    // Clean up function
    return () => {
      window.removeEventListener('resize', handleResize);
      handleResize.cancel(); // cancel the debounced function when unmounting
    };
  }, []); // Empty array ensures effect only runs once

  const handleCellClick = useMemo(() => {
    const cellClickHandler = onCellClick?.(data);
    if (cellClickHandler && content) {
      return (event: React.MouseEvent<HTMLDivElement>) => {
        event.stopPropagation();
        event.preventDefault();
        cellClickHandler();
      };
    } else {
      return undefined;
    }
  }, [content, data, onCellClick]);

  const handleMouseEnter = useCallback(() => {
    if (isOverflow !== undefined) {
      //* we already know that isOverflow is true or false, so we can skip checking width
      return;
    }
    // check element scroll width and client width to see if there is overflow
    const divElement = textRef.current;
    if (divElement) {
      setIsOverflow(divElement.scrollWidth > divElement.clientWidth);
    }
  }, [isOverflow]);

  const overflowText = useMemo(() => {
    return (
      <HStack
        alignItems="center"
        spacerGap={0.5}
        overflow="hidden"
        width="100%"
        justifyContent={align}
      >
        {accessoryStart}
        <OverflowText
          key="overflow-text"
          ref={textRef}
          className={textClassName}
          style={{
            textAlign: textAlignMap[align],
            color: colorVar,
          }}
          hoverUnderline={!!handleCellClick}
          onMouseEnter={handleMouseEnter}
        >
          <span
            className={
              enableCellHighlight ? 'data-table-cell-highlight' : undefined
            }
            onClick={handleCellClick}
            data-testid={`table-column-${key}`}
          >
            {/*
            // @ts-expect-error: TODO Please fix */}
            {content ?? defaultValue}
          </span>
        </OverflowText>
        {accessoryEnd}
      </HStack>
    );
  }, [
    align,
    accessoryStart,
    textClassName,
    colorVar,
    handleCellClick,
    handleMouseEnter,
    enableCellHighlight,
    key,
    content,
    defaultValue,
    accessoryEnd,
  ]);

  if (isOverflow) {
    return <Tooltip content={content?.toString()}>{overflowText}</Tooltip>;
  }
  return overflowText;
}

type OverflowTextProps = {
  hoverUnderline?: boolean;
};

const OverflowText = styled.div<OverflowTextProps>`
  text-overflow: ellipsis;
  overflow: hidden;
  white-space: nowrap;
  & > span:hover {
    text-decoration: ${props => (props.hoverUnderline ? 'underline' : 'none')};
  }
`;

export default typedMemo(DataTableBodyCell);

import React, { cloneElement } from 'react';
import { m, MotionStyle, Variants } from 'framer-motion';
import styled from 'styled-components';

import {
  animateInOpacityConfig,
  animateOutOpacityConfig,
  getTranslateConfigByPlacement,
} from '@cbhq/cds-common/animation/tooltip';
import { zIndex } from '@cbhq/cds-common/tokens/zIndex';
import type { SpacingScale } from '@cbhq/cds-common/types';
import { IconButton } from '@cbhq/cds-web/buttons';
import { Box } from '@cbhq/cds-web/layout/Box';
import { useMotionProps } from '@cbhq/cds-web/motion/useMotionProps';
import { Popover } from '@cbhq/cds-web/overlays/popover/Popover';
import type { PopoverContentPositionConfig } from '@cbhq/cds-web/overlays/popover/PopoverProps';
import { useTooltipState } from '@cbhq/cds-web/overlays/Tooltip/useTooltipState';

import { typedMemo } from 'views/AdvancedPortfolio/utils/typedMemo';

import { Tooltip } from './TooltipNoAnimation';
import type { ActionHoverColor, ActionType, CommonData } from './types';

const contentPosition: PopoverContentPositionConfig = {
  placement: 'top-end',
  //* negative skid is supported but not documented in the CDS library
  skid: -1 as SpacingScale,
};

const preventMouseDown = (event: React.MouseEvent) => {
  event.preventDefault();
  event.stopPropagation();
};

type Props<T extends CommonData<T>> = {
  data: T;
  actions: ActionType<T>[];
  children: React.ReactElement<{ isHovered: boolean }>;
};

function RowActionTooltip<T extends CommonData<T>>({
  actions,
  children,
  data,
}: Props<T>) {
  const {
    isOpen,
    handleOnMouseEnter,
    handleOnMouseLeave,
    handleOnFocus,
    handleOnBlur,
  } = useTooltipState();

  return (
    <Popover
      contentPosition={contentPosition}
      onMouseEnter={handleOnMouseEnter}
      onMouseLeave={handleOnMouseLeave}
      onFocus={handleOnFocus}
      onBlur={handleOnBlur}
      onMouseDown={preventMouseDown}
      invertPopoverSpectrum={false}
      visible={isOpen}
      content={<TooltipContent data={data} actions={actions} />}
    >
      {cloneElement(children, { isHovered: isOpen })}
    </Popover>
  );
}

const TooltipContent = typedMemo(
  <T extends CommonData<T>>({ data, actions }: Omit<Props<T>, 'children'>) => {
    const motionProps = useMotionProps({
      style: { marginBottom: -4, zIndex: zIndex.overlays.tooltip as number },
      enterConfigs: [
        animateInOpacityConfig,
        getTranslateConfigByPlacement({ placement: 'top' }),
      ],
      exitConfigs: [
        animateOutOpacityConfig,
        getTranslateConfigByPlacement({ placement: 'top', isExiting: true }),
      ],
      exit: 'exit',
    });

    return (
      <m.div
        variants={motionProps.variants as Variants}
        style={motionProps.style as MotionStyle}
        exit="exit"
        initial="exit"
        animate="enter"
        transition={motionProps.transition}
      >
        <Box
          spacing={0.5}
          borderRadius="roundedFull"
          flexDirection="row"
          style={{ gap: 4 }}
          background="background"
          elevation={1}
        >
          {actions.map(
            ({
              key,
              label,
              variant = 'secondary',
              iconName,
              onClick,
              hoverColor = 'iconFill',
            }) => {
              const icon = (
                <IconWrapper key={key} hoverColor={hoverColor}>
                  <IconButton
                    testID={`action-button-${key}`}
                    // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                    onPress={() => onClick(data)}
                    compact
                    name={iconName}
                    variant={variant}
                  />
                </IconWrapper>
              );
              if (label) {
                return (
                  <Tooltip key={key} content={label}>
                    {icon}
                  </Tooltip>
                );
              } else {
                return icon;
              }
            },
          )}
        </Box>
      </m.div>
    );
  },
);

const IconWrapper = styled.div<{ hoverColor: ActionHoverColor }>`
  /* stylelint-disable  -- 2023.06.01 */
  & button:hover {
    background-color: ${p => p.theme.color[p.hoverColor]};
    & span {
      color: ${p => p.theme.color.white} !important;
    }
  }
  /* stylelint-enable  */
`;

export default typedMemo(RowActionTooltip);

