import useFeature from 'hooks/useFeature';

import {
  ADVANCED_REFERRAL_TERMS_LINK,
  FORMATTED_PERCENT_CONFIG,
} from '../constants';
import messages from '../messages';
import { AdvancedReferralFormFragment$key } from './__generated__/AdvancedReferralFormFragment.graphql';

type Props = {
  queryRef: AdvancedReferralFormFragment$key;
};

function AdvancedReferralForm({ queryRef }: Props) {
  const query = useFragment(
    graphql`
      fragment AdvancedReferralFormFragment on Query {
        viewer {
          nuxProperties {
            referrerTerms(tag: "advanced") {
              promoCode
            }
          }
        }
      }
    `,
    queryRef,
  );

  const { formatMessage, formatNumber } = useIntl();
  const isAdvancedReferralAmbassador = useFeature(
    '2024.may.advanced_referral_program_ambassador',
  );

  const [isCopied, setIsCopied] = useState(false);
  const referralLink = `https://advanced.coinbase.com/join/${query.viewer.nuxProperties.referrerTerms?.promoCode}`;
  const toast = useToast();

  const handleCopyLink = useCallback(() => {
    logEvent('advanced_referral_copy_link', {
      componentType: ComponentType.button,
      action: ActionType.click,
    });

    copyToClipboard(referralLink);
    setIsCopied(true);
    toast.show(formatMessage(messages.copiedLinkToastTest));
  }, [formatMessage, referralLink, toast]);

  // TODO: Replace with actual rebate percentage once we have the data from the API
  const maximumRebatePercentage = isAdvancedReferralAmbassador ? '0.3' : '0.15';

  const formattedMaximumRebatePercentage = formatNumber(
    parseFloat(maximumRebatePercentage || '0'),
    FORMATTED_PERCENT_CONFIG,
  );

  return (
    <VStack alignItems={'flex-start'} spacerGap={2} maxWidth={800}>
      <TextDisplay3 as="h3">
        {formatMessage(messages.referFriendsTitle, {
          maximumRebatePercentage: formattedMaximumRebatePercentage,
        })}
      </TextDisplay3>

      <TextTitle4 as="p" color="foregroundMuted" spacingBottom={2}>
        {formatMessage(messages.referFriendsDescription, {
          maximumRebatePercentage: formattedMaximumRebatePercentage,
          link: (content: React.ReactNode) => [
            <Link
              href={ADVANCED_REFERRAL_TERMS_LINK}
              openInNewWindow
              underline={false}
            >
              <>{content}</>
            </Link>,
          ],
        })}
      </TextTitle4>

      <HStack flexGrow={1} spacerGap={2} alignItems="flex-end" width="100%">
        <VStack width="100%">
          <TextBody as="span" spacingBottom={0.5}>
            {formatMessage(messages.yourReferralLink)}
          </TextBody>
          <TextInput color="foreground" placeholder={referralLink} disabled />
        </VStack>

        <Box flexGrow={1}>
          <Button
            testID="copy-referral-link-button"
            variant="primary"
            onPress={handleCopyLink}
            endIcon={isCopied ? 'checkmark' : 'copy'}
          >
            {isCopied
              ? formatMessage(messages.copiedLinkText)
              : formatMessage(messages.copyLinkText)}
          </Button>
        </Box>
      </HStack>
    </VStack>
  );
}

