import { ItemSetter } from 'views/AdvancedTrade/components/AdvancedDropdown/AdvancedDropdown';

export type AdvancedDropdownItemProps = {
  id: string;
  selected: string[];
  setter: ItemSetter<{ id: string }>;
  borderedBottom?: boolean;
  content?: string;
  testID?: string;
  isMultiSelect?: boolean;
};

const STANDARD_WIDTH = 120;
const MULTI_SELECT_WIDTH = 200;

function AdvancedDropdownItem({
  id,
  content,
  setter,
  selected,
  borderedBottom,
  testID,
  isMultiSelect,
}: AdvancedDropdownItemProps) {
  const clickHandler = useCallback(() => {
    return setter(id);
  }, [id, setter]);

  const isSelected = selected.some(selectedId => {
    return selectedId === id;
  });

  return (
    <PressableOpacity
      style={{ border: 'none' }}
      as="button"
      onPress={clickHandler}
      data-testid={testID}
      tabIndex={-1}
    >
      <StyledBox
        spacingHorizontal={1}
        spacingVertical={2}
        minWidth={isMultiSelect ? MULTI_SELECT_WIDTH : STANDARD_WIDTH}
        alignItems="center"
        justifyContent="space-between"
        borderedBottom={borderedBottom}
        tabIndex={0}
      >
        <StyledTextLabel1 noWrap spacingEnd={0.5}>
          {content || id}
        </StyledTextLabel1>
        {isMultiSelect ? (
          <Checkbox
            checked={isSelected}
            testID="advanced-dropdown-item-checkbox"
          />
        ) : (
          isSelected && (
            <Icon
              name="checkmark"
              size="xs"
              color="foregroundMuted"
              spacingStart={0.5}
            />
          )
        )}
      </StyledBox>
    </PressableOpacity>
  );
}

