  (
    p: Pick<
      React.ComponentProps<typeof TextLabel1>,
      'noWrap' | 'spacingEnd' | 'className' | 'children'
    >,
  ) => <TextLabel1 as="span" {...p} />,
)`
  /* stylelint-disable-next-line declaration-no-important -- 2023.09.28 */
  text-transform: capitalize !important;
`;

