import React, { useEffect, useRef, memo, useCallback, useMemo } from 'react';
import { useIntl } from 'react-intl';

import NumericInput from '@cbhq/advanced-trade-web/components/OrderForm/NumericInput';
import { OrderFormSection } from '@cbhq/advanced-trade-web/components/OrderForm/OrderFormSection';
import LimitPriceShortcuts from '@cbhq/advanced-trade-web/components/OrderForm/shortcuts/LimitPriceShortcuts';

import useUser from 'hooks/useUser/useUser';
import { advancedCommonMessages } from 'views/Advanced/constants/commonMessages';
import useSubscribePriceOverrideHandler from 'views/Advanced/contexts/PriceOverrideNotificationContext/useSubscribePriceOverrideHandler';
import useHandleNavigationKeyInputDate from 'views/AdvancedTrade/components/OrderForm/hooks/useHandleNavigationKeyInputUpdate';
import useOrderFormContext from 'views/AdvancedTrade/contexts/OrderFormContext/useOrderFormContext';
import useCurrentProductId from 'views/AdvancedTrade/contexts/ProductContext/useCurrentProductId';
import useProductContext from 'views/AdvancedTrade/contexts/ProductContext/useProductContext';

import getQuoteSuffix from './getQuoteSuffix';
import messages from './messages';
import NumericInputErrorLabel from './NumericInputErrorLabel/NumericInputErrorLabel';

type Props = {
  disabled?: boolean;
  hasUSDCAlias?: boolean;
};

function PriceSection({ disabled = false, hasUSDCAlias = false }: Props) {
  const stopPriceInputRef = useRef<HTMLInputElement>(null);
  const limitPriceInputRef = useRef<HTMLInputElement>(null);
  const subscribePriceOverrideHandler = useSubscribePriceOverrideHandler();

  const { formatMessage, formatNumber } = useIntl();
  const productId = useCurrentProductId();
  const { quoteCurrencyId, priceIncrement, pricePrecision } =
    useProductContext();
  const {
    type,
    side,
    stopPrice,
    stopPriceError,
    handleStopPriceUpdate,
    limitPrice,
    limitPriceError,
    handleLimitPriceUpdate,
    paymentMethod,
    resetErrors,
  } = useOrderFormContext();

  const { countryCode } = useUser();

  const handleKeyDownLimitPrice = useHandleNavigationKeyInputDate({
    currentValue: +limitPrice,
    precision: pricePrecision,
    increment: +priceIncrement,
    onChange: handleLimitPriceUpdate,
  });

  const handleKeyDownStopPrice = useHandleNavigationKeyInputDate({
    currentValue: +stopPrice,
    precision: pricePrecision,
    increment: +priceIncrement,
    onChange: handleStopPriceUpdate,
  });

  const placeholderFormatConfig = useMemo(
    () => ({
      style: 'decimal' as const,
      minimumFractionDigits: pricePrecision,
    }),
    [pricePrecision],
  );

  const quoteNumericPlaceholder = useMemo(
    () => formatNumber(0, placeholderFormatConfig),
    [formatNumber, placeholderFormatConfig],
  );

  const handleStopPriceChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      e.preventDefault();
      handleStopPriceUpdate(e.target.value);
    },
    [handleStopPriceUpdate],
  );

  const handleLimitPriceChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      e.preventDefault();

      // This will be '' if user either clears input or enters '.'
      const priceString = e.target.value;
      handleLimitPriceUpdate(priceString);
    },
    [handleLimitPriceUpdate],
  );

  const handleShortcutPress = useCallback(
    (value: string) => {
      resetErrors();
      handleLimitPriceUpdate(value);
    },
    [handleLimitPriceUpdate, resetErrors],
  );

  const suffix = getQuoteSuffix({
    quoteCurrencyId,
    hasUSDCAlias,
    countryCode,
    paymentMethod,
  });

  // When price override is set, re-focus
  useEffect(() => {
    return subscribePriceOverrideHandler(
      (_: string, activeElement: Element | null) => {
        // Focus the top-most input, unless one of the price fields is already focused
        if (
          type === 'stop_limit' &&
          activeElement !== limitPriceInputRef.current
        ) {
          stopPriceInputRef.current?.focus();
        } else if (type !== 'market') {
          limitPriceInputRef.current?.focus();
        }
      },
    );
  }, [subscribePriceOverrideHandler]);

  // Re-focus top price field when type/side changes
  useEffect(() => {
    if (type === 'stop_limit') {
      stopPriceInputRef.current?.focus();
    } else if (type !== 'market') {
      limitPriceInputRef.current?.focus();
    }
  }, [type, side]);

  return (
    <>
      {type === 'stop_limit' && (
        <OrderFormSection disabled={disabled}>
          <NumericInput
            onKeyDown={handleKeyDownStopPrice}
            disabled={disabled}
            label={formatMessage(messages.stopPrice)}
            suffix={suffix}
            value={stopPrice}
            error={
              stopPriceError ? (
                <NumericInputErrorLabel error={stopPriceError} />
              ) : null
            }
            onChange={handleStopPriceChange}
            key="stop-price-input"
            id="stop-price-input"
            data-testid="stop-price-input"
            ariaLabel={formatMessage(messages.stopPrice)}
            placeholder={quoteNumericPlaceholder}
            autoFocus
            ref={stopPriceInputRef}
          />
        </OrderFormSection>
      )}
      <OrderFormSection gap={0.5} disabled={disabled}>
        <NumericInput
          onKeyDown={handleKeyDownLimitPrice}
          disabled={disabled}
          label={formatMessage(advancedCommonMessages.limitPrice)}
          suffix={suffix}
          value={limitPrice}
          error={
            limitPriceError ? (
              <NumericInputErrorLabel error={limitPriceError} />
            ) : null
          }
          onChange={handleLimitPriceChange}
          key="limit-price-input"
          id="limit-price-input"
          data-testid="limit-price-input"
          ariaLabel={formatMessage(advancedCommonMessages.limitPrice)}
          placeholder={quoteNumericPlaceholder}
          autoFocus={type === 'limit'}
          ref={limitPriceInputRef}
        />
        {type === 'limit' && (
          <LimitPriceShortcuts
            entryPoint="OrderForm"
            productId={productId}
            orderSide={side}
            pricePrecision={pricePrecision}
            onSelect={handleShortcutPress}
          />
        )}
      </OrderFormSection>
    </>
  );
}

export default memo(PriceSection);

import React, {
