import { theme } from '@cb/shared/styles/theme';
import NumericInputWithToggle from '@cbhq/advanced-trade-web/components/OrderForm/NumericInputWithToggle';
import { OrderFormSection } from '@cbhq/advanced-trade-web/components/OrderForm/OrderFormSection';
import { HStack } from '@cbhq/cds-web/layout';
