import { graphql, useFragment } from '@cbhq/data-layer';

import useUser from 'hooks/useUser/useUser';
import { advancedCommonMessages } from 'views/Advanced/constants/commonMessages';
import useHandleNavigationKeyInputDate from 'views/AdvancedTrade/components/OrderForm/hooks/useHandleNavigationKeyInputUpdate';
import useAccountsContext from 'views/AdvancedTrade/contexts/AccountsContext/useAccountsContext';
import useOrderFormContext from 'views/AdvancedTrade/contexts/OrderFormContext/useOrderFormContext';
import useProductContext from 'views/AdvancedTrade/contexts/ProductContext/useProductContext';
import { usePersistOrderFormSizeInQuote } from 'views/AdvancedTrade/hooks/usePersistOrderFormSizeInQuote';

import AmountShortcuts from '../../components/AmountShortcuts';
import { useLogOrderFormAmountCurrencyToggle } from '../../eventing';
import getQuoteSuffix from '../../getQuoteSuffix';
import messages from '../../messages';
import NumericInputErrorLabel from '../../NumericInputErrorLabel/NumericInputErrorLabel';
import { AmountInputFragment$key } from './__generated__/AmountInputFragment.graphql';
import NUXTooltip from './NUXTooltip';
import useShouldShowOrderFormNuxTooltip from './useShouldShowOrderFormNuxTooltip';

type Props = {
  queryRef: AmountInputFragment$key;
  disabled?: boolean;
  hasUSDCAlias?: boolean;
  selectedCurrencyIsQuote: boolean;
  setSelectedCurrencyIsQuote: Dispatch<SetStateAction<boolean>>;
};

const isUSDOrUSDC = (currency: string) => {
  return currency === 'USD' || currency === 'USDC';
};

function AmountInput({
  queryRef,
  disabled = false,
  hasUSDCAlias = false,
  selectedCurrencyIsQuote,
  setSelectedCurrencyIsQuote,
}: Props) {
  const query = useFragment(
    graphql`
      fragment AmountInputFragment on Query {
        ...AmountShortcutsDeprecatedFragment
      }
    `,
    queryRef,
  );
  const amountInputRef = useRef<HTMLInputElement>(null);

  const persistOrderFormSizeInQuote = usePersistOrderFormSizeInQuote();

  const logOrderFormAmountCurrencyToggle =
    useLogOrderFormAmountCurrencyToggle();
  const {
    side,
    type,
    amount,
    total,
    handleAmountUpdate,
    handleTotalUpdate,
    setLastFocusedInput,
    amountError,
    totalError,
    paymentMethod,
    limitPrice,
    resetErrors,
    selectedPortfolioUuid,
  } = useOrderFormContext();
  const { formatMessage, formatNumber } = useIntl();
  const {
    baseCurrencyId,
    quoteCurrencyId,
    basePrecision,
    quotePrecision,
    baseIncrement,
    priceIncrement,
    aliasTo,
    currentProduct: { productId },
  } = useProductContext();
  const { baseBalance, quoteBalance } = useAccountsContext();
  const { countryCode } = useUser();

  const quoteSuffix = getQuoteSuffix({
    quoteCurrencyId,
    hasUSDCAlias,
    countryCode,
    paymentMethod,
  });

  const [selectedCurrency, setSelectedCurrency] = useState(
    selectedCurrencyIsQuote ? quoteSuffix : baseCurrencyId,
  );

  // This is necessary to keep the currency in sync with the payment method when we have a quote currency,
  // due to the fact that it is dynamic between USD or USDC
  const derivedSelectedCurrency = useMemo(() => {
    if (isUSDOrUSDC(selectedCurrency) && paymentMethod !== selectedCurrency) {
      return quoteSuffix;
    }

    return selectedCurrency;
  }, [paymentMethod, quoteSuffix, selectedCurrency]);

  const isSizeInQuote = derivedSelectedCurrency === quoteSuffix;

  const handleKeyDown = useHandleNavigationKeyInputDate({
    onChange: isSizeInQuote ? handleTotalUpdate : handleAmountUpdate,
    currentValue: isSizeInQuote ? +total : +amount,
    increment: isSizeInQuote ? +priceIncrement : +baseIncrement,
    precision: isSizeInQuote ? quotePrecision : basePrecision,
  });

  const handleAmountQuickSelectClick = useCallback(
    (newAmount: string) => {
      resetErrors();
      amountInputRef.current?.focus();

      if (side === 'buy') {
        handleTotalUpdate(newAmount);
      } else {
        handleAmountUpdate(newAmount);
      }
    },
    [handleAmountUpdate, handleTotalUpdate, resetErrors, side],
  );

  const handleAmountChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      e.preventDefault();
      isSizeInQuote
        ? handleTotalUpdate(e.target.value)
        : handleAmountUpdate(e.target.value);
    },
    [handleAmountUpdate, handleTotalUpdate, isSizeInQuote],
  );

  const baseNumericPlaceholder = useMemo(
    () =>
      formatNumber(0, {
        style: 'decimal',
        minimumFractionDigits: basePrecision,
      }),
    [formatNumber, basePrecision],
  );

  const quoteNumericPlaceholder = useMemo(
    () =>
      formatNumber(0, {
        style: 'decimal',
        minimumFractionDigits: quotePrecision,
      }),
    [formatNumber, quotePrecision],
  );

  const handleToggleChange = useCallback(() => {
    // clear the amount when they change what currency the amount is denominated in
    handleAmountUpdate('');

    // TODO: refactor this legacy logic out of OrderFormContext after experiment is complete and old order form is deprecated
    // the old order form keeps track of which input was "last focused" and has a useEffect that "anchors" to the amount
    // in the last focused input, while changing the other input amount based on limit price, avg price for market orders, etc.
    // we only have a single "amount" input now, but for the OrderFormContext useEffect to set state correctly,
    // we have to simulate this old focus behavior when the user changes the sizeInQuote dropdown
    if (selectedCurrency === quoteSuffix) {
      // Switch to base
      persistOrderFormSizeInQuote(false);
      setSelectedCurrencyIsQuote(false);
      setLastFocusedInput('amount');
      logOrderFormAmountCurrencyToggle({
        selectedCurrency: baseCurrencyId,
        isSizeInQuote: false,
      });
      setSelectedCurrency(baseCurrencyId);
    } else {
      // Switch to quote
      persistOrderFormSizeInQuote(true);
      setSelectedCurrencyIsQuote(true);
      setLastFocusedInput('total');
      logOrderFormAmountCurrencyToggle({
        selectedCurrency: quoteSuffix,
        isSizeInQuote: true,
      });
      setSelectedCurrency(quoteSuffix);
    }
  }, [
    baseCurrencyId,
    handleAmountUpdate,
    logOrderFormAmountCurrencyToggle,
    persistOrderFormSizeInQuote,
    quoteSuffix,
    selectedCurrency,
    setLastFocusedInput,
    setSelectedCurrencyIsQuote,
  ]);
  const { shouldShowTooltip, handleNuxTooltipSeen } =
    useShouldShowOrderFormNuxTooltip();
  const [isNuxTooltipVisible, setIsNuxTooltipVisible] = useState(true);
  const handleHideTooltip = useCallback(() => {
    handleNuxTooltipSeen();
    setIsNuxTooltipVisible(false);
  }, [handleNuxTooltipSeen]);

  const error = useMemo(() => {
    const amountOrTotalError = amountError ?? totalError;

    if (!amountOrTotalError) {
      return null;
    }

    return <NumericInputErrorLabel error={amountOrTotalError} />;
  }, [amountError, totalError]);

  // persistent settings are not guaranteed to be fetched on mount, but this should only run
  // once (if already fetched by mount) or twice (undefined -> fetched value) per market
  useEffect(() => {
    setSelectedCurrency(selectedCurrencyIsQuote ? quoteSuffix : baseCurrencyId);
    selectedCurrencyIsQuote
      ? setLastFocusedInput('total')
      : setLastFocusedInput('amount');
  }, [selectedCurrencyIsQuote]);

  return (
    <OrderFormSection
      id="order-form-size-section"
      gap={0.5}
      disabled={disabled}
    >
      <NumericInputIndexElevator
        isNuxTooltipVisible={shouldShowTooltip && isNuxTooltipVisible}
      >
        <NumericInputWithToggle
          onKeyDown={handleKeyDown}
          disabled={disabled}
          label={formatMessage(advancedCommonMessages.amount)}
          suffix={isSizeInQuote ? quoteSuffix : baseCurrencyId}
          value={isSizeInQuote ? total : amount}
          placeholder={
            isSizeInQuote ? quoteNumericPlaceholder : baseNumericPlaceholder
          }
          error={error}
          onChange={handleAmountChange}
          data-testid="amount-input"
          ariaLabel={formatMessage(advancedCommonMessages.amount)}
          selected={derivedSelectedCurrency}
          onToggle={handleToggleChange}
          autoFocus={type === 'market'}
          disableVerticalPadding
          ref={amountInputRef}
        />
      </NumericInputIndexElevator>
      {shouldShowTooltip && (
        <NUXTooltip
          tooltipTitleText={formatMessage(messages.orderFormNewLookTitle)}
          tooltipBodyText={formatMessage(messages.orderFormNewLookBody)}
          visible={isNuxTooltipVisible}
          align="left"
          position="bottom"
          showArrow
        />
      )}

      {shouldShowTooltip && isNuxTooltipVisible && (
        <Backdrop onClick={handleHideTooltip} />
      )}

      {isSizeInQuote && (
        <HStack justifyContent="flex-end">
          <TextLabel2
            as="p"
            noWrap
            color="foregroundMuted"
            transform="uppercase"
          >
            {`≈ ${amount ? amount : 0} ${baseCurrencyId}`}
          </TextLabel2>
        </HStack>
      )}

      <AmountShortcuts
        queryRef={query}
        disabled={disabled}
        isSizeInQuote={isSizeInQuote}
        onChange={handleAmountQuickSelectClick}
        orderSide={side}
        orderType={
          type === 'market'
            ? 'MARKET'
            : type === 'stop_limit'
            ? 'STOP_LIMIT'
            : 'LIMIT'
        }
        paymentMethod={paymentMethod}
        limitPrice={limitPrice}
        productId={productId}
        quoteCurrencyId={quoteCurrencyId}
        basePrecision={basePrecision}
        quotePrecision={quotePrecision}
        aliasTo={aliasTo}
        baseAvailableToTradeBalance={baseBalance}
        quoteAvailableToTradeBalance={quoteBalance}
        selectedPortfolioUuid={selectedPortfolioUuid}
      />
    </OrderFormSection>
  );
}

const NumericInputIndexElevator = styled.span<{
  isNuxTooltipVisible?: boolean;
}>`
  z-index: ${p =>
    p.isNuxTooltipVisible ? theme.zIndex.top : theme.zIndex.elevated};
`;

