import LimitPreviewContent from './LimitPreviewContent';
import MarketPreviewContent from './MarketPreviewContent';
import StopLimitPreviewContent from './StopLimitPreviewContent';

interface SpotOrderPreviewProps {
  currentProduct: CoinbasePublicApiAuthedRetailBrokerageApiProduct;
  queryRef: SpotOrderPreviewFragment$key;
  orderPreview: CoinbasePublicApiAuthedRetailBrokerageApiOrderPreviewResponse;
  setShowOrderPreview: (showOrderPreview: boolean) => void;
  tpslForm: ReturnType<typeof useTPSLOrderForm>;
}

function SpotOrderPreview({
  currentProduct,
  orderPreview,
  setShowOrderPreview,
  tpslForm,
  queryRef,
}: SpotOrderPreviewProps) {
  const query = useFragment(
    graphql`
      fragment SpotOrderPreviewFragment on Query {
        ...MarketPreviewContentFragment
        ...LimitPreviewContentFragment
        ...StopLimitPreviewContentFragment
      }
    `,
    queryRef,
  );

  const logSpotOrderPreviewClick = useLogSpotPreviewOrderClick(
    CoinbasePublicApiAuthedRetailBrokerageApiProductType.SPOT,
  );
  const spectrum = useSpectrum();
  const dark = spectrum === 'dark';
  const { formatMessage } = useIntl();
  const { type, side } = useOrderFormContext();
  const { orderTotal, commissionTotal } = orderPreview;

  useEffect(() => {
    logSpotOrderPreviewClick({
      orderType: type,
      orderSide: side,
      feeUsd: parseFloat(commissionTotal),
      totalUsd: parseFloat(orderTotal),
    });
  }, []);

  const previewContent = {
    limit: <LimitPreviewContent orderPreview={orderPreview} queryRef={query} />,
    market: (
      <MarketPreviewContent orderPreview={orderPreview} queryRef={query} />
    ),
    stop_limit: (
      <StopLimitPreviewContent orderPreview={orderPreview} queryRef={query} />
    ),
    bracket: (
      <BracketPreviewContent
        currentProduct={currentProduct}
        tpslForm={tpslForm}
      />
    ),
  }[type];

  const handleKeyDown = useCallback(
    (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        setShowOrderPreview(false);
      }
    },
    [setShowOrderPreview],
  );

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);

  const handleOnClick = useCallback(
    () => setShowOrderPreview(false),
    [setShowOrderPreview],
  );

  return (
    <AdvancedBoundary
      name="advanced-component-spot-order-preview"
      owner="advanced-spot"
    >
      <FormContainer showOverlay={true} isDark={dark}>
        <Overlay show={true} onClick={handleOnClick} />
        <VStack
          testID="SpotOrderPreview"
          spacingHorizontal={2}
          spacingTop={2}
          spacingBottom={2}
          spacerGap={2}
          height="100%"
          id="spot-order-preview-container"
        >
          <HStack
            justifyContent="center"
            alignItems="center"
            position="relative"
          >
            <HStack position="absolute" left="0">
              <IconButton
                onClick={handleOnClick}
                name="backArrow"
                variant="foregroundMuted"
                transparent
                data-testid="icon-button"
              />
            </HStack>
            <TextHeadline as="h1">
              {formatMessage(messages.orderPreview)}
            </TextHeadline>
          </HStack>
          {previewContent}
          <SubmitOrderButton
            disabled={type === 'bracket' && !tpslForm.lastPreviewResult}
            bracketForm={tpslForm}
            isPreview={true}
          />
          <Box width="100%" justifyContent="center">
            <OrderFormLegalDisclaimer spacingTop={0} />
          </Box>
        </VStack>
      </FormContainer>
    </AdvancedBoundary>
  );
}

