import TableRowGrid from './TableRow';

type Props = {
  testID?: string;
  order: CoinbasePublicApiAuthedRetailBrokerageApiOrder;
  onClick: (order: CoinbasePublicApiAuthedRetailBrokerageApiOrder) => void;
  portfolioName?: string;
  showPortfolioName?: boolean;
};

function OrderRow({
  testID,
  order,
  onClick,
  portfolioName,
  showPortfolioName = false,
}: Props) {
  const logOpenOrderRowContextMenu = useLogOpenOrderRowContextMenu();
  const [contextMenuCoords, setContextMenuCoords] = useState<{
    left: number;
    top: number;
  } | null>(null);

  const handleRightClick = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault();
      logOpenOrderRowContextMenu('right_click');
      setContextMenuCoords({ left: e.clientX, top: e.clientY });
    },
    [logOpenOrderRowContextMenu],
  );
  const handleOpenMoreOptions = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();
      logOpenOrderRowContextMenu('more_options_button');
      setContextMenuCoords({ left: e.clientX, top: e.clientY });
    },
    [logOpenOrderRowContextMenu],
  );
  const handleCloseContextMenu = useCallback(() => {
    logCloseOrderRowContextMenu();
    setContextMenuCoords(null);
  }, []);

  const generateFormattedOrder = useGenerateFormattedOrder();

  const currentProduct = useSilentGetProduct({ productId: order.productId });

  const handleClick = useCallback(() => {
    if (currentProduct) {
      onClick(order);
    }
  }, [currentProduct, onClick, order]);

  const {
    side,
    status,
    price,
    type,
    size,
    total,
    completionPercentage,
    createdTime,
    productName,
    // filledSize,
  } = generateFormattedOrder(order, currentProduct ?? null);

  const isOpenOrderStatus = useMemo(
    () => openOrderStatuses.includes(order.status),
    [order.status],
  );

  const [showContextMenuButton, setShowContextMenuButton] = useState(false);

  const handleMouseOver = useCallback(() => {
    if (currentProduct) {
      setShowContextMenuButton(true);
    }
  }, [currentProduct]);

  const handleMouseOut = useCallback(() => {
    if (showContextMenuButton) {
      setShowContextMenuButton(false);
    }
  }, [showContextMenuButton]);

  return (
    <>
      <OrderDetailTrigger
        onClick={handleClick}
        onContextMenu={handleRightClick}
        onMouseOver={handleMouseOver}
        onMouseOut={handleMouseOut}
        disabled={!currentProduct}
      >
        <TableRowGrid
          data-testid={testID}
          shouldDisplayPortfolio={showPortfolioName}
        >
          {/* Created Time */}
          <TableCell>
            <TextLabel2 as="span" color="foregroundMuted">
              {createdTime}
            </TextLabel2>
          </TableCell>
          {
            /* Portfolio Name */
            showPortfolioName && (
              <TableCell>
                <TextLabel2
                  as="span"
                  color="foregroundMuted"
                  overflow="truncate"
                >
                  {portfolioName}
                </TextLabel2>
              </TableCell>
            )
          }
          {/* ProductId */}
          <TableCell>
            <TextLabel2 as="span" color="foreground">
              {productName}
            </TextLabel2>
          </TableCell>

          {/* Order Type */}
          <TableCell>
            <TextLabel2 as="span" color="foreground">
              {type}
            </TextLabel2>
          </TableCell>

          {/* Order Side (buy/sell) */}
          <TableCell>
            <TextLabel2 as="span" transform="uppercase">
              {side}
            </TextLabel2>
          </TableCell>

          {/* Order limit price */}
          <TableCell>
            <PriceCell order={order} price={price} product={currentProduct} />
          </TableCell>

          {/* order size */}
          <TableCell>
            <TextLabel2 as="span" color="foreground">
              {size}
            </TextLabel2>
          </TableCell>

          {/* order completion percentage */}
          <TableCell>
            <TextLabel2 as="span" color="foregroundMuted">
              {completionPercentage}
            </TextLabel2>
          </TableCell>

          {/* order total (trade proceeds) */}
          <TableCell>
            <TextLabel2 as="span" color="foreground">
              {total}
            </TextLabel2>
          </TableCell>

          {/* order status (open/closed/filled/failed/cancelled/pending) */}
          <TableCell justifyContent="flex-end">
            <TextLabel2
              color={isOpenOrderStatus ? 'positive' : 'foregroundMuted'}
              as="span"
            >
              {status}
            </TextLabel2>
          </TableCell>

          {/* actions */}
          <TableCell justifyContent="flex-end">
            <StyledSpan>
              <IconButton
                name="more"
                compact
                onPress={handleOpenMoreOptions}
                variant="foregroundMuted"
                transparent
              />
            </StyledSpan>
          </TableCell>
        </TableRowGrid>
      </OrderDetailTrigger>
      {contextMenuCoords && (
        <OrderRowContextMenu
          coordinates={contextMenuCoords}
          order={order}
          onShowDetailsModal={onClick}
          onClose={handleCloseContextMenu}
        />
      )}
    </>
  );
}

