type Props = {
  coordinates: { left: number; top: number };
  order: CoinbasePublicApiAuthedRetailBrokerageApiOrder;
  onClose: () => void;
  onShowDetailsModal: (
    order: CoinbasePublicApiAuthedRetailBrokerageApiOrder,
  ) => void;
};

function OrderRowContextMenu({
  coordinates,
  order,
  onShowDetailsModal,
  onClose,
}: Props) {
  const ref = useRef<HTMLDivElement>(null);
  const { formatMessage } = useIntl();
  const { showModal } = useModal();
  const cancelOrders = useCancelOrders();
  const updateBalances = useAccountsFetcher();
  const notifyAdvancedError = useNotifyAdvancedError();

  const handleViewOrderDetails = useCallback(() => {
    logOrderRowContextMenuViewOrderDetails();
    onShowDetailsModal(order);
    onClose();
  }, [onShowDetailsModal, order, onClose]);

  const handleCancelOrder = useCallback(async () => {
    logOrderRowContextMenuCancelOrder();
    try {
      await cancelOrders({ orderIds: [order.orderId] });
      updateBalances();
    } catch (e) {
      notifyAdvancedError(getErrorInstance(e), {
        orderId: order.orderId,
        context: 'advanced-component-orders-row',
        owner: HIGH_LEVEL_OWNERSHIP_TAG,
        isNetworkError: true,
        isHandled: true,
      });
    } finally {
      onClose();
    }
  }, [
    cancelOrders,
    order.orderId,
    onClose,
    updateBalances,
    notifyAdvancedError,
  ]);

  const handleEditOrder = useCallback(() => {
    logOrderRowContextMenuEditOrder();
    showModal(
      <EditOrderModal
        orderId={order.orderId}
        entryPoint="order-row-context-menu"
      />,
    );
    onClose();
  }, [order.orderId, showModal, onClose]);

  useOrderRowContextMenuVisibilityControls(ref, onClose);

  return (
    <ModalWrapper
      visible
      hideOverlay
      id="order-row-context-menu-modal-wrapper"
      onOverlayPress={onClose}
    >
      <ContextOnlyThemeProvider scale="large">
        <StyledBox
          opacity={1}
          background="background"
          ref={ref}
          flexDirection="column"
          position="fixed"
          borderRadius="roundedLarge"
          bordered
          style={coordinates}
          zIndex={zIndex.overlays.popoverMenu}
          id="order-row-context-menu"
          overflow="hidden"
        >
          <Pressable
            as="button"
            background="backgroundAlternate"
            onPress={handleViewOrderDetails}
          >
            <ListCell
              description={formatMessage(messages.viewDetails)}
              compact
            />
          </Pressable>
          <Pressable
            as="button"
            background="backgroundAlternate"
            onPress={handleEditOrder}
            disabled={!isOrderEditModalViewable(order)}
          >
            <ListCell description={formatMessage(messages.edit)} compact />
          </Pressable>
          <Pressable
            as="button"
            background="backgroundAlternate"
            onPress={handleCancelOrder}
            disabled={
              order.status !==
              CoinbasePublicApiAuthedRetailBrokerageApiOrderExecutionStatus.OPEN
            }
          >
            <ListCell description={formatMessage(messages.cancel)} compact />
          </Pressable>
        </StyledBox>
      </ContextOnlyThemeProvider>
    </ModalWrapper>
  );
}

