type ItemData = {
  positions: FuturesPosition[] | PerpetualFuturesPositionTableType[];
  onSelect: (
    order: FuturesPosition | PerpetualFuturesPositionTableType,
  ) => void;
  isPositionPerpetual: boolean;
};

type ListItemProps = {
  data: ItemData;
  index: number;
  style: React.CSSProperties;
};

type TPSLOrder = {
  limitPrice: number;
  stopPrice: number;
};

export type PerpetualFuturesPositionTableType = {
  // account uuid or asset uuid
  key: string;
  // asset display symbol or account code
  assetSymbol: string;
  productId: string;
  displayName: string;
  // number of contracts
  amount?: number;
  side?: string;
  sideColor: GainLossColor;
  value?: string;
  avgEntry?: string;
  // leverage
  leverage: number | null;
  initialMargin?: string;
  maintenanceMargin?: string;
  marketPrice?: string;
  type: PortfolioMarginType | null;
  liquidationPrice?: string;
  unrealizedNumeric?: number; // used for sorting
  unrealizedColor: GainLossColor;
  aggregatedNumeric?: number; // used for sorting
  aggregatedColor: GainLossColor;
  openTpslOrders?: TPSLOrder[];
};

const ListItem: FC<ListItemProps> = memo(function ListItem({
  data,
  index,
  style,
}: ListItemProps) {
  const { positions, onSelect, isPositionPerpetual } = data;
  const position = positions[index];

  const onClick = useCallback(() => {
    advancedTradeSharedEvent({
      eventName: 'positions_details_modal',
      optionalEventParameters: {
        productType: isPositionPerpetual ? 'perpetual_future' : 'future',
      },
    });
    onSelect(position);
  }, [isPositionPerpetual, onSelect, position]);

  const onClickPerps = useCallback(() => {
    advancedTradeSharedEvent({
      eventName: 'positions_row_click',
    });
    onSelect(position);
  }, [onSelect, position]);

  if (isPositionPerpetual && 'sideColor' in position) {
    return (
      <div style={style} onClick={onClickPerps}>
        <PerpetualPositionsRow position={position} />
      </div>
    );
  } else if (!isPositionPerpetual && 'avgEntryPrice' in position) {
    return (
      <div onClick={onClick} style={style}>
        <PositionsRow
          testID="positions-table-content-position-row"
          position={position}
        />
      </div>
    );
  }
  return null;
},
areEqual);

const getItemKey = (index: number, data: ItemData) =>
  data.positions[index].productId;

type Props = {
  skipPerpsTradingQuery: boolean;
  productId: string;
  selectedProduct?: string;
  onSelect: (
    position: FuturesPosition | PerpetualFuturesPositionTableType,
  ) => void;
  testID?: string;
};
// desktop only order table content
function PositionsTableContent({
  skipPerpsTradingQuery,
  productId,
  selectedProduct = 'ALL',
  onSelect,
  testID,
}: Props) {
  const isPositionPerpetual =
    getContractExpiryType(productId) === ContractExpiryType.PERPETUAL;

  const query = useLazyLoadQuery<PositionsTableContentQuery>(
    graphql`
      query PositionsTableContentQuery($skipPerpsTrading: Boolean!) {
        ...usePerpetualFuturesPositionsFragment
        ...usePollFuturesPositionsFragment
      }
    `,
    {
      skipPerpsTrading: skipPerpsTradingQuery,
    },
  );

  // Always fetch all positions for Derivatives since there is no endpoint consumes assetType.
  const futuresPositions = usePollFuturesPositions(query);

  const futuresPositionsOrNull = useMemo(
    () =>
      futuresPositions
        ? getFilteredFuturesOrdersOrPositions({
            selectedProduct,
            futuresPositions,
          })
        : null,
    [futuresPositions, selectedProduct],
  );

  const { formatMessage } = useIntl();
  const perpItems = usePerpetualFuturesPositions(query, selectedProduct);

  const itemData = useMemo(
    () => ({
      positions: isPositionPerpetual
        ? perpItems
        : futuresPositionsOrNull?.filteredFuturesPositions ?? [],
      onSelect,
      isPositionPerpetual,
    }),
    [
      isPositionPerpetual,
      perpItems,
      futuresPositionsOrNull?.filteredFuturesPositions,
      onSelect,
    ],
  );

  const tableContent = useMemo(() => {
    if (
      (isPositionPerpetual && perpItems.length === 0) ||
      (!isPositionPerpetual &&
        futuresPositionsOrNull?.filteredFuturesPositions &&
        futuresPositionsOrNull.filteredFuturesPositions.length === 0)
    ) {
      return <NoOrders subtitle={formatMessage(messages.noPositions)} />;
    }

    // Null means BE error so throw to the error boundary
    if (!isPositionPerpetual && !futuresPositionsOrNull) {
      throw new Error('Backend returned null for futures positions');
    }

    return (
      <div style={{ flex: 1 }} data-testid="positions-table-container">
        <AutoSizer>
          {({ height, width }) => (
            <StyledList
              height={height}
              width={width}
              itemCount={
                isPositionPerpetual
                  ? perpItems.length
                  : futuresPositionsOrNull?.filteredFuturesPositions?.length ??
                    0
              }
              itemSize={TABLE_ROW_HEIGHT}
              itemData={itemData}
              itemKey={getItemKey}
            />
          )}
        </AutoSizer>
      </div>
    );
  }, [
    formatMessage,
    futuresPositionsOrNull,
    isPositionPerpetual,
    itemData,
    perpItems.length,
  ]);

  return (
    <>
      {isPositionPerpetual ? (
        <PerpetualPositionsTableHeader />
      ) : (
        <PositionsTableHeader testID={testID} />
      )}
      {isPositionPerpetual && !skipPerpsTradingQuery && (
        <PerpetualFuturesSubscription />
      )}
      {tableContent}
    </>
  );
}

const StyledList = styled((props: Omit<FixedSizeListProps, 'children'>) => (
  <List {...props}>{ListItem}</List>
))`
  /* firefox */
  scrollbar-width: none;
  /* chrome */
  ::-webkit-scrollbar {
    display: none;
  }
`;

export default memo(PositionsTableContent);

