type OrdersTrayProps = {
  queryRef: OrdersTrayFragment$key;
  productId: string;
  quoteCurrencyId: string;
  isDerivativesProduct: boolean;
  aliasTo?: string[];
  showPortfolioName?: boolean;
};

function OrdersTray({
  productId,
  quoteCurrencyId,
  isDerivativesProduct,
  aliasTo,
  queryRef,
  showPortfolioName,
}: OrdersTrayProps) {
  const { formatMessage } = useIntl();
  const history = useHistory();
  const { isTrayOpen, handleToggleIsTrayOpen, handleSetIsTrayOpen } =
    useOrdersTrayContext();

  const logOrderTrayTypeClickEvent = useLogOrderTrayTypeClickEvent();
  const logOrderTrayError = useLogAdvanceTradeErrorEvent();
  const { countryCode } = useUser();

  const contractExpiryType = getContractExpiryType(productId);
  const isPerpetual = contractExpiryType === ContractExpiryType.PERPETUAL;
  perfMarkOnce('advanced_trade_orders_table', { type: 'start' });
  perfMarkOnce('advanced_trade_orders_tray', { type: 'end' });
  const portfolioFilterKilled = useKillSwitch(
    'kill_portfolio_orders_filter_web',
  );

  const query = useFragment(
    graphql`
      fragment OrdersTrayFragment on Query {
        ...useIsPerpetualFuturesEligibleFragment
        ...OrdersTableFragment
        ...useShowFuturesOrdersFragment
        ...useShowFuturesPositionsFragment
        ...OrdersTrayPortfolioSelectorDropdownFragment
        viewer {
          isOnboardedPortfolio
        }
      }
    `,
    queryRef,
  );

  const showFuturesOrders = useShowFuturesOrders(query);
  const showFuturesPositions = useShowFuturesPositions(query);

  const usdcAliasProductId = generateUSDCProductIdForUSDMarket(productId);

  const hasUSDCAlias = useHasUSDCAlias({
    quoteCurrencyId: quoteCurrencyId || '',
    productId,
    aliasTo,
  });

  if (hasUSDCAlias && countryCode !== 'US') {
    productId = usdcAliasProductId;
  }

  const initialSelectedProductId = 'ALL';

  const [selectedProductId, setSelectedProductId] = useState(
    initialSelectedProductId,
  );

  const [selectedStatus, setSelectedStatus] = useState<SelectableStatus>('ALL');
  const [selectedPortfolio, setSelectedPortfolio] =
    useState<PortfolioFilter>('ALL');

  const [selectedTableType, setSelectedTableType] = useState<TrayTab>('orders');

  const selectedOrders = useSelectedOrders({
    productId,
    selectedProduct: 'ALL',
    selectedStatus: 'ALL',
    isDerivativesProduct,
    selectedPortfolio,
  });

  /**
   * These productIds are used to be listed in the product selector dropdown.
   */
  const productIdsAvailableToFilter = useMemo(() => {
    // Get all unique productIds from selectedOrders
    return Array.from(new Set(selectedOrders.map(order => order.productId)));
  }, [selectedOrders]);

  const viewAllLink = useMemo(() => {
    if (selectedTableType === 'positions') {
      advancedTradeSharedEvent({
        eventName: 'view_all_positions',
        optionalEventParameters: {
          from: 'orders_tray',
          productType: !isDerivativesProduct
            ? 'spot'
            : isPerpetual
            ? 'perpetual_future'
            : 'future',
        },
      });
      return '/advanced-portfolio?section=futures-positions';
    }
    advancedTradeSharedEvent({
      eventName: 'view_all_orders',
      optionalEventParameters: {
        from: 'orders_tray',
      },
    });
    return VIEW_ALL_ORDERS_URL;
  }, [isDerivativesProduct, isPerpetual, selectedTableType]);

  const { startAdvancedTradePerfMark } = useAdvancedTradePerfMarkers();

  const { width } = useViewportDimensions();

  const handleRedirect = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (e: any) => {
      e.preventDefault();
      e.stopPropagation();
      history.push(viewAllLink);

      if (selectedTableType === 'positions') {
        startAdvancedTradePerfMark('navigate_to_positions_table', {
          page: 'portfolio',
        });
      }
    },
    [history, selectedTableType, startAdvancedTradePerfMark, viewAllLink],
  );

  const handleOnChange = useCallback(
    (type: string) => {
      setSelectedTableType(type as TrayTab);
      logOrderTrayTypeClickEvent(type as TrayTab);
    },
    [logOrderTrayTypeClickEvent],
  );

  const { isPerpetualFuturesEligible, skipPerpsTradingQuery } =
    useIsPerpetualFuturesEligible({
      queryRef: query,
    });

  const OrdersTrayHeader = useMemo(() => {
    if (
      (isDerivativesProduct && showFuturesOrders) ||
      (isPerpetual && isPerpetualFuturesEligible)
    ) {
      const tabs = [
        {
          id: 'orders',
          label: formatMessage(messages.orders),
          testID: 'orders-tray-orders-tab',
        },
      ];

      if (isPerpetual || (isDerivativesProduct && showFuturesPositions)) {
        tabs.push({
          id: 'positions',
          label: formatMessage(messages.positions),
          testID: 'orders-tray-positions-tab',
        });
      }

      return (
        <TabNavigation
          tabs={tabs}
          value={selectedTableType}
          variant="secondary"
          onChange={handleOnChange}
          zIndex={theme.zIndex.normal}
        />
      );
    }

    return <SpotOrdersTrayHeader />;
  }, [
    isDerivativesProduct,
    showFuturesOrders,
    isPerpetual,
    isPerpetualFuturesEligible,
    formatMessage,
    showFuturesPositions,
    selectedTableType,
    handleOnChange,
  ]);

  // For derivatives we hide the filters below 1313 to avoid overflowing UI
  const showFilters =
    !isDerivativesProduct || (isDerivativesProduct && width >= 1313);

  useEffect(() => {
    if (!showFilters && selectedStatus !== 'ALL') {
      setSelectedStatus('ALL');
    }

    if (!showFilters && selectedProductId !== initialSelectedProductId) {
      setSelectedProductId(initialSelectedProductId);
    }
  }, [showFilters, selectedStatus]);

  const OrdersTableActions = useMemo(
    () => (
      <HStack alignItems="center">
        <HStack spacerGap={1}>
          {/*
            fallback to null in desktop
          */}
          {selectedTableType === 'orders' && (
            <InstrumentedSuspense
              instrumentationId="CancelAllButton"
              fallback={null}
            >
              <CancelAllButton
                selectedProduct={selectedProductId}
                isDerivativesProduct={isDerivativesProduct}
                currentProductId={productId}
                contractExpiryType={
                  isDerivativesProduct ? contractExpiryType : undefined
                }
              >
                {formatMessage(messages.cancelAll)}
              </CancelAllButton>
            </InstrumentedSuspense>
          )}

          {isDerivativesProduct && (
            <Button
              to={viewAllLink}
              transparent
              noScaleOnPress
              compact
              onPress={handleRedirect}
            >
              <Box as="div">
                <TextHeadline color="primary" noWrap align="center" as="span">
                  {formatMessage(messages.viewAllOrders)}
                </TextHeadline>
              </Box>
            </Button>
          )}
          {!isDerivativesProduct && (
            <Pressable
              background="background"
              to={viewAllLink}
              onPress={handleRedirect}
              borderRadius="roundedLarge"
              as="button"
            >
              <Box as="div" spacing={1}>
                <TextHeadline color="primary" noWrap align="center" as="span">
                  {formatMessage(messages.viewAllOrders)}
                </TextHeadline>
              </Box>
            </Pressable>
          )}
          {/* Filters */}
          {showFilters && (
            <ProductSelectorDropdown
              productIdsAvailableToFilter={productIdsAvailableToFilter}
              disabled={!isTrayOpen}
              candidateProductId={productId}
              selectedProductId={selectedProductId}
              onChange={setSelectedProductId}
              isDerivativesProduct={isDerivativesProduct}
            />
          )}

          {selectedTableType === 'orders' && showFilters && (
            <StatusSelectorDropdown
              disabled={!isTrayOpen}
              selectedStatus={selectedStatus}
              onStatusChange={setSelectedStatus}
            />
          )}
          {selectedTableType === 'orders' &&
            showFilters &&
            query?.viewer?.isOnboardedPortfolio &&
            !portfolioFilterKilled && (
              <PortfolioSelectorDropdown
                disabled={!isTrayOpen}
                selectedPortfolio={selectedPortfolio}
                onPortfolioChange={setSelectedPortfolio}
                queryRef={query}
              />
            )}
          <IconButton
            compact
            name={isTrayOpen ? 'caretDown' : 'caretUp'}
            testID="orders-tray-toggle-btn"
            onPress={handleToggleIsTrayOpen}
          />
        </HStack>
      </HStack>
    ),
    [
      selectedTableType,
      selectedProductId,
      isDerivativesProduct,
      productId,
      contractExpiryType,
      formatMessage,
      viewAllLink,
      handleRedirect,
      showFilters,
      productIdsAvailableToFilter,
      isTrayOpen,
      selectedStatus,
      handleToggleIsTrayOpen,
      selectedPortfolio,
      setSelectedPortfolio,
      portfolioFilterKilled,
      query,
    ],
  );

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleOnCatch = (error: Error) => {
    handleSetIsTrayOpen();
    logOrderTrayError({ error: error.message, componentName: 'order_tray' });
  };

  const renderErrorFallback = useCallback(
    (props: ErrorBoundaryFallbackProps) => (
      <ErrorFallbackWithGracefulDegrade
        component="OrderHistoryTrayErrorFallback"
        gracefulDegradeMessages={errMessages}
        baseErrorFallback={ErrorView}
        apiErrorFallback={OrderHistoryTrayErrorBanner}
        height={ORDERS_TRAY_HEIGHT}
        {...props}
      />
    ),
    [],
  );

  return (
    <OrdersTrayLayout
      open={isTrayOpen}
      headerContent={OrdersTrayHeader}
      actionsContent={OrdersTableActions}
      tableContent={
        <AdvancedBoundaryWithSuspense
          owner="advanced"
          name="advanced-component-orders-tray"
          onCatch={handleOnCatch}
          suspenseFallback={
            <LoadingOrdersTableContent showPortfolioName={showPortfolioName} />
          }
          errorFallback={renderErrorFallback}
        >
          <OrdersTable
            queryRef={query}
            productId={productId}
            selectedProduct={selectedProductId}
            selectedStatus={selectedStatus}
            selectedPortfolio={selectedPortfolio}
            type={selectedTableType}
            isDerivativesProduct={isDerivativesProduct}
            skipPerpsTradingQuery={skipPerpsTradingQuery}
            quoteCurrencyId={quoteCurrencyId}
            aliasTo={aliasTo}
            showPortfolioName={showPortfolioName}
          />
        </AdvancedBoundaryWithSuspense>
      }
    />
  );
}

function OrdersTrayWithProviders(props: OrdersTrayProps) {
  const renderFallback = useCallback(
    (props: ErrorBoundaryFallbackProps) => (
      <ErrorFallbackWithGracefulDegrade
        component="OrderHistoryTrayWithProvidersErrorFallback"
        gracefulDegradeMessages={errMessages}
        baseErrorFallback={ErrorView}
        apiErrorFallback={OrderHistoryTrayErrorBanner}
        height={ORDERS_TRAY_HEIGHT}
        {...props}
      />
    ),
    [],
  );

  return (
    <AdvancedBoundary
      owner="advanced"
      name="advanced-component-orders-tray"
      fallback={renderFallback}
    >
      <OrdersTrayProvider>
        <OrdersTray {...props} />
      </OrdersTrayProvider>
    </AdvancedBoundary>
  );
}

export default memo(OrdersTrayWithProviders);

