import React, { useMemo, useEffect, memo, useCallback } from 'react';
import { BorderRadius } from '@cbhq/cds-web';

import Backdrop from 'components/Layout/components/Backdrop';

import SpotlightCard from './SpotlightCard';
import {
  SpotlightAlign,
  SpotlightDismissType,
  SpotlightName,
  SpotlightPositon,
} from './types';
import { useSpotlightContext } from './useSpotlightContext';

export type SpotlightProps = {
  children: React.ReactElement;
  /**
   * The step number of the spotlight flow. This is used to determine which step to show.
   * The step number starts from 1.
   */
  stepNumber: Exclude<number, 0>;
  /**
   * The name of the spotlight flow. This is used to identify the spotlight flow.
   */
  name: SpotlightName;
  /**
   * The position of the spotlight relative to the element that is being spotlighted.
   */
  position?: SpotlightPositon;
  /**
   * The alignment of the spotlight relative to the element that is being spotlighted.
   */
  align?: SpotlightAlign;
  disableChildPointerEvents?: boolean;
  disableOverlay?: boolean;
  isStepEnabled?: boolean;
  /**
   * Hides step number in the spotlight card. Can be useful when there is only one step and you don't want to show "1 of 1".
   */
  hideStepNumber?: boolean;

  /**
   * Dismiss the spotlight when the spotlighted element is clicked.
   * In some cases we may want the user to explicitly click the spotlight card to dismiss it.
   */
  dismissOnClick?: boolean;

  /**
   * Whether to render the focus ring around the spotlighted element.
   */
  renderFocusRing?: boolean;

  focusRingRadius?: BorderRadius;
};

export function Spotlight({
  children,
  stepNumber,
  name,
  position = 'left',
  align = 'start',
  disableChildPointerEvents,
  disableOverlay,
  isStepEnabled = true,
  hideStepNumber = false,
  dismissOnClick = true,
  renderFocusRing,
  focusRingRadius,
}: SpotlightProps) {
  const {
    goToNextStep,
    getSteps,
    getCurrentStep,
    onDismiss,
    getConfig,
    addInitializedFlow,
    removeInitializedFlow,
    ready,
    currentActiveSpotlightName,
    forcedSpotlight,
  } = useSpotlightContext();

  useEffect(() => {
    // When Spotlight is first initialized, add the flow to the list of initialized flows, so that we only show Spotlight Flow if it is rendered in the DOM.
    addInitializedFlow(name);

    return () => {
      // When Spotlight is unmounted, remove the flow from the list of initialized flows.
      removeInitializedFlow(name);
    };
  }, [name]);

  const handleGoToNextStep = useCallback(() => {
    goToNextStep(name);
  }, [goToNextStep, name]);

  const steps = useMemo(() => {
    return getSteps(name);
  }, [getSteps, name]);

  const currentStep = useMemo(() => {
    return getCurrentStep(name);
  }, [getCurrentStep, name]);

  const isEnabled = useMemo(() => {
    return getConfig(name)?.isEnabled;
  }, [getConfig, name]);

  const isLastStep = stepNumber === steps?.length;

  const handleDismiss = useCallback(
    (dismissType: SpotlightDismissType) => {
      onDismiss?.(name, dismissType);
    },
    [name, onDismiss],
  );

  const handleBackdropClick = useCallback(() => {
    handleDismiss('backdrop-click');
  }, [handleDismiss]);

  const handleSpotlightedElementClick = useCallback(() => {
    if (forcedSpotlight || (isLastStep && dismissOnClick)) {
      return handleDismiss('spotlighted-element-click');
    }

    goToNextStep(name);
  }, [
    dismissOnClick,
    forcedSpotlight,
    goToNextStep,
    handleDismiss,
    isLastStep,
    name,
  ]);

  /**
   * If the step is not the current step, we don't want to render the Spotlight
   */
  if (
    !isEnabled ||
    !isStepEnabled ||
    currentActiveSpotlightName !== name ||
    steps[stepNumber - 1] !== currentStep ||
    !ready
  ) {
    if (forcedSpotlight?.name !== name) {
      return children;
    }
  }

  const childProps = disableChildPointerEvents
    ? { style: { pointerEvents: 'none' } as const }
    : {};

  let isOverlayDisabled = disableOverlay;

  /**
   * Override properties when the spotlight is forced and override props are provided
   */
  if (forcedSpotlight && forcedSpotlight.overrideProps) {
    isOverlayDisabled =
      forcedSpotlight.overrideProps.disableOverlay ?? isOverlayDisabled;
  }

  return (
    <>
      <SpotlightCard
        totalSteps={steps.length}
        currentStepNumber={stepNumber}
        currentStep={currentStep}
        onDismiss={handleDismiss}
        onNext={handleGoToNextStep}
        isLastStep={isLastStep}
        position={position}
        align={align}
        disableOverlay={isOverlayDisabled}
        hideStepNumber={hideStepNumber}
        renderFocusRing={renderFocusRing}
        focusRingRadius={focusRingRadius}
      >
        <div onClick={handleSpotlightedElementClick}>
          <div {...childProps} data-testid="spotlight-children">
            {children}
          </div>
        </div>
      </SpotlightCard>

      <Backdrop
        enabled={!isOverlayDisabled}
        onClick={handleBackdropClick}
        position="fixed"
      />
    </>
  );
}

export default memo(Spotlight);

