import { memo, useCallback } from 'react';
import { useIntl } from 'react-intl';

import { useModal } from '@cbhq/cds-common/overlays/useModal';
import { Switch } from '@cbhq/cds-web/controls/Switch';
import { useToast } from '@cbhq/cds-web/overlays/useToast';

import { useEditCloudApiKey } from 'views/ApiKeysManagement/hooks/useEditCloudApiKey';
import { logDisableRetailKey } from 'views/ApiKeysManagement/utils/analytics';

import messages from '../../../messages';
import { LazyCloudDisableModal } from '../../CloudDisableModal';

type ToggleActiveCellProps = {
  isEnabled: boolean;
  recordId: string;
  keyUuid: string;
  scopes: string[];
  portfolioUuid: string;
};

function ToggleActiveCell({
  isEnabled,
  keyUuid,
  recordId,
  scopes,
  portfolioUuid,
}: ToggleActiveCellProps) {
  const { editCloudApiKey, isLoading } = useEditCloudApiKey();
  const toast = useToast();
  const { formatMessage } = useIntl();
  const { openModal, closeModal } = useModal();

  const handleEditSuccess = useCallback(() => {
    toast.show(formatMessage(messages.editModalSuccess));
  }, [formatMessage, toast]);

  const handleEditError = useCallback(() => {
    logDisableRetailKey();
    toast.show(formatMessage(messages.editModalError));
  }, [toast, formatMessage]);

  const requiresTwoFactor =
    scopes.includes('trade') || scopes.includes('transfer');

  const handleToggle = useCallback(() => {
    if (isEnabled || !requiresTwoFactor) {
      editCloudApiKey({
        isEnabled: !isEnabled,
        onSuccess: handleEditSuccess,
        onError: handleEditError,
        portfolioUuid,
        recordId,
        keyUuid,
      });
    } else {
      openModal(
        <LazyCloudDisableModal
          keyUuid={keyUuid}
          onClose={closeModal}
          visible
          recordId={recordId}
          portfolioUuid={portfolioUuid}
        />,
      );
    }
  }, [
    isEnabled,
    editCloudApiKey,
    handleEditSuccess,
    handleEditError,
    keyUuid,
    recordId,
    closeModal,
    openModal,
    portfolioUuid,
    requiresTwoFactor,
  ]);

  return (
    <Switch
      testID={`cloud-body-cell-toggleActive-${recordId}`}
      checked={isEnabled}
      onClick={handleToggle}
      disabled={isLoading}
    />
  );
}

export default memo(ToggleActiveCell);

import { useCallback, useEffect, memo, ChangeEvent } from 'react';
import {
  useFormContext,
  type FieldValues,
  useController,
} from 'react-hook-form';
import { useIntl } from 'react-intl';

import { Button } from '@cbhq/cds-web/buttons/Button';
import { TextInput } from '@cbhq/cds-web/controls/TextInput';
import { useCheckboxGroupState } from '@cbhq/cds-web/hooks/useCheckboxGroupState';
import { VStack } from '@cbhq/cds-web/layout/VStack';
import { ModalBody } from '@cbhq/cds-web/overlays/Modal/ModalBody';
import { ModalFooter } from '@cbhq/cds-web/overlays/Modal/ModalFooter';
import { ModalHeader } from '@cbhq/cds-web/overlays/Modal/ModalHeader';
import { useToast } from '@cbhq/cds-web/overlays/useToast';
import { graphql, useFragment } from '@cbhq/data-layer';

import useStepper from 'components/Stepper/hooks/useStepper';
import {
  CreateCloudKeyResponse,
  useCreateCloudApiKey,
} from 'views/ApiKeysManagement/hooks/useCreateCloudApiKey';
import { logCreateRetailKey } from 'views/ApiKeysManagement/utils/analytics';
import { validateAllowedIps } from 'views/ApiKeysManagement/utils/utils';

import messages from '../../messages';
import AdvancedTradeSettingsFormSection from '../Form/AdvancedTradeSettingsFormSection';
import { CreateStepFragment$key } from './__generated__/CreateStepFragment.graphql';
import { DEFAULT_PERMISSION } from './constants';
import stepper from './stepper';

const TRADE_CHECKBOX_OPTIONS = {
  view: 'View (read-only)',
  trade: 'Trade (execute trades on your behalf)',
  transfer: 'Transfer (initiate transfer of funds)',
};

export type CreateStepProps = {
  onClose: () => void;
  queryRef: CreateStepFragment$key;
};

function CreateStep({ onClose, queryRef }: CreateStepProps) {
  const { formatMessage } = useIntl();
  const { goToStep } = useStepper(stepper);
  const toast = useToast();

  const query = useFragment(
    graphql`
      fragment CreateStepFragment on Query {
        viewer {
          retailBrokerage {
            retailApiKeys {
              apiKeys {
                nickname
              }
            }
          }
        }
        ...AdvancedTradeSettingsFormSectionFragment
      }
    `,
    queryRef,
  );

  const { createCloudApiKey, isLoading } = useCreateCloudApiKey();

  const existingKeyNicknames =
    query?.viewer?.retailBrokerage?.retailApiKeys?.apiKeys ?? [];

  const [selectedScopes, { toggle: toggleCheckbox }] = useCheckboxGroupState(
    Object.keys(TRADE_CHECKBOX_OPTIONS),
    [DEFAULT_PERMISSION],
  );

  const { handleSubmit, formState, control, setValue } = useFormContext();

  const { field: portfolioUuid } = useController({
    control,
    name: 'portfolioUuid',
  });

  const { field: allowedIps } = useController({
    control,
    name: 'allowedIps',
    rules: {
      validate: {
        restrictChars: value => {
          if (!value) return true;

          return validateAllowedIps(value) || formatMessage(messages.invalidIp);
        },
      },
    },
  });

  const { field: scopes } = useController({
    control,
    name: 'scopes',
  });

  const { field: nickname } = useController({
    control,
    name: 'nickname',
    rules: {
      required: formatMessage(messages.requiredField),
      min: 2,
      max: 50,
      validate: {
        noSpaces: value =>
          !existingKeyNicknames.find(key => key?.nickname === value) ||
          formatMessage(messages.duplicateNameError),
        restrictChars: value => {
          const regex = /^[A-Za-z][A-Za-z0-9\-_]*$/;
          return (
            regex.test(value) || formatMessage(messages.invalidCharacterError)
          );
        },
      },
    },
  });

  const { isSubmitting, errors } = formState;

  const requiresTwoFactor =
    selectedScopes.has('transfer') || selectedScopes.has('trade');

  useEffect(() => {
    scopes.onChange(Array.from(selectedScopes));
  }, [selectedScopes]);

  const handleCreateKeySuccess = useCallback(
    (response: CreateCloudKeyResponse) => {
      setValue('uuid', response?.apiKey?.uuid);
      setValue('privateKey', response?.apiKey?.privateKey);

      logCreateRetailKey({
        scopes: response?.apiKey?.scopes,
        allowedIpsEdited: !!response?.apiKey?.allowedIps,
      });

      goToStep('success');
    },
    [goToStep, setValue],
  );

  const handleCreateKeyError = useCallback(() => {
    toast.show(
      formatMessage(messages.createModalError, { variant: 'negative' }),
    );
  }, [toast, formatMessage]);

  const onSubmit = useCallback(
    (data: FieldValues) => {
      if (requiresTwoFactor && data) {
        return goToStep('twoFactorDetails');
      }

      createCloudApiKey({
        allowedIps: data?.allowedIps,
        nickname: data?.nickname,
        scopes: data?.scopes,
        portfolioId: data?.portfolioUuid,
        onSuccess: handleCreateKeySuccess,
        onError: handleCreateKeyError,
      });
    },
    [
      goToStep,
      requiresTwoFactor,
      handleCreateKeySuccess,
      createCloudApiKey,
      handleCreateKeyError,
    ],
  );

  const handleNicknameChange = useCallback(
    (e: ChangeEvent<HTMLInputElement>) => {
      nickname.onChange(e.target.value.replace(/ /g, ''));
    },
    [nickname],
  );

  const handleAllowedIpsChange = useCallback(
    (e: ChangeEvent<HTMLInputElement>) => {
      allowedIps.onChange(e.target.value.replace(/ /g, ''));
    },
    [allowedIps],
  );

  const AdvancedTradeSettingsProps = {
    allowedIpsProps: {
      onChange: handleAllowedIpsChange,
      value: allowedIps.value,
    },
    scopesProps: {
      selectedValues: selectedScopes,
      onChange: toggleCheckbox,
    },
    portfolioUuidProps: {
      value: portfolioUuid.value,
      onChange: portfolioUuid.onChange,
    },
  };

  return (
    <>
      <ModalHeader
        title={formatMessage(messages.cloudCreateModalTitle)}
        closeAccessibilityLabel="Close"
      />
      <ModalBody>
        <VStack gap={2}>
          <TextInput
            testID="create-step-name-input"
            label={formatMessage(messages.cloudCreateModalNameLabel)}
            placeholder={formatMessage(
              messages.cloudCreateModalNamePlaceholder,
            )}
            value={nickname.value}
            onChange={handleNicknameChange}
            helperText={(errors?.nickname?.message as string) ?? ''}
            variant={errors.nickname ? 'negative' : undefined}
          />
          <AdvancedTradeSettingsFormSection
            {...AdvancedTradeSettingsProps}
            errors={errors}
            queryRef={query}
          />
        </VStack>
      </ModalBody>
      <ModalFooter
        primaryAction={
          <Button
            loading={isLoading}
            disabled={isSubmitting || !!errors?.nickname || isLoading}
            onPress={handleSubmit(onSubmit)}
          >
            {formatMessage(messages.cloudCreateModalCreateCta)}
          </Button>
        }
        secondaryAction={
          <Button variant="secondary" onPress={onClose}>
            {formatMessage(messages.cancelCta)}
          </Button>
        }
      />
    </>
  );
}

export default memo(CreateStep);

import { useCallback, memo, useEffect, useMemo, ChangeEvent } from 'react';
import {
  useController,
  useFormContext,
  type FieldValues,
} from 'react-hook-form';
import { useIntl } from 'react-intl';

import { Button } from '@cbhq/cds-web/buttons/Button';
import { TextInput } from '@cbhq/cds-web/controls';
import { useCheckboxGroupState } from '@cbhq/cds-web/hooks/useCheckboxGroupState';
import { VStack } from '@cbhq/cds-web/layout/VStack';
import { ModalHeader, ModalBody, ModalFooter } from '@cbhq/cds-web/overlays';
import { useToast } from '@cbhq/cds-web/overlays/useToast';
import { graphql, useFragment } from '@cbhq/data-layer';

import useStepper from 'components/Stepper/hooks/useStepper';
import { removeFalsyValues } from 'utils/ArrayUtils';
import {
  useEditCloudApiKey,
  type EditCloudApiKeyResponse,
} from 'views/ApiKeysManagement/hooks/useEditCloudApiKey';
import { logUpdateRetailKey } from 'views/ApiKeysManagement/utils/analytics';
import { validateAllowedIps } from 'views/ApiKeysManagement/utils/utils';

import messages from '../../messages';
import AdvancedTradeSettingsFormSection from '../Form/AdvancedTradeSettingsFormSection';
import { EditStepFragment$key } from './__generated__/EditStepFragment.graphql';
import stepper from './stepper';

const TRADE_CHECKBOX_OPTIONS = {
  view: 'View (read-only)',
  trade: 'Trade (execute trades on your behalf)',
  transfer: 'Transfer (initiate transfer of funds)',
};

export type EditStepProps = {
  onClose: () => void;
  queryRef: EditStepFragment$key;
  recordId: string;
  uuid: string;
};

function EditStep({ onClose, queryRef, uuid, recordId }: EditStepProps) {
  const query = useFragment(
    graphql`
      fragment EditStepFragment on Query {
        viewer {
          retailBrokerage {
            retailApiKeys {
              apiKeys {
                id
                nickname
                scopes
              }
            }
          }
        }
        ...AdvancedTradeSettingsFormSectionFragment
      }
    `,
    queryRef,
  );

  const { formatMessage } = useIntl();
  const { goToStep } = useStepper(stepper);
  const toast = useToast();

  const { editCloudApiKey, isLoading } = useEditCloudApiKey();
  const { handleSubmit, formState, control } = useFormContext();

  const { errors, isSubmitting } = formState;

  const handleEditKeyError = useCallback(() => {
    toast.show(formatMessage(messages.editModalError), { variant: 'negative' });
    onClose();
  }, [toast, formatMessage, onClose]);

  const existingKeyNicknames = removeFalsyValues(
    query?.viewer?.retailBrokerage?.retailApiKeys?.apiKeys ?? [],
  ).map(key => key?.nickname);

  const currentApiKey = (
    query?.viewer?.retailBrokerage?.retailApiKeys?.apiKeys ?? []
  ).find(apiKey => {
    return apiKey && apiKey?.id === recordId;
  });

  const { field: allowedIps } = useController({
    control,
    name: 'allowedIps',
    rules: {
      validate: {
        restrictChars: value => {
          if (!value) return true;
          return validateAllowedIps(value) || formatMessage(messages.invalidIp);
        },
      },
    },
  });

  const { field: portfolioUuid } = useController({
    control,
    name: 'portfolioUuid',
  });

  const { field: scopes } = useController({
    control,
    name: 'scopes',
  });

  const { field: nickname } = useController({
    control,
    name: 'nickname',
    rules: {
      required: formatMessage(messages.requiredField),
      min: 2,
      max: 50,
      validate: {
        noDuplicateNames: value => {
          if (value !== currentApiKey?.nickname) {
            return (
              !existingKeyNicknames.find(nickname => nickname === value) ||
              formatMessage(messages.duplicateNameError)
            );
          }
        },
        restrictChars: value => {
          const regex = /^[A-Za-z][A-Za-z0-9\-_]*$/;
          return (
            regex.test(value) || formatMessage(messages.invalidCharacterError)
          );
        },
      },
    },
  });

  const [selectedScopes, { toggle: toggleCheckbox }] = useCheckboxGroupState(
    Object.keys(TRADE_CHECKBOX_OPTIONS),
    scopes.value,
  );

  useEffect(() => {
    scopes.onChange(Array.from(selectedScopes));
  }, [selectedScopes]);

  const handleNicknameChange = useCallback(
    (e: ChangeEvent<HTMLInputElement>) => {
      nickname.onChange(e.target.value.replace(/ /g, ''));
    },
    [nickname],
  );

  const handleAllowedIpsChange = useCallback(
    (e: ChangeEvent<HTMLInputElement>) => {
      allowedIps.onChange(e.target.value.replace(/ /g, ''));
    },
    [allowedIps],
  );

  const requiresTwoFactor = useMemo(() => {
    const currentScopeTwoFactorRequired =
      selectedScopes.has('transfer') || selectedScopes.has('trade');

    const previousScopes = currentApiKey?.scopes ?? [];
    const previousScopeTwoFactorRequired =
      previousScopes.includes('rat#trade') ||
      previousScopes.includes('rat#transfer');

    return currentScopeTwoFactorRequired || previousScopeTwoFactorRequired;
  }, [selectedScopes, currentApiKey?.scopes]);

  const handleEditKeySuccess = useCallback(
    (response: EditCloudApiKeyResponse) => {
      toast.show(formatMessage(messages.editModalSuccess));
      logUpdateRetailKey({
        scopes: response?.apiKey?.scopes,
        allowedIpsEdited: !!response?.apiKey?.allowedIps,
      });
      onClose();
    },
    [toast, formatMessage, onClose],
  );

  const onSubmit = useCallback(
    (data: FieldValues) => {
      if (requiresTwoFactor && data) {
        return goToStep('twoFactorDetails');
      }

      editCloudApiKey({
        allowedIps: data?.allowedIps,
        nickname: data?.nickname,
        scopes: data?.scopes,
        portfolioUuid: data?.portfolioUuid,
        onSuccess: handleEditKeySuccess,
        onError: handleEditKeyError,
        keyUuid: uuid,
        recordId,
      });
    },
    [
      goToStep,
      requiresTwoFactor,
      handleEditKeySuccess,
      editCloudApiKey,
      uuid,
      recordId,
      handleEditKeyError,
    ],
  );

  const AdvancedTradeSettingsProps = {
    allowedIpsProps: {
      onChange: handleAllowedIpsChange,
      value: allowedIps.value,
    },
    scopesProps: {
      selectedValues: selectedScopes,
      onChange: toggleCheckbox,
    },
    portfolioUuidProps: {
      value: portfolioUuid.value,
      onChange: portfolioUuid.onChange,
    },
  };

  return (
    <>
      <ModalHeader
        title={formatMessage(messages.editModalDetailsTitle)}
        closeAccessibilityLabel="Close"
      />
      <ModalBody>
        <VStack gap={2}>
          <TextInput
            testID="edit-step-name-input"
            label={formatMessage(messages.cloudCreateModalNameLabel)}
            placeholder={formatMessage(
              messages.cloudCreateModalNamePlaceholder,
            )}
            value={nickname.value}
            onChange={handleNicknameChange}
            helperText={(errors?.nickname?.message as string) ?? ''}
            variant={errors.nickname ? 'negative' : undefined}
          />
          <AdvancedTradeSettingsFormSection
            {...AdvancedTradeSettingsProps}
            errors={errors}
            queryRef={query}
          />
        </VStack>
      </ModalBody>
      <ModalFooter
        primaryAction={
          <Button
            disabled={isSubmitting || isLoading}
            onPress={handleSubmit(onSubmit)}
            loading={isLoading}
          >
            {formatMessage(messages.editModalSaveCta)}
          </Button>
        }
        secondaryAction={
          <Button
            onPress={onClose}
            variant="secondary"
            disabled={isSubmitting || isLoading}
          >
            {formatMessage(messages.cancelCta)}
          </Button>
        }
      />
    </>
  );
}

