import { computeIconColor } from 'views/AssetCategories/components/IconThemeProvider';

import { SMALL_ICON, MOBILE_ICON } from '../constants';
import { logEntryPointClickEvent } from '../eventing';
import { AssetCategoryCardFragment$key } from './__generated__/AssetCategoryCardFragment.graphql';

type Props = {
  assetCategoryRef: AssetCategoryCardFragment$key;
  index: number;
};

function AssetCategoriesCard({ assetCategoryRef, index }: Props) {
  const category = useFragment(
    graphql`
      fragment AssetCategoryCardFragment on AssetCategory {
        name
        slug
        iconKey
      }
    `,
    assetCategoryRef,
  );
  const history = useHistory();
  const isMobile = useScreenMatch('phone');
  const { iconColor, iconBgColor } = computeIconColor(index);
  const isDesktopGiant = useIsMatchingMediaQuery({
    query: `(min-width: 1440px)`,
    initialValue: isMobile,
  });
  const Text = isDesktopGiant ? TextHeadline : TextLabel1;
  const { name, slug, iconKey } = category;

  const handleOnPress = useCallback(() => {
    logEntryPointClickEvent({ type: slug });
    history.push(`/trade/asset-categories/${slug}`);
  }, [history, slug]);

  return (
    <Pressable
      background="background"
      onPress={handleOnPress}
      width="100%"
      borderRadius="rounded"
    >
      <HStack
        borderRadius="rounded"
        spacing={1}
        alignItems="center"
        background="backgroundAlternate"
        overflow="hidden"
      >
        <Box
          height={isMobile ? MOBILE_ICON : SMALL_ICON}
          width="100%"
          maxWidth={isMobile ? MOBILE_ICON : SMALL_ICON}
          minWidth={isMobile ? MOBILE_ICON : SMALL_ICON}
          background={iconBgColor}
          borderRadius="rounded"
          alignItems="center"
          justifyContent="center"
        >
          <Icon
            name={iconKey as IconProps['name']}
            size="m"
            color={iconColor}
          />
        </Box>
        <Text spacingStart={isMobile ? 1 : 2} as="span">
          <ClampedLines isLongWord={isLongSingleWord(name)}>
            {name}
          </ClampedLines>
        </Text>
      </HStack>
    </Pressable>
  );
}

function isLongSingleWord(word: string) {
  const words = word.trim().split(' ');
  if (words.length === 1) {
    return !words[0].includes('-');
  }

  return false;
}

const ClampedLines = styled.span<{ isLongWord: boolean }>`
  display: -webkit-box;
  -webkit-line-clamp: ${p => (p.isLongWord ? 1 : 2)};
  -webkit-box-orient: vertical;
  overflow: hidden;
  word-break: break-word;
`;

