              currency
              value
            }
            totalBalance {
              currency
              value
            }
            hasPerformanceAvailable
            percentOfPortfolio
            averageCost {
              currency
              value
            }
          }
          ... on AssetPerformanceUserNotFound {
            __typename
          }
        }
        assetPerformancesTimeRanges @skip(if: $skipAssetPerfTimeRanges) {
          __typename
          ... on AssetPerformanceTimeRanges {
            oneDayPerformance {
              gainLoss {
                value
                currency
              }
              hasPerformanceAvailable
            }
            allTimePerformance {
              gainLoss {
                value
                currency
              }
              totalBalance {
                currency
                value
              }
              hasPerformanceAvailable
              percentOfPortfolio
              averageCost {
                currency
                value
              }
              totalInvested {
                currency
                value
              }
            }
          }
