    return { dataIsAvailable: false };
  }, [
    assetPerformanceDeprecated,
    assetPerformancesTimeRanges,
    hasAssetPerfTimeRanges,
  ]);

  const showPerDayMetric = hasAssetPerfTimeRanges && hasPerDayPerfAvailable;

  const isStableCoin = useMemo(
