      return;
    }
  }, [onPressBalanceSummaryEntryPoint, showBalanceSummaryEntryPoint]);

  const onDesktopMetricHover = useCallback((metricKey: string) => {
    performanceClickEvent(metricKey);
    if (metricKey === 'past_day_returns') {
      triggerResearchEventOnUserAction('view_gain_loss_by_time_range');
    }
  }, []);

  const debouncedHoverInfoHandler = useDebouncedCallback(
    onDesktopMetricHover,
    1000,
  );
  const onMobileMetricClick = useCallback(
    (metricKey: string, collapsed: boolean) => {
      if (!collapsed) {
        performanceClickEvent(metricKey);
        if (metricKey === 'past_day_returns') {
          triggerResearchEventOnUserAction('view_gain_loss_by_time_range');
        }
      }
    },
    [],
  );

  if (gainLossIneligible) {
    return null;
  }

  const isPastOwnedAsset = Boolean(
    totalBalance && parseFloat(totalBalance.value) === 0,
  );
  //* format performance four metrics
  const avgCostVal = averageCost?.value
    ? formatAmount({
        amount: averageCost,
        isFiat: true,
        exponent: getPriceScale(parseFloat(averageCost.value)),
      })
    : VALUE_FALLBACK;

  const totalInvestedVal = totalInvested?.value
    ? formatAmount({ amount: totalInvested, isFiat: true })
    : VALUE_FALLBACK;

  const gainLossObj = gainLoss?.value
    ? formatGainLoss(gainLoss.value, gainLoss.currency)
    : {
        value: '',
        valueWithSign: VALUE_FALLBACK,
        variant: 'foreground' as GainLossColor,
      };

  const pastDayGainLossObj = pastDayReturn?.value
    ? formatGainLoss(pastDayReturn.value, pastDayReturn.currency)
    : {
        value: '',
        valueWithSign: VALUE_FALLBACK,
        variant: 'foreground' as GainLossColor,
      };

  const percentOfPortfolioVal = percentOfPortfolio
    ? percentOfPortfolio + '%'
    : PERCENT_FALLBACK;

  return (
    <>
      {spacingTop > 0 && <Spacer vertical={spacingTop} />}
      <ContentSection
        owner="asset"
        name="AssetPerformance"
        testID="asset-page-asset-performance"
        context="asset_performance"
      >
        <HStack
          justifyContent="space-between"
          spacingBottom={3}
          alignItems="center"
        >
          <HStack alignItems="center">
            <TextTitle3 as="div" spacingEnd={1}>
              {formatMessage(messages.title)}
            </TextTitle3>
            {!isMobile && (
              <Tooltip
                content={formatMessage(messages.vaultDisclaimer)}
                placement="top"
              >
                <Icon
                  name="info"
                  color="foregroundMuted"
                  size="xs"
                  testID="disclaimer-tooltip-icon"
                />
              </Tooltip>
            )}
          </HStack>
          {hasPerformanceAvailable && (
            <Link variant="headline" onPress={viewMoreHandler}>
              {formatMessage(messages.viewMore)}
            </Link>
          )}
        </HStack>
        {isMobile ? (
          <>
            {!isPastOwnedAsset && showPerDayMetric && (
              <CollapsibleMetric
                metricKey="past_day_returns"
                label={formatMessage(messages.pastDayReturns)}
                content={formatMessage(messages.pastDayReturnsDescription)}
                value={
                  <TextBody as="span" color={pastDayGainLossObj.variant}>
                    {pastDayGainLossObj.valueWithSign}
                  </TextBody>
                }
                onTextClick={onMobileMetricClick}
              />
            )}
            <CollapsibleMetric
              metricKey="total_returns"
              label={formatMessage(messages.totalReturns)}
              content={formatMessage(messages.totalReturnsDescription)}
              value={
                <TextBody as="span" color={gainLossObj.variant}>
                  {gainLossObj.valueWithSign}
                </TextBody>
              }
              onTextClick={onMobileMetricClick}
            />
            {!isPastOwnedAsset && !showPerDayMetric && (
              <CollapsibleMetric
                metricKey="total_invested"
                label={formatMessage(messages.totalInvestedLabel)}
                content={formatMessage(messages.totalInvestedDescription)}
                value={totalInvestedVal}
                onTextClick={onMobileMetricClick}
              />
            )}
            <CollapsibleMetric
              metricKey="average_price"
              label={formatMessage(messages.avgCost)}
              content={formatMessage(messages.avgCostDescription)}
              onTextClick={onMobileMetricClick}
              value={avgCostVal}
            />
            {!isPastOwnedAsset && (
              <CollapsibleMetric
                metricKey="portfolio"
                label={formatMessage(messages.portfolioPercent)}
                content={formatMessage(messages.portfolioPercentDescription)}
                onTextClick={onMobileMetricClick}
                value={percentOfPortfolioVal}
              />
            )}
            <TextLabel2 as="div" color="foregroundMuted">
              {formatMessage(messages.vaultDisclaimer)}
            </TextLabel2>
          </>
        ) : (
          <HStack justifyContent="space-between">
            {showPerDayMetric && !isPastOwnedAsset && (
              <MetricWithTooltip
                metricKey="past_day_returns"
                value={pastDayGainLossObj.valueWithSign}
                valueVariant={pastDayGainLossObj.variant}
                title={formatMessage(messages.pastDayReturns)}
                description={formatMessage(messages.pastDayReturnsDescription)}
                onInfoIconHover={debouncedHoverInfoHandler}
              />
            )}
            <MetricWithTooltip
              metricKey="total_returns"
              value={gainLossObj.valueWithSign}
              valueVariant={gainLossObj.variant}
              title={formatMessage(messages.totalReturns)}
              description={formatMessage(messages.totalReturnsDescription)}
              onInfoIconHover={debouncedHoverInfoHandler}
            />
            {!isPastOwnedAsset && !showPerDayMetric && (
              <MetricWithTooltip
                metricKey="total_invested"
                value={totalInvestedVal}
                title={formatMessage(messages.totalInvestedLabel)}
                description={formatMessage(messages.totalInvestedDescription)}
                onInfoIconHover={debouncedHoverInfoHandler}
              />
            )}
            <MetricWithTooltip
              metricKey="average_price"
              value={avgCostVal}
              title={formatMessage(messages.avgCost)}
              description={formatMessage(messages.avgCostDescription)}
              onInfoIconHover={debouncedHoverInfoHandler}
            />
            {!isPastOwnedAsset && (
              <MetricWithTooltip
                metricKey="portfolio"
                value={percentOfPortfolioVal}
                title={formatMessage(messages.portfolioPercent)}
                description={formatMessage(
                  messages.portfolioPercentDescription,
                )}
                onInfoIconHover={debouncedHoverInfoHandler}
              />
            )}
          </HStack>
        )}
      </ContentSection>
      {isMobile && <Divider />}
    </>
  );
}

type MetricWithTooltipProps = {
  metricKey: string;
  value: string;
  description: string;
  title: string;
  valueVariant?: GainLossColor;
  onInfoIconHover?: (metricKey: string) => void;
};

function MetricWithTooltipContent({
  value,
  title,
  description,
  valueVariant,
  metricKey,
  onInfoIconHover,
}: MetricWithTooltipProps) {
  const infoIconHoverHandler = useCallback(() => {
    onInfoIconHover?.(metricKey);
  }, [onInfoIconHover, metricKey]);
  return (
    <VStack flexGrow={1}>
      <HStack alignItems="center" spacingBottom={0.5}>
        <TextHeadline as="span" color="foregroundMuted" spacingEnd={1}>
          {title}
        </TextHeadline>
        <Tooltip content={description} placement="top">
          <div onMouseEnter={infoIconHoverHandler}>
            <Icon
              name="info"
              color="foregroundMuted"
              size="xs"
              testID="metric-tooltip-icon"
            />
          </div>
        </Tooltip>
      </HStack>
      <TextBody as="span" color={valueVariant ?? 'foreground'}>
        {value}
      </TextBody>
    </VStack>
  );
}

const MetricWithTooltip = memo(MetricWithTooltipContent);

export default memo(AssetPerformance);

import { ReactNode, memo, ReactChild, useCallback } from 'react';
import { useToggler } from '@cbhq/cds-common/hooks/useToggler';
import { Collapsible } from '@cbhq/cds-web/collapsible/Collapsible';
import { Icon } from '@cbhq/cds-web/icons/Icon';
import { VStack } from '@cbhq/cds-web/layout';
import { HStack } from '@cbhq/cds-web/layout/HStack';
import { TextBody } from '@cbhq/cds-web/typography/TextBody';

type CollapsibleMetricProps = {
  metricKey: string;
  label: ReactNode;
  subLabel?: ReactChild;
  value?: ReactNode;
  content: ReactChild;
  onTextClick?: (metricKey: string, collapsed: boolean) => void;
};

//* mainly used for mobile version
function CollapsibleMetric({
  label,
  subLabel,
  value,
  content,
  onTextClick,
  metricKey,
}: CollapsibleMetricProps) {
  const [collapsed, { toggle }] = useToggler(true);
  const textClickHandler = useCallback(() => {
    onTextClick?.(metricKey, !collapsed);
    toggle();
  }, [metricKey, collapsed, toggle, onTextClick]);
  return (
    <VStack>
      <HStack
        onClick={textClickHandler}
        alignItems="center"
        justifyContent="space-between"
        spacingVertical={3}
      >
        <VStack>
          {typeof label === 'string' ? (
            <TextBody as="span">{label}</TextBody>
          ) : (
            label
          )}
          {subLabel}
        </VStack>
        <HStack alignItems="center">
          {typeof value === 'string' ? (
            <TextBody as="span">{value}</TextBody>
          ) : (
            value
          )}
          {collapsed ? (
            <Icon
              name="caretDown"
              spacingStart={1}
              size="xs"
              color="foregroundMuted"
            />
          ) : (
            <Icon
              spacingStart={1}
              name="caretUp"
              size="xs"
              color="foregroundMuted"
            />
          )}
        </HStack>
      </HStack>
      <Collapsible collapsed={collapsed} spacingBottom={3}>
        {typeof content === 'string' ? (
          <TextBody as="p" color="foregroundMuted">
            {content}
          </TextBody>
        ) : (
          content
        )}
      </Collapsible>
    </VStack>
  );
}

export default memo(CollapsibleMetric);

import { useMemo, memo, useCallback } from 'react';
import { defineMessages, useIntl } from 'react-intl';
import { useHistory } from 'react-router-dom';

import { useKillSwitch } from '@cb/shared/utils/clientKillSwitch/useKillSwitch';
import { gutter } from '@cbhq/cds-common/tokens/sizing';
import { Button, IconButton } from '@cbhq/cds-web/buttons';
import { useBreakpoints } from '@cbhq/cds-web/hooks/useBreakpoints';
import { Fallback, HStack, VStack } from '@cbhq/cds-web/layout';
import { RemoteImage } from '@cbhq/cds-web/media';
import { TextBody, TextTitle2 } from '@cbhq/cds-web/typography';
import { useFragment, graphql } from '@cbhq/data-layer';

import ComponentBoundary from 'components/ComponentBoundary';
import { InstrumentedBalanceErrorBanner } from 'components/ErrorBanner/BalanceErrorBanner';
import { useFilterDappWalletBalancesByAssetId } from 'hooks/api/fragments/useDappWalletMultiChainBalance';
import useAssetTotalBalance from 'hooks/balance/useAssetTotalBalance/useAssetTotalBalance';
import { removeFalsyValues } from 'utils/ArrayUtils';
import { useWeb3Wallet } from 'views/Assets/hooks/useWeb3Wallet';

import { BalanceSectionFragment$key } from './__generated__/BalanceSectionFragment.graphql';
import { AssetPerformance, AssetPerformanceFallback } from './AssetPerformance';

const i18nKey = 'AssetBalanceSection';

const messages = defineMessages({
  seeBalanceSummary: {
    id: `${i18nKey}.seeBalanceSummary`,
    defaultMessage: 'See balance summary',
    description: `#Component: Button
    #CharLimit: 25
    #Context: Button to navigate to the balance summary modal`,
  },
});

type BalanceSectionProps = {
  queryRef: BalanceSectionFragment$key;
  isStablecoinOrAccountId: boolean;
};

function BalanceSectionContent({
  queryRef,
  isStablecoinOrAccountId,
}: BalanceSectionProps) {
  const { formatMessage } = useIntl();
  const { isPhone } = useBreakpoints();
  const { push } = useHistory();

  const query = useFragment(
    graphql`
      fragment BalanceSectionFragment on Query {
        ...useAssetTotalBalanceFragment
        ...useWeb3WalletFragment @arguments(chainId: $chainId)
        ...useDappWalletMultiChainBalancesFragment
        viewer {
          portfolioGainLossBreakdown {
            gainLossEnabled
          }
          assetBySlug(slug: $assetSlug) @required(action: THROW) {
            ...useBalanceSummaryEntryPointAssetFragment
            ...AssetPerformanceSectionFragment
            asset {
              uuid
              imageUrl
              contractAddress
              isListed(country: $countryCode)
            }
            supportedContextsV2 {
              isDex
              isTradable
            }
            allAccounts: accounts(portfolioCategory: PORTFOLIO_CATEGORY_ALL) {
              uuid
              availableBalance {
                currency
              }
            }
            assetPerformancesTimeRanges {
              ... on AssetPerformanceTimeRanges {
                allTimePerformance {
                  totalBalance {
                    value
                  }
                }
              }
            }
          }
        }
      }
    `,
    queryRef,
  );

  const viewerAsset = query.viewer.assetBySlug;
  const assetId = viewerAsset.asset.uuid;

  // DEX only asset -> can send/receive on CB Dex exchange
  const isDexOnly = Boolean(
    !viewerAsset?.supportedContextsV2?.isTradable &&
      !viewerAsset?.asset?.isListed &&
      viewerAsset?.supportedContextsV2?.isDex,
  );

  // Non DEX or CEX asset (like PEPE), can send/receive to off platform wallets
  const isOffPlatform = Boolean(
    !viewerAsset?.supportedContextsV2?.isTradable &&
      !viewerAsset?.asset?.isListed &&
      !viewerAsset?.supportedContextsV2?.isDex,
  );

  const killBalanceErrorBanner = useKillSwitch(
    'kill_balance_error_banner_on_assets_web',
  );

  const {
    hasBalanceError,
    formattedTotalBalance,
    formattedTotalBalanceInFiat,
  } = useAssetTotalBalance({
    queryRef: query,
    supportPartialBalance: killBalanceErrorBanner,
  });

  const onPressBalanceSummary = useCallback(() => {
    // If Dex only asset, or off platform asset but holds balance, link directly to w3w adp
    if (isOffPlatform || isDexOnly)
      return push(
        `/balances/${assetId}&${viewerAsset.asset.contractAddress}/web3-wallet`,
      );
    push(`/balance-summary/${assetId}`);
  }, [
    isOffPlatform,
    isDexOnly,
    push,
    assetId,
    viewerAsset.asset.contractAddress,
  ]);

  const balanceSummaryCTA = useMemo(() => {
    return isPhone ? (
      <IconButton name="forwardArrow" onPress={onPressBalanceSummary} />
    ) : (
      <Button compact variant="secondary" onPress={onPressBalanceSummary}>
        {formatMessage(messages.seeBalanceSummary)}
      </Button>
    );
  }, [formatMessage, isPhone, onPressBalanceSummary]);

  const { walletAddress } = useWeb3Wallet(query);

  const balanceValue =
    query?.viewer.assetBySlug.assetPerformancesTimeRanges?.allTimePerformance
      ?.totalBalance?.value ?? '0';
  const ownsEarningBalance = useMemo(() => {
    return Boolean(parseFloat(balanceValue) !== 0);
  }, [balanceValue]);
  const isGainLossEnabled =
    !!query?.viewer?.portfolioGainLossBreakdown?.gainLossEnabled;

  const isAssetPerformanceKilled = useKillSwitch('kill_asset_performance_web');

  const showGainLossFeature =
    isGainLossEnabled &&
    ((!isAssetPerformanceKilled && ownsEarningBalance) || !walletAddress);

  const accounts = useMemo(
    () =>
      removeFalsyValues(viewerAsset?.allAccounts ?? []).filter(
        account => account.uuid !== account?.availableBalance?.currency,
      ),
    [viewerAsset?.allAccounts],
  );

  const defiAccounts = useFilterDappWalletBalancesByAssetId({
    queryRef: query,
    assetId: query.viewer.assetBySlug.asset.uuid,
  });

  const augmentedMetadata = useMemo(() => {
    return {
      allAccountCount: accounts.length + defiAccounts.length,
      web3AccountCount: defiAccounts.length,
    };
  }, [accounts.length, defiAccounts]);

  return (
    <VStack spacingTop={gutter} testID="balance-section-content">
      {!killBalanceErrorBanner && hasBalanceError ? (
        <VStack testID="BalanceErrorBanner" spacingTop={2} spacingBottom={1}>
          <InstrumentedBalanceErrorBanner
            slim
            titlePreset="balancesUnavailableTitle"
            component="AssetBalances"
          />
        </VStack>
      ) : (
        <HStack
          justifyContent="space-between"
          spacingBottom={isPhone ? 1 : gutter}
          alignItems="center"
        >
          <HStack alignItems="center">
            <RemoteImage size="xl" source={viewerAsset.asset.imageUrl} />
            <VStack spacingStart={2}>
              <TextTitle2 as="p">{formattedTotalBalanceInFiat}</TextTitle2>
              <TextBody as="p" color="foregroundMuted">
                {formattedTotalBalance}
              </TextBody>
            </VStack>
          </HStack>
          {balanceSummaryCTA}
        </HStack>
      )}
      {showGainLossFeature && (
        <AssetPerformance
          viewerAssetRef={viewerAsset}
          augmentedMetadata={augmentedMetadata}
          showPortfolioOnly={isStablecoinOrAccountId}
        />
      )}
    </VStack>
  );
}

function BalanceSectionFallback() {
  const { isPhone } = useBreakpoints();
  return (
    <VStack spacingTop={gutter}>
      <HStack
        justifyContent="space-between"
        spacingBottom={isPhone ? 1 : gutter}
        alignItems="center"
      >
        <HStack alignItems="center">
          <Fallback width={40} height={40} shape="circle" />
          <VStack spacingStart={2} gap={1}>
            <Fallback height={40} width={200} />
            <Fallback height={20} width={200} />
          </VStack>
        </HStack>
      </HStack>
      <AssetPerformanceFallback />
    </VStack>
  );
}

function BalanceSection(props: BalanceSectionProps) {
  return (
    <ComponentBoundary
      owner="asset"
      boundaryName="BalanceSection"
      loadingFallback={<BalanceSectionFallback />}
    >
      <BalanceSectionContent {...props} />
    </ComponentBoundary>
  );
}

export default memo(BalanceSection);

