import ComponentBoundary from 'components/ComponentBoundary';
import useAssetsFinancialPromotionsUk from 'hooks/useAssetsFinancialPromotionsUk';
import useModal from 'hooks/useModal';

import TopAssets from '../TopAssets';
import { CorrelatedAssetsFragment$key } from './__generated__/CorrelatedAssetsFragment.graphql';
import { CorrelatedAssetsTopAssetsFragment$key } from './__generated__/CorrelatedAssetsTopAssetsFragment.graphql';
import AboutCorrelatedModal from './AboutCorrelatedModal';
import CorrelatedAsset from './CorrelatedAsset';
import CorrelatedAssetsFallback from './CorrelatedAssetsFallback';
import messages from './messages';

type Props = {
  assetRef: CorrelatedAssetsFragment$key;
  queryRef: CorrelatedAssetsTopAssetsFragment$key;
};

function CorrelatedAssets(props: Props) {
  return (
    <ComponentBoundary
      owner="asset"
      boundaryName="CorrelatedAssets"
      loadingFallback={<CorrelatedAssetsFallback />}
    >
      <CorrelatedAssetsContent {...props} />
    </ComponentBoundary>
  );
}

function CorrelatedAssetsContent({ assetRef, queryRef }: Props) {
  const query = useFragment(
    graphql`
      fragment CorrelatedAssetsTopAssetsFragment on Query {
        ...TopAssetsFragment
      }
    `,
    queryRef,
  );

  const asset = useFragment(
    graphql`
      fragment CorrelatedAssetsFragment on Asset
      @argumentDefinitions(currency: { type: "TickerSymbol!" }) {
        name
        signals @skip(if: $skipCorrelatedAssets) {
          priceCorrelations {
            assetCorrelations {
              ...CorrelatedAssetFragment @arguments(currency: $currency)
            }
            updatedAt
          }
        }
        ...TopAssetsAssetFragment
      }
    `,
    assetRef,
  );

  const { formatMessage } = useIntl();
  const { showModal } = useModal();

  const hasUkFinProm = useAssetsFinancialPromotionsUk();

  const priceCorrelations = asset?.signals?.priceCorrelations;

  const handleOnPress = useCallback(
    () =>
      showModal(
        <AboutCorrelatedModal
          assetName={asset.name}
          updatedAt={priceCorrelations?.updatedAt}
        />,
      ),
    [asset.name, priceCorrelations?.updatedAt, showModal],
  );

  if (!priceCorrelations)
    return <TopAssets assetRef={asset} queryRef={query} />;

  const correlatedAssets = priceCorrelations.assetCorrelations;

  return (
    <Card testID="correlated-assets" bordered borderRadius="rounded">
      <HStack
        spacingTop={2}
        spacingBottom={1}
        spacingStart={3}
        spacingEnd={2}
        justifyContent="space-between"
        alignItems="center"
        position="relative"
      >
        <TextTitle3 as="h2">
          {formatMessage(hasUkFinProm ? messages.title90d : messages.title)}
        </TextTitle3>
        <IconButton
          name="info"
          variant="foregroundMuted"
          transparent
          onPress={handleOnPress}
        />
      </HStack>
      {correlatedAssets.map(asset => (
        <CorrelatedAsset assetCorrelationRef={asset} />
      ))}
    </Card>
  );
}

export default CorrelatedAssets;

