import { renderHook } from '@testing-library/react-hooks';
import { createBrowserHistory } from 'history';
import { Router, Route, Switch } from 'react-router-dom';

import useActiveTab from './useActiveTab';

type Params = {
  accounts?: { uuid: string; primary: boolean }[];
  symbol?: string | null | undefined;
};

describe('useActiveTab', () => {
  let history: any;

  const renderTest = ({ accounts = [], symbol }: Params = {}) =>
    renderHook(() => useActiveTab({ accounts, symbol }), {
      wrapper: ({ children }: { children: React.ReactNode }) => (
        <Router history={history}>
          <Switch>
            <Route path="/price/:assetSlug?" render={() => children} />
            <Route path="/accounts/:accountId?" render={() => children} />
            <Route path="/accounts/:accountId/vault?" render={() => children} />
          </Switch>
        </Router>
      ),
    });

  beforeEach(() => {
    history = createBrowserHistory();
  });

  it('returns overview if active route is /price/:assetSlug', async () => {
    history.push('/price/bitcoin');
    const { result } = renderTest();
    expect(result.current).toEqual('overview');
  });

  it('returns emptyVault if active route is /accounts/:accountId/vault', async () => {
    history.push('/accounts/btc_account_id/vault');
    const { result } = renderTest();
    expect(result.current).toEqual('emptyVault');
  });

  it('returns accountId if active route is /accounts/:accountId', async () => {
    history.push('/accounts/btc_account_id');
    const { result } = renderTest({
      accounts: [{ uuid: 'btc_account_id', primary: true }],
      symbol: 'BTC',
    });
    expect(result.current).toEqual('btc_account_id');
  });

  it('returns nothing if active route is /accounts/:accountId and no account is matching', async () => {
    history.push('/accounts/BTC');
    const { result } = renderTest();
    expect(result.current).toEqual(undefined);
  });

  it('returns accountId if active route is /accounts/BTC', async () => {
    history.push('/accounts/BTC');
    const { result } = renderTest({
      accounts: [{ uuid: 'btc_account_id', primary: true }],
      symbol: 'BTC',
    });
    expect(result.current).toEqual('btc_account_id');
  });

  it('returns nothing if active route is /accounts/BTC and no account is matching', async () => {
    history.push('/accounts/BTC');
    const { result } = renderTest();
    expect(result.current).toEqual(undefined);
  });
});

import { useMemo, useCallback, useContext } from 'react';
import { useIntl } from 'react-intl';

import { useFields, useSubmitter } from '@cb/forms';
import { Button } from '@cbhq/cds-web/buttons/Button';
import { ButtonGroup } from '@cbhq/cds-web/buttons/ButtonGroup';
import { VStack } from '@cbhq/cds-web/layout/VStack';
import { Link, TextLegal } from '@cbhq/cds-web/typography';

import useStepper from 'components/Stepper/hooks/useStepper';
import AssetRecoveryForm from 'views/AssetRecovery/assetRecoveryForm';
import { MultiStepProgressContext } from 'views/AssetRecovery/components/MultiStepProgressBar/MultiStepProgressBar';

import {
  logAssetRecoveryIntroCancelClick,
  logAssetRecoveryIntroContinueClick,
} from '../analytics';
import {
  AssetRecoveryCommitMutation$data,
  AssetRecoveryCreateMutation$data,
} from '../AssetRecovery';
import sharedMessages from '../messages';
import stepper from '../steps/stepper';

type AssetRecoveryFooter = {
  close?(): void;
  isSubmitting: boolean;
};

export default function AssetRecoveryFooter({
  close,
  isSubmitting,
}: AssetRecoveryFooter) {
  const { formatMessage } = useIntl();
  const { goBack, currentStep, steps, goToStep } = useStepper(stepper);
  const {
    transactionHash,
    inboundAddress,
    selfCustodyWalletAddress,
    operationUuid,
    amount,
    contractAddress,
    estimatedSendTime,
    coinbaseFee,
    networkFee,
    assetRecoveryId,
    title,
    subtitle,
    deeplinkUrl,
    signature,
  } = useFields(AssetRecoveryForm);

  const [submit, isSubmittable] = useSubmitter(AssetRecoveryForm);

  const { updateProgress, clearProgress } = useContext(
    MultiStepProgressContext,
  );

  const onContinuePress = useCallback(() => {
    switch (currentStep) {
      // because this is the default step we need to specify the first step to go to
      case 'assetRecoveryIntro':
        logAssetRecoveryIntroContinueClick();
        break;
      case 'findTransactionStep':
        submit({
          currentStep,
          onCompleted: () => {
            updateProgress(0, 1);
            goToStep(steps[steps.indexOf(currentStep) + 1]);
          },
        });
        return;
      case 'transactionFoundStep':
        updateProgress(1, 0.5);
        break;
      case 'connectWalletStep':
        updateProgress(0, 1);
        submit({
          currentStep,
          onCompleted: ({
            createP2PAssetRecovery,
          }: AssetRecoveryCreateMutation$data) => {
            amount.onChange(createP2PAssetRecovery?.amount ?? '');
            networkFee.onChange(createP2PAssetRecovery?.networkFee ?? null);
            coinbaseFee.onChange(createP2PAssetRecovery?.coinbaseFee ?? null);
            estimatedSendTime.onChange(
              createP2PAssetRecovery?.estimatedSendTime ?? '',
            );
            contractAddress.onChange(
              createP2PAssetRecovery?.contractAddress ?? '',
            );
            assetRecoveryId.onChange(
              createP2PAssetRecovery?.assetRecoveryId ?? '',
            );
            updateProgress(1, 1);
            goToStep(steps[steps.indexOf(currentStep) + 1]);
          },
        });
        return;
      case 'commitSendStep':
        // going to submit here
        // should just return instead of break for now
        submit({
          currentStep,
          onCompleted: ({
            commitP2PAssetRecovery,
          }: AssetRecoveryCommitMutation$data) => {
            title.onChange(commitP2PAssetRecovery?.title ?? '');
            subtitle.onChange(commitP2PAssetRecovery?.subtitle ?? '');
            deeplinkUrl.onChange(commitP2PAssetRecovery?.deeplinkUrl ?? '');
            goToStep('sendSuccessStep');
            updateProgress(2, 1);
          },
        });
        return;
      case 'sendSuccessStep':
        updateProgress(2, 2);
        break;
    }
    goToStep(steps[steps.indexOf(currentStep) + 1]);
  }, [
    amount,
    assetRecoveryId,
    coinbaseFee,
    contractAddress,
    currentStep,
    deeplinkUrl,
    estimatedSendTime,
    goToStep,
    networkFee,
    steps,
    submit,
    subtitle,
    title,
    updateProgress,
  ]);

  const onCancelPress = useCallback(() => {
    switch (currentStep) {
      case 'assetRecoveryIntro':
        logAssetRecoveryIntroCancelClick();
        clearProgress();
        close?.();
        break;
      case 'connectWalletStep':
        setTimeout(() => {
          updateProgress(1, 0);
        }, 250);
        break;
      case 'findTransactionStep':
        clearProgress();
        break;
      case 'transactionFoundStep':
        updateProgress(1, 0);
        setTimeout(() => {
          updateProgress(0, 0.5);
        }, 500);
        break;
      case 'commitSendStep':
        updateProgress(2, 0);
        break;
    }
    goBack();
  }, [clearProgress, currentStep, goBack, close, updateProgress]);

  const doNotProceed = useMemo(() => {
    switch (currentStep) {
      case 'assetRecoveryIntro':
        return false;
      case 'findTransactionStep':
        return (
          transactionHash.errors.length > 0 || inboundAddress.errors.length > 0
        );
      case 'transactionFoundStep':
        return !operationUuid.value;
      case 'commitSendStep':
        return !isSubmittable;
      case 'connectWalletStep':
        return !selfCustodyWalletAddress.value || !signature.value;
    }
  }, [
    currentStep,
    transactionHash.errors.length,
    inboundAddress.errors.length,
    operationUuid.value,
    isSubmittable,
    selfCustodyWalletAddress.value,
    signature.value,
  ]);

  const isIntro = currentStep === 'assetRecoveryIntro';

  return (
    <VStack spacerGap={4} flexGrow={1} spacingTop={4}>
      {currentStep !== 'sendSuccessStep' ? (
        <VStack alignItems={isIntro ? 'center' : undefined}>
          <ButtonGroup accessibilityLabel="asset-recovery-buttons" block>
            <Button tabIndex={1} variant="secondary" onPress={onCancelPress}>
              {formatMessage(sharedMessages.cancel)}
            </Button>
            <Button
              variant="primary"
              onPress={onContinuePress}
              disabled={doNotProceed || isSubmitting}
              loading={isSubmitting}
            >
              {formatMessage(
                currentStep === 'commitSendStep'
                  ? sharedMessages.sendNow
                  : sharedMessages.continue,
              )}
            </Button>
          </ButtonGroup>
        </VStack>
      ) : (
        <ButtonGroup block accessibilityLabel="asset-recovery-buttons">
          <Button tabIndex={1} to={deeplinkUrl.value} variant="secondary">
            {formatMessage(sharedMessages.viewDetails)}
          </Button>
          <Button
            variant="primary"
            disabled={doNotProceed || isSubmitting}
            onPress={close}
            loading={isSubmitting}
          >
            {formatMessage(sharedMessages.done)}
          </Button>
        </ButtonGroup>
      )}
      {currentStep === 'transactionFoundStep' ? (
        <TextLegal color="foregroundMuted" as="p">
          {formatMessage(sharedMessages.legal)}
        </TextLegal>
      ) : null}
      {currentStep === 'commitSendStep' ? (
        <TextLegal color="foregroundMuted" as="p">
          {formatMessage(
            !coinbaseFee.value
              ? sharedMessages.legalFee
              : sharedMessages.legalCoinbaseFee,
            {
              learnMore: (
                <TextLegal as="span">
                  <Link
                    openInNewWindow
                    to="https://help.coinbase.com/coinbase/trading-and-funding/pricing-and-fees/fees"
                  >
                    {formatMessage(sharedMessages.learnMore)}
                  </Link>
                </TextLegal>
              ),
            },
          )}
        </TextLegal>
      ) : null}
    </VStack>
  );
}

