export default function CommitSendStep() {
  const { updateProgress } = useContext(MultiStepProgressContext);
  const { formatMessage } = useIntl();
  const formatAddress = useFormatAddress();

  const query = useLazyLoadQuery<CommitSendStepQuery>(
    graphql`
      query CommitSendStepQuery {
        viewer {
          assetBySymbol(symbol: "ETH") {
            supportedNetworks(
              action: ASSET_RECOVERY
              applicationContext: CONSUMER
            ) {
              ...useSupportedNetworksFragment
            }
          }
        }
      }
    `,
    {},
  );

  const { supportedNetworks } = useSupportedNetworks(
    query.viewer.assetBySymbol?.supportedNetworks ?? null,
  );

  useLogAssetRecoveryStepView('recovery_commit');

  const {
    selfCustodyWalletAddress,
    amount,
    contractAddress,
    estimatedSendTime,
    coinbaseFee,
    networkFee,
    network,
  } = useFields(AssetRecoveryForm);

  const selectedNetwork = useMemo(
    () => supportedNetworks?.find(n => n?.networkSlug === network.value),
    [network.value, supportedNetworks],
  );

  useOnce(() => {
    setTimeout(() => {
      updateProgress(2, 0.5);
    }, 250);
  });

  const handleOnPress = useCallback(
    () => copyToClipboard(selfCustodyWalletAddress.value),
