export default function FindTransactionStep({
  setShowSecondaryContent,
}: FindTransactionStep) {
  const { updateProgress } = useContext(MultiStepProgressContext);
  const fields = useFields(form);
  const transactionHashField = fields.transactionHash;
  const inboundAddressField = fields.inboundAddress;
  const { formatMessage } = useIntl();
  const hasL2AssetRecovery = useIsTreatment('nov_2023_l2_asset_recovery');

  const query = useLazyLoadQuery<FindTransactionStepQuery>(
    graphql`
      query FindTransactionStepQuery {
        ...SupportedNetworksSelectorQueryFragment
        viewer {
          assetBySymbol(symbol: "ETH") {
            ... on ViewerAsset {
              supportedNetworks(
                action: ASSET_RECOVERY
                applicationContext: CONSUMER
              ) {
                supportedNetworks {
                  __typename
                }
              }
            }
          }
        }
      }
    `,
    {},
  );
  useLogAssetRecoveryStepView('recovery_find_transaction');

  useEffectOnce(() => {
    updateProgress(0, 0.5);
    setShowSecondaryContent(true);
  });

  const onChangeHandler = useCallback(
    (field: 'transactionHash' | 'inboundAddress' | 'network') =>
      (e: React.ChangeEvent<HTMLInputElement>) => {
        fields[field].onChange(e.target.value);
        if (fields[field].value.length > 0 && fields[field].isDirty) {
          fields.operationUuid.onChange('');
        }

        if (fields[field].name === 'network') {
          Object.keys(fields).forEach(field => {
            if (field !== 'network') {
              fields[field as keyof typeof initialValues].errors.length > 0 &&
                fields[field as keyof typeof initialValues].onErrors([]);
            }
          });
        }
      },
    [fields],
  );

  const hasNetworks =
    (query.viewer.assetBySymbol?.supportedNetworks?.supportedNetworks ?? [])
      .length > 0;

  const isL2Recovery = hasL2AssetRecovery && hasNetworks;

  const handleOnChange = useCallback(
    (slug: string) => fields.network.onChange(slug),
    [fields.network],
  );

  return (
    <ModalBoundary
      owner="p2p"
      boundaryName="assetRecovery"
      context="asset_recovery"
    >
      <VStack
        spacerGap={3}
        justifyContent="center"
        alignItems="flex-start"
        spacingVertical={4}
      >
        <TextTitle1 as="h1">{formatMessage(messages.title)}</TextTitle1>
        <TextBody as="span" color="foregroundMuted">
          {formatMessage(
            hasNetworks ? messages.descriptionL2 : messages.description,
            {
              link: (
                <Link
                  to="https://help.coinbase.com/en/coinbase/getting-started/crypto-education/what-is-a-transaction-hash-hash-id"
                  openInNewWindow
                >
                  {formatMessage(messages.howToFindLink)}
                </Link>
              ),
            },
          )}
        </TextBody>
        {isL2Recovery ? (
          <InstrumentedSuspense
            instrumentationId="asset-recovery"
            key="asset-recovery"
            fallback={<Fallback width={'100%'} height={60} shape="squircle" />}
          >
            <SupportedNetworksSelector
              defaultValue={
                !fields.network.value ? 'ethereum' : fields.network.value
              }
              onChange={handleOnChange}
              label={formatMessage(messages.transactionNetwork)}
              queryRef={query}
            />
          </InstrumentedSuspense>
        ) : null}
        <TextInput
          helperText={
            transactionHashField?.errors?.length > 0 &&
            transactionHashField.isDirty
              ? transactionHashField.errors[0].defaultMessage
              : formatMessage(messages.transactionIdHelperText)
          }
          variant={
            transactionHashField.errors.length > 0 &&
            transactionHashField.isDirty
              ? 'negative'
              : undefined
          }
          value={transactionHashField.value}
          onChange={onChangeHandler('transactionHash')}
          placeholder={formatMessage(messages.transactionIdPlaceholder)}
          title={formatMessage(messages.transactionId)}
        />
        <TextInput
          helperText={
            inboundAddressField.errors.length > 0 && inboundAddressField.isDirty
              ? inboundAddressField.errors[0].defaultMessage
              : formatMessage(messages.walletAddressHelperText)
          }
          variant={
            inboundAddressField.errors.length > 0 && inboundAddressField.isDirty
              ? 'negative'
              : undefined
          }
          value={inboundAddressField.value}
          onChange={onChangeHandler('inboundAddress')}
          placeholder={formatMessage(messages.coinbaseWalletAddress)}
          title={formatMessage(messages.coinbaseWalletAddress)}
        />
      </VStack>
    </ModalBoundary>
  );
}

