export default function TransactionFoundStep() {
  const { formatMessage, formatDate } = useIntl();
  const { openModal, closeModal } = useModal();
  const hasL2AssetRecovery = useIsTreatment('nov_2023_l2_asset_recovery');
  const {
    transactionHash: { value: transactionHashValue },
    inboundAddress: { value: inboundAddressValue },
    operationUuid: {
      onChange: selectedTransactionIdOnChange,
      value: selectedTransactionIdValue,
    },
    network: { value: networkValue },
  } = useFields(AssetRecoveryForm);

  useLogAssetRecoveryStepView('recovery_transaction_found');

  const { viewer } = useLazyLoadQuery<TransactionFoundStepQuery>(
    graphql`
      query TransactionFoundStepQuery(
        $transactionHash: String!
        $inboundAddress: String!
        $network: String!
      ) {
        viewer {
          p2pAssetRecovery {
            existingTransaction(
              transaction_hash: $transactionHash
              inbound_address: $inboundAddress
              network: $network
              first: 100
            ) {
              ... on P2PAssetRecoveryExistingTransactionConnection {
                success
                network
                createdAt
                transactionHash
                inboundAddress
                edges {
                  node {
                    amount
                    recoverableDetails
                    isRecoverable
                    contractAddress
                    operationUuid
                  }
                }
              }
            }
          }
        }
      }
    `,
    {
      transactionHash: transactionHashValue,
      inboundAddress: inboundAddressValue,
      network: networkValue,
    },
  );

  const formatAddress = useFormatAddress();
  const [selected, setSelected] = useState<string | null>(
    selectedTransactionIdValue || null,
  );
  const onContentCellPress = useCallback(
    (selection: string | null) => {
      selectedTransactionIdOnChange(selection ?? '');
      setSelected(selection);
    },
    [selectedTransactionIdOnChange],
  );
  const existingTransaction = viewer?.p2pAssetRecovery?.existingTransaction;
  const transactions = removeFalsyValues(
    viewer?.p2pAssetRecovery?.existingTransaction?.edges ?? [],
  );
  const hasMultipleTransactions = transactions.length > 1;
  const transactionHash =
    viewer?.p2pAssetRecovery?.existingTransaction?.transactionHash;
  const singleTransaction = transactions[0]?.node;

  useEffectOnce(() => {
    if (singleTransaction && !hasMultipleTransactions) {
      selectedTransactionIdOnChange(singleTransaction?.operationUuid ?? '');
    }
  });

  const handleContentCellPress = useCallback(
    (operationUuid: string | null, recoverableDetails: string | null) => {
      return () => {
        if (
          recoverableDetails === RECOVERY_TYPES.TRANSFER_RECOVERY_UNAVAILABLE
        ) {
          openModal(
            <AssetRecoveryErrorModal
              onRequestClose={closeModal}
              title={formatMessage(messages.unrecoverableTitle)}
              body={formatMessage(messages.unrecoverableBody)}
              mode="error"
              action={{
                label: sharedMessages.learnMore,
                goTo: 'https://help.coinbase.com/en/coinbase/trading-and-funding/sending-or-receiving-cryptocurrency/lost-assets',
              }}
            />,
          );
          return;
        }
        onContentCellPress(operationUuid);
      };
    },
    [closeModal, formatMessage, onContentCellPress, openModal],
  );

  const RECOVERY_STATUSES = useMemo(
    () => ({
      [RECOVERY_TYPES.TRANSFER_RECOVERED]: (
        <HStack alignItems="center" spacerGap={2}>
          <TextBody as="span">{formatMessage(messages.recovered)}</TextBody>
          <Icon size="xs" name="caretRight" color="foregroundMuted" />
        </HStack>
      ),
      [RECOVERY_TYPES.TRANSFER_RECOVERY_UNAVAILABLE]: (
        <HStack alignItems="center" spacerGap={2}>
          <TextBody as="span" color="negative">
            {formatMessage(messages.notRecoverable)}
          </TextBody>
          <Icon size="xs" name="caretRight" color="foregroundMuted" />
        </HStack>
      ),
      [RECOVERY_TYPES.TRANSFER_RECOVERY_IN_PROGRESS]: 'In progress',
    }),
    [formatMessage],
  );

  const handleOnPress = useCallback(() => {
    if (!transactionHash) return null;
    return copyToClipboard(transactionHash);
  }, [transactionHash]);

  const handleOnPress1 = useCallback(
    () => copyToClipboard(singleTransaction?.contractAddress ?? ''),
    [singleTransaction?.contractAddress],
  );

  return (
    <VStack spacerGap={3} justifyContent="center" spacingVertical={4}>
      <TextTitle1 as="h1">{formatMessage(messages.title)}</TextTitle1>
      <TextBody as="p" color="foregroundMuted">
        {formatMessage(
          hasMultipleTransactions
            ? messages.titleMultipleAssets
            : messages.transactionDateSubtitle,
          {
            date: (
              <TextHeadline color="foregroundMuted" as="span">
                {formatDate(
                  new Date(
                    secondsToMilliseconds(
                      parseInt(
                        existingTransaction?.createdAt?.replace(
                          'seconds:',
                          '',
                        ) ?? '0',
                      ),
                    ),
                  ),
                  {
                    month: 'long',
                    day: 'numeric',
                    year: 'numeric',
                  },
                )}
              </TextHeadline>
            ),
          },
        )}
      </TextBody>
      {transactionHash ? (
        <HStack justifyContent="space-between" alignItems="center">
          <TextBody as="p" color="foregroundMuted">
            {formatMessage(messages.transactionId)}
          </TextBody>
          <HStack spacerGap={1} alignItems="center">
            <TextLabel1 as="span">{formatAddress(transactionHash)}</TextLabel1>
            <Tooltip content={transactionHash}>
              <IconButton name="visibleActive" onPress={handleOnPress} />
            </Tooltip>
          </HStack>
        </HStack>
      ) : null}
      {hasL2AssetRecovery && existingTransaction?.network && (
        <HStack justifyContent="space-between" alignItems="center">
          <HStack spacerGap={2} alignItems="center">
            <TextBody as="p" color="foregroundMuted">
              {formatMessage(messages.assetNetwork, {
                network: existingTransaction?.network,
              })}
            </TextBody>
            <Tooltip
              content={formatMessage(messages.networkTooltip, {
                network: existingTransaction?.network,
              })}
            >
              <Icon name="info" size="xs" color="foreground" />
            </Tooltip>
          </HStack>
          <HStack spacerGap={1} alignItems="center">
            <TextLabel1 as="span">{existingTransaction?.network}</TextLabel1>
          </HStack>
        </HStack>
      )}
      <VStack>
        {hasMultipleTransactions ? (
          transactions.map(({ node }, index) => {
            return (
              <ContentCell
                description={node?.contractAddress}
                title={formatMessage(messages.assetLabel, {
                  index: index + 1,
                })}
                meta={
                  RECOVERY_STATUSES[
                    node?.recoverableDetails ??
                      RECOVERY_TYPES.TRANSFER_RECOVERY_UNAVAILABLE
                  ]
                }
                disabled={
                  RECOVERY_TYPES.TRANSFER_RECOVERED === node?.recoverableDetails
                }
                onPress={handleContentCellPress(
                  node?.operationUuid ?? null,
                  node?.recoverableDetails ?? null,
                )}
                selected={node?.operationUuid === selected}
              />
            );
          })
        ) : (
          <>
            <HStack justifyContent="space-between" alignItems="center">
              <HStack spacerGap={2} alignItems="center">
                <TextBody as="p" color="foregroundMuted">
                  {formatMessage(messages.assetLabel, { index: 'ID' })}
                </TextBody>
                <Tooltip content={formatMessage(messages.assetTooltip)}>
                  <Icon name="info" size="xs" color="foreground" />
                </Tooltip>
              </HStack>
              <HStack spacerGap={1} alignItems="center">
                <TextLabel1 as="span">
                  {formatAddress(singleTransaction?.contractAddress ?? '')}
                </TextLabel1>
                <Tooltip content={singleTransaction?.contractAddress}>
                  <IconButton name="visibleActive" onPress={handleOnPress1} />
                </Tooltip>
              </HStack>
            </HStack>
            <Spacer vertical={3} />
            <HStack justifyContent="space-between" alignItems="center">
              <HStack spacerGap={2} alignItems="center">
                <TextBody as="p" color="foregroundMuted">
                  {formatMessage(messages.amount)}
                </TextBody>
                <Tooltip content={formatMessage(messages.amountTooltip)}>
                  <Icon name="info" size="xs" color="foreground" />
                </Tooltip>
              </HStack>
              <HStack spacerGap={1} alignItems="center">
                <TextLabel1 as="span">
                  {Number(singleTransaction?.amount ?? '').toLocaleString()}
                </TextLabel1>
              </HStack>
            </HStack>
          </>
        )}
      </VStack>
    </VStack>
  );
}

