import { useCallback, memo, useMemo } from 'react';
import { useIntl } from 'react-intl';
import { useHistory } from 'react-router-dom';

import useFormatPercentChange from '@cb/shared/components/PercentChange/useFormatPercentChange';
import {
  useGainLossFormatter,
  useIsMobile,
  useScreenMatch,
} from '@cb/shared/utils';
import type { PaletteForeground } from '@cbhq/cds-common';
import { CellMedia } from '@cbhq/cds-web/cells';
import { Box } from '@cbhq/cds-web/layout';
import { TableCell, TableRow } from '@cbhq/cds-web/tables';
import {
  DEFAULT_FORMATTED_FALLBACK,
  useCurrencyFormatter,
} from '@cbhq/common-web';
import { useCurrencyConverter } from '@cbhq/common-web/hooks/useCurrencyConverter';
import { graphql, InstrumentedSuspense, useFragment } from '@cbhq/data-layer';

import { DeprecatedUnsafeCurrencyIcon } from 'components/CurrencyIcon';
import useNativeCurrency from 'hooks/useNativeCurrency';
import preloadBundleForRoute from 'utils/preloadBundleForRoute';
import { accountUrl, assetPageUrl } from 'utils/routeHelper';
import InlineQuickActions from 'views/Assets/components/QuickActionsCard/InlineQuickActions';
import useStableBalancesEligible from 'views/Assets/hooks/useStableBalancesEligible';

import TableActionButton, {
  TableActionButtonProps,
} from '../TableActionButton';
import { AccountTableV2RowContentFragment$key } from './__generated__/AccountTableV2RowContentFragment.graphql';
import { AccountTableV2RowContentViewerAssetFragment$key } from './__generated__/AccountTableV2RowContentViewerAssetFragment.graphql';
import { AccountTableV2RowFragment$key } from './__generated__/AccountTableV2RowFragment.graphql';
import { OptionKey } from './AccountTableV2Filter';
import { AccountTableV2LoadingStateRow } from './AccountTableV2LoadingState';

type AssetMetadata = {
  assetName: string;
  displaySymbol: string;
  assetImageUrl: string;
  assetType: string;
  assetSlug: string;
  assetKey: string;
};

export type ActionButton = Omit<TableActionButtonProps, 'onPress'> & {
  onPress: (asset: AssetMetadata) => void;
};

export type AccountTableV2RowProps = AssetMetadata & {
  queryRef: AccountTableV2RowFragment$key;
  platformName: string;
  assetPrice: string | number;
  assetPercentChange: number;
  assetBalance: string;
  assetBalanceInNativeCurrency: string;
  assetAllocationPercent: number;
  hideAllocationColumn: boolean;
  holdingColSubDetail: OptionKey;
  perfColOptionKey: OptionKey;
  showPerformanceColumn?: boolean;
  showBalanceFallback?: boolean;
  allTimeGainLoss?: { currency: string; value: string } | null;
  pastDayGainLoss?: { currency: string; value: string } | null;
  canBuy?: boolean;
  canSell?: boolean;
  canConvert?: boolean;
  canSend?: boolean;
  canReceive?: boolean;
  canAddCash?: boolean;
  accountId: string;
  onClick?: (asset: AssetMetadata) => void;
  renderActionButtonColumns?: (
    assetEligibilityFields: Pick<
      AccountTableV2RowProps,
      'canBuy' | 'canSend' | 'canReceive'
    >,
  ) => (ActionButton | null)[];
  viewerAssetRef: AccountTableV2RowContentViewerAssetFragment$key | null;
};

type AccountTableV2RowContentProps = Omit<
  AccountTableV2RowProps,
  'queryRef'
> & {
  queryRef: AccountTableV2RowContentFragment$key;
};

// TODO: apply relay pattern and remove asset prop drilling
function AccountTableV2RowContent({
  assetName = '',
  displaySymbol = '',
  platformName = '',
  assetImageUrl = '',
  assetType = '',
  assetPrice = '',
  assetPercentChange = 0,
  assetBalance = '',
  assetBalanceInNativeCurrency = '',
  assetAllocationPercent = 0,
  hideAllocationColumn = true,
  assetSlug = '',
  assetKey = '',
  holdingColSubDetail,
  allTimeGainLoss,
  pastDayGainLoss,
  showPerformanceColumn = false,
  showBalanceFallback,
  perfColOptionKey,
  canBuy = false,
  canSell = false,
  canConvert = false,
  canSend = false,
  canReceive = false,
  canAddCash = false,
  accountId,
  onClick,
  renderActionButtonColumns,
  queryRef,
  viewerAssetRef,
}: AccountTableV2RowContentProps) {
  const query = useFragment(
    graphql`
      fragment AccountTableV2RowContentFragment on Query {
        viewer {
          earn {
            assets {
              current {
                assetV2: asset {
                  asset {
                    platformName
                  }
                  rewardApy {
                    formattedValue
                    statsLabel
                  }
                }
              }
            }
          }
        }
      }
    `,
    queryRef,
  );

  const viewerAsset =
    useFragment<AccountTableV2RowContentViewerAssetFragment$key>(
      graphql`
        fragment AccountTableV2RowContentViewerAssetFragment on ViewerAsset {
          asset {
            ...useCurrencyConverterSourceAssetFragment
          }
        }
      `,
      viewerAssetRef,
    );

  const { formatNumber } = useIntl();
  const isTablet = useScreenMatch('tablet');
  const nativeCurrency = useNativeCurrency();
  const formatCurrency = useCurrencyFormatter();
  const gainLossFormatter = useGainLossFormatter();
  const convertCurrency = useCurrencyConverter({
    sourceAssetRef: viewerAsset?.asset,
    nativeCurrency,
  });
  const formattedPercentChange = useFormatPercentChange(
    assetPercentChange,
    false,
    true,
    platformName,
  );
  const formattedAllocationPercent = formatNumber(assetAllocationPercent, {
    style: 'percent',
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });
  const isStableBalancesEligible = useStableBalancesEligible();

  const onMouseEnter = useCallback(
    () => preloadBundleForRoute('/accounts/x'),
    [],
  );

  //apr_2022_web_yield_asset experiment
  const rewards = useMemo(
    () => query.viewer.earn?.assets?.current ?? [],
    [query.viewer.earn?.assets],
  );
  const assetReward = useMemo(() => {
    return rewards.find(
      reward => reward?.assetV2?.asset.platformName === platformName,
    );
  }, [rewards, platformName]);

  const assetSymbolAndYield = assetReward?.assetV2?.rewardApy
    ? `${displaySymbol} · ${assetReward.assetV2?.rewardApy?.formattedValue} ${assetReward.assetV2?.rewardApy?.statsLabel}`
    : displaySymbol;

  const isMobile = useIsMobile();
  const history = useHistory();

  const nameColumn = useMemo(() => {
    let width = undefined;

    if (isStableBalancesEligible) {
      if (isMobile) {
        width = '50%';
      } else if (isTablet) {
        width = '38%';
      } else {
        width = '33%';
      }
    }

    return (
      <TableCell
        start={
          assetType === 'FIAT' || !assetImageUrl ? (
            <DeprecatedUnsafeCurrencyIcon symbol={platformName} size={32} />
          ) : (
            <CellMedia
              type="asset"
              source={assetImageUrl}
              title={displaySymbol}
            />
          )
        }
        title={assetName}
        subtitle={assetSymbolAndYield}
        innerSpacing={{ spacingStart: 3 }}
        width={width}
      />
    );
  }, [
    isStableBalancesEligible,
    assetType,
    assetImageUrl,
    platformName,
    displaySymbol,
    assetName,
    assetSymbolAndYield,
    isMobile,
    isTablet,
  ]);

  const formattedPrice = useMemo(() => {
    let amount: string | number | undefined = assetPrice;
    if (assetType === 'FIAT' && platformName) {
      const inputCurrency = { amount: '1', currency: platformName };
      amount = convertCurrency(inputCurrency, nativeCurrency);
    }
    return amount || assetPrice
      ? formatCurrency({
          isFiat: true,
          amount: {
            amount:
              assetType === 'FIAT' && amount
                ? String(amount)
                : String(assetPrice),
            currency: nativeCurrency,
          },
        })
      : '--';
  }, [
    assetPrice,
    assetType,
    convertCurrency,
    formatCurrency,
    nativeCurrency,
    platformName,
  ]);

  const priceColumn = useMemo(
    () => (
      <TableCell
        testID={`account-table-price-cell-${displaySymbol.toLowerCase()}`}
        title={formattedPrice}
        subtitle={
          formattedPercentChange.includes('0.00%') ? '' : formattedPercentChange
        }
        subtitleColor={assetPercentChange > 0 ? 'positive' : 'negative'}
      />
    ),
    [assetPercentChange, displaySymbol, formattedPercentChange, formattedPrice],
  );

  const formattedTotalBalanceInNativeCurrency = useMemo(
    () =>
      formatCurrency({
        isFiat: true,
        amount: {
          amount: assetBalanceInNativeCurrency,
          currency: nativeCurrency,
        },
      }),
    [assetBalanceInNativeCurrency, formatCurrency, nativeCurrency],
  );

  const formattedBalance = useMemo(
    () =>
      formatCurrency({
        isFiat: assetType === 'FIAT',
        amount: {
          amount: assetBalance,
          currency: displaySymbol,
        },
      }),
    [assetBalance, assetType, displaySymbol, formatCurrency],
  );

  const totalBalanceColumn = useMemo(() => {
    if (showBalanceFallback) {
      return (
        <TableCell
          testID={`balance-column-${displaySymbol.toLowerCase()}`}
          title={DEFAULT_FORMATTED_FALLBACK}
        />
      );
    }

    let subtitle;
    let subtitleColor: PaletteForeground | undefined;

    if (holdingColSubDetail === OptionKey.BALANCE) {
      subtitle = formattedBalance;
    }
    if (isMobile) {
      if (holdingColSubDetail === OptionKey.PERFORMANCE && allTimeGainLoss) {
        const { valueWithSign, variant } = gainLossFormatter(
          allTimeGainLoss.value,
          allTimeGainLoss.currency,
        );
        subtitleColor = variant;
        subtitle = valueWithSign;
      }
      if (
        holdingColSubDetail === OptionKey.PAST_DAY_PERFORMANCE &&
        pastDayGainLoss
      ) {
        const { valueWithSign, variant } = gainLossFormatter(
          pastDayGainLoss.value,
          pastDayGainLoss.currency,
        );
        subtitleColor = variant;
        subtitle = valueWithSign;
      }
    }
    return (
      <TableCell
        testID={`balance-column-${displaySymbol.toLowerCase()}`}
        title={formattedTotalBalanceInNativeCurrency}
        subtitle={subtitle}
        subtitleColor={subtitleColor}
      />
    );
  }, [
    holdingColSubDetail,
    isMobile,
    displaySymbol,
    formattedTotalBalanceInNativeCurrency,
    formattedBalance,
    allTimeGainLoss,
    pastDayGainLoss,
    showBalanceFallback,
    gainLossFormatter,
  ]);

  const allocationColumn = useMemo(
    () => <TableCell title={formattedAllocationPercent} />,
    [formattedAllocationPercent],
  );

  const performanceColumn = useMemo(() => {
    const gainLoss =
      perfColOptionKey === OptionKey.PAST_DAY_PERFORMANCE
        ? pastDayGainLoss
        : allTimeGainLoss;
    if (!gainLoss) {
      return <TableCell title="" />;
    }
    const { valueWithSign, variant } = gainLossFormatter(
      gainLoss.value,
      gainLoss.currency,
    );
    return (
      <TableCell
        testID="performance-column"
        title={valueWithSign}
        titleColor={variant}
      />
    );
  }, [allTimeGainLoss, gainLossFormatter, pastDayGainLoss, perfColOptionKey]);

  const onRowClick = useCallback(() => {
    let assetLink;
    if (onClick) {
      onClick({
        displaySymbol,
        assetImageUrl,
        assetKey,
        assetName,
        assetSlug,
        assetType,
      });
      return;
    } else if (assetSlug) {
      assetLink = assetPageUrl(assetSlug);
    } else if (assetKey) {
      assetLink = accountUrl(assetKey);
    } else {
      return;
    }

    history.push(assetLink);
  }, [
    onClick,
    assetSlug,
    assetKey,
    history,
    displaySymbol,
    assetImageUrl,
    assetName,
    assetType,
  ]);

  const inlineQuickActionColumn = useMemo(() => {
    if (
      !canConvert &&
      !canReceive &&
      !canSend &&
      !canBuy &&
      !canSell &&
      !canAddCash
    ) {
      // to prevent row divider inconsistencies
      return (
        <TableCell width="5%">
          <></>
        </TableCell>
      );
    }

    return (
      <td
        // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
        onClick={e => {
          e.stopPropagation();
        }}
        width="5%"
      >
        <Box spacingEnd={2}>
          <InlineQuickActions
            contractAddress={''}
            assetUuid={''}
            accountId={accountId}
            canSend={canSend}
            canReceive={canReceive}
            canBuy={canBuy}
            canSell={canSell}
            canConvert={canConvert}
            canAddCash={canAddCash}
            assetCode={displaySymbol}
            surface="assets"
          />
        </Box>
      </td>
    );
  }, [
    accountId,
    canAddCash,
    canBuy,
    canConvert,
    canReceive,
    canSell,
    canSend,
    displaySymbol,
  ]);

  const renderedActionButtonColumns = useMemo(() => {
    const actionButtonColumns =
      renderActionButtonColumns?.({
        canBuy,
        canSend,
        canReceive,
      }) || [];

    return actionButtonColumns?.map(column =>
      column ? (
        <TableActionButton
          label={column.label}
          color={column.color}
          // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
          onPress={() => {
            column.onPress({
              displaySymbol,
              assetImageUrl,
              assetKey,
              assetName,
              assetSlug,
              assetType,
            });
          }}
        />
      ) : (
        <TableCell title="" />
      ),
    );
  }, [
    assetImageUrl,
    assetKey,
    assetName,
    assetSlug,
    assetType,
    displaySymbol,
    canBuy,
    canSend,
    canReceive,
    renderActionButtonColumns,
  ]);

  return (
    <TableRow
      onMouseEnter={onMouseEnter}
      onPress={onRowClick}
      testID={`account-table-row-for-${displaySymbol.toLowerCase()}`}
    >
      {nameColumn}
      {totalBalanceColumn}
      {!isMobile && priceColumn}
      {!isMobile && showPerformanceColumn && performanceColumn}
      {!isMobile && !hideAllocationColumn && allocationColumn}
      {renderedActionButtonColumns.length > 0
        ? renderedActionButtonColumns
        : inlineQuickActionColumn}
    </TableRow>
  );
}

function AccountTableV2Row({
  queryRef,
  hideAllocationColumn,
  ...props
}: AccountTableV2RowProps) {
  const query = useFragment(
    graphql`
      fragment AccountTableV2RowFragment on Query {
