  children: React.ReactNode;
};

export const CRYPTO_ASSETS_SELECTED_COLUMNS = 'crypto_asset_selected_columns';

export function CryptoAssetsCustomTableDropdown({ children }: Props) {
  const { formatMessage } = useIntl();
  const dropdownRef = useRef<DropdownRefProps>(null);
  const { maxColumns, availableColumns, selectedColumns, toggleColumn } =
    useCryptoAssetsTable();

  const handleOnChange = useCallback(() => {
    dropdownRef?.current?.closeMenu();
  }, []);

  const dropdownItems = useMemo(() => {
    const handleOnChange = (e?: React.ChangeEvent<HTMLInputElement>) => {
      const checkedValue = e?.target.value as CryptoTableColumn;
      toggleColumn(checkedValue);

      // if maxColumns is 1 and the user is not unchecking the selected column
      // close automatically on selection
      if (
        maxColumns === 1 &&
        !selectedColumns.find(column => column.key === checkedValue)
      ) {
        dropdownRef?.current?.closeMenu();
      }
    };

    return availableColumns.map(column => {
      return (
        <Box
          key={column.key}
          as="label"
          justifyContent="space-between"
          spacingVertical={1}
          height="auto"
        >
          <TextLabel1 as="span" spacingEnd={4}>
            {column.label}
          </TextLabel1>
          <Checkbox
            value={column.key}
            onChange={handleOnChange}
            checked={column.selected}
          />
        </Box>
      );
    });
  }, [availableColumns, selectedColumns, toggleColumn, maxColumns]);

  const dropdownContent = useMemo(() => {
    return (
      <VStack spacing={2}>
        <TextLabel1 as="p" spacingBottom={1} color="foregroundMuted">
          {formatMessage(messages.customizeTable)}
        </TextLabel1>
        {dropdownItems}
      </VStack>
    );
  }, [dropdownItems, formatMessage]);

  return (
    <Dropdown
      ref={dropdownRef}
      content={dropdownContent}
      onChange={handleOnChange}
      testID="crypto-assets-column-dropdown"
      contentPosition={{
        placement: 'bottom-end',
        skid: 1,
        gap: 2,
      }}
    >
      {children}
    </Dropdown>
  );
}

