import { useMemo, memo, useCallback, useRef } from 'react';
import { compact, noop } from 'lodash';
import { useIntl } from 'react-intl';

import { useIsMobile } from '@cb/shared/utils';
import { IconButton } from '@cbhq/cds-web/buttons';
import { SelectOption } from '@cbhq/cds-web/controls';
import { Dropdown, DropdownRefProps } from '@cbhq/cds-web/dropdown';

import {
  InlineQuickActionsSurfaceType,
  useInlineQuickActionsButtonAnalytics,
  useInlineQuickActionsDropdownAnalytics,
} from './Analytics';
import useInlineQuickActionsMap, {
  QuickActionIds,
} from './useInlineQuickActionsMap';

export type InlineQuickActionsProps = {
  assetCode: string;
  accountId: string;
  canBuy?: boolean;
  canSell?: boolean;
  canConvert?: boolean;
  canSend?: boolean;
  canAddCash?: boolean;
  canCashOut?: boolean;
  canCashTransfer?: boolean;
  canReceive?: boolean;
  canReceiveDappWallet?: boolean;
  canOpenVault?: boolean;
  canStake?: boolean;
  canUnstake?: boolean;
  canDappWalletReceive?: boolean;
  onSelectionChange?: (option: QuickActionIds) => void;
  nativeCurrency?: string;
  surface: InlineQuickActionsSurfaceType;
  assetUuid: string;
  contractAddress: string;
  defiOnly?: boolean;
};

function InlineQuickActions({
  canConvert = false,
  canBuy = false,
  canSell = false,
  canSend = false,
  canReceive = false,
  canAddCash = false,
  canCashOut,
  canCashTransfer = false,
  canReceiveDappWallet = false,
  canOpenVault = false,
  canStake = false,
  canUnstake = false,
  canDappWalletReceive = false,
  defiOnly = false,
  assetCode,
  assetUuid,
  accountId,
  contractAddress,
  onSelectionChange = noop,
  nativeCurrency,
  surface,
}: InlineQuickActionsProps) {
  const isMobile = useIsMobile();
  const { formatMessage } = useIntl();

  const optionsMap = useInlineQuickActionsMap({
    assetSymbol: assetCode,
    nativeCurrency,
    accountId,
    assetUuid,
    contractAddress,
  });

  const options = useMemo(
    () =>
      defiOnly
        ? compact([optionsMap.dappWalletReceive])
        : compact([
            canBuy ? optionsMap.buy : null,
            canSell ? optionsMap.sell : null,
            canConvert ? optionsMap.convert : null,
            canCashTransfer ? optionsMap.cashTransfer : null,
            canSend ? optionsMap.send : null,
            canReceive ? optionsMap.receive : null,
            canAddCash ? optionsMap.addCash : null,
            // allow showing cashout when add cash is not in the menu
            canCashOut ?? canAddCash ? optionsMap.cashOut : null,
            canReceiveDappWallet ? optionsMap.dappWalletReceive : null,
            canOpenVault ? optionsMap.openVault : null,
            canStake ? optionsMap.stake : null,
            canDappWalletReceive ? optionsMap.dappWalletReceive : null,
            canUnstake ? optionsMap.unstake : null,
          ]),
    [
      defiOnly,
      canBuy,
      optionsMap.buy,
      optionsMap.sell,
      optionsMap.convert,
      optionsMap.cashTransfer,
      optionsMap.send,
      optionsMap.receive,
      optionsMap.addCash,
      optionsMap.cashOut,
      optionsMap.dappWalletReceive,
      optionsMap.openVault,
      optionsMap.stake,
      optionsMap.unstake,
      canSell,
      canConvert,
      canCashTransfer,
      canSend,
      canReceive,
      canAddCash,
      canCashOut,
      canReceiveDappWallet,
      canOpenVault,
      canStake,
      canDappWalletReceive,
      canUnstake,
    ],
  );

  const trackOptionClick = useInlineQuickActionsButtonAnalytics();

  const content = useMemo(
    () =>
      options.map(option => (
        <SelectOption
          key={option.id}
          value={option.id}
          // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
          onPress={() => {
            trackOptionClick({ componentName: option.id, surface });
            onSelectionChange?.(option.id);
            option.onPress?.();
          }}
          title={formatMessage(option.title, option.titleValues ?? {})}
        />
      )),
    [formatMessage, onSelectionChange, options, surface, trackOptionClick],
  );

  const dropdownRef = useRef<DropdownRefProps>(null);

  const handleOnChange = useCallback(() => {
    dropdownRef?.current?.closeMenu();
  }, []);

  const trackInlineMenuViewed = useInlineQuickActionsDropdownAnalytics();

  const handleOnMenuOpen = useCallback(() => {
    trackInlineMenuViewed({
      surface,
      options: options.map(option => option.id),
    });
  }, [options, surface, trackInlineMenuViewed]);

  if (options.length === 0) {
    return null;
  }

  return (
    <Dropdown
      testID="inline-quick-actions-dropdown"
      ref={dropdownRef}
      onChange={handleOnChange}
      content={content}
      enableMobileModal={isMobile}
      onOpenMenu={handleOnMenuOpen}
    >
      <IconButton
        testID="inline-quick-actions"
        compact
        transparent
        name="more"
      />
    </Dropdown>
  );
}

export default memo(InlineQuickActions);

