const DAY_IN_MS = 24 * 60 * 60 * 1000;

type Props = {
  userAttestation: UserAttestation;
  onAttestationRevoke: (userAttestationUuid: string) => void;
  onAttestationStateChange: (
    state: UserAttestationState | null | undefined,
  ) => void;
  showViewAttributes?: boolean;
};

function EligibleAttestationCardEntry({
  userAttestation,
  onAttestationRevoke,
  onAttestationStateChange,
  showViewAttributes,
}: Props) {
  const [visible, { toggle }] = useToggler();
  const { formatMessage, formatDate } = useIntl();
  const formatAddress = useFormatAddress();
  const getUserAttestationStatus = useGetUserAttestationStatus();

  const handleRevokeButtonPress = useCallback(() => {
    onAttestationRevoke(userAttestation.uuid);
  }, [onAttestationRevoke, userAttestation.uuid]);

  const isRevocable = useMemo(() => {
    return (
      userAttestation.state === 'ISSUED' &&
      userAttestation.issuedAt !== null &&
      Date.now() - new Date(userAttestation.issuedAt).getTime() > DAY_IN_MS
    );
  }, [userAttestation.state, userAttestation.issuedAt]);
  const isInactive = useMemo(
    () =>
      userAttestation.state === 'ISSUING' ||
      userAttestation.state === 'STATE_UNSPECIFIED',
    [userAttestation.state],
  );

  return (
    <>
      <VStack spacingVertical={3}>
        <HStack alignItems="center" justifyContent="space-between">
          <TextBody as="p">{formatMessage(messages.addressAltLabel)}</TextBody>
          {isInactive ? (
            <TextBody as="p" color="foregroundMuted">
              {formatAddress(userAttestation.recipient)}
            </TextBody>
          ) : (
            <PressableOpacity
              to={`https://${
                isProductionTarget() ? 'base' : 'base-sepolia'
              }.easscan.org/attestation/view/${userAttestation.externalId}`}
              target="_blank"
            >
              <HStack spacerGap={1} alignItems="center">
                <TextBody as="p">
                  {formatAddress(userAttestation.recipient)}
                </TextBody>
                <Icon name="externalLink" size="s" color="foreground" />
