            </PressableOpacity>
          )}
        </HStack>
        <Spacer vertical={2} />
        <HStack alignItems="center" justifyContent="space-between">
          <TextBody as="p">{formatMessage(messages.statusLabel)}</TextBody>
          <TextBody
            as="p"
            color={isInactive ? 'foregroundMuted' : 'foreground'}
          >
            {getUserAttestationStatus(userAttestation.state)}
          </TextBody>
        </HStack>
        <Spacer vertical={2} />
        <HStack alignItems="center" justifyContent="space-between">
          <TextBody as="p">{formatMessage(messages.verifiedOnLabel)}</TextBody>
          <TextBody
            as="p"
            color={isInactive ? 'foregroundMuted' : 'foreground'}
          >
            {!isInactive
              ? formatDate(userAttestation.issuedAt, {
                  year: 'numeric',
                  month: '2-digit',
                  day: '2-digit',
                })
              : '-'}
          </TextBody>
        </HStack>
        <Spacer vertical={2} />
        {showViewAttributes ? (
          <>
            <PressableOpacity onPress={toggle} transparentWhilePressed>
              <HStack
                alignItems="center"
                justifyContent="space-between"
                spacingVertical={1}
              >
                <TextBody as="p">
                  {formatMessage(messages.attributesLabel)}
                </TextBody>
                {isInactive ? (
                  <TextBody as="p" color="foregroundMuted">
                    -
                  </TextBody>
                ) : (
                  <Icon
                    size="s"
                    color="foreground"
                    name={visible ? 'caretUp' : 'caretDown'}
                  />
                )}
              </HStack>
            </PressableOpacity>
            <Collapsible collapsed={!visible}>
              <VStack>
                <TextLabel2 as="p" color="foregroundMuted">
                  {formatMessage(messages.attributesAltDescription)}
                </TextLabel2>
                <Spacer vertical={3} />
                <UserAttestationAttributes userAttestation={userAttestation} />
              </VStack>
            </Collapsible>
            <Spacer vertical={2} />
          </>
        ) : undefined}
        <Button
          variant="secondary"
          onPress={handleRevokeButtonPress}
          disabled={!isRevocable}
        >
          {formatMessage(messages.revokeButton)}
        </Button>
      </VStack>
      <UserAttestationRefresh
        userAttestationUuid={userAttestation.uuid}
        onAttestationStateChange={onAttestationStateChange}
      />
    </>
  );
}

export default memo(EligibleAttestationCardEntry);

