function ConfirmationStep() {
  const { formatMessage } = useIntl();
  const { goToStep } = useStepper(stepper);
  const { closeModal, userAttestationUuid, onRevokeRequestSuccess } =
    useContext(RevokeAttestationModalContext);
  const [revokeUserAttestation, isRevokeUserAttestationInFlight] =
    useRevokeUserAttestation();

  const handleConfirmButtonPress = useCallback(async () => {
    try {
      const revokedUserAttestationUuid = await revokeUserAttestation(
        userAttestationUuid,
      );

      if (revokedUserAttestationUuid !== null) {
        if (onRevokeRequestSuccess !== undefined) {
          onRevokeRequestSuccess();
        }
        goToStep('revokingStep');
      }
    } catch (err) {
      // Fail silently
      /**
       * Fails silently, if this changes please change comment in
       * useRevokeUserAttestation.tsx
       */
    }
  }, [
    goToStep,
    revokeUserAttestation,
    userAttestationUuid,
    onRevokeRequestSuccess,
  ]);

  const handleCloseButtonPress = useCallback(() => {
    closeModal();
  }, [closeModal]);

  return (
    <>
      <HStack
        spacing={3}
        justifyContent="center"
        alignItems="center"
        position="relative"
      >
        <TextTitle3 as="p">
          {formatMessage(messages.revokeConfirmTitle)}
        </TextTitle3>
        <Box
          position="absolute"
          height="100%"
          right={0}
          alignItems="center"
          justifyContent="center"
          spacingEnd={3}
        >
          <IconButton name="close" onPress={closeModal} transparent />
        </Box>
      </HStack>
      <Spacer vertical={3} />
      <VStack spacing={3} alignItems="center">
        <HeroSquare name="coinCheckmark" />
        <Spacer vertical={3} />
        <TextBody align="center" color="foregroundMuted" as="p">
          {formatMessage(messages.revokeConfirmBody)}
        </TextBody>
        <Spacer vertical={4} />
        <Button
          block
          variant="primary"
          onPress={handleConfirmButtonPress}
          disabled={isRevokeUserAttestationInFlight}
        >
          {formatMessage(messages.confirmButton)}
        </Button>
        <Spacer vertical={2} />
        <Button
          block
          variant="secondary"
          onPress={handleCloseButtonPress}
