const PAGE_SIZE = 10;

type TransactionRowsProps = {
  query: string;
  statuses?: Set<TransactionStatus>;
  startDate: Date;
  numFiltersApplied: number;
  setNumTransactionsDisplayed: (numTransactionsDisplayed: number) => void;
  queryRef: CBCardTransactionsFragment$key;
};

function TransactionRows({
  query,
  statuses = new Set(),
  startDate,
  numFiltersApplied,
  setNumTransactionsDisplayed,
  queryRef,
}: TransactionRowsProps) {
  logSearchText(query);

  const { data, loadNext, hasNext, isLoadingNext, refetch } =
    usePaginationFragment<
      CBCardTransactionsRefetchable,
      CBCardTransactionsFragment$key
    >(
      graphql`
        fragment CBCardTransactionsFragment on Query
        @argumentDefinitions(
          query: { type: "String" }
          statuses: { type: "[CardTransactionStatus!]" }
          first: { type: "Int!" }
          after: { type: "String" }
        )
        @refetchable(queryName: "CBCardTransactionsRefetchable") {
          viewer {
            card @required(action: THROW) {
              transactions(
                query: $query
                statuses: $statuses
                first: $first
                after: $after
              )
                @connection(key: "Query_transactions")
                @required(action: THROW) {
                edges {
                  node {
                    ...CBCardTransactionRowFragment
                    uuid
                    createdAt
                  }
                }
                pageInfo {
                  hasNextPage
                }
              }
            }
          }
        }
      `,
      queryRef,
    );

  useEffect(() => {
    refetch({ first: PAGE_SIZE, query, statuses: [...statuses] });
  }, [query, statuses]);

  const loadMoreItems = useCallback(() => {
    if (hasNext) {
      return loadNext(PAGE_SIZE);
    } else {
      return null;
    }
  }, [hasNext, loadNext]);

  const transactions = data.viewer.card.transactions.edges;

  const filteredTransactions = useMemo(
    () =>
      transactions.filter(
        transaction => new Date(transaction.node?.createdAt || '') > startDate,
      ) || [],
    [startDate, transactions],
  );

  useEffect(() => {
    setNumTransactionsDisplayed(filteredTransactions.length);
  }, [filteredTransactions.length]);

  if (transactions.length === 0) {
    if (numFiltersApplied !== 0 && filteredTransactions.length === 0) {
      return <NoFilteredTransactions />;
    } else if (query.length > 0 && filteredTransactions.length === 0) {
      return <NoFilteredTransactions />;
    }
    return <EmptyTransactions />;
  }

  const transactionRows = filteredTransactions.map((transaction, index) => {
    if (!transaction.node) {
      // TODO Fix with @required once the data-layer
      // supports it inside a connection.
      throw new Error('transactionNode is empty');
    }
    return (
      <CBCardTransactionRow
        cardTransactionRef={transaction.node}
        hasBottomBorder={index < filteredTransactions.length - 1}
        key={transaction.node.uuid}
      />
    );
  });

  return (
    <VStack maxHeight={700} overflow="scroll">
      <InfiniteScroll
        isLoading={isLoadingNext}
        getMoreItems={loadMoreItems}
        spinner={isLoadingNext ? <ActivityListCellFallback /> : null}
        forceObserve={hasNext}
        scrollable
      >
        {transactionRows}
      </InfiniteScroll>
    </VStack>
  );
}

const defaultStartDate = new Date(0);

const tomorrow = getDateTomorrow();

function CoinbaseCardEventsContent({ queryRef }: CoinbaseCardEventsProps) {
  const { formatMessage } = useIntl();
  const [query, setQuery] = useState('');

  const debouncedQuery = useDebounce(query, 300);
  const [numTransactionsDisplayed, setNumTransactionsDisplayed] = useState(0);

  const allTransactionsOption: DateRangeOption = useMemo(() => {
    return {
      start: defaultStartDate,
      end: tomorrow,
      optionText: formatMessage(messages.allTransactionsOption),
      id: 'allTransactionsOption',
    };
  }, [formatMessage]);

  const [selectedTransactionStatuses, setSelectedTransactionStatuses] =
    useState<Set<TransactionStatus>>(new Set());

  const [selectedDateOption, setSelectedDateOption] = useState(
    allTransactionsOption,
  );

  const numFiltersApplied = useMemo(() => {
    let filtersCount = 0;
    if (
      // increment unless all or none of the transaction statuses are selected
      selectedTransactionStatuses.size !== 5 &&
      selectedTransactionStatuses.size > 0
    ) {
      filtersCount++;
    }
    if (
      selectedDateOption.start.toDateString() !==
        defaultStartDate.toDateString() ||
      selectedDateOption.end.toDateString() !== tomorrow.toDateString()
    ) {
      filtersCount++;
    }
    return filtersCount;
  }, [selectedDateOption, selectedTransactionStatuses.size]);

  const { showModal } = useModal();
  const openModal = useCallback(() => {
    showModal(
      <FiltersModal
        selectedStatuses={selectedTransactionStatuses}
        onChangeStatuses={setSelectedTransactionStatuses}
        selectedDateOption={selectedDateOption}
        onChangeDateRange={setSelectedDateOption}
      />,
    );
  }, [selectedDateOption, selectedTransactionStatuses, showModal]);

  const hasFiltersExperiment = useFiltersExperiment();

  const handleOnChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => setQuery(e.target.value),
    [],
  );

  const handleClearQuery = useCallback(() => setQuery(''), []);

  return (
    <VStack
      width="100%"
      bordered
      borderRadius="rounded"
      background="background"
    >
      <CardRow hasBottomBorder spacingEnd={0} spacingBottom={0}>
        <VStack
          flexBasis={1}
          flexGrow={1}
          spacingStart={3}
          offsetHorizontal={3}
          spacerGap={1}
        >
          <CardHeader>{formatMessage(messages.transactions)}</CardHeader>
          {hasFiltersExperiment ? (
            <HStack
              spacingTop={1}
              spacerGap={1}
              spacingBottom={1}
              spacingEnd={2}
            >
              <StyledClearableSearchBar
                type="small"
                query={query}
                onChange={handleOnChange}
                clearQuery={handleClearQuery}
                placeholder={'Search'}
              />
              <Box spacingTop={0.5}>
                <DotCount
                  count={numFiltersApplied}
                  pin="top-end"
                  overlap="circular"
                >
                  <IconButton
                    name="filter"
                    onPress={openModal}
                    testID="filters-modal-icon-button"
                    transparent
                  />
                </DotCount>
              </Box>
            </HStack>
          ) : null}
        </VStack>
      </CardRow>
      <InstrumentedSuspense
        instrumentationId="TransactionRows"
        fallback={
          <DelayedLoading delay={400}>
            <TransactionsLoadingFallback
              numFallbacks={numTransactionsDisplayed}
            />
          </DelayedLoading>
        }
      >
        <TransactionRows
          query={debouncedQuery}
          statuses={selectedTransactionStatuses}
          startDate={selectedDateOption.start}
          setNumTransactionsDisplayed={setNumTransactionsDisplayed}
          numFiltersApplied={numFiltersApplied}
          queryRef={queryRef}
        />
      </InstrumentedSuspense>
    </VStack>
  );
}

