import { notifyError } from '@cb/shared/utils/notifyError';
import { ListCell } from '@cbhq/cds-web/cells/ListCell';
import { Switch } from '@cbhq/cds-web/controls/Switch';
import { getErrorInstance } from '@cbhq/common-web/utils/notifyError';
import { graphql, useFragment } from '@cbhq/data-layer';

import useModal from 'hooks/useModal';

import { LazyLockCard } from '../../flows/LockCard';
import useLockCard from '../../flows/LockCard/hooks/useLockCard';
import messages from '../../messages';
import { LockCardRowFragment$key } from './__generated__/LockCardRowFragment.graphql';

type Props = {
  cardRef: LockCardRowFragment$key;
};

function LockCardRow({ cardRef }: Props) {
  const { formatMessage } = useIntl();
  const { updateCardLocked, isUpdating } = useLockCard();
  const { showModal } = useModal();

  const query = useFragment(
    graphql`
      fragment LockCardRowFragment on Card {
        cardSummary @required(action: THROW) {
          locked
        }
      }
    `,
    cardRef,
  );

  const locked = query.cardSummary.locked;

  const onClick = useCallback(() => {
    if (locked) {
      updateCardLocked({
        variables: { input: { lockCard: false } },
        onError: error =>
          notifyError(getErrorInstance(error), {
            owner: 'card',
            context: 'coinbase_card',
          }),
      });
    } else {
      showModal(<LazyLockCard />);
    }
  }, [locked, updateCardLocked, showModal]);

  return (
    <ListCell
      title={formatMessage(messages.lockCard)}
      action={
        <Switch
          checked={locked}
          onChange={onClick}
          title={formatMessage(messages.lockCard)}
          disabled={isUpdating}
        />
      }
    />
  );
}

export default memo(LockCardRow);

