import messages from '../../messages';
import { AbsoluteLoadingRow, LoadingRow, RelativeSpan } from '../../styles';
import { ManageCardFragment$key } from './__generated__/ManageCardFragment.graphql';
import LockCardRow from './LockCardRow';

type Props = {
  showCardNumber: boolean;
  setShowCardNumber: (show: React.ChangeEvent<HTMLInputElement>) => void;
  needsActivation: boolean;
  isOrdered: boolean | null;
  queryRef: ManageCardFragment$key;
};

function ManageCard({
  showCardNumber,
  setShowCardNumber,
  needsActivation,
  isOrdered,
  queryRef,
}: Props) {
  const { formatMessage } = useIntl();
  const { showModal } = useModal();
  const { bootstrapped, hasError } = useMarqeta();

  const query = useFragment(
    graphql`
      fragment ManageCardFragment on Query {
        viewer {
          card @required(action: THROW) {
            ...LockCardRowFragment
          }
        }
      }
    `,
    queryRef,
  );

  const card = query.viewer.card;
  const hasDefaultToVirtualCardFlow = useDefaultToVirtualCardFlow();

  const handleOnPress = useCallback(
    () => showModal(<LazyActivation />),
    [showModal],
  );

  const handleOnPress1 = useCallback(
    () => showModal(<LazySetPin />),
    [showModal],
  );

  const handleOnPress2 = useCallback(
    () => showModal(<LazyReplaceCard />),
    [showModal],
  );

  return (
    <VStack bordered borderRadius="rounded" background="background">
      <CardRow hasBottomBorder>
        <CardHeader>{formatMessage(messages.manageCard)}</CardHeader>
      </CardRow>
      {/* show card number row */}
      {!bootstrapped ? (
        <LoadingRow />
      ) : (
        <Box borderedBottom>
          <ListCell
            disabled={!bootstrapped || hasError}
            title={formatMessage(messages.showCardNumber)}
            action={
              <Switch
                checked={showCardNumber}
                onChange={setShowCardNumber}
                title={formatMessage(messages.showCardNumber)}
              />
            }
          />
        </Box>
      )}
      {/* copy card number row */}
      <StyledRelativeSpan>
        {!bootstrapped && <AbsoluteLoadingRow />}
        <Box borderedBottom>
          <ListCell
            disabled={!bootstrapped || hasError}
            title={formatMessage(messages.copyCardNumber)}
            detail={
              <StyledInnerRelativeSpan id={COPY_PAN_CONTAINER_ID}>
                <IconButton name="copy" variant="secondary" transparent />
              </StyledInnerRelativeSpan>
            }
          />
        </Box>
      </StyledRelativeSpan>
      {/* activate coinbase card row */}
      {needsActivation && (
        <Box borderedBottom>
          <ListCell
            onPress={handleOnPress}
            accessory="arrow"
            title={formatMessage(messages.activateCard)}
          />
        </Box>
      )}
      {/* lock card row */}
      <Box borderedBottom>
        <LockCardRow cardRef={card} />
      </Box>
      {/* set pin row */}
      {hasDefaultToVirtualCardFlow && !isOrdered ? null : (
        <Box borderedBottom>
          <ListCell
            onPress={handleOnPress1}
            accessory="arrow"
            title={formatMessage(messages.changePin)}
            description={formatMessage(messages.updatePin)}
          />
        </Box>
      )}
      {/* contact support row */}
      <ListCell
        onPress={handleOnPress2}
        accessory="arrow"
        title={formatMessage(messages.support)}
        description={formatMessage(messages.supportReachOut)}
      />
    </VStack>
  );
}

