const i18nKey = 'LinkoutModule';

const messages = defineMessages({
  refresh: {
    id: `${i18nKey}.refresh`,
    defaultMessage: 'Refresh',
    description: `#Component: Label
    #CharLimit: 25
    #Context: Refresh NFT metadata button`,
  },
  viewTransaction: {
    id: `${i18nKey}.viewTransaction`,
    defaultMessage: 'View transaction',
    description: `#Component: Label
    #CharLimit: 25
    #Context: Link out copy for opening the NFT in the block scan site`,
  },
  refreshDataToast: {
    id: `${i18nKey}.refreshDataToast`,
    defaultMessage:
      'Data will refresh soon. This may take several minutes to complete.',
    description: `#Component: Body
    #CharLimit: none
    #Context: Successful refresh metadata message displayed to the user`,
  },
  refreshDataErrorToast: {
    id: `${i18nKey}.refreshDataErrorToast`,
    defaultMessage: 'Refresh data failed. Try again later.',
    description: `#Component: Body
    #CharLimit: none
    #Context: Message displayed to the user when refresh metadata api failed`,
  },
});

type LinkoutModuleProps = {
  defiNFTRef: LinkoutModuleFragment$key;
  refresh: () => Promise<void>;
  isRefreshing: boolean;
};

export function LinkoutModule({
  defiNFTRef,
  refresh,
  isRefreshing,
}: LinkoutModuleProps) {
  const { formatMessage } = useIntl();
  const toast = useToast();

  const details = useFragment(
    graphql`
      fragment LinkoutModuleFragment on DefiNFT {
        uuid @required(action: THROW)
      }
    `,
    defiNFTRef,
  );

  const onRefreshPress = useCallback(async () => {
    if (isRefreshing) {
      return;
    }

    toast.clearQueue();

    try {
      await refresh();
      toast.show(formatMessage(messages.refreshDataToast));
    } catch (e) {
      toast.show(formatMessage(messages.refreshDataErrorToast));
    }
  }, [formatMessage, isRefreshing, refresh, toast]);

  const linkoutUrl = useMemo(
    () => buildBlockScanUrl(details?.uuid),
    [details?.uuid],
  );

  const styling = useMemo<CellSpacing>(
    () => ({
      spacingHorizontal: 0,
      spacingVertical: 0,
    }),
    [],
  );

  return (
    <VStack spacing={3} borderedBottom>
      <ListCell
        media={
          <IconButton
            name="refresh"
            onPress={onRefreshPress}
            testID="refresh-button"
          />
        }
        title={formatMessage(messages.refresh)}
        outerSpacing={styling}
        compact
      />
      <ListCell
        media={
          <IconButton
            name="externalLink"
            to={linkoutUrl}
            target="_blank"
            testID="linkout-button"
            rel="noopener,noreferrer"
            aria-label={formatMessage(messages.viewTransaction)}
          />
        }
        title={formatMessage(messages.viewTransaction)}
        outerSpacing={styling}
        compact
      />
    </VStack>
  );
}

