      fragment CardComponents_DetailsHeaderFragment on LoyaltyCard {
        details {
          label
          value
        }
        table {
          title
          ...InfoModalFragment
        }
      }
    `,
    loyaltyCardRef,
  );

  if (!details || details.length === 0) return null;

  return (
    <Row>
      {details.map((d, i) => (
        <Cell key={i}>
          <Box alignItems="center">
            {i === 1 && table && table.title !== '' ? (
              <RewardModalTrigger
                label={
                  <TextLegal as="p" color="foregroundMuted">
                    {d?.label}
                  </TextLegal>
                }
                modal={
                  <InfoModal loyaltyTableRef={table} cardName={cardName} />
                }
              />
            ) : (
              <TextLegal as="p" color="foregroundMuted">
                {d?.label}
              </TextLegal>
            )}
          </Box>
        </Cell>
      ))}
    </Row>
  );
}

