import { useCallback, useMemo, useState } from 'react';
import styled from 'styled-components';

import { useIsMobile } from '@cb/shared/utils';
import { HeroSquareName, SpotSquareName } from '@cbhq/cds-common';
import { IconButton } from '@cbhq/cds-web/buttons';
import { HeroSquare, SpotSquare } from '@cbhq/cds-web/illustrations';
import { Box, HStack, VStack } from '@cbhq/cds-web/layout';
import { deviceMqRanges } from '@cbhq/cds-web/layout/breakpoints';
import { RemoteImage } from '@cbhq/cds-web/media';
import { FullscreenModal } from '@cbhq/cds-web/overlays';
import {
  TextBody,
  TextTitle1,
  TextTitle3,
  TextTitle4,
} from '@cbhq/cds-web/typography';
import { graphql, useFragment } from '@cbhq/data-layer';

import { StepIndicator } from 'views/Earn/components/StepIndicator';

import { StaticLessonCardFragment$key } from './__generated__/StaticLessonCardFragment.graphql';
import { StaticLessonFragment$key } from './__generated__/StaticLessonFragment.graphql';

type StaticLessonProps = {
  earnStaticLessonRef: StaticLessonFragment$key;
  onClose: () => void;
  isVisible: boolean;
  isLessonCompleted: boolean;
  loyaltyCardRef: StaticLessonCardFragment$key;
  toggleQuizOn: () => void;
};

export function StaticLesson({
  earnStaticLessonRef,
  onClose,
  isVisible,
  isLessonCompleted,
  loyaltyCardRef,
  toggleQuizOn,
}: StaticLessonProps) {
  const [currentScreenIndex, setCurrentScreenIndex] = useState(0);
  const isMobile = useIsMobile();
  const data = useFragment(
    graphql`
      fragment StaticLessonFragment on EarnStaticLesson {
        screens {
          title
          body
          imageUrl
        }
      }
    `,
    earnStaticLessonRef,
  );

  const cardQuery = useFragment(
    graphql`
      fragment StaticLessonCardFragment on LoyaltyCard {
        title
      }
    `,
    loyaltyCardRef,
  );

  const lessonScreens = useMemo(() => data.screens || [], [data.screens]);

  const currentScreen = useMemo(
    () => lessonScreens[currentScreenIndex],
    [currentScreenIndex, lessonScreens],
  );

  const handleNextScreen = useCallback(() => {
    if (currentScreenIndex === lessonScreens.length - 1 && !isLessonCompleted) {
      toggleQuizOn();
    } else {
      setCurrentScreenIndex(screenIndex => screenIndex + 1);
    }
  }, [
    currentScreenIndex,
    isLessonCompleted,
    lessonScreens.length,
    toggleQuizOn,
  ]);

  const handlePreviousScreen = useCallback(() => {
    setCurrentScreenIndex(screenIndex => screenIndex - 1);
  }, []);

  const showNextScreenButton =
    currentScreenIndex !== lessonScreens.length - 1 ? true : !isLessonCompleted;

  const progressBars = useMemo(
    () => (
      <Box spacingTop={isMobile ? 0 : 9} spacingHorizontal={3}>
        <StepIndicator
          numOfSteps={lessonScreens.length}
          currentStepIndex={currentScreenIndex}
          size={isMobile ? 'normal' : 'large'}
        />
      </Box>
    ),
    [currentScreenIndex, isMobile, lessonScreens],
  );

  const primaryContent = useMemo(
    () => (
      <VStack
        alignItems="center"
        height="100%"
        width="100%"
        justifyContent="center"
        background="secondary"
        spacingVertical={isMobile ? 3 : 0}
        spacerGap={isMobile ? 5 : 0}
      >
        {isMobile && progressBars}
        <HeroSquare
          testID="LoyaltyStaticLessonLayout-HeroSquare"
          name={currentScreen?.imageUrl as HeroSquareName}
          scaleMultiplier={isMobile ? 1 : 1.25}
          dimension="240x240"
          fallback={
            <SpotSquare
              testID="LoyaltyStaticLessonLayout-SpotSquare"
              scaleMultiplier={isMobile ? 2.5 : 3.125}
              name={currentScreen?.imageUrl as SpotSquareName}
              dimension="96x96"
              fallback={
                <RemoteImage
                  width={isMobile ? 240 : 300}
                  height={isMobile ? 240 : 300}
                  source={currentScreen?.imageUrl ?? ''}
                />
              }
            />
          }
        />
      </VStack>
    ),
    [currentScreen?.imageUrl, isMobile, progressBars],
  );

  const secondaryContent = useMemo(
    () => (
      <VStack
        spacing={3}
        justifyContent="space-between"
        height="100%"
        flexGrow={1}
      >
        {!isMobile && progressBars}
        <VStack spacerGap={1} spacingHorizontal={3}>
          {isMobile ? (
            <TextTitle3 as="p">{currentScreen?.title}</TextTitle3>
          ) : (
            <TextTitle1 as="p">{currentScreen?.title}</TextTitle1>
          )}
          {isMobile ? (
            <TextBody as="p">{currentScreen?.body}</TextBody>
          ) : (
            <TextTitle4 as="p">{currentScreen?.body}</TextTitle4>
          )}
        </VStack>
        <HStack
          justifyContent={
            currentScreenIndex !== 0 ? 'space-between' : 'flex-end'
          }
        >
          {currentScreenIndex !== 0 && (
            <IconButton
              name="backArrow"
              compact
              variant="secondary"
              onPress={handlePreviousScreen}
              testID="static-lesson-back-button"
            />
          )}
          {showNextScreenButton && (
            <IconButton
              name="forwardArrow"
              compact
              variant="secondary"
              onPress={handleNextScreen}
              testID="static-lesson-next-button"
            />
          )}
        </HStack>
      </VStack>
    ),
    [
      currentScreen?.body,
      currentScreen?.title,
      currentScreenIndex,
      handleNextScreen,
      handlePreviousScreen,
      isMobile,
      progressBars,
      showNextScreenButton,
    ],
  );

  return (
    <StyledFullscreenModal
      title={cardQuery.title}
      visible={isVisible}
      onRequestClose={onClose}
      primaryContent={primaryContent}
      secondaryContent={secondaryContent}
      showSecondaryContentDivider
      testID="static-lesson-modal"
    />
  );
}

type StyledFullscreenModalProps = Omit<
  React.ComponentProps<typeof FullscreenModal>,
  'dangerouslySetContentClassName'
> & {
  className?: string;
};

export const StyledFullscreenModal = styled(
  ({ className, ...props }: StyledFullscreenModalProps) => (
    <FullscreenModal dangerouslySetContentClassName={className} {...props} />
  ),
)`
  margin-left: 0;
  padding: 0;

  @media ${deviceMqRanges.phone} {
    height: 100%;

    .fsm-primary-content-container,
    .fsm-secondary-content-container {
      height: 50%;
    }
  }

  .fsm-primary-content-container,
  .fsm-secondary-content-container {
    /* stylelint-disable declaration-no-important -- override CDS */
    padding: 0 !important;
    margin: 0;
    max-width: 100%;
  }

  .fsm-secondary-content-container {
    width: 100% !important;
  }
`;

import { useCallback, useEffect, useMemo, useState } from 'react';
import styled from 'styled-components';

import { Video } from '@cb/shared/components/Video';
import { useIsMobile } from '@cb/shared/utils';
import { IconButton } from '@cbhq/cds-web/buttons';
import { HStack, VStack } from '@cbhq/cds-web/layout';
import {
  TextBody,
  TextTitle1,
  TextTitle3,
  TextTitle4,
} from '@cbhq/cds-web/typography';
import { graphql, useFragment } from '@cbhq/data-layer';

import { earnFlow, useEarnAdvanceEvent } from 'views/Earn/analytics';
import { EarnCampaignType } from 'views/Earn/types';

import { VideoLessonCardFragment$key } from './__generated__/VideoLessonCardFragment.graphql';
import { VideoLessonFragment$key } from './__generated__/VideoLessonFragment.graphql';
import { StyledFullscreenModal } from './StaticLesson';

type VideoLessonProps = {
  viewerAssetRef: VideoLessonFragment$key;
  onClose: () => void;
  isVisible: boolean;
  isLessonCompleted: boolean;
  toggleQuizOn: () => void;
  loyaltyCardRef: VideoLessonCardFragment$key;
  assetSlug: string;
  campaignSlug: string;
  lessonIndex: string;
  lessonType: EarnCampaignType;
};

export function VideoLesson({
  viewerAssetRef,
  onClose,
  isVisible,
  isLessonCompleted,
  toggleQuizOn,
  loyaltyCardRef,
  assetSlug,
  campaignSlug,
  lessonIndex,
  lessonType,
}: VideoLessonProps) {
  const isMobile = useIsMobile();
  const [shouldShowVideo, setShouldShowVideo] = useState(true);
  const viewerAsset = useFragment(
    graphql`
      fragment VideoLessonFragment on ViewerAsset
      @argumentDefinitions(
        index: { type: "Int!" }
        campaignSlug: { type: "String" }
      ) {
        earnLessonByIndex(index: $index, campaignSlug: $campaignSlug)
          @required(action: THROW) {
          earnLesson {
            displayData {
              ... on EarnVideoLesson {
                title
                body
                video {
                  videoUrl
                  height
                  width
                }
              }
            }
          }
        }
      }
    `,
    viewerAssetRef,
  );

  const earnAnalyticsAdvanceEvent = useEarnAdvanceEvent({
    lessonType,
    flow: earnFlow.Lesson,
    currency: assetSlug,
    campaignSlug,
    lessonIndex,
    isComplete: false,
  });

  const cardQuery = useFragment(
    graphql`
      fragment VideoLessonCardFragment on LoyaltyCard {
        title
      }
    `,
    loyaltyCardRef,
  );

  const videoLesson = viewerAsset.earnLessonByIndex.earnLesson.displayData;

  useEffect(() => {
    // Reenable video
    if (!shouldShowVideo) {
      setShouldShowVideo(true);
    }
  }, [shouldShowVideo]);

  const handlePress = useCallback(() => {
    earnAnalyticsAdvanceEvent();
    toggleQuizOn();
    // Disables video when quiz is toggled on
    setShouldShowVideo(false);
  }, [earnAnalyticsAdvanceEvent, toggleQuizOn]);

  const primaryContent = useMemo(() => {
    const ratio =
      (videoLesson.video?.width ?? 1) / (videoLesson.video?.height ?? 1);
    return (
      <VStack
        alignItems="center"
        height="100%"
        width="100%"
        justifyContent="center"
        spacingVertical={isMobile ? 3 : 0}
      >
        {shouldShowVideo && videoLesson.video?.videoUrl && (
          <VideoWrapper>
            <Video
              src={videoLesson.video?.videoUrl}
              ratio={ratio}
              title={videoLesson.title}
            />
          </VideoWrapper>
        )}
      </VStack>
    );
  }, [
    isMobile,
    shouldShowVideo,
    videoLesson.title,
    videoLesson.video?.height,
    videoLesson.video?.videoUrl,
    videoLesson.video?.width,
  ]);

  const secondaryContent = useMemo(
    () => (
      <VStack spacing={3} height="100%">
        <VStack
          spacerGap={1}
          spacingHorizontal={3}
          flexGrow={1}
          justifyContent="center"
        >
          {isMobile ? (
            <TextTitle3 as="p">{videoLesson?.title}</TextTitle3>
          ) : (
            <TextTitle1 as="p">{videoLesson?.title}</TextTitle1>
          )}
          {isMobile ? (
            <TextBody as="p">{videoLesson?.body}</TextBody>
          ) : (
            <TextTitle4 as="p">{videoLesson?.body}</TextTitle4>
          )}
        </VStack>
        <HStack justifyContent={'flex-end'}>
          {!isLessonCompleted && (
            <IconButton
              name="forwardArrow"
              compact
              variant="secondary"
              onPress={handlePress}
              testID="video-lesson-next-button"
            />
          )}
        </HStack>
      </VStack>
    ),
    [
      handlePress,
      isLessonCompleted,
      isMobile,
      videoLesson?.body,
      videoLesson?.title,
    ],
  );

  return (
    <StyledFullscreenModal
      title={cardQuery.title}
      visible={isVisible}
      onRequestClose={onClose}
      primaryContent={primaryContent}
      secondaryContent={secondaryContent}
      showSecondaryContentDivider
      testID="video-lesson-modal"
    />
  );
}

