const StyledRemoteImage = styled(RemoteImage)`
  /* stylelint-disable declaration-no-important -- It needs to override CDS styles */
  border-radius: 24px !important;
`;

export type MixedCampaignCardContentProps = {
  campaign: Omit<MixedCampaign, 'title' | 'extendedBody' | 'tasks'> & {
    tasks: readonly {
      type: string | null;
      isComplete: boolean | null;
      isLocked: boolean | null;
      isIDVRestricted: boolean | null;
      url: string;
    }[];
    externalUrl: string;
  };
  stepsIconName: string;
  stepsIconLabel: string;
};

export const MixedCampaignCardContent = memo(function MixedCampaignCardContent({
  campaign,
  stepsIconName,
  stepsIconLabel,
}: MixedCampaignCardContentProps) {
  const { formatMessage } = useIntl();
  const { userMustSubmitIDV, userHasPendingIDV } = useGetIDVStatus();
  const history = useHistory();
  const isRedesignEnabled = useIsQuestsRedesignEnabled();
  const [completionRate, setCompletionRate] = useState(0);
  const {
    cardName,
    imageUrl,
    iconUrl,
    header,
    body,
    duration,
    reward,
    tasks,
    style,
    externalUrl,
  } = campaign;
  const noReward = reward === 'None';

  const trackClickCard = useLoyaltyTracker('loyalty_card_tapped', {
    action: ActionType.click,
    componentType: ComponentType.button,
    card_name: cardName,
  });

  const completionRateHelper = useCallback(() => {
    if (tasks.length === 0) {
      setCompletionRate(0);
    }
    const backendCompletionRate =
      tasks.filter(task => task.isComplete).length / tasks.length;
    setCompletionRate(backendCompletionRate);
  }, [tasks]);

  // Check and reflect progress
  useEffect(() => {
    completionRateHelper();
  }, [completionRateHelper, tasks]);

  const isLocked = useMemo(() => {
    return tasks.reduce((acc, task) => acc && !!task.isLocked, true);
  }, [tasks]);

  const handlePress = useCallback(() => {
    if (isLocked) return;
    trackClickCard();
    if (style === 'EXTENDED_WITH_TASKS' && externalUrl) {
      window.open(externalUrl, '_blank');
      return;
    }

    const isIDVRestricted = !!tasks[0].isIDVRestricted;
    if (isIDVRestricted && userMustSubmitIDV) {
      history.push('/verify-identity');
    } else if (isIDVRestricted && userHasPendingIDV) {
      history.push('/pending-documents');
    } else if (tasks.length === 1 && tasks[0].type === 'QUEST') {
      const {
        assetSlug,
        campaignSlug,
        index: lessonIndex,
      } = getTaskCampaignProps(tasks[0].url) || {};
      if (assetSlug && campaignSlug && lessonIndex) {
        history.push(
          `/learning-rewards/${assetSlug}/${campaignSlug}/${lessonIndex}/quest`,
        );
      }
    } else {
      history.push(`learning-rewards/${cardName}/details`);
    }
  }, [
    cardName,
    externalUrl,
    history,
    isLocked,
    style,
    tasks,
    trackClickCard,
    userHasPendingIDV,
    userMustSubmitIDV,
  ]);

  const earnMessage = useMemo(() => {
    if (isRedesignEnabled) {
      return completionRate === 1 ? messages.earnedLabel : messages.earnLabel;
    }
    return completionRate === 1 ? messages.earnedLabel : messages.rewardLabel;
  }, [completionRate, isRedesignEnabled]);

  const ctaButton = useMemo(() => {
    if (isLocked) {
      return <IconButton name="lock" variant="foregroundMuted" />;
    }
    return (
      <Button
        testID="mixedCampaignCard_startButton"
        variant="secondary"
        compact
      >
        {formatMessage(messages.startCTA)}
      </Button>
    );
  }, [isLocked, formatMessage]);

  if (tasks.length === 0) {
    return null;
  }

  if (isRedesignEnabled) {
    return (
      <PressableOpacity onPress={handlePress}>
        <VStack spacing={0} width={REDESIGN_CARD_WIDTH}>
          <StyledRemoteImage
            testID="mixedCampaignCard_image"
            source={imageUrl}
            height={REDESIGN_REMOTE_IMAGE_HEIGHT}
            width={REDESIGN_CARD_WIDTH}
            resizeMode="cover"
          />
          <VStack spacingVertical={2} flexGrow={1}>
            <TextTitle3 as="p" noWrap overflow="truncate" title={header}>
              {header}
            </TextTitle3>
            <Box height={48}>
              <TextBody as="p" color="foregroundMuted" numberOfLines={2}>
                {body}
              </TextBody>
            </Box>
          </VStack>
          <HStack
            justifyContent={noReward ? 'flex-end' : 'space-between'}
            alignItems="center"
          >
            {!noReward && (
              <HStack alignItems="center" spacerGap={1}>
                <RemoteImage source={iconUrl} shape="circle" size="l" />
                <VStack alignItems="flex-start">
                  <TextCaption
                    as="p"
                    transform="uppercase"
                    color={
                      completionRate === 1 ? 'positive' : 'foregroundMuted'
                    }
                  >
                    {formatMessage(earnMessage)}
                  </TextCaption>
                  <TextHeadline
                    as="p"
                    color={completionRate === 1 ? 'positive' : 'foreground'}
                  >
                    {reward}
                  </TextHeadline>
                </VStack>
              </HStack>
            )}
            {completionRate === 1 ? (
              <Icon
                testID="mixedCampaignCard_completedCampaignIcon"
                name="checkmark"
                size="s"
                color="positive"
                spacingEnd={1}
              />
            ) : (
              ctaButton
            )}
          </HStack>
        </VStack>
      </PressableOpacity>
    );
  }

  return (
    <PressableOpacity onPress={handlePress}>
      <Box
        bordered
        borderRadius="rounded"
        spacing={0}
        width={CARD_WIDTH}
        height={CARD_HEIGHT}
        overflow="hidden"
        background="background"
      >
        <VStack spacing={0} spacerGap={0} width={CARD_WIDTH}>
          <RemoteImage
            testID="mixedCampaignCard_image"
            source={imageUrl}
            height={REMOTE_IMAGE_HEIGHT}
            width={CARD_WIDTH}
            resizeMode="cover"
            shape="rectangle"
          />
          <VStack spacing={2} spacerGap={1} flexGrow={1}>
            <TextTitle3 as="p" noWrap overflow="truncate" title={header}>
              {header}
            </TextTitle3>
            <Box height={48}>
              <TextBody as="p" color="foregroundMuted" numberOfLines={2}>
                {body}
              </TextBody>
            </Box>
            <HStack spacerGap={3}>
              {!!duration && (
                <HStack alignItems="center" spacerGap={1}>
                  <Icon
                    testID="mixedCampaignCard_durationIcon"
                    name="clockOutline"
                    size="s"
                    color="foregroundMuted"
                  />
                  <TextLabel2 as="p" color="foregroundMuted">
                    {duration}
                  </TextLabel2>
                </HStack>
              )}
              <HStack alignItems="center" spacerGap={1}>
                <Icon
                  testID="mixedCampaignCard_stepsIcon"
                  name={stepsIconName as UiIconName}
                  size="s"
                  color="foregroundMuted"
                />
                <TextLabel2
                  as="p"
                  testID="mixedCampaignCard_stepLabel"
                  color="foregroundMuted"
                >
                  {stepsIconLabel}
                </TextLabel2>
              </HStack>
            </HStack>
          </VStack>
          <HStack
            spacing={2}
            justifyContent={noReward ? 'flex-end' : 'space-between'}
            alignItems="center"
            spacerGap={2}
            borderedTop
          >
            {!noReward && (
              <HStack alignItems="center" spacerGap={1}>
                <RemoteImage source={iconUrl} shape="circle" size="m" />
                <VStack alignItems="flex-start">
                  <TextCaption
                    as="p"
                    transform="uppercase"
                    color={
                      completionRate === 1 ? 'positive' : 'foregroundMuted'
                    }
