const DEBOUNCE_DELAY = 10;
const MIN_TOUCH_DRAG = 0;

export const easingGlobal = `cubic-bezier(${curves.global.join(',')})`;

type AnnouncementCardsSectionProps = {
  queryRef: AnnouncementCardsSectionFragment$key;
};

const AnnouncementCardsSectionContent = memo<AnnouncementCardsSectionProps>(
  function AnnouncementCardsSectionContent({ queryRef }) {
    const { viewer } = useFragment(
      graphql`
        fragment AnnouncementCardsSectionFragment on Query {
          viewer @skip(if: $skipRAV4Fields) {
            announcementCardSurface: uiComponentsBySurface(
              surface: UI_COMPONENT_SURFACE_ANNOUNCEMENT_CARD
              categories: [
                UI_COMPONENT_CATEGORY_ANNOUNCEMENT_CARD_LANDING_PAGE_PROMO
              ]
            ) {
              edges {
                node {
                  id
                  componentId
                  contentId
                  surface
                  category
                  type
                  language
                  publishedAt
                  component {
                    ... on AnnouncementCardComponent {
                      ...AnnouncementCardFragment
                    }
                  }
                }
                cursor
              }
            }
          }
        }
      `,
      queryRef,
    );

    const isMobile = useIsMobile();
    const { formatMessage } = useIntl();

    const carouselWrapperRef = useRef<HTMLElement>(null);
    const carouselRef = useRef<HTMLElement>(null);
    const isAnimating = useRef(false);
    const [dismissedIndices, setDismissedIndices] = useState<Set<string>>(
      () => new Set(),
    );

    const [cardWidth, setCardWidth] = useState<number | undefined>(undefined);
    const [canScrollLeft, setCanScrollLeft] = useState(false);
    const [canScrollRight, setCanScrollRight] = useState(false);

    const cards = useMemo(() => {
      return removeFalsyValues(
        (viewer?.announcementCardSurface?.edges ?? []).map((edge, index) =>
          edge?.node?.component
            ? {
                ...edge.node.component,
                id: edge.node.id,
                uiComponent: {
                  componentId: edge.node.componentId ?? '',
                  contentId: edge.node.contentId ?? '',
                  surface: edge.node.surface ?? '',
                  category: edge.node.category ?? '',
                  type: edge.node.type ?? '',
                  language: edge.node.language ?? '',
                  publishedAt: edge.node.publishedAt ?? '',
                  feedId: edge.cursor ?? '',
                  order: index,
                },
              }
            : null,
        ),
      );
    }, [viewer]);

    const visibleCards = useMemo(
      () => cards.filter(card => !!card.id && !dismissedIndices.has(card.id)),
      [cards, dismissedIndices],
    );

    const handleResize = useDebouncedCallback(() => {
      if (carouselRef?.current) {
        setCardWidth(
          calculateCardWidth(
            carouselRef.current.offsetWidth,
            visibleCards.length,
            isMobile,
          ),
        );
      }
    }, DEBOUNCE_DELAY);

    const handleScroll = useDebouncedCallback(() => {
      if (carouselRef.current) {
        const { scrollLeft, scrollWidth, clientWidth } = carouselRef.current;
        setCanScrollLeft(scrollLeft > 0);
        setCanScrollRight(scrollLeft < scrollWidth - clientWidth - 1);
      }
    }, DEBOUNCE_DELAY);

    useEffect(() => {
      window.addEventListener('resize', handleResize);
      handleResize();
      handleScroll();
      return () => {
        window.removeEventListener('resize', handleResize);
      };
    }, [visibleCards.length, handleResize, handleScroll]);

    /* desktop scroll */
    const handleScrollPrev = useCallback(() => {
      if (carouselRef.current && cardWidth) {
        carouselRef.current.scrollBy({
          left: -(cardWidth + CARD_GAP),
          behavior: 'smooth',
        });
      }
    }, [cardWidth]);

    const handleScrollNext = useCallback(() => {
      if (carouselRef.current && cardWidth) {
        carouselRef.current.scrollBy({
          left: cardWidth + CARD_GAP,
          behavior: 'smooth',
        });
      }
    }, [cardWidth]);

    /* mobile swipe */
    const [currentIndex, setCurrentIndex] = useState<number>(0);
    const [initialX, setInitialX] = useState<number>(0);
    const [onMove, setOnMove] = useState<boolean>(false);
    const [direction, setDirection] = useState<string>('');

    const handleTouchStart = useCallback((e: React.TouchEvent<HTMLElement>) => {
      setInitialX(e.touches[0].clientX);
      setOnMove(true);
    }, []);

    const handleTouchMove = useCallback(
      (e: React.TouchEvent<HTMLElement>) => {
        const lastX = e.touches[0].clientX;
        const diff = initialX - lastX;
        if (diff < -MIN_TOUCH_DRAG) {
          setDirection('left');
        } else if (diff > MIN_TOUCH_DRAG) {
          setDirection('right');
        } else {
          setDirection('');
        }
      },
      [initialX],
    );

    const handleTouchEnd = useCallback(() => {
      if (onMove && cardWidth) {
        let nextIndex = currentIndex;
        if (direction === 'left') {
          nextIndex = currentIndex - 1;
        } else if (direction === 'right') {
          nextIndex = currentIndex + 1;
        }
        carouselRef.current?.scrollTo({
          left: nextIndex * (cardWidth + CARD_GAP),
          behavior: 'smooth',
        });
        setCurrentIndex(nextIndex);
      }
      setOnMove(false);
      setDirection('');
    }, [cardWidth, currentIndex, direction, onMove]);

    const handleCarouselDismiss = useCallback(
      (id: string, cardRef: RefObject<HTMLElement>) => {
        if (isAnimating.current || !cardRef.current) return;
        isAnimating.current = true;
        const cardIndex = visibleCards.findIndex(card => card.id === id);

        const animateCardOpacity = animateElement(cardRef.current, 'opacity', {
          fromValue: '1',
          toValue: '0',
          duration: durations.fast2,
          easing: 'linear',
        });

        const animateCardScale = animateElement(cardRef.current, 'transform', {
          fromValue: 'scale(1)',
          toValue: 'scale(0.9)',
          duration: durations.fast2,
          easing: easingGlobal,
        });

        const animateCardWidth = animateElement(cardRef.current, 'width', {
          fromValue: '100%',
          toValue: '0',
          duration: durations.slow2,
          easing: easingGlobal,
        });

        const animateWrapperHeight =
          carouselWrapperRef.current && visibleCards.length === 1
            ? animateElement(carouselWrapperRef.current, 'height', {
                fromValue: 'auto',
                toValue: '0',
                duration: durations.slow2,
                easing: easingGlobal,
              })
            : Promise.resolve();

        Promise.all([
          animateCardOpacity,
          animateCardScale,
          animateCardWidth,
          animateWrapperHeight,
        ]).then(() => {
          isAnimating.current = false;
          setDismissedIndices(prev => new Set(prev).add(id));
          setCurrentIndex(
            cardIndex === visibleCards.length - 1 ? cardIndex - 1 : cardIndex,
          );
        });
      },
      [visibleCards],
    );

    const header = useMemo(() => {
      if (isMobile) {
        return null;
      }
      return (
        <HStack
          justifyContent="space-between"
          alignItems="center"
          spacingHorizontal={4}
          spacingVertical={2}
          height={72}
        >
          <TextTitle3 as="h2">{formatMessage(messages.forYou)}</TextTitle3>
          {(canScrollLeft || canScrollRight) && (
            <HStack gap={1}>
              <IconButton
                name="backArrow"
                transparent
                onPress={handleScrollPrev}
                disabled={!canScrollLeft}
                aria-label={formatMessage(messages.prevButton)}
              />
              <IconButton
                name="forwardArrow"
                transparent
                onPress={handleScrollNext}
                disabled={!canScrollRight}
                aria-label={formatMessage(messages.nextButton)}
              />
            </HStack>
          )}
        </HStack>
      );
    }, [
      canScrollLeft,
      canScrollRight,
      formatMessage,
      handleScrollNext,
      handleScrollPrev,
      isMobile,
    ]);

    if (cards.length === dismissedIndices.size) {
      return null;
    }

    return (
      <VStack ref={carouselWrapperRef} testID="announcement-cards-section">
        {/* removed bottom border from balance section and added here so it can disappear when cards are dismissed */}
        {!isMobile && <Divider />}
        {header}
        <HStack
          key="announcement-cards-carousel"
          width="100%"
          overflow="hidden"
          ref={carouselRef}
          onScroll={handleScroll}
          gap={isMobile ? 1 : 1.5}
          spacingHorizontal={isMobile ? 3 : 4}
          onTouchStart={handleTouchStart}
          onTouchMove={handleTouchMove}
          onTouchEnd={handleTouchEnd}
        >
          {visibleCards.map(card => {
            return (
              <AnnouncementCard
                key={card.id}
                id={card.id}
                cardWidth={cardWidth}
                dismiss={handleCarouselDismiss}
                announcementCardComponentRef={card}
                cardUIComponent={card.uiComponent}
              />
            );
          })}
        </HStack>
      </VStack>
    );
  },
);

export const AnnouncementCardsSectionFallback = memo(
  function AnnouncementCardsSectionFallback() {
    const isMobile = useIsMobile();
    return (
      <VStack spacingHorizontal={isMobile ? 3 : 4}>
