type BalanceBreakdownProps = {
  queryRef: BalanceBreakdownFragment$key;
  isBalanceStale: boolean;
};

export function BalanceBreakdown({
  queryRef,
  isBalanceStale,
}: BalanceBreakdownProps) {
  const skipEarn = useKillSwitch('kill_my_assets_staking_summary_web');
  const { formatMessage, formatNumber } = useIntl();
  useUserCefiBalancesSubscription();

  const query = useFragment(
    graphql`
      fragment BalanceBreakdownFragment on Query
      @argumentDefinitions(
        contractAddresses: { type: "[String!]" }
        chainId: { type: "Int!" }
        includeDefiOutageChecks: { type: "Boolean!" }
      ) {
        viewer {
          earn {
            assets {
              current {
                ...useGetEligibleRewardsFragment
                asset {
                  asset {
                    platformName
                  }
                }
              }
            }
          }
          assetBySymbol(symbol: "USDC") {
            accounts {
              primary
              type
              totalBalanceInNativeCurrency {
                value
              }
              portfolio {
                type
              }
            }
            earnProgram {
              isEnrolled
              currentRate {
                formatted
              }
            }
          }
        }
        ...useUserNonCashEquivalentBalanceFragment
          @arguments(
            contractAddresses: $contractAddresses
            chainId: $chainId
            includeDefiOutageChecks: $includeDefiOutageChecks
          )
        ...useCurrentMaxRateFragment
        ...useUserCashEquivalentBalanceFragment
          @arguments(
            chainId: $chainId
            contractAddresses: $contractAddresses
            includeDefiOutageChecks: $includeDefiOutageChecks
          )
        ...useTotalStakingPercentFragment
          @arguments(skipEarn: $skipEarn, nativeCurrency: $nativeCurrency)
        ...useCurrentAverageRateFragment
      }
    `,
    queryRef,
  );

  const {
    balanceInFiat: nonCashBalanceInFiat,
    formattedBalanceInFiat: formattedNonCashBalanceInFiat,
  } = useUserNonCashEquivalentBalance({
    queryRef: query,
  });

  const {
    balanceInFiat: cashBalanceInFiat,
    formattedBalanceInFiat: formattedCashBalanceInFiat,
  } = useUserCashEquivalentBalance({
    queryRef: query,
  });

  const canCalculateAllocation =
    cashBalanceInFiat !== undefined && nonCashBalanceInFiat !== undefined;
  const nonCashAllocationPercentage = canCalculateAllocation
    ? nonCashBalanceInFiat / (cashBalanceInFiat + nonCashBalanceInFiat)
    : 0;
  const nonCashAllocationPercentageFormatted = canCalculateAllocation
    ? formatNumber(nonCashAllocationPercentage, {
        style: 'percent',
        maximumFractionDigits: 0,
      })
    : numberFallback;
  const cashAllocationPercentageFormatted = canCalculateAllocation
    ? formatNumber(1 - nonCashAllocationPercentage, {
        style: 'percent',
        maximumFractionDigits: 0,
      })
    : numberFallback;

  // Non-cash row
  const totalStakingPercent = useTotalStakingPercent({ queryRef: query });
  const averageCryptoApy = useCurrentAverageRate(query, ['USDC']);
  const rewards = useGetEligibleRewards(
    query.viewer.earn?.assets?.current,
    false,
  ).filter(reward => (reward.asset?.asset?.platformName ?? '') !== 'USDC');
  const isStakingEligible = rewards.length > 0;
  const maxCryptoApy = useCurrentMaxRate(query, ['USDC']);

  const NonCashBalanceDetail = useMemo(() => {
    // Default to showing percentage allocation
    let label = formatMessage(messages.allocation);
    let mainContent: string | null = nonCashAllocationPercentageFormatted;
    let secondaryContent = null;
    if (!skipEarn) {
      if (averageCryptoApy && totalStakingPercent) {
        // User is staking
        label = formatMessage(messages.staked);
        mainContent = formatNumber(totalStakingPercent, {
          style: 'percent',
          maximumFractionDigits: 0,
        });
        secondaryContent = `${averageCryptoApy?.formatted} ${averageCryptoApy?.unitSymbol}`;
      } else if (isStakingEligible && maxCryptoApy) {
        // User is not staking, but is eligible
        label = formatMessage(messages.staking);
        mainContent = null;
        secondaryContent = formatMessage(messages.earnUpToAPY, {
          rewardsApy: maxCryptoApy.formatted,
        });
      }
    }

    return (
      <BalanceBreakdownRowDetail
        label={label}
        mainContent={mainContent}
        secondaryContent={secondaryContent}
      />
    );
  }, [
    averageCryptoApy,
    formatMessage,
    formatNumber,
    isStakingEligible,
    maxCryptoApy,
    nonCashAllocationPercentageFormatted,
    skipEarn,
    totalStakingPercent,
  ]);

  // Cash row
  const isUSDCRewardsEligible = !!query.viewer?.assetBySymbol?.earnProgram;
  const isUSDCRewardsEnrolled =
    query.viewer.assetBySymbol?.earnProgram?.isEnrolled ?? false;
  const usdcRewardsRate =
    query.viewer.assetBySymbol?.earnProgram?.currentRate?.formatted ?? null;

  const usdcAccount = query.viewer.assetBySymbol?.accounts?.find(
    account =>
      account?.type === 'WALLET' &&
      account?.portfolio?.type === 'DEFAULT' &&
      account?.primary,
  );
  const totalUSDCBalanceInNativeCurrency = parseFloat(
    usdcAccount?.totalBalanceInNativeCurrency?.value ?? '0',
  );

  const cashBalanceDetail = useMemo(() => {
    // Default to showing percentage allocation
    let label = formatMessage(messages.allocation);
    let mainContent: string | null = cashAllocationPercentageFormatted;
    let secondaryContent = null;
    if (isUSDCRewardsEligible) {
      if (isUSDCRewardsEnrolled) {
        if (
          cashBalanceInFiat !== undefined &&
          totalUSDCBalanceInNativeCurrency !== undefined
        ) {
          label = formatMessage(messages.earning);
          mainContent = formatNumber(
            totalUSDCBalanceInNativeCurrency / cashBalanceInFiat,
            {
              style: 'percent',
              maximumFractionDigits: 0,
            },
          );
          if (usdcRewardsRate) {
            secondaryContent = formatMessage(messages.apyDisplay, {
              rewardsApy: usdcRewardsRate,
            });
          }
        }
      } else if (usdcRewardsRate) {
        label = formatMessage(messages.earn);
        mainContent = null;
        secondaryContent = formatMessage(messages.earnUpToAPY, {
          rewardsApy: usdcRewardsRate,
        });
      }
    }

    return (
      <BalanceBreakdownRowDetail
        label={label}
        mainContent={mainContent}
        secondaryContent={secondaryContent}
      />
    );
  }, [
    cashAllocationPercentageFormatted,
    cashBalanceInFiat,
    formatMessage,
    formatNumber,
    isUSDCRewardsEligible,
    isUSDCRewardsEnrolled,
    totalUSDCBalanceInNativeCurrency,
    usdcRewardsRate,
  ]);

  if (isBalanceStale) {
    return null;
  }

  return (
