import { useMemo, useCallback } from 'react';
import { useIntl } from 'react-intl';

import { useChartPeriods } from '@cb/shared/components/Chart';
import { useIsMobile } from '@cb/shared/utils';
import { ChartPeriod } from '@cb/types';
import { ChartData, ChartScrubParams } from '@cbhq/cds-common';
import { SparklineInteractive } from '@cbhq/cds-web-visualization';
import { Collapsible } from '@cbhq/cds-web/collapsible';
import { Box } from '@cbhq/cds-web/layout';
import { useCurrencyFormatter } from '@cbhq/common-web';

import useNativeCurrency from 'hooks/useNativeCurrency';

export type HoverDisplayData = {
  balance: string;
  timestamp: string;
};

type HomePortfolioChartProps = {
  chartData: Record<ChartPeriod, ChartData>;
  activePeriod: ChartPeriod;
  setActivePeriod: (period: ChartPeriod) => void;
  minimized: boolean;
  setHoverDisplayData: (value: HoverDisplayData | null) => void;
  isBalanceStale: boolean;
};

export function HomePortfolioChart({
  chartData,
  activePeriod,
  setActivePeriod,
  minimized,
  setHoverDisplayData,
  isBalanceStale,
}: HomePortfolioChartProps) {
  const { formatDate } = useIntl();
  const formatter = useCurrencyFormatter();
  const nativeCurrency = useNativeCurrency();
  const isMobile = useIsMobile();

  const dateFormatter = useCallback(
    (date: Date, period: ChartPeriod) => {
      const onlyShowHours = period === 'day' || period === 'hour';
      return onlyShowHours
        ? formatDate(date, { hour: 'numeric', minute: 'numeric' })
        : formatDate(date, {
            month: 'short',
            day: 'numeric',
          });
    },
    [formatDate],
  );

  const standardPeriods = useChartPeriods();
  const chartPeriods = useMemo(
    () =>
      standardPeriods.map(p => ({
        label: p.label.toLocaleUpperCase(),
        value: p.period,
      })),
    [standardPeriods],
  );

  const handleSelectPeriod = useCallback(
    (period: ChartPeriod) => {
      setActivePeriod(period);
    },
    [setActivePeriod],
  );

  const handleScrub = useCallback(
    ({ point }: ChartScrubParams<string>) => {
      setHoverDisplayData({
        balance: formatter({
          isFiat: true,
          amount: { value: point.value.toString(), currency: nativeCurrency },
        }),
        timestamp: formatDate(point.date, {
          month: 'short',
          day: 'numeric',
          year: 'numeric',
          weekday: 'short',
          hour: 'numeric',
          minute: 'numeric',
        }),
      });
    },
    [formatDate, formatter, nativeCurrency, setHoverDisplayData],
  );

  const handleScrubEnd = useCallback(() => {
    setHoverDisplayData(null);
  }, [setHoverDisplayData]);

  if (isBalanceStale) {
    return null;
  }

  return (
    <Collapsible collapsed={minimized}>
      <Box
        minHeight={182}
        width="100%"
        testID="HomePortfolioChart"
        spacingHorizontal={isMobile ? 3 : 4}
      >
        <SparklineInteractive
          key="sparkline-interactive"
          data={chartData}
          defaultPeriod={activePeriod}
          formatDate={dateFormatter}
          periods={chartPeriods}
          onPeriodChanged={handleSelectPeriod}
          onScrub={handleScrub}
          onScrubEnd={handleScrubEnd}
          periodSelectorPlacement="below"
          strokeColor="#0052FF"
          compact
        />
      </Box>
    </Collapsible>
  );
}

