const i18nKey = 'HomePortfolioChartButton';

const messages = defineMessages({
  expandChart: {
    id: `${i18nKey}.expandChart`,
    defaultMessage: 'Expand portfolio chart',
    description: `#Component: PressableOpcity:aria-label
    #CharLimit: 50
    #Context: Aria label accessibility text for button that expands the portfolio chart`,
  },
  collapseChart: {
    id: `${i18nKey}.collapseChart`,
    defaultMessage: 'Collapse portfolio chart',
    description: `#Component: IconButton:aria-label
    #CharLimit: 50
    #Context: Aria label accessibility text for button that collapses the portfolio chart`,
  },
});

const DESKTOP_WIDTH = 235;
const DESKTOP_HEIGHT_WITH_GL = 80;
const DESKTOP_HEIGHT_WITHOUT_GL = 60;
const MOBILE_WIDTH = 75;
const MOBILE_HEIGHT = 30;

type HomePortfolioChartMinimizedProps = {
  chartData: Record<ChartPeriod, ChartData>;
  activePeriod: ChartPeriod;
  hasGainLoss: boolean;
};

const HomePortfolioChartMinimized = memo<HomePortfolioChartMinimizedProps>(
  function HomePortfolioChartMinimized({
    chartData,
    activePeriod,
    hasGainLoss,
  }) {
    const isMobile = useIsMobile();
    const sparklineSize = useMemo(() => {
      const width = isMobile ? MOBILE_WIDTH : DESKTOP_WIDTH;
      const height = isMobile
        ? MOBILE_HEIGHT
        : hasGainLoss
        ? DESKTOP_HEIGHT_WITH_GL
        : DESKTOP_HEIGHT_WITHOUT_GL;

      return {
        width,
        height,
      };
    }, [hasGainLoss, isMobile]);

    const dataForPeriod = useMemo(() => {
      return (chartData[activePeriod] ?? []).map(dataPoint => dataPoint.value);
    }, [chartData, activePeriod]);

    const sparklinePath = useSparklinePath({
      data: dataForPeriod,
      ...sparklineSize,
    });

    const sparklineArea = useSparklineArea({
      data: dataForPeriod,
      ...sparklineSize,
    });

    return (
      <Sparkline path={sparklinePath} color="#0052FF" {...sparklineSize}>
        <SparklineArea area={sparklineArea} />
      </Sparkline>
    );
  },
);

type HomePortfolioChartButtonProps = {
  minimized: boolean;
  setMinimized: (minimized: boolean) => void;
  isBalanceStale: boolean;
} & HomePortfolioChartMinimizedProps;

export const HomePortfolioChartButton = memo<HomePortfolioChartButtonProps>(
  function HomePortfolioChartButton({
    minimized,
    setMinimized,
    isBalanceStale,
    ...props
  }) {
    const { formatMessage } = useIntl();
    const isMobile = useIsMobile();

    const miniChartContainerRef = useRef<HTMLElement>(null);
    const collapseButtonContainerRef = useRef<HTMLElement>(null);

    const trackHomepageAnalytics = useHomepageAnalytics();

    const handleExpandChart = useCallback(() => {
      if (miniChartContainerRef.current && collapseButtonContainerRef.current) {
        miniChartContainerRef.current.animate(
          [{ opacity: 1 }, { opacity: 0 }],
          {
            duration: durations.quick,
            easing: 'linear',
            fill: 'forwards',
          },
        ).onfinish = () => {
          setMinimized(false);
        };
        collapseButtonContainerRef.current.animate(
          [{ opacity: 0 }, { opacity: 1 }],
          {
            duration: durations.quick,
            delay: durations.quick,
            easing: 'linear',
            fill: 'forwards',
          },
        );
        trackHomepageAnalytics(
          ActionType.click,
          ComponentType.button,
          'home_chart',
          'expand',
        );
      }
    }, [setMinimized, trackHomepageAnalytics]);

    const handleCollapseChart = useCallback(() => {
      if (miniChartContainerRef.current && collapseButtonContainerRef.current) {
        collapseButtonContainerRef.current.animate(
          [{ opacity: 1 }, { opacity: 0 }],
          {
            duration: durations.quick,
            easing: 'linear',
            fill: 'forwards',
          },
        ).onfinish = () => {
          setMinimized(true);
        };
        miniChartContainerRef.current.animate(
          [{ opacity: 0 }, { opacity: 1 }],
          {
            duration: durations.quick,
            delay: durations.quick,
            easing: 'linear',
            fill: 'forwards',
          },
        );
        trackHomepageAnalytics(
          ActionType.click,
          ComponentType.button,
          'home_chart',
          'collapse',
        );
      }
    }, [setMinimized, trackHomepageAnalytics]);

    if (isBalanceStale) {
      return null;
    }

    return (
      <Box position="relative" display="inline-block">
        <Box
          key="mini-chart"
          ref={miniChartContainerRef}
          position="absolute"
          right={0}
          visibility={minimized ? 'visible' : 'hidden'}
          testID="HomePortfolioChartMinimized"
        >
          <PressableOpacity
            onPress={handleExpandChart}
            aria-label={formatMessage(messages.expandChart)}
          >
            <HomePortfolioChartMinimized {...props} />
          </PressableOpacity>
        </Box>
        <Box
          key="collapse-button"
          spacingTop={isMobile ? 0 : 1}
          ref={collapseButtonContainerRef}
          visibility={minimized ? 'hidden' : 'visible'}
          testID="ChartCollapseButton"
        >
          <IconButton
            name="caretUp"
            variant="secondary"
            onPress={handleCollapseChart}
            aria-label={formatMessage(messages.collapseChart)}
          />
        </Box>
      </Box>
    );
  },
);

import { useCallback, useEffect, useState, useRef, memo } from 'react';
import { useIntl } from 'react-intl';
import styled from 'styled-components';

import { useIsMobile } from '@cb/shared/utils';
import { IconButton } from '@cbhq/cds-web/buttons';
import { HStack } from '@cbhq/cds-web/layout/HStack';
import { VStack } from '@cbhq/cds-web/layout/VStack';
import { Spinner } from '@cbhq/cds-web/loaders';
import { TextTitle3 } from '@cbhq/cds-web/typography/TextTitle3';
import { Disposable, FragmentRefs } from '@cbhq/data-layer';

import useAssetsFinancialPromotionsUk from 'hooks/useAssetsFinancialPromotionsUk';
import { type TopMoversEntryPoint } from 'views/Home/utils/Analytics';

// eslint-disable-next-line @cbhq/cdl-no-type-import-across-modules
import { TopMoversFragmentRefetchableQuery$variables } from '../__generated__/TopMoversFragmentRefetchableQuery.graphql';
import {
  messages,
  TOTAL_TOP_MOVERS_TO_SHOW,
  TOTAL_TOP_MOVERS_TO_SHOW_MAX,
} from '../TopMovers';
import TopMoversAssetCard from './components/TopMoversAssetCard';

type TopMoversCarouselProps = {
  assets: {
    readonly ' $fragmentSpreads': FragmentRefs<
      'TopMoversAssetCardFragment' | 'TopMoversRowFragment'
    >;
  }[];
  loadNext: (
    count: number,
    options?:
      | {
          onComplete?: ((arg: Error | null) => void) | undefined;
          UNSTABLE_extraVariables?:
            | Partial<TopMoversFragmentRefetchableQuery$variables>
            | undefined;
        }
      | undefined,
  ) => Disposable;
  hasNext: boolean;
  isLoadingNext: boolean;
  entryPoint: TopMoversEntryPoint;
};

function TopMoversCarousel({
  assets,
  loadNext,
  hasNext,
  isLoadingNext,
  entryPoint,
}: TopMoversCarouselProps) {
  const isMobile = useIsMobile();
  const { formatMessage } = useIntl();
  const scrollableRef = useRef<HTMLElement>(null);
  const [canScrollLeft, setCanScrollLeft] = useState(false);
  const [canScrollRight, setCanScrollRight] = useState(false);
  const hasUkFinProm = useAssetsFinancialPromotionsUk();

  useEffect(() => {
    updateScrollability();
    window.addEventListener('resize', updateScrollability);
    return () => {
      window.removeEventListener('resize', updateScrollability);
    };
  }, []);

  useEffect(() => {
    if (assets.length > TOTAL_TOP_MOVERS_TO_SHOW) {
      updateScrollability();
    }
  }, [assets.length]);

  const loadNextHandler = useCallback(() => {
    if (hasNext && assets.length < TOTAL_TOP_MOVERS_TO_SHOW_MAX) {
      loadNext(TOTAL_TOP_MOVERS_TO_SHOW);
    }
  }, [assets.length, hasNext, loadNext]);

  const updateScrollability = useCallback(() => {
    if (scrollableRef.current) {
      const { scrollLeft, scrollWidth, clientWidth } = scrollableRef.current;
      setCanScrollLeft(scrollLeft > 0);
      setCanScrollRight(scrollLeft < scrollWidth - clientWidth - 1);
      if (scrollLeft > scrollWidth - clientWidth - 1) {
        loadNextHandler();
      }
    }
  }, [loadNextHandler]);

  const scrollHandler = useCallback(
    (direction: string) => {
      return function scrollHandlerCallback() {
        // Scroll
        if (scrollableRef.current) {
          const { scrollLeft, scrollWidth, clientWidth } =
            scrollableRef.current;
          const distance = clientWidth * (direction === 'left' ? -1 : 1);
          scrollableRef.current.scrollBy({
            left: distance,
            behavior: 'smooth',
          });

          // Fetch more data if has reached end of scroll
          if (scrollLeft + distance > scrollWidth - clientWidth - 1) {
            loadNextHandler();
          }
        }
      };
    },
    [loadNextHandler],
  );

  return (
    <VStack spacingVertical={3} gap={2}>
      <HStack
        justifyContent="space-between"
        alignItems="center"
        spacingHorizontal={isMobile ? 3 : 4}
      >
        <TextTitle3 as="h2">
          {hasUkFinProm
            ? formatMessage(messages.topMoversUk)
            : formatMessage(messages.topMovers)}
        </TextTitle3>
        <HStack gap={1}>
          <IconButton
            name="backArrow"
            transparent
            onPress={scrollHandler('left')}
            disabled={!canScrollLeft}
          />
          <IconButton
            name="forwardArrow"
            transparent
            onPress={scrollHandler('right')}
            disabled={!canScrollRight}
          />
        </HStack>
      </HStack>
      <StyledHStack
        key="scrollable-carousel-area-74202a9d-1051-4bf1-b5ee-6fa4b238abb5"
        overflow="auto"
        ref={scrollableRef}
        onScroll={updateScrollability}
        gap={2}
        position="relative"
        spacingHorizontal={isMobile ? 3 : 4}
      >
        {isLoadingNext && (
          <VStack
            minHeight="100%"
            width="100%"
            justifyContent="center"
            alignItems="center"
            position="absolute"
            top="0"
            left="0"
            right="0"
            bottom={0}
            zIndex={10000}
            background="primaryWash"
            opacity={0.4}
          >
            <Spinner size={5} color="primary" />
          </VStack>
        )}
        {assets.map(node => (
          <TopMoversAssetCard assetRef={node} entryPoint={entryPoint} />
        ))}
      </StyledHStack>
    </VStack>
  );
}

const StyledHStack = styled(HStack)`
  /* Hide scrollbar for IE, Edge and Firefox */
  -ms-overflow-style: none; /* IE and Edge */
  scrollbar-width: none; /* Firefox */
  /* Hide scrollbar for Chrome, Safari and Opera */
  &::-webkit-scrollbar {
    display: none;
  }
`;

export default memo(TopMoversCarousel);

