export const AcknowledgeScreen = memo<AcknowledgeScreenProps>(
  ({ questions }) => {
    const { questionIndex } = useScamQuizNavigation();
    const acknowledgementQuestion = questions[questionIndex];
    const { formatMessage } = useIntl();
    const [, setAnswers] = useScamQuizAnswer();
    const [isSubmitting, submitQuizAnswers] = useSubmitQuizAnswers();
    const [isCancelling, cancelTransaction] = useCancelTransaction();
    const [isAckAccepted, setAckAccepted] = useState(false);

    useEffect(() => logAcknowledgeViewed(), []);

    const handleAckChange = useCallback(() => {
      setAckAccepted(prev => {
        logAckTermsChange(!prev);
        return !prev;
      });
    }, []);

    const handleContinuePress = useCallback(async () => {
      const updatedAnswers = setAnswers({
        [acknowledgementQuestion.uuid]: acknowledgementQuestion.options,
      });

      await submitQuizAnswers(updatedAnswers);
      logQuizSubmitClicked('continue');
    }, [
      acknowledgementQuestion.options,
      acknowledgementQuestion.uuid,
      setAnswers,
      submitQuizAnswers,
    ]);

    const handleCancelPress = useCallback(async () => {
      await cancelTransaction();
      logQuizSubmitClicked('canceled');
    }, [cancelTransaction]);

    const description =
      acknowledgementQuestion.title + ' ' + acknowledgementQuestion.subtitle;

    const action = (
      <VStack gap={2}>
        <Box
          spacingHorizontal={0.5}
          alignItems="center"
          as="label"
          style={{ cursor: 'pointer' }}
        >
          <Checkbox
            checked={isAckAccepted}
            onChange={handleAckChange}
            value="ackAccepted"
          ></Checkbox>
          <TextBody
            as="p"
            spacingStart={2}
            color={isAckAccepted ? 'foreground' : 'foregroundMuted'}
          >
            {formatMessage(messages.acknowledgement.terms)}
          </TextBody>
        </Box>
        <Button
          disabled={!isAckAccepted}
          onPress={handleContinuePress}
          loading={isSubmitting || isCancelling}
        >
          {formatMessage(messages.acknowledgement.continueBtn)}
        </Button>
        <Button
          variant="secondary"
          onPress={handleCancelPress}
          loading={isSubmitting || isCancelling}
        >
          {formatMessage(messages.acknowledgement.cancelBtn)}
        </Button>
      </VStack>
    );

    return (
      <HStack width={'100%'} justifyContent="center" height={'100%'} background>
        <Box spacingHorizontal={3}>
          <MultiContentModule
            maxWidth={550}
            pictogram="done"
            title={formatMessage(messages.acknowledgement.title)}
            description={description}
            action={action}
          >
            <VStack gap={2}>
              {acknowledgementQuestion.options.map(({ value, title }) => (
                <ListCell
                  compact
                  multiline
                  key={value}
                  description={title}
                  media={<Icon name="checkmark" size="m" color="foreground" />}
                  outerSpacing={{
                    spacingHorizontal: 0.5,
                  }}
                />
              ))}
            </VStack>
          </MultiContentModule>
        </Box>
      </HStack>
    );
  },
);

export function useSubmitQuizAnswers(): [
  boolean,
  (ans: Answers) => Promise<void>,
] {
  const [isSubmitting, submitQuiz] = useSubmitQuiz();
  const { navNext } = useScamQuizNavigation();
  const { formatMessage } = useIntl();
  const toast = useToast();

  return useMemo(
    () => [
      isSubmitting,
      async (answers: Answers) => {
        // transform answers to mutation request format
        const answersList = Object.entries(answers).reduce<
          GenericComplianceAnswerInput[]
        >((acc, [uuid, opt]) => {
          const options = Array.isArray(opt) ? opt : [opt];
          options.forEach(option => {
            acc.push({
              questionUuid: uuid,
              answerOption: option,
            });
          });

          return acc;
        }, []);

        try {
          await submitQuiz(answersList);
          navNext();
          logQuizSubmitSuccess();
        } catch (err) {
          toast.show(formatMessage(messages.scamQuizErrorMessage), {
            bottomOffset: 125,
            variant: 'negative',
          });
          logQuizSubmitFailure(err);
        }
      },
    ],
    [formatMessage, isSubmitting, navNext, submitQuiz, toast],
  );
}

export function useCancelTransaction(): [boolean, () => Promise<void>] {
  const toast = useToast();
  const { formatMessage } = useIntl();
  const { exit } = useScamQuizNavigation();
  const params: ScamQuizUrlParams = useParams();
  const [isCancelling, cancelTransaction] = useScamQuizCancelTransaction();

  return useMemo(
    () => [
      isCancelling,
      async () => {
        try {
          if (params.accountId && params.transactionId) {
            await cancelTransaction(params.accountId, params.transactionId);
          }
          logCancelTxnSuccess();
          exit();
        } catch (err) {
          toast.show(formatMessage(messages.acknowledgement.errorMessage), {
            bottomOffset: 125,
            variant: 'negative',
          });
          logCancelTxnFailure(err);
        }
      },
    ],
    [
      cancelTransaction,
      exit,
      formatMessage,
      isCancelling,
      params.accountId,
      params.transactionId,
      toast,
    ],
  );
}

