            futuresCurrentPositionLimitTier {
              displayName
              monetaryRequirement
              riskTier
            }
          }
        }
      }
    `,
    queryRef,
  );

  const availablePositionLimitTiersResponse =
    retailBrokerage?.futuresAvailablePositionLimitTiers;

  const userCurrentTier = retailBrokerage?.futuresCurrentPositionLimitTier;

  const handleClose = useCallback(() => {
    closeModal();
    setSelectedTier(undefined);
  }, [closeModal]);

  const toast = useToast();

  const handleSuccess = useCallback(() => {
    toggle();
    markStep('futures_position_limit_increase_success');
    toast.show('Futures position limit has been updated');
    handleClose();
  }, [handleClose, toast, toggle]);

  const handleSelection = useCallback(
    (value: string) => {
      const selectedTier = availablePositionLimitTiersResponse?.find(
        (tier: PositionLimitTier) => tier?.riskTier === value,
      );

      setSelectedTier(selectedTier);

      openModal(
        <PositionLimitTieringModal
          visible
          onClose={handleClose}
          onSuccess={handleSuccess}
          selectedTier={selectedTier}
          settingsPage
        />,
      );
    },
    [
      availablePositionLimitTiersResponse,
      openModal,
      handleClose,
      handleSuccess,
    ],
  );

  const isTopLimitTier = userCurrentTier?.riskTier === MAX_TIER;

  const currentTierAndCaret = useMemo(() => {
    return (
      <Tooltip
        content={formatMessage(messages.tooltipContent)}
        placement="top"
        visible={isTopLimitTier}
      >
        <Pressable as="button" background="transparent" noScaleOnPress>
          <HStack spacerGap={1} alignItems="center">
            <VStack>
              <TextBody as="p" color="foregroundMuted">
                {userCurrentTier?.displayName}
              </TextBody>
              <TextBody as="p" color="foregroundMuted">
                {formatNumber(userCurrentTier?.monetaryRequirement ?? 0, {
                  style: 'currency',
                  currency: 'USD',
                  maximumFractionDigits: 0,
                })}
              </TextBody>
            </VStack>
            <Box
              justifyContent="flex-end"
              alignItems="flex-end"
              flexDirection="column"
            >
              {!isTopLimitTier ? (
                <AnimatedCaret rotate={collapsed ? 180 : 0} />
              ) : null}
            </Box>
          </HStack>
        </Pressable>
      </Tooltip>
    );
  }, [
    collapsed,
    formatMessage,
    formatNumber,
    isTopLimitTier,
    userCurrentTier?.displayName,
    userCurrentTier?.monetaryRequirement,
  ]);

  return (
    <AdvancedBoundaryWithSuspense
      owner="advanced-futures"
      name="advanced-component-futures-position-limit-tiers-setting"
    >
      <VStack>
        <PressableOpacity
          noScaleOnPress
          onPress={!isTopLimitTier ? toggle : undefined}
        >
          <ListCell
            title={formatMessage(messages.positionLimitHeader)}
            description={formatMessage(messages.positionLimitBody, {
              learnMoreLink: (
                <Link href={positionLimitLearnMoreLink} openInNewWindow>
                  {formatMessage(messages.positionLimitLearnMore)}
                </Link>
              ),
            })}
            detail={userCurrentTier?.riskTier ? currentTierAndCaret : null}
            detailWidth={isMobile ? 260 : 100}
          />
        </PressableOpacity>
        {availablePositionLimitTiersResponse && (
          <Collapsible collapsed={collapsed} spacingEnd={2} spacingBottom={2}>
            <Group
              role="radiogroup"
              aria-labelledby="choose-position-limit-tier"
              flexGrow={1}
              gap={2}
            >
              {availablePositionLimitTiersResponse.map(tier => (
                <HStack key={tier?.riskTier} alignItems="center">
                  <ListCell
                    compact
                    title={tier?.displayName}
                    description={`> ${formatNumber(
                      tier?.monetaryRequirement ?? 0,
                      {
                        style: 'currency',
                        currency: 'USD',
                        maximumFractionDigits: 0,
                      },
                    )} ${formatMessage(messages.annualIncomeOrNetWorth)}`}
                  />
                  <Radio
                    key={tier?.riskTier}
                    checked={selectedTier?.riskTier === tier?.riskTier}
                    id={`radio-group-${tier?.riskTier}`}
                    name="radio-group"
                    // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                    onChange={event => handleSelection(event.target.value)}
                    value={tier?.riskTier as string}
                  />
                </HStack>
              ))}
            </Group>
          </Collapsible>
        )}
      </VStack>
    </AdvancedBoundaryWithSuspense>
  );
}

