function DigitalWalletRightDetail({
  paymentMethod,
}: Pick<Props, 'paymentMethod'>) {
  const { formatMessage } = useIntl();
  const isApplePay = paymentMethod.type === 'apple_pay';
  const isGooglePay = paymentMethod.type === 'google_pay';

  const {
    isLoading: isApplePaySupportedLoading,
    isSupportedWithActiveCard: isApplePaySupportedWithActiveCard,
  } = useIsApplePaySupported();

  const isGooglePayDisabledExperiment = useIsTreatment(
    'feb_2024_helper_text_google_pay',
  );

  const {
    isGooglePaySupportedWithActiveCardLoading: isGooglePaySupportedLoading,
    isGooglePaySupportedWithActiveCard,
  } = useContext(DigitalWalletSupportedContext);

  const isDigitalWalletReadyToUse =
    (isGooglePay && isGooglePaySupportedWithActiveCard) ||
    (isApplePay && isApplePaySupportedWithActiveCard);

  // Don't show loading indicator if digital wallet is ready to use
  const loadingDigitalWallet =
    !isDigitalWalletReadyToUse &&
    ((isApplePay && isApplePaySupportedLoading) ||
      (isGooglePay && isGooglePaySupportedLoading));

  const isDigitalWalletMissingActiveCard =
    !isGooglePaySupportedWithActiveCard || !isApplePaySupportedWithActiveCard;

  // Ready to use
  if (isDigitalWalletReadyToUse) {
    if (isGooglePayDisabledExperiment) {
      return null;
    }

    return (
      <TextBody as="p" color="foregroundMuted">
        {formatMessage(messages.digitalWalletActiveCardDetected)}
      </TextBody>
    );
  }
  // Checking for eligible cards
  else if (loadingDigitalWallet) {
    return (
      <HStack spacerGap={2} alignItems="center">
        <Spinner size="small" />
        <TextBody as="p" color="foregroundMuted">
          {formatMessage(messages.digitalWalletActiveCardLoading)}
        </TextBody>
      </HStack>
    );
  }
  // No eligible cards found
  else if (isDigitalWalletMissingActiveCard) {
    if (isGooglePay) {
      if (isGooglePayDisabledExperiment) {
        return null;
      }

      return (
        <Link to="https://pay.google.com/payments/#paymentMethods">
          {formatMessage(messages.addGooglePayText)}
        </Link>
      );
    } else if (isApplePay) {
      return (
        <Link to="https://support.apple.com/en-us/HT204506">
          {formatMessage(messages.setupApplePayText)}
        </Link>
      );
    } else {
      return null;
    }
  } else {
    return null;
  }
}

function LinkedAccountRow({ queryRef, onAddAgainClick, paymentMethod }: Props) {
  const query = useFragment(
    graphql`
      fragment LinkedAccountRowFragment on Query {
        ...PaymentMethodDescriptionFragment
        ...useDisplayDataForPaymentMethodFragment
        viewer {
          fiatAccounts {
            uuid
            availableBalance {
              value
              currency
            }
          }
        }
      }
    `,
    queryRef,
  );

  const intl = useIntl();
  const { formatMessage } = intl;
  const invalidateUser = useUserFetcher();
  const fetchPolicyRestrictions = usePolicyRestrictionsFetcher();
  const isMobile = useIsMobile();
  const toasts = useToasts();
  const fetchPaymentMethods = usePaymentMethodsFetcher();
  const fetchAvailablePaymentMethods = useAvailablePaymentMethodsFetcher();
  const deletePaymentMethod = usePaymentMethodDeleter();
  const { deletePaymentMethodV3 } = usePaymentMethodDeleterV3();
  const { triggerRelinkFlow } = useHandleRelink();
  const isFedwireDecomped = useIsTreatment('may_2024_web_fedwire_decomp');
  const isAchDecomp = useIsTreatment('may_2024_web_ach_decomp');

  const isDigitalWallet =
    paymentMethod.type === 'apple_pay' || paymentMethod.type === 'google_pay';

  const { label } = useDisplayDataForPaymentMethod({
    queryRef: query,
    paymentMethod,
  });

  const [deleteConfirmVisible, setDeleteConfirmVisible] = useState(false);

  const [verificationModalVisible, setVerificationModalVisible] =
    useState(false);

  const [isDeleting, setIsDeleting] = useState(false);

  const showDeleteConfirm = useCallback(() => {
    setDeleteConfirmVisible(true);
  }, []);

  const hideDeleteConfirm = useCallback(() => {
    setDeleteConfirmVisible(false);
  }, []);

  const showVerificationModal = useCallback(() => {
    setVerificationModalVisible(true);
  }, []);

  const hideVerificationModal = useCallback(() => {
    setVerificationModalVisible(false);
  }, []);

  const onDeletePaymentMethodComplete = useCallback(() => {
    setIsDeleting(false);
    fetchPaymentMethods();
    invalidateUser();
    // fetching policy restricitions ensures the trade flows are updated
    fetchPolicyRestrictions({ type: 'buys' });
    fetchPolicyRestrictions({ type: 'sells' });
    fetchAvailablePaymentMethods();
    toasts.showSuccessToast(formatMessage(messages.deleteSuccess));

    if (
      PPRO_PAYMENT_METHODS.includes(
        paymentMethod.type as CheckoutPaymentMethodType,
      )
    ) {
      logEvent('deposit_PPRO_account_removed', {
        action: ActionType.click,
        account_type: `${paymentMethod.type} linked`,
        componentType: ComponentType.button,
      });
    }
  }, [
    fetchPolicyRestrictions,
    fetchPaymentMethods,
    formatMessage,
    invalidateUser,
    fetchAvailablePaymentMethods,
    paymentMethod.type,
    toasts,
  ]);

  const onDeletePaymentMethodError = () => {
    setIsDeleting(false);
  };

  const handleDelete = useCallback(async () => {
    setIsDeleting(true);
    hideDeleteConfirm();

    if (
      GQL_SUPPORTED_DELETE_PAYMENT_METHODS.includes(paymentMethod.type) ||
      (isFedwireDecomped && paymentMethod.type === 'fedwire') ||
      (isAchDecomp && paymentMethod.type === 'ach_bank_account')
    ) {
      deletePaymentMethodV3({
        paymentMethodId: paymentMethod.id,
        onSuccess: onDeletePaymentMethodComplete,
        onError: onDeletePaymentMethodError,
      });
    } else {
      const success = await deletePaymentMethod(paymentMethod.id);
      if (success) {
        onDeletePaymentMethodComplete();
      } else {
        onDeletePaymentMethodError();
      }
    }
  }, [
    hideDeleteConfirm,
    paymentMethod.type,
    paymentMethod.id,
    isFedwireDecomped,
    isAchDecomp,
    deletePaymentMethodV3,
    onDeletePaymentMethodComplete,
    deletePaymentMethod,
  ]);

  const handleEmailVerificationSuccess = useCallback(async () => {
    invalidateUser();
    fetchPaymentMethods();
  }, [invalidateUser, fetchPaymentMethods]);

  const pickerData = paymentMethod.pickerData;

  const relinkHandler = useCallback(() => {
    triggerRelinkFlow({
      paymentMethodUUid: paymentMethod.id,
      paymentMethodType: paymentMethod?.type,
    });
  }, [paymentMethod.id, paymentMethod.type, triggerRelinkFlow]);

  const handleOnPress = useCallback(
    () => onAddAgainClick(paymentMethod),
    [onAddAgainClick, paymentMethod],
  );

  const handleOnSuccess = useCallback(
    () => handleEmailVerificationSuccess(),
    [handleEmailVerificationSuccess],
  );

  return (
    <Row testID={`linked-account-row-${paymentMethod.type}`}>
      <TextContainer>
        <IconContainer>
          <PaymentMethodIcon
            type={paymentMethod.type || pickerData?.symbol}
            // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
            iconUrl={pickerData?.iconUrl}
            currency={paymentMethod.currency}
            // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
            cardNetwork={pickerData?.cardNetwork}
            // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
            institutionCode={pickerData?.institutionCode}
            disabled={paymentMethod.rejected}
            size={isMobile ? 30 : 42}
            pickerDataSymbol={pickerData?.symbol}
            trueLayerBankProviderId={
              (pickerData as UkBankPickerDataV2)?.trueLayerBankProviderId
            }
            institutionLogoUrl={
              (pickerData as UkBankPickerDataV2)?.institutionLogoUrl
            }
          />
        </IconContainer>
        <AccountTextContainer flexDirection="column">
          <AccountText
            as="label"
            color={paymentMethod.rejected ? color.slate : undefined}
          >
            {label}
          </AccountText>
          <PaymentMethodDescription
            queryRef={query}
            paymentMethod={paymentMethod}
          />
        </AccountTextContainer>
      </TextContainer>
      <Actions>
        {isDigitalWallet && (
          <DigitalWalletRightDetail paymentMethod={paymentMethod} />
        )}
        {paymentMethod.rejected && !paymentMethod.isVerifiable && (
          <Button onPress={handleOnPress} variant="secondary">
            {formatMessage(messages.paymentMethodaddAgainButton)}
          </Button>
        )}
        {paymentMethod.isVerifiable &&
          !paymentMethod.isPendingEmailVerification && (
            <Button onPress={showVerificationModal}>
              {formatMessage(messages.actionsverify)}
            </Button>
          )}
        {paymentMethod.isPendingEmailVerification && (
          <ModalTrigger
            modal={
              <EmailVerificationModal
                // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
                paymentMethodId={pickerData?.pmObjectId || ''}
                onSuccess={handleOnSuccess}
              />
            }
          >
            <Button>{formatMessage(messages.actionsverify)}</Button>
          </ModalTrigger>
        )}
        {paymentMethod.isRevoked && (
          <a onClick={relinkHandler}>{formatMessage(messages.relinkButton)}</a>
        )}
        {paymentMethod.isPending && (
          <TextBody as="p">{formatMessage(messages.actionspending)}</TextBody>
        )}
        {paymentMethod.isPendingAutomaticVerification && (
          <PendingAutomaticVerification />
        )}
        {paymentMethod.isDestroyable && (
          <Button
            testID="delete-account-button"
            loading={isDeleting}
            disabled={isDeleting}
            onPress={showDeleteConfirm}
            variant="secondary"
          >
            {formatMessage(messages.actionsremove)}
          </Button>
        )}
      </Actions>

      {deleteConfirmVisible && (
        <Confirm
          testID="delete-account-confirm"
          title={formatMessage(messages.deleteConfirmTitle)}
          close={hideDeleteConfirm}
          onConfirm={handleDelete}
        >
          <TextBody as="p">{formatMessage(messages.deleteConfirm)}</TextBody>
        </Confirm>
      )}

      {paymentMethod.isVerifiable && verificationModalVisible && (
        <LazyDepositVerificationModal
          paymentMethod={paymentMethod}
          close={hideVerificationModal}
          onSuccess={hideVerificationModal}
          entryPoint={PaymentsModalEntryPoints.SETTINGS}
        />
      )}
    </Row>
  );
}

