const PREFERENCE_EXPIRATION_YEAR = 1;
const expiration = PREFERENCE_EXPIRATION_YEAR * 365;

const cookieOptions = {
  expires: expiration,
  domain: getDomainWithoutSubdomain(),
  path: '/',
};

function getDomainWithoutSubdomain(): string | undefined {
  const hostname = getHostname();
  if (!hostname) {
    return;
  }
  if (hostname === 'localhost') return hostname;
  const [, ...domain] = hostname.split('.');
  return `.${domain.join('.')}`;
}

function getHostname(): string | undefined {
  if (typeof window !== 'undefined') {
    return window.location.hostname;
  }
}

type PrivacyOptionsSectionProps = {
  queryRef: PrivacyOptionsSectionFragment$key;
};

const AdvertisingOptOutAmplitudeEventData: AnalyticsEventData = {
  action: ActionType.click,
  componentType: ComponentType.unknown,
};

function PrivacyOptionsSection({ queryRef }: PrivacyOptionsSectionProps) {
  const { formatMessage, locale } = useIntl();

  const query = useFragment(
    graphql`
      fragment PrivacyOptionsSectionFragment on Query {
        viewer {
          userProperties {
            privacySettings {
              isCryptoAddressDiscoverable
            }
          }
        }
      }
    `,
    queryRef,
  );

  const user = useUser();
  const [updatePrivacySettings] = useMutation<PrivacyOptionsSectionMutation>(
    graphql`
      mutation PrivacyOptionsSectionMutation(
        $input: UpdatePrivacySettingsInput!
      ) {
        updatePrivacySettings(input: $input) {
          __typename
          ... on UpdatePrivacySettingsSuccess {
            privacySettings {
              isCryptoAddressDiscoverable
            }
          }
          ... on BadRequestError {
            message
            code
          }
        }
      }
    `,
  );
  const [toggled, setToggled] = useState(
    Boolean(
      query.viewer.userProperties?.privacySettings?.isCryptoAddressDiscoverable,
    ),
  );

  // Only users in the US and GDPR countries have the ability to opt out of ad tracking
  const adTrackingOptOutEligible = user.isInUS || user.isInEurope;
  const { showSuccessToast, showErrorToast } = useToasts();
  const [marketingTrackingEnabled, setMarketingTrackingEnabled] = useState<
    boolean | null
  >(user.marketingTrackingEnabled);
  const [advertisingSharingAllowedCookie, setAdvertisingSharingAllowedCookie] =
    useCookie('advertising_sharing_allowed');
  const marketingTrackingUpdatedAt = user.marketingTrackingEnabledUpdatedAt;
  const { updateMarketingTrackingEnabled } =
    useUpdateMarketingTrackingEnabled();

  const onUpdateMarketingTrackingEnabled = useCallback(
    (isEnabled: boolean) => {
      updateMarketingTrackingEnabled({
        variables: {
          input: {
            enabled: isEnabled,
            product: 'MARKETING_TRACKING_PRODUCT_COINBASE_WWW',
          },
        },
        onError: () => {
          showErrorToast(formatMessage(messages.saveError));
        },
        onCompleted: () => {},
      });
    },
    [updateMarketingTrackingEnabled, showErrorToast, formatMessage],
  );

  const advertisingSharingAllowedCookieIsNull =
    advertisingSharingAllowedCookie === undefined ||
    advertisingSharingAllowedCookie === null ||
    advertisingSharingAllowedCookie.value === null ||
    advertisingSharingAllowedCookie.value === undefined ||
    advertisingSharingAllowedCookie.updatedAt === null ||
    advertisingSharingAllowedCookie.updatedAt === undefined;

  const marketingTrackingIsNull =
    marketingTrackingUpdatedAt === null || marketingTrackingEnabled === null;

  const initialMarketingTrackingEnabledReconciliation = useCallback(() => {
    // If both the values are null, initialize them to default values.
    if (marketingTrackingIsNull && advertisingSharingAllowedCookieIsNull) {
      const isEnabled = true;
      const updatedAt = Date.now();
      setAdvertisingSharingAllowedCookie(
        {
          value: isEnabled,
          updatedAt,
        },
        cookieOptions,
      );
      setMarketingTrackingEnabled(isEnabled);
      onUpdateMarketingTrackingEnabled(isEnabled);
    } else if (
      // if values from the database are null, set them equal to the cookie stored
      marketingTrackingIsNull
    ) {
      setMarketingTrackingEnabled(advertisingSharingAllowedCookie.value);
      onUpdateMarketingTrackingEnabled(advertisingSharingAllowedCookie.value);
    } else if (
      // if the cookie is null, set it equal to the value stored in the database
      advertisingSharingAllowedCookieIsNull
    ) {
      const marketingTrackingUpdatedAtParsed = Date.parse(
        marketingTrackingUpdatedAt,
      );
      setAdvertisingSharingAllowedCookie(
        {
          value: marketingTrackingEnabled,
          updatedAt: marketingTrackingUpdatedAtParsed,
        },
        cookieOptions,
      );
    } else {
      const advertisingSharingAllowedCookieUpdatedAt =
        advertisingSharingAllowedCookie.updatedAt;
      const marketingTrackingUpdatedAtParsed = Date.parse(
        marketingTrackingUpdatedAt,
      );
      // if both the values exist, compare the timestamps and set them to the value which is more latest
      if (
        marketingTrackingUpdatedAtParsed >
        advertisingSharingAllowedCookieUpdatedAt
      ) {
        // set the cookie to the marketingTrackingUpdatedAt value
        setAdvertisingSharingAllowedCookie(
          {
            value: marketingTrackingEnabled,
            updatedAt: marketingTrackingUpdatedAtParsed,
          },
          cookieOptions,
        );
      } else {
        // set the marketing tracking enabled
        setMarketingTrackingEnabled(advertisingSharingAllowedCookie.value);
        onUpdateMarketingTrackingEnabled(advertisingSharingAllowedCookie.value);
      }
    }
  }, [
    marketingTrackingEnabled,
    advertisingSharingAllowedCookie,
    advertisingSharingAllowedCookieIsNull,
    marketingTrackingIsNull,
    marketingTrackingUpdatedAt,
    onUpdateMarketingTrackingEnabled,
    setAdvertisingSharingAllowedCookie,
  ]);

  useEffect(() => {
    initialMarketingTrackingEnabledReconciliation();
  }, []);

  const handleDiscoverabilityToggleChange = useCallback(
    (event: ChangeEvent<HTMLInputElement>) => {
      const isCryptoAddressDiscoverable = event.target.checked;
      setToggled(isCryptoAddressDiscoverable);
      updatePrivacySettings({
        variables: {
          input: {
            isCryptoAddressDiscoverable,
          },
        },
        onCompleted: ({ response }) => {
          matchUnion(response.updatePrivacySettings)
            .when('UpdatePrivacySettingsSuccess', () => {
              showSuccessToast(formatMessage(messages.saved));
            })
            .when('BadRequestError', e => {
              notifyError(getErrorInstance(e), {
                owner: 'settings',
                context: 'discoverability_preferences',
              });
              setToggled(!isCryptoAddressDiscoverable);
              showErrorToast(e.message);
            })
            .otherwise(variant => {
              notifyError(getErrorInstance(variant), {
                owner: 'settings',
                context: 'discoverability_preferences',
              });
              setToggled(!isCryptoAddressDiscoverable);
              showErrorToast(`Unexpected error: ${String(variant)}`);
            });
        },
        onError: ({ alreadyReportedError }) => {
          notifyError(getErrorInstance(alreadyReportedError), {
            owner: 'settings',
            context: 'discoverability_preferences',
          });
          setToggled(!isCryptoAddressDiscoverable);
          showErrorToast(alreadyReportedError.message);
        },
      });
    },
    [formatMessage, updatePrivacySettings, showSuccessToast, showErrorToast],
  );

  const handleMarketingToggleChange = useCallback(
    (event: ChangeEvent<HTMLInputElement>) => {
      const isEnabled = event.target.checked;
      setMarketingTrackingEnabled(isEnabled);

      onUpdateMarketingTrackingEnabled(isEnabled);
      // logEvent to Amplitude
      if (isEnabled) {
        logEvent(
          'advertising_sharing_logged_in_web_toggle_enabled',
          AdvertisingOptOutAmplitudeEventData,
        );
      } else {
        logEvent(
          'advertising_sharing_logged_in_web_toggle_disabled',
          AdvertisingOptOutAmplitudeEventData,
        );
      }
      // set the cookie value as well
      setAdvertisingSharingAllowedCookie(
        {
          value: isEnabled,
          updatedAt: Date.now(),
        },
        cookieOptions,
      );
    },
    [
      setMarketingTrackingEnabled,
      onUpdateMarketingTrackingEnabled,
      setAdvertisingSharingAllowedCookie,
    ],
  );

  return (
    <SettingsTabSection
      title={formatMessage(messages.header)}
      description={formatMessage(messages.headerDescription, {
        learnMoreLink: (
          <Link
            key="one"
            href={`https://help.coinbase.com/${locale}/coinbase/privacy-and-security/data-privacy/what-is-the-gdpr`}
            openInNewWindow
            underline={false}
          >
            {formatMessage(messages.learnMore)}
          </Link>
        ),
      })}
    >
      <ListCell
        title={formatMessage(messages.addressDiscoverabilityToggleTitle)}
        description={formatMessage(
          messages.addressDiscoverabilityToggleDescription,
        )}
        action={
          <Switch
            checked={toggled}
            onChange={handleDiscoverabilityToggleChange}
          />
        }
        outerSpacing={{ spacingVertical: 1, spacingHorizontal: 0 }}
        priority={'end'}
        multiline
      />
      {adTrackingOptOutEligible && (
        <ListCell
          title={formatMessage(messages.useYourActivityToggleTitle)}
          description={formatMessage(
            messages.useYourActivityToggleDescription,
            {
              learnMoreLink: (
                <Link
                  key="one"
                  href={`https://help.coinbase.com/${locale}/coinbase/privacy-and-security/data-privacy/what-is-the-gdpr`}
                  openInNewWindow
                >
                  {formatMessage(messages.learnMore)}
                </Link>
              ),
            },
          )}
          action={
            <Switch
              checked={!!marketingTrackingEnabled}
              onChange={handleMarketingToggleChange}
            />
          }
          outerSpacing={{ spacingVertical: 1, spacingHorizontal: 0 }}
          priority={'end'}
          multiline
        />
      )}
    </SettingsTabSection>
  );
}

export default PrivacyOptionsSection;

