};

const policyLink = (href: string, message: string) => (
  <a href={href} target="_blank" rel="noopener noreferrer">
    {message}
  </a>
);

export const normalizeField = (field: string) => {
  if (field === 'Delete all of my data') return 'all';
  return field.replaceAll('-', ' ').toLowerCase();
};

function Section({ section: { options, prompt, bullets, divider }, i }: Props) {
