      )}
      {options &&
        options.map(({ name, label, tooltip }) =>
          bullets ? (
            <CheckboxContainer
              key={name}
              // @ts-expect-error This prop doesn't exist yet it's still used
              columnView
            >
              <Bullet>{label}</Bullet>
            </CheckboxContainer>
          ) : (
