}

export default memo(
  ({
    type,
    close,
  }: {
    type: typeof RequestTypes[keyof typeof RequestTypes];
    close?: () => void;
    stepName: string;
  }) => {
    const { formatMessage } = useIntl();
    const { setFormData } = useContext(PrivacyRequestContext);
    const goTo2FA = useStepFunction('2fa');
    const [error, setError] = useState<Error | undefined>();
    const onSuccess = useStepFunction('success');
    const goToConfirm = useStepFunction('confirmDeletion');
    const userInPrivacyBermudaExperiment = usePrivacyBermudaExperiment();
    const userInPriventExperiment = usePriventExperiment();

    const query = useLazyLoadQuery<FormOptionsQuery>(
      graphql`
        query FormOptionsQuery {
          ...useIsOnboardedToIntxFragment
        }
      `,
      {},
    );

    const isOnboardedToIntx = useIsOnbordedToIntx({
      queryRef: query,
    });

    const submit = useMemo(
      () =>
        submitter({
          requestType: type,
          goTo2FA,
          onError: setError,
          onSuccess,
          isOnboardedToIntx,
        }),
      [type, goTo2FA, onSuccess, isOnboardedToIntx],
    );

    const { createDsarRequest } = useCreateDsarRequest();

    const onCreateDsarRequest = useCallback(
      (
        fields: string[],
        requestAction: DsarAction,
        requestorComment: string,
        productsInScope: DsarProductCategory[],
      ) => {
        createDsarRequest({
          variables: {
            input: {
              fields,
              requestAction,
              requestorComment,
              productsInScope: productsInScope
                ? (productsInScope as DsarProductCategory[])
                : null,
            },
          },
          onCompleted: () => {
            onSuccess?.();
          },
          onError: error => {
            notifyError(getErrorInstance(error.alreadyReportedError), {
              owner: 'settings',
              context: 'privacy',
            });
          },
        });
      },
      [createDsarRequest, onSuccess],
    );

    const {
      modalDescription,
      modalAction,
      modalTitle,
      title,
      productDescription,
      products,
    } = getInfo(type, formatMessage);

    const handleOnSubmit = useCallback(
      // @ts-expect-error: 2021-02-19: Whitelisted implicitAny error. Please fix. */
      async formData => {
        setFormData(formData);
        setError(undefined);

        const fields = Object.keys(formData)
          .filter(field => formData[field] === true)
          .map(normalizeField);

        const productsInScope = [];
        const products = [Exchange.International, Exchange.Exchange];

        // `productsInScope` Values Capitalized to Match Enums for Requests to Retail DSAR
        if (fields.includes(Exchange.International)) {
          productsInScope.push(ProductScope.Spot);
        }
        if (fields.includes(Exchange.Exchange)) {
          productsInScope.push(ProductScope.Retail);
        }

        let productCategories: DsarProductCategory[] = [];
        if (productsInScope.length > 0) {
          productCategories = productsInScope as DsarProductCategory[];
        }

        const fieldsWithoutProducts = fields.filter(
          item => !products.includes(item as Exchange),
        );

        if (formData['Delete all of my data']) {
          goToConfirm();
        } else {
          // Privent DSAR Experiment (2FA Not Supported for Experiment)
          if (userInPriventExperiment) {
            onCreateDsarRequest(
              fieldsWithoutProducts,
              type.toUpperCase() as DsarAction,
              formData['Additional message'] || '',
              productCategories,
            );
          } else {
            // Monorail DSAR Operations
            await submit(formData);
          }
        }
      },
      [
        goToConfirm,
        onCreateDsarRequest,
        setFormData,
        submit,
        type,
        userInPriventExperiment,
      ],
    );

    const handleOnChange = useCallback(
      // @ts-expect-error: 2021-02-19: Whitelisted implicitAny error. Please fix. */
      formData => {
        setFormData(formData);
      },
      [setFormData],
    );

    return (
      <Modal close={close} width="large" disableTransition>
        <ModalHeader title={modalTitle || title} />
        <ModalBody>
          <Form
            /*
 // @ts-expect-error: 2021-02-19: Whitelisted implicitAny error. Please fix. */
            onSubmit={handleOnSubmit}
            // @ts-expect-error: 2021-02-19: Whitelisted implicitAny error. Please fix. */
            onChange={handleOnChange}
          >
            {modalDescription && (
              <Container>
                <TextLabel1 as="p">{modalDescription}</TextLabel1>
              </Container>
            )}

            {userInPrivacyBermudaExperiment && (
              <PolicyLinkContainer>
                <Box justifyContent="flex-end">
                  <TextLabel1 as="p">
                    {formatMessage(messages.privacyPolicyDescription, {
                      privacyPolicyLink: policyLink(
                        'https://www.coinbase.com/legal/privacy',
                        formatMessage(messages.privacyPolicyLink),
                      ),
                    })}
                  </TextLabel1>
                </Box>
              </PolicyLinkContainer>
            )}

            <Box justifyContent="space-between">
              {userInPrivacyBermudaExperiment &&
                isOnboardedToIntx &&
                productDescription && (
                  <Container>
                    <TextBody as="p">{productDescription}</TextBody>
                    <HStack spacerGap={2} spacingTop={2}>
                      {products &&
                        products.map((product, i) => (
                          <Checkbox
                            key={i}
                            name={product.name}
                            label={
                              <Box alignItems="center">
                                <Body>{product.name}</Body>
                                {!!product.tooltip && (
                                  <TooltipContainer>
                                    <TooltipTrigger
                                      isDark
                                      align="right"
                                      content={product.tooltip}
                                    >
                                      <QuestionMark />
                                    </TooltipTrigger>
                                  </TooltipContainer>
                                )}
                              </Box>
                            }
                            labelPosition="right"
                          />
                        ))}
                    </HStack>
                  </Container>
                )}
            </Box>
            {error && error.message === ProductsNotSelected && (
              <StyledInlineError>{error.message}</StyledInlineError>
            )}
            {getOptions(type, formatMessage).map((section, i) => (
              <Section section={section} i={i} />
            ))}
            {type === 'object' && (
              <Container>
                <FormLabel>
                  <TextLabel1 as="p">
                    {formatMessage(messages.objectionReasoning)}
                  </TextLabel1>
                </FormLabel>
                <ValidatedInput
                  name="Additional message"
                  validators={[]}
                  component="textarea"
                />
              </Container>
            )}
            {error && error.message !== ProductsNotSelected && (
              <StyledInlineError>{error.message}</StyledInlineError>
            )}
            {modalAction && (
              <Button
                type="submit"
                eventName="request_tapped_send_request"
                block
              >
                {modalAction}
              </Button>
            )}
          </Form>
        </ModalBody>
      </Modal>
    );
  },
);

