import messages from '../messages';
import { WhitelistingInfoModalContent } from './WhitelistingInfoModal/WhitelistingInfoModalContent';
import WhitelistTwoFactorContent from './WhitelistingInfoModal/WhitelistTwoFactorContent';

export function TogglerButton() {
  const { formatMessage } = useIntl();
  const { enabled, toggleWhitelistSettings } = useContext(WhitelistContext);
  const [isToggled, { toggle, toggleOn }] = useToggler(enabled);

  useEffect(() => {
    if (enabled) {
      toggleOn();
    }
  }, [enabled]);

  const infoModal = useModal();
  const twoFaModal = useModal();

  const open2FaModal = useCallback(() => {
    // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
    const handleSuccess = (token: string) => {
      toggleWhitelistSettings(!enabled, token).then(status => {
        if (status) {
          twoFaModal.closeModal();
          toggle();
        }
      });
    };

    twoFaModal.openModal(
      <Modal visible onRequestClose={twoFaModal.closeModal}>
        <ModalBody>
          <WhitelistTwoFactorContent handleSuccess={handleSuccess} />
        </ModalBody>
      </Modal>,
    );
  }, [enabled, toggle, toggleWhitelistSettings, twoFaModal]);

  const openInfoModal = useCallback(() => {
    infoModal.openModal(
      <Modal
        testID="whitelisting-info-modal"
        visible
        onRequestClose={infoModal.closeModal}
      >
        <WhitelistingInfoModalContent
          closeModal={infoModal.closeModal}
          openNextModal={open2FaModal}
        />
      </Modal>,
    );
  }, [infoModal, open2FaModal]);

  const handleChange = useCallback(() => {
    if (enabled) open2FaModal();
    else openInfoModal();
  }, [enabled, open2FaModal, openInfoModal]);

  return (
    <HStack as="div">
      <Box flexGrow={1}>
        <TextHeadline as="span">
          {formatMessage(messages.whitelistingLabelV2)}
        </TextHeadline>
      </Box>

      <Switch
        testID="toggler-button"
        checked={isToggled}
        onChange={handleChange}
      />
    </HStack>
  );
}

import {
  useMemo,
  type ErrorInfo,
  memo,
  useCallback,
  useEffect,
  useState,
} from 'react';
import qs from 'query-string';
import { Route, Switch, useLocation } from 'react-router-dom';

import {
  AddressStep,
  AddressConfirmStep,
  AddressPendingStep,
  ConfirmEmailStep,
  IdentityStep,
  IDVStep,
  PendingDocumentsStep,
  EmailPreferenceStep,
  AttestationsStep,
  SuitabilityStep,
  EDPCStep,
  TOSStep,
  NationalityStep,
  RemediationAlertStep,
  ConfirmDetailsStep,
  CDDStep,
  ExtendedCDDStep,
  RfiPepStep,
  BasicKYCStep,
  KYCRefreshStep,
  BirthplaceStep,
  BlockedOnboardingStep,
  RiskDisclosureStep,
  ConsentStep,
  DOBStep,
  RDVStep,
  IDVMissingAddressStep,
  CustomerCategorisationStep,
  WEMStep,
