import ErrorBoundary from 'components/ErrorBoundary';
import FullScreenSpinner from 'components/FullScreenSpinner';
import {
  ApplicationContextProvider,
  onboardingContext,
} from 'context/applicationContext';
import { useGetEligibilityForProvePrefill } from 'hooks/useGetEligibilityForProvePrefill';
import useGetGuidanceDetails from 'hooks/useGetGuidanceDetails';
import useIsSdkIdvEligible from 'hooks/useIsSdkIdvEligible';
import useOnboarding from 'hooks/useOnboarding';
import useOnboardingUnskip from 'hooks/useOnboardingUnskip';
import useUser from 'hooks/useUser';
import { client } from 'utils/client';

import ErrorBoundaryWithCause from './components/ErrorBoundaryWithCause';
import Layout from './components/Layout';
import { LazySetupDepositCrypto } from './components/SetupDepositCrypto';
import SetupPhoneNumber from './components/SetupPhoneNumber';
import { LazySetupPlaid } from './components/SetupPlaid';
import useKYCRefresh from './useKYCRefresh';
import useSetup from './useSetup';

function Setup() {
  const { countryCode, email } = useUser();
  const unskipOnboarding = useOnboardingUnskip();
  const [showFullScreenSpinner, setShowFullScreenSpinner] = useState(false);

  const isOnboardingGuidanceEnabled = useOnboardingGuidance(countryCode);
  const trackOnboardingGuidance =
    useTrackOnboardingGuidanceExposure(countryCode);

  const {
    remainingVerification,
    nextVerificationPath,
    setHasViewedRemediationAlert,
    showSkipButton,
    setShowSkipButton,
  } = useOnboarding();

  const {
    onIDVOrPOAUpdate,
    onIDVNextStep,
    onIdvContinue,
    onPOASubmit,
    onPendingTryAgain,
    setOnboardingGuidance,
    onGuidanceRetry,
  } = useSetup();

  const {
    onKYCRefreshCDDItemEdit,
    onKYCRefreshEDPItemEdit,
    onKYCRefreshEDPCPersonalInfoItemEdit,
    onKYCRefreshEDPCAddressItemEdit,
    onKYCRefreshNationalityEdit,
    onKYCRefreshBasicKYCItemEdit,
    onKYCRefreshSuitabilityItemEdit,
  } = useKYCRefresh();

  const getGuidanceDetails = useGetGuidanceDetails(
    client,
    remainingVerification?.verification || '',
    trackOnboardingGuidance,
    () => setShowFullScreenSpinner(false),
  );

  const location = useLocation<{ referrer: string }>();

  const showGermanySkipConfirmation =
    location.state?.referrer === '/skip-de-onboarding';

  const isProvePrefillEligible = useGetEligibilityForProvePrefill({
    isUSUser: countryCode === 'US',
    verificationMetadata: remainingVerification?.verificationMetadata,
  });

  const { isEligible: isSdkEligible } = useIsSdkIdvEligible();

  const disableSkipForPrefillEDP = useMemo(() => {
    return isProvePrefillEligible && location.pathname === '/setup/identity';
  }, [location.pathname, isProvePrefillEligible]);

  const checkAndShowOnboardingGuidance = useCallback(async () => {
    const guidanceData = await getGuidanceDetails();
    if (guidanceData && isOnboardingGuidanceEnabled) {
      setOnboardingGuidance(guidanceData);
    }

    setShowFullScreenSpinner(false);
  }, [getGuidanceDetails, isOnboardingGuidanceEnabled, setOnboardingGuidance]);

  const handleIDVNextStep = useCallback(() => {
    if (
      isOnboardingGuidanceEnabled &&
      remainingVerification?.verification === 'idv_required'
    ) {
      checkAndShowOnboardingGuidance();
    } else onIDVNextStep();
  }, [
    isOnboardingGuidanceEnabled,
    remainingVerification?.verification,
    onIDVNextStep,
    checkAndShowOnboardingGuidance,
  ]);

  const handlePOASubmit = useCallback(() => {
    if (isOnboardingGuidanceEnabled) {
      checkAndShowOnboardingGuidance();
    } else onPOASubmit();
  }, [
    isOnboardingGuidanceEnabled,
    onPOASubmit,
    checkAndShowOnboardingGuidance,
  ]);
  const idvProps = {
    onUpdate: onIDVOrPOAUpdate,
    onNextStep: handleIDVNextStep,
    onContinue: onIdvContinue,
    skipIDCaptureIntro: !!remainingVerification?.state.isIDVRetry,
    pendingVerificationDocumentId:
      remainingVerification?.pendingVerificationDocumentId || undefined,
    pendingVerificationFacematchDocumentId:
      remainingVerification?.pendingVerificationFacematchDocumentId ||
      undefined,
  };

  const handleError = useCallback((error: Error, errorInfo?: ErrorInfo) => {
    if (!shouldDisregardError(error)) {
      /**
       * Notify error and log the error to Datadog/Amplitude
       */
      notifyError(error, {
        componentStack: error?.stack ?? errorInfo?.componentStack,
        owner: 'onboarding',
        isBoundaryError: true,
        context: 'setup',
      });

      logEvent('onboarding_unhandled_error_web', {
        componentType: ComponentType.content_script,
        action: ActionType.measurement,
        experience: typeof error.cause === 'string' ? error.cause : 'unknown',
        error: error instanceof Error ? error.message : 'unknown',
      });
    }

    // Re-throw the error so it can be handled by the outer error boundary and appropriate fallback rendered
    throw error;
  }, []);

  const handleUnskipOnboarding = useCallback(async () => {
    await unskipOnboarding();
    window.location.replace('/setup');
  }, [unskipOnboarding]);

  useEffect(() => {
    const queryParams = qs.parse(window.location.search, {
      parseBooleans: true,
    });

    if (queryParams.unskip_onboarding) {
      handleUnskipOnboarding();
    }
  }, [window.location.search]);

  useEffect(() => {
    if (
      remainingVerification?.verification !== 'onboarding_guidance' &&
      !remainingVerification?.state?.hasRedirected
    ) {
      checkAndShowOnboardingGuidance();
    }
  }, [remainingVerification?.verification]);

  const renderConfirmEmailStep = useCallback(() => {
    return (
      <ErrorBoundaryWithCause cause="ConfirmEmailStep">
        <ConfirmEmailStep email={email} />
      </ErrorBoundaryWithCause>
    );
  }, [email]);

  const renderSetupPhoneNumber = useCallback(() => {
    return (
      <ErrorBoundaryWithCause cause="SetupPhoneNumber">
        <SetupPhoneNumber />
      </ErrorBoundaryWithCause>
    );
  }, []);

  const renderIdentityStep = useCallback(() => {
    return (
      <ErrorBoundaryWithCause cause="IdentityStep">
        <IdentityStep
          showGermanySkipConfirmation={showGermanySkipConfirmation}
          isProvePrefillEligible={isProvePrefillEligible}
        />
      </ErrorBoundaryWithCause>
    );
  }, [isProvePrefillEligible, showGermanySkipConfirmation]);

  const renderBasicKYCStep = useCallback(
    () => (
      <ErrorBoundaryWithCause cause="BasicKYCStep">
        <BasicKYCStep />
      </ErrorBoundaryWithCause>
    ),
    [],
  );

  const renderEmailPreferenceStep = useCallback(
    () => (
      <ErrorBoundaryWithCause cause="EmailPreferenceStep">
        <EmailPreferenceStep />
      </ErrorBoundaryWithCause>
    ),
    [],
  );

  const renderTOSStep = useCallback(
    () => (
      <ErrorBoundaryWithCause cause="TOSStep">
        <TOSStep />
      </ErrorBoundaryWithCause>
    ),
    [],
  );

  const renderRiskDisclosureStep = useCallback(
    () => (
      <ErrorBoundaryWithCause cause="RiskDisclosureStep">
        <RiskDisclosureStep />
      </ErrorBoundaryWithCause>
    ),
    [],
  );

  const renderConsentStep = useCallback(
    () => (
      <ErrorBoundaryWithCause cause="ConsentStep">
        <ConsentStep />
      </ErrorBoundaryWithCause>
    ),
    [],
  );

  const renderNationalityStep = useCallback(() => <NationalityStep />, []);

  const renderCustomerCategorisation = useCallback(
    () => (
      <ErrorBoundaryWithCause cause="CustomerCategorisation">
        <CustomerCategorisationStep />
      </ErrorBoundaryWithCause>
    ),
    [],
  );

  if (showFullScreenSpinner) {
    return <FullScreenSpinner />;
  }

  return (
    <ErrorBoundary
      owner="onboarding"
      skipErrorLogging={true}
      onCatch={handleError}
      context="setup"
    >
      <ApplicationContextProvider applicationContext={onboardingContext}>
        <Layout
          verificationPath={nextVerificationPath}
          countryCode={countryCode}
          skippable={
            (remainingVerification?.verificationMetadata?.skippable &&
              !disableSkipForPrefillEDP &&
              showSkipButton) ??
            false
          }
        >
          <Switch>
            <Route path="/setup/confirm" render={renderConfirmEmailStep} />

            <Route path="/setup/phone" render={renderSetupPhoneNumber} />

            <Route path="/setup/remediate">
              <ErrorBoundaryWithCause cause="RemediationAlertStep">
                <RemediationAlertStep
                  onComplete={setHasViewedRemediationAlert}
                />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/identity" render={renderIdentityStep} />

            <Route path="/setup/dob">
              <ErrorBoundaryWithCause cause="DOBStep">
                <DOBStep />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/birthplace">
              <ErrorBoundaryWithCause cause="BirthplaceStep">
                <BirthplaceStep />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/basic-kyc" render={renderBasicKYCStep} />

            <Route
              path="/setup/email-preference"
              render={renderEmailPreferenceStep}
            />

            <Route path="/setup/terms-of-service" render={renderTOSStep} />

            <Route
              path="/setup/risk-disclosure"
              render={renderRiskDisclosureStep}
            />

            <Route path="/setup/consent" render={renderConsentStep} />

            <Route path="/setup/nationality" render={renderNationalityStep} />

            <Route
              path="/setup/customer-categorisation"
              render={renderCustomerCategorisation}
            />

            <Route path="/setup/confirm-details">
              <ErrorBoundaryWithCause cause="ConfirmDetailsStep">
                <ConfirmDetailsStep />
              </ErrorBoundaryWithCause>
            </Route>
            <Route path="/setup/customer-due-diligence">
              <ErrorBoundaryWithCause cause="CDDStep">
                <CDDStep />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/vendor-verification">
              <ErrorBoundaryWithCause cause="VendorVerificationStep">
                <VendorVerificationStep />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/enhanced-due-diligence">
              <ErrorBoundaryWithCause cause="EDDStep">
                <WEMStep />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/extended-customer-due-diligence">
              <ErrorBoundaryWithCause cause="ExtendedCDDStep">
                <ExtendedCDDStep isRetry={false} />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/blocked-onboarding">
              <ErrorBoundaryWithCause cause="BlockedOnboardingStep">
                <BlockedOnboardingStep />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/document">
              <ErrorBoundaryWithCause cause="IDVStep">
                <IDVStep
                  {...idvProps}
                  isOnboardingGuidanceEnabled={isOnboardingGuidanceEnabled}
                  onfido={isSdkEligible}
                  hideInstructions
                />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/document-address">
              <ErrorBoundaryWithCause cause="IDVMissingAddressStep">
                <IDVMissingAddressStep {...idvProps} />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/idv-tax-id">
              <ErrorBoundaryWithCause cause="IDVMissingTaxIdStep">
                <IDVMissingTaxIdStep
                  {...idvProps}
                  isOnboardingGuidanceEnabled={isOnboardingGuidanceEnabled}
                />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/facematch">
              <ErrorBoundaryWithCause cause="IDVStep">
                <IDVStep
                  facematch
                  {...idvProps}
                  onfido={isSdkEligible}
                  facematchType="face"
                  forceCrossDevice={false}
                  hideInstructions
                />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/document-liveness">
              <ErrorBoundaryWithCause cause="IDVStep">
                <IDVStep
                  {...idvProps}
                  onfido
                  facematchType="video"
                  forceCrossDevice={countryCode === 'ES'}
                  pendingVerificationDocumentId={undefined}
                  pendingVerificationFacematchDocumentId={undefined}
                  // force to stay in @cbhq/id-capture pending state
                  shouldSkipIDVPendingScreen={false}
                  isOnboardingGuidanceEnabled={false}
                />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/proof-of-address">
              <ErrorBoundaryWithCause cause="AddressStep">
                <AddressStep
                  onUpdate={onIDVOrPOAUpdate}
                  onSubmit={handlePOASubmit}
                  isOnboardingGuidanceEnabled={isOnboardingGuidanceEnabled}
                />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/proof-of-address-confirm">
              <ErrorBoundaryWithCause cause="AddressConfirmStep">
                <AddressConfirmStep />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/proof-of-address-pending">
              <ErrorBoundaryWithCause cause="AddressPendingStep">
                <AddressPendingStep />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/rdv">
              <ErrorBoundaryWithCause cause="RDVStep">
                <RDVStep />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/pending-documents">
              <ErrorBoundaryWithCause cause="PendingDocumentsStep">
                <PendingDocumentsStep onTryAgain={onPendingTryAgain} />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/rfi-pep">
              <ErrorBoundaryWithCause cause="RfiPepStep">
                <RfiPepStep />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/attestations">
              <ErrorBoundaryWithCause cause="AttestationsStep">
                <AttestationsStep />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/suitability">
              <ErrorBoundaryWithCause cause="SuitabilityStep">
                <SuitabilityStep />
              </ErrorBoundaryWithCause>
            </Route>

            <Route path="/setup/edpc">
              <ErrorBoundaryWithCause cause="EDPCStep">
                <EDPCStep />
              </ErrorBoundaryWithCause>
            </Route>
            <Route path="/setup/add-payment">
              <ErrorBoundaryWithCause cause="LazySetupPlaid">
                <LazySetupPlaid />
              </ErrorBoundaryWithCause>
            </Route>
            <Route path="/setup/deposit-crypto">
              <ErrorBoundaryWithCause cause="LazySetupDepositCrypto">
                <LazySetupDepositCrypto />
              </ErrorBoundaryWithCause>
            </Route>
            <Route path="/setup/kyc-refresh-alert">
              <ErrorBoundaryWithCause cause="RemediationAlertStep">
                <RemediationAlertStep
                  illustration="VerifyInfo"
                  onComplete={setHasViewedRemediationAlert}
                />
              </ErrorBoundaryWithCause>
            </Route>
            <Route path="/setup/kyc-refresh">
              <ErrorBoundaryWithCause cause="KYCRefreshStep">
                <KYCRefreshStep
                  setShowSkipButton={setShowSkipButton}
                  onCDDItemEdit={onKYCRefreshCDDItemEdit}
                  onEDPItemEdit={onKYCRefreshEDPItemEdit}
                  onEDPCPersonalInfoItemEdit={
                    onKYCRefreshEDPCPersonalInfoItemEdit
                  }
                  onEDPCAddressItemEdit={onKYCRefreshEDPCAddressItemEdit}
                  onNationalityEdit={onKYCRefreshNationalityEdit}
                  onBasicKYCItemEdit={onKYCRefreshBasicKYCItemEdit}
                  onSuitabilityItemEdit={onKYCRefreshSuitabilityItemEdit}
                />
              </ErrorBoundaryWithCause>
            </Route>
            <Route path="/setup/info">
              <ErrorBoundaryWithCause cause="WEMStep">
                <WEMStep />
              </ErrorBoundaryWithCause>
            </Route>
            <Route path="/setup/appropriateness-assessment">
              <ErrorBoundaryWithCause cause="CAAStep">
                <CAAStep />
              </ErrorBoundaryWithCause>
            </Route>
            <Route path="/setup/virtual-account-agreement">
              <ErrorBoundaryWithCause cause="VirtualAccountAgreementStep">
                <VirtualAccountAgreementStep />
              </ErrorBoundaryWithCause>
            </Route>
            <Route path="/setup/account-setup">
              <ErrorBoundaryWithCause cause="AccountSetup">
                <AccountSetupStep />
              </ErrorBoundaryWithCause>
            </Route>
            <Route path="/setup/onboarding-guidance">
              <ErrorBoundaryWithCause cause="OnboardingGuidanceStep">
                <OnboardingGuidanceStep
                  guidanceDetails={
                    remainingVerification?.state?.guidanceDetails
                  }
                  onRetry={onGuidanceRetry}
                />
              </ErrorBoundaryWithCause>
            </Route>
          </Switch>
        </Layout>
      </ApplicationContextProvider>
    </ErrorBoundary>
  );
}

