type Props = {
  onClose: () => void;
};

function ReferralsModal({ onClose }: Props) {
  const { formatMessage } = useIntl();
  const spectrum = useSpectrum();
  const toast = useToast();
  const { copyText } = useClipboardApi();

  const query = useLazyLoadQuery<ReferralsModalQuery>(
    graphql`
      query ReferralsModalQuery {
        ...useSubscriptionReferralsFragment
        ...LearnMoreFragment
        ...ReferralsOverviewFragment
        ...useIsReferralRewardZeroFragment
      }
    `,
    {},
  );

  const style = useMemo(
    () => ({
      backgroundColor: paletteValueToRgbaString('green0', spectrum),
    }),
    [spectrum],
  );

  const [copied, setCopied] = useState(false);
  const [showLearnMoreModal, setShowLearnMoreModal] = useState(false);
  const [showReferralsOverview, setShowReferralsOverview] = useState(false);

  const {
    rewardAmount,
    usersReferred,
    totalCreditEarned,
    referralCode,
    totalCreditEarnedNumber,
  } = useSubscriptionReferrals({ queryRef: query });

  const isRewardZero = useIsReferralRewardZero({ queryRef: query });

  const handlePressCopy = useCallback(() => {
    copyText(referralURL(referralCode));
    setCopied(true);
    toast.show(formatMessage(messages.inviteLinkCopied));
  }, [copyText, formatMessage, referralCode, toast]);
  const onPressLearnMore = useCallback(() => {
    logSubscriptionManageEvent({
      action: ActionType.click,
      componentType: ComponentType.button,
      additionalProperties: {
        componentName: 'referrals_modal_learn_more',
        flow: 'referrals',
      },
    });
    setShowLearnMoreModal(true);
  }, []);
  const onPressEarnedCredit = useCallback(() => {
    logSubscriptionManageEvent({
      action: ActionType.click,
      componentType: ComponentType.button,
      additionalProperties: {
        componentName: 'referrals_modal_earned_credit',
        flow: 'referrals',
      },
    });
    if (!isRewardZero || totalCreditEarnedNumber > 0) {
      setShowReferralsOverview(true);
    }
  }, [isRewardZero, totalCreditEarnedNumber]);

  const renderFallback = useCallback(
    () => <ErrorContent onPressTryAgain={onClose} />,
    [onClose],
  );

  const handleOnBack = useCallback(() => setShowLearnMoreModal(false), []);

  const handleOnBack1 = useCallback(() => setShowReferralsOverview(false), []);

  return (
    <Modal onRequestClose={onClose} visible={true}>
      <Cb1ErrorBoundary boundaryName="ReferralsModal" fallback={renderFallback}>
        {showLearnMoreModal && (
          <LearnMore queryRef={query} onBack={handleOnBack} />
        )}
        {showReferralsOverview && (
          <ReferralsOverview queryRef={query} onBack={handleOnBack1} />
        )}
        {!showLearnMoreModal && !showReferralsOverview && (
          <>
            <ModalHeader title={formatMessage(messages.modalHeader)} />
            <ModalBody>
              <VStack alignItems="center" spacerGap={3}>
                <SpotRectangle name="referralsCoinbaseOne" />
                {usersReferred > 0 && (
                  <Pressable
                    onPress={onPressEarnedCredit}
                    background="transparent"
                  >
                    <HStack
                      spacerGap={1}
                      alignItems="center"
                      borderRadius="roundedSmall"
                      style={style}
                    >
                      <TextLabel1 as="p" color="positive">
                        {totalCreditEarnedNumber > 0
                          ? formatMessage(messages.creditEarned, {
                              amount: totalCreditEarned,
                            })
                          : formatMessage(messages.friendsSignedUp, {
                              amount: usersReferred,
                            })}
                      </TextLabel1>
                      {!isRewardZero && (
                        <Icon size="s" name="info" color="positive" />
                      )}
                    </HStack>
                  </Pressable>
                )}
                <TextTitle2 align="center" as="h2">
                  {formatMessage(
                    isRewardZero ? messages.titleZeroReward : messages.title,
                    { productName: PRODUCT_NAME, amount: rewardAmount },
                  )}
                </TextTitle2>
                <TextLabel2 color="foregroundMuted" align="center" as="p">
                  {formatMessage(
                    isRewardZero
                      ? messages.descriptionZeroReward
                      : messages.description,
                    {
                      amount: rewardAmount,
                      link: (children: React.ReactNode) => {
                        return [
                          <Link
                            onPress={onPressLearnMore}
                            color="primary"
                            to="#"
                          >
                            {[children]}
                          </Link>,
                        ];
                      },
                      productName: PRODUCT_NAME,
                    },
                  )}
                </TextLabel2>
              </VStack>
              <HStack alignItems="flex-end" spacingTop={3} spacerGap={2}>
                <TextInput
                  label={formatMessage(messages.shareInviteLink)}
                  value={referralURL(referralCode)}
                  readOnly
                />
                <Button
                  onPress={handlePressCopy}
                  variant={copied ? 'positive' : 'primary'}
                >
                  <HStack alignItems="center" spacerGap={1}>
                    <TextHeadline color="primaryForeground" as="p">
                      {formatMessage(copied ? messages.copied : messages.copy)}
                    </TextHeadline>
                    <Icon
                      name={copied ? 'checkmark' : 'copy'}
                      size="s"
                      color="primaryForeground"
                    />
                  </HStack>
                </Button>
              </HStack>
            </ModalBody>
          </>
        )}
      </Cb1ErrorBoundary>
    </Modal>
  );
}

export default ReferralsModal;

