import { useMonotonicallyIncreasingId } from 'product/cb1/utils/useGuid';

type FAQItemProps = {
  index: number;
  question: React.ReactNode;
  answer: React.ReactNode[];
  format: 'paragraphs' | 'paragraphWithList';
};

type FAQTextBodyProps = {
  children: React.ReactNode;
};

function FAQTextBody({ children }: FAQTextBodyProps) {
  return (
    <TextBody as="p" spacingBottom={1} color="foregroundMuted">
      {children}
    </TextBody>
  );
}

function FAQItem({ question, answer, format, index }: FAQItemProps) {
  const isPhone = useScreenMatch('phone');
  const [isOpen, setIsOpen] = useState(false);
  const genId = useMonotonicallyIncreasingId();
  const [uid] = useState(() => genId());

  const formattedAnswer = useMemo(() => {
    if (format === 'paragraphWithList') {
      const [firstParagraph, ...listItems] = answer;
      return (
        <>
          <FAQTextBody>{firstParagraph}</FAQTextBody>
          <List removeStyles={true}>
            {listItems.map((listItem, index) => {
              return (
                // Using index as key is not ideal here, however now that we have
                // rich text coming from react-intl we can't use the item itself
                // as the key. FAQ items currently do not change on the fly, so that's ok.
                // TODO: provide UUIDs or refactor so this is not a concern.
                <HStack as="li" spacerGap={0.5} key={index}>
                  <Icon
                    name="caretRight"
                    color="foregroundMuted"
                    size="s"
                    spacingTop={0.5}
                  />
                  <FAQTextBody>{listItem}</FAQTextBody>
                </HStack>
              );
            })}
          </List>
        </>
      );
    }

    return (
      <>
        {answer.map(paragraph => (
          <FAQTextBody key={`${paragraph}-${uid}`}>{paragraph}</FAQTextBody>
        ))}
      </>
    );
  }, [answer, format, uid]);

  const handleOnPress = useCallback(() => {
    logSignupEvent({
      action: ActionType.click,
      componentType: ComponentType.button,
      feature: 'signup_home',
      additionalData: {
        componentName: 'FAQ',
        selectedItem: index,
      },
    });
    setIsOpen(prev => !prev);
  }, [index]);

  return (
    <VStack as="li" spacing={1}>
      <Pressable
        as="button"
        background="transparent"
        noScaleOnPress
        aria-expanded={isOpen}
        aria-controls={`faq-answer-${uid}`}
        onPress={handleOnPress}
        testID="subscription-faq-item-button"
      >
        <HStack
          alignItems="center"
          justifyContent="space-between"
          flexGrow={1}
          spacingHorizontal={!isPhone ? 2 : 0}
          spacingVertical={3}
        >
          <Box flexGrow={1} spacingEnd={2}>
            <TextHeadline as="h4">{question}</TextHeadline>
          </Box>
          <Icon name={isOpen ? 'minus' : 'add'} size="s" />
        </HStack>
      </Pressable>

      <Transitioner step={isOpen ? 'open' : ''}>
        <TextBody
          as="p"
          key="open"
          spacingStart={2}
          spacingBottom={2}
          spacingEnd={4}
          id={`faq-answer-${uid}`}
          color="foregroundMuted"
          testID="subscription-faq-item-answer"
        >
          {formattedAnswer}
        </TextBody>
      </Transitioner>
    </VStack>
  );
}

export { FAQItem };

