import FiatCurrencyIcon from 'components/CurrencyIcon/FiatCurrencyIcon';
import InfiniteScrollLoader from 'components/InfiniteScrollLoader';

import useAssetHistory, {
  AssetHistoryFragment,
} from '../hooks/useAssetHistory';
import { ASSET_FILTER_LIST_COUNT, AssetListItem } from './constants';
import TransactDropdownSection from './TransactDropdownSection';
import { messages } from './TransactionFilterMenu/messages';
import { MenuState } from './TransactionFilterMenu/TransactionFilterMenu';

type TransactAssetFilterProps = {
  initialSelectedAsset: AssetListItem[];
  onAssetSelect: (selectedStatus: AssetListItem) => void;
  onCloseDropdown: () => void;
  onResetState: (state: MenuState) => void;
  onApplyFilter: () => void;
  queryRef: AssetHistoryFragment;
};

function TransactAssetFilter({
  initialSelectedAsset,
  onAssetSelect,
  onCloseDropdown,
  onResetState,
  onApplyFilter,
  queryRef,
}: TransactAssetFilterProps) {
  const { assetList, hasNext, loadNext, isLoadingNext } =
    useAssetHistory(queryRef);
  const { formatMessage } = useIntl();

  const handleEndReached = useCallback(() => {
    if (hasNext) {
      loadNext(ASSET_FILTER_LIST_COUNT);
    } else return null;
  }, [hasNext, loadNext]);

  const handleClearAll = useCallback(() => {
    onResetState('asset');
    onCloseDropdown();
  }, [onCloseDropdown, onResetState]);

  const handleOnPress = useCallback(() => {
    onApplyFilter();
    onCloseDropdown();
  }, [onApplyFilter, onCloseDropdown]);

  const hasSelection = initialSelectedAsset.length > 0;

  if (assetList.length === 0) {
    return (
      <VStack alignItems="center" maxWidth={400}>
        <VStack gap={1} spacing={gutter} alignItems="center">
          <SpotSquare name="tradeImmediately" />
          <TextTitle3 as="h3">
            {formatMessage(messages.noAssetFilterData)}
          </TextTitle3>
          <TextBody align="center" as="p">
            {formatMessage(messages.noAssetFilterDataDescription)}
          </TextBody>
        </VStack>
      </VStack>
    );
  }
  return (
    <TransactDropdownSection
      hasSelection={hasSelection}
      handleClearAll={handleClearAll}
      handleOnPress={handleOnPress}
    >
      <InfiniteScroll
        isLoading={isLoadingNext}
        getMoreItems={handleEndReached}
        spinner={isLoadingNext ? <InfiniteScrollLoader /> : null}
        forceObserve={hasNext}
        scrollable={false}
        setMaxHeight={false}
      >
        {assetList.map(item => {
          const isSelected = initialSelectedAsset.some(
            asset => asset.symbolOrCode === item.symbolOrCode,
          );

          return (
            <HStack
              as="label"
              alignItems="center"
              justifyContent="space-between"
              spacingVertical={1.5}
              spacingHorizontal={2}
              minWidth={326}
              key={item.symbolOrCode}
            >
              <HStack alignItems="center" gap={1.5}>
                {item.type === 'asset' ? (
                  <RemoteImage source={item.iconUrl} />
                ) : (
                  <FiatCurrencyIcon symbol={item.symbolOrCode} size={24} />
                )}
                <TextHeadline as="p" spacingEnd={1}>
                  {item.name}
                </TextHeadline>
              </HStack>
              <Checkbox
                // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                onChange={() => onAssetSelect(item)}
                checked={isSelected}
              />
            </HStack>
          );
        })}
      </InfiniteScroll>
    </TransactDropdownSection>
  );
}

export default memo(TransactAssetFilter);

