        supportsFreeTextInput
        freeTextInputRegex
        options {
          value
          title
          subtitle
        }
      }
    `,
    genericComplianceQuestionRef,
  );

  const { freeInputRegExp, maxChars } = useMemo(
    () => parseFreeTextInputRegex(questionData?.freeTextInputRegex ?? ''),
    [questionData?.freeTextInputRegex],
  );

  const handleOptionClick = useCallback(
    (optValue: string) => () => {
      if (questionData?.inputType === 'MULTI_SELECT') {
        setSelectedOptions(val => ({
          ...val,
          [optValue]: !val[optValue],
        }));
      } else {
        setSelectedOptions(val => ({
          [optValue]: !val[optValue],
        }));
      }
    },
    [questionData?.inputType],
  );

  const handleUserInputChange = useCallback(
    (e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
      setFreeTextInput(e.target?.value ?? '');
    },
    [],
  );

  const handleAnswerSubmitClick = useCallback(() => {
    handleAnswerSubmit({
      freeTextInput,
      selectedOptions,
      uuid: questionData?.uuid,
      inputType: questionData?.inputType,
    });
  }, [
    freeTextInput,
    selectedOptions,
    handleAnswerSubmit,
    questionData?.inputType,
    questionData?.uuid,
  ]);

  // Find if there is any option selected/user input is present and return is disabled based on it
  const isButtonDisabled = useMemo(() => {
    const inputType = questionData?.inputType;
    const answerValues: string[] = [];
    let isFreeTextInputValid = true;

    if (inputType === 'MULTI_SELECT' || inputType === 'SINGLE_SELECT') {
      Object.keys(selectedOptions).forEach(key => {
        if (selectedOptions[key]) {
          if (key === FREE_INPUT) {
            isFreeTextInputValid = freeInputRegExp
              ? freeInputRegExp.test(freeTextInput)
              : true;
            answerValues.push(freeTextInput);
          } else {
            answerValues.push(key);
          }
        }
      });
    }

    if (inputType === 'FREE_TEXT' && freeTextInput.length > 0) {
      isFreeTextInputValid = freeInputRegExp
        ? freeInputRegExp.test(freeTextInput)
        : true;
      answerValues.push(freeTextInput);
    }

    return answerValues.length === 0 || !isFreeTextInputValid;
  }, [
    freeInputRegExp,
    freeTextInput,
    questionData?.inputType,
    selectedOptions,
  ]);

  const renderQuestionFields = useCallback(() => {
    switch (questionData?.inputType) {
      case 'MULTI_SELECT':
      case 'SINGLE_SELECT':
        return (
          <>
            {questionData?.options?.map(option => {
              // NOTE: Questions service does not send a value for a free-ended option(where user can input anything instead of select an option)
              const optValue = option?.value || FREE_INPUT;

              return (
                <Fragment key={`quiz-question-option-${optValue}`}>
                  <Pressable
                    as="button"
                    background="transparent"
                    onPress={handleOptionClick(optValue)}
                    borderColor="line"
                    borderRadius="rounded"
                  >
                    <ListCell
                      title={option?.title}
                      innerSpacing={{
                        spacingVertical: 2,
                        spacingHorizontal: 3,
                      }}
                      compact
                      outerSpacing={{
                        spacingHorizontal: 2,
                        spacingVertical: 0,
                      }}
                      selected={selectedOptions[optValue]}
                      disabled={selectedOptions[optValue]}
                    />
                  </Pressable>

                  {optValue === 'free_input' &&
                    questionData?.supportsFreeTextInput &&
                    selectedOptions[optValue] && (
                      <Box spacingVertical={0.5}>
                        <TextInput
                          accessibilityLabel="Text input field"
                          accessibilityHint={option?.title || ''}
                          value={freeTextInput}
                          onChange={handleUserInputChange}
                          placeholder="Enter your answer"
                          maxLength={maxChars}
                        />
                      </Box>
                    )}
                </Fragment>
              );
            })}
          </>
        );
      case 'FREE_TEXT':
        return (
          <Box spacingTop={2}>
            <TextInput
              accessibilityLabel="Text input field"
              accessibilityHint={questionData?.title || ''}
              height={160}
              inputNode={
                <NativeTextArea
                  value={freeTextInput}
                  onChange={handleUserInputChange}
                  placeholder="Enter your answer"
                  maxLength={maxChars}
                />
              }
              helperText={
                maxChars
                  ? formatMessage(messages.inputCharsRemainingHelperText, {
                      charactersCount: maxChars - freeTextInput.length,
                    })
                  : undefined
              }
            />
          </Box>
        );
      default:
        return null;
    }
  }, [
    formatMessage,
    freeTextInput,
    handleOptionClick,
    handleUserInputChange,
    maxChars,
    questionData?.inputType,
    questionData?.options,
    questionData?.supportsFreeTextInput,
    questionData?.title,
    selectedOptions,
  ]);

  return (
    <VStack>
      <VStack gap={0.5} spacingBottom={2}>
        <TextTitle2 as="h2">{questionData?.title ?? ''}</TextTitle2>
        <TextBody color="foregroundMuted" as="p">
          {questionData?.subtitle ?? ''}
        </TextBody>
      </VStack>

      <VStack gap={1} spacingBottom={4}>
        {renderQuestionFields()}
      </VStack>

      <Button onPress={handleAnswerSubmitClick} disabled={isButtonDisabled}>
        {formatMessage(messages.continueBtn)}
      </Button>
    </VStack>
  );
}

import { useMemo, useCallback } from 'react';
import { Id, IdAlternate, Document } from '@cb/shared/assets/icons/documents';

import useStepper from 'components/Stepper/hooks/useStepper';

import SelectBox from '../components/SelectBox';
import stepper from '../stepper';
import {
  IdType,
  OnIdSelect,
  SupportedDocuments,
  UploadMethodType,
} from '../types';
import useGoToDocumentUploadStep from '../utils/useGoToDocumentUploadStep';

const documentMetaMap = {
  drivers_license: {
    image: Id,
    text: "Driver's License",
  },
  id_card: {
    image: IdAlternate,
    text: 'State Issued ID',
  },
  another_document: {
    image: Document,
    text: 'Another document*',
  },
  social_security: {
    image: IdAlternate,
    text: 'Social Security card',
  },
  w2_or_1099: {
    image: Document,
    text: 'Recent W-2 or 1099',
  },
};

type Props = {
  documentType: IdType;
  onSelect: OnIdSelect;
  supportedDocuments: SupportedDocuments;
};

function useUploadMethods(
  idType: IdType,
  supportedDocuments: SupportedDocuments,
) {
  const documentMeta = useMemo(
    () => supportedDocuments.find(doc => doc.type === idType),
    [idType, supportedDocuments],
  );

  if (!documentMeta) {
    // TODO: handle error; this theoretically shouldn't be possible
    return;
  }

  return documentMeta.uploadMethods;
}

function Selector({ documentType, onSelect, supportedDocuments }: Props) {
  const meta = documentMetaMap[documentType];
  const supportedUploadMethodsForDocumentType = useUploadMethods(
    documentType,
    supportedDocuments,
  );

  const goToDocumentUploadStep = useGoToDocumentUploadStep();
  const { goToStep } = useStepper(stepper);
  const handleNextStep = useCallback(() => {
    if (!supportedUploadMethodsForDocumentType) {
      // TODO: handle error; this theoretically shouldn't be possible
      return;
    }

    onSelect({
      selectedIdType: documentType,
      selectedUploadMethods:
        supportedUploadMethodsForDocumentType as UploadMethodType[],
    });

    // if there's only one corresponding upload method for the selected document type,
    // immediately send the user to that screen. otherwise, let the user choose from
    // the given selection
    if (supportedUploadMethodsForDocumentType.length === 1) {
      goToDocumentUploadStep({
        idType: documentType,
        uploadMethod:
          supportedUploadMethodsForDocumentType[0] as UploadMethodType,
      });
      return;
    }

    goToStep('upload-method-selection');
  }, [
    goToStep,
    onSelect,
    documentType,
    supportedUploadMethodsForDocumentType,
    goToDocumentUploadStep,
  ]);

  return (
    // required to handle some really weird behavior where setting an onClick on SelectBox doesn't register
    <div onClick={handleNextStep}>
      <SelectBox
        image={<meta.image style={{ width: '100%', height: '100%' }} />}
        text={meta.text}
      />
    </div>
  );
}

export default Selector;

import { useCallback } from 'react';
import styled from 'styled-components';

import { useIssuanceProduct } from 'views/MarqetaIssuance/context/IssuanceProductContext';

import {
  logUploadPhoto,
  logPhotoCapture,
} from '../../CoinbaseCard/CardAnalytics';
import SelectBox from '../components/SelectBox';
import { IdType, UploadMethodType } from '../types';
import useGoToDocumentUploadStep from '../utils/useGoToDocumentUploadStep';
import { ReactComponent as FileUploadImage } from './method-file.svg';
import { ReactComponent as WebcamImage } from './method-webcam.svg';
// below styling method was taken from identity package
// @ts-expect-error: 2021-02-19: Whitelisted implicitAny error. Please fix.
const styleIcon = component => styled(component)`
  width: 40px;
  height: 40px;

  * {
    fill: ${({ theme }) => theme.color.accessoryActive};
  }
`;

const uploadMethodMetaMap = {
  webcam: {
    image: styleIcon(WebcamImage),
    text: 'Webcam',
  },
  file: {
    image: styleIcon(FileUploadImage),
    text: 'File Upload',
  },
};

type Props = {
  uploadMethod: UploadMethodType;
  idType: IdType;
};

function Selector({ uploadMethod, idType }: Props) {
  const meta = uploadMethodMetaMap[uploadMethod];
  const goToDocumentUploadStep = useGoToDocumentUploadStep();
  const { product } = useIssuanceProduct();

  const handleNextStep = useCallback(() => {
    if (uploadMethod === 'file') {
      logUploadPhoto(idType, product);
    } else {
      logPhotoCapture(idType, product);
    }
    goToDocumentUploadStep({ uploadMethod, idType });
  }, [uploadMethod, goToDocumentUploadStep, idType, product]);

  return (
    // required to handle some really weird behavior where setting an onClick on SelectBox doesn't register
    <div onClick={handleNextStep}>
      <SelectBox text={meta.text} image={<meta.image />} />
    </div>
  );
}

export default Selector;

