import { useStakingAvailableBalance } from 'components/StakingV2/hooks/useStakingAvailableBalance';
import { useStakingFlowModal } from 'components/StakingV2/hooks/useStakingFlowModal';
import useNativeCurrency from 'hooks/useNativeCurrency';

import {
  YieldEventContext,
  trackAssetStakingSummaryCardClick,
} from '../eventing';
import messages from '../messages';
import { AssetNotStakedCardFragment$key } from './__generated__/AssetNotStakedCardFragment.graphql';

type AssetNotStakedCardProps = {
  viewerAssetRef: AssetNotStakedCardFragment$key;
  context: YieldEventContext;
};

export const AssetNotStakedCard = memo(function AssetNotStakedCard({
  viewerAssetRef,
  context,
}: AssetNotStakedCardProps) {
  const { formatMessage, formatNumber } = useIntl();
  const nativeCurrency = useNativeCurrency();

  const viewerAsset = useFragment(
    graphql`
      fragment AssetNotStakedCardFragment on ViewerAsset {
        asset {
          slug
          platformName
          displaySymbol
        }
        earnProgram {
          currentRate {
            formatted
            unitSymbol
          }
        }
        ...useStakingAvailableBalanceFragment
          @arguments(nativeCurrency: $nativeCurrency)
      }
    `,
    viewerAssetRef,
  );

  const asset = viewerAsset?.asset;
  const currentRate = viewerAsset?.earnProgram?.currentRate;

  const showStakingModal = useStakingFlowModal({
    assetSlug: viewerAsset?.asset?.slug,
    eventContext: context,
  });

  const stakingAvailableBalance = useStakingAvailableBalance({
    viewerAssetRef: viewerAsset,
  });
  const stakingAvailableBalanceFiat =
    stakingAvailableBalance?.stakingBalanceInFiat ?? 0;

  const totalLessThanOne = stakingAvailableBalanceFiat < 1;

  // only format the truncated amount instead of rounding
  // if less then 1, show decimals, otherwise, truncate
  const formattedAvailableToStake = formatNumber(
    totalLessThanOne
      ? stakingAvailableBalanceFiat
      : Math.trunc(stakingAvailableBalanceFiat),
    {
      style: 'currency',
      currency: nativeCurrency,
      minimumFractionDigits: totalLessThanOne ? 2 : 0,
      maximumFractionDigits: totalLessThanOne ? 2 : 0,
    },
  );

  const handlePress = useCallback(() => {
    trackAssetStakingSummaryCardClick({
      assetName: asset.platformName ?? '',
      type: 'notStaked',
    });

    showStakingModal();
  }, [asset, showStakingModal]);

  if (!currentRate || !asset) {
    return null;
  }

  return (
    <Pressable
      noScaleOnPress
      as="button"
      width="100%"
      background="transparent"
      onPress={handlePress}
    >
      <NudgeCard
        title={formatMessage(messages.earnUpToHeader, {
          maxApy: currentRate.formatted,
          label: currentRate.unitSymbol,
        })}
        description={
          <Box spacingTop={1}>
            <TextLabel2 as="span">
              {formatMessage(messages.assetEarnMoreDescription, {
                asset: asset?.displaySymbol,
                amount: formattedAvailableToStake,
                bold: (bold: React.ReactNode) => [
                  <TextHeadline key="bold" as="span">
                    {bold}
                  </TextHeadline>,
                ],
              })}
            </TextLabel2>
          </Box>
        }
        pictogram="earnNavigation"
        width="100%"
      />
    </Pressable>
  );
});

