    showModal(<LazyMissedEarnings eventContext={context} onDismiss={noop} />);
  }, [showModal, context]);

  if (!maxApy) {
    return null;
  }

  return (
    <Pressable
      noScaleOnPress
      as="button"
      width="100%"
      background="transparent"
      onPress={handlePress}
    >
      <NudgeCard
        title={formatMessage(messages.earnUpToHeader, {
          maxApy: maxApy.formatted,
          label: maxApy.unitSymbol,
        })}
        description={
          <TextLabel2 as="span">
            {formatMessage(messages.earnMoreDescription, {
              amount: formattedAvailableToStake,
              bold: (bold: React.ReactNode) => [
                <TextHeadline as="span" key="bold">
                  {bold}
                </TextHeadline>,
              ],
            })}
          </TextLabel2>
        }
        pictogram="earnNavigation"
        action={
          compact ? undefined : (
            <HStack offsetBottom={2}>
              <Button compact transparent flush="start" onPress={handlePress}>
                {formatMessage(messages.startEarning)}
              </Button>
            </HStack>
          )
        }
        onActionPress={handlePress}
        background="backgroundAlternate"
        width="100%"
      />
    </Pressable>
  );
});

