const CARD_PATH = '/card';
const LEARN_PATH = '/learning-rewards';

function YieldUpsellSection({ queryRef }: YieldUpsellSectionProps) {
  const { formatMessage } = useIntl();

  const query = useFragment(
    graphql`
      fragment YieldUpsellSectionFragment on Query {
        viewer {
          earnUserProgress {
            earnings {
              activeCampaign {
                remaining {
                  value
                }
              }
            }
          }
        }
      }
    `,
    queryRef,
  );

  const isUkFinProm = useUkFinProm();

  const history = useHistory();

  // Extracted from CoinbaseCard condition to render in sidenav
  const { isInUS: isCoinbaseCardVisible } = useUser();

  const shouldShowLearningRewardUpsell = useMemo(() => {
    const earnableValue =
      query.viewer.earnUserProgress?.earnings?.activeCampaign?.remaining;
    const useEarnBadge = !!earnableValue && Number(earnableValue.value) > 0;

    return useEarnBadge;
  }, [query.viewer.earnUserProgress?.earnings?.activeCampaign?.remaining]);

  const handleLinkPress = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (link: any) => {
      history.push(link);
    },
    [history],
  );

  const handleOnPress = useCallback(
    () => handleLinkPress(CARD_PATH),
    [handleLinkPress],
  );

  const handleOnPress1 = useCallback(
    () => handleLinkPress(LEARN_PATH),
    [handleLinkPress],
  );

  if (
    (!shouldShowLearningRewardUpsell && !isCoinbaseCardVisible) ||
    isUkFinProm
