import { useCallback, useMemo, useState } from 'react';
import noop from 'lodash/noop';
import { useIntl } from 'react-intl';

import { useFields } from '@cb/forms';
import { Button } from '@cbhq/cds-web/buttons';
import { VStack } from '@cbhq/cds-web/layout';
import { TextHeadline } from '@cbhq/cds-web/typography';
import { graphql, useFragment } from '@cbhq/data-layer';

import EntryInput, {
  useEntryInputSwitcher,
} from 'components/BuySellComponents/EntryInput';
import Footer from 'components/BuySellComponents/Footer';
import { useInputSymbols } from 'components/StakingV2/hooks/useInputSymbols';
import StakingPercentPicker from 'components/StakingV2/Stake/components/StakingPercentPicker/StakingPercentPicker';
import useStepper from 'components/Stepper/hooks/useStepper';
import useNativeCurrency from 'hooks/useNativeCurrency';

import { ModalBody } from '../../../../../components/Modal';
import { ModalHeaderContents as ModalHeader } from '../../../../../components/Modal/components/ModalHeader/ModalHeader';
import {
  logMissedEarningsInputConfirmClick,
  logPercentPercentClick,
  useLogMissedEarningsInputView,
} from '../eventing';
import { messages } from '../messages';
import { useMissedEarningsAmounts } from '../MissedEarningsProvider';
import { stepper, form } from '../stepper';
import { InputStepFragment$key } from './__generated__/InputStepFragment.graphql';
import { StepContainer } from './components/StepContainer/StepContainer';

type MissedEarningsInputProps = {
  queryRef: InputStepFragment$key;
};

export default function InputStep({ queryRef }: MissedEarningsInputProps) {
  const { formatMessage, formatNumber } = useIntl();
  const nativeCurrency = useNativeCurrency();
  const { goToStep, goBack } = useStepper(stepper);
  const { getStakeAmounts, setStakeAmounts } = useMissedEarningsAmounts();
  const { editingAssetUuid, isFiatInput, amount, eventContext } =
    useFields(form);

  const stakeAmounts = getStakeAmounts(editingAssetUuid.value ?? '');

  const [error, setError] = useState('');

  useLogMissedEarningsInputView({
    asset: editingAssetUuid.value,
    context: eventContext.value,
  });

  const { viewer } = useFragment(
    graphql`
      fragment InputStepFragment on Query {
        viewer {
          earn {
            assets {
              current {
                asset {
                  ...EntryInputFragment
                  asset {
                    uuid
                    name
                    platformName
                    displaySymbol
                    exponent
                  }
                  accounts {
                    primary
                    assetOrFiatCurrency {
                      ...FooterFragment
                    }
                  }
                }
              }
            }
          }
        }
      }
    `,
    queryRef,
  );

  const viewerAsset = viewer?.earn?.assets?.current?.find(
    asset => asset?.asset?.asset?.uuid === editingAssetUuid.value,
  )?.asset;

  const primaryAccount = viewerAsset?.accounts?.find(
    account => account?.primary,
  );

  const assetName = viewerAsset?.asset?.name ?? '';
  const assetUuid = viewerAsset?.asset?.uuid ?? '';
  const assetSymbol = viewerAsset?.asset?.displaySymbol ?? '';
  const assetPlatformName = viewerAsset?.asset?.platformName ?? '';
  const assetExponent = viewerAsset?.asset?.exponent ?? 6;

  const { activeSymbol, inactiveSymbol } = useInputSymbols({
    isFiatInput,
    targetAssetSymbol: assetSymbol,
  });
  const { activeSymbol: activePlatformName } = useInputSymbols({
    isFiatInput,
    targetAssetSymbol: assetPlatformName,
  });

  const amountToStakeInCrypto = isFiatInput.value
    ? Number(amount.value) / (stakeAmounts?.latestPrice ?? 0)
    : Number(amount.value);
  const amountToStakeInFiat = isFiatInput.value
    ? Number(amount.value)
    : Number(amount.value) * (stakeAmounts?.latestPrice ?? 0);

  const switchInput = useEntryInputSwitcher({
    form,
    quoteFiatAmount: amountToStakeInFiat.toString(),
    quoteCryptoAmount: amountToStakeInCrypto.toFixed(assetExponent).toString(),
  });

  const isValidAmount = useCallback(
    (value: string) => {
      return isFiatInput.value
        ? Number(value) <= (stakeAmounts?.totalStakingBalanceInFiat ?? 0)
        : Number(value) <= (stakeAmounts?.totalStakingBalanceInCrypto ?? 0);
    },
    [stakeAmounts, isFiatInput],
  );

  const handleChange = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (value: any) => {
      setError('');
      amount.onChange(value);

      if (!isValidAmount(value)) {
        setError(formatMessage(messages.inputError, { asset: assetName }));
      }
    },
    [formatMessage, isValidAmount, assetName, amount],
  );

  const handleConfirmButtonPress = useCallback(() => {
    logMissedEarningsInputConfirmClick({
      asset: assetUuid,
      context: eventContext.value,
    });

    setStakeAmounts(assetUuid, {
      amountToStakeInCrypto,
      amountToStakeInFiat,
    });

    goToStep('customizeAmountStep');
  }, [
    goToStep,
    assetUuid,
    setStakeAmounts,
    eventContext.value,
    amountToStakeInFiat,
    amountToStakeInCrypto,
  ]);

  const handlePercentPress = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (percent: any) => {
      setError('');

      if (
        !stakeAmounts?.totalStakingBalanceInFiat ||
        !stakeAmounts?.totalStakingBalanceInCrypto ||
        !stakeAmounts?.latestPrice
      ) {
        return;
      }

      logPercentPercentClick({
        percent,
        asset: assetUuid,
        context: eventContext.value,
      });

      const cryptoAmount = stakeAmounts.totalStakingBalanceInCrypto * percent;

      if (isFiatInput.value) {
        amount.onChange((stakeAmounts.latestPrice * cryptoAmount).toString());
      } else {
        amount.onChange(cryptoAmount.toString());
      }
    },
    [isFiatInput, stakeAmounts, amount, assetUuid, eventContext.value],
  );

  const handleCloseModalPress = useCallback(() => {
    goToStep('customizeAmountStep');
  }, [goToStep]);

  const title = useMemo(() => {
    return (
      <TextHeadline as="p">
        {formatMessage(messages.customizeAmountHeader)}
      </TextHeadline>
    );
  }, [formatMessage]);

  // store with precision to make percent pickers exact, display with 2 decimals for fiat
  const displayValue = useMemo(() => {
    return isFiatInput.value
      ? amount.value.replace(/(\.[\d]{2}).*/g, '$1')
      : amount.value;
  }, [amount.value, isFiatInput.value]);

  const formattedBalances = useMemo(() => {
    return {
      crypto: formatNumber(stakeAmounts?.totalStakingBalanceInCrypto ?? 0, {
        style: 'currency',
        currency: assetPlatformName,
        minimumFractionDigits: assetExponent,
        maximumFractionDigits: assetExponent,
      }),
      fiat: formatNumber(stakeAmounts?.totalStakingBalanceInFiat ?? 0, {
        style: 'currency',
        currency: nativeCurrency,
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
      }),
    };
  }, [
    formatNumber,
    stakeAmounts,
    assetPlatformName,
    assetExponent,
    nativeCurrency,
  ]);

  return (
    <StepContainer dynamicHeight>
      <ModalHeader
        close={handleCloseModalPress}
        onBack={goBack}
        title={title}
        center
      />
      <ModalBody>
        <VStack spacing={1}>
          <EntryInput
            viewerAssetRef={viewerAsset ?? null}
            error={error}
            autoFocus
            input={{
              symbol: activePlatformName,
              displaySymbol: activeSymbol,
              value: displayValue,
              onChange: handleChange,
              onEnter: noop,
              noCommas: true,
            }}
            switchActiveInput={{ onPress: switchInput, inactiveSymbol }}
          />
        </VStack>
        <StakingPercentPicker
          handlePercentPress={handlePercentPress}
          percents={[0.5, 0.75, 1]}
        />
        <VStack width="100%">
          <Button
            onPress={handleConfirmButtonPress}
            disabled={error.length > 0}
          >
            {formatMessage(messages.confirmAmount)}
          </Button>
          <VStack offsetHorizontal={2} offsetBottom={3}>
            <Footer
              balance={formattedBalances.crypto}
              fiatBalance={formattedBalances.fiat}
              assetOrCurrencyRef={primaryAccount?.assetOrFiatCurrency}
              entryPoint="staking"
            />
          </VStack>
        </VStack>
      </ModalBody>
    </StepContainer>
  );
}

import { useCallback, memo, useMemo } from 'react';
