import { useMissedEarningsAmounts } from '../../../MissedEarningsProvider';
import { MissedEarningAssetsCellFragment$key } from './__generated__/MissedEarningAssetsCellFragment.graphql';

export type MissedEarningAsset = {
  assetUuid: string;
};

const MissedEarningAssetsCellContent = memo(
  function MissedEarningAssetsCellContent({
    earnProgramRef,
    onPress,
  }: MissedEarningAssetsCellProps) {
    const { formatMessage, formatNumber } = useIntl();
    const nativeCurrency = useNativeCurrency();

    const earnProgram = useFragment(
      graphql`
        fragment MissedEarningAssetsCellFragment on EarnProgram {
          currentRate {
            formatted
            unitSymbol
          }
          asset {
            asset {
              uuid
              name
              imageUrl
              color
            }
          }
        }
      `,
      earnProgramRef,
    );

    const rewardApy = earnProgram?.currentRate;
    const viewerAsset = earnProgram?.asset;
    const asset = viewerAsset?.asset;
    const { getStakeAmounts } = useMissedEarningsAmounts();
    const stakeAmounts = getStakeAmounts(asset?.uuid ?? '');

    const title = useMemo(() => {
      const assetName = rewardApy ? `${asset?.name} · ` : asset?.name;

      return (
        <HStack>
          <TextHeadline as="p">
            {assetName}
            {rewardApy ? (
              <TextHeadline as="span" color="positive" inherit>
                {formatMessage(messages.formattedApy, {
                  apyValue: rewardApy.formatted,
                  apyLabel: rewardApy.unitSymbol,
                })}
              </TextHeadline>
            ) : null}
          </TextHeadline>
        </HStack>
      );
    }, [asset?.name, formatMessage, rewardApy]);

    const rawPercent =
      (stakeAmounts?.amountToStakeInCrypto ?? 0) /
      (stakeAmounts?.totalStakingBalanceInCrypto ?? 0);

    const handleOnPress = useCallback(
      () =>
        onPress({
          assetUuid: asset?.uuid ?? '',
        }),
      [asset?.uuid, onPress],
    );

    if (!asset || !stakeAmounts || !stakeAmounts?.totalStakingBalanceInCrypto) {
      return null;
    }

    const stakeTotal = formatNumber(stakeAmounts.amountToStakeInFiat, {
      style: 'currency',
      currency: nativeCurrency,
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });

    const stakePercent = formatNumber(rawPercent, {
      style: 'percent',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });

    return (
      <VStack as="li">
        <VStack spacingHorizontal={3}>
          <Divider />
        </VStack>
        <ListCell
          priority="start"
          media={
            <AssetAllocationIcon
              imageUrl={asset?.imageUrl ?? ''}
              color={asset?.color ?? '#fff'}
              progress={rawPercent}
            />
          }
          title={title}
          description={
            <TextBody as="p" color="foregroundMuted">
              {`${stakeTotal} (${stakePercent})`}
            </TextBody>
          }
          action={
            <IconButton
              testID={`missed-earnings-cell-edit-${asset?.uuid}`}
              name="pencil"
              variant="secondary"
              onPress={handleOnPress}
            />
          }
        />
      </VStack>
    );
  },
);

type MissedEarningAssetsCellProps = {
