import { useCallback, memo, useMemo } from 'react';
import { useIntl } from 'react-intl';
import { useHistory, useLocation } from 'react-router-dom';

import { useBreakpoints } from '@cbhq/cds-web/hooks/useBreakpoints';
import { Box, VStack } from '@cbhq/cds-web/layout';
import { startPerfMark } from '@cbhq/client-analytics';
import {
  CoinbasePublicApiAuthedRetailBrokerageApiContractExpiryType as ContractExpiryType,
  CoinbasePublicApiAuthedRetailBrokerageApiProductType,
} from '@cbhq/instant-api-hooks-retail-brokerage/types';

import useFeatureFlag from '../../../hooks/useFeatureFlag';
import {
  MarketType,
  MarketTypeFilters,
  MARKET_TYPE_QUERY_PARAM_KEY,
} from '../constants';
import { DISABLED_PILLS } from '../contexts/constants';
import { useAdvancedTradeRouteParams } from '../hooks/useAdvancedTradeRoute';
import useMarketTypeContext from '../hooks/useMarketTypeContext';
import messages from '../messages';
import FutureMarketSelectorFilter from './FutureMarketSelectorFilter';
import MarketSelectorFilterPills from './MarketSelectorFilterPills';
import MarketSelectorSearchBar from './MarketSelectorSearchBar';
import MarketTypeTabNavigation, {
  MarketTypeTabNavigationProps,
} from './MarketTypeTabNavigation';
import PerpetualMarketSelectorFilter from './PerpetualMarketSelectorFilter';

type MarketSelectorControlPanelProps = {
  disabledNavBar?: DISABLED_PILLS;
  isFuturesEnabled: boolean;
  topContent?: {
    SPOT?: React.ReactNode;
    FUTURE?: React.ReactNode;
    PERPETUAL?: React.ReactNode;
  };
  hidePreLaunchFilter?: boolean;
} & Pick<
  MarketTypeTabNavigationProps,
  'productDisplayCount' | 'isPerpetualFuturesEnabled'
>;

function MarketSelectorControlPanel({
  isFuturesEnabled,
  isPerpetualFuturesEnabled,
  topContent,
  productDisplayCount,
  disabledNavBar,
  hidePreLaunchFilter,
}: MarketSelectorControlPanelProps) {
  const { isPhone } = useBreakpoints();
  const { formatMessage } = useIntl();
  const location = useLocation();
  const history = useHistory();
  const { marketTypeFilter, contractExpiryType } = useMarketTypeContext();
  const { route, tradeParam } = useAdvancedTradeRouteParams();
  const isFuturesEnabledAndUserEligibleForFutures = useFeatureFlag(
    'may_2022_derivatives_futures',
  );
  const isIntxPreLaunchContractsEnabled = useFeatureFlag(
    'apr_2024_intx_pre_launch_contracts',
  );
  const topContentComponent = useMemo(() => {
    if (!topContent) {
      return null;
    }

    return topContent && contractExpiryType === ContractExpiryType.PERPETUAL
      ? topContent[ContractExpiryType.PERPETUAL]
      : topContent[marketTypeFilter];
  }, [contractExpiryType, marketTypeFilter, topContent]);

  const onMarketTypeChange = useCallback(
    (tabId: MarketType, contractExpiryType: ContractExpiryType) => {
      const queryParams = new URLSearchParams(location.search);

      if (route === 'advanced-trade' && !tradeParam) {
        if (contractExpiryType === ContractExpiryType.PERPETUAL) {
          queryParams.set(
            MARKET_TYPE_QUERY_PARAM_KEY,
            MarketTypeFilters[
              CoinbasePublicApiAuthedRetailBrokerageApiProductType.FUTURE
            ],
          );
        } else {
          // Use query params only for dedicated page which impacts the side bar
          queryParams.set(
            MARKET_TYPE_QUERY_PARAM_KEY,
            MarketTypeFilters[tabId],
          );
        }
        history.replace({
          pathname: location.pathname,
          search: queryParams.toString(),
        });
      }

      if (
        tabId === CoinbasePublicApiAuthedRetailBrokerageApiProductType.FUTURE
      ) {
        startPerfMark('advanced-trade', {
          label: 'navigate_to_advanced_futures',
        });
      }
    },
    [location.search, location.pathname, route, tradeParam, history],
  );

  const marketTabs = (
    <MarketTypeTabNavigation
      beta={isFuturesEnabledAndUserEligibleForFutures}
      primaryTabs
      onChange={onMarketTypeChange}
      isPerpetualFuturesEnabled={isPerpetualFuturesEnabled}
      productDisplayCount={productDisplayCount}
    />
  );

  return (
    <>
      <Box as="div" spacingHorizontal={3} spacingTop={3} flexDirection="column">
        {isPhone ? (
          <VStack spacingBottom={2}>
            {isFuturesEnabled && <Box spacingBottom={2}>{marketTabs}</Box>}
            <MarketSelectorSearchBar />
          </VStack>
        ) : (
          <Box justifyContent="space-between" alignItems="center">
            {isFuturesEnabled && (
              <Box as="div" alignItems="center">
                {marketTabs}
              </Box>
            )}
            <Box width="50%">
              <MarketSelectorSearchBar />
            </Box>
          </Box>
        )}
      </Box>

      {topContentComponent}

      <Box
        as="div"
        spacingHorizontal={3}
        spacingVertical={2}
        flexDirection="column"
      >
        <div aria-label={formatMessage(messages.filterMarkets)} tabIndex={0}>
          {marketTypeFilter === 'SPOT' && (
            <MarketSelectorFilterPills disabledNavBar={disabledNavBar} />
          )}
          {marketTypeFilter === 'FUTURE' &&
            contractExpiryType === 'EXPIRING' && <FutureMarketSelectorFilter />}
          {marketTypeFilter === 'FUTURE' &&
            contractExpiryType === ContractExpiryType.PERPETUAL &&
            isIntxPreLaunchContractsEnabled &&
            !hidePreLaunchFilter && <PerpetualMarketSelectorFilter />}
        </div>
      </Box>
    </>
  );
}

export default memo(MarketSelectorControlPanel);

import { memo, useCallback, useState } from 'react';
import { debounce } from 'lodash';
import { useIntl } from 'react-intl';

import { SearchInput } from '@cbhq/cds-web/controls';

import { useLogSearchBarClickedEvent } from '../eventing';
import useMarketSelectorFilterContext from '../hooks/useMarketSelectorFilterContext';
import useMarketTypeContext from '../hooks/useMarketTypeContext';
import messages from '../messages';

function MarketSelectorSearchBar() {
  const { formatMessage } = useIntl();
  const { setSearchFilter } = useMarketSelectorFilterContext();
  const { marketTypeFilter } = useMarketTypeContext();
  const logSearchBar = useLogSearchBarClickedEvent(marketTypeFilter);
  const onClickSearchBar = useCallback(() => logSearchBar(), [logSearchBar]);
  // eslint-disable-next-line @cb/react-hooks-exhaustive-deps
  const debouncedSetSearchFilter = useCallback(debounce(setSearchFilter, 100), [
    setSearchFilter,
  ]);
  const [input, setInput] = useState('');
  const handleChange = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (text: any) => {
      setInput(text);
      debouncedSetSearchFilter(text);
    },
    [debouncedSetSearchFilter],
  );
  const handleClearInput = useCallback(
    (e: React.MouseEvent) => {
      setInput('');
      setSearchFilter('');
      e.stopPropagation();
    },
    [setSearchFilter],
  );

  return (
    <SearchInput
      onChangeText={handleChange}
      onFocus={onClickSearchBar}
      value={input}
      onClear={handleClearInput}
      placeholder={formatMessage(messages.searchBarPlaceholder)}
      autoFocus
      compact
    />
  );
}

export default memo(MarketSelectorSearchBar);

