import { memo, useMemo, useCallback, useState, useEffect } from 'react';
import { noop } from 'lodash/fp';
import { useIntl } from 'react-intl';

import { CustomTabProps } from '@cbhq/cds-common';
import { SearchInput } from '@cbhq/cds-web/controls';
import { Icon } from '@cbhq/cds-web/icons/Icon';
import { HStack, VStack } from '@cbhq/cds-web/layout';
import { NavigationBar } from '@cbhq/cds-web/navigation/NavigationBar';
import { Pressable, ThemeProvider } from '@cbhq/cds-web/system';
import { TabNavigation } from '@cbhq/cds-web/tabs';
import { TextHeadline, TextLabel1 } from '@cbhq/cds-web/typography';
import { useDebounce } from '@cbhq/common-web';
import {
  CoinbasePublicApiAuthedRetailBrokerageApiProductType,
  CoinbasePublicApiAuthedRetailBrokerageApiContractExpiryType as ContractExpiryType,
} from '@cbhq/instant-api-hooks-retail-brokerage/types';

import { logMarketSelectorV3Search } from './eventing';
import useMarketSelectorV3FilterSortContext from './hooks/useMarketSelectorV3FilterSortContext';
import messages from './messages';
import { ProductDisplayCountMap } from './types';

type MarketSelectorV3NavBarProps = {
  handleClose: () => void;
  isLoading?: boolean;
  productDisplayCountMap: ProductDisplayCountMap;
  isMobile?: boolean;
  isFuturesEnabledAndUserEligibleForFutures: boolean;
  isPerpetualFuturesEligible: boolean;
};

function MarketSelectorV3NavBar({
  handleClose,
  isLoading = false,
  productDisplayCountMap,
  isMobile = false,
  isFuturesEnabledAndUserEligibleForFutures,
  isPerpetualFuturesEligible,
}: MarketSelectorV3NavBarProps) {
  const { formatMessage } = useIntl();
  const { productTypeTab, setProductTypeTab, searchFilter, setSearchFilter } =
    useMarketSelectorV3FilterSortContext();
  // State for immediate user input given debounce logic below
  const [localSearchInput, setLocalSearchInput] = useState(searchFilter);

  const tabs = useMemo(() => {
    const tabsArray = [
      {
        id: 'Watchlist',
        testID: 'marketSelectorNavBarWatchlistTab',
        label: formatMessage(messages.watchlist),
        count: searchFilter.length > 0 ? productDisplayCountMap.WATCHLIST : 0,
      },
      {
        id: CoinbasePublicApiAuthedRetailBrokerageApiProductType.SPOT,
        testID: 'marketSelectorNavBarSpotTab',
        label: formatMessage(messages.spot),
        count: searchFilter.length > 0 ? productDisplayCountMap.SPOT : 0,
      },
    ];

    if (isFuturesEnabledAndUserEligibleForFutures) {
      tabsArray.push({
        id: CoinbasePublicApiAuthedRetailBrokerageApiProductType.FUTURE,
        testID: 'marketSelectorNavBarFuturesTab',
        label: formatMessage(messages.futures),
        count: searchFilter.length > 0 ? productDisplayCountMap.FUTURE : 0,
      });
    }

    if (isPerpetualFuturesEligible) {
      tabsArray.push({
        id: ContractExpiryType.PERPETUAL,
        testID: 'marketSelectorNavBarPerpsTab',
        label: formatMessage(messages.perps),
        count: searchFilter.length > 0 ? productDisplayCountMap.PERPETUAL : 0,
      });
    }

    return tabsArray;
  }, [
    formatMessage,
    searchFilter.length,
    productDisplayCountMap.WATCHLIST,
    productDisplayCountMap.SPOT,
    productDisplayCountMap.FUTURE,
    productDisplayCountMap.PERPETUAL,
    isFuturesEnabledAndUserEligibleForFutures,
    isPerpetualFuturesEligible,
  ]);

  const setTabWithOneProduct = useCallback(() => {
    // if there is a hit in only one of the tabs based on the search query, then set that tab as the active tab
    const tabsWithHit = Object.keys(productDisplayCountMap).filter(
      key => productDisplayCountMap[key as keyof ProductDisplayCountMap] !== 0,
    );
    if (tabsWithHit.length === 1) {
      switch (tabsWithHit[0]) {
        case 'SPOT':
          setProductTypeTab(
            CoinbasePublicApiAuthedRetailBrokerageApiProductType.SPOT,
          );
          break;
        case 'FUTURE':
          setProductTypeTab(
            CoinbasePublicApiAuthedRetailBrokerageApiProductType.FUTURE,
          );
          break;
        case 'PERPETUAL':
          setProductTypeTab(ContractExpiryType.PERPETUAL);
          break;
        case 'WATCHLIST':
          setProductTypeTab('Watchlist');
          break;
        default:
          break;
      }
    }
  }, [productDisplayCountMap, setProductTypeTab]);

  useEffect(() => {
    setTabWithOneProduct();
  }, [productDisplayCountMap, setTabWithOneProduct]);

  const [, cancelDebounce] = useDebounce(
    () => {
      setSearchFilter(localSearchInput);
      logMarketSelectorV3Search({ searchInput: localSearchInput });
    },
    250,
    [localSearchInput],
  );

  const handleSearchInputChange = useCallback((text: string) => {
    setLocalSearchInput(text);
  }, []);

  const handleClearInput = useCallback(() => {
    setLocalSearchInput('');
    setSearchFilter('');
    cancelDebounce();
  }, [setSearchFilter, cancelDebounce]);

  const renderCustomTabLabel = useCallback((props: CustomTabProps) => {
    return (
      <TextLabel1 spacingVertical={1} as="p">
        {props.label}
      </TextLabel1>
    );
  }, []);
  return (
    <ThemeProvider scale="xSmall">
      <NavigationBar spacingBottom={0} spacingTop={2}>
        <VStack
          width="100%"
          justifyContent="space-around"
          spacingHorizontal={0.5}
          maxWidth={isMobile ? '100%' : 295}
        >
          <HStack spacingBottom={1} justifyContent="space-between">
            <TextHeadline as="p">
              {formatMessage(messages.marketsLabel)}
            </TextHeadline>
            <Pressable background="transparent" onPress={handleClose}>
              <Icon name="close" size="s" color="foreground" />
            </Pressable>
          </HStack>
          <HStack
            width="100%"
            alignItems="center"
            justifyContent="center"
            spacingVertical={2}
            testID="market-selector-v3-nav-bar"
          >
            <SearchInput
              compact
              accessibilityLabel={formatMessage(messages.search)}
              onChangeText={handleSearchInputChange}
              onClear={handleClearInput}
              placeholder={formatMessage(messages.searchBarPlaceholder)}
              value={localSearchInput}
              testID="marketSelectorV3NavBarSearchInput"
              disabled={isLoading}
            />
          </HStack>
          <TabNavigation
            Component={renderCustomTabLabel}
            tabs={tabs}
            value={productTypeTab}
            onChange={
              // CDS doesnt let us specify a custom type for the onChange handler so we have to cast it here.
              // They just want a primitive `string` type in the State Dispatcher function arguments but we prefer to be more specific with the setProductTypeTab type in our app level code..
              isLoading ? noop : (setProductTypeTab as (value: string) => void)
            }
            gap={2}
            spacingVertical={0}
            width="100%"
          />
        </VStack>
      </NavigationBar>
    </ThemeProvider>
  );
}

export default memo(MarketSelectorV3NavBar);

import { useState, memo, useCallback, useMemo } from 'react';
import Big from 'big.js';
import { useIntl } from 'react-intl';
import { useHistory } from 'react-router-dom';

import { UseEnrichedDataOptions } from '@cbhq/advanced-trading-shared/hooks/enrichedData';
import { useEnrichedProductStats } from '@cbhq/advanced-trading-shared/hooks/enrichedData/productStats/useEnrichedProductStats';
import { Icon } from '@cbhq/cds-web/icons/Icon';
import { HStack, VStack } from '@cbhq/cds-web/layout';
import { Tooltip } from '@cbhq/cds-web/overlays';
import { Pressable } from '@cbhq/cds-web/system';
import { TextBody, TextHeadline } from '@cbhq/cds-web/typography';
import {
  DEFAULT_FORMATTED_FALLBACK,
  useFiatCurrencyCodes,
} from '@cbhq/common-web';
import {
  useGetWatchlist,
  useWithOptimisticWatchlistUpdates,
} from '@cbhq/instant-api-hooks-retail-brokerage/fetch';
import {
  useUnwatchProduct,
  useWatchProduct,
} from '@cbhq/instant-api-hooks-retail-brokerage/mutation';
import { ProductStatsResult } from '@cbhq/instant-api-hooks-retail-brokerage/stream';
import {
  CoinbasePublicApiAuthedRetailBrokerageApiProductType,
  CoinbasePublicApiAuthedRetailBrokerageApiProductWithSparkline,
} from '@cbhq/instant-api-hooks-retail-brokerage/types';

import useIsIntxPreLaunchContract from '../../hooks/useIsIntxPreLaunchContract';
import { useLatestProductPrice } from '../../hooks/useLatestProductPrice';
import { convertIncrementToPrecision } from '../../utils/convertIncrementToPrecision';
import AssetCurrencyIcon from '../CurrencyIcon/AssetCurrencyIcon';
import { MarketIconPair } from '../MarketIconPair';
import MarketSelectorBadge from '../MarketSelector/MarketSelectorTableProductRow/MarketSelectorBadge';
import { useProductStatsFormatter } from '../ProductStats/hooks/useProductStatsFormatter';
import {
  logMarketSelectorV3ProductSelected,
  logMarketSelectorV3AddToWatchlist,
} from './eventing';
import messages from './messages';
import {
  formatPriceChange,
  formatVolume,
  getProductRowClickPath,
} from './utils';

type MarketSelectorV3TableProductRowProps = {
  productWithSparkline: CoinbasePublicApiAuthedRetailBrokerageApiProductWithSparkline;
  productStatus?: string;
  isSelected: boolean;
  style: React.CSSProperties;
  assetIconMap: Partial<Record<string, string>>;
  nativeCurrency: string;
  // isPerpsPreviewModeOnly?: boolean;
};

function MarketSelectorV3TableProductRow({
  productWithSparkline,
  productStatus,
  isSelected,
  style,
  assetIconMap,
  nativeCurrency,
}: MarketSelectorV3TableProductRowProps) {
  const fiatCurrencyCodes = useFiatCurrencyCodes();
  const { formatPrice } = useProductStatsFormatter();
  const { formatMessage } = useIntl();
  const history = useHistory();

  const {
    price = '',
    approximateQuote24hVolume = '',
    productId = '',
    pricePercentageChange24h = '',
    displayName = '',
    quoteCurrencyId = '',
    baseCurrencyId = '',
    priceIncrement = '',
    quoteIncrement = '',
    futureProductDetails,
    productType,
    viewOnly,
    new: isNewlyListed,
  } = productWithSparkline.product || {};

  const { watchlist } = useGetWatchlist();
  const isWatched = useMemo(() => {
    return (watchlist?.productIds || []).includes(productId);
  }, [watchlist, productId]);
  const withOptimisticUpdates = useWithOptimisticWatchlistUpdates();

  const postWatchProduct = useWatchProduct();
  const postUnwatchProduct = useUnwatchProduct();

  const handleFavoriteClick = useCallback(
    (productId: string) => {
      withOptimisticUpdates(currentWatchlist => {
        return [
          {
            watchlist: {
              ...(currentWatchlist?.watchlist || {
                id: '',
                productIds: [],
                createdAt: '',
                updatedAt: '',
              }),
              productIds: [
                ...(currentWatchlist?.watchlist?.productIds || []),
                productId,
              ],
            },
          },
          postWatchProduct({ productId }),
        ];
      });
      logMarketSelectorV3AddToWatchlist({ productId, productType });
    },
    [postWatchProduct, productType, withOptimisticUpdates],
  );
  const handleUnfavoriteClick = useCallback(
    (productId: string) => {
      withOptimisticUpdates(currentWatchlist => {
        return [
          {
            watchlist: {
              ...(currentWatchlist?.watchlist || {
                id: '',
                productIds: [],
                createdAt: '',
                updatedAt: '',
              }),
              productIds: (
                currentWatchlist?.watchlist?.productIds || []
              ).filter(_ => _ !== productId),
            },
          },
          postUnwatchProduct({ productId }),
        ];
      });
    },
    [postUnwatchProduct, withOptimisticUpdates],
  );

  const enrichedProductStatsArgs = useMemo(() => ({ productId }), [productId]);
  const enrichedProductStatsOptions = useMemo(
    (): UseEnrichedDataOptions<ProductStatsResult> => ({
      streamingSuspend: true, // TODO (RAT-13237): Make conditional to PDE experiment
      onUpdate: updatedData => {
        setProductStats(updatedData);
      },
      skip: !isSelected,
    }),
    [isSelected],
  );

  const productStatsSnapshot = useEnrichedProductStats(
    enrichedProductStatsArgs,
    enrichedProductStatsOptions,
  );
  const [productStats, setProductStats] = useState(productStatsSnapshot);
  const livePricePercentChange24h = productStats?.pricePercentageChange24h;
  const liveVolume24h = productStats?.volume24h;
  const livePrice = useLatestProductPrice(productId, !isSelected);

  const currentPrice = isSelected && livePrice ? livePrice : price;
  const currentPricePercentChange24h =
    livePricePercentChange24h ?? pricePercentageChange24h;

  const isFiat = useMemo(
    () => fiatCurrencyCodes.includes(nativeCurrency),
    [fiatCurrencyCodes, nativeCurrency],
  );

  // Convert the live volume in terms of quote currency until the product stats stream returns approximate quote volume
  const currentVolume24h = useMemo(() => {
    if (!liveVolume24h) {
      return approximateQuote24hVolume;
    }

    return Big(liveVolume24h).mul(price).toString();
  }, [liveVolume24h, price, approximateQuote24hVolume]);

  const isWatchlistEnabled =
    productType === CoinbasePublicApiAuthedRetailBrokerageApiProductType.SPOT;

  const isDerivativesProduct =
    productType !== CoinbasePublicApiAuthedRetailBrokerageApiProductType.SPOT;

  const quoteExponent = useMemo(
    () => convertIncrementToPrecision(priceIncrement || quoteIncrement),
    [priceIncrement, quoteIncrement],
  );

  const formattedPrice = useMemo(() => {
    if (!currentPrice) return DEFAULT_FORMATTED_FALLBACK;
    const precision = parseFloat(currentPrice) >= 1 ? 2 : quoteExponent;

    return formatPrice(currentPrice, isFiat, nativeCurrency, precision);
  }, [currentPrice, quoteExponent, formatPrice, isFiat, nativeCurrency]);

  const isPriceChangePositive = useMemo(
    () => parseFloat(pricePercentageChange24h) > 0,
    [pricePercentageChange24h],
  );

  const formattedPricePercentageChange24h = useMemo(
    () =>
      formatPriceChange(currentPricePercentChange24h, isPriceChangePositive),
    [currentPricePercentChange24h, isPriceChangePositive],
  );

  const formattedVolume24h = useMemo(
    () => formatVolume(currentVolume24h, isDerivativesProduct),
    [isDerivativesProduct, currentVolume24h],
  );

  const volume24hText = useMemo(() => {
    if (viewOnly) {
      return formatMessage(messages.viewOnly);
    } else if (formattedVolume24h === DEFAULT_FORMATTED_FALLBACK) {
      return formattedVolume24h;
    }
    return formatMessage(messages.volume24h, {
      volume: formattedVolume24h,
    });
  }, [formatMessage, formattedVolume24h, viewOnly]);

  const pricePercentChangeColor = useMemo(() => {
    if (formattedPricePercentageChange24h === DEFAULT_FORMATTED_FALLBACK)
      return 'foregroundMuted';
    return isPriceChangePositive ? 'positive' : 'negative';
  }, [formattedPricePercentageChange24h, isPriceChangePositive]);

  const handleProductRowClick = useCallback(() => {
    logMarketSelectorV3ProductSelected({ productId, productType, isWatched });
    const to = getProductRowClickPath(
      productId,
      isDerivativesProduct,
      futureProductDetails,
    );
    history.push(to);
  }, [
    futureProductDetails,
    history,
    isDerivativesProduct,
    isWatched,
    productId,
    productType,
  ]);

  const handleWatchlistStarPress = useCallback(
    async (e: React.MouseEvent, productId: string) => {
      e.stopPropagation();
      e.preventDefault();
      if (isWatched) {
        handleUnfavoriteClick(productId);
      } else {
        handleFavoriteClick(productId);
      }
    },
    [handleFavoriteClick, isWatched, handleUnfavoriteClick],
  );

  const handleOnPress: React.MouseEventHandler = useCallback(
    e => handleWatchlistStarPress(e, productId),
    [handleWatchlistStarPress, productId],
  );

  const isPerpetualFuturesPreLaunch = useIsIntxPreLaunchContract(productStatus);
  const isPerpetualFuture =
    futureProductDetails?.contractExpiryType === 'PERPETUAL';

  const rowSubtitle = useMemo(() => {
    if (isPerpetualFuture && isPerpetualFuturesPreLaunch) {
      return <MarketSelectorBadge>{`PRE-LAUNCH`}</MarketSelectorBadge>;
    }

    if (!isPerpetualFuture && isNewlyListed) {
      return (
        <MarketSelectorBadge>
          {formatMessage(messages.newTagLabel)}
        </MarketSelectorBadge>
      );
    }

    return (
      <TextBody as="p" color="foregroundMuted">
        {volume24hText}
      </TextBody>
    );
  }, [
    formatMessage,
    isNewlyListed,
    isPerpetualFuture,
    isPerpetualFuturesPreLaunch,
    volume24hText,
  ]);

  return (
    // Using anchor tag instead of CDS Link which seems to disrupt the grid layout
    <a style={style} onClick={handleProductRowClick}>
      <HStack
        alignItems="center"
        justifyContent="space-between"
        spacingVertical={1}
        spacingHorizontal={3}
        background={isSelected ? 'primaryWash' : 'background'}
        testID="market-selector-v3-table-product-row"
        className="market-selector-v3-product-row"
      >
        <HStack alignItems="center" gap={2}>
          {isDerivativesProduct ? (
            <AssetCurrencyIcon
              size={24}
              symbol={futureProductDetails?.contractRootUnit}
              assetUuid={futureProductDetails?.perpetualDetails?.baseAssetUuid}
            />
          ) : (
            <MarketIconPair
              assetIconMap={assetIconMap}
              baseCurrencyId={baseCurrencyId || ''}
              quoteCurrencyId={quoteCurrencyId || ''}
              iconSize={20}
            />
          )}
          <VStack alignItems="flex-start" justifyContent="center">
            <TextHeadline as="p">{displayName}</TextHeadline>
            {rowSubtitle}
          </VStack>
        </HStack>
        <HStack alignItems="center" gap={2}>
          <VStack alignItems="flex-end" justifyContent="center">
            <TextBody as="p">{formattedPrice}</TextBody>
            <TextBody as="p" color={pricePercentChangeColor}>
              {formattedPricePercentageChange24h}
            </TextBody>
          </VStack>
          <Tooltip
            content={formatMessage(messages.disabledWatchlistStarButtonText)}
            placement="right"
            visible={!isWatchlistEnabled}
          >
            <Pressable
              background="transparent"
              onPress={handleOnPress}
              testID={`marketSelectorV3WatchlistStarButton-${productId}`}
              disabled={!isWatchlistEnabled}
            >
              <Icon
                name={isWatched ? 'starActive' : 'starInactive'}
                size="xs"
                color={isWatched ? 'foreground' : 'foregroundMuted'}
              />
            </Pressable>
          </Tooltip>
        </HStack>
      </HStack>
    </a>
  );
}

export default memo(MarketSelectorV3TableProductRow);

import { memo, useCallback } from 'react';
import { Icon } from '@cbhq/cds-web/icons/Icon';
import { HStack } from '@cbhq/cds-web/layout/HStack';
import { Pressable } from '@cbhq/cds-web/system/Pressable';
import { TextHeadline } from '@cbhq/cds-web/typography';

import { logMarketSelectorV3Opened } from './eventing';

type MarketSelectorV3TogglerProps = {
  productIcon: React.ReactNode;
  productDisplayName: string | undefined;
  isMarketSelectorDrawerOpen?: boolean;
  showMarketSelectorDrawer?: () => void;
  hideMarketSelectorDrawer?: () => void;
};

function MarketSelectorV3Toggler({
  productIcon,
  productDisplayName,
  isMarketSelectorDrawerOpen = false,
  showMarketSelectorDrawer,
  hideMarketSelectorDrawer,
}: MarketSelectorV3TogglerProps) {
  const handleToggle = useCallback(() => {
    if (isMarketSelectorDrawerOpen) {
      hideMarketSelectorDrawer?.();
    } else {
      showMarketSelectorDrawer?.();
      logMarketSelectorV3Opened();
    }
  }, [
    hideMarketSelectorDrawer,
    isMarketSelectorDrawerOpen,
    showMarketSelectorDrawer,
  ]);

  return (
    <HStack alignItems="center" gap={2}>
      <Pressable
        background="secondary"
        onPress={handleToggle}
        borderRadius={20}
        style={{ padding: 12 }}
      >
        <Icon name="advancedMarketSelector" size="m" color="foreground" />
      </Pressable>
      <HStack alignItems="center" gap={1} spacingVertical={1}>
        {productIcon}
        <TextHeadline as="p">{productDisplayName}</TextHeadline>
      </HStack>
    </HStack>
  );
}

export default memo(MarketSelectorV3Toggler);

import React, {
  type KeyboardEvent,
  ReactNode,
  memo,
  forwardRef,
  useImperativeHandle,
  useMemo,
  useRef,
  ForwardRefExoticComponent,
  RefAttributes,
  useCallback,
} from 'react';
import styled from 'styled-components';

import { useSpectrum } from '@cbhq/cds-web';
import { Icon } from '@cbhq/cds-web/icons';
import { HStack } from '@cbhq/cds-web/layout/HStack';
import { VStack } from '@cbhq/cds-web/layout/VStack';
import { Pressable } from '@cbhq/cds-web/system';
import { palette, spacing } from '@cbhq/cds-web/tokens';
import { TextLabel1 } from '@cbhq/cds-web/typography/TextLabel1';
import { TextLabel2 } from '@cbhq/cds-web/typography/TextLabel2';

import { BACKGROUND_COLOR_CSS_VALUE } from '../../components/shared/TradingComponentsLayoutManager';
import { getSpectrumColor } from '../../constants/colors';
import { ORDER_FORM_INPUT_HEIGHT } from '../../constants/orderForm';
import { isSafari } from '../../utils/isSafari';
import { numericInputCheck } from '../../utils/numericInputCheck';
import AdvancedTooltip from '../shared/AdvancedTooltip';

export type Props = {
  highlighted?: boolean;
  error?: ReactNode | null;
  label?: ReactNode;
  suffix?: ReactNode;
  ariaLabel?: string;
  autoFocus?: boolean;
  disableVerticalPadding?: boolean;
  tooltipContent?: ReactNode;
  /** Displays the toggle icon after the suffix and gets called on input press */
  onToggle?: () => void;
} & React.InputHTMLAttributes<HTMLInputElement> &
  RefAttributes<HTMLInputElement>;

const NumericInput: ForwardRefExoticComponent<Props> = memo(
  forwardRef<HTMLInputElement, Omit<Props, 'ref'>>(
    (
      {
        error,
        label,
        suffix,
        children,
        disabled,
        highlighted,
        value,
        ariaLabel,
        autoFocus,
        disableVerticalPadding,
        onKeyDown,
        tooltipContent,
        onToggle,
        ...inputProps
      },
      ref,
    ) => {
      const inputRef = useRef<HTMLInputElement>(null);
      useImperativeHandle<HTMLInputElement | null, HTMLInputElement | null>(
        ref,
        () => inputRef.current,
      );

      const shouldUseForcedInputCheck = isSafari();

      // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
      const handleContainerClick = () => {
        inputRef.current?.focus();
      };

      const handleOnKeyDown = useCallback(
        (event: KeyboardEvent<HTMLInputElement>) => {
          if (
            // non-Safari browser, trigger onKeyDown asap
            !shouldUseForcedInputCheck ||
            numericInputCheck(event)
          ) {
            onKeyDown?.(event);
          } else {
            event.preventDefault();
          }
        },
        [onKeyDown, shouldUseForcedInputCheck],
      );

      const inputLabel = useMemo(() => {
        if (!label) {
          return null;
        }

        if (typeof label === 'string') {
          return (
            <TextLabel1
              as="p"
              color={disabled ? 'foregroundMuted' : 'foreground'}
              selectable="none"
              noWrap
              transform="uppercase"
            >
              {label}
            </TextLabel1>
          );
        }

        return label;
      }, [label, disabled]);

      const inputSuffix = useMemo(() => {
        if (typeof suffix === 'string') {
          return (
            <TextLabel2
              as="p"
              color={
                disabled || value === '' ? 'foregroundMuted' : 'foreground'
              }
              spacingStart={0.5}
              transform="uppercase"
            >
              {suffix}
            </TextLabel2>
          );
        }

        return suffix;
      }, [suffix, disabled, value]);

      const spectrum = useSpectrum();
      const handleScroll = useCallback(
        (e: React.WheelEvent<HTMLInputElement>) => {
          e.preventDefault();
          inputRef.current?.blur();
        },
        [],
      );

      const handleSuffixPress = useCallback(() => {
        onToggle?.();
      }, [onToggle]);

      const formattedSuffix = useMemo(() => {
        if (!suffix) return null;
        return (
          <Pressable background="transparent" onPress={handleSuffixPress}>
            <HStack spacingEnd={2} alignItems="center" gap={0.5}>
              {inputSuffix}
              {onToggle && (
                <Icon
                  size="s"
                  name="arrowsHorizontal"
                  color="foreground"
                  testID="toggleIcon"
                  accessibilityLabel="Toggle"
                />
              )}
            </HStack>
          </Pressable>
        );
      }, [handleSuffixPress, inputSuffix, onToggle, suffix]);

      return (
        <VStack width="100%">
          <Container
            onClick={handleContainerClick}
            data-disabled={disabled}
            data-has-error={!!error}
            data-highlighted={highlighted}
            data-vertical-padding-disabled={disableVerticalPadding}
            data-spectrum={spectrum}
          >
            <HStack width="100%" alignItems="center">
              {inputLabel}
              {tooltipContent && (
                <HStack spacingStart={1}>
                  <AdvancedTooltip>{tooltipContent}</AdvancedTooltip>
                </HStack>
              )}
              <Input
                key="NumericInputStyledInput"
                {...inputProps}
                onKeyDown={handleOnKeyDown}
                disabled={disabled}
                value={value}
                ref={inputRef}
                onWheel={handleScroll}
                type="number"
                data-disabled={disabled}
                data-spectrum={spectrum}
                aria-label={ariaLabel}
                autoFocus={autoFocus}
              />
              {formattedSuffix}
            </HStack>
            {children}
          </Container>
          {error ? <Error>{error}</Error> : null}
        </VStack>
      );
    },
  ),
);

NumericInput.displayName = 'NumericInput';

