import { useMemo, memo, useState, useCallback, ReactNode } from 'react';
import { TabProps } from '@cbhq/cds-common';
import { IconButton } from '@cbhq/cds-web/buttons';
import { HStack, VStack } from '@cbhq/cds-web/layout';
import { TabNavigation } from '@cbhq/cds-web/tabs';

export const OPEN_HEIGHT = '225px';
export const CLOSED_HEIGHT = '52px';

export type TradeMangementTrayTab = TabProps & {
  actions?: ReactNode;
  body?: ReactNode;
};

export type TradeManagementTrayProps<T extends string> = {
  tabs: TradeMangementTrayTab[];
  defaultTab: T;
  isOpen?: boolean;
  onToggleTray?: () => void;
};

/**
 * This is intenteded to be a generic component that can be used
 * to render a tray with tabs and content for any market type
 * without the need for order tray context.
 *
 * Each market type will be responsible for providing the tabs,
 * defaultTab, bodyContentMap, and actionsContentMap. while this
 * component will handle the rendering of the tabs and content in
 * a uniform way.
 */
function TradeManagementTray({
  tabs,
  defaultTab,
  isOpen,
  onToggleTray,
}: TradeManagementTrayProps<string>) {
  const [activeTab, setActiveTab] = useState(defaultTab);

  const { body: bodyContent, actions: actionContent } = useMemo(() => {
    const tab = tabs.find(tab => tab.id === activeTab);
    if (!tab) return { body: null, actions: null };
    return tab;
  }, [tabs, activeTab]);

  const handleOnChange = useCallback(
    (type: string) => {
      setActiveTab(type);
    },
    [setActiveTab],
  );

  const actions = useMemo(() => {
    return (
      <HStack spacerGap={1}>
        {actionContent}
        <IconButton
          compact
          name={isOpen ? 'caretDown' : 'caretUp'}
          onPress={onToggleTray}
        />
      </HStack>
    );
  }, [isOpen, actionContent, onToggleTray]);

  const headerContent = useMemo(() => {
    return (
      <HStack
        spacing={3}
        spacerGap={1}
        alignContent="center"
        justifyContent="space-between"
        zIndex={1}
      >
        <TabNavigation
          tabs={tabs}
          value={activeTab}
          variant="secondary"
          onChange={handleOnChange}
        />
        {actions}
      </HStack>
    );
  }, [tabs, activeTab, handleOnChange, actions]);

  return (
    <VStack
      flexShrink={0}
      flexGrow={0}
      minHeight={isOpen ? OPEN_HEIGHT : CLOSED_HEIGHT}
      data-component="AdvancedLayoutAreaCard"
      style={{
        transition: 'min-height 0.3s ease-in-out',
      }}
      position="relative"
    >
      {headerContent}
      {isOpen && bodyContent}
    </VStack>
  );
}

export default memo(TradeManagementTray);

