import { logLayoutTabPress } from '../../../components/shared/TradingComponentsLayoutManager/eventing';
import { useTradingComponentsLayoutContext } from '../../../components/shared/TradingComponentsLayoutManager/useTradingComponentsLayoutContext';
import { advancedCommonMessages } from '../../../constants/commonMessages';
import { usePersistentSettingsContext } from '../../../contexts/PersistentSettingsContext';
import { usePersistChartsCardActive } from '../../../hooks/usePersistChartsCardActive';
import { AdvancedLayoutAreaCard } from './AdvancedLayoutCard';

export enum ChartsTab {
  PriceChartTab = 'price_chart',
  DepthChartTab = 'depth_chart',
}

type Tabs = Omit<TabProps<string>, 'children'>[];

type Props = {
  priceChart: React.ReactNode;
  depthChart: React.ReactNode;
};

// TODO: This should be integrated with TabbedCard eventually
export const ChartsCard = memo(function ChartsCard({
  priceChart,
  depthChart,
}: Props) {
  const { formatMessage } = useIntl();

  const {
    isPhone: isPhoneVertical,
    isPhoneLandscape,
    isDesktop,
  } = useBreakpoints();
  const isPhone = isPhoneVertical || isPhoneLandscape;

  const persistChartsCardActive = usePersistChartsCardActive();
  const { rat_charts_card_active: persistedActiveTab } =
    usePersistentSettingsContext();

  const [activeTab, setActiveTab] = useState<ChartsTab>(
    persistedActiveTab ?? ChartsTab.PriceChartTab,
  );

  const chartTabs: Tabs = useMemo(() => {
    const tabs: Tabs = [
      {
        id: ChartsTab.PriceChartTab,
        label: formatMessage(advancedCommonMessages.priceChart),
      },
    ];

    if (!isPhone) {
      tabs.push({
        id: ChartsTab.DepthChartTab,
        label: formatMessage(advancedCommonMessages.depthChart),
      });
    }

    return tabs;
  }, [formatMessage, isPhone]);

  const handleTabChange = useCallback(
    (id: string) => {
      const activeTabId = id as ChartsTab;
      logLayoutTabPress({
        previous: activeTab,
        next: activeTabId,
      });
      setActiveTab(activeTabId);
      persistChartsCardActive(activeTabId);
    },
    [activeTab, persistChartsCardActive],
  );

  useEffect(() => {
    setActiveTab(persistedActiveTab ?? ChartsTab.PriceChartTab);
  }, [persistedActiveTab]);

  return (
    <AdvancedLayoutAreaCard
      minHeight={480}
      data-testid="charts-container"
      borderedBottom
    >
      <HStack
        height={43}
        alignItems="center"
        borderedBottom={true}
        id="charts-container-header"
      >
        <StyledHStack
          width="100%"
          justifyContent="space-between"
          alignItems="center"
          spacingStart={3}
          spacingEnd={1}
        >
          <TabNavigation
            variant="secondary"
            tabs={chartTabs}
            value={activeTab}
            onChange={handleTabChange}
            zIndex={0}
          />
          {isDesktop && <ExpandCollapseColumnButton />}
        </StyledHStack>
      </HStack>
      {activeTab === ChartsTab.DepthChartTab ? depthChart : priceChart}
    </AdvancedLayoutAreaCard>
  );
});

function ExpandCollapseColumnButton() {
  const { activeLayout, setPresetName } = useTradingComponentsLayoutContext();
  const isExpanded = activeLayout === 'charts-column-expanded';

  const iconName = useMemo<UiIconName>(
    () => (isExpanded ? 'collapse' : 'expand'),
    [isExpanded],
  );

  const handleOnPress = useCallback(() => {
    if (isExpanded) {
      setPresetName('default');
    } else {
      setPresetName('charts-column-expanded');
    }
  }, [isExpanded, setPresetName]);

  return (
    <IconButton
      testID="expand-collapse-button"
      name={iconName}
      compact
      transparent
      variant="foregroundMuted"
      onPress={handleOnPress}
    />
  );
}

