  beforeEach(() => {
    (useBreakpoints as jest.Mock).mockReturnValue({
      isPhone: false,
      isDesktop: true,
      isExtraWide: false,
    });
  });

  it('should render default view', () => {
    const { wrapper } = createTestProvider();
    const { queryByTestId, queryAllByText } = render(
      <DefaultTradingComponentManager />,
      { wrapper },
    );

    const tradeHistoryTabButton = queryAllByText(/Trade history/)[0];

    expect(queryByTestId('charts')).toBeTruthy();
    expect(queryByTestId('tray')).toBeTruthy();
    expect(queryByTestId('tradeHistory')).toBeFalsy(); // tabbed - hidden
    expect(tradeHistoryTabButton).toBeTruthy(); // tab text
    expect(queryByTestId('orderBook')).toBeTruthy();
    expect(queryByTestId('marginHealth')).toBeTruthy();
    expect(queryByTestId('orderForm')).toBeTruthy();
    expect(queryByTestId('portfolioSelector')).toBeTruthy();
  });

  it('should handle tabbed view click', () => {
    const { wrapper } = createTestProvider();
    const { queryByTestId, getAllByText } = render(
      <DefaultTradingComponentManager />,
      { wrapper },
    );

    expect(queryByTestId('tradeHistory')).toBeFalsy(); // tabbed - hidden
    const tradeHistoryTabButton = getAllByText(/Trade history/)[0];

    fireEvent.click(tradeHistoryTabButton);

    expect(queryByTestId('tradeHistory')).toBeTruthy();
    expect(queryByTestId('orderBook')).toBeFalsy();
  });

  it('should handle wrapping components in a card', () => {
    window.innerWidth = deviceBreakpoints.extraWide;
    const { wrapper } = createTestProvider();
    const { queryByTestId } = render(<DefaultTradingComponentManager />, {
      wrapper,
    });

    const tradeHistory = queryByTestId('tradeHistory');

    expect(queryByTestId('charts')).toBeTruthy();
    expect(queryByTestId('tray')).toBeTruthy();
    expect(tradeHistory).toBeTruthy();
    expect(queryByTestId('orderBook')).toBeTruthy();
    expect(queryByTestId('marginHealth')).toBeTruthy();
    expect(queryByTestId('orderForm')).toBeTruthy();
    expect(queryByTestId('portfolioSelector')).toBeTruthy();

    // Check we wrap these components properly when they have no containers
    expect(tradeHistory?.parentElement?.getAttribute('data-component')).toEqual(
      'AdvancedLayoutAreaCard',
    );
  });
});

