import React, { useCallback, memo, useState, useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';

import { debounce } from '@cb/shared/utils';
import { InputIcon } from '@cbhq/cds-web/controls/InputIcon';
import { InputIconButton } from '@cbhq/cds-web/controls/InputIconButton';
import { TextInput } from '@cbhq/cds-web/controls/TextInput';

import { FilterQueryStringType } from './types';
import { useQueryString } from './useQueryString';

const i18nKey = 'Filter';

const messages = defineMessages({
  placeholder: {
    id: `${i18nKey}.placeholder`,
    defaultMessage: 'Search',
    description: `#Component: TextInput:placeholder
    #CharLimit: 40
    #Context: Search placeholder`,
  },
});

export function Search() {
  const { formatMessage } = useIntl();
  const [query, setQuery] = useQueryString<FilterQueryStringType>();
  const [currentSearch, setCurrentSearch] = useState<string>(
    query.search || '',
  );

  const setQueryString = useCallback(
    (nextValue?: string) => {
      setQuery('search', nextValue);
    },
    [setQuery],
  );

  const debouncedSetQS = useMemo(
    () => debounce(setQueryString, 300),
    [setQueryString],
  );

  const handleSearch = useCallback(
    (nextValue: string) => {
      setCurrentSearch(nextValue);

      if (nextValue !== currentSearch) debouncedSetQS(nextValue.trim());
    },
    [currentSearch, debouncedSetQS],
  );

  const clearSearch = useCallback(() => {
    setCurrentSearch('');
    setQueryString();
  }, [setQueryString]);

  const handleOnClick = useCallback(() => clearSearch(), [clearSearch]);

  const handleOnChange: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(({ target: { value } }) => handleSearch(value), [handleSearch]);

  return (
    <TextInput
      label=""
      start={<InputIcon name="search" color="foregroundMuted" />}
      end={
        currentSearch && (
          <InputIconButton
            disableInheritFocusStyle
            name="close"
            color="foregroundMuted"
            onClick={handleOnClick}
          />
        )
      }
      compact
      placeholder={formatMessage(messages.placeholder)}
      value={currentSearch}
      onChange={handleOnChange}
    />
  );
}

export const SearchInput = memo(Search);

import { memo, useState, useCallback, useContext } from 'react';
import { theme } from '@cb/shared/styles/theme';
import { InputIcon } from '@cbhq/cds-web/controls/InputIcon';
import { TextInput } from '@cbhq/cds-web/controls/TextInput';
import { Box } from '@cbhq/cds-web/layout/Box';
import { VStack } from '@cbhq/cds-web/layout/VStack';

import PageComposeContext from 'pages/cms/context/PageComposeContext';

import AssetsTable from './AssetsTable';

function AssetsWrapper() {
  const assets = useContext(PageComposeContext);
  const [filter, setFilter] = useState('');

  const sortAssetsByMarketCap = useCallback(() => {
    return assets.sort(
      (a, b) => parseInt(b.market_cap) - parseInt(a.market_cap),
    );
  }, [assets]);

  const getAssets = () => {
    const sorted = sortAssetsByMarketCap();
    return sorted.filter(
      ({ name, symbol }) =>
        name.toLowerCase().includes(filter.toLowerCase()) ||
        symbol.includes(filter.toLowerCase()),
    );
  };

  const handleOnChange: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(({ target }) => setFilter(target.value), []);

  return (
    <Box width="100%" justifyContent="center" spacingVertical={8}>
      <VStack spacingHorizontal={3} width="100%" maxWidth={theme.layout.width}>
        <Box width="100%" spacingBottom={3}>
          <TextInput
            label=""
            start={<InputIcon name="search" />}
            placeholder="Search all assets..."
            onChange={handleOnChange}
          />
        </Box>
        <AssetsTable assets={getAssets()} />
      </VStack>
    </Box>
  );
}

export default memo(AssetsWrapper);

