export default function CardGrid({
  description,
  title,
  expandable = false,
  pages,
}: CardGrid) {
  const [visibleCount, setVisibleCount] = useState(3);
  const { isPhone, isSmallDesktop, isTablet } = useBreakpoint();
  const { mainSectionSpacingHorizontal, instoSpacingTop } = useInstoSpacing();
  const {
    location: { search },
  } = useHistory();

  const { cards = [] } = useMemo(() => {
    const queryString = search
      ? `?${new URLSearchParams(search).toString()}`
      : '';

    return buildSourceManualOnly({
      queryString,
      originalEntry: { fields: { pages } },
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
    } as any);
  }, [search, pages]);

  const cardsToRender = useMemo(() => {
    return uniqBy(cards, card => card.id);
  }, [cards]);

  if (cardsToRender.length === 0) {
    return <NoResutlsFound />;
  }
  const screenSize: ScreenSize = isPhone
    ? 'mobile'
    : isTablet || isSmallDesktop
    ? 'tablet'
    : 'desktop';

  const selectedLayout = LAYOUT?.[screenSize];
  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const onClick = () => setVisibleCount(limit => limit + 3);
  return (
    <MainSection
