          <TextDisplay2 spacingBottom={2} as="h2">
            {title}
          </TextDisplay2>
        ) : null}
        {description ? (
          <TextTitle4 spacingBottom={10} as="p" color="foregroundMuted">
            {description}
          </TextTitle4>
        ) : null}
        <Grid
          gridTemplateColumns={selectedLayout.gridTemplateColumns}
          isTablet={isTablet || isSmallDesktop}
        >
          {cardsToRender
            .slice(0, visibleCount)
            .map(
              ({
                id,
                title,
                description,
                linkUrl,
                imageUrl,
                imageAlt,
                imageOverlayText,
                tags,
                publicationDate,
                duration,
                openInNewWindow,
                showExternalLinkIcon,
              }) => {
                return (
                  <Card
                    key={id}
                    title={title}
                    description={description}
                    imageUrl={imageUrl}
                    imageAlt={imageAlt}
                    imageOverlayText={imageOverlayText}
                    tags={tags}
                    duration={duration}
                    openInNewWindow={openInNewWindow}
                    imageHeight={selectedLayout.imageHeight}
                    imageWidth={isPhone ? 120 : 160}
                    linkUrl={linkUrl}
                    publicationDate={publicationDate}
                    showExternalLinkIcon={showExternalLinkIcon}
                  />
                );
              },
            )}
        </Grid>

        {expandable && cards.length > visibleCount ? (
          <Button setLimit={onClick} buttonLabel={seeAllNewsLabel} />
        ) : null}
      </BoxWithMargin>
    </MainSection>
  );
