import Button from './Button';
import { LAYOUTS, LIMITS } from './constants';
import { ScreenSize, CardGridProps } from './types';
import {
  buildSourceManualOnly,
  buildSourceParentPage,
  buildSourceSelectedTypePage,
} from './utils';

export default function CardGrid({
  options: {
    shouldShowNoResultsFoundInfo,
    shouldHideIfCountNotMatchingLayout,
    ...options
  },
  originalEntry,
  sectionAnchor,
}: CardGridProps) {
  const {
    layout = 'Row of 3',
    source,
    title,
    expandable = false,
  } = originalEntry.fields;
  const [visibleCount, setVisibleCount] = useState(LIMITS[layout]);
  const { isPhone, isSmallDesktop, isTablet } = useBreakpoint();
  const { mainSectionSpacingHorizontal, instoSpacingTop, instoCDSSpacingTop } =
    useInstoSpacing();
  const {
    location: { search },
  } = useHistory();

  const {
    cards = [],
    tabs,
    ctaLink,
  } = useMemo(() => {
    const queryString = search
      ? `?${new URLSearchParams(search).toString()}`
      : '';

    const propGenerator =
      source === 'Filter Using Parent Page'
        ? buildSourceParentPage
        : source === 'Filter Using Selected Page'
        ? buildSourceSelectedTypePage
        : buildSourceManualOnly;

    return propGenerator({
      options,
      queryString,
      originalEntry,
    });
  }, [options, search, source, originalEntry]);

  const [selectedTabId, setSelectedTabId] = useState(tabs?.[0]?.id || 0);

  const cardsToRender = useMemo(() => {
    return uniqBy(cards, card => card.id).filter(
      card =>
        (tabs && tabs?.length > 0
          ? card.tags.includes(`${selectedTabId}`) || selectedTabId === 'all'
          : true) &&
        !(options?.excludeEntryIdsList ?? [])?.includes(`${card.id}`),
    );
  }, [cards, tabs, selectedTabId, options?.excludeEntryIdsList]);

  const handleOnClick = useCallback(
    (id: string | number) => setSelectedTabId(id),
    [],
  );

  if (cardsToRender.length === 0) {
    if (shouldShowNoResultsFoundInfo) {
      return <NoResutlsFound />;
    }

    return null;
  }

  const screenSize: ScreenSize = isPhone
    ? 'mobile'
    : isTablet || isSmallDesktop
    ? 'tablet'
    : 'desktop';

  const selectedLayout = LAYOUTS[layout]?.[screenSize];

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const onClick = () => setVisibleCount(limit => limit + LIMITS?.[layout]);

  if (
    shouldHideIfCountNotMatchingLayout &&
    cardsToRender.length < LIMITS?.[layout]
  ) {
    return null;
  }

  return (
    <MainSection
      background="background"
      spacingTop={instoSpacingTop}
      spacingHorizontal={mainSectionSpacingHorizontal}
      sectionAnchor={sectionAnchor}
    >
      <Box flexDirection="column">
        {title ? (
          <TextDisplay2 spacingBottom={7} as="h1">
            {title}
          </TextDisplay2>
        ) : null}
        {tabs?.length && (
          <Box spacingBottom={2}>
            <PillTabs
              pills={tabs}
              selectedId={selectedTabId}
              onClick={handleOnClick}
            ></PillTabs>
          </Box>
        )}
        <Grid
          gridTemplateColumns={selectedLayout.gridTemplateColumns}
          isTablet={isTablet || isSmallDesktop}
        >
          {cardsToRender
            .slice(0, visibleCount)
            .map(
              (
                {
                  id,
                  title,
                  description,
                  linkUrl,
                  imageUrl,
                  imageAlt,
                  imageOverlayText,
                  tags,
                  publicationDate,
                  duration,
                  openInNewWindow,
                  showExternalLinkIcon,
                },
                index,
              ) => {
                return (
                  <Card
                    key={id}
                    title={title}
                    description={description}
                    imageUrl={imageUrl}
                    imageAlt={imageAlt}
                    imageOverlayText={imageOverlayText}
                    tags={tags}
                    duration={duration}
                    openInNewWindow={openInNewWindow}
                    imageHeight={selectedLayout.imageHeight}
                    imageWidth={isPhone ? 120 : 160}
                    linkUrl={linkUrl}
                    publicationDate={publicationDate}
                    showExternalLinkIcon={showExternalLinkIcon}
                    showSecondaryTag={
                      layout === '1 Large 2 Small' && index === 0
                    }
                  />
                );
              },
            )}
        </Grid>

        {expandable && cards.length > visibleCount ? (
          <Button setLimit={onClick} buttonLabel={seeMoreLabel} />
        ) : null}

        {ctaLink ? (
          <Box spacingTop={instoCDSSpacingTop}>
            <Pressable background="transparent" href={ctaLink}>
              <HStack alignItems="center" spacerGap={1}>
                <TextBody as="p" spacingVertical={2} color="primary">
                  {ctaText}
                </TextBody>
                <Icon size="xs" name="forwardArrow" color="primary" />
              </HStack>
            </Pressable>
          </Box>
        ) : null}
      </Box>
    </MainSection>
  );
}

