import { useCallback, useState, useMemo } from 'react';
import { defineMessages, useIntl } from 'react-intl';

import { debounce } from '@cb/shared/utils';
import { InputIcon } from '@cbhq/cds-web/controls/InputIcon';
import { InputIconButton } from '@cbhq/cds-web/controls/InputIconButton';
import { TextInput } from '@cbhq/cds-web/controls/TextInput';

const i18nKey = 'Filter';

const messages = defineMessages({
  placeholder: {
    id: `${i18nKey}.placeholder`,
    defaultMessage: 'Search',
    description: `#Component: TextInput:placeholder
    #CharLimit: 40
    #Context: Search placeholder`,
  },
});

type SearchInputProps = {
  onSearch: (term?: string) => void;
};

export function SearchInput({ onSearch }: SearchInputProps) {
  const { formatMessage } = useIntl();

  const [currentSearch, setCurrentSearch] = useState<string>('');

  const setQueryString = useCallback(
    (nextValue?: string) => {
      onSearch(nextValue);
    },
    [onSearch],
  );

  const debouncedSetQS = useMemo(
    () => debounce(setQueryString, 300),
    [setQueryString],
  );

  const handleSearch = useCallback(
    (nextValue: string) => {
      setCurrentSearch(nextValue);

      if (nextValue !== currentSearch) debouncedSetQS(nextValue.trim());
    },
    [currentSearch, debouncedSetQS],
  );

  const clearSearch = useCallback(() => {
    setCurrentSearch('');
    setQueryString();
  }, [setQueryString]);

  const handleOnClick = useCallback(() => clearSearch(), [clearSearch]);

  const handleOnChange: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(({ target: { value } }) => handleSearch(value), [handleSearch]);

  return (
    <TextInput
      label=""
      start={<InputIcon name="search" color="foregroundMuted" />}
      end={
        currentSearch && (
          <InputIconButton
            disableInheritFocusStyle
            name="close"
            color="foregroundMuted"
            onClick={handleOnClick}
          />
        )
      }
      compact
      placeholder={formatMessage(messages.placeholder)}
      value={currentSearch}
      onChange={handleOnChange}
    />
  );
}

