export const DEFAULT_STAKABLE_TABLE_PAGE_SIZE = 9;

function HighlightStakableTableContent({
  legalDisclaimer,
  options,
}: HighlightStakableTableFields) {
  const existingQueryParams = useQueryParams();
  const [selectedFilter] = useState<StakableTableFilters>(
    paramFilterToEarnPageFilters(existingQueryParams?.filter),
  );
  const { pathname } = useLocation();
  const query = useFragment<StakableTableFragment$key>(
    graphql`
      fragment StakableTableFragment on Query {
        stakingAssets(
          first: $stakableTableSize
          after: $stakableTableCursor
          filter: $stakableTableFilter
        ) @required(action: THROW) {
          totalCount
          pageInfo {
            startCursor
            endCursor
          }
          edges {
            node {
              name
              imageUrl
              displaySymbol
              slug
              marketCapV2(quoteCurrency: $currency)
              stakingStats {
                percentageStaked
                isSupportedOnCoinbase
                hasStakingPage
                rewardApy
              }
            }
          }
        }
      }
    `,
    options?.queryRef || null,
  );
  const { localeCode, currency } = useLocale();
  const history = useHistory();
  const { formatNumber, formatMessage } = useIntl();
  const isMobile = useIsMobile();
  const isDesktopLarge = useScreenMatch('desktop_large');
  const [isTransitioning, startTransition] = useTransition();
  const isClientSide = useIsHydrated();
  const stakingAssets = query?.stakingAssets?.edges;
  const totalAssets = query?.stakingAssets?.totalCount;
  const pageInfo = query?.stakingAssets?.pageInfo;
  const tableTitle =
    isMobile && selectedFilter === 'STAKING'
      ? messages.tableTitleSTAKINGShort
      : messages[`tableTitle${selectedFilter}`];
  const missingMarketCap =
    stakingAssets?.filter(asset => asset?.node?.marketCapV2).length === 0;

  if (missingMarketCap && isClientSide) {
    throw new Error('Failed to fetch market cap data.');
  }

  const formatStakingMarketCap = useCallback(
    ({
      marketCap,
      percentageStaked,
      hasStakingPage,
    }: {
      percentageStaked: string | null | undefined;
      marketCap: string | null | undefined;
      hasStakingPage: boolean | null | undefined;
    }) => {
      const parsedMarketCap = Number(marketCap);
      const parsedPercentageStaked = Number(percentageStaked);

      if (
        !percentageStaked ||
        !marketCap ||
        isNaN(parsedPercentageStaked) ||
        isNaN(parsedMarketCap) ||
        !hasStakingPage
      ) {
        return formatMessage(messages.nonApplicable);
      }

      return formatNumber(parsedPercentageStaked * parsedMarketCap, {
        style: 'currency',
        currency,
        notation: 'compact',
        minimumFractionDigits: 1,
        maximumFractionDigits: 1,
      });
    },
    [formatNumber, currency, formatMessage],
  );

  // 2023-10-19: TODO please fix
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const stopPropagation = useCallback<OnPress>((event: any) => {
    event.stopPropagation();
  }, []);

  const getPageUrlForAsset = useCallback(
    ({
      slug,
