      if (hasStakingPage) {
        return getStakingPageUrl(slug, localeCode);
      } else {
        return getAssetPageUrl(slug ?? undefined, null, localeCode);
      }
    },
    [localeCode],
  );

  const redirectToPageForAsset = useCallback(
    ({
      slug,
      hasStakingPage,
    }: {
      slug: string | null | undefined;
      hasStakingPage: boolean | null | undefined;
    }) => {
      const url = getPageUrlForAsset({ slug, hasStakingPage });
