  );

  const nextPageParams = useMemo(() => {
    return new URLSearchParams({
      ...existingQueryParams,
      page: pageInfo?.endCursor || '',
    });
  }, [existingQueryParams, pageInfo?.endCursor]);

  const previousPageParams = useMemo(() => {
    return new URLSearchParams({
      ...existingQueryParams,
      page: pageInfo?.startCursor || '',
