      event.preventDefault();
      startTransition(() => {
        history.push({
          search: nextPageParams.toString(),
        });
      });
    },
    [nextPageParams, history],
  );

  const handlePreviousPageClick = useCallback<OnPress>(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (event: any) => {
      event.preventDefault();
      startTransition(() => {
        history.push({
          search: previousPageParams.toString(),
        });
      });
    },
    [previousPageParams, history],
  );

  // const handleSelectFilter = useCallback(
  //   (filter: StakableTableFilters) => {
  //     setSelectedFilter(filter);
  //     const newSearchParams = new URLSearchParams({
  //       ...existingQueryParams,
  //       filter,
  //     });
  //     newSearchParams.delete('page');
  //     startTransition(() => {
  //       history.push({ search: newSearchParams.toString() });
  //     });
  //   },
  //   [existingQueryParams, history],
  // );

  if (!stakingAssets || missingMarketCap) return null;

  return (
    <SectionComponentLayout
      hasSpacingHorizontal
      fullViewportWidth
      hasSpacingTop
    >
      <FeatureFlagProvider flexGap>
        <ThemeProvider>
          <VStack>
            <TextDisplay3 as="h2" spacingBottom={6}>
              {formatMessage(messages.title)}
            </TextDisplay3>
            <HStack justifyContent="space-between">
              <HStack
                alignItems="baseline"
                spacerGap={2}
                spacingEnd={1}
                responsiveConfig={{
                  phone: { flexDirection: 'column', gap: 1 },
                }}
              >
                <TextTitle1 as="h3">{formatMessage(tableTitle)}</TextTitle1>
                <TextBody as="p" color="foregroundMuted">
                  {formatMessage(messages.tableTotalAssets, {
                    totalAssets,
                  })}
                </TextBody>
              </HStack>
              {/*We need to hide the filters due to a change in the stakingrewards.com API which wasn't backwards compatible */}
              {/*TODO: Followup on new stakingrewards API filter options*/}
              {/*<TableFilters*/}
              {/*  value={selectedFilter}*/}
              {/*  onChange={handleSelectFilter}*/}
              {/*/>*/}
            </HStack>
            <Box offsetHorizontal={2} opacity={isTransitioning ? 0.3 : 1}>
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableCell
                      title={formatMessage(messages.columnTitleAsset)}
                    />
                    <TableCell
                      title={formatMessage(messages.columnTitleRewardRate)}
                    />
                    {!isMobile && (
                      <TableCell
                        title={formatMessage(messages.columnTitleStakingCap)}
