import { logAssetTapped } from 'pages/AssetPage/utils/analytics';

import { AssetHeaderToolbarFragment$key } from './__generated__/AssetHeaderToolbarFragment.graphql';

type Props = {
  queryRef: AssetHeaderToolbarFragment$key;
  hideSignupActions?: boolean;
};

const i18nKey = 'AssetHeaderToolbar';

const messages = defineMessages({
  addToWatchlist: {
    id: `${i18nKey}.addToWatchlist`,
    defaultMessage: 'Add to Watchlist',
    description: `#Component: Tooltip:content
    #CharLimit: 50
    #Context: Tooltip message shown when user hovers over a button`,
  },
  shareTooltip: {
    id: `${i18nKey}.shareTooltip`,
    defaultMessage: 'Sign up to share',
    description: `#Component: Tooltip:content
    #CharLimit: 50
    #Context: Tooltip message shown when user hovers over a button`,
  },
  buyButtonText: {
    id: `${i18nKey}.buyButtonText`,
    defaultMessage: 'Buy',
    description: `#Component: Button
    #CharLimit: 50
    #Context: Text for buy button`,
  },
});

function AssetHeaderToolbar({ queryRef, hideSignupActions = false }: Props) {
  const query = useFragment(
    graphql`
      fragment AssetHeaderToolbarFragment on Query
      @argumentDefinitions(slug: { type: "String!" }) {
        assetBySlug(slug: $slug) {
          id
          platformName
        }
      }
    `,
    queryRef,
  );
  const [isTypeaheadActive, setIsTypeaheadActive] = useState(false);
  const { formatMessage } = useIntl();
  const { pageCurrency, setPageCurrency } = useAssetPageCurrency();
  const handleOptionSelection = useCallback(
    (selectedOption: SearchDropdownOption) => {
      setPageCurrency(selectedOption.displayValue.primary);
    },
    [setPageCurrency],
  );
  const isPhoneSmall = useScreenMatch('phone_small');
  const searchContainer = useRef<HTMLDivElement | null>(null);
  const assetId = query?.assetBySlug?.id;
  const assetPlatformName = query?.assetBySlug?.platformName;
  const { isTreatment: isBuyPreviewExperiment } = useIsSEOExperimentGroup({
    mobileVariant:
      experiments[MAY_2024_LOGGED_OUT_ASSET_BUY_PREVIEW_MOBILE_WEB],
    desktopVariant: experiments[MAY_2024_LOGGED_OUT_ASSET_BUY_PREVIEW_DESKTOP],
    variantGroupNames: ['treatment'],
    additionalSkipTracking: false,
  });

  const handleSignupClick = useSignupClickHandler({
    section: 'follow',
    callback: () =>
      logAssetTapped(
        {
          assetId,
          assetSymbol: assetPlatformName || '',
        },
        'follow',
      ),
  });

  useAutoFocus({
    shouldAutoFocus: isPhoneSmall && isTypeaheadActive,
    findNode: () => searchContainer.current?.querySelector('input'),
    delay: 100,
  });

  useEffect(() => {
    // If the user resizes the page while typeahead is active
    if (!isPhoneSmall) {
      setIsTypeaheadActive(false);
    }
  }, [isPhoneSmall]);

  const handleOnPress = useCallback(() => setIsTypeaheadActive(true), []);

  if (!query?.assetBySlug) {
    return null;
  }
  return (
    <HStack spacerGap={1} height="40px">
      {isBuyPreviewExperiment && (
        <>
          <Button
            variant="primary"
            compact
            startIcon="chartCandles"
            onPress={handleSignupClick}
          >
            {`${formatMessage(messages.buyButtonText)}`}
          </Button>
          <Spacer horizontal={1} />
        </>
      )}
      {!isTypeaheadActive && (
        <>
          {hideSignupActions ? null : (
            <>
              <Tooltip
                content={formatMessage(messages.addToWatchlist)}
                placement="top"
                tooltipId="watchlist-tooltip"
              >
                <Box spacingEnd={1}>
                  <IconButton
                    name="starInactive"
                    onPress={handleSignupClick}
                    accessibilityLabel={formatMessage(messages.addToWatchlist)}
                  />
                </Box>
              </Tooltip>
              <Tooltip
                content={formatMessage(messages.shareTooltip)}
                placement="top"
                tooltipId="share-tooltip"
              >
                <Box spacingEnd={1}>
                  <IconButton
                    name="share"
                    onPress={handleSignupClick}
                    accessibilityLabel={formatMessage(messages.shareTooltip)}
                  />
                </Box>
              </Tooltip>
            </>
          )}
          <SearchableNativeCurrencyDropdown
            initialSelectedCurrency={pageCurrency}
            handleOptionSelection={handleOptionSelection}
            inputId="asset-page-currency-selector"
            isPillUI
            alignDropdown="left"
          />
        </>
      )}

      {isPhoneSmall && !isTypeaheadActive ? (
        <Tooltip
          content={formatMessage(messages.addToWatchlist)}
          placement="top"
          tooltipId="watchlist-tooltip-mobile"
        >
          <IconButton name="search" onPress={handleOnPress} />
        </Tooltip>
      ) : (
        <Box
          key="typeahead-wrapper"
          width={isPhoneSmall ? 'calc(100vw - 64px)' : '100%'}
          ref={searchContainer}
          alignItems="center"
        >
          <AssetPageTypeahead
            isTypeaheadActive={isTypeaheadActive}
            setIsTypeaheadActive={setIsTypeaheadActive}
          />
        </Box>
      )}
    </HStack>
  );
}

