import React, { memo, useCallback, useEffect, useRef } from 'react';
import { useIntl, MessageDescriptor } from 'react-intl';
import { useLocation } from 'react-router-dom';

import { useScreenMatch } from '@cb/shared/utils';
import { useToggler } from '@cbhq/cds-web';
import { Collapsible } from '@cbhq/cds-web/collapsible';
import { Icon } from '@cbhq/cds-web/icons/Icon';
import { Box } from '@cbhq/cds-web/layout/Box';
import { VStack } from '@cbhq/cds-web/layout/VStack';
import { Pressable } from '@cbhq/cds-web/system/Pressable';
import { TextDisplay3 } from '@cbhq/cds-web/typography/TextDisplay3';
import { TextTitle2 } from '@cbhq/cds-web/typography/TextTitle2';
import { MetricType, logMetric } from '@cbhq/client-analytics';
import { ErrorBoundary } from '@cbhq/common-web';

type Props = {
  title: MessageDescriptor | string;
  children: React.ReactChild;
  isCollapsed?: boolean;
  id: string;
  hasNestedIds?: boolean;
};

function AssetPageSection({
  title,
  children,
  id,
  hasNestedIds,
  isCollapsed = false,
}: Props) {
  const [collapsed, { toggle }] = useToggler(isCollapsed);
  const { hash } = useLocation();
  const { formatMessage } = useIntl();
  const isDesktop = useScreenMatch('desktop');
  const isMobile = useScreenMatch('phone');
  const Title = isMobile ? TextTitle2 : TextDisplay3;
  // We hide nested headings on mobile.
  const isNestedHeadings = hasNestedIds && isDesktop;
  const sectionRef = useRef<HTMLDivElement>(null);

  const querySelectHash = useCallback(() => {
    if (!hash) {
      return null;
    }

    try {
      return sectionRef?.current?.querySelector(hash);
    } catch (e) {
      // We don't validate that hash is a valid query selector, so some errors
      // are expected. These should be caught so as not to crash the webpage.
      console.error(e);
      logMetric({
        metricName: 'asset_page_section_query_selection_error',
        metricType: MetricType.count,
        value: 1,
      });
      return null;
    }
  }, [hash, sectionRef]);

  useEffect(() => {
    // Users could hide the section and then click on the table of contents
    // if the section is collapsed
    // and the URL hash is the same as the section id, open the section
    // or if the section contains a child with the hash ID, open the section
    if (collapsed && (hash === `#${id}` || querySelectHash())) {
      toggle();

      // If it's a nested heading, scroll to the element
      if (querySelectHash()) {
        // Push onto callback queue so it runs after the DOM is updated,
        setTimeout(() => {
          const id = hash.replace('#', '');
          const element = document.getElementById(id);

          if (element) {
            const elementPosition = element.getBoundingClientRect().top;

            window.scroll({
              top: elementPosition + window.scrollY - 67,
              behavior: 'smooth',
            });
          }
        }, 0);
      }
    }
  }, [hash, querySelectHash]);

  return (
    <ErrorBoundary context="asset-page-section" owner="acquisition">
      <VStack width="100%" id={isNestedHeadings ? '' : id} ref={sectionRef}>
        <Box
          justifyContent="space-between"
          alignItems="center"
          borderedTop
          spacingTop={7}
          spacingBottom={3}
          spacingHorizontal={4}
          id={isNestedHeadings ? id : ''}
        >
          <Title as="h3">
            {typeof title === 'string' ? title : formatMessage(title)}
          </Title>
          {/*TODO: replace IconButton with AnimatedCaret once ready in CDS*/}
          <Pressable
            onPress={toggle}
            as="button"
            type="button"
            borderRadius="roundedFull"
            background="backgroundAlternate"
            width="45px"
            height="45px"
          >
            <Box justifyContent="center">
              <Icon
                name={collapsed ? 'caretDown' : 'caretUp'}
                size={isMobile ? 's' : 'm'}
                color="foreground"
              ></Icon>
            </Box>
          </Pressable>
        </Box>
        <Collapsible collapsed={collapsed}>{children}</Collapsible>
