    defaultMessage:
      '{baseSymbol}/{targetSymbol}: Convert {base} ({baseSymbol}) to {target} ({targetSymbol})',
    description:
      'The title that describes the conversion page from one cryptocurrency to a fiat currency',
  },
  // 2023-10-05: TODO please fix, see go/i18n-linter-messages
  // eslint-disable-next-line @cbhq/i18n-enhanced-description
  convertAssetToAssetTitle: {
    id: `${i18nKey}.convertAssetToAssetTitle`,
    defaultMessage:
