type Props = {
  baseSymbol: string;
  baseId: string;
  baseName: string;
  targetCurrency?: string;
  targetPrice?: number;
  queryRef: ConversionToolFragment$key;
  setTarget: (targetName: string) => void;
  setBase: (baseSymbol: string) => void;
  assetToAsset?: boolean;
  targetSymbol?: string;
  targetSymbolId?: string;
  targetName: string;
  hideTitle?: boolean;
};

function ConversionToolContent({
  baseSymbol,
  baseId,
  baseName,
  targetCurrency,
  targetPrice,
  queryRef,
  setTarget,
  setBase,
  assetToAsset,
  targetSymbol,
  targetSymbolId,
  targetName,
  hideTitle,
}: Props) {
  const [query, refetch] = useRefetchableFragment(
    graphql`
      fragment ConversionToolFragment on Query
      @argumentDefinitions(
        skipFetchingCurrency: { type: "Boolean!" }
        skipFetchingSecondAsset: { type: "Boolean!" }
        targetSymbol: { type: "String!" }
      )
      @refetchable(queryName: "ConversionToolFragmentRefetchQuery") {
        assetBySymbol(symbol: $baseSymbol) {
          name
          displaySymbol
          latestPrice(quoteCurrency: $targetCurrency)
            @skip(if: $skipFetchingCurrency) {
            price
            quoteCurrency
            timestamp
          }
          imageUrl
          supportedContextsForLocation(countryCode: $country) {
            isTradable
            isDex
            isWallet
          }
          coinMarketCapId
          coinGeckoId
        }
        asset2: assetBySymbol(symbol: $targetSymbol)
          @skip(if: $skipFetchingSecondAsset) {
          name
          imageUrl
        }
      }
    `,
    queryRef,
  );

  const { formatMessage } = useIntl();
  const formatDate = useSSRSafeFormatDate();
  const [isReversed, setIsReversed] = useState<boolean>(false);
  const [isRefreshing, startRefreshTransition] = useTransition();
  const [isLoadingValueChange, startValueChangeTransition] = useTransition();
  const isMobile = useIsMobile();
  const asset = query?.assetBySymbol;

  const { baseValue, targetValue, onBaseValueChange, onTargetValueChange } =
    useControlledConversionInputs({
      targetPrice,
    });

  const flipConverter = useCallback(() => {
    isReversed
      ? onBaseValueChange(targetValue)
      : onTargetValueChange(String(baseValue));
    setIsReversed(!isReversed);
  }, [
    baseValue,
    targetValue,
    isReversed,
    setIsReversed,
    onBaseValueChange,
    onTargetValueChange,
  ]);

  const refreshPrice = useCallback(() => {
    startRefreshTransition(() => {
      refetch({}, { fetchPolicy: 'network-only' });
    });
  }, [refetch]);

  const handleBaseValueInputChange = useCallback(
    (event: ChangeEvent<HTMLInputElement>) => {
      onBaseValueChange(event.target.value);
    },
    [onBaseValueChange],
  );

  const handleTargetValueInputChange = useCallback(
    (event: ChangeEvent<HTMLInputElement>) => {
      onTargetValueChange(event.target.value);
    },
    [onTargetValueChange],
  );

  const handleBaseValueChange = useCallback(
    (value: string) => {
      startValueChangeTransition(() => setBase(value));
    },
    [setBase],
  );

  const handleTargetValueChange = useCallback(
    (value: string) => {
      startValueChangeTransition(() => setTarget(value));
    },
    [setTarget],
  );

  const dataSources = useMemo(() => {
    const sources = [];
    if (asset?.coinMarketCapId) {
      sources.push('CoinMarketCap');
    }
    if (asset?.coinGeckoId) {
      sources.push('CoinGecko');
    }
    return sources;
  }, [asset?.coinGeckoId, asset?.coinMarketCapId]);

  const isGenericPage = useIsGenericPage();
  const conversionTitleMessage = assetToAsset
    ? messages.convertAssetToAssetTitle
    : isGenericPage
    ? messages.genericConversionTitle
    : messages.convertAssetToCurrencyTitle;

  const [conversionTitle, conversionSubtitle] = useConversionTitleAndSubtitle({
    baseName,
    targetName,
    baseSymbol,
    targetSymbol,
    targetValue,
    targetPrice,
    baseValue,
    isReversed,
    assetToAsset,
    conversionTitleMessage,
    baseToTarget: messages.baseToTarget,
    price: asset?.latestPrice?.price || '0',
    quoteCurrency: asset?.latestPrice?.quoteCurrency || 'USD',
  });

  return (
    <>
      {!hideTitle && (
        <DatadogSyntheticTag tagName="converter_page_title">
          <CurrencyConverterTitle
            title={conversionTitle}
            conversionSubtitle={conversionSubtitle}
            loading={isLoadingValueChange}
            baseAssetName={asset?.name || ''}
            baseAssetDisplaySymbol={asset?.displaySymbol}
            isTradable={
              asset?.supportedContextsForLocation?.isTradable || false
            }
            isDex={asset?.supportedContextsForLocation?.isDex || false}
            isWallet={asset?.supportedContextsForLocation?.isWallet || false}
            baseAssetImageUrl={asset?.imageUrl || ''}
            targetImageUrl={query?.asset2?.imageUrl || ''}
            dataSources={dataSources}
          />
        </DatadogSyntheticTag>
      )}
      <Box
        spacingBottom={3}
        flexDirection={isReversed ? 'row-reverse' : 'row'}
        responsiveConfig={{
          phone: {
            flexDirection: isReversed ? 'column-reverse' : 'column',
            spacingBottom: 2,
          },
          desktop: { spacingTop: 6 },
        }}
      >
        <HStack
          responsiveConfig={{ tablet: { flexDirection: 'column', gap: 1 } }}
          spacerGap={2}
          width="100%"
          minWidth={0}
        >
          <SearchInputWrapper>
            <TextInput
              id="base"
              onChange={handleBaseValueInputChange}
              min="0"
              type="number"
              value={String(baseValue || 0)}
              borderRadius="roundedFull"
              compact
            />
          </SearchInputWrapper>
          <BaseCurrencySelectionContainer
            setBaseSymbol={handleBaseValueChange}
            baseCurrencyName={baseName}
            baseSymbol={baseSymbol}
            baseId={baseId}
            alignDropdownLeft={!isReversed}
          />
        </HStack>
        <Box
          spacingHorizontal={3}
          spacingTop={1}
          responsiveConfig={{
            phone: { spacingVertical: 2, spacingHorizontal: 0 },
          }}
        >
          <IconButton
            name={isMobile ? 'arrowsVertical' : 'arrowsHorizontal'}
            onPress={flipConverter}
            variant="secondary"
            accessibilityLabel="Flip conversion input fields"
          />
        </Box>
        <HStack
          responsiveConfig={{ tablet: { flexDirection: 'column', gap: 1 } }}
          spacerGap={2}
          width="100%"
          minWidth={0}
        >
          <SearchInputWrapper>
            <TextInput
              id="target"
              value={String(targetValue || 0)}
              onChange={handleTargetValueInputChange}
              min="0"
              type="number"
              borderRadius="roundedFull"
              compact
            />
          </SearchInputWrapper>
          {assetToAsset ? (
            <BaseCurrencySelectionContainer
              setBaseSymbol={handleTargetValueChange}
              baseCurrencyName={targetName || ''}
              baseSymbol={targetSymbol || ''}
              baseId={targetSymbolId || ''}
              alignDropdownLeft={!assetToAsset}
            />
          ) : (
            <TargetCurrencySelectionContainer
              setTargetCurrency={handleTargetValueChange}
              targetCurrency={targetCurrency || 'USD'}
            />
          )}
        </HStack>
      </Box>
      <HStack
        justifyContent="flex-end"
        responsiveConfig={{ phone: { flexDirection: 'column', gap: 1 } }}
      >
        <HStack
          responsiveConfig={{ phone: { flexDirection: 'column', gap: 1 } }}
          spacerGap={3}
        >
          <TextLabel2 as="p" color="foregroundMuted">
            {formatMessage(messages.lastUpdate, {
              lastUpdateTime: formatDate(
                asset?.latestPrice?.timestamp || Date.now(),
                {
                  hour: 'numeric',
                  minute: 'numeric',
                },
              ),
              lastUpdateDate: formatDate(
                asset?.latestPrice?.timestamp || Date.now(),
                {
                  year: 'numeric',
                  month: 'long',
                  day: 'numeric',
                },
              ),
            })}
          </TextLabel2>
          <RefreshContainer isAssetLoading={isRefreshing}>
            <Box alignItems="center" onClick={refreshPrice}>
              <TextLabel1 as="p" color="primary">
                {formatMessage(
                  isRefreshing ? messages.refreshing : messages.refresh,
                )}
              </TextLabel1>
              <Spacer horizontal={1} />
              <RotatableDiv isRotating={isRefreshing}>
                <Icon size="s" color="primary" name="undo" />
              </RotatableDiv>
            </Box>
          </RefreshContainer>
        </HStack>
      </HStack>
    </>
  );
}

const rotate = keyframes`
  from {
    transform: rotate(360deg);
  }

  to {
    transform: rotate(0deg);
  }
`;

const RotatableDiv = styled.div<{ isRotating: boolean }>`
  animation: ${rotate} 0.5s linear infinite;
  animation-play-state: ${props => (props.isRotating ? 'running' : 'paused')};
`;

const RefreshContainer = styled.div<{ isAssetLoading: boolean }>`
  cursor: ${props => (props.isAssetLoading ? 'progress' : 'pointer')};
`;

const SearchInputWrapper = styled.div`
  width: 100%;
  min-width: 0;
  input {
    font-size: var(--title1-font-size);
    padding-left: ${spacing[3]};
    padding-right: ${spacing[3]};
  }
`;

function ConversionTool(props: Props) {
  return (
    <ErrorBoundaryWithGlobalBanner context="conversion-tool">
      <ConversionToolContent {...props} />
    </ErrorBoundaryWithGlobalBanner>
  );
}

export default memo(ConversionTool);

