import React, { memo, useCallback } from 'react';
import { useIntl } from 'react-intl';

import { AssetsSearchStore } from '@cb/shared/components/AssetsList/types';
import { InputIcon } from '@cbhq/cds-web/controls/InputIcon';
import { InputIconButton } from '@cbhq/cds-web/controls/InputIconButton';
import { TextInput } from '@cbhq/cds-web/controls/TextInput';

import { messages } from 'components/AssetSearchDropdownBar/messages';

type Props = {
  searchAssets: AssetsSearchStore;
  showAssetHighlights?: boolean;
  setShowAssetHighlights?: React.Dispatch<React.SetStateAction<boolean>>;
};

function AssetsSearchBar({
  searchAssets,
  showAssetHighlights,
  setShowAssetHighlights,
}: Props) {
  const { formatMessage } = useIntl();
  const { triggerSearch } = searchAssets;
  const handleChangeQuery = useCallback(
    (e: React.SyntheticEvent<HTMLInputElement>) => {
      triggerSearch(e.currentTarget.value);
    },
    [triggerSearch],
  );

  const handleFocusInput = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (e: any) => {
      e.preventDefault();
      e.stopPropagation();
      setShowAssetHighlights?.(false);
    },
    [setShowAssetHighlights],
  );

  const handleBlur = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (e: any) => {
      e.preventDefault();
      e.stopPropagation();
      setShowAssetHighlights?.(true);
    },
    [setShowAssetHighlights],
  );

  const handleCancel = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (e: any) => {
      e.preventDefault();
      e.stopPropagation();
      searchAssets.clearSearch();
      setShowAssetHighlights?.(true);
    },
    [searchAssets, setShowAssetHighlights],
  );

  const clearSearch = useCallback(() => {
    searchAssets.clearSearch();
  }, [searchAssets]);

  return (
    <TextInput
      compact
      value={searchAssets.query}
      placeholder={formatMessage(messages.search)}
      start={
        showAssetHighlights ? (
          <InputIcon name={'search'} testID="search-bar-search-icon-mobile" />
        ) : (
          <InputIconButton
            name={'backArrow'}
            onPress={handleCancel}
            testID="search-bar-back-icon-mobile"
          />
        )
      }
      onFocus={handleFocusInput}
      onBlur={handleBlur}
      autoComplete="off"
      onChange={handleChangeQuery}
      testID="search-bar-mobile"
      borderRadius="roundedFull"
      width="100%"
      type="search"
      end={
        showAssetHighlights || searchAssets.query === '' ? null : (
          <InputIconButton
            name={'close'}
            onPress={clearSearch}
            testID="search-bar-close-icon-mobile"
          />
        )
      }
    />
  );
}

export default memo(AssetsSearchBar);

import { memo } from 'react';
import { defineMessages } from 'react-intl';
import { Route, Switch, useRouteMatch } from 'react-router-dom';

import { useIsMobile } from '@cb/shared/utils';
import { graphql, useFragment } from '@cbhq/data-layer';

import { FooterBannerCTAProps } from 'components/FooterBannerCTA/types';
import { AssetSearchSort, SortOrder } from 'pages/Prices-v2/Prices';

import { useDesktopPage } from '../../hooks/useDesktopPage';
import { useMobilePage } from '../../hooks/useMobilePage';
