import PricesDesktopContent from '../PricesDesktopContent';
import PricesMobileContent from '../PricesMobileContent';
import PricesProvider from '../PricesProvider';
import { PricesContentsFragment$key } from './__generated__/PricesContentsFragment.graphql';

type PagePropsWithHighlights = PageProps & {
  footerBannerCTA?: FooterBannerCTAProps;
  queryRef: PricesContentsFragment$key;
  changeAssetSearchSortAndOrder: (newAssetSearchSort: AssetSearchSort) => void;
  sort?: AssetSearchSort;
  order?: SortOrder;
};

const i18nKey = 'pricesContentsMessages';

export const PRICES_CONTENTS_MESSAGES = defineMessages({
  exploreLegalDisclosure: {
    id: `${i18nKey}.exploreLegalDisclosure`,
    defaultMessage:
      'Certain content has been prepared by third parties not affiliated with Coinbase Inc. or any of its affiliates and Coinbase is not responsible for such content. Coinbase is not liable for any errors or delays in content, or for any actions taken in reliance on any content. Information is provided for informational purposes only and is not investment advice. This is not a recommendation to buy or sell a particular digital asset or to employ a particular investment strategy. Coinbase makes no representation on the accuracy, suitability, or validity of any information provided or for a particular asset. Prices shown are for illustrative purposes only. Actual cryptocurrency prices and associated stats may vary. Data presented may reflect assets traded on Coinbase’s exchange and select other cryptocurrency exchanges.',
    description: `#Component: TextLegal:mainContent
    #CharLimit: 1125
    #Context: Legal disclaimer for explore page`,
  },
  exploreUKFinPromDisclosure: {
    id: `${i18nKey}.exploreUKFinPromDisclosure`,
    defaultMessage:
      'This data was sourced in real-time from Coinbase and other third party market vendors. Real-time data may encounter temporary delays due to system performance or downtime.',
    description: `#Component: TextLegal:mainContent
    #CharLimit: 255
    #Context: UK Legal disclaimer for explore page`,
  },
});

function PricesContents(props: PagePropsWithHighlights) {
  const query = useFragment<PricesContentsFragment$key>(
    graphql`
      fragment PricesContentsFragment on Query {
        ...useMobilePageFragment
        ...useDesktopPageFragment
        ...PricesMobileContentFragment
          @arguments(supportedLocale: $supportedLocale, currency: $currency)
        ...PricesDesktopContentFragment
          @arguments(supportedLocale: $supportedLocale, currency: $currency)
      }
    `,
    props.queryRef,
  );

  const { path } = useRouteMatch();
  const isMobile = useIsMobile();
  const mobilePage = useMobilePage({ ...props, queryRef: query });
  const desktopPage = useDesktopPage({ ...props, queryRef: query });
  const page = isMobile ? mobilePage : desktopPage;

  const Content = isMobile ? PricesMobileContent : PricesDesktopContent;

  const setPage = isMobile
    ? mobilePage?.searchAssets[mobilePage.mobileTab].updatePage
    : desktopPage?.searchAssets.all.updatePage;

  const getPageUrl = isMobile
    ? mobilePage?.searchAssets[mobilePage.mobileTab].getPageUrl
    : desktopPage?.searchAssets.all.getPageUrl;

  return (
    <PricesProvider
      {...props}
      page={page}
      setPage={setPage}
      getPageUrl={getPageUrl}
    >
      <Switch>
        <Route exact path={`${path}/:view(defi)`}>
          <Content footerBannerCTA={props.footerBannerCTA} queryRef={query} />
        </Route>
        <Route path={path}>
          <Content footerBannerCTA={props.footerBannerCTA} queryRef={query} />
        </Route>
      </Switch>
    </PricesProvider>
  );
}

export default memo(PricesContents);

