type Props = {
  showAssetHighlights?: boolean;
  setShowAssetHighlights?: React.Dispatch<React.SetStateAction<boolean>>;
};

function PricesHeadContent({
  showAssetHighlights,
  setShowAssetHighlights,
}: Props) {
  const isMobile = useIsMobile();
  const { formatMessage } = useIntl();
  const killMarketHealth = useKillSwitch('kill_market_health');
  const isUKUser = useIsUKUser();
  const { page } = useContext(PricesContext);
  const { all: searchAssets } = page.searchAssets;
  const percentChange = page.marketHealth.percentChange;

  const change = toNumber(percentChange);
  const isPositive = change >= 0;
  const messageDesktop =
    messages[isPositive ? 'marketDescriptionUp' : 'marketDescriptionDown'];
  const messageMobile =
