import React, { useCallback, useState } from 'react';
import { useIntl } from 'react-intl';

import { useToggler } from '@cbhq/cds-common/hooks/useToggler';
import { InputVariant } from '@cbhq/cds-common/types/InputBaseProps';
import { InputIconButton } from '@cbhq/cds-web/controls/InputIconButton';
import { TextInput } from '@cbhq/cds-web/controls/TextInput';
import { VStack } from '@cbhq/cds-web/layout/VStack';

import usePasswordStrength, {
  PasswordStrength,
} from 'components/SignupForm/SignupFlow/PasswordField/usePasswordStrength';
import PasswordStrengthIndicator from 'components/SignupForm/SignupFlow/PasswordStrengthIndicator';

import reskinSignupMessages from '../utils/reskinMessages';

type InputFieldType = {
  compact?: boolean;
  name: string;
  value: string;
  errors?: Error[];
  isDirty: boolean;
  required: boolean;
  onChange: (value: string) => void;
  onBlur?: React.FocusEventHandler<HTMLInputElement>;
  onFocus?: React.FocusEventHandler<HTMLInputElement>;
  showRequiredInstructions: boolean;
  label: string;
  placeholder: string;
  testID?: string;
  type?: React.HTMLInputTypeAttribute;
};

const DEFAULT_VARIANT = 'foregroundMuted' as InputVariant;
const NEGATIVE_VARIANT = 'negative' as InputVariant;

type blurEventType = {
  setHelperText: React.Dispatch<React.SetStateAction<string>>;
  setVariant: React.Dispatch<React.SetStateAction<InputVariant>>;
  isDirty: boolean;
  errors: Error[] | undefined;
};

type focusEventType = {
  setHelperText: React.Dispatch<React.SetStateAction<string>>;
  setVariant: React.Dispatch<React.SetStateAction<InputVariant>>;
};

const updateError = ({
  setHelperText,
  setVariant,
  isDirty,
  errors,
}: blurEventType) => {
  if (isDirty && errors) {
    setHelperText(errors[0].message);
    setVariant(NEGATIVE_VARIANT);
  } else if (isDirty) {
    setHelperText('');
    setVariant(DEFAULT_VARIANT);
  }
};

const clearError = ({ setHelperText, setVariant }: focusEventType) => {
  setHelperText('');
  setVariant(DEFAULT_VARIANT);
};

const getFormLabel = (labelText: string, required: boolean) => {
  return labelText + (required ? '*' : '');
};

export function TextInputField({
  compact,
  name,
  value,
  errors,
  isDirty,
  required,
  onChange,
  onBlur,
  onFocus,
  label,
  placeholder,
  showRequiredInstructions,
  testID,
  type,
}: InputFieldType) {
  const [variant, setVariant] = useState<InputVariant>(DEFAULT_VARIANT);
  const [helperText, setHelperText] = useState<string>('');

  const handleOnBlur: React.FocusEventHandler<HTMLInputElement> = useCallback(
    e => {
      updateError({ setHelperText, setVariant, isDirty, errors });
      onBlur?.(e);
    },
    [errors, isDirty, onBlur],
  );

  const handleOnFocus: React.FocusEventHandler<HTMLInputElement> = useCallback(
    e => {
      clearError({ setHelperText, setVariant });
      onFocus?.(e);
    },
    [onFocus],
  );

  const handleOnChange: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(e => onChange(e.target.value), [onChange]);

  return (
    <TextInput
      compact={compact}
      name={name}
      label={getFormLabel(label, required && showRequiredInstructions)}
      placeholder={placeholder}
      required={required}
      aria-required
      value={value}
      helperText={helperText}
      variant={variant}
      onBlur={handleOnBlur}
      onFocus={handleOnFocus}
      onChange={handleOnChange}
      testID={testID}
      type={type}
    />
  );
}

export type PasswordInputFieldProps = Omit<
  InputFieldType,
  'onChange' | 'showRequiredInstructions'
> & {
  onChange: (value: string, strength: PasswordStrength) => void;
  testID?: string;
};

export function PasswordInputField({
  compact,
  name,
  value,
  errors,
  isDirty,
  required,
  label,
  placeholder,
  onChange,
  testID,
}: PasswordInputFieldProps) {
  const { formatMessage } = useIntl();

  const [isVisible, { toggle: toggleIsVisible }] = useToggler();
  const [variant, setVariant] = useState<InputVariant>(DEFAULT_VARIANT);
  const [helperText, setHelperText] = useState<string>('');

  const [showProgressBar, setShowProgressBar] = useState<boolean>(false);

  const { getPasswordStrength } = usePasswordStrength();
  const [strength, setStrength] = useState<PasswordStrength>('weak');

  const onChangePassword = useCallback(
    (updatedPassword: string) => {
      const newStrength = getPasswordStrength(updatedPassword);
      setShowProgressBar(!!updatedPassword);
      setStrength(newStrength);
      onChange(updatedPassword, newStrength);
    },
    [onChange, setStrength, getPasswordStrength],
  );

  const updatePasswordError = useCallback(() => {
    updateError({
      setHelperText,
      setVariant,
      isDirty,
      errors,
    });
    errors ? setShowProgressBar(false) : setShowProgressBar(true);
  }, [errors, isDirty]);

  const handleOnBlur = useCallback(
    () => updatePasswordError(),
    [updatePasswordError],
  );

  const handleOnFocus = useCallback(
    () => clearError({ setHelperText, setVariant }),
    [],
  );

  const handleOnChange: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(e => onChangePassword(e.target.value), [onChangePassword]);

  return (
    <VStack width="100%">
      <TextInput
        aria-describedby="password-strength-indicator"
        compact={compact}
        name={name}
        label={getFormLabel(label, required)}
        placeholder={placeholder}
        type={isVisible ? 'text' : 'password'}
        end={
          <InputIconButton
            name={isVisible ? 'visibleActive' : 'visibleInactive'}
            accessibilityLabel={
              isVisible
                ? formatMessage(reskinSignupMessages.hideAccessibilityLabel)
                : formatMessage(reskinSignupMessages.showAccessibilityLabel)
            }
            onPress={toggleIsVisible}
            variant="foregroundMuted"
            transparent
          />
        }
        required={required}
        aria-required
        value={value}
        helperText={helperText}
        variant={variant}
        onBlur={handleOnBlur}
        onFocus={handleOnFocus}
        onChange={handleOnChange}
        testID={testID}
      />
      {showProgressBar ? (
        <PasswordStrengthIndicator
          descriptionId="password-strength-indicator"
          strength={strength}
        />
      ) : null}
    </VStack>
  );
}

/**
 * Password input box to show error on change and renders password
 * strength indicator
 */
export function PasswordWithShowErrorOnChange({
  isDirty,
  label,
  placeholder,
  onChange,
  errors = [],
  value = '',
  testID,
  ...props
}: PasswordInputFieldProps) {
  const { formatMessage } = useIntl();

  const [isVisible, { toggle: toggleIsVisible }] = useToggler();
  const { getPasswordStrength } = usePasswordStrength();
  const [strength, setStrength] = useState<PasswordStrength>('weak');
  const [showStrengthIndicator, setShowStrengthIndicator] = useState(false);

  const onChangePassword = useCallback(
    (updatedPassword: string) => {
      const newStrength = getPasswordStrength(updatedPassword);
      setShowStrengthIndicator(!!updatedPassword);
      setStrength(newStrength);
      onChange(updatedPassword, newStrength);
    },
    [onChange, setStrength, getPasswordStrength],
  );

  const errorMsg = errors[0]?.message;

  const handleOnChange: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(
      event => onChangePassword(event.target.value),
      [onChangePassword],
    );

  return (
    <VStack>
      <TextInput
        {...props}
        aria-describedby="password-strength-indicator"
        label={label}
        placeholder={placeholder}
        onChange={handleOnChange}
        helperText={isDirty && errorMsg ? errorMsg : undefined}
        variant={isDirty && errorMsg ? 'negative' : undefined}
        value={value}
        type={isVisible ? 'text' : 'password'}
        end={
          <InputIconButton
            name={isVisible ? 'visibleActive' : 'visibleInactive'}
            accessibilityLabel={
              isVisible
                ? formatMessage(reskinSignupMessages.hideAccessibilityLabel)
                : formatMessage(reskinSignupMessages.showAccessibilityLabel)
            }
            onPress={toggleIsVisible}
            variant="foregroundMuted"
            testID="passwordWithShowError_eye"
            transparent
          />
        }
        testID={testID}
      />
      {showStrengthIndicator && (
        <VStack spacingTop={1} width="100%" flexGrow={1}>
          <PasswordStrengthIndicator
            descriptionId="password-strength-indicator"
            strength={strength}
          />
        </VStack>
      )}
    </VStack>
  );
}

