    setIsSubmitting(true);

    try {
      const response = await fetchTimeout(
        `${envLoginServiceUrl()}/v3/coinbase.global_onboarding_service.public.signup.SignupService/SetupUser`,
        {
          body: JSON.stringify({
            country_code: locale.country,
            locale: locale.localeCode,
            first_name: firstName,
            last_name: lastName,
            email,
          }),
          credentials: 'include',
          headers: {
            ...getAnalyticsHeaders(),
            'Content-Type': 'application/json',
          },
          method: 'POST',
          mode: 'cors',
          redirect: 'follow',
          referrerPolicy: 'strict-origin-when-cross-origin',
          timeout: 10000,
        },
      ).then(res => res.json());

      if (response.userId) {
        // Signin (SessionsController#new) will set appropriate state and figure out where to redirect the user
        window.location.assign('/signin');
        return;
      }

      throw new Error('Setup user failed');
    } catch (error) {
      toast.show(formatMessage(messages.submitError), {
        variant: 'negative',
      });
      logEvent('user_setup_submit_failed', {
        componentType: ComponentType.button,
        action: ActionType.click,
        content: error,
      });
      notifyError(error, {
        owner: 'onboarding',
        context: 'signup_oidc',
        action: 'setup_user_failed',
      });
    } finally {
      setIsSubmitting(false);
    }
  }, [
    locale.country,
    locale.localeCode,
    firstName,
    lastName,
    email,
    toast,
    formatMessage,
  ]);

  const checkIfUserExists = useCallback(async () => {
    try {
      const response = await fetchTimeout(
        `${envLoginServiceUrl()}/v3/coinbase.global_onboarding_service.public.signup.SignupService/CompleteSignupWithOIDC`,
        {
          body: JSON.stringify({
            country_code: locale.country,
            locale: locale.localeCode,
          }),
          credentials: 'include',
          headers: {
            ...getAnalyticsHeaders(),
            'Content-Type': 'application/json',
          },
          method: 'POST',
          mode: 'cors',
          redirect: 'follow',
          referrerPolicy: 'strict-origin-when-cross-origin',
          timeout: 10000,
        },
      ).then(res => res.json());

      if (response.userId) {
        logEvent('user_setup_user_exists', {
          componentType: ComponentType.page,
          action: ActionType.render,
        });
        // Signin (SessionsController#new) will set appropriate state and figure out where to redirect the user
        window.location.assign('/signin');
        return;
      }

      throw new Error('User doesnt exist');
    } catch (error) {
      // Log and Supress error as this is expected if user doesn't exist
      logEvent('user_setup_user_doesnt_exist', {
        componentType: ComponentType.page,
        action: ActionType.render,
        context: error?.message,
      });
    }
  }, [locale]);

  useEffect(() => {
    checkIfUserExists();
    logEvent('user_setup_viewed', {
      componentType: ComponentType.page,
      action: ActionType.render,
    });
  }, []);

  const isSubmitable = useMemo(
    () => email && firstName && lastName && emailValidator(email),
    [email, lastName, firstName],
  );

  const checkMisspellingEmail = useCallback(() => {
    if (!isMisspellingEmail(email)) return;

    toast.show(formatMessage(messages.emailTypoValidationMessage), {
      variant: 'negative',
    });

    logEvent('misspelling_email_banner_viewed', {
      action: ActionType.render,
      componentType: ComponentType.banner,
    });
  }, [email, formatMessage, toast]);

  const handleSignout = useCallback(() => {
    // Delete the session cookies on signout
    fetch(`${envLoginServiceUrl()}/api/v1/delete`, {
      method: 'post',
      credentials: 'include',
      mode: 'cors',
      headers: {
        Accept: 'application/json',
        'Content-Type': 'application/json',
      },
    })
      .catch(error => {
        logEvent('sign_up_oidc_delete_session_error', {
          action: ActionType.unknown,
          componentType: ComponentType.content_script,
        });
        notifyError(error, {
          owner: 'onboarding',
          context: 'signup_oidc',
          action: 'signup_oauth_delete_session_failed',
        });
      })
      .finally(() => {
        window.location.assign('/signout');
      });
  }, []);

  const handleOnChange: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(event => setFirstName(event.target.value), []);

  const handleOnChange1: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(event => setLastName(event.target.value), []);

  const handleOnChange2: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(event => setEmail(event.target.value), []);

  const handleOnFocus = useCallback(() => toast.hide(), [toast]);

  return (
    <ErrorBoundary owner="onboarding" context="user_setup">
      <VStack minHeight="100vh">
        <NavBar />
        <Spacer vertical={10} />
        <Box justifyContent="center" responsiveConfig={responsiveConfig}>
          <HStack
            maxWidth={1133}
            justifyContent="center"
            alignSelf="center"
            width="100%"
            spacerGap={5}
          >
            {showBackButton && <BackButton />}
            <VStack
              maxWidth={isUKUser && isDesktop ? 600 : '100%'}
              alignSelf="flex-start"
              justifyContent="center"
              spacingEnd={isUKUser && showBackButton ? 10 : undefined}
            >
              <Box maxWidth={448}>
                <TextDisplay3 as="h1" spacingBottom={2}>
                  <DatadogSyntheticTag tagName="marketing_setup_user">
                    {formatMessage(messages.completeYourSignUp)}
                  </DatadogSyntheticTag>
                </TextDisplay3>
              </Box>
              {!isUKUser && !isDesktop && <MobileMarketingSection />}
              <TextBody
                as="p"
                spacingBottom={2}
                spacingTop={1}
                color="foregroundMuted"
              >
                {formatMessage(messages.legalNameNote)}
              </TextBody>
              <TextLabel2 as="label" spacingBottom={2} spacingTop={1}>
                {formatMessage(messages.formInstructions)}
              </TextLabel2>
              <VStack spacerGap={2}>
                <Group
                  flexDirection={isDesktop ? 'row' : 'column'}
                  gap={isDesktop ? 0 : 2}
                >
                  <Box
                    width={isDesktop ? '50%' : '100%'}
                    spacingEnd={isDesktop ? 1 : 0}
                  >
                    <TextInput
                      label={`${formatMessage(messages.legalFirstNameField)}*`}
                      value={firstName}
                      aria-required="true"
                      onChange={handleOnChange}
                    />
                  </Box>
                  <Box
                    width={isDesktop ? '50%' : '100%'}
                    spacingEnd={isDesktop ? 1 : 0}
                  >
                    <TextInput
                      label={`${formatMessage(messages.legalLastNameField)}*`}
                      value={lastName}
                      aria-required="true"
                      onChange={handleOnChange1}
                    />
                  </Box>
                </Group>
                <TextInput
                  label={`${formatMessage(messages.emailField)}*`}
                  aria-required="true"
                  value={email}
                  variant={
                    email && !emailValidator(email) ? 'negative' : undefined
                  }
                  helperText={
                    email && !emailValidator(email)
                      ? formatMessage(messages.invalidEmailError)
                      : undefined
                  }
                  onChange={handleOnChange2}
                  onFocus={handleOnFocus}
                  onBlur={checkMisspellingEmail}
                />
                <HStack spacingTop={2}>
                  <Button
                    disabled={isSubmitting || !isSubmitable}
                    onPress={handleSubmit}
                    block
                    testID="user-setup-submit-button"
                  >
                    {formatMessage(messages.submitButton)}
                  </Button>
                </HStack>
              </VStack>
              <HStack spacingVertical={2}>
                <Button block transparent onPress={handleSignout}>
                  {formatMessage(messages.signout)}
                </Button>
              </HStack>
            </VStack>
            {!isUKUser && isDesktop && <WebMarketingSection />}
          </HStack>
        </Box>
        <MetaTags
          title={formatMessage(messages.completeYourSignUp)}
          includeHrefLangs
        />
      </VStack>
    </ErrorBoundary>
  );
}

