const i18nKey = 'AssetPageProfitResults';

const messages = defineMessages({
  restart: {
    id: `${i18nKey}.restart`,
    description: `#Component: Button
    #CharLimit: 40
    #Context: restart and try new values`,
    defaultMessage: 'Restart',
  },
  tweet: {
    id: `${i18nKey}.tweet`,
    description: `#Component: Button
    #CharLimit: 35
    #Context: Click this button to share results in a pop up tweet`,
    defaultMessage: 'Tweet',
  },
  buttonGroupLabel: {
    id: `${i18nKey}.buttonGroupLabel`,
    description: `#Component: ButtonGroup:accessibilityLabel
    #CharLimit: 145
    #Context: Explanation for button accessibility label`,
    defaultMessage:
      'On the left is the restart button, on the right is the share button to share on Twitter.',
  },
  // 2023-10-05: TODO please fix, see go/i18n-linter-messages
  // eslint-disable-next-line @cbhq/i18n-enhanced-description
  tweetShareSentence: {
    id: `${i18nKey}.tweetShareSentence`,
    description:
      'Sentence to share on twitter detailing how much gains/loss you would have recieved.',
    defaultMessage:
      'A {inputPrice} investment of {assetSymbol} in {yearSelected} is now worth {currentCost}',
  },
});

function ProfitResults({
  profitType,
  currentCost,
  inputPrice,
  colorSelected,
  setProfitType,
  showState,
  setShowState,
  setFormState,
  yearSelected,
  assetSymbol,
}: Props) {
  const [tokenSentence, setTokenSentence] = useState<string>('');
  const [sentence, setSentence] = useState<string>('');
  const { formatMessage, formatNumber } = useIntl();
  const isMobile = useScreenMatch('phone');
  const { pageCurrency } = useAssetPageCurrency();

  const handleRetryClick = useCallback(() => {
    logEvent('token_return_tool_restart_button', {
      action: ActionType.click,
      componentType: ComponentType.button,
    });
    setShowState({
      ...showState,
      displayTokenReturnTool: true,
      displayProfitResults: false,
    });
    setFormState({
      pseudoProfit: 0,
      inputPrice: '10',
    });
    setProfitType(null);
  }, [setShowState, showState, setFormState, setProfitType]);

  const openTwitterUrl = useCallback((twitterUrl: string) => {
    const width = 575;
    const height = 400;
    const divisor = 2;
    const left = (window.outerWidth - 575) / divisor;
    const top = (window.outerHeight - 400) / divisor;
    window.open(
      twitterUrl,
      '_blank',
      `width=${width},height=${height},top=${top},left=${left}`,
    );
    window.opener = null; // Keep opener = null for security when window is using target="_blank"
  }, []);

  const handleTweetShare = useCallback(() => {
    logEvent('token_return_tool_tweet_button', {
      action: ActionType.click,
      componentType: ComponentType.button,
    });

    const uriString = formatMessage(messages.tweetShareSentence, {
      inputPrice: formatNumber(inputPrice, {
        style: 'currency',
        currency: pageCurrency,
        notation: 'compact',
        minimumFractionDigits: 2,
      }),
      currentCost: formatNumber(
        isFinite(currentCost) ? currentCost : 1000000000000000.0,
        {
          style: 'currency',
          currency: pageCurrency,
          notation: 'compact',
          minimumFractionDigits: 2,
        },
      ),
      yearSelected,
      assetSymbol,
    });

    const uri = encodeURIComponent(
      `${uriString} \n @coinbase \n ${consumerUrl}`,
    );

    openTwitterUrl(`https://twitter.com/intent/tweet?text=${uri}`);
  }, [
    assetSymbol,
    pageCurrency,
    formatMessage,
    formatNumber,
    inputPrice,
    openTwitterUrl,
    currentCost,
    yearSelected,
  ]);

  return (
    <>
      <VStack
        minHeight="inherit"
        height="100%"
        maxWidth="100%"
        display="flex"
        alignItems="stretch"
        justifyContent="flex-start"
        spacingTop={0.5}
      >
        <ProfitResultsProgrammaticContent
          sentence={sentence}
          colorSelected={colorSelected}
          setSentence={setSentence}
          setTokenSentence={setTokenSentence}
          profitType={profitType}
          inputPrice={inputPrice}
          currentCost={currentCost}
          tokenSentence={tokenSentence}
        />
        <HStack
          spacingTop={1}
          alignContent="flex-end"
          display="inline-block"
          spacingBottom={2}
        >
          {isMobile ? (
            <ButtonGroup
              accessibilityLabel={formatMessage(messages.buttonGroupLabel)}
            >
              <Button
                block={false}
                variant="secondary"
                compact
                onPress={handleRetryClick}
              >
                <Icon name="undo" size="m" color="foregroundMuted" />
              </Button>
              <Button
                variant="secondary"
                block={false}
                compact
                onPress={handleTweetShare}
              >
                <Box justifyContent="center">
                  <Twitter />
                </Box>
              </Button>
            </ButtonGroup>
          ) : (
            <ButtonGroup
              accessibilityLabel={formatMessage(messages.buttonGroupLabel)}
            >
              <Button
                block={false}
                variant="secondary"
                compact
                endIcon="undo"
                onPress={handleRetryClick}
              >
                {formatMessage(messages.restart)}
              </Button>
              <Button
                variant="secondary"
                block={false}
                compact
                onPress={handleTweetShare}
              >
                {formatMessage(messages.tweet)}
              </Button>
            </ButtonGroup>
          )}
        </HStack>
      </VStack>
    </>
  );
}

export default memo(ProfitResults);

