export type InflationCalculatorProps = {
  currency: string;
  setPageCurrency: Dispatch<SetStateAction<string>>;
  isLoading: boolean;
  assetRef: InflationCalculatorFragment$key | null | undefined;
};

export function InflationCalculator({
  currency,
  setPageCurrency,
  isLoading,
  assetRef,
}: InflationCalculatorProps) {
  const { formatMessage, formatNumber, formatDate } = useIntl();
  const color = usePaletteValueToRgbaString('green0');
  const [monthlySavingsAmount, setSavingsAmount] = useState(500);

  const formatStartDate = useCallback(
    (date: string) => {
      return formatDate(date, {
        year: 'numeric',
        month: 'long',
        day: 'numeric',
      });
    },
    [formatDate],
  );
  const [startDate, setStartDate] = useState(
    formatStartDate(INFLATION_CALCULATOR_DATES[0]),
  );

  const handleStartDateChange = useCallback(
    (newValue: string) => {
      setStartDate(formatStartDate(newValue));
    },
    [formatStartDate],
  );

  const handleSavingsAmountChange = useCallback(
    (e: ChangeEvent<HTMLInputElement>) => {
      const update = parseFloat(e.target.value);
      if (update >= 0) {
        setSavingsAmount(update);
      }

      if (!update) {
        setSavingsAmount(0);
      }
    },
    [],
  );

  const data = useFragment<InflationCalculatorFragment$key>(
    graphql`
      fragment InflationCalculatorFragment on Asset {
        all: priceDataForAllV2(quoteCurrency: $currency) {
          quotes {
            price
            timestamp
          }
        }
        latestQuote: latestQuoteV3(quoteCurrency: $currency) {
          price
        }
      }
    `,
    assetRef ?? null,
  );

  const inflationAdjustedSavings = useMemo(() => {
    const quotes = data?.all?.quotes;
    const latestQuote = data?.latestQuote;

    const inflationAdjustedSavings = quotes
      ? getInflationAdjustedSavings({
          quotes,
          latestQuotePrice: latestQuote?.price ? latestQuote.price : '',
          monthlySavingsAmount,
          startDate,
        })
      : null;

    return inflationAdjustedSavings;
  }, [data, monthlySavingsAmount, startDate]);

  const formattedInflationSavingsAmount = useMemo(() => {
    if (isLoading || !inflationAdjustedSavings) {
      return '...';
    }
    return formatNumber(inflationAdjustedSavings, {
      minimumSignificantDigits: 1,
      maximumSignificantDigits: 3,
      notation: 'compact',
      compactDisplay: 'short',
    });
  }, [formatNumber, inflationAdjustedSavings, isLoading]);

  const getTranslatedFiatCurrency = useCallback(
    (currencyCode: string) => {
      /** @ts-expect-error This will produce a message or undefined. */
      return formatMessage(TranslatedFiats[currencyCode]);
    },
    [formatMessage],
  );

  return (
    <HStack
      justifyContent="space-between"
      spacingTop={8}
      testID="inflation-calculator"
      flexWrap="wrap"
      responsiveConfig={containerResponsiveConfig}
      gap={2}
      spacing={2}
    >
      <SquareContainer color={color} bordered>
        <HStack>
          <Box overflow="clip" maxWidth={240}>
            <TextDisplay1 as="p">
              {formatMessage(messages.inflationAdjustedSavings, {
                inflationAdjustedSavings: formattedInflationSavingsAmount,
              })}
              &nbsp;
            </TextDisplay1>
          </Box>
          <TextDisplay1 as="p">
            {formatMessage(messages.currency, {
              currency,
            })}
          </TextDisplay1>
        </HStack>
        <HStack>
          <TextBody as="p" color="positive">
            {formatMessage(messages.greenText)}
          </TextBody>
          <TextBody as="p" color="foregroundMuted">
            &nbsp;{formatMessage(messages.grayText)}
          </TextBody>
        </HStack>
      </SquareContainer>
      <VStack width={SQUARE_DIMENSIONS} spacerGap={2}>
        <TextTitle2 as="p">
          {formatMessage(messages.calculatorTitle)}
        </TextTitle2>
        <TextLabel1 as="p">{formatMessage(messages.selectCurrency)}</TextLabel1>
        <Select
          placeholder={formatMessage(messages.selectCurrency)}
          value={currency}
          onChange={setPageCurrency}
        >
          {WHITELIST_CURRENCIES.map(option => (
            <SelectOption
              value={option}
              key={option}
              title={option}
              description={getTranslatedFiatCurrency(option)}
            />
          ))}
        </Select>
        <TextInput
          type="number"
          label={formatMessage(messages.monthlySavingAmount)}
          placeholder={formatMessage(messages.monthlySavingAmount)}
          value={monthlySavingsAmount || ''}
          onChange={handleSavingsAmountChange}
          suffix={currency}
        />
        <TextLabel1 as="p">
          {formatMessage(messages.selectStartDate)}
        </TextLabel1>
        <Select
          value={startDate}
          placeholder={formatMessage(messages.selectStartDate)}
          onChange={handleStartDateChange}
        >
          {INFLATION_CALCULATOR_DATES.map(option => (
            <SelectOption
              value={option}
              key={option}
              title={formatStartDate(option)}
            />
          ))}
        </Select>
      </VStack>
    </HStack>
  );
}

