type Props = {
  client: ApiClient;
  onSuccess: () => void;
  onError: (e: Error) => void;
  track: AmplitudeFunction;
};

const i18nKey = 'AttestationsForm';

function AttestationsForm({ client, onSuccess, onError, track }: Props) {
  const analytics = useOnce(() => createAnalytics(track, 'attestations'));

  const { checkboxes, setCheckboxes, submitAttestations, missingFields } =
    useAttestationsFormState({
      client,
      onSuccess,
      onError,
      analytics,
    });

  useEffect(() => {
    analytics.trackView({});
  }, []);

  const handleChange = useCallback(
    (selected: Record<string, boolean>) => {
      setCheckboxes(selected);
    },
    [setCheckboxes],
  );

  const handleSubmit = useCallback(() => {
    analytics.trackTap({ context: 'submit' });
    submitAttestations();
