const messages = defineMessages({
  cityOfBirthPlaceholder: {
    id: 'Birthplace.cityOfBirthPlaceholder',
    defaultMessage: 'City',
    description: `
    #CharLimit: 50
    #Component:Label
    #Context:Placeholder for city of birth field`,
  },
  requiredValidationMessage: {
    id: 'Birthplace.requiredValidationMessage',
    defaultMessage: 'City of birth is required.',
    description: `
    #CharLimit: 50
    #Component:ErrorLabel
    #Context:Validation error for a missing city of birth`,
  },
});

const findCountry = (countryCode: string): Country => {
  const country = countries.find(c => c.code === countryCode);

  if (!country) {
    throw new Error(`Unknown country code: ${countryCode}`);
  }

  return country;
};

const FormGroup = styled.div`
  width: 100%;
`;

type Props = {
  onSuccess: () => void;
  loading?: boolean;
  onError?: (error: Error) => void;
};

export function Birthplace({ onSuccess, loading = false, onError }: Props) {
  const { formatMessage } = useIntl();
  const {
    client,
    addApiError,
    analytics: { logButtonClick },
    user: { countryCode },
  } = useOnboardingContext();
  const [cityOfBirth, setCityOfBirth] = useState('');
  const [countryOfBirth, setCountryOfBirth] = useState(
    findCountry(countryCode),
  );
  const [isSubmitting, setIsSubmitting] = useState(false);

  const onChange = useCallback((value: string | boolean) => {
    if (typeof value !== 'string') return;
    setCityOfBirth(value);
  }, []);

  const handleSelectCountry = useCallback(
    (countryCode: string) => {
      setCountryOfBirth(findCountry(countryCode));
    },
    [setCountryOfBirth],
  );

  const handleSubmit = useCallback(async () => {
    logButtonClick('birthplace_volume_tapped_submit');
    setIsSubmitting(true);

    try {
      await client.put('/v2/user/basic-diligence', {
        city_of_birth: cityOfBirth,
        country_of_birth: countryOfBirth.code,
      });

      onSuccess();
    } catch (err) {
      addApiError(err);
      errorLoggers.birthplace(err);
      onError?.(err);
    } finally {
      setIsSubmitting(false);
    }
  }, [
    addApiError,
    cityOfBirth,
    countryOfBirth,
    client,
    onSuccess,
    logButtonClick,
    onError,
  ]);

  useLogPageViewOnMount('birthplace_volume_viewed');

  return (
    <FormGroup>
      {
        <>
          <Labeled
            label={
              <FormattedMessage
                id="Birthplace.cityOfBirthLabel"
                defaultMessage="City of birth"
                description="Label for city of birth field"
              />
            }
          >
            <ValidatedInput
              name="cityOfBirth"
              component="input"
              showSuccess={false}
              autoFocus
              validateOnBlur
              value={cityOfBirth}
              onChange={onChange}
              placeholder={formatMessage(messages.cityOfBirthPlaceholder)}
              validators={[
                [required, formatMessage(messages.requiredValidationMessage)],
              ]}
              autoCapitalize="words"
            />
          </Labeled>
          <Labeled
            label={
              <FormattedMessage
                id="Birthplace.countryOfBirthLabel"
                defaultMessage="Country of birth"
                description="Label for country of birth field"
              />
            }
          >
            <CountrySelect
              activeCountry={countryOfBirth}
              onSelectCountry={handleSelectCountry}
            />
          </Labeled>
        </>
      }

      <Spacer as="div" vertical={2} />
      <Button
        disabled={isSubmitting || !cityOfBirth || !countryOfBirth || loading}
        loading={isSubmitting || loading}
        onPress={handleSubmit}
        block
      >
        <FormattedMessage
          id="Birthplace.submitButton"
          defaultMessage="Submit"
          description="Button to submit the user's answer"
        />
      </Button>
    </FormGroup>
  );
}

