type Props = {
  onSuccess: () => void;
  loading?: boolean;
  onError?: (error: Error) => void;
};

function ConfirmDetails({ onSuccess, loading = false, onError }: Props) {
  const { formatMessage } = useIntl();
  const {
    client,
    addApiError,
    analytics: { logButtonClick },
  } = useOnboardingContext();
  const [showAddressPage, setShowAddressPage] = useState<boolean>(false);
  const [userDetailsState, setUserDetailsState] = useState<UserDetails | null>(
    null,
  );
  const { fetchVerifiedPOA } = usePOA({
    client,
  });

  const fetchDetails = async () => {
    try {
      const userDetailsResponse = await client.get(
        '/v3/coinbase.workflow_engine.user_details_confirmation.UserDetailsConfirmationService/GetUserDetails',
        undefined,
        {
          'Content-Type': 'application/json',
        },
      );

      if (!userDetailsResponse) {
        errorLoggers.missingData('user_confirmation_details');
      }
      invariant(userDetailsResponse, 'Invalid data from the API');

      const userDetails: UserDetails = { ...userDetailsResponse, poaId: '' };
      if (!userDetails.address) {
        try {
          const verifiedAddress = await fetchVerifiedPOA();

          if (!verifiedAddress) {
            errorLoggers.missingData('poa_confirm_user_details');
          }

          invariant(verifiedAddress, 'No verified addresses on record');

          const { id, address } = verifiedAddress;
          userDetails.address = {
            line1: address.line1 ?? '',
            line2: address.line2 ?? '',
            city: address.city ?? '',
            postalCode: address.postalCode ?? '',
          };
          userDetails.poaId = id;
        } catch (e) {
          errorLoggers.poaAddress(e);
          // Rethrow error
          throw e;
        }
      }
      setUserDetailsState(userDetails);
    } catch (e) {
      errorLoggers.userDetailsFetch(e);
      addApiError(e);
    }
  };

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleSubmit = async () => {
    const { idvId: idv_id, poaId: poa_id } = userDetailsState as UserDetails;
    const submitUserDetailsWithRetry = withRetry({
      shouldRetry: (e, depth) =>
        isApiClentError(e) &&
        e.apiClientErrorId === 'generic-error' &&
        depth < 3,
    })(() =>
      client.post(
        '/v3/coinbase.workflow_engine.user_details_confirmation.UserDetailsConfirmationService/ConfirmUserDetails',
        { idv_id, poa_id },
      ),
    );

    try {
      await submitUserDetailsWithRetry();
    } catch (e) {
      errorLoggers.userDetailsSubmit(e);
      addApiError(e);
      onError?.(e);
    }
    onSuccess();
  };

  useLogPageViewOnMount('confirm_details_screen_viewed');

  useEffect(() => {
    fetchDetails();
  }, []);

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleContinue = () => {
    logButtonClick('confirm_details_continue_clicked');
    setShowAddressPage(true);
  };

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleSignOut = () => {
    logButtonClick('confirm_details_cancel_clicked', {});
    signOut();
  };

  if (!userDetailsState) {
    return <Spinner />;
  }

  const {
    legalName,
    dateOfBirth: { day, month, year },
    idNumber,
  } = userDetailsState;

  return (
    <>
      {showAddressPage ? (
        <ConfirmAddress
          loading={loading}
          userDetails={userDetailsState}
          handleSubmit={handleSubmit}
          handleSignOut={handleSignOut}
        />
      ) : (
        <VStack width="100%">
          <TextBody as="p" color="foregroundMuted">
            {formatMessage(messages.regulationsInfo, {
              link: (
                <Link
                  to="https://www.coinbase.com/legal/licenses"
                  underline
                  openInNewWindow
                >
                  {formatMessage(messages.regulationsLink)}
                </Link>
              ),
            })}
          </TextBody>
          <VStack spacerGap={2} spacingTop={3}>
            <TextInput
              disabled
              value={legalName}
              label={formatMessage(messages.legalName)}
            />
            <TextInput
              disabled
              value={`${day}/${month}/${year}`}
              label={formatMessage(commonMessages.dob)}
              helperText={formatMessage(messages.dobFormat)}
            />
            <TextInput
              disabled
              value={idNumber}
              label={formatMessage(messages.idNumber)}
            />
          </VStack>
          <Spacer />
          <VStack spacingVertical={4}>
            <Card>
              <HStack alignItems="center" spacing={2} spacingBottom={1}>
                <Icon name="lock" size="s" spacingEnd={2} />
                <TextHeadline as="p">
                  {formatMessage(messages.changeInfoTitle)}
                </TextHeadline>
              </HStack>
              <TextLabel2
                as="p"
                color="foregroundMuted"
                spacing={2}
                spacingTop={0}
              >
                {formatMessage(messages.changeInfoBody)}
              </TextLabel2>
            </Card>
          </VStack>
          <ButtonGroup direction="vertical">
            <Button onPress={handleContinue}>
              {formatMessage(commonMessages.continue)}
            </Button>
            <Button onPress={handleSignOut} transparent>
              {formatMessage(messages.cancelSetupButton)}
            </Button>
          </ButtonGroup>
        </VStack>
      )}
    </>
  );
}

