function DecoupledEDPForm({
  store,
  showExplanation,
  showTitle = false,
}: DecoupledEDPFormProps) {
  const {
    analytics: { logMeasurement, logButtonClick },
    user,
    verificationMetadata,
  } = useOnboardingContext();
  const isMobile = useIsMobile();

  const { formatMessage } = useIntl();

  const isZipCodeFixExperiment = useIsTreatment('apr_2024_zip_fix_www');
  const isEUHouseNumberEligible = useMemo(
    () =>
      countryCodeEligibleForEUHouseNumberField.includes(
        user.countryCode.toUpperCase(),
      ),
    [user.countryCode],
  );

  const countryCodesEligibleForPostalCodeValidation =
    getCountryCodesEligibleForPostalCodeValidation();

  const shouldUseFullNameField = useFullNameField({
    countryCode: user.countryCode,
  });

  useLogPageViewOnMount('verify_identity_viewed', {
    context: 'decoupled_edp_form',
  });

  const {
    onFormSubmit,
    valid,
    isLoading,
    isFetchingInitial,
    isFetchingAttempts,
    markValid,
    markInvalid,
    error,
    auIdChoice,
    onFormChange,
    lifetimeMaxReached,
    attemptsRemaining,
    countrySpecificFields,
    requiresState,
    errorMessage,
    countrySpecificStateField,
    prefillChallenge,
    disableKYCRefreshSSNDOBEdit,
    hasPreviousEdpDob,
    disableKYCRefreshEditSSN,
    formData: {
      firstName,
      lastName,
      address1,
      address2,
      city,
      state,
      zip: postalCode,
      month,
      day,
      year,
      ssn,
      addressComponents,
      country_select,
      australiaDriverLicenseNumber,
      australiaDriverLicenseState,
      australiaDriverLicenseCardNumber,
      australiaMedicareNumber,
      australiaMedicareReference,
      australiaMedicareDateOfExpiry,
      australiaMedicareColor,
      australiaPassportNumber,
      australiaCreditBureauVerifyAllowed,
      australiaCreditBureauElectoralRollVerifyAllowed,
      gender,
    },
  } = store;
  const showFCAContent =
    verificationMetadata?.targets?.includes('fca_enhanced_cdd') ?? false;
  const showAuContent = user.countryCode === 'AU';
  const isCanadianUser = user.countryCode === 'CA';

  const isEDPFieldPrefillEnabled = useCbelEdpPrefill();

  const variant = showAuContent
    ? 'au'
    : user.countryCode === 'DE'
    ? 'de'
    : user.isInEurope
    ? 'eu'
    : state === 'NY'
    ? 'ny'
    : null;

  const isPostalCodeValidationEligible = useMemo(
    () =>
      countryCodesEligibleForPostalCodeValidation.includes(
        isZipCodeFixExperiment
          ? country_select?.toUpperCase() || user.countryCode.toUpperCase()
          : user.countryCode.toUpperCase(),
      ),
    [
      countryCodesEligibleForPostalCodeValidation,
      isZipCodeFixExperiment,
      country_select,
      user.countryCode,
    ],
  );

  const shouldShowAUCreditBureauElectoralRollCheckbox =
    useIsTreatment('apr_2024_au_electoral_roll', {
      skipTracking: !showAuContent,
    }) && showAuContent;

  const explanationView = useCallback((): JSX.Element => {
    return (
      <VStack alignItems={variant === 'au' ? 'flex-start' : 'center'}>
        <TextBody as="p" spacingBottom={5} align="center">
          {getEDPFormSubtitle(formatMessage, variant)}
        </TextBody>
        <Line />
      </VStack>
    );
  }, [formatMessage, variant]);

  const address2View = useCallback((): JSX.Element | null => {
    if (isEUHouseNumberEligible) {
      return (
        <ValidatedInput
          name="address2"
          placeholder={formatMessage(messages.streetAddress)}
          validators={getRequiredValidator(
            formatMessage(messages.streetAddress),
            formatMessage,
          )}
        />
      );
    }
    return user.isInEurope ? null : (
      <ValidatedInput
        name="address2"
        placeholder={formatMessage(
          isCanadianUser ? messages.apartmentSuiteDetails : messages.address2,
        )}
        validators={getEmptyValidators()}
      />
    );
  }, [formatMessage, isEUHouseNumberEligible, user.isInEurope, isCanadianUser]);

  const onAutofillAddress = useCallback(() => {
    logMeasurement('verify_identity_autofill_address', {
      context: 'decoupled_edp_form',
    });
  }, [logMeasurement]);

  const hasProvince = useCallback((countryCode: string): boolean => {
    switch (countryCode) {
      case 'CA':
      case 'IT':
        return true;
      default:
        return false;
    }
  }, []);

  const userPersonalDetails = useUserPersonalDetails();

  const userCurrentDateOfBirth = useMemo(() => {
    if (isEDPFieldPrefillEnabled && userPersonalDetails?.dateOfBirth) {
      return {
        day: dobFromDateString(userPersonalDetails?.dateOfBirth).day,
        month: dobFromDateString(userPersonalDetails?.dateOfBirth).month,
        year: dobFromDateString(userPersonalDetails?.dateOfBirth).year,
      };
    }

    return {
      day: user.dob.day?.toString() || '',
      month: user.dob.month?.toString() || '',
      year: user.dob.year?.toString() || '',
    };
  }, [userPersonalDetails, isEDPFieldPrefillEnabled, user.dob]);

  const disableKYCRefreshEditDOB = useMemo(() => {
    return (
      disableKYCRefreshSSNDOBEdit &&
      !!(
        // We can not use formData.day / month / year to disable DOB fields as it changes with onFormChange.
        // This can cause the fields to be disabled when the user is trying to edit the DOB.
        // Relying on hasPreviousEdpDob to see if EDP API returned DOB.
        (
          hasPreviousEdpDob ||
          (userCurrentDateOfBirth.day &&
            userCurrentDateOfBirth.month &&
            userCurrentDateOfBirth.year)
        )
      )
    );
  }, [disableKYCRefreshSSNDOBEdit, userCurrentDateOfBirth, hasPreviousEdpDob]);

  const dateOfBirthView = useCallback((): JSX.Element => {
    const useInternationalDOBFormat = !['US', 'CA', 'PH'].includes(
      user.countryCode,
    );
    const monthView = (
      <MonthSelect
        name="month"
        validators={getRequiredValidator(
