        disabled={disableKYCRefreshEditDOB}
      />
    );
    const dayView = (
      <DaySelect
        name="day"
        validators={getRequiredValidator(
          formatMessage(commonMessages.day),
          formatMessage,
        )}
        disabled={disableKYCRefreshEditDOB}
      />
    );
    const yearView = (
      <YearSelect
        name="year"
        validators={getRequiredValidator(
          formatMessage(commonMessages.year),
          formatMessage,
        )}
        disabled={disableKYCRefreshEditDOB}
      />
    );
    return (
      <HStack
        spacerGap={1}
        responsiveConfig={{
          phone: {
            flexDirection: 'column',
            gap: 1,
          },
        }}
      >
        {useInternationalDOBFormat && dayView}
        {monthView}
        {!useInternationalDOBFormat && dayView}
        {yearView}
      </HStack>
    );
  }, [formatMessage, user.countryCode, disableKYCRefreshEditDOB]);

  const countryView = useCallback((): JSX.Element => {
    const countrySelect = countrySpecificFields?.filter(
      (field: CountrySpecificField) => field.field === 'country_select',
    );

    if (!countrySelect?.length) {
      return (
        <TextInput
          label={formatMessage(commonMessages.country)}
          value={user.countryName}
          disabled
        />
      );
    }
    const { field, label, choices } = countrySelect[0];

    return (
      <SelectList
        name={field}
        label={label}
        placeholder={label}
        validators={getRequiredValidator(
          formatMessage(commonMessages.country),
          formatMessage,
        )}
        options={choices || []}
      >
        {(choices || []).map(o => (
          <SelectOption value={o.value} key={o.value} title={o.label} />
        ))}
      </SelectList>
    );
  }, [countrySpecificFields, formatMessage, user.countryName]);

  const getCountrySpecificValidators = useCallback(
    (
      fieldLabel: string,
      lengths?: Array<number> | null,
      allowsAlphabet?: boolean | null,
      allowsSpace?: boolean | null,
      isPanField?: boolean | null,
    ): Array<[ValidatorFunction, string | null]> => {
      const validations: [ValidatorFunction, string | null][] = [];
      const alphaNumericRegex = regex(/^[A-Za-z\d]*$/);
      const alphaNumericRegexWithSpace = regex(
        /^[a-zA-Z0-9.]+[a-zA-Z0-9 .]*[a-zA-Z0-9.]+$/,
      );
      const getRegex = allowsSpace
        ? alphaNumericRegexWithSpace
        : alphaNumericRegex;

      if (lengths) {
        validations.push([
          allowedLengths(lengths),
          formatMessage(messages.fieldLength, {
            lengths: lengths.join(', '),
            field: fieldLabel,
          }),
        ]);
      }

      if (allowsAlphabet) {
        validations.push([
          getRegex,
          formatMessage(messages.fieldAlphanumericCharacters),
        ]);
      } else {
        validations.push([
          regex(/^\d*$/),
          formatMessage(messages.fieldNumericCharacters),
        ]);
      }

      if (isPanField) {
        validations.push([isValidPan, formatMessage(messages.invalidPan)]);
      }

      return [
        [
          required,
          formatMessage(messages.requiredError, { field: fieldLabel }),
        ],
        ...validations,
      ];
    },
    [formatMessage],
  );

  const renderCountrySpecificField = useCallback(
    ({
      label,
      allowedLengths: lengths,
      allowsAlphabet,
      field,
      choices,
      allowsSpace,
    }: CountrySpecificField): JSX.Element | null => {
      if (field.includes('state') || field === 'country_select') {
        return null;
      }

      let fieldLabel = label;
      // bypassing for the field as it requires an upper case text as a label
      if (
        !field.includes('spanish_nif_nie_number') &&
        !field.includes('indian_pan_number') &&
        !field.includes('indian_pan_specific_full_name')
      ) {
        fieldLabel =
          label.charAt(0).toUpperCase() + label.toLowerCase().substr(1); // Sentence case is our convention
      }
      const fieldId = `${fieldLabel.replace(/\s/g, '')}Field`;
      const isPanField = field.includes('indian_pan_number');

      const isCPFField = field.includes('brazilian_individual_taxpayer_number');
      if (isCPFField) {
        return (
          <>
            <FormGroup key={field} column>
              <CPFField
                id={fieldId}
                name={field}
                hideInlineErrorMessages={false}
              />
            </FormGroup>

            <CPFExplanation />
          </>
        );
      }

      return (
        <>
          {choices ? (
            <SelectList
              testID={field}
              name={field}
              label={fieldLabel}
              placeholder={fieldLabel}
              options={choices}
              validators={getRequiredValidator(fieldLabel, formatMessage)}
            >
              {choices.map(choice => (
                <SelectOption
                  title={choice.label}
                  value={choice.value}
                  key={choice.value}
                />
              ))}
            </SelectList>
          ) : (
            <ValidatedInput
              id={fieldId}
              testID={field}
              name={field}
              label={fieldLabel}
              placeholder={fieldLabel}
              validators={getCountrySpecificValidators(
                fieldLabel,
                lengths,
                allowsAlphabet,
                allowsSpace,
                isPanField,
              )}
              size={lengths ? Math.max(...lengths) : 30}
              maxLength={lengths ? Math.max(...lengths) : 50}
            />
          )}
        </>
      );
    },
    [formatMessage, getCountrySpecificValidators],
  );

  const renderStateField = useCallback(() => {
    if (user.countryCode === 'US') {
      return (
        <StateSelect
          name="state"
          validators={getRequiredValidator(
            formatMessage(messages.state),
            formatMessage,
          )}
        />
      );
    }

    if (countrySpecificStateField) {
      const maxLength = countrySpecificStateField.allowedLengths
        ? Math.max(...countrySpecificStateField.allowedLengths)
        : 50;

      return (
        <ValidatedInput
          testID={countrySpecificStateField.field}
          name={countrySpecificStateField.field}
          placeholder={formatMessage(
            hasProvince(user.countryCode) ? messages.province : messages.state,
          )}
          validators={
            isCanadianUser
              ? getRequiredCAProvinceValidators(
                  formatMessage(messages.province),
                  formatMessage,
                )
              : getRequiredValidator(
                  formatMessage(
                    hasProvince(user.countryCode)
                      ? messages.province
                      : messages.state,
                  ),
                  formatMessage,
                )
          }
          maxLength={maxLength}
          autoCapitalize={maxLength < 4 ? 'characters' : 'words'}
        />
      );
    }
    return null;
  }, [
    countrySpecificStateField,
    formatMessage,
    hasProvince,
    user.countryCode,
    isCanadianUser,
  ]);

  const handleContinueEvent = useCallback(() => {
    logButtonClick('verify_identity_tapped_submit', {
      componentName: 'submit_button',
      context: 'decoupled_edp_form',
    });
  }, [logButtonClick]);

  // This is required since there is a generic error message thrown from api client in case of
  //    api failures and the api client doesm't have react-intl context
  const localizedDefaultError = useCallback(
    (message: ReactNode) => {
      if (message === 'Something went wrong, please try again.') {
        return formatMessage(messages.defaultErrorMessage);
      }
      return message;
    },
    [formatMessage],
  );

  const prefillSSN =
    prefillChallenge.challengeType === 'SSN' ? prefillChallenge.value : '';

  const { prefillFirstName = '', prefillLastName = '' } = useMemo(() => {
    /**
     * In Canada, we can only use previous EDP data to prefill firstName and lastName, and not IDV data, due to Compliance reasons.
     * Hence, we are not using user.firstName and user.lastName to prefill name for Canadian users.
     */
    if (isCanadianUser) {
      return {
        prefillFirstName: firstName || '',
        prefillLastName: lastName || '',
      };
    }

    if (isEDPFieldPrefillEnabled) {
      return {
        prefillFirstName: userPersonalDetails?.legalName.firstName,
        prefillLastName: userPersonalDetails?.legalName.lastName,
      };
    }

    return {
      prefillFirstName: firstName || user.firstName,
      prefillLastName: lastName || user.lastName,
    };
  }, [
    isCanadianUser,
    isEDPFieldPrefillEnabled,
    firstName,
    user.firstName,
    user.lastName,
    lastName,
    userPersonalDetails?.legalName.firstName,
    userPersonalDetails?.legalName.lastName,
  ]);

  const handleOnChange = useCallback(
    () =>
      onFormChange({
        australiaCreditBureauElectoralRollVerifyAllowed:
          !australiaCreditBureauElectoralRollVerifyAllowed,
      }),
    [australiaCreditBureauElectoralRollVerifyAllowed, onFormChange],
  );

  const handleOnChange1 = useCallback(
    () =>
      onFormChange({
        australiaCreditBureauVerifyAllowed: !australiaCreditBureauVerifyAllowed,
      }),
    [australiaCreditBureauVerifyAllowed, onFormChange],
  );

  return (
    <VStack
      width="100%"
      maxWidth="580px"
      responsiveConfig={{
        desktop: {
          spacing: 2,
        },
      }}
      testID="decoupled-edp-form"
    >
      {isFetchingInitial ? (
        <VStack alignItems="center" justifyContent="center" minHeight={600}>
          <Spinner />
        </VStack>
      ) : (
        <VStack
          responsiveConfig={{
            phone: {
              spacing: 2,
            },
          }}
        >
          <VStack alignItems="center" spacerGap={2} spacingBottom={2}>
            {showTitle ? (
              <FormHeader
                subtitle={
                  showExplanation
                    ? getEDPFormSubtitle(formatMessage, variant)
                    : undefined
                }
              />
            ) : (
              showExplanation && explanationView()
            )}
            {!!(
              errorMessage &&
              errorMessage.errors &&
              errorMessage.errors.length > 0
            ) && (
              <StyledInlineAlert
                title={errorMessage.header}
                subtitle={errorMessage.errors.join('. ')}
                type="error"
              />
            )}
            {!!error && (
              <StyledInlineAlert
                title={localizedDefaultError(error.message)}
                type="error"
              />
            )}
          </VStack>
          <Form
            // @ts-expect-error: 2022-11-10: Whitelisted type error. To be corrected after typescript migration.
            onSubmit={onFormSubmit}
            onValid={markValid}
            onInvalid={markInvalid}
            // @ts-expect-error: 2022-11-10: Whitelisted type error. To be corrected after typescript migration.
            onChange={onFormChange}
            countryCode={country_select}
            onAutofillAddress={onAutofillAddress}
            initialValues={{
              firstName: prefillFirstName,
              lastName: prefillLastName,
              fullName: getFullNameFromIdentityStoreOrUser(user, store),
              day: userCurrentDateOfBirth.day || day || '',
              month: userCurrentDateOfBirth.month || month || '',
              year: userCurrentDateOfBirth.year || year || '',
              state:
                state || isEDPFieldPrefillEnabled
                  ? userPersonalDetails?.primaryAddress?.state ||
                    userPersonalDetails?.residentialAddress?.state ||
                    ''
                  : user.state || '',
              address1:
                address1 || isEDPFieldPrefillEnabled
                  ? userPersonalDetails?.primaryAddress?.line1 ||
                    userPersonalDetails?.residentialAddress?.line1 ||
                    ''
                  : user.addressLine1 || '',
              address2:
                address2 || isEDPFieldPrefillEnabled
                  ? userPersonalDetails?.primaryAddress?.line2 ||
                    userPersonalDetails?.residentialAddress?.line2 ||
                    ''
                  : user.addressLine2 || '',
              zip:
                postalCode || isEDPFieldPrefillEnabled
                  ? userPersonalDetails?.primaryAddress?.postalCode ||
                    userPersonalDetails?.residentialAddress?.postalCode ||
                    ''
                  : user.postalCode || '',
              city:
                city || isEDPFieldPrefillEnabled
                  ? userPersonalDetails?.primaryAddress?.city ||
                    userPersonalDetails?.residentialAddress?.city ||
                    ''
                  : user.city || '',
              ssn: ssn || prefillSSN || '',
              addressComponents,
              australiaDriverLicenseNumber: australiaDriverLicenseNumber || '',
              australiaDriverLicenseState: australiaDriverLicenseState || '',
              australiaDriverLicenseCardNumber:
                australiaDriverLicenseCardNumber || '',
              australiaMedicareNumber: australiaMedicareNumber || '',
              australiaMedicareReference: australiaMedicareReference || '',
              australiaMedicareDateOfExpiry:
                australiaMedicareDateOfExpiry || '',
              australiaMedicareColor: australiaMedicareColor || '',
              australiaPassportNumber: australiaPassportNumber || '',
              australiaCreditBureauVerifyAllowed:
                australiaCreditBureauVerifyAllowed || false,
              australiaCreditBureauElectoralRollVerifyAllowed:
                australiaCreditBureauElectoralRollVerifyAllowed || false,
              gender: gender || '',
              country_select: country_select || user.countryCode,
              ...(countrySpecificFields &&
                countrySpecificFields.reduce(
                  (obj, { field }) => ({
                    [field]: store.formData[field],
                    ...obj,
                  }),
                  {},
                )),
            }}
            attachAutofillAddress
            separateHouseNumberAutofill={isEUHouseNumberEligible}
            /**
             * Want to validate on mount in case form is auto-filled from existing
             * EDP data and is valid. Without this the button would be disabled until
             * user interacted with the form.
             */
            validateOnMount
          >
            <VStack spacerGap={1}>
              {shouldUseFullNameField ? (
                <FullNameField />
              ) : (
                <HStack
                  spacerGap={1}
                  responsiveConfig={{
                    phone: {
                      flexDirection: 'column',
                    },
                  }}
                >
                  <ValidatedInput
                    name="firstName"
                    label={formatMessage(commonMessages.legalFirstNameField)}
                    placeholder={formatMessage(
                      commonMessages.legalFirstNameField,
                    )}
                    validators={getRequiredValidator(
                      formatMessage(commonMessages.legalFirstNameField),
                      formatMessage,
                    )}
                    size={4}
                    autoFocus
                    autoCapitalize="words"
                  />
                  <ValidatedInput
                    name="lastName"
                    label={formatMessage(commonMessages.legalLastNameField)}
                    placeholder={formatMessage(
                      commonMessages.legalLastNameField,
                    )}
                    validators={getRequiredValidator(
                      formatMessage(commonMessages.legalLastNameField),
                      formatMessage,
                    )}
                    size={4}
                    autoCapitalize="words"
                  />
                </HStack>
              )}
              <TextLabel1 as="p" disabled={disableKYCRefreshEditDOB}>
                {formatMessage(commonMessages.dob)}
              </TextLabel1>
              {dateOfBirthView()}
              <ValidatedInput
                label={formatMessage(
                  showFCAContent
                    ? messages.residentialAddress
                    : isEUHouseNumberEligible
                    ? messages.address
                    : messages.streetAddress,
                )}
                placeholder={
                  isEUHouseNumberEligible
                    ? formatMessage(messages.houseNumber)
                    : formatMessage(messages.address1)
                }
                name="address1"
                validators={getRequiredValidator(
                  isEUHouseNumberEligible
                    ? formatMessage(messages.houseNumber)
                    : formatMessage(messages.streetAddress),
                  formatMessage,
                )}
              />
              {address2View()}
              <HStack spacerGap={1}>
                <Box width={requiresState ? '49.2%' : '100%'}>
                  <ValidatedInput
                    label={requiresState ? '' : formatMessage(messages.city)}
                    name="city"
                    placeholder={formatMessage(messages.city)}
                    aria-required="true"
                    maxLength={128}
                    size={12}
                    validators={getRequiredValidator(
                      formatMessage(messages.city),
                      formatMessage,
                    )}
                    autoCapitalize="words"
                  />
                </Box>
                {requiresState && <Box width="49.2%">{renderStateField()}</Box>}
              </HStack>
              <Box
                width="100%"
                display="flex"
                flexDirection={isMobile ? 'column' : 'row'}
                responsiveConfig={{
                  desktop: {
                    gap: 1,
                  },
                  tablet: {
                    gap: 1,
                  },
                  phone: {
                    gap: 1,
                  },
                }}
              >
                <Box width={isMobile ? '100%' : '50%'}>
                  {user.countryCode === 'US' ? (
                    <ValidatedInput
                      name="zip"
                      label={formatMessage(messages.zip)}
                      placeholder={formatMessage(messages.zip)}
                      validators={getRequiredZipValidators(formatMessage)}
                      maxLength={10}
                      size={12}
                    />
                  ) : (
                    <ValidatedInput
                      name="zip"
                      label={formatMessage(messages.postalCode)}
                      placeholder={formatMessage(messages.postalCode)}
                      aria-required="true"
                      validators={getRequiredPostCodeValidators(
                        formatMessage,
                        isZipCodeFixExperiment
                          ? country_select ?? user.countryCode
                          : user.countryCode,
                        isPostalCodeValidationEligible,
                      )}
                      maxLength={
                        countrySpecificPostalCodeLengthMap[
                          isZipCodeFixExperiment
                            ? country_select ?? user.countryCode
                            : user.countryCode
                        ] ?? 16
                      }
                      mask={
                        countrySpecificPostalCodeMaskMap[
                          isZipCodeFixExperiment
                            ? country_select ?? user.countryCode
                            : user.countryCode
                        ]
                      }
                      size={12}
                      autoCapitalize="characters"
                    />
                  )}
                </Box>
                <Box width={isMobile ? '100%' : '50%'}>{countryView()}</Box>
              </Box>
              {showAuContent && auIdChoice && (
                <AUCountryFields
                  auIdChoice={auIdChoice}
                  australiaMedicareColor={australiaMedicareColor}
                  australiaMedicareDateOfExpiry={australiaMedicareDateOfExpiry}
                  australiaDriverLicenseCardNumber={
                    australiaDriverLicenseCardNumber
                  }
                  onFormChange={onFormChange}
                />
              )}
              {showAuContent && (
                <Box spacingBottom={2}>
                  {shouldShowAUCreditBureauElectoralRollCheckbox ? (
                    <Checkbox
                      checked={australiaCreditBureauElectoralRollVerifyAllowed}
                      onChange={handleOnChange}
                      name="australiaCreditBureauElectoralRollVerifyAllowed"
                    >
                      {formatMessage(
                        messages.australia_credit_bureau_electoral_roll_verify_allowed_label,
                        {
                          strong: (children: React.ReactNode) => [
                            <TextHeadline color="foregroundMuted" as="span">
                              {children}
                            </TextHeadline>,
                          ],
                        },
                      )}
                    </Checkbox>
                  ) : (
                    <Checkbox
                      checked={australiaCreditBureauVerifyAllowed}
                      onChange={handleOnChange1}
                      name="australiaCreditBureauVerifyAllowed"
                    >
                      {formatMessage(
                        messages.australia_credit_bureau_verify_allowed_label,
                        {
                          strong: (children: React.ReactNode) => [
                            <TextHeadline color="foregroundMuted" as="span">
                              {children}
                            </TextHeadline>,
                          ],
                        },
                      )}
                    </Checkbox>
                  )}
                </Box>
              )}
              {user.countryCode === 'US' && (
                <React.Fragment>
                  <VStack>
                    <ValidatedInput
                      name="ssn"
                      testID="ssn"
                      label={formatMessage(messages.ssnHeader)}
                      placeholder="1234"
                      aria-required="true"
                      validators={getRequiredSsnValidators(formatMessage)}
                      maxLength={4}
                      size={4}
                      inputMode="numeric"
                      disabled={disableKYCRefreshEditSSN}
                    />
                  </VStack>
                  <VStack spacingVertical={2}>
                    <Banner
                      variant="informational"
                      title={formatMessage(messages.ssnCollectionHeader)}
                      startIcon="protection"
                      numberOfLines={4}
                    >
                      {formatMessage(messages.ssnCollectionDescription)}
                    </Banner>
                  </VStack>
                </React.Fragment>
              )}
              {countrySpecificFields?.map(renderCountrySpecificField)}
              <VStack spacingTop={1}>
                <Button
                  onPress={handleContinueEvent}
                  testID="edp-submit-button"
                  type="submit"
                  disabled={
                    !valid ||
                    isLoading ||
                    isFetchingAttempts ||
                    lifetimeMaxReached ||
                    attemptsRemaining === 0
                  }
                  loading={isLoading}
                >
                  {formatMessage(commonMessages.continue)}
                </Button>
              </VStack>
            </VStack>
            <InvisibleFormField name="addressComponents" />
          </Form>
        </VStack>
      )}
    </VStack>
  );
}

export default memo(DecoupledEDPForm);

import { useIntl } from 'react-intl';

import { Box } from '@cbhq/cds-web/layout';
import { TextLabel2 } from '@cbhq/cds-web/typography';

import { messages } from '../../../EDP.messages';
import { getRequiredValidator } from '../../../EDP.utils';
import ValidatedInput from './ValidatedInput';

function FullNameField() {
