  return (
    <>
      <ValidatedInput
        id="fullNameInput"
        name="fullName"
        label={formatMessage(messages.fullName)}
        placeholder={formatMessage(messages.fullName)}
        validators={getRequiredValidator(
          formatMessage(messages.fullName),
          formatMessage,
        )}
        size={4}
        autoFocus
        autoCapitalize="words"
      />
      <Box spacingTop={1}>
        <TextLabel2 as="span" color="foregroundMuted">
          {formatMessage(messages.fullNameHelpText)}
        </TextLabel2>
      </Box>
    </>
  );
}

export default FullNameField;

import React, { useCallback } from 'react';
import type { DefaultTheme } from 'styled-components';

import { Validators } from '@cb/shared/components/Form/useValidationStore';
import { TextInput } from '@cbhq/cds-web/controls';

export type InputProps = {
  id?: string; // a11y
  value?: string;
  placeholder?: string;
  disabled?: boolean;
  label?: string;
  onChange?: (value: string) => void;
  onBlur?: () => void;
  onFocus?: () => void;
  onPaste?: () => void;
  onEscape?: () => void;
  onEnter?: () => void;
  onTouchStart?: () => void;
  showError?: boolean;
  error: string | undefined | null;
  removeError?: () => void;
  addError?: () => void;
  resetState?: () => void;
  actionLabel?: React.ReactNode | string;
  onActionClick?: () => void;
  // By default, action button is only shown when input is focused and empty
  // However, for certain cases, we will want to show the action button permanently.
  forceShowAction?: boolean;
  validators?: Validators;
  className?: string;
  autoFocus?: boolean;
  /**
   * See here for docs: https://developer.mozilla.org/en-US/docs/Web/HTML/Global_attributes/autocapitalize
   */
  autoCapitalize?: 'none' | 'off' | 'sentences' | 'on' | 'words' | 'characters';
  mask?: string;
  maskChar?: string;
  maxLength?: number;
  size?: number;
  height?: string;
  icon?: React.ReactNode | null;
  containerStyles?: React.CSSProperties;
  inputStyles?: React.CSSProperties;
  labelStyles?: React.CSSProperties;
  iconStyles?: React.CSSProperties;
  component?: 'input' | 'textarea';
  annotation?: React.ReactNode;
  annotationPosition?: 'left' | 'right';
  rows?: string;
  allowShrink?: boolean;
  type?: 'password' | 'text' | 'number';
  'data-testid'?: string;
  inputMode?: React.HTMLAttributes<HTMLLIElement>['inputMode'];
  autoComplete?: string;
  name?: string;
  errorBorder?: keyof DefaultTheme['color'];
  focusBorder?: keyof DefaultTheme['color'];
  errorID?: string; // a11y
  invalid?: boolean; // a11y
  testID?: string;
  refCallback?: (inputElement: HTMLInputElement) => void;
};

function Input({
  id,
  size,
  type,
  inputMode,
  autoComplete,
  annotation,
  className,
  maskChar,
  placeholder,
  maxLength,
  icon,
  validators,
  onActionClick,
  onBlur,
  onChange,
  onEnter,
  onEscape,
  onFocus,
  onPaste,
  onTouchStart,
  label,
  mask,
  addError,
  removeError,
  resetState,
  actionLabel,
  forceShowAction,
  value,
  name,
  errorID,
  invalid,
  showError = false,
  error,
  autoFocus = false,
  autoCapitalize,
  refCallback,
  disabled,
  ...props
}: InputProps) {
  // TODO: We should remove this and use ValidatedInput instead
  const validInput = useCallback(
    (value: string) => {
      return (
        !validators ||
        !validators.some(v => {
          return !v[0] || !v[0](value);
        })
      );
    },
    [validators],
  );

  const handleChange = useCallback(
    (e: React.SyntheticEvent) => {
      const target = e.target as HTMLInputElement;
      const value: string = target.value;

      if (onPaste && mask && e.type === 'paste') {
        // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
        onPaste(e);
      }

      if (onChange) onChange(value);
      const isValid = validInput(value);

      if (!isValid && addError) {
        addError();
      } else if (isValid && removeError) {
        removeError();
      }
    },
    [onPaste, mask, onChange, validInput, addError, removeError],
  );

  const handleBlur = useCallback(
    (event: React.SyntheticEvent) => {
      if (showError) {
        if (removeError) removeError();
        if (resetState) resetState();
      }

      // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
      if (onBlur) onBlur(event);
    },
    [showError, removeError, resetState, onBlur],
  );

  const handleFocus = useCallback(
    (event: React.SyntheticEvent) => {
      // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
      if (onFocus) onFocus(event);
    },
    [onFocus],
  );

  const setRef = useCallback(
    (input: HTMLInputElement) => {
      if (refCallback) refCallback(input);
    },
    [refCallback],
  );

  return (
    <TextInput
      key={id}
      ref={setRef}
      testID={props.testID}
      aria-invalid={invalid ? 'true' : 'false'}
      name={name}
      label={label}
      placeholder={placeholder}
      maxLength={maxLength}
      size={size}
      value={value}
      variant={showError ? 'negative' : 'foregroundMuted'}
      helperText={showError && error ? error : undefined}
      onBlur={handleBlur}
      onFocus={handleFocus}
      onPaste={onPaste}
      onChange={handleChange}
      autoFocus={autoFocus}
      autoComplete="off"
      autoCapitalize={autoCapitalize}
      disabled={disabled}
    />
  );
}

