import { useCallback } from 'react';
import { useIntl } from 'react-intl';

import { useFields, useSubmitter } from '@cb/forms';
import { states } from '@cb/shared/data';
import { useIsMobile } from '@cb/shared/utils';
import { Button } from '@cbhq/cds-web/buttons';
import { Select, SelectOption, TextInput } from '@cbhq/cds-web/controls';
import { VStack } from '@cbhq/cds-web/layout';
import { TextBody, TextLegal } from '@cbhq/cds-web/typography';
import { TextTitle2 } from '@cbhq/cds-web/typography/TextTitle2';

import { commonMessages } from '../../../../../commonOnboardingMessages';
import { useOnboardingContext } from '../../../../../Context';
import { getRequiredFieldLabel } from '../../../../../utils/formatters';
import { PrefillAddressType } from '../../../EDP.types';
import { isUserEnteredAddressPresentInVendorAddresses } from '../../../EDP.utils';
import PrefillForm, {
  messages,
  state,
} from '../config/PrefillPersonalInfoConfig';

type PrefillAddressProps = {
  addresses: PrefillAddressType | undefined;
  onSubmit: (address: PrefillAddressType[number]) => void;
};

function PrefillAddress({ onSubmit, addresses }: PrefillAddressProps) {
  const { formatMessage } = useIntl();
  const { line1, line2, city, region, postalCode, isAddressEdited } =
    useFields(PrefillForm);
  const [, isSubmittable] = useSubmitter(PrefillForm);
  const isMobile = useIsMobile();
  const {
    analytics: { logButtonClick },
  } = useOnboardingContext();

  const handleSubmit = useCallback(() => {
    const userEnteredAddress = {
      line1: line1.value,
      line2: line2.value,
      city: city.value,
      region: region.value,
      postalCode: postalCode.value,
    };

    const isPresentInVendorAddresses =
      isUserEnteredAddressPresentInVendorAddresses(
        userEnteredAddress,
        addresses,
      );

    logButtonClick('prefill_personal_info_address_edited', {
      manually_edited: !isPresentInVendorAddresses,
    });

    if (isPresentInVendorAddresses) {
      isAddressEdited.onChange(false);
    } else {
      isAddressEdited.onChange(true);
    }
    onSubmit(userEnteredAddress);
  }, [
    logButtonClick,
    addresses,
    city.value,
    isAddressEdited,
    line1.value,
    line2.value,
    onSubmit,
    postalCode.value,
    region.value,
  ]);

  const handleOnChange: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(e => line1.onChange(e.currentTarget.value), [line1]);

  const handleOnChange1: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(e => line2.onChange(e.currentTarget.value), [line2]);

  const handleOnChange2: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(e => city.onChange(e.currentTarget.value), [city]);

  const handleOnChange3: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(e => postalCode.onChange(e.currentTarget.value), [postalCode]);

  return (
    <VStack
      spacerGap={2}
      width="100%"
      minWidth={isMobile ? '100%' : '480px'}
      testID="PrefillPersonalInfo_manual_address_input_section"
    >
      <TextTitle2
        as="p"
        testID="PrefillPersonalInfo_manual_address_input_section_title"
      >
        {formatMessage(messages.header)}
      </TextTitle2>
      <TextBody
        as="p"
        testID="PrefillPersonalInfo_manual_address_input_section_sub_title"
      >
        {formatMessage(messages.instructions)}
      </TextBody>
      <TextLegal as="p" color="foregroundMuted">
        {formatMessage(messages.prefill_required_fields)}
      </TextLegal>
      <TextInput
        value={line1.value}
        label={getRequiredFieldLabel(formatMessage(messages.address_label))}
        onChange={handleOnChange}
        placeholder={formatMessage(messages.address_placeholder)}
        helperText={
          line1.errors?.length > 0
            ? formatMessage(messages.address_validator_required)
            : ''
        }
        variant={line1.errors?.length > 0 ? 'negative' : 'foregroundMuted'}
        testID="PrefillPersonalInfo_manual_address_address1_input"
      />
      <TextInput
        label={formatMessage(messages.apt_label)}
        value={line2.value || ''}
        onChange={handleOnChange1}
        placeholder={formatMessage(messages.apt_placeholder)}
        helperText={formatMessage(messages.apt_suite_label)}
        testID="PrefillPersonalInfo_manual_address_address2_input"
      />
      <TextInput
        label={getRequiredFieldLabel(formatMessage(messages.city_label))}
        value={city.value}
        onChange={handleOnChange2}
        placeholder={formatMessage(messages.city_placeholder)}
        helperText={
          city.errors?.length > 0
            ? formatMessage(messages.city_validator_required)
            : ''
        }
        variant={city.errors?.length > 0 ? 'negative' : 'foregroundMuted'}
        testID="PrefillPersonalInfo_manual_address_city_input"
      />
      <Select
        label={formatMessage(messages.state_label)}
        value={region?.value}
        onChange={region.onChange}
        placeholder={formatMessage(messages.state_placeholder)}
        valueLabel={
          states.find((s: state) => s.abbreviation === region.value)?.name
        }
        helperText={
          region.errors?.length > 0
            ? formatMessage(messages.state_validator_required)
            : ''
        }
        variant={region.errors?.length > 0 ? 'negative' : 'foregroundMuted'}
        testID="PrefillPersonalInfo_manual_address_state_input"
      >
        {states.map((state: state) => {
          if (state.abbreviation !== 'HI') {
            return (
              <SelectOption
                value={state.abbreviation}
                key={state.abbreviation}
                title={state.name}
              />
            );
          }
        })}
      </Select>
      <TextInput
        label={getRequiredFieldLabel(formatMessage(messages.zipcode_label))}
        value={postalCode?.value}
        onChange={handleOnChange3}
        placeholder={formatMessage(messages.zipcode_placeholder)}
        helperText={
          postalCode.errors?.length > 0
            ? formatMessage(messages.zipcode_validator_format)
            : ''
        }
        variant={postalCode.errors?.length > 0 ? 'negative' : 'foregroundMuted'}
        testID="PrefillPersonalInfo_manual_address_zip_input"
      />
      <Button
        testID="PrefillPersonalInfo_manual_address_input_submit_button"
        onPress={handleSubmit}
        disabled={!isSubmittable}
      >
        {formatMessage(commonMessages.continue)}
      </Button>
    </VStack>
  );
}

export default PrefillAddress;

import { useCallback } from 'react';
import { defineMessages, useIntl } from 'react-intl';

