export type PrefillDOBProps = {
  prefillDob: FieldProps<string, object>;
  isDOBEdited: FieldProps<boolean, object>;
  showEditDobSection: boolean;
  toggleShowDobEditSection: () => void;
};

function PrefillDob({
  prefillDob,
  isDOBEdited,
  showEditDobSection,
  toggleShowDobEditSection,
}: PrefillDOBProps) {
  const { formatMessage } = useIntl();
  const {
    analytics: { logButtonClick },
  } = useOnboardingContext();

  const handleSubmit = useCallback(() => {
    logButtonClick('prefill_personal_info_dob_edited');
    isDOBEdited.onChange(true);
    toggleShowDobEditSection();
  }, [logButtonClick, isDOBEdited, toggleShowDobEditSection]);

  const handleOnChange: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(e => prefillDob.onChange(e.currentTarget.value), [prefillDob]);

  return showEditDobSection ? (
    <VStack spacingTop={5} alignItems="center" spacerGap={2}>
      <TextInput
        type="date"
        label={formatMessage(commonMessages.dob)}
        value={prefillDob.value || ''}
        onChange={handleOnChange}
        helperText={
          prefillDob.errors?.length > 0
            ? formatMessage(messages.prefill_dob_validator)
            : ''
        }
        variant={prefillDob.errors?.length > 0 ? 'negative' : 'foregroundMuted'}
        testID="PrefillPersonalInfo_manual_dob_input"
      />
      <Box width="50%">
        <Button
          block
          onPress={toggleShowDobEditSection}
          disabled={prefillDob.errors.length > 0}
          testID="PrefillPersonalInfo_dob_update_button"
        >
          {formatMessage(messages.update_label)}
        </Button>
      </Box>
    </VStack>
  ) : (
    <HStack spacingTop={2} alignItems="center" justifyContent="space-between">
      <VStack width="80%">
        <TextHeadline spacingTop={5} as="p">
          {prefillDob ? prefillDob.value : ''}
        </TextHeadline>
        <TextBody
          testID="PrefillPersonalInfo_dob_label"
          color="foregroundMuted"
          as="p"
        >
          {formatMessage(commonMessages.dob)}
        </TextBody>
      </VStack>
      <PressableOpacity onPress={handleSubmit}>
        <TextBody
          testID="PrefillPersonalInfo_edit_dob_section_toggle_icon"
          color="primary"
          as="p"
        >
          {formatMessage(messages.update_label)}
        </TextBody>
      </PressableOpacity>
    </HStack>
  );
}

