type PrefillDOBInputProps = {
  onSubmit: (value: string) => void;
};

export default function PrefillDOBInput({ onSubmit }: PrefillDOBInputProps) {
  const { formatMessage } = useIntl();
  const [dobInput, setDobInput] = useState('');
  const [isDobInputValid, setIsDobInputValid] = useState(true);
  const isMobile = useScreenMatch('phone');
  const {
    analytics: { logButtonClick },
  } = useOnboardingContext();

  useLogPageViewOnMount('prefill_dob_input_screen_viewed');

  const validateDob = useCallback((dobInput: string) => {
    const today = new Date();
    const dobDate = new Date(dobInput);
    const diff = differenceInYears(today, dobDate);
    return diff >= MIN_ALLOWED_AGE && diff <= MAX_ALLOWED_AGE;
  }, []);

  const dobInputChangeHandler = useCallback(
    (e: ChangeEvent<HTMLInputElement>) => {
      const dateInput = e.target.value;
      setIsDobInputValid(validateDob(dateInput));
      setDobInput(dateInput);
    },
    [validateDob],
  );

  const submitHandler = useCallback(() => {
    if (dobInput.length === 0 || !isDobInputValid) {
      return;
    }
    logButtonClick('prefill_dob_input_submit_clicked');
    onSubmit(dobInput);
  }, [logButtonClick, dobInput, isDobInputValid, onSubmit]);

  return (
    <VStack
      alignItems="center"
      width={isMobile ? '100%' : '50%'}
      spacing={2}
      testID="prefill-dob-input"
    >
      <ScreenHeader
        title={formatMessage(messages.dob_input_title)}
        subtitle={formatMessage(messages.dob_input_description, {
          financialRegulations: (
            <Link
              to="https://www.coinbase.com/legal/licenses"
              variant="body"
              openInNewWindow
              underline={false}
            >
              {formatMessage(messages.financial_regulations)}
            </Link>
          ),
        })}
        testID="prefillDobInput_screen_header"
      />
      <Box spacingVertical={2} width="100%">
        <TextInput
          type="date"
          label={formatMessage(commonMessages.dob)}
          value={dobInput}
          onChange={dobInputChangeHandler}
          helperText={
            isDobInputValid ? '' : formatMessage(messages.prefill_dob_validator)
          }
          variant={isDobInputValid ? 'foregroundMuted' : 'negative'}
          testID="prefillDobInput_date_input"
        />
      </Box>
      <Spacer />
      <Button
        name="continue"
        testID="prefillDobInput_continue_button"
        disabled={!isDobInputValid || dobInput === ''}
        onPress={submitHandler}
        block
      >
        {formatMessage(commonMessages.continue)}
      </Button>
    </VStack>
  );
}

import { useRef } from 'react';
