const i18nKey = 'SplitInput';

const messages = defineMessages({
  ssn_input_label: {
    id: `${i18nKey}.ssn_input_label`,
    defaultMessage: 'Enter the last 4 digits of your SSN',
    description: `
    #Component: Body
    #CharLimit: 35
    #Context: Label of the SSN input field
    #VariableExample: Enter the last 4 digits of your SSN
    `,
  },
  ssn_accessibility_label: {
    id: `${i18nKey}.ssn_accessible_label`,
    defaultMessage: `social security number {digit} of 4`,
    description: `
    #Component: Body
    #CharLimit: 35
    #Context: Label of the SSN input field
    #VariableExample: social security number 1 of 4 
    `,
  },
});

const SSN_CODE_LENGTH = 4;
const BACKSPACE_KEY = 'Backspace';

type SplitInputProps = {
  ssnCode: string;
  onChange: (value: string) => void;
  name: string;
  isLoading: boolean;
};

function SplitInput({ ssnCode, onChange, name, isLoading }: SplitInputProps) {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const inputFieldRef = useRef<any>([]);
  const { formatMessage } = useIntl();

  const handlePartChange = (value: string, position: number) => {
    if (value.length === SSN_CODE_LENGTH && /^\d+$/.test(value)) {
      inputFieldRef.current?.[SSN_CODE_LENGTH - 1].focus();

      onChange(value);
    }

    const newCode = (
      ssnCode.substring(0, position) +
      value +
      ssnCode.substring(position + 1)
    ).slice(0, SSN_CODE_LENGTH);

    onChange(newCode);
  };

  const handleKeyPress = (value: string, position: number) => {
    if (value === BACKSPACE_KEY && position > 0) {
      inputFieldRef.current?.[position - 1]?.focus();
    } else if (value !== BACKSPACE_KEY && position < SSN_CODE_LENGTH - 1) {
      inputFieldRef.current?.[position + 1].focus();
    }
  };

  return (
    <Box
      justifyContent="center"
      flexDirection="column"
      spacingTop={3}
      width="100%"
    >
      <TextLabel1 as="p">{formatMessage(messages.ssn_input_label)}</TextLabel1>
      <HStack
        spacingTop={1}
        justifyContent="space-between"
        spacerGap={0.5}
        testID="ssnInputScreen_split_input"
        height={80}
      >
        {[...Array(SSN_CODE_LENGTH)].map((_, index) => (
          <TextInput
            testID={`${name}_${index + 1}`}
            compact
            align="center"
            autoFocus={index === 0}
            key={index}
            accessibilityLabel={formatMessage(
              messages.ssn_accessibility_label,
              {
                digit: index + 1,
              },
            )}
            // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
            ref={el => (inputFieldRef.current[index] = el)}
            value={ssnCode.charAt(index)}
            // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
            onChange={evt => handlePartChange(evt.target.value, index)}
            // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
            onKeyUp={({ key }) => handleKeyPress(key, index)}
            width="24%"
            height={56}
            disabled={isLoading}
            type="tel"
          />
        ))}
      </HStack>
    </Box>
  );
}

export default SplitInput;

