function QuestionsForm({ store, showTitle }: Props) {
  const {
    onAnswersSubmit,
    onAnswersChange,
    questions,
    answers,
    timeLeft,
    valid,
    isLoading,
    markValid,
    markInvalid,
  } = store;

  const { formatMessage } = useIntl();

  const {
    analytics: { logButtonClick },
    user,
  } = useOnboardingContext();

  useLogPageViewOnMount('verify_identity_questions_viewed');

  useEffect(() => {
    store.startTimer(210);
  }, []);

  const handleOnPress = useCallback(
    () => logButtonClick('verify_identity_questions_tapped_submit'),
    [logButtonClick],
  );

  return (
    <Container column data-testid="questions-form">
      {showTitle ? <FormHeader /> : null}
      <TimerContainer>
        <Text>
          <FormattedMessage
            id={`${i18nKey}.timer`}
            defaultMessage="You have {time} remaining to answer these questions"
            values={{
              time: timeLeft,
            }}
            description="Timer for user to answer a set of questions"
          />
        </Text>
      </TimerContainer>
      <Line />
      <Form
        countryCode={user.countryCode}
        onSubmit={onAnswersSubmit}
        // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
        onChange={onAnswersChange}
        onValid={markValid}
        onInvalid={markInvalid}
      >
        <QuestionsGroup column>
          {questions.map((q, index) => (
            <Question
              key={q.prompt}
              label={q.prompt}
              color="accent"
              size="large"
            >
              <RadioButtonGroup
                name={index.toString()}
                value={answers[index]}
                key={q.prompt}
                column
                validators={[[required, formatMessage(messages.fieldRequired)]]}
              >
                {q.answers.map((a, i) => (
                  <RadioButton label={a} value={i.toString()} key={a} />
                ))}
              </RadioButtonGroup>
            </Question>
          ))}
        </QuestionsGroup>
        <Flex justify="center">
          <Button
            onPress={handleOnPress}
            disabled={!valid || isLoading}
            loading={isLoading}
            block
            type="submit"
          >
            <FormattedMessage
              id={`${i18nKey}.idologyContinueLabel`}
              defaultMessage="Continue"
              description="Text for the button that continues to next page"
            />
          </Button>
        </Flex>
