export type IdentityBasicKycFormProps = {
  store: ReturnType<typeof useEDP>;
  showTitle?: boolean;
  showExplanation?: boolean;
  showBackButton?: boolean;
  onPressBackButton: () => void;
};

function IdentityBasicKycForm({
  store,
  showBackButton = false,
  onPressBackButton,
}: IdentityBasicKycFormProps) {
  const {
    analytics: { logButtonClick },
    verificationMetadata,
  } = useOnboardingContext();

  const { formatMessage } = useIntl();

  const handleContinueEvent = useCallback(() => {
    logButtonClick('verify_identity_tapped_submit', {
      context: 'split_edp_form',
    });
  }, [logButtonClick]);

  useLogPageViewOnMount('verify_identity_basic_kyc_viewed');

  const {
    onFormSubmit,
    isFetchingInitial,
    markValid,
    markInvalid,
    coinbaseUses,
    sourceOfFunds,
    error,
    onFormChange,
    employmentStatuses,
    errorMessage,
    formData: {
      currentJobTitle,
      currentEmployer,
      primarySourceOfFunds,
      usesCoinbaseFor,
    },
    isLoading,
  } = store;
  const showFCAContent =
    verificationMetadata?.targets?.includes('fca_enhanced_cdd') ?? false;

  const usesView = useCallback(
    (): JSX.Element => (
      <CoinbaseUsesComponent
        // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
        onChange={value => {
          onFormChange({ usesCoinbaseFor: value?.toString() });
        }}
        value={usesCoinbaseFor}
        coinbaseUses={coinbaseUses}
      />
    ),
    [usesCoinbaseFor, coinbaseUses, onFormChange],
  );

  const fundsView = useCallback(
    (): JSX.Element => (
      <FundsComponent
        showFCAContent={showFCAContent}
        // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
        onChange={value => {
          onFormChange({ primarySourceOfFunds: value?.toString() });
        }}
        value={primarySourceOfFunds}
        sourceOfFunds={sourceOfFunds}
      />
    ),
    [showFCAContent, primarySourceOfFunds, sourceOfFunds, onFormChange],
  );

  const employmentStatusView = useCallback(
    (): JSX.Element => (
      <EmploymentStatusComponent
        showFCAContent={showFCAContent}
        // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
        onChange={value => {
          onFormChange({ currentJobTitle: value?.toString() });
        }}
        value={currentJobTitle}
        employmentStatuses={employmentStatuses}
      />
    ),
    [showFCAContent, currentJobTitle, employmentStatuses, onFormChange],
  );

  // This is required since there is a generic error message thrown from api client in case of api failures and the api client doesm't have react-intl context
  const localizedDefaultError = useCallback(
    (message: ReactNode) => {
      if (message === 'Something went wrong, please try again.') {
        return formatMessage(messages.defaultErrorMessage);
      }
      return message;
    },
    [formatMessage],
  );

  const handleBackButton = useCallback(() => {
    onPressBackButton();
  }, [onPressBackButton]);

  return (
    <SingleColumnFormContainer column>
      {isFetchingInitial || isLoading ? (
        <LoadingContainer>
          <Spinner />
        </LoadingContainer>
      ) : (
        <div>
          {showBackButton && (
            <HStack offsetStart={9} offsetBottom={5}>
              <BackButton onPressBackButton={handleBackButton} />
            </HStack>
          )}
          <ScreenHeader
            title={formatMessage(messages.tellUsAboutYou)}
            subtitle={
              showFCAContent
                ? formatMessage(messages.helpTextForUses, {
                    link: (
                      <Link
                        href={'https://www.coinbase.com/legal/licenses'}
                        openInNewTab
                        rel="noopener noreferrer"
                        color="accent"
                        underlined
                        noHover
                      >
                        {formatMessage(messages.helpLinkForUses)}
                      </Link>
                    ),
                  })
                : formatMessage(messages.usesCoinbaseForDesc, {
                    link: (content: React.ReactNode) => [
                      <Link
                        href={'https://www.coinbase.com/legal/licenses'}
                        openInNewTab
                        rel="noopener noreferrer"
                        color="accent"
                        underlined
                        noHover
                      >
                        {content}
                      </Link>,
                    ],
                  })
            }
            spacingBottom={5}
          />
          {!!(
            errorMessage &&
            errorMessage.errors &&
            errorMessage.errors.length > 0
          ) && (
            <StyledInlineAlert
              title={errorMessage.header}
              subtitle={errorMessage.errors.join('. ')}
              type="error"
            />
          )}
          {!!error && (
            <StyledInlineAlert
              title={localizedDefaultError(error.message)}
              type="error"
            />
          )}
          <Form
            // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
            onSubmit={onFormSubmit}
            onValid={markValid}
            onInvalid={markInvalid}
            // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
            onChange={onFormChange}
            initialValues={{
              currentJobTitle: currentJobTitle || '',
              currentEmployer: currentEmployer || '',
              primarySourceOfFunds: primarySourceOfFunds || '',
              usesCoinbaseFor: usesCoinbaseFor || '',
            }}
            /**
             * Want to validate on mount in case form is auto-filled from existing
             * EDP data and is valid. Without this the button would be disabled until
             * user interacted with the form.
             */
            validateOnMount
          >
            <StyledForm>
              <StyledFormSection column>
                {usesView()}
                {fundsView()}
                {employmentStatusView()}
              </StyledFormSection>
            </StyledForm>
            <Button
              testID="basic-kyc-submit-button"
              onPress={handleContinueEvent}
              loading={isLoading}
              block
              disabled={isLoading}
              type="submit"
            >
              <FormattedMessage
                id="IdentityBasicKycForm.submit"
                defaultMessage="Submit"
                description="Text for the button that submits the form"
              />
            </Button>
          </Form>
        </div>
      )}
    </SingleColumnFormContainer>
  );
}

