import { CircleCheckmark, Lock, Shield } from '../../../../assets/icons';
import useSolarisbankSkipKillSwitch from '../../../../hooks/useSolarisbankSkipKillSwitch';
import type { Track } from '../../../../types';
import createAnalytics from '../../../../utils/analytics';
import { Container, Strong, Text } from '../../EDP.styled';
import type { EDPResponse } from '../../EDP.types';
import { SupportedSteps } from '../../hooks/useEDP';
import SkipConfirmationModal from './components/SkipConfirmationModal';

type Props = {
  onError: (e: Error) => void;
  track: Track;
  /**
   * Function to get a pending EDP
   */
  getPendingEDP: () => Promise<EDPResponse>;
  showGermanySkipConfirmation?: boolean;
  skippable?: boolean;
  goToStep: (step: SupportedSteps) => void;
  vendorId?: string;
  setVendorId?: Dispatch<SetStateAction<string>>;
};

let polling: number | NodeJS.Timeout;

function VendorVerification({
  getPendingEDP,
  onError,
  track,
  showGermanySkipConfirmation,
  skippable = false,
  goToStep,
  vendorId,
  setVendorId,
}: Props) {
  const analytics = createAnalytics(track, 'kyc_vendor_verification');
  const [vendorURL, setVendorURL] = useState('');
  const killSolarisbankSkip = useSolarisbankSkipKillSwitch();
  const [showSkipConfirmationModal, { toggleOff }] = useToggler(
    showGermanySkipConfirmation && skippable && !killSolarisbankSkip,
  );

  useEffect(() => {
    analytics.trackView({
      name: 'kyc_vendor_verification_viewed',
      content: 'kyc_vendor_verification_page_viewed',
      context: 'vendor_verification_page',
    });
    if (!vendorURL && !vendorId) {
      pollingFetchNextRequirement();
    }
    return () => {
      if (polling) {
        clearTimeout(polling);
      }
    };
  }, []);

  const handleContinue = useCallback(() => {
    analytics.trackTap({
      name: 'kyc_vendor_verification_continue',
      content: 'kyc_vendor_verification_continue_clicked',
      context: 'redirect_to_vendor',
    });
    if (vendorURL) {
      const finalVendorURL = !killSolarisbankSkip
        ? vendorURL + `/?ssb=${skippable}`
        : vendorURL;
      window.location.assign(finalVendorURL);
    } else {
      goToStep('german_choose_verification');
    }
  }, [analytics, goToStep, killSolarisbankSkip, skippable, vendorURL]);

  const pollingFetchNextRequirement = useCallback(async (): Promise<void> => {
    try {
      const res = await getPendingEDP();
      if (!res) throw new Error('Response missing data');
      const { status, sessionUrl: redirectUrl, referenceId } = res;

      if (status === 'pending') {
        // handling pending status, polling to get redirectUrl
        // pending status will update in few seconds so setting 5 sec delay for setTimeout
        polling = setTimeout(pollingFetchNextRequirement, 5000);
        return;
      }

      if (status === 'has_redirect') {
        if (!vendorURL && redirectUrl) {
          // set redirectUrl and stop polling
          setVendorURL(redirectUrl);
          return;
        }
        polling = setTimeout(pollingFetchNextRequirement, 10000);
        return;
      }

      if (status === 'has_reference') {
        if (!vendorId && referenceId && setVendorId) {
          // set vendorId and stop polling
          setVendorId(referenceId);
          return;
        }
        polling = setTimeout(pollingFetchNextRequirement, 10000);
        return;
      }

      polling = setTimeout(pollingFetchNextRequirement, 5000);
      return;
    } catch (e) {
      analytics.trackOther({
        name: 'kyc_vendor_verification_polling_error',
        content: e.message || '',
        context: 'error',
      });
      onError(e);
    }
  }, [analytics, getPendingEDP, onError, setVendorId, vendorId, vendorURL]);

  return (
    <Container data-testid="vendor-verification">
      {showSkipConfirmationModal && (
        <SkipConfirmationModal analytics={analytics} toggleOff={toggleOff} />
      )}
      <Strong>
        <FormattedMessage
          id="KYC.vendorVerification.header"
          defaultMessage="Verify your identity with Solarisbank"
          description="Title for screen to verify KYC to vendor"
        />
      </Strong>
      <Text>
        <FormattedMessage
          id="KYC.vendorVerification.explanation"
          defaultMessage="Financial regulations require us to verify your ID. This helps prevent someone else from creating a Coinbase account in your name. Coinbase partners with Solarisbank to verify your identity. After this step, you’ll be ready to start trading crypto!"
          description="Text explaining the vendor verification"
        />
      </Text>
      <TextLegal as="p" spacing={3} color="foregroundMuted">
        <FormattedMessage
          id="KYC.vendorVerification.explanation2"
          defaultMessage="If you're unable to verify your identity, you can exit and continue using Coinbase. However, you won't be able to trade crypto until you're verified."
          description="Text explaining users cannot trade crypto until they verify their identity"
        />
      </TextLegal>
      {!vendorURL && !vendorId ? (
        <LoadingIndicator />
      ) : (
        <>
          <TrustInspiringIcons />
          <Box width="100%" spacingTop={5} spacingBottom={3}>
            <Button
              onPress={handleContinue}
              block
              loading={!vendorId && !vendorURL}
            >
              <FormattedMessage
                id="KYC.vendorVerification.continueButton"
                defaultMessage="Continue"
                description="Continue button for vendor verification"
              />
            </Button>
          </Box>
        </>
      )}
    </Container>
  );
}

function TrustInspiringIcons() {
  return (
    <IconRow>
      <IconContainer>
        <Lock />
        <IconText weight="demiBold">
          <FormattedMessage
            id="KYC.vendorVerification.secure"
            defaultMessage="Secure"
            description={`Just the word "Secure"`}
          />
        </IconText>
