type Props = {
  goToStep: (step: SupportedSteps) => void;
  vendorId: string;
  setBankRedirectUrl: Dispatch<SetStateAction<string>>;
  store?: ReturnType<typeof useEDP>;
};

export type PostSolarisSubmitIBANResponse = {
  identification_id: string;
  url: string;
  status: string;
  failure_reason: string;
};

function EnterIBAN({ goToStep, vendorId, setBankRedirectUrl, store }: Props) {
  const { client, track, addApiError } = useOnboardingContext();
  const analytics = createAnalytics(track, 'de_bankident_iban_screen');
  const { formatMessage, locale, formatDate } = useIntl();
  const [isChecked, { toggle }] = useToggler();
  const [iban, setIban] = useState<string | undefined>('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const helpLinkGenerator = useHelpLinkGenerator();
  const [isErrorState, setIsErrorState] = useState(false);
  const [isIBANInvalid, setIsIBANInvalid] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');
  const [edpDetailsConfirmed, setEdpDetailsConfirmed] = useState(true);
  const [
    whyThisInfoVisible,
    { toggleOn: whyThisInfoOn, toggleOff: whyThisInfoOff },
  ] = useToggler();

  const LEARN_MORE_LINK = helpLinkGenerator(
    `coinbase/getting-started/getting-started-with-coinbase/id-doc-verification`,
    `https://help.coinbase.com/en/coinbase/getting-started/getting-started-with-coinbase/id-doc-verification`,
  );
  const FIND_OUT_MORE_LINK = helpLinkGenerator(
    `coinbase/privacy-and-security/data-privacy/what-is-the-gdpr`,
    `https://help.coinbase.com/en/coinbase/privacy-and-security/data-privacy/what-is-the-gdpr`,
  );
  const TERMS_CONDITIONS = `https://w3.swissdigicert.ch/TermsOfUse_Pers_EU-${locale}.pdf`;

  useEffect(
    () => analytics.trackView({ content: 'de_bankident_iban_screen_viewed' }),
    [],
  );

  const submitIban = useCallback(async () => {
    if (!isValidDEIban(iban ?? '')) {
      setIsIBANInvalid(true);
      return;
    }
    analytics.trackTap({
      name: 'de_bankident_iban_screen_submitted',
    });
    setIsSubmitting(true);
    try {
      const res = await client.post<PostSolarisSubmitIBANResponse>(
        '/v3/coinbase.users.vendor_solaris.PublicApi/SubmitIBAN',
        {
          vendor_id: vendorId,
          iban,
        },
      );

      if (res.status === 'created') {
        setBankRedirectUrl(res.url);
        goToStep('german_complete_verification');
      } else {
        throw new Error('SubmitIBAN failed');
      }
    } catch (error) {
      analytics.trackView({ context: 'error' });
      addApiError(error);
      errorLoggers.solarisSubmitIBANPost(error);
      setIsErrorState(true);
      setErrorMessage(error.errorMessage || error.message || '');
    } finally {
      setIsSubmitting(false);
    }
  }, [
    addApiError,
    analytics,
    client,
    goToStep,
    iban,
    setBankRedirectUrl,
    vendorId,
  ]);

  const validateAndFormatIBAN = useCallback(() => {
    if (!isValidDEIban(iban ?? '')) {
      setIsIBANInvalid(true);
      return;
    }
    setIban(formatDeIBAN(iban ?? ''));
  }, [iban]);

  const handleOnChange = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (event: any) => {
      setIsIBANInvalid(false);
      setIban(event.target.value);
    },
    [setIban],
  );

  const confirmEDPDetails = useCallback(() => {
    analytics.trackTap({
      name: 'de_bankident_iban_screen_confirm_edp',
    });
    setEdpDetailsConfirmed(true);
  }, [analytics]);

  const continueWithVideoIdent = useCallback(() => {
    analytics.trackTap({
      name: 'de_bankident_iban_screen_continue_with_video_ident',
    });
    goToStep('german_choose_verification');
  }, [analytics, goToStep]);

  if (!edpDetailsConfirmed && store?.formData.firstName) {
    const { day, month, year } = store.formData;
    const dateOfBirthObj = new Date(Number(year), Number(month), Number(day));
    const dateOfBirthString = formatDate(String(dateOfBirthObj), {
      day: '2-digit',
      month: 'long',
      year: 'numeric',
    });

    return (
      <Container>
        <Box flexDirection="column" width="100%">
          <ScreenHeader
            title={formatMessage(messages.verifyDetails)}
            subtitle={formatMessage(messages.confirmDetailsContent)}
            spacingBottom={3}
          />
          <VStack spacingBottom={3} spacerGap={2}>
            <TextInput
              value={store.formData.firstName}
              label={formatMessage(commonMessages.legalFirstNameField)}
              readOnly={true}
              end={<Icon spacing={1} size="m" name="lock" />}
            />
            <TextInput
              value={store.formData.lastName}
              label={formatMessage(commonMessages.legalLastNameField)}
              readOnly={true}
              end={<Icon spacing={1} size="m" name="lock" />}
            />
            <TextInput
              value={dateOfBirthString}
              label={formatMessage(commonMessages.dob)}
              readOnly={true}
              end={<Icon spacing={1} size="m" name="lock" />}
            />
          </VStack>
        </Box>
        <VStack spacerGap={1} spacingTop={1} width="100%">
          <Button block onPress={confirmEDPDetails}>
            {formatMessage(messages.confirmedDetails)}
          </Button>
          <Button variant="secondary" block onPress={continueWithVideoIdent}>
            {formatMessage(messages.retryVerificationMethod)}
          </Button>
        </VStack>
      </Container>
    );
  }

  if (isErrorState) {
    return (
      <Container>
        <VStack spacingTop={3} alignItems="center">
          <HeroSquare name="bigWarning" />
          <TextTitle3 as="p">{formatMessage(messages.failedTitle)}</TextTitle3>
          <TextBody as="p" align="center" spacingVertical={5}>
            {errorMessage || formatMessage(messages.failedContent)}
          </TextBody>
        </VStack>
        <Spacer />
        <VStack spacerGap={1} spacingTop={1} width="100%">
          {/* eslint-disable-next-line react-perf/jsx-no-new-function-as-prop */}
          <Button block onPress={() => setIsErrorState(false)}>
            {formatMessage(messages.tryAgain)}
          </Button>
          <Button
            variant="secondary"
            block
            // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
            onPress={() => setEdpDetailsConfirmed(false)}
          >
            {formatMessage(messages.verifyDetails)}
          </Button>
          <Button variant="secondary" block onPress={continueWithVideoIdent}>
            {formatMessage(messages.retryVerificationMethod)}
          </Button>
        </VStack>
      </Container>
    );
  }

  return (
    <Container>
      <Box flexDirection="column" spacingVertical={2} width="100%">
        <ScreenHeader
          title={formatMessage(messages.header)}
          subtitle={formatMessage(messages.content, {
            link: (content: React.ReactNode) => [
              <Link
                testID="why-info-link"
                variant="body"
                underline
                onPress={whyThisInfoOn}
              >
                {content as string}
              </Link>,
            ],
          })}
          spacingBottom={3}
        />
        <TextInput
          testID="iban-input"
          value={iban}
          onChange={handleOnChange}
          onBlur={validateAndFormatIBAN}
          label={formatMessage(messages.iban)}
          placeholder={formatMessage(messages.ibanPlaceholder)}
          helperText={
            isIBANInvalid
              ? formatMessage(messages.invalidIBAN)
              : formatMessage(messages.jointNotAccepted)
          }
          variant={isIBANInvalid ? 'negative' : undefined}
        />
      </Box>
      <Box spacingTop={10} spacingBottom={2}>
        <Checkbox testID="iban-terms" onChange={toggle} checked={isChecked}>
          <TextLegal as="span" color="foregroundMuted">
            {formatMessage(messages.termsAndConditions, {
              link: (content: React.ReactNode) => [
                content ? (
