import { useOnboardingContext } from '../../../../../../Context';
import { Analytics, errorLoggers } from '../../../../../../utils/analytics';
import { Strong, Text } from '../../../../EDP.styled';

type Props = {
  analytics: Analytics;
  toggleOff: () => void;
};

function SkipConfirmationModal({ analytics, toggleOff }: Props) {
  const { client, addApiError, refresh } = useOnboardingContext();
  const [isSkipping, setIsSkipping] = useState(false);

  const onSkip = useCallback(() => {
    analytics.trackTap({
      content: 'vendor_verification_web',
      context: 'modal_skip_button',
    });
    setIsSkipping(true);
    client
      .post('/v3/coinbase.public_api.authed.RemediationSkipService/Skip')
      .then(refresh)
      .catch(e => {
        errorLoggers.skip(e);
        addApiError(e);
      })
      .finally(() => {
        setIsSkipping(false);
      });
  }, [analytics, client, refresh, addApiError]);

  const handleOnPress = useCallback(() => {
    analytics.trackTap({
      content: 'vendor_verification_web',
      context: 'modal_dismiss_button',
    });
    toggleOff();
  }, [analytics, toggleOff]);

  return (
    <Modal isOpen close={isSkipping ? undefined : toggleOff}>
      <VStack spacing={2}>
        <Strong>
          <FormattedMessage
            id="KYC.vendorVerification.skipModalTitle"
            defaultMessage="Are you sure you want to skip?"
            description="Title of skip confirmation modal"
          />
        </Strong>
        <Text>
          <FormattedMessage
            id="KYC.vendorVerification.skipModalBody"
            defaultMessage="We'll save your progress for when you come back."
            description="Body of skip confirmation modal"
          />
        </Text>
        <VStack spacerGap={2} spacingTop={4}>
          <Button
            block
            onPress={onSkip}
            loading={isSkipping}
            disabled={isSkipping}
          >
            <FormattedMessage
              id="KYC.vendorVerification.skipModalConfirmButton"
              defaultMessage="Yes, skip"
              description="Confirm button of skip confirmation modal"
            />
          </Button>
          <Button
            block
            onPress={handleOnPress}
            variant="secondary"
            disabled={isSkipping}
          >
            <FormattedMessage
              id="KYC.vendorVerification.skipModalCancelButton"
              defaultMessage="Go back"
              description="Cancel button of skip confirmation modal"
            />
          </Button>
        </VStack>
      </VStack>
    </Modal>
  );
}

