const consentTextCountries = ['DE', 'SG', 'CA'];

type KYCRefreshScreenProps = {
  setShowSkipButton: (show: boolean) => void;
};

export default function KYCRefreshScreen({
  setShowSkipButton,
}: KYCRefreshScreenProps) {
  const { formatDate, formatMessage } = useIntl();
  const [isConfirming, setIsConfirming] = useState(false);
  const { data, confirmKYCRefresh, countryCode, disableKYCRefreshSSNDOBEdit } =
    useKYCRContext();
  const isSGUser = countryCode === 'SG';
  const [isConsentChecked, { toggle }] = useToggler();
  const helpLinkGenerator = useHelpLinkGenerator();
  const isMobileOrTablet = !useScreenMatch('desktop');
  const { restrictionDate, ...dataWithoutRestrictionDate } = data;
  const { isTreatment, trackExposure } = useIsHideSkipButtonKYCRefresh();

  const fieldsWithExpiredStatus = useMemo(() => {
    const allFields = Object.keys(dataWithoutRestrictionDate) as Array<
      keyof typeof dataWithoutRestrictionDate
    >;
    return allFields
      .filter(fieldKey =>
        dataWithoutRestrictionDate[fieldKey]?.status === 'EXPIRED'
          ? fieldKey
          : '',
      )
      .join('|');
  }, [dataWithoutRestrictionDate]);

  // if user is in treatment and has no expired docs, hide edit buttons
  const [editable, setEditable] = useState(
    isTreatment && fieldsWithExpiredStatus.length === 0 ? false : true,
  );

  useEffect(() => {
    if (!editable) {
      setShowSkipButton(false);
    }
    return () => {
      if (!editable) {
        setShowSkipButton(true);
      }
    };
  }, []);

  const learnMoreLinkUrl = useMemo(
    () =>
      helpLinkGenerator(
        'coinbase/getting-started/getting-started-with-coinbase/acting-on-behalf-of-third-parties',
        ThirdPartyConsentInfoUrl,
      ),
    [helpLinkGenerator],
  );

  const showConsentCheckbox = useMemo(
    () => consentTextCountries.includes(countryCode),
    [countryCode],
  );

  const checkboxConsentText = formatMessage(
    isSGUser
      ? messages.sg_consent_checkbox
      : messages.third_party_consent_checkbox,
    {
      learnMore: (str: React.ReactNode) => [
        <Link
          to={learnMoreLinkUrl}
          rel="noopener noreferrer"
          openInNewWindow
          underline={false}
        >
          <span>{str}</span>
        </Link>,
      ],
    },
  );

  useEffect(() => {
    logKYCRefreshScreenView();
    if (!editable) {
      logKYCRefreshExperimentView();
    }
  }, []);

  useEffect(() => {
    if (fieldsWithExpiredStatus) {
      logKYCRefreshScreenWithExpiredIDView(fieldsWithExpiredStatus);
    } else {
      trackExposure();
    }
  }, [fieldsWithExpiredStatus]);

  const handleConfirm = useCallback(async () => {
    setIsConfirming(true);
    await confirmKYCRefresh();
    logKYCRefreshScreenConfirm();
    setIsConfirming(false);
  }, [confirmKYCRefresh]);

  const areAllPersonalInfoItemsEditable = useMemo(() => {
    return [data.address.status, data.dob.status, data.legalName.status].every(
      isEditableStatus,
    );
  }, [data.address.status, data.dob.status, data.legalName.status]);

  const isSubmitButtonDisabled = useMemo(() => {
    if (showConsentCheckbox && !isConsentChecked) {
      return true;
    }
    return (
      isConfirming ||
      (
        Object.keys(
          dataWithoutRestrictionDate,
        ) as (keyof typeof dataWithoutRestrictionDate)[]
      ).filter(key => {
        return shouldDisableKYCRefreshConfirmButton(
          dataWithoutRestrictionDate[key],
        );
      }).length > 0
    );
  }, [
    isConfirming,
    dataWithoutRestrictionDate,
    showConsentCheckbox,
    isConsentChecked,
  ]);

  const handleNoButtonClick = useCallback(() => {
    logKYCRefreshExperimentButton();
    setEditable(true);
  }, []);

  return (
    <VStack width="100%">
      {(disableKYCRefreshSSNDOBEdit || !areAllPersonalInfoItemsEditable) && (
        <Box spacingTop={2}>
          <Box
            spacingHorizontal={3}
            spacingVertical={2}
            offsetBottom={2}
            borderRadius="roundedSmall"
            alignItems="center"
            background="primaryWash"
            width="100%"
          >
            <Icon name="info" size="m" />
            <TextLabel2 as="p" color="primary" spacingStart={2}>
              {formatMessage(messages.name_address_change_info)}
            </TextLabel2>
          </Box>
        </Box>
      )}
      <Row>
        <Col>
          <KYCRListItem
            field={data.legalName}
            label={formatMessage(messages.legal_name)}
            disableEdit={!editable}
          />
          <KYCRListItem
            field={{
              ...data.dob,
              value: formatDate(data.dob.value, {
                day: 'numeric',
                month: 'long',
                year: 'numeric',
              }),
            }}
            label={formatMessage(commonMessages.dob)}
            disableEdit={disableKYCRefreshSSNDOBEdit || !editable}
          />
          <KYCRListItem
            field={data.address}
            label={formatMessage(messages.address)}
            disableEdit={!editable}
          />
          <KYCRIdDigitsListItem field={data.idDigits} disableEdit={!editable} />
          <KYCRListItem
            field={data.nationality}
            label={formatMessage(messages.nationality)}
            disableEdit={!editable}
          />
        </Col>
        <Spacer />
        <Line />
        <Col>
          <KYCRefreshCDDQuestionnaire data={data} disableEdit={!editable} />
        </Col>
      </Row>
      {showConsentCheckbox && (
        <HStack
          justifyContent="center"
          alignItems="center"
          spacerGap={isMobileOrTablet ? 3 : 2}
          spacingBottom={isMobileOrTablet ? 3 : 2}
        >
          <Box alignItems="flex-start">
            <Checkbox
              aria-required
              checked={isConsentChecked}
              onChange={toggle}
            />
          </Box>
          {isMobileOrTablet ? (
            <TextLegal as="span">{checkboxConsentText}</TextLegal>
          ) : (
            <TextBody as="span">{checkboxConsentText}</TextBody>
          )}
        </HStack>
      )}
      <Button block onPress={handleConfirm} disabled={isSubmitButtonDisabled}>
        <FormattedMessage {...messages.confirm_button} />
      </Button>
      {!editable && (
        <Button block transparent onPress={handleNoButtonClick}>
          <FormattedMessage {...messages.no_button} />
        </Button>
      )}
    </VStack>
  );
}

