    id: 'OnboardingVideo.onboarding_video_title',
    defaultMessage: 'How to complete your account setup',
    description: `
    #Component: TextTitle3
    #CharLimit: 40
    #Context: Title for the onboarding video.
    `,
  },

  caption: {
    id: 'OnboardingVideo.caption',
    defaultMessage:
      "We'll walk you through a simple account setup, so you can quickly start exploring the endless possibilities of crypto!",
    description: `
    #Component: TextBody
    #CharLimit: 140
    #Context: Caption for the onboarding video
    `,
