type OnboardingVideoProps = {
  title?: string;
  caption?: string;
};

/*
  This onboarding video component calls the corresponding videos from the assets folder and renders it based the user's
  countryCode.
*/
function OnboardingVideo({ title, caption }: OnboardingVideoProps) {
  const { formatMessage, locale } = useIntl();
  const errorVitalsClient = getErrorVitalsClient();

  const { user } = useOnboardingContext();

  const { video, loading, error } = useOnboardingVideo(
    user.countryCode,
    locale,
  );
  const {
    analytics: { logMeasurement },
  } = useOnboardingContext();

  useLogPageViewOnMount('onboarding_video_rendered');

  const handleVideoPlay = useCallback(() => {
    logMeasurement('onboarding_video_played');
  }, [logMeasurement]);

  const handleVideoEnd = useCallback(() => {
    logMeasurement('onboarding_video_watched_to_end');
  }, [logMeasurement]);

  if (error !== null) {
    errorVitalsClient?.logError(error, {
      severity: 'error',
      context: 'OnboardingVideo component',
      isHandled: false,
    });
    throw error;
  }

  return (
    <VStack
      spacing={5}
      alignContent="center"
      maxWidth="524px"
      style={{ position: 'relative', top: '202px' }}
    >
      <Box justifyContent="center">
        <TextTitle3 as="h3" align="center">
          {title ? title : formatMessage(messages.onboarding_video_title)}
        </TextTitle3>
      </Box>
      <Box justifyContent="center" style={{ position: 'relative', top: '4px' }}>
        <TextBody as="p" align="center" color="foregroundMuted">
          {caption ? caption : formatMessage(messages.caption)}
        </TextBody>
      </Box>
      <Box
        justifyContent="center"
        style={{ position: 'relative', top: '32px' }}
      >
        {loading ? (
          <Fallback width={325} height={200} shape="squircle" />
        ) : (
          <video
            controls
            width="100%"
            style={{ borderRadius: '8px' }}
            onPlay={handleVideoPlay}
            onEnded={handleVideoEnd}
          >
            <source src={video} type="video/webm" />
          </video>
        )}
      </Box>
    </VStack>
  );
}

export default memo(OnboardingVideo);

