type UserAgreementType = {
  value: boolean;
  onChange: (value: boolean) => void;
  color?: PaletteForeground;
};

export function UserAgreement({ value, onChange, color }: UserAgreementType) {
  const { formatMessage } = useIntl();
  const isPhone = useScreenMatch('phone');
  const isPhoneLarge = useScreenMatch('phone_large');
  const isPhoneSmall = useScreenMatch('phone_small');
  const isTablet = useScreenMatch('tablet');
  const isMobileOrTablet = isPhone || isPhoneLarge || isPhoneSmall || isTablet;

  const {
    user: { countryCode },
  } = useOnboardingContext();
  const showGermanyContent = countryCode === 'DE';
  const showSingaporeContent = countryCode === 'SG';
  const showUnitedStatesContent = countryCode === 'US';
  const helpLinkGenerator = useHelpLinkGenerator();

  const learnMoreLinkUrl = useMemo(
    () =>
      helpLinkGenerator(
        'coinbase/getting-started/getting-started-with-coinbase/acting-on-behalf-of-third-parties',
        'https://help.coinbase.com/en/coinbase/getting-started/getting-started-with-coinbase/acting-on-behalf-of-third-parties',
      ),
    [helpLinkGenerator],
  );

  const countrySpecificAgreementText = useMemo(() => {
    if (showGermanyContent) {
      return messages.deAcceptTermsOfUse;
    } else if (showSingaporeContent) {
      return messages.sgAcceptTermsOfUse;
    } else if (showUnitedStatesContent) {
      return messages.usUserAgreementMessage;
    } else return messages.userAgreementMessage;
  }, [showGermanyContent, showSingaporeContent, showUnitedStatesContent]);

  const userAgreementText = formatMessage(countrySpecificAgreementText, {
    age: LEGAL_AGE_TO_TRADE,
    userAgreementLink: (str: React.ReactNode) => [
      <Link
        to="/legal/user_agreement"
        target="_blank"
        rel="noopener noreferrer"
      >
        <span>{str}</span>
      </Link>,
    ],
    learnMoreLink: (str: React.ReactNode) => [
      <Link
        to={learnMoreLinkUrl}
        rel="noopener noreferrer"
        openInNewWindow
        underline={false}
      >
        <span>{str}</span>
      </Link>,
    ],
    break: () => [<br></br>],
  });

  const handleOnChange: React.ChangeEventHandler<HTMLInputElement> =
    useCallback(e => onChange(e.target.checked), [onChange]);

  return (
    <HStack
      gap={isMobileOrTablet ? 3 : 2}
      spacingBottom={isMobileOrTablet ? 3 : 2}
    >
      <Box alignItems="flex-start" spacingTop={0.5}>
        <Checkbox
          testID="signup-agreement-checkbox"
          aria-required
          checked={value}
          onChange={handleOnChange}
        />
      </Box>
      {isMobileOrTablet ? (
        <TextLegal as="span" color={color}>
          {userAgreementText}
        </TextLegal>
      ) : (
        <TextBody as="span" color={color}>
          {userAgreementText}
        </TextBody>
      )}
    </HStack>
  );
}

import { useState, useEffect, useCallback } from 'react';
import invariant from 'invariant';
import { useIntl, defineMessages, FormattedMessage } from 'react-intl';
import styled from 'styled-components';

import { Button } from '@cbhq/cds-web/buttons/Button';
import { Spacer } from '@cbhq/cds-web/layout/Spacer';
import { TextBody } from '@cbhq/cds-web/typography/TextBody';

import OnboardingStep from '../../components/OnboardingStep';
import { useOnboardingContext } from '../../Context';
import { useLogPageViewOnMount } from '../../hooks/useLogPageViewOnMount';
import usePOA, { type VerifiedPOA } from '../../hooks/usePOA';
import { errorLoggers } from '../../utils/analytics';

const i18nKey = 'ProofOfAddressConfirm';

const messages = defineMessages({
  title: {
    id: `${i18nKey}.title`,
    defaultMessage: 'Is this your address?',
    description: `
    #CharLimit: 120
    #Component:Header
    #Context:Title for the Proof of Address Confirm page`,
  },
});

type AddressLinesProps = {
  lines?: string[];
};

function AddressLines({ lines }: AddressLinesProps) {
  return (
    <>
      {lines &&
        lines.map((line, idx) => <AddressLine key={idx}>{line}</AddressLine>)}
    </>
  );
}

function AddressConfirm() {
  const {
    client,
    refresh,
    addApiError,
    analytics: { logButtonClick },
    verificationMetadata,
  } = useOnboardingContext();
  const canRetry = verificationMetadata?.canRetry;
  const [isSubmittingConfirm, setIsSubmittingConfirm] = useState(false);
  const [isSubmittingReview, setIsSubmittingReview] = useState(false);
  const [isSubmittingReject, setIsSubmittingReject] = useState(false);
  const [poa, setPoa] = useState<VerifiedPOA>({} as VerifiedPOA);
  const { fetchVerifiedPOA } = usePOA({
    client,
  });

  const fetchPOAs = useCallback(async () => {
    try {
      const verifiedPOA = await fetchVerifiedPOA();
      if (!verifiedPOA) {
        errorLoggers.missingData('poa_confirm');
      }

      invariant(verifiedPOA, 'No addresses on record');

      setPoa(verifiedPOA);
    } catch (e) {
      errorLoggers.poaAddress(e);

      addApiError(e);
    }
  }, [addApiError, fetchVerifiedPOA]);

  useLogPageViewOnMount('upload_proof_of_address_confirmation_viewed');

  useEffect(() => {
    fetchPOAs();
  }, []);

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleConfirm = () => {
    logButtonClick('upload_proof_of_address_confirmation_tapped_confirm');
    setIsSubmittingConfirm(true);
    client
      .put(`/v2/proof-of-addresses/${poa.id}/confirm`, {})
      .catch(e => {
        errorLoggers.poaConfirm(e, 'confirm');
        addApiError(e);
      })
      .then(refresh)
      .catch(e => {
        errorLoggers.nextRequirement(e, 'poa');
        addApiError(e);
      })
      .finally(() => setIsSubmittingConfirm(false));
  };

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleReject = () => {
    logButtonClick('upload_proof_of_address_confirmation_tapped_reject');
    setIsSubmittingReject(true);
    client
      .put(`/v2/proof-of-addresses/${poa.id}/reject`, {})
      .catch(e => {
        errorLoggers.poaConfirm(e, 'reject');
        addApiError(e);
      })
      .then(refresh)
      .catch(e => {
        errorLoggers.nextRequirement(e, 'poa');
        addApiError(e);
      })
      .finally(() => setIsSubmittingReject(false));
  };

  // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
  const handleManualReview = () => {
    logButtonClick('upload_proof_of_address_confirmation_tapped_manual_review');
    setIsSubmittingReview(true);
    client
      .put('/v2/user/manual-address-review', {})
      .catch(e => {
        errorLoggers.poaConfirm(e, 'manual');
        addApiError(e);
      })
      .then(refresh)
      .catch(e => {
        errorLoggers.nextRequirement(e, 'poa');
        addApiError(e);
      })
      .finally(() => setIsSubmittingReview(false));
  };

  const isButtonDisabled = (): boolean => {
    return isSubmittingConfirm || isSubmittingReview || isSubmittingReject;
  };

  const { formatMessage } = useIntl();

  return (
    <OnboardingStep
      header={{
        title: formatMessage(messages.title),
      }}
      width="375px"
    >
      <TextBody as="p" spacingBottom={3}>
        <FormattedMessage
          id={`${i18nKey}.subtitle`}
          defaultMessage="Please confirm that the address below matches the address listed on your driver’s license and utility bill."
          description="Subtitle explaining why the information is collected"
        />
      </TextBody>
      <Label>
        <FormattedMessage
          id={`${i18nKey}.citizenshipLabel`}
          defaultMessage="Address:"
          description="Label for the user address"
        />
      </Label>
      <AddressLines lines={poa.addressArray} />
      <Spacer as="div" vertical={5} />
      <Button
        disabled={isButtonDisabled()}
        loading={isSubmittingConfirm}
        block
        onPress={handleConfirm}
      >
        <FormattedMessage
          id={`${i18nKey}.confirmButton`}
          defaultMessage="Yes, looks good"
          description="Button to confirm the user's address"
        />
      </Button>
      <Spacer as="div" vertical={2} />
      {canRetry ? (
        <Button
          variant="secondary"
          disabled={isButtonDisabled()}
          loading={isSubmittingReject}
          block
          onPress={handleReject}
        >
          <FormattedMessage
            id={`${i18nKey}.rejectButton`}
            defaultMessage="No, upload another document"
            description="Button to reject and reupload user's address"
          />
        </Button>
      ) : (
        <Button
          variant="secondary"
          disabled={isButtonDisabled()}
          loading={isSubmittingReview}
          block
          onPress={handleManualReview}
        >
          <FormattedMessage
            id={`${i18nKey}.manualReviewButton`}
            defaultMessage="No, it’s incorrect (~5 day delay)"
            description="Button to submit the user's address for manual review"
          />
        </Button>
      )}
    </OnboardingStep>
  );
}

