import ListSelectItem from '@cb/shared/components/QuestionSelect/components/ListSelectItem';
import { useIsMobile } from '@cb/shared/utils';
import { IconButton } from '@cbhq/cds-web/buttons';
import { Box, HStack, VStack } from '@cbhq/cds-web/layout';

import { Spinner } from '../../../components/Spinner';
import { useOnboardingContext } from '../../../Context';
import { useLogPageViewOnMount } from '../../../hooks/useLogPageViewOnMount';
import CAAppropriatenessAssessmentForm, { ComplianceQuestion } from '../form';
import { MIN_WIDTH } from './constants';

export type Props = {
  questions: ComplianceQuestion[];
  handleSubmit: (answers: Record<string, string>) => Promise<void>;
  goToScreen: (screen: string) => void;
  isExistingUserUpdate: boolean;
};

function CAAQuestions({
  questions,
  handleSubmit,
  goToScreen,
  isExistingUserUpdate,
}: Props) {
  const {
    analytics: { logButtonClick },
  } = useOnboardingContext();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const isMobile = useIsMobile();
  const { complianceAnswers, currentQuestionIndex, editInfo } = useFields(
    CAAppropriatenessAssessmentForm,
  );
  const { isEditRedirect } = editInfo.value;
  const { value: answersData } = complianceAnswers;
  const question = useMemo(
    () => questions[currentQuestionIndex.value],
    [questions, currentQuestionIndex.value],
  );
  const isSubmit = useMemo(
    () =>
      currentQuestionIndex.value === questions.length - 1 &&
      !isExistingUserUpdate,
    [questions, currentQuestionIndex.value, isExistingUserUpdate],
  );
  const { key, title, subtitle, options } = question;

  useLogPageViewOnMount('caa_questions_page_view', {
    isExistingUser: isExistingUserUpdate,
    questionIndex: currentQuestionIndex.value,
  });

  const handleGoBack = useCallback(() => {
    if (currentQuestionIndex.value > 0) {
      currentQuestionIndex.onChange(currentQuestionIndex.value - 1);
    } else goToScreen('intro');
  }, [currentQuestionIndex, goToScreen]);

  const handleOnPress = useCallback(
    async (value: unknown) => {
      if (typeof value === 'string') {
        const newAnswers = { ...answersData };
        newAnswers[key] = value;
        complianceAnswers.onChange(newAnswers);

        logButtonClick('caa_question_answered', {
          questionIndex: currentQuestionIndex.value,
          isExistingUser: isExistingUserUpdate,
        });

        if (isSubmit) {
          setIsSubmitting(true);
          await handleSubmit(newAnswers);
          setIsSubmitting(false);
        } else {
          editInfo.onChange({ isEditRedirect, hasBeenEdited: isEditRedirect });
          if (isEditRedirect) {
            goToScreen('review');
          } else currentQuestionIndex.onChange(currentQuestionIndex.value + 1);
        }
      }
    },
    [
      answersData,
      key,
      complianceAnswers,
      logButtonClick,
      currentQuestionIndex,
      isExistingUserUpdate,
      isSubmit,
      handleSubmit,
      editInfo,
      isEditRedirect,
      goToScreen,
    ],
  );

  return (
    <VStack minWidth={isMobile ? '100%' : MIN_WIDTH}>
      {isSubmitting ? (
        <HStack
          minHeight="100%"
          width="100%"
          alignItems="center"
          justifyContent="center"
          testID="spinner"
        >
          <Spinner />
        </HStack>
      ) : (
        <Box position="relative" offsetTop={2} testID="question-select">
          {!isExistingUserUpdate && (
            <Box position="absolute" left="-64px" top="8px">
              <IconButton
                variant="secondary"
                name="backArrow"
                testID="back-arrow"
                onPress={handleGoBack}
              />
            </Box>
          )}
          <QuestionSelect
            value={answersData[key]}
            onChange={handleOnPress}
            title={title}
            description={parseMarkdown(subtitle)}
            isSmallerTitle
          >
            {options?.map(({ title, subtitle, value }) => {
              return (
                <ListSelectItem
                  key={value}
                  title={title}
                  description={subtitle}
                  value={value}
                  multiline
                />
              );
            })}
          </QuestionSelect>
        </Box>
      )}
    </VStack>
  );
}

export default memo(CAAQuestions);

