import { useMemo, useCallback, useState } from 'react';
import { memoize } from 'lodash';
import { injectIntl, IntlFormatters, IntlShape } from 'react-intl';

import DaySelect from '@cb/shared/components/DaySelect';
import Form from '@cb/shared/components/Form';
import MonthSelect from '@cb/shared/components/MonthSelect';
import YearSelect from '@cb/shared/components/YearSelect';
import { countries } from '@cb/shared/utils';
import { required, ValidatorFunction } from '@cb/shared/validators';
import { useToggler } from '@cbhq/cds-common';
import { Button } from '@cbhq/cds-web/buttons/Button';
import { Spacer } from '@cbhq/cds-web/layout/Spacer';

import { commonMessages } from '../../commonOnboardingMessages';
import { DOBStatuses } from '../../components/EDP/EDP.types';
import { calculateAge, getDOBStatus } from '../../components/EDP/EDP.utils';
import OnboardingStep from '../../components/OnboardingStep';
import { useOnboardingContext } from '../../Context';
import { useLogPageViewOnMount } from '../../hooks/useLogPageViewOnMount';
import { APIError } from '../../types';
import { errorLoggers } from '../../utils/analytics';
import { messages } from './DOB.messages';
import {
  StyledInlineAlert,
  FormGroup,
  DateOfBirthFieldSet,
  DateOfBirthLegend,
  RowSection,
  CountryFieldLabeledSection,
  StyledValidatedInputBase,
} from './DOB.styled';

type DOBProps = {
  intl: IntlShape;
};

type DOBFormData = {
  year?: string;
  month?: string;
  day?: string;
};

const getRequiredValidator = memoize(
  (
    field: string,
    formatMessage: IntlFormatters['formatMessage'],
  ): Array<[ValidatorFunction, string | undefined | null]> => {
    return [
      [
        required,
        formatMessage(messages.requiredError, {
          field,
        }),
      ],
    ];
  },
);

export function DOB({ intl }: DOBProps) {
  const { formatMessage } = intl;
  const [formData, setFormData] = useState<DOBFormData>({});
  const [error, setError] = useState<APIError>();

  const [valid, { toggleOn: markValid, toggleOff: markInvalid }] =
    useToggler(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const {
    client,
    addApiError,
    analytics: { logButtonClick },
    user,
    refresh,
  } = useOnboardingContext();
  const country = useMemo(
    () => countries.find(c => c.code === user.countryCode) ?? countries[0],
    [user.countryCode],
  );

  const dateOfBirthView = useCallback((): JSX.Element => {
    const useInternationalDOBFormat = !['US', 'CA', 'PH'].includes(
      user.countryCode,
    );
    const dayView = (
      <DaySelect
        avoidResizingOptions
        name="day"
        validators={getRequiredValidator(
          formatMessage(commonMessages.day),
          formatMessage,
        )}
      />
    );
    const monthView = (
      <MonthSelect
        avoidResizingOptions
        name="month"
        validators={getRequiredValidator(
          formatMessage(commonMessages.month),
          formatMessage,
        )}
      />
    );
    const yearView = (
      <YearSelect
        avoidResizingOptions
        name="year"
        validators={getRequiredValidator(
          formatMessage(commonMessages.year),
          formatMessage,
        )}
      />
    );
    return (
      <DateOfBirthFieldSet>
        <DateOfBirthLegend>
          {formatMessage(commonMessages.dob)}
        </DateOfBirthLegend>
        <RowSection>
          {useInternationalDOBFormat && dayView}
          {monthView}
          {!useInternationalDOBFormat && dayView}
          {yearView}
        </RowSection>
      </DateOfBirthFieldSet>
    );
  }, [formatMessage, user.countryCode]);

  const isDOBValid = useCallback(
    (dobStatus: DOBStatuses): boolean => {
      if (dobStatus === DOBStatuses.underage) {
        setError({
          name: 'invalid dob',
          message: formatMessage(messages.minAgeError),
        });
        return false;
      }
      if (dobStatus === DOBStatuses.invalid) {
        setError({
          name: 'invalid dob',
          message: formatMessage(messages.maxAgeError),
        });
        return false;
      }
      return true;
    },
    [formatMessage],
  );

  useLogPageViewOnMount('dob_viewed');

  const onFormChange = useCallback(
    (data: DOBFormData) => {
      setFormData(prevData => ({
        ...prevData,
        ...data,
      }));
      setError(undefined);
    },
    [setFormData, setError],
  );

  const handleSubmit = useCallback(() => {
    logButtonClick('dob_submitted');

    const dobStatus = getDOBStatus(
      calculateAge({
        month: Number(formData.month),
        day: Number(formData.day),
        year: Number(formData.year),
      }),
    );
    if (!isDOBValid(dobStatus)) {
      return;
    }

    setError(undefined);
    setIsSubmitting(true);

    client
      .post('/v1/user-info', {
        dob_month: formData.month,
        dob_day: formData.day,
        dob_year: formData.year,
      })
      .then(refresh)
      .catch(err => {
        errorLoggers.dobSubmit(err);

        addApiError(err);
      })
      .finally(() => setIsSubmitting(false));
  }, [
    addApiError,
    client,
    formData.day,
    formData.month,
    formData.year,
    isDOBValid,
    refresh,
    logButtonClick,
  ]);

  return (
    <OnboardingStep
      header={{
        title: formatMessage(messages.title),
      }}
      alignItems="flex-start"
    >
      {!!error && <StyledInlineAlert title={error.message} type="error" />}
      <Form
        onValid={markValid}
        onInvalid={markInvalid}
        // @ts-expect-error: 2022-01-17: Whitelisted type error. To be corrected after typescript migration
        onChange={onFormChange}
        initialValues={{
          country: formatMessage(country.name),
        }}
      >
        <FormGroup>{dateOfBirthView()}</FormGroup>
        <FormGroup>
          <CountryFieldLabeledSection
            label={formatMessage(messages.country)}
            labelFor="country"
            auto
          >
            <StyledValidatedInputBase
              id="country"
              name="country"
              size={4}
              autoFocus
              validators={[]}
              disabled
            />
          </CountryFieldLabeledSection>
        </FormGroup>
        <Spacer as="div" vertical={3} />
        <Button
          block
          disabled={isSubmitting || !valid}
          loading={isSubmitting}
          data-testid="dob-submit-button"
          onPress={handleSubmit}
        >
          {formatMessage(commonMessages.continue)}
        </Button>
      </Form>
    </OnboardingStep>
  );
}

