import { useEffect, useCallback, useState, useMemo } from 'react';
import { useIntl, FormattedMessage } from 'react-intl';
import styled from 'styled-components';

import Text from '@cb/shared/components/Text';
// Whitelisted non-CDS import: please fix

import { notifyError } from '@cb/shared/utils';
import countries from '@cb/shared/utils/countries';
import { Button } from '@cbhq/cds-web/buttons';
import { triggerResearchEventOnUserAction } from '@cbhq/user-research-web';

import KYCRefreshScreen, { KYCRContext } from '../../components/KYCRefresh';
import type { KYCRefreshServiceResponse } from '../../components/KYCRefresh';
import { messages } from '../../components/KYCRefresh/KYCR.utils';
import OnboardingStep from '../../components/OnboardingStep';
import { Spinner } from '../../components/Spinner';
import { useOnboardingContext } from '../../Context';
import useApiClient from '../../hooks/useApiClient';
import { useDisableKYCRefreshSSNDOBEdit } from '../../hooks/useDisableKYCRefreshSSNDOBEdit';
import { errorLoggers } from '../../utils/analytics';
import type { KYCRefreshProps } from './KYCRefresh.types';
import { handleKYCRefreshItemEditButtonClick } from './KYCRefresh.utils';

interface Status<T> {
  status: T;
}

type StateLoading = Status<'loading'>;

type StateError = Status<'error'>;

type StateSuccess = Status<'success'> & {
  data: KYCRefreshServiceResponse;
};

type State = StateLoading | StateError | StateSuccess;

const USER_RESEARCH_VIEWED_KYC_REFRESH_CONFIRMATION_EVENT =
  'Viewed KYC Refresh Confirmation Screen';

const USER_RESEARCH_CONFIRMED_KYC_REFRESH_EVENT = 'Confirmed KYC Refresh';

function KYCRefresh(props: KYCRefreshProps) {
  const {
    addApiError,
    refresh,
    user: { countryCode },
  } = useOnboardingContext();
  const client = useApiClient();
  const disableKYCRefreshSSNDOBEdit = useDisableKYCRefreshSSNDOBEdit(
    countryCode,
    true,
  );

  const [state, setState] = useState<State>({
    status: 'loading',
  });

  const loadAndSetData = useCallback(() => {
    setState({
      status: 'loading',
    });

    let canceled = false;
    client
      .get<KYCRefreshServiceResponse>(
        '/v3/coinbase.public_api.authed.refresh.RefreshService/GetKycRefresh',
      )
      .then((data: KYCRefreshServiceResponse) => {
        if (canceled) {
          return;
        }

        setState({
          status: 'success',
          data,
        });
      })
      .catch(e => {
        if (canceled) {
          return;
        }

        setState({
          status: 'error',
        });
        errorLoggers.kycRefreshData(e);
        addApiError(e);
        notifyError(new Error('Failed to retrieve user KYC refresh data'), {
          owner: 'onboarding',
          context: 'KYCRefreshError',
        });
      });
    return () => {
      canceled = true;
    };
  }, [addApiError, client]);

  useEffect(() => {
    if (state.status === 'loading') {
      return loadAndSetData();
    } else if (state.status === 'success') {
      triggerResearchEventOnUserAction(
        USER_RESEARCH_VIEWED_KYC_REFRESH_CONFIRMATION_EVENT,
      );
    }
  }, [state.status]);

  const { formatDate, formatMessage } = useIntl();

  const getCountryByLocalizedName = useCallback(
    (localizedName: string) => {
      const country = countries.find(
        c => formatMessage(c.name) === localizedName,
      );
      if (!country) {
        // it's possible that the localized country returned API is different from returned by
        // formatMessage(c.name) because user's locale on FE is different from user locale set on BE.
        // We want to only log error here and not crash the app in this case
        errorLoggers.kycRefreshNationalityPrefillError(
          `${localizedName} not found in countries list`,
        );
        return '';
      }
      return country.code;
    },
    [formatMessage],
  );

  const kycRefreshNationalityCode = useMemo(() => {
    if (state.status === 'success') {
      // we're getting error while reading state.data.nationality.value: https://app.amplitude.com/analytics/coinbase/chart/new/3qd0exqr
      // Ideally, this should never happen, but we're adding a check here to prevent the app from crashing
      // and logging to debug it.
      if (state.data?.nationality?.value) {
        return getCountryByLocalizedName(state.data.nationality.value);
      } else {
        const error = new Error(
          'nationality value is missing from KYC refresh data',
        );
        errorLoggers.kycRefreshData(error);
        notifyError(error, {
          owner: 'onboarding',
          context: 'KYCRefreshError',
        });
      }
    }
  }, [state, getCountryByLocalizedName]);

  function renderSuccess(successState: StateSuccess) {
    const content = (
      <KYCRContext.Provider
        value={{
          countryCode,
          data: successState.data,
          onEdit: editId => {
            handleKYCRefreshItemEditButtonClick({
              editId,
              data: successState.data,
              kycRefreshCallbacks: props,
              transformedData: {
                nationalityCode: kycRefreshNationalityCode,
              },
            });
          },
          confirmKYCRefresh: () =>
            client
              .post(
                '/v3/coinbase.public_api.authed.refresh.RefreshService/UpdateKycRefresh',
                { confirmed: true },
              )
              .catch(e => {
                errorLoggers.kycRefresh(e);
                addApiError(e);
              })
              .then(() => {
                triggerResearchEventOnUserAction(
                  USER_RESEARCH_CONFIRMED_KYC_REFRESH_EVENT,
                );

                return refresh();
              })
              .catch(e => {
                errorLoggers.nextRequirement(e, 'kyc-refresh');
                addApiError(e);
              }),
          disableKYCRefreshSSNDOBEdit,
        }}
      >
        <KYCRefreshScreen setShowSkipButton={props.setShowSkipButton} />
      </KYCRContext.Provider>
    );

    return (
      <OnboardingStep
        header={{
          title: formatMessage(messages.header),
          subtitle: formatMessage(messages.description, {
            date: formatDate(successState.data.restrictionDate, {
              day: 'numeric',
              month: 'long',
            }),
          }),
        }}
        width="auto"
      >
        {content}
      </OnboardingStep>
    );
  }

  switch (state.status) {
    case 'loading':
      return (
        <LoadingContainer>
          <Spinner />
        </LoadingContainer>
      );
    default:
    case 'error':
      return (
        <OnboardingStep
          header={{
            title: formatMessage(messages.error_header),
          }}
          width="auto"
        >
          <MarginBottom>
            <Text>
              <FormattedMessage {...messages.error_description} />
            </Text>
          </MarginBottom>

          <Button onPress={loadAndSetData}>
            <FormattedMessage {...messages.reload_button} />
          </Button>
        </OnboardingStep>
      );
    case 'success':
      return renderSuccess(state);
  }
}

const LoadingContainer = styled.div`
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 600px;
  min-width: ${({ theme }) => (theme.isMobile ? '400px' : '853px')};
  padding: ${({ theme }) => theme.size.huge};
`;

