        <Route path={RfiPepRoutes.multiHit}>
          <MultiHitScreen
            onContinue={onContinueMultiHitScreen}
            loading={loading}
          />
        </Route>
        <Route path={RfiPepRoutes.multiHitForm}>
          <MultiHitForm onContinue={onContinueMultiHitForm} loading={loading} />
        </Route>
        <Route path={RfiPepRoutes.success}>
          <RfiPepSuccess onContinue={onContinueSuccess} />
        </Route>
      </Switch>
    </OnboardingStep>
  );
}

