import React, { memo, useCallback } from 'react';
import { noop } from 'lodash';
import styled from 'styled-components';

import { theme } from '../../shared/styles/theme';

const TOGGLER_SIZE = 30;
const TOGGLER_WIDTH = 54;
const TOGGLER_PADDING = 2;
const ANIMATION_TIME = 200;

type Props = {
  toggled: boolean;
  onToggle?: (isToggled: boolean) => void;
  onClick?: () => void;
  disabled?: boolean;
};

function Toggler({ onClick, toggled, onToggle, disabled }: Props) {
  const handleClick = useCallback(() => {
    if (onClick) onClick();
    if (onToggle) {
      onToggle(!toggled);
    }
  }, [toggled, onToggle, onClick]);

  return (
    <Container
      toggled={toggled}
      onClick={disabled ? noop : handleClick}
      disabled={disabled}
    >
      <Switch toggled={toggled} />
    </Container>
  );
}

export const Container = styled.div<{ disabled?: boolean; toggled?: boolean }>`
  user-select: none;
  -webkit-touch-callout: none;
  cursor: ${({ disabled }) => (disabled ? 'not-allowed' : 'pointer')};
  width: ${TOGGLER_WIDTH}px;
  position: relative;
  border: 0;
  transition: background-color ${ANIMATION_TIME}ms;
  background-color: ${p =>
    p.toggled ? theme.color.buttonFill : theme.color.accessoryInactive};
  border-radius: ${TOGGLER_SIZE}px;
  height: ${TOGGLER_SIZE}px;
`;

const Switch = styled.div<{
  toggled?: boolean;
}>`
  position: absolute;
  top: 2px;
  left: 0;
  background-color: ${theme.color.white};
  text-align: center;
  font-weight: 500;
  box-shadow: ${theme.boxShadow.hover};
  transition: transform ${ANIMATION_TIME}ms;
  width: ${TOGGLER_SIZE - TOGGLER_PADDING * 2}px;
  height: ${TOGGLER_SIZE - TOGGLER_PADDING * 2}px;
  border-radius: ${TOGGLER_SIZE - TOGGLER_PADDING * 2}px;
  transform: translateX(
    ${p =>
      p.toggled
        ? TOGGLER_WIDTH - TOGGLER_SIZE + TOGGLER_PADDING
        : TOGGLER_PADDING}px
  );
`;

export default memo(Toggler);

