import React, { memo, useMemo, useCallback, ReactNode } from 'react';
import { MessageDescriptor, useIntl } from 'react-intl';
import { useHistory } from 'react-router-dom';
import styled from 'styled-components';

import { useToggler } from '@cbhq/cds-web';
import { Collapsible } from '@cbhq/cds-web/collapsible';
import { Icon } from '@cbhq/cds-web/icons/Icon';
import { HStack, VStack, Box } from '@cbhq/cds-web/layout';
import { TextTitle3, TextBody, Link } from '@cbhq/cds-web/typography';
import { ActionType, ComponentType, logEvent } from '@cbhq/client-analytics';
import { graphql, useFragment } from '@cbhq/data-layer';

import { removeFalsyValues } from '../../../Web3/utils/dapps';
import { AssetRiskCategoriesFragment$key } from './__generated__/AssetRiskCategoriesFragment.graphql';
import { Category } from './Category';
import { messages } from './messages';

// Supported asset links for the asset risk categories details, allows us to link to the asset screen
const assets: Record<string, string> = {
  USDC: 'usdc',
  USDT: 'tether',
  UNI: 'uniswap',
  AAVE: 'aave',
  cbETH: 'coinbase-wrapped-staked-eth',
  WBTC: 'wrapped-bitcoin',
  DOGE: 'dogecoin',
  SHIB: 'shiba-inu',
  ETH: 'ethereum',
  ATOM: 'cosmos',
};

const ADP_ASSET_CATEGORY_INVESTMENTS_RISK =
  'adp_asset_investment_category_risks';

type Props = {
  queryRef: AssetRiskCategoriesFragment$key;
  renderLoggedOutLayout?: (children: ReactNode) => ReactNode | null;
  hideBorder?: boolean;
};

function AssetRiskCategories({
  queryRef,
  renderLoggedOutLayout,
  hideBorder,
}: Props) {
  const isLoggedOut = Boolean(renderLoggedOutLayout);

  const data = useFragment(
    graphql`
      fragment AssetRiskCategoriesFragment on Query {
        assetBySlug(slug: $assetSlug) {
          slug
          ukFinancialPromotionCategories
        }
      }
    `,
    queryRef,
  );

  const asset = data?.assetBySlug ?? null;
  const { formatMessage } = useIntl();
  const [isAssetRiskContainerVisible, { toggle: toggleAssetRiskContainer }] =
    useToggler(true);

  const history = useHistory();
  const goToAsset = useCallback(
    (slug: string) => {
      history.push('/price/' + slug);
    },
    [history],
  );

  const list = useCallback((...chunks: React.ReactNode[]) => {
    return (
      <HStack alignItems="flex-start">
        <TextBody as="p" color="foregroundMuted" spacingEnd={1}>
          {'\u2022'}
        </TextBody>
        <TextBody as="p" color="foregroundMuted">
          {chunks}
        </TextBody>
      </HStack>
    );
  }, []);

  const listIndented = useCallback((...chunks: React.ReactNode[]) => {
    return (
      <HStack alignItems="flex-start" spacingStart={2}>
        <TextBody as="p" color="foregroundMuted" spacingEnd={1}>
          {'\u25E6'}
        </TextBody>
        <TextBody as="p" color="foregroundMuted">
          {chunks}
        </TextBody>
      </HStack>
    );
  }, []);

  const urlLink = useCallback(
    (...chunks: React.ReactNode[]) => {
      return <Link to={chunks.join?.()}>{formatMessage(messages.here)}</Link>;
    },
    [formatMessage],
  );

  const assetLink = useCallback(
    (...chunks: React.ReactNode[]) => {
      const slug = assets[chunks.join?.()];
      // Don't link to the asset if we are already on the asset screen
      if (slug && asset?.slug !== slug) {
        return (
          // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
          <Link color="foregroundMuted" onPress={() => goToAsset(slug)}>
            {chunks.join?.()}
          </Link>
        );
      }

      return chunks.join?.();
    },
    [asset?.slug, goToAsset],
  );

  const formatCategory = useCallback(
    ({
      id,
      title,
      summary,
      details,
    }: {
      id: string;
      title: MessageDescriptor;
      summary: MessageDescriptor;
      details: MessageDescriptor;
    }) => {
      return {
        id,
        title: formatMessage(title),
        summary: formatMessage(summary, {
          assetLink,
        }),
        details: formatMessage(details, {
          list,
          listIndented,
          urlLink,
          assetLink,
        }),
      };
    },
    [assetLink, formatMessage, list, listIndented, urlLink],
  );

  const assetRiskCategories = useMemo(() => {
    // Uk financial promotions are enabled, so we can show the categories
    const ukFinancialPromotionCategories = removeFalsyValues(
      asset?.ukFinancialPromotionCategories ?? [],
    ) as (string | null | undefined)[];

    // Add all financial promotion categories to the sections array e.g. for Uk, Canada, etc
    const sections = [
      ...(ukFinancialPromotionCategories?.length
        ? ukFinancialPromotionCategories
        : []),
    ].filter(Boolean);

    // Make sure we only have unique categories
    const categories = [...new Set(sections)]?.map?.(section => {
      switch (section) {
        case 'baselineRisk':
          return formatCategory({
            id: section,
            title: messages.baselineRisk,
            summary: messages.baselineRiskSummary,
            details: messages.baselineRiskDetails,
          });
        case 'stableCoins':
          return formatCategory({
            id: section,
            title: messages.stableCoins,
            summary: messages.stableCoinsSummary,
            details: messages.stableCoinsDetails,
          });
        case 'defiTokens':
          return formatCategory({
            id: section,
            title: messages.defiTokens,
            summary: messages.defiTokensSummary,
            details: messages.defiTokensDetails,
          });
        case 'wrappedTokens':
          return formatCategory({
            id: section,
            title: messages.wrappedTokens,
            summary: messages.wrappedTokensSummary,
            details: messages.wrappedTokensDetails,
          });
        case 'memeCoins':
          return formatCategory({
            id: section,
            title: messages.memeCoins,
            summary: messages.memeCoinsSummary,
            details: messages.memeCoinsDetails,
          });
        case 'stakedAssets':
          return formatCategory({
            id: section,
            title: messages.stakedAssets,
            summary: messages.stakedAssetsSummary,
            details: messages.stakedAssetsDetails,
          });
        default:
          return null;
      }
    });

    return removeFalsyValues(categories);
  }, [asset?.ukFinancialPromotionCategories, formatCategory]);

  const handleToggleAssetRisk = useCallback(() => {
    toggleAssetRiskContainer();

    logEvent('adp_asset_investment_category_risks', {
      action: ActionType.click,
      componentType: ComponentType.button,
      context: ADP_ASSET_CATEGORY_INVESTMENTS_RISK,
      isExpanded: !isAssetRiskContainerVisible,
    });
  }, [toggleAssetRiskContainer, isAssetRiskContainerVisible]);

  const elevation = hideBorder ? undefined : 1;

  if (!asset || !assetRiskCategories?.length) return null;

  const assetRiskContent = (
    <VStack
      background
      borderRadius={hideBorder ? undefined : 'rounded'}
      elevation={isLoggedOut ? 0 : elevation}
      spacingHorizontal={isLoggedOut ? 4 : 3}
    >
      {!isLoggedOut && (
        <Container>
          <HStack
            as="aside"
            justifyContent="space-between"
            spacingTop={3}
            onClick={handleToggleAssetRisk}
          >
            <TextTitle3 as="h3" spacingBottom={3}>
              {formatMessage(messages.investmentRisk)}
            </TextTitle3>
            <Box>
              <Icon
                size="m"
                name={isAssetRiskContainerVisible ? 'caretUp' : 'caretDown'}
                color="foreground"
              />
            </Box>
          </HStack>
        </Container>
      )}

      <Collapsible collapsed={!isAssetRiskContainerVisible}>
        <VStack>
          {assetRiskCategories.map(category => (
            <Category
              key={category.id}
              id={category.id}
              title={category.title}
              summary={category.summary}
              details={category.details}
              isLoggedOut={isLoggedOut}
            />
          ))}
        </VStack>
      </Collapsible>
    </VStack>
  );

  return renderLoggedOutLayout
    ? renderLoggedOutLayout(assetRiskContent)
    : assetRiskContent;
}

const Container = styled.div`
  cursor: pointer;
  -webkit-tap-highlight-color: rgba(255, 255, 255, 0);
`;

export default memo(AssetRiskCategories);

import { memo, ReactNode, useMemo } from 'react';
import { useIntl } from 'react-intl';

import { useScreenMatch } from '@cb/shared/utils';
import { useToggler } from '@cbhq/cds-web';
import { Collapsible } from '@cbhq/cds-web/collapsible';
import { VStack } from '@cbhq/cds-web/layout';
import { Link, TextBody, TextHeadline } from '@cbhq/cds-web/typography';

import { messages } from './messages';

const VISIBLE_BULLET_COUNT = {
  loggedOut: {
    desktop: 3,
    tablet: 2,
    phone: 1,
  },
  loggedIn: {
    desktop: 2,
    tablet: 1,
    phone: 1,
  },
} as const;

type CategoryProps = {
  id: string;
  title: string;
  summary: ReactNode;
  details: ReactNode;
  isLoggedOut: boolean;
};

function Category({ id, title, summary, details, isLoggedOut }: CategoryProps) {
  const { formatMessage } = useIntl();
  const visibleBulletCount = useVisibleBulletCount(isLoggedOut);

  const [showMore, { toggleOn, toggleOff }] = useToggler(false);

  const detailedLines = useMemo(() => {
    return Object.values((details ?? []) as ReactNode[]).filter(detail =>
      typeof detail === 'string' ? detail.trim() : detail,
    );
  }, [details]);

  return (
    <VStack spacingBottom={3} testID={id}>
      <TextHeadline as="h4">{title}</TextHeadline>
      <TextBody as="p" spacingTop={1} color="foregroundMuted">
        {summary}
      </TextBody>

      {detailedLines.slice(0, visibleBulletCount).map((line, i) => {
        return (
          <VStack spacingTop={i === 0 ? 2 : undefined} spacingEnd={2}>
            {line}
          </VStack>
        );
      })}

      {detailedLines.length > visibleBulletCount && (
        <VStack>
          {!showMore && (
            <VStack display="block" spacingTop={1}>
              <Link variant="headline" onPress={toggleOn}>
                {formatMessage(messages.readMore)}
              </Link>
            </VStack>
          )}

          <Collapsible collapsed={!showMore}>
            <VStack spacingEnd={2}>
              {detailedLines.slice(visibleBulletCount)}
            </VStack>
          </Collapsible>

          {showMore && (
            <VStack display="block" spacingTop={2}>
              <Link variant="headline" onPress={toggleOff}>
                {formatMessage(messages.readLess)}
              </Link>
            </VStack>
          )}
        </VStack>
      )}
    </VStack>
  );
}

const useVisibleBulletCount = (isLoggedOut: boolean) => {
  const isMobile = useScreenMatch('phone_small');
  const isDesktop = useScreenMatch('desktop');
  const loginState = isLoggedOut ? 'loggedOut' : 'loggedIn';
  const screen = isMobile ? 'phone' : isDesktop ? 'desktop' : 'tablet';
  return VISIBLE_BULLET_COUNT[loginState][screen];
};

const CategoryMemo = memo(Category);

export { CategoryMemo as Category };

