  const chartPeriods = useChartPeriods();
  const { foreground, foregroundMuted } = usePalette();

  const handleMouseEnter = useCallback(
    (e: MouseEvent<HTMLSpanElement, Event>) => {
      e.currentTarget.style.color = foreground;
    },
    [foreground],
  );
  const handleMouseLeave = useCallback(
    (e: MouseEvent<HTMLSpanElement, Event>) => {
