import { useCallback, memo } from 'react';
import { TextInput } from '@cbhq/cds-web/controls/TextInput';
import { Box } from '@cbhq/cds-web/layout/Box';
import { Link } from '@cbhq/cds-web/typography/Link';

import { copyToClipboard, useToggledTimeout } from '../../utils';

type Props = {
  /**
   * The text displayed on the button to copy the url
   */
  copyText: string;

  /**
   * The text displayed when the component is copied
   */
  copiedText: string;

  /**
   * The optional text that will be displayed to the user instead of the value passed
   */
  displayValue?: string;

  /**
   * An optional label that will be displayed above the input
   */
  label?: string;

  /**
   * An optional handler that will be called when a user clicks copy
   */
  onCopy?: () => void;

  /**
   * The string copied to the clipboard when clicked
   */
  value: string;
};

function ClipboardTrigger({
  copyText = 'Copy',
  copiedText = 'Copied',
  displayValue,
  label,
  onCopy,
  value,
}: Props) {
  const [wasCopied, trigger] = useToggledTimeout(1000);
  const copy = useCallback(() => {
    copyToClipboard(value);
    trigger();

    if (onCopy) {
      onCopy();
    }
  }, [value, onCopy, trigger]);

  return (
    <TextInput
      label={label}
      value={displayValue || value}
      readOnly
      end={
        <Box spacingEnd={2}>
          <Link variant="label1" color="primary" onPress={copy}>
            {wasCopied ? copiedText : copyText}
          </Link>
        </Box>
      }
    />
  );
}

export default memo(ClipboardTrigger);
