type Params = {
  isPaused: boolean;
  showQuiz: boolean;
  showShare: boolean;
  showEndCards: boolean;
};

const DEFAULTS: Params = {
  isPaused: false,
  showQuiz: false,
  showShare: false,
  showEndCards: false,
};

const StoryDebuggerContext = createContext<Params>({ ...DEFAULTS });

export function useStoryDebugger(): Params {
  const context = useContext(StoryDebuggerContext);
  return context || { ...DEFAULTS };
}

export function StoryDebuggerProvider({
  children,
}: React.PropsWithChildren<unknown>) {
  return __DEV__ ? <StoryDebugger>{children}</StoryDebugger> : <>{children}</>;
}

function StoryDebugger({ children }: React.PropsWithChildren<unknown>) {
  const [isPaused, setIsPaused] = useState(false);
  const [showQuiz, setShowQuiz] = useState(false);
  const [showShare, setShowShare] = useState(false);
  const [showEndCards, setShowEndCards] = useState(false);

  const handleKeyPress = (ev: KeyboardEvent) => {
    //* Pause
    if ([' ', 'spacebar'].includes(ev.key.toLowerCase())) {
      ev.preventDefault();
      setIsPaused(v => !v);
    }
    //* Show Quiz
    if (ev.key.toLowerCase() === 'q') {
      ev.preventDefault();
      setShowQuiz(v => !v);
    }

    //* Show Share
    if (ev.key.toLowerCase() === 's') {
      ev.preventDefault();
      setShowShare(v => !v);
    }

    //* Show End Cards
    if (ev.key.toLowerCase() === 'e') {
      ev.preventDefault();
      setShowEndCards(v => !v);
    }
  };

  useEffect(() => {
    if (typeof window !== 'undefined') {
      window.addEventListener('keypress', handleKeyPress, true);
    }
    return () => {
      if (typeof window !== 'undefined') {
        window.removeEventListener('keypress', handleKeyPress, true);
      }
    };
  }, []);

  if (__DEV__) {
    return (
      <StoryDebuggerContext.Provider
        value={{ isPaused, showQuiz, showShare, showEndCards }}
      >
        {children}
        <StoryDebuggerPanel
          setIsPaused={setIsPaused}
          setShowQuiz={setShowQuiz}
          setShowShare={setShowShare}
          setShowEndCards={setShowEndCards}
        ></StoryDebuggerPanel>
      </StoryDebuggerContext.Provider>
    );
  }

  return null;
}

type DebugProps = {
  setIsPaused: React.Dispatch<React.SetStateAction<boolean>>;
  setShowQuiz: React.Dispatch<React.SetStateAction<boolean>>;
  setShowShare: React.Dispatch<React.SetStateAction<boolean>>;
  setShowEndCards: React.Dispatch<React.SetStateAction<boolean>>;
};

