    }
  }, [isPaused, showQuiz, showShare, showEndCards]);

  if (__DEV__) {
    return (
      <>
        {visible && (
          <DebugPanel>
            <Box
              bordered
              borderRadius="rounded"
              background="background"
              width={200}
              alignItems="center"
