                  <IconButton
                    name="circleCheckmark"
                    variant={isPaused ? 'primary' : 'foregroundMuted'}
                    // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                    onPress={() => setIsPaused(v => !v)}
                    transparent
                  />
                  <TextTitle3
                    as="h1"
                    spacingVertical={0.5}
                  >{`Paused`}</TextTitle3>
                </HStack>
                <Divider direction="horizontal" />
                <HStack alignContent="space-around" spacing={1}>
                  <IconButton
                    name="circleCheckmark"
                    variant={showQuiz ? 'primary' : 'foregroundMuted'}
                    // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                    onPress={() => setShowQuiz(v => !v)}
                    transparent
                  />
                  <TextTitle3
                    as="h1"
                    spacingVertical={0.5}
                  >{`Show Quiz`}</TextTitle3>
                </HStack>
                <Divider direction="horizontal" />
                <HStack alignContent="space-between" spacing={1}>
                  <IconButton
                    name="circleCheckmark"
                    variant={showShare ? 'primary' : 'foregroundMuted'}
                    // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                    onPress={() => setShowShare(v => !v)}
                    transparent
                  />
                  <TextTitle3
                    as="h1"
                    spacingVertical={0.5}
                  >{`Show Share`}</TextTitle3>
                </HStack>
                <Divider direction="horizontal" />
                <HStack alignContent="space-between" spacing={1}>
                  <IconButton
                    name="circleCheckmark"
                    variant={showEndCards ? 'primary' : 'foregroundMuted'}
                    // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
                    onPress={() => setShowEndCards(v => !v)}
                    transparent
                  />
                  <TextTitle3
                    as="h1"
                    spacingVertical={0.5}
                  >{`Show End Cards`}</TextTitle3>
                </HStack>
              </VStack>
            </Box>
          </DebugPanel>
        )}
      </>
    );
  }

  return null;
}

