export type InputProps = {
  id?: string; // a11y
  value?: string;
  placeholder?: string;
  disabled?: boolean;
  label?: React.ReactNode | (string | undefined | null);
  onChange?: (value: string) => void;
  // TODO: fix typing here
  onBlur?: (event?: unknown) => void;
  onFocus?: () => void;
  onPaste?: () => void;
  onEscape?: () => void;
  onEnter?: () => void;
  onTouchStart?: () => void;
  showError?: boolean;
  refCallback?: (el: HTMLInputElement) => void;
  removeError?: () => void;
  addError?: () => void;
  resetState?: () => void;
  actionLabel?: React.ReactNode | string;
  onActionClick?: () => void;
  // By default, action button is only shown when input is focused and empty
  // However, for certain cases, we will want to show the action button permanently.
  forceShowAction?: boolean;
  validators?: Validators;
  className?: string;
  autoFocus?: boolean;
  /**
   * See here for docs: https://developer.mozilla.org/en-US/docs/Web/HTML/Global_attributes/autocapitalize
   */
  autoCapitalize?: 'none' | 'off' | 'sentences' | 'on' | 'words' | 'characters';
  mask?: string;
  maskChar?: string;
  maxLength?: number;
  size?: number;
  height?: string;
  icon?: React.ReactNode | null;
  containerStyles?: React.CSSProperties;
  inputStyles?: React.CSSProperties;
  labelStyles?: React.CSSProperties;
  iconStyles?: React.CSSProperties;
  component?: 'input' | 'textarea';
  annotation?: React.ReactNode;
  annotationPosition?: 'left' | 'right';
  rows?: number;
  allowShrink?: boolean;
  type?: 'password' | 'text' | 'number';
  'data-testid'?: string;
  inputMode?: React.HTMLAttributes<HTMLLIElement>['inputMode'];
  autoComplete?: string;
  name?: string;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  ref?: any;
  errorBorder?: keyof DefaultTheme['color'];
  focusBorder?: keyof DefaultTheme['color'];
  errorID?: string; // a11y
  invalid?: boolean; // a11y
  cdsVersion?: boolean;
};

export function InputWithoutFormControl({
  id,
  size,
  type,
  inputMode,
  autoComplete,
  annotation,
  className,
  maskChar,
  placeholder,
  maxLength,
  height = 'auto',
  icon,
  validators,
  onActionClick,
  onBlur,
  onChange,
  onEnter,
  onEscape,
  onFocus,
  onPaste,
  onTouchStart,
  label,
  mask,
  addError,
  removeError,
  resetState,
  actionLabel,
  forceShowAction,
  value,
  refCallback,
  name,
  containerStyles = {},
  labelStyles = {},
  inputStyles = {},
  iconStyles = {},
  errorBorder = 'negative',
  focusBorder = 'borderAccent',
  errorID,
  invalid,
  disabled = false,
  showError = false,
  autoFocus = false,
  component = 'input' as const,
  annotationPosition = 'left' as const,
  rows = 1,
  allowShrink = false,
  cdsVersion = false,
  autoCapitalize = 'off',
  ...props
}: InputProps) {
  const [focus, setFocus] = useState(false);

  // TODO: We should remove this and use ValidatedInput instead
  const validInput = useCallback(
    (value: string) => {
      return (
        !validators ||
        !validators.some(v => {
          return !v[0] || !v[0](value);
        })
      );
    },
    [validators],
  );

  const handleChange = useCallback(
    (e: { target: { value?: string }; type: string }) => {
      const target = e.target as HTMLInputElement;
      const value = target.value;

      if (onPaste && mask && e.type === 'paste') {
        // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
        onPaste(e);
      }

      if (onChange) onChange(value);
      const isValid = validInput(value);

      if (!isValid && addError) {
        addError();
      } else if (isValid && removeError) {
        removeError();
      }
    },
    [onPaste, mask, onChange, validInput, addError, removeError],
  );

  const handleBlur = useCallback(
    (event: unknown) => {
      setFocus(false);

      if (showError) {
        if (removeError) removeError();
        if (resetState) resetState();
      }

      if (onBlur) onBlur(event);
    },
    [showError, removeError, resetState, onBlur],
  );

  const handleFocus = useCallback(
    (event: unknown) => {
      setFocus(true);
      // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
      if (onFocus) onFocus(event);
    },
    [onFocus],
  );

  const handleKeyDown = useCallback(
    (event: { keyCode: number }) => {
      if (event.keyCode === 27 && onEscape) {
        // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
        onEscape(event);
      } else if (event.keyCode === 13 && onEnter) {
        // @ts-expect-error: 2021-03-20: Whitelisted type error. To be corrected after typescript migration.
        onEnter(event);
      }
    },
    [onEscape, onEnter],
  );

  const onActionMouseDown = useCallback(
    (event: React.SyntheticEvent) => {
      if (onActionClick) {
        event.preventDefault();
        onActionClick();
      }
    },
    [onActionClick],
  );

  const setRef = useCallback(
    (input: HTMLInputElement) => {
      if (refCallback) refCallback(input);
    },
    [refCallback],
  );

  const renderedLabel = useMemo(() => {
    return (
      label && (
        <Label
          style={labelStyles}
          align="center"
          justify="center"
          // @ts-expect-error "disabled" doesn't exist on Label, not sure what it's being used here for
          disabled={disabled}
        >
          {label}
        </Label>
      )
    );
  }, [label, labelStyles, disabled]);

  const renderedAction = useMemo(() => {
    return (
      !isNil(actionLabel) &&
      onActionClick &&
      (forceShowAction || (focus && !value)) && (
        <Action onMouseDown={onActionMouseDown}>{actionLabel}</Action>
      )
    );
  }, [
    actionLabel,
    onActionClick,
    focus,
    value,
    onActionMouseDown,
    forceShowAction,
  ]);

  const borderColor = useMemo(() => {
    if (showError) return errorBorder;
    if (focus) return focusBorder;
  }, [showError, focus, errorBorder, focusBorder]);

  const Field = component === 'input' ? InputField : TextareaField;
  const annotationElement = annotation && (
    <Annotation position={annotationPosition} center>
      <Text color="light">{annotation}</Text>
    </Annotation>
  );
  const input = (
    <Container
      // @ts-expect-error "focus" prop doesn't exist here? Not sure what it's used for here.
      focus={focus}
      borderColor={borderColor}
      className={className}
      disabled={disabled}
      style={containerStyles}
      auto
      annotationPosition={annotation ? annotationPosition : undefined}
      cdsVersion={cdsVersion}
    >
      {mask ? (
        <MaskedField
          id={id}
          aria-describedby={errorID}
          aria-invalid={invalid ? 'true' : 'false'}
          mask={mask}
          maskChar={maskChar}
          autoCapitalize={autoCapitalize}
          autoFocus={autoFocus}
          placeholder={placeholder || ''}
          aria-label={placeholder || ''}
          value={value}
          onChange={handleChange}
          onBlur={handleBlur}
          onFocus={handleFocus}
          onKeyDown={handleKeyDown}
          onTouchStart={onTouchStart}
          size={size}
          type={type}
          inputMode={inputMode}
          autoComplete={autoComplete}
          name={name}
          disabled={disabled}
          height={height}
          data-testid={props['data-testid']}
        />
      ) : (
        <Field
          id={id}
          aria-describedby={errorID}
          aria-invalid={invalid ? 'true' : 'false'}
          data-testid={props['data-testid']}
          key="field"
          // @ts-expect-error It's not worth it to fix this error
          ref={setRef}
          autoFocus={autoFocus}
          placeholder={placeholder || ''}
          aria-label={placeholder || ''}
          value={value}
          onChange={handleChange}
          onBlur={handleBlur}
          onFocus={handleFocus}
          onPaste={onPaste}
          onKeyDown={handleKeyDown}
          maxLength={maxLength}
          rows={Field === TextareaField ? rows : undefined}
          autoComplete="off"
          autoCorrect="off"
          autoCapitalize={autoCapitalize}
          spellCheck="false"
          size={size}
          allowShrink={allowShrink}
          type={type}
          disabled={disabled}
          inputMode={inputMode}
          name={name}
          height={height}
          style={inputStyles}
        />
      )}
      {renderedLabel}
      {renderedAction}
      {icon && (
        <IconContainer style={iconStyles} id="icon-container">
          {icon}
        </IconContainer>
      )}
    </Container>
  );
  return annotation ? (
    <Wrapper auto position={annotationPosition}>
      {annotationElement}
      {input}
    </Wrapper>
  ) : (
    input
  );
}

