import { memo, useCallback } from 'react';
import styled, { css } from 'styled-components';

import { FieldProps } from '../../new-forms';
import Flex from '../Flex';
import InputValueButton from './InputValueButton';
export type Props = {
  disabled?: boolean;
  validateItem?: ((s: string | undefined) => boolean) | null;
  separator?: RegExp;
  placeholder?: string;
  className?: string;
  onFocus?: () => void;
} & FieldProps<Array<string | undefined>>;

function MultiInput({
  value,
  onChange,
  onFocus,
  disabled,
  separator = /\s|,/,
  placeholder,
  validateItem,
  className,
}: Props) {
  // eslint-disable-next-line @cb/react-hooks-exhaustive-deps
  const buttonValues = [...value];
  const inputValue = buttonValues.pop() || '';
  const onTextChange = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (e: any) => {
      const oldButtonValues = value.slice(0, -1);
      const newInputString: string = e?.target?.value || '';
      /*
       * The separator needs to be handled in `onTextChange` and not `onKeyDown`
       * to handle copy/pastes.
       */

      const newValues = newInputString.split(separator);
      const lastValue = newValues.pop();
      const newButtonValues = newValues.filter(
        newValue => newValue && !oldButtonValues.includes(newValue),
      );
      onChange([...oldButtonValues, ...newButtonValues, lastValue]);
    },
    [onChange, separator, value],
  );
  const addItem = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (newValue: any) => {
      if (buttonValues.includes(newValue)) {
        onChange([...buttonValues, '']);
      } else {
        onChange([...buttonValues, newValue, '']);
      }
    },
    [onChange, buttonValues],
  );
  const removeItem = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (idx: any) => {
      onChange([...value.slice(0, idx), ...value.slice(idx + 1, value.length)]);
    },
    [onChange, value],
  );
  const onKeyPress = useCallback(
    // 2023-10-19: TODO please fix
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (e: any) => {
      if (e.key === 'Tab' && e.target.value !== '') {
        e.preventDefault();
        addItem(e.target.value);
      }

      if (e.target.selectionEnd === 0 && e.key === 'Backspace') {
        removeItem(value.length - 2);
      }
    },
    [removeItem, value, addItem],
  );
  const showPlaceholderText = buttonValues.length === 0;
  return (
    <InputContainer className={className}>
      <ValuesContainer>
        {buttonValues.map((renderedValue, idx) => (
          <InputValueButton
            key={renderedValue}
            value={renderedValue}
            validate={validateItem}
            disabled={disabled}
            // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
            onClick={() => removeItem(idx)}
          />
        ))}
        <TextInput
          value={inputValue}
          disabled={disabled}
          onChange={onTextChange}
          onKeyDown={onKeyPress}
          placeholder={showPlaceholderText ? placeholder : ''}
          onFocus={onFocus}
          aria-label={placeholder}
        />
      </ValuesContainer>
    </InputContainer>
  );
}

