export const CellAccessory = memo(
  forwardRef(function CellAccessory(
    { type, ...props }: CellAccessoryProps,
    ref: ForwardedRef<HTMLElement>,
  ) {
    let icon;

    if (type === 'more') {
      icon = <Icon name="more" size="s" color="foregroundMuted" />;
    }

    if (type === 'arrow') {
      icon = <Icon name={'caretLeft'} size="s" color="foregroundMuted" />;
    }

    if (type === 'selected') {
      icon = <Icon name="checkmark" size="s" color="positive" />;
    }

    if (!icon) {
      return null;
    }

    return (
      <Box {...props} testID="accessory" ref={ref}>
        {icon}
      </Box>
    );
  }),
);

function ListCellItem({
