export default function ListSelectItem({
  title,
  description,
  value,
  onPress,
  onKeyPress,
  ...props
}: SelectItemProps) {
  const { onChange, value: selectedValue } = useListSelectContext();
  const selected = selectedValue === value;

  const handleChange = useCallback(() => {
    onChange(value);
  }, [onChange, value]);

  const handlePress = useCallback(
    (event: React.MouseEvent) => {
      handleChange();
      onPress?.(event);
    },
    [onPress, handleChange],
  );

  return (
    <Pressable
      noScaleOnPress
      onPress={handlePress}
      onKeyPress={onKeyPress}
      borderColor={paletteBorders[5]}
      background={paletteBackgrounds[0]}
