    description: 'Error message',
  },
  // 2023-10-05: TODO please fix, see go/i18n-linter-messages
  // eslint-disable-next-line @cbhq/i18n-enhanced-description
  simulateButton: {
    id: `${i18nKey}.simulateButton`,
    defaultMessage: 'Simulate',
    description: 'Dev only button that allows simulation of fido 2fa',
  },
});

function FidoAuthentication({
  onChange,
  onValid,
  onInvalid,
  className,
  noBorder,
  onSubmit,
  onSubmitFido,
  client,
  endpointOverrides,
}: Props) {
  const { formatMessage } = useIntl();

  const { state, authenticate, simulate } = useFidoAuthentication({
    client,
    endpointOverrides,
  });

  const handleSubmit = useCallback(
    (token?: string) => {
      // @ts-expect-error token should be string but it can be undefined
      onChange(token);
      onValid();

      if (onSubmitFido) {
        onSubmitFido(token);
      } else if (onSubmit) {
        onSubmit();
      }
    },
    [onChange, onSubmit, onSubmitFido, onValid],
  );

  const authenticateSecurityKey = useCallback(async () => {
    try {
      const token = await authenticate();
      handleSubmit(token);
    } catch (error) {
      onInvalid();
    }
  }, [authenticate, handleSubmit, onInvalid]);

  const renderRetryLink = () => {
    const retryStates = [AuthState.INITIAL, AuthState.ERROR];

    if (retryStates.includes(state)) {
      return (
        <HStack justifyContent="space-between">
          <button onClick={authenticateSecurityKey}>
            <FormattedMessage
              id={`${i18nKey}.retry`}
              defaultMessage="Reload"
              description="Retry security key authentiation"
            />
          </button>
          {!!__DEV__ && (
            <button
              // eslint-disable-next-line react-perf/jsx-no-new-function-as-prop
              onClick={() => {
                const simulatedToken = simulate();
                handleSubmit(simulatedToken);
              }}
            >
              {formatMessage(messages.simulateButton)}
            </button>
          )}
        </HStack>
      );
    }

    return null;
  };

  const renderIcon = () => {
    const iconMap = {
      [AuthState.INITIAL]: SecurityKey,
      [AuthState.UNSUPPORTED]: SecurityKeyUnsupported,
      [AuthState.CHECKING]: Spinner,
      [AuthState.AUTHENTICATED]: SecurityKeySuccess,
      [AuthState.ERROR]: SecurityKeyError,
    };

    const Icon = iconMap[state];

    if (state === AuthState.CHECKING) {
      return <Icon size="normal" />;
    }

    return <Icon width="35" height="35" />;
  };

  const renderText = () => {
    const textMap = {
      [AuthState.INITIAL]: messages.instructions,
      [AuthState.UNSUPPORTED]: messages.unsupported,
      [AuthState.CHECKING]: messages.checking,
      [AuthState.AUTHENTICATED]: messages.authenticated,
      [AuthState.ERROR]: messages.error,
    };

    return formatMessage(textMap[state]);
  };

  useEffect(() => {
    const timer = setTimeout(() => authenticateSecurityKey());
    return () => clearTimeout(timer);
  }, []);

  return (
    <Container
      justify="flex-start"
      align="center"
      className={className}
      noBorder={noBorder}
    >
      <IconWrapper>{renderIcon()}</IconWrapper>
      <TextWrapper column>
        {renderText()}
        <div>{renderRetryLink()}</div>
      </TextWrapper>
    </Container>
  );
}

const Container = styled(Flex)<{
  noBorder?: boolean;
}>`
  min-height: 100px;
  box-sizing: border-box;
  ${({ noBorder, theme }) =>
    !noBorder &&
    css`
      border-top: 1px solid ${theme.color.border};
      border-bottom: 1px solid ${theme.color.border};
      background: ${theme.color.background};
    `};
`;

const IconWrapper = styled(Flex)`
  padding: ${({ theme }) => theme.size.enormous};
`;

const TextWrapper = styled(Flex)`
  line-height: 22px;
  font-size: ${({ theme }) => theme.fontSize.small};
  padding: 0px ${({ theme }) => theme.size.large};
  margin-right: 5px;
  color: ${({ theme }) => theme.color.text};

  & button {
    color: ${({ theme }) => theme.color.textAccent};
    font-family: ${({ theme }) => theme.fontFamily.regular};
    background: none;
    border: none;
    padding: 0;
    cursor: pointer;
  }
`;

export default memo(FidoAuthentication);

import React, { memo, useMemo, useCallback, useEffect } from 'react';
import styled from 'styled-components';

import { Check } from '../../assets/icons';
import { createChainedFunction } from '../../utils';
import { cssValue } from '../../utils';
import Flex from '../Flex';
import { useFormControl } from '../Form';
import { Validators } from '../Form/useValidationStore';
import useValidationStore from '../Form/useValidationStore';
import InlineError from '../InlineError';
import { InputWithoutFormControl as Input } from '../Input';
import InputErrorIcon from '../InputErrorIcon';

export type ValidatedInputProps = {
  /** Validators that component need to pass */
  validators: Validators;

  /** Display success icon */
  showSuccess?: boolean;

  onChange?: (value: string | boolean) => void;
  onValid?: () => void;
  onInvalid?: (errorMessages: string[]) => void;
  validateOnBlur?: boolean;
  applicationContext?: string;

  /** Hide validation error message (useful when combined with <Form/> and displayed outside the form) */
  hideInlineErrorMessages?: boolean;

  minHeight?: number;
  cdsVersion?: boolean;
  testID?: string;
} & Omit<React.ComponentProps<typeof Input>, 'validators' | 'onChange'>;

/**
 * Validated text input
 *
 * Input can be used independently or with <Form/> component. When used inside
 * a form, following props should be left out as they are automatically assigned:
 *
 * - `value`
 * - `onChange`
 * - `onValid`
 * - `onInvalid`
 * - `validateOnBlur`
 */

const inputStyles = { outline: 'none', border: 'none' };

function ValidatedInput({
  value = '',
  showSuccess = false,
  component = 'input',
  icon,
  onActionClick: onActionClickProp,
  className,
  name,
  minHeight = 70,
  height = 'auto',
  cdsVersion,
  onFocus: onFocusProp,
  onBlur: onBlurProp,
  testID,
  validateOnBlur = false,
  autoFocus = false,
  hideInlineErrorMessages,
  validators,
  ...others
}: ValidatedInputProps) {
  // This likely shouldn't be optional
  const formName = name || 'input';

  const { store: formStore, refCallback } = useFormControl({
    name: formName,
    validators,
    hideInlineErrorMessages,
    autoFocus,
    onChange: others.onChange,
  });

  const inputStore = useValidationStore({
    validators,
    onChange: others.onChange,
    onValid: others.onValid,
    onInvalid: others.onInvalid,
    focused: autoFocus,
    dirty: false,
    validateOnBlur,
    hideInlineErrorMessages,
  });

  const managedByForm = !!formStore;

  const store = useMemo(() => {
    if (formStore) {
      return formStore;
    }
    return inputStore;
  }, [formStore, inputStore]);

  const inputValue = useMemo(() => {
    const inputValue = (store ? store.value || value : value) || '';
    return typeof inputValue === 'string' ? inputValue : '';
  }, [store, value]);

  const {
    showInlineErrorMessage,
    hasErrors,
    handleChange,
    handleFocus,
    handleBlur,
    markDirty,
    showErrors,
    dirty,
    validate,
  } = store;

  useEffect(() => {
    if (dirty) {
      validate(inputValue);
    }
  }, [dirty, inputValue]);

  const inputIcon = useMemo(() => {
    if (icon) {
      return icon;
    }

    // Success icon on validation after user has touched the element
    if (showSuccess && dirty && !hasErrors) {
      return (
        <CheckIconWrapper>
          <CheckIcon />
        </CheckIconWrapper>
      );
    }
  }, [dirty, hasErrors, icon, showSuccess]);

  // When component is managed by <Form/>, make it dirty and validate on focus
  const onFocus = useCallback(() => {
    const chainedOnFocus = managedByForm
      ? createChainedFunction(
          markDirty,
          () => {
            store.validate(inputValue);
          },
          handleFocus,
        )
      : handleFocus;
    chainedOnFocus();
    if (onFocusProp) onFocusProp();
  }, [handleFocus, inputValue, managedByForm, markDirty, onFocusProp, store]);

  const onBlur = useCallback(
    (event: unknown) => {
      const chainedOnBlur = createChainedFunction(handleBlur, onBlurProp);
      return chainedOnBlur(event);
    },
    [handleBlur, onBlurProp],
  );

  const onActionClick = useCallback(() => {
    const chainedOnActionClick = createChainedFunction(
      markDirty,
      onActionClickProp,
    );
    return chainedOnActionClick();
  }, [markDirty, onActionClickProp]);

  const errorID = `${others.id || name}_error`;

  return (
    <Wrapper auto column className={className} minHeight={minHeight}>
      <>
        <Input
          refCallback={refCallback}
          {...others}
          validators={validators}
          autoFocus={autoFocus}
          errorID={errorID}
          invalid={Boolean(errorID)}
          className={className}
          onActionClick={onActionClick}
          value={inputValue}
          showError={showErrors}
          onChange={handleChange}
          name={name}
          onFocus={onFocus}
          onBlur={onBlur}
          icon={inputIcon}
          component={component}
          height={height}
          inputStyles={inputStyles}
          cdsVersion={cdsVersion}
          data-testid={testID}
        />
        {showInlineErrorMessage && (
          <ErrorWrapper>
            <InputErrorIcon errorID={errorID} />
            <InlineError id={errorID} noMarginTop>
              {store.error}
            </InlineError>
          </ErrorWrapper>
        )}
      </>
    </Wrapper>
  );
}

const Wrapper = styled(Flex)<{
  minHeight: number;
}>`
  &:first-child {
    min-height: ${({ minHeight }) => cssValue(minHeight)}px;
  }
`;

const ErrorWrapper = styled(Flex)`
  align-items: center;
  margin-top: ${({ theme }) => theme.size.medium};
`;

const CheckIconWrapper = styled(Flex)`
  border-radius: 50%;
  background-color: ${({ theme }) => theme.color.positive};
`;

const CheckIcon = styled(Check)`
  fill: ${({ theme }) => theme.color.white};
  width: 15px;
  height: 15px;
  padding: 5px;
`;

export { ValidatedInput };
export default memo(ValidatedInput);

import { useMemo, useCallback } from 'react';
import { useIntl } from 'react-intl';

import { Button, IconButton } from '@cbhq/cds-web/buttons';
import { Box, Spacer, VStack } from '@cbhq/cds-web/layout';
import { TextLegal } from '@cbhq/cds-web/typography';
import { Link } from '@cbhq/cds-web/typography/Link';
import {
  ActionType,
  ComponentType,
  logEvent,
  useLogEventOnMount,
} from '@cbhq/client-analytics';
import { graphql, useFragment } from '@cbhq/data-layer';

import useIsMobile from '../../utils/useIsMobile';
import HeroLayout from '../HeroLayout';
import { DownloadWalletAssetFragment$key } from './__generated__/DownloadWalletAssetFragment.graphql';
import { WALLET_HOME, WALLET_TERMS } from './constants';
import { WALLET_DEX_TRADE } from './eventing';
import messages from './messages';

type Props = {
  assetRef: DownloadWalletAssetFragment$key;
  goBack?: () => void;
};

export default function DownloadWallet({ assetRef, goBack }: Props) {
  const asset = useFragment(
    graphql`
      fragment DownloadWalletAssetFragment on Asset {
        name
      }
    `,
    assetRef,
  );

  const { formatMessage } = useIntl();
  const isMobile = useIsMobile();

  useLogEventOnMount(WALLET_DEX_TRADE, {
    componentType: isMobile ? ComponentType.modal : ComponentType.card,
    currency: asset.name,
  });

  const sharedEvents = useMemo(() => {
    return {
      action: ActionType.click,
      currency: asset.name,
    };
  }, [asset.name]);

  const handleLinkPress = useCallback(() => {
    logEvent(WALLET_DEX_TRADE, {
      componentType: ComponentType.link,
      ...sharedEvents,
    });
  }, [sharedEvents]);

  const handleButtonPress = useCallback(() => {
    logEvent(WALLET_DEX_TRADE, {
      componentType: ComponentType.button,
      ...sharedEvents,
    });
  }, [sharedEvents]);

  return (
    <Box position="relative" height="100%">
      {goBack && (
        <Box position="absolute" top={16} left={16}>
          <IconButton name="backArrow" onPress={goBack} transparent />
        </Box>
      )}
      <VStack spacing={3} height="100%">
        <HeroLayout
          heroName="downloadCoinbaseWallet"
          title={formatMessage(messages.tradeMoreOnWallet, {
            assetName: asset.name,
          })}
          body={formatMessage(messages.selfCustodyWarning)}
        />
        <Spacer vertical={isMobile ? undefined : 3} />
        <TextLegal as="p" align="center" color="foregroundMuted">
          {formatMessage(messages.disclaimer, {
            link: (content: React.ReactNode) => [
              <Link
                variant="legal"
                href={WALLET_TERMS}
                onPress={handleLinkPress}
                openInNewWindow
              >
                {content as string}
              </Link>,
            ],
          })}
        </TextLegal>
        <Spacer vertical={2} />
        <Button
          block
          to={WALLET_HOME}
          target="_blank"
          onPress={handleButtonPress}
        >
          {formatMessage(messages.getWallet)}
        </Button>
      </VStack>
    </Box>
  );
}

import React, { memo } from 'react';
import { useIntl } from 'react-intl';
import styled from 'styled-components';

import { IconButton } from '@cbhq/cds-web/buttons';

import { Star } from '../../assets/icons';
import { cssValue } from '../../utils';
import useTheme from '../../utils/useTheme';
import Button from '../Button';
import { messages } from './messages';

type Props = {
  isIcon?: boolean;
  isCDSIcon?: boolean;
  isStretched?: boolean;
  transparent?: boolean;
  onClick?: React.MouseEventHandler<HTMLButtonElement> | undefined;
  isWatched?: boolean;
  color?: 'yellow' | 'blue';
  name?: string;
  testID?: string;
};

function WatchStar({
  name,
  isIcon,
  isCDSIcon,
  isStretched,
  transparent = true,
  onClick,
  isWatched,
  color = 'yellow',
  testID,
}: Props) {
  const { formatMessage } = useIntl();
  const theme = useTheme();
  const fillColor =
    color === 'yellow' ? theme.color.warning : theme.color.backgroundAccent;
  const label = isWatched
    ? formatMessage(messages.watchlist)
    : formatMessage(messages.assetFollow);

  const ariaLabel = isWatched
    ? formatMessage(messages.starIconLabelWatch, { name })
    : formatMessage(messages.starIconLabelUnwatch, { name });

  if (isCDSIcon) {
    return (
      <IconButton
        testID={testID}
        aria-label={ariaLabel}
        aria-pressed={isWatched}
        onPress={onClick}
        name={isWatched ? 'starActive' : 'starInactive'}
        transparent={transparent}
        variant={isWatched ? 'primary' : 'secondary'}
      />
    );
  }

  if (isIcon) {
    return (
      <IconButtonWrapper
        onClick={onClick}
        aria-label={ariaLabel}
        aria-pressed={isWatched}
      >
        <StarIcon
          filled={isWatched ? 1 : 0}
          color={fillColor}
          focusable="false"
          aria-hidden="true"
        />
      </IconButtonWrapper>
    );
  }

  return (
    <StarButton
      isStretched={!!isStretched}
      type="light"
      size="medium"
      onClick={onClick}
      aria-label={ariaLabel}
      aria-pressed={isWatched}
    >
      <StarIconButton
        filled={isWatched ? 'filled' : ''}
        color={fillColor}
        focusable="false"
        aria-hidden="true"
      />
      <Span>{label}</Span>
    </StarButton>
  );
}

const IconButtonWrapper = styled.button`
  background: none;
  padding: 0;
`;

const Span = styled.span`
  margin-left: 10px;
  white-space: nowrap;
  font-size: ${p => p.theme.fontSize.medium};
`;

const StarButton = styled(Button)<{ isStretched?: boolean }>`
  ${p => (p.isStretched ? 'width: 100%' : '')};
`;

const StarIconButton = styled(Star)<{ filled: 'filled' | '' }>`
  fill: ${p => (p.filled ? p.theme.color.warning : '')};
  stroke-width: 1px;
  cursor: pointer;

  path {
    stroke: ${p => (p.filled ? p.theme.color.warning : '')};
  }
`;

const StarIcon = styled(Star)<{ filled: 1 | 0 }>`
  fill: ${p => (p.filled ? cssValue(p.color) : 'transparent')};
  stroke-width: 1px;
  cursor: pointer;

  path {
    stroke: ${p => (p.filled ? cssValue(p.color) : '')};
  }
`;

export { WatchStar };
export default memo(WatchStar);

import { memo, useEffect } from 'react';
import { Box } from '@cbhq/cds-web/layout/Box';

import { notifyError } from '../../../../utils';
import { Media } from '../../utils/mediaUtils';

type DappVideoProps = {
  video?: Media;
};

function DappVideo({ video }: DappVideoProps) {
  const videoIsNotSupported = !video?.url?.includes('.mp4');
  useEffect(() => {
    if (videoIsNotSupported) {
      notifyError(new Error('Video source not supported'), {
        owner: 'dapps',
        src: video?.url,
        context: 'video',
      });
    }
  }, []);

  if (videoIsNotSupported) {
    return null;
  }

  return (
    <Box
      borderRadius="roundedSmall"
      background="backgroundAlternate"
      overflow="hidden"
      width="100%"
    >
      <video preload="auto" controls width="100%" autoPlay>
        <track kind="captions" />
        <source src={video?.url} type="video/mp4" />
      </video>
    </Box>
  );
}

export default memo(DappVideo);
